import type { Hadith } from './hadith-data';
export const HADEETH_HADEETHS: Hadith[] = [{"id":"he_5907","text":"عن أبي موسى الأشعري رضي الله عنه عن النبي صلى الله عليه وسلم قال: «تَعَاهَدُوا هَذَا الْقُرْآنَ، فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَهُوَ أَشَدُّ تَفَلُّتًا مِنَ الْإِبِلِ فِي عُقُلِهَا».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَمَرَ النبيُّ صلى الله عليه وسلم بمُعاهَدةِ القرآنِ والمواظبةِ على تلاوتِهِ كي لا ينساه بعد أن كان حافظًا له في صدرِهِ، وأَكَّدَ ذلك بِحَلِفِهِ صلى الله عليه وسلم على أنَّ القرآنَ أشدُّ تَخَلُّصًا وذهابًا من الصدور مِن الإبل المَعقولة وهي المشدودة بحبلٍ في وسط الذراع، إنْ تَعاهدَها الإنسانُ أَمْسَكَها وإنْ أَطْلَقَها ذهبتْ وضاعتْ.","reference":"صحيح مسلم (1/ 545) (791).\nبهجة الناظرين شرح رياض الصالحين، تأليف سليم الهلالي (2/ 231).\nرياض الصالحين من كلام سيد المرسلين (ص299) (1002).\nشرح رياض الصالحين، للشيخ محمد بن صالح العثيمين (4/ 657).\nكنوز رياض الصالحين، لمجموعة من الباحثين (13/ 5).","benefits":["إنْ واظَبَ حافظُ القرآنِ على تلاوتِه مرَّة بعد مرَّة بقي محفوظًا في قلبه، وإلا ذهبَ عنه ونسيَه.","من فوائد تعاهُدِ القرآن: الأجر والثواب، ورفعة الدرجات يوم القيامة."],"wordsMeanings":[],"category":"quran","tags":["تعاهدوا","هذا","القرآن،","فوالذي","نفس","محمد"],"source":"hadeethenc"},{"id":"he_5913","text":"عن عثمان رضي الله عنه عن النبي صلى الله عليه وسلم قال: «خَيْرُكُمْ مَنْ تَعَلَّمَ الْقُرْآنَ وَعَلَّمَهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ أفضلَ المسلمين وأعلاهم عند الله درجة: مَن تَعَلَّم القرآنَ، تلاوةً وحفظًا وترتيلًا وفقهًا وتفسيرًا، وعَلَّمَ غيرَه ما عنده من علوم القرآن مع عَمَلِهِ به.","reference":"صحيح البخاري (6/ 192) (5027).\nفتح الباري شرح صحيح البخاري، لابن حجر العسقلاني (1/ 374).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 226).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخن وغيره (1/ 740).\nشرح رياض الصالحين، لابن عثيمين (4/ 638).","benefits":["بيان شرف القرآن، وأنه خير الكلام؛ لأنه كلام الله.","خير المُتعلمين مَن يُعَلِّمُ غيرَه لا مَن يَقتصِرُ على نفسِه.","تَعَلُّمُ القرآنِ وتَعْلِيْمُه يشمل التلاوةَ والمعاني والأحكام."],"wordsMeanings":[],"category":"quran","bookId":"bukhari","tags":["خيركم","تعلم","القرآن","وعلمه"],"source":"hadeethenc"},{"id":"he_6208","text":"عن أبي هريرة رضي الله عنه: أن رسول الله صلى الله عليه وسلم قال: «لَا تَجْعَلُوا بُيُوتَكُمْ مَقَابِرَ، إِنَّ الشَّيْطَانَ يَنْفِرُ مِنَ الْبَيْتِ الَّذِي تُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يَنْهَى النبيُّ صلى الله عليه وسلم عن تعطيلِ البيوت من الصلاة فتكون كالمقابر التي لا يصلى فيها.\n\nثم أخبر صلى الله عليه وسلم أنَّ الشيطانَ يَنْفِرُ من البيت الذي تُقرأُ فيه سورةُ البقرة.","reference":"صحيح مسلم (1/ 539) (780).\nبهجة الناظرين، لسليم الهلالي (2/ 240).\nشرح رياض الصالحين، لابن عثيمين (4/ 682).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 757).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (4/ 1460).","benefits":["استحباب الإكثار من العبادات وصلاة النافلة في البيوت.","لا يجوز الصلاة في المقابر؛ لأنها وسيلة من وسائل الشرك والغلو في أصحابها، ما عدا صلاة الجنازة.","النهي عن الصلاة عند القبور قد تَقَرَّر عند الصحابة، ولذلك نهى النبي صلى الله عليه وسلم أن تُجعل البيوت مثل المقابر لا يُصلّى فيها."],"wordsMeanings":[{"word":"ينفر","meaning":" يصد ويعرض إعراضاً بالغاً."}],"category":"quran","bookId":"muslim","tags":["تجعلوا","بيوتكم","مقابر،","الشيطان","ينفر","البيت"],"source":"hadeethenc"},{"id":"he_6274","text":"عن أبي مسعود رضي الله عنه قال: قال النبي صلى الله عليه وسلم: «مَنْ قَرَأَ بِالْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنَّ مَن قَرأ الآيتين الأخيرتين من سورة البقرة في الليل فإنَّ الله يكفيه الشر والمكروه، وقيل: تكفيه عن قيام الليل، وقيل: تكفيه عن سائر الأوراد، وقيل: إنهما أقلُّ ما يجزىء من قراءة القرآن في قيام الليل، وقيل غير ذلك، ولعل كلَّ ما ذُكِرَ صحيح يَشملُه اللفظ.","reference":"صحيح البخاري (6/ 188) (5008-5009).\nصحيح مسلم (1/ 554) (807).\nفتح الباري بشرح صحيح البخاري، لابن حجر (9/ 56).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 240).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص593).\nمرقاة المفاتيح شرح مشكاة المصابيح، لملا علي القاري (4/ 1465).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 757).","benefits":["بيان فضل أواخر سورة البقرة، وهي من قوله تعالى : (آمن الرسول ...)  إلى آخر السورة.","أواخر سورة البقرة تدفع عن صاحبها السوءَ والشرَّ والشيطانَ إذا قرأها من الليل.","الليلة تبدأ بغروب الشمس، وتنتهي بطلوع الفجر."],"wordsMeanings":[],"category":"quran","tags":["قرأ","بالآيتين","آخر","سورة","البقرة","ليلة"],"source":"hadeethenc"},{"id":"he_6275","text":"عن عبد الله بن مسعود رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ قَرَأَ حَرْفًا مِنْ كِتَابِ اللهِ فَلَهُ بِهِ حَسَنَةٌ، وَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا، لَا أَقُولُ {الم} حَرْفٌ، وَلَكِنْ {أَلِفٌ} حَرْفٌ، وَ{لَامٌ} حَرْفٌ، وَ{مِيمٌ} حَرْفٌ».","attribution":"رواه الترمذي","grade":"حسن","gradeKey":"hasan","explanation":"أَخْبرَ النبيُّ صلى الله عليه وسلم أنَّ كلَّ مسلمٍ يقرأ حرفًا من كتاب اللّه فله به حسنة، ويُضاعَفُ له الأجرُ إلى عشَرةِ أمثالِه.\n\nثم بَيَّنَ ذلك بقوله: (لا أقول \"ألم\" حرف، ولكن ألف حرف، ولام حرف، وميم حرف): فتكون ثلاثة فيها ثلاثون حسنة.","reference":"سنن الترمذي (5/ 33) (2910).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 229).\nسلسلة الأحاديث الصحيحة، للألباني (7/ 970).\nشرح رياض الصالحين، لابن عثيمين (4/ 655).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 742).","benefits":["الحث على الإكثار من تلاوة القرآن.","للقارئ بكل حرف من كل كلمة يتلوها حسنة مضاعفة بعشر أمثالها.","سعة رحمة الله وكرمه حيث ضاعف للعباد الأجر فضلًا منه وكرمًا.","فضل القرآن على غيره من الكلام، والتعبد بتلاوته؛ وذلك بأنه كلام الله تعالى."],"wordsMeanings":[],"category":"quran","bookId":"tirmidhi","tags":["قرأ","حرفا","كتاب","الله","فله","حسنة،"],"source":"hadeethenc"},{"id":"he_8402","text":"عن عائشة رضي الله عنها قالت: كَانَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ اللهَ عَلَى كُلِّ أَحْيَانِهِ.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"تُخْبِرُ عائشةُ أمُّ المؤمنين رضي الله عنها أنَّ النبيَّ صلى الله عليه وسلم كان شديدَ الحِرْصِ على ذِكْرِ الله تعالى، وأنَّه كان يَذكرُ اللهَ تعالى في كلِّ زمانٍ ومكانٍ وحالٍ.","reference":"صحيح مسلم (1/ 282) (373).\nصحيح البخاري (1/ 68)، (1/ 129).\nتوضيح الأحكام مِن بلوغ المرام، للبسام (1/ 315).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (1/ 273).\nمجموع فتاوى ومقالات، لابن باز (26/ 17).","benefits":["لا تُشترط الطهارةُ من الحَدَثِ الأصغر والأكبر لذِكْر الله تعالى.","مداومة النبي صلى الله عليه وسلم لذِكْر الله تعالى.","الحث على الإكثار من ذكر الله تعالى في كل الأحيان اقتداء بالنبي صلى الله عليه وسلم، إلا في الحالات التي يمتنع فيها عن الذكر، كقضاء الحاجة."],"wordsMeanings":[],"category":"quran","bookId":"muslim","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_65099","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللهُ عنه سَمِعْتُ رَسُولَ اللهِ صلى الله عليه وسلم يَقُولُ: «قَالَ اللهُ تَعَالَى: قَسَمْتُ الصَّلَاةَ بَيْنِي وَبَيْنَ عَبْدِي نِصْفَيْنِ، وَلِعَبْدِي مَا سَأَلَ، فَإِذَا قَالَ الْعَبْدُ: {الْحَمْدُ لِلهِ رَبِّ الْعَالَمِينَ}، قَالَ اللهُ تَعَالَى: حَمِدَنِي عَبْدِي، وَإِذَا قَالَ: {الرَّحْمَنِ الرَّحِيمِ}، قَالَ اللهُ تَعَالَى: أَثْنَى عَلَيَّ عَبْدِي، وَإِذَا قَالَ: {مَالِكِ يَوْمِ الدِّينِ}، قَالَ: مَجَّدَنِي عَبْدِي، -وَقَالَ مَرَّةً: فَوَّضَ إِلَيَّ عَبْدِي-، فَإِذَا قَالَ: {إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ}، قَالَ: هَذَا بَيْنِي وَبَيْنَ عَبْدِي وَلِعَبْدِي مَا سَأَلَ، فَإِذَا قَالَ: {اهْدِنَا الصِّرَاطَ الْمُسْتَقِيمَ، صِرَاطَ الَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلا الضَّالِّينَ}، قَالَ: هَذَا لِعَبْدِي وَلِعَبْدِي مَا سَأَلَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنَّ الله تعالى قال في الحديث القدسي: قسمت سورة الفاتحة في الصلاة بيني وبين عبدي نصفين، لي نصفُها، وله نصفُها.\n\nفنصفُها الأول: حمدٌ وثناءٌ وتمجيدٌ لله، أجزيه عليه خير الجزاء.\n\nونصفُها الثاني: تَضَرُّعٌ ودعاء، أستجيب له وأعطيه ما سأل. \n\nفإذا قال المصلي: {الحمد لله رب العالمين}، قال الله: حمدني عبدي، وإذا قال: {الرحمن الرحيم}، قال الله: أثنى عليَّ عبدي فمدحني واعتراف لي بعموم الإنعام على خَلْقي، وإذا قال: {مالك يوم الدين}، قال الله: مَجَّدني عبدي، وهو الشرف الواسع.\n\nفإذا قال: {إياك نعبد وإياك نستعين}، قال الله: هذا بيني وبين عبدي.\n\nفالنصف الأول من هذه الآية لله وهو: (إياك نعبد) وهو اعتراف بالألوهية لله، والاستجابة بالعبادة، وبه ينتهي النصف الذي لله. \n\nوالنصف الثاني من الآية وهو للعبد: (إياك نستعين) طلب العون من الله، ووعده بالإعانة.\n\nفإذا قال: {اهدنا الصراط المستقيم * صراط الذين أنعمت عليهم غير المغضوب عليهم ولا الضالين}، قال الله: هذا تضرُّع ودعاء من عبدي، ولعبدي ما سأل، وقد أجبتُ دعاءه.","reference":"صحيح مسلم (1/ 296) (395)، إكمال المعلم (2/275)، المفهم لما أشكل من تلخيص كتاب مسلم (2/ 27)، شرح النووي على مسلم (4/103)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (9/ 232) (9/ 253).","benefits":["هذا الحديث مما يرويه النبي صلى الله عليه وسلم عن ربه، ويسمى بالحديث القدسي أو الإلهي، وهو الذي لفظه ومعناه من الله، غير أنه ليست فيه خصائص القرآن التي امتاز بها عما سواه، من التعبد بتلاوته والطهارة له والتحدي والإعجاز وغير ذلك.","عظم شأن الفاتحة فقد سماها الله تعالى (الصلاة).","بيان عناية الله تعالى بعبده، حيث مَدَحَه بسبب حَمْدِه وثنائِه وتمجيدِه، ووَعدَه أنْ يُعطيَه ما سأل.","اشتملت هذه السورة الكريمة، على حمد الله، وذكر المعاد، ودعاء الله، وإخلاص العبادة له، وسؤال الهداية إلى الصراط المستقيم، والتحذير من مسالك الباطل.","استشعار المصلي هذا الحديث -اذا قرأ الفاتحة- يَزيدُ مِن خشوعِه في الصلاة."],"wordsMeanings":[],"category":"quran","bookId":"muslim","tags":["قال","الله","تعالى:","قسمت","الصلاة","بيني"],"source":"hadeethenc"},{"id":"he_3410","text":"عن سَعِيدِ بْنِ الْمُسَيَّبِ، عَنْ أَبِيهِ قَالَ: لَمَّا حَضَرَتْ أَبَا طَالِبٍ الْوَفَاةُ، جَاءَهُ رَسُولُ اللهِ صلى الله عليه وسلم فَوَجَدَ عِنْدَهُ أَبَا جَهْلٍ وَعَبْدَ اللهِ بْنَ أَبِي أُمَيَّةَ بْنِ الْمُغِيرَةِ، فَقَالَ: «أَيْ عَمِّ، قُلْ: لَا إِلَهَ إِلَّا اللهُ، كَلِمَةً أُحَاجُّ لَكَ بِهَا عِنْدَ اللهِ»، فَقَالَ أَبُو جَهْلٍ وَعَبْدُ اللهِ بْنُ أَبِي أُمَيَّةَ: أَتَرْغَبُ عَنْ مِلَّةِ عَبْدِ الْمُطَّلِبِ، فَلَمْ يَزَلْ رَسُولُ اللهِ صلى الله عليه وسلم يَعْرِضُهَا عَلَيْهِ، وَيُعِيدَانِهِ بِتِلْكَ الْمَقَالَةِ، حَتَّى قَالَ أَبُو طَالِبٍ آخِرَ مَا كَلَّمَهُمْ: عَلَى مِلَّةِ عَبْدِ الْمُطَّلِبِ، وَأَبَى أَنْ يَقُولَ: لَا إِلَهَ إِلَّا اللهُ، قَالَ: قَالَ رَسُولُ اللهِ صلى الله عليه وسلم: «وَاللهِ لَأَسْتَغْفِرَنَّ لَكَ مَا لَمْ أُنْهَ عَنْكَ»، فَأَنْزَلَ اللهُ: {مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ} [التوبة: 113]، وَأَنْزَلَ اللهُ فِي أَبِي طَالِبٍ، فَقَالَ لِرَسُولِ اللهِ صلى الله عليه وسلم: {إِنَّكَ لا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللهَ يَهْدِي مَنْ يَشَاءُ} [القصص: 56].","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"دَخَلَ النبيُّ صلى الله عليه وسلم على عَمِّه أبي طالب وهو يَحْتَضِرُ، فقال له: \nيا عم، قل \"لا إله إلا الله\"، كلمة أشهد لك بها عند الله، \nفقال أبو جهل وعبد الله بن أبي أمية: يا أبا طالب، تترك ملة أبيك عبد المطلب؟! وهي عبادة الأصنام، فلم يزالا يُكلِّمانه حتى قال آخر شيء كلَّمهم به: على مِلَّةِ عبد المطلب، ملة الشرك وعبادة الأصنام، \nفقال النبي صلى الله عليه وسلم: سأدعوا لك بالمغفرة ما لم ينهني ربي عن ذلك، فنزل قول الله تعالى: \n{مَا كَانَ لِلنَّبِيِّ وَالَّذِينَ آمَنُوا أَنْ يَسْتَغْفِرُوا لِلْمُشْرِكِينَ وَلَوْ كَانُوا أُولِي قُرْبَى مِنْ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَابُ الْجَحِيمِ} [التوبة: 113]، \nونزل في أبي طالب قول الله تعالى: \n{إِنَّكَ لا تَهْدِي مَنْ أَحْبَبْتَ وَلَكِنَّ اللَّهَ يَهْدِي مَنْ يَشَاءُ وَهُوَ أَعْلَمُ بِالْمُهْتَدِينَ} [القصص: 56]، \nفإنك لا تهدي مَن أحببتَ هدايتَه، إنما عليك البلاغ، والله يهدي من يشاء.","reference":"صحيح البخاري (6/ 112) (4772).\nصحيح مسلم (1/ 54) (24).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص155).\nالجديد في شرح كتاب التوحيد، للقرعاوي (ص169).","benefits":["تحريم الاستغفار للمشركين مهما كانت قرابتهم وعملهم وإحسانهم.","تقليدُ الآباء والأكابر بالباطل مِن فِعْل أهل الجاهلية.","كمالُ شفقة النبيِّ صلى الله عليه وسلم وحرصِه على دعوة الناس وهدايتهم.","الرد على مَن زعم إسلام أبي طالب.","الأعمال بالخواتيم.","بطلان التعلُّق بالنبيِّ عليه الصلاة والسلام وغيره لِجَلْب النفع أو دفع الضرر.","من قال \"لا إله إلا الله\" عن علمٍ ويقين واعتقادٍ دخل في الإسلام.","مضرة أصحاب السوء وقرناء الشر على الإنسان.","معنى \"لا إله إلا الله\": تركُ عبادة الأصنام والأولياء والصالحين وإفراد الله بالعبادة، وأنّ المشركين يعرفون معناها.","جواز عيادة المريض المشرك إذا رُجي إسلامُه.","هداية التوفيق بيد الله وحده لا شريك له،  وإنما على الرسول صلى الله عليه وسلم هداية الدلالة والإرشاد والبلاغ."],"wordsMeanings":[],"category":"quran","tags":["عم،","قل:","إله","إلا","الله،","كلمة"],"source":"hadeethenc"},{"id":"he_6258","text":"عَن أَبي مُوْسى الأَشْعريِّ رضي الله عنه قال: قال رسولُ اللهِ صلى اللهُ عليه وسلم: «مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْأُتْرُجَّةِ، رِيحُهَا طَيِّبٌ وَطَعْمُهَا طَيِّبٌ، وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ التَّمْرَةِ، لَا رِيحَ لَهَا وَطَعْمُهَا حُلْوٌ، وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الرَّيْحَانَةِ، رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ، وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ، لَيْسَ لَهَا رِيحٌ وَطَعْمُهَا مُرٌّ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أقسامَ الناسِ في قراءة القرآن والانتفاع به: \n\nفالقسم الأول: المؤمن الذي يقرأ القرآنَ وينتفع به، فهو كَثَمَرَةِ الأترجة، طَيِّبُ الطعم والرائحة وحَسَن اللون، ومنافعه كثيرة، فهو يعمل بما يقرأ، وينفع عبادَ الله. \n\nالثاني: المُؤمن الذي لا يقرأ القرآن، فهو كالتَّمْرَة، طعمُها حُلْو، ولا ريح لها، فقلبُه مُشتملٌ على الإيمان كاشتمال التمرة على الحلاوة في طعمها وباطنها، وعدم ظهور ريح لها يَشُمُّه الناسُ؛ لعدم ظهور قراءة منه يرتاح الناس بسماعها. \n\nالثالث: المنافق الذي يقرأ القرآن، فهو كالريحانة، لها رائحة طيبة وطعمها مُرّ، حيث لم يُصلِح قلبَه بالإيمان، ولم يعملْ بالقرآن، ويَظهرُ أمامَ الناس أنه مؤمن، فريحُها الطيب يُشبه قراءتَه، وطعمُها المُرُّ يُشبه كُفرَه. \n\nالرابع: المنافق الذي لا يقرأ القرآن، فهو كالحَنْظَلَة، حيثُ إنها لا رائحة لها، ومُرٌّ مذاقُها، فانعدام ريحِها أَشبَهَ انعدامَ ريحِه؛ لعدم قراءته، ومَرَارةُ طعمِها شَبيهٌ بمرارة كفرِه، فباطنُه خَالٍ من الإيمان، وظاهره لا نفع فيه، بل هو ضارٌّ.","reference":"صحيح البخاري (7/ 77) (5427).\nصحيح مسلم (1/ 549) (797).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 227).\nنزهة المتقين، لجمعٌ من المشايخ (1/ 741).\nكنوز رياض الصالحين، لمجموعة من الباحثين (12/ 568).\nشرح رياض الصالحين، للعثيمين (4/ 642).","benefits":["بيان فضيلة حامل القرآن العامل به.","مِن طُرُق التعليم ضَرْبُ المَثَل؛ لتقريب الفهم.","ينبغي للمسلم أن يكونَ له وِرْدٌ مُسْتَمِرٌّ مِن كتاب الله تعالى."],"wordsMeanings":[],"category":"quran","tags":["مثل","المؤمن","الذي","يقرأ","القرآن","كمثل"],"source":"hadeethenc"},{"id":"he_6276","text":"عن أبي لبابة بشير بن عبد المنذر رضي الله عنه : أن النبي صلى الله عليه وسلم قال: «مَن لَم يَتَغنَّ بِالقُرآنِ فَليسَ مِنَّا».","attribution":"رواه أبو داود","grade":"صحيح","gradeKey":"sahih","explanation":"حث النبي صلى الله عليه وسلم في هذا الحديث على التغني بالقرآن، وهذه الكلمة لها معنيان؛ الأول: من لم يتغن به، أي: من لم يحسن صوته بالقرآن فليس من أهل هدينا وطريقتنا، والمعنى الثاني: من لم يستغن به عن غيره بحيث يطلب الهدى من سواه فليس منا، ولا شك أن من طلب الهدى من غير القرآن أضله الله والعياذ بالله، فيدل الحديث على أنه ينبغي للإنسان أن يحسن صوته بالقرآن، وأن يستغنى به عن غيره.","reference":"1- بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.-الطبعة الأولى 1418ه.\n2- رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n3- سنن أبي داود؛ للإمام أبي داود سليمان بن الأشعث السجستاني، تعليق عزت الدعاس وغيره، دار ابن حزم-بيروت، الطبعة الأولى، 1418هـ.\n4- شرح رياض الصالحين؛ للشيخ محمد بن صالح العثيمين، مد","benefits":["الحث على تحسين الصوت بالقرآن، دون تمطيط أو تلحين يخرجه إلى حد الغناء المذموم, وأن يستغنى به عن غيره.","من لم يتغن بالقرآن فليس من أهل سنة النبي -صلى الله عليه وسلم- وهديه."],"wordsMeanings":[{"word":"فليس منا","meaning":" ليس من أهل هدينا وطريقتنا."},{"word":"يتغن","meaning":" يُحَسِّنُ صَوْتَهُ بِالقُرْآنِ."}],"category":"quran","bookId":"abudawud","tags":["يتغن","بالقرآن","فليس","منا"],"source":"hadeethenc"},{"id":"he_10112","text":"عن أبي سعيد رافع بن المعلى رضي الله عنه قال: قال لي رسول الله صلى الله عليه وسلم : «أَلاَ أُعَلِّمُكَ أَعْظَمَ سُورَةٍ في القُرْآن قَبْلَ أنْ تَخْرُجَ مِنَ الْمَسْجِد؟» فَأخَذَ بِيَدِي، فَلَمَّا أرَدْنَا أنْ نَخْرُجَ، قُلْتُ: يَا رَسُولَ اللهِ، إنَّكَ قُلْتَ: لأُعَلِّمَنَّكَ أعْظَمَ سُورَةٍ في القُرْآنِ؟ قالَ: «الحَمْدُ للهِ رَبِّ العَالَمِينَ، هِيَ السَّبْعُ المَثَانِي وَالقُرْآنُ العَظِيمُ الَّذِي أُوتِيتُهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"عن أبي سعيد رافع بن المعلى رضي الله عنه قال: قال لي رسول اللّه صلى الله عليه وسلم : \"ألا\" أتى بها لتنبيه المخاطب لما يلقى إليه بعدها، قوله: \"أعلمك أعظم سورة في القرآن قبل أن تخرج من المسجد\"، وإنما قال له ذلك، ولم يعلمه بها ابتداء؛ ليكون أدعى إلى تفريغ ذهنه لتلقيها وإقباله عليها بكليته، قوله: \"فأخذ بيدي\"، أي: بعد أن قال ذلك ومشينا، قوله: \"فلما أردنا أن نخرج قلت: يا رسول اللّه إنك قلت: لأعلمنك أعظم سورة في القرآن\"، قوله: \"قال: الحمد للّه ربّ العالمين\"، أي: سورة الفاتحة، وإنما كانت أعظم سورة لأنها جمعت جميع مقاصد القرآن، ولذا سميت بأم القرآن. ثم أشار إلى ما تميزت به الفاتحة عن غيرها من بقية السور حتى صارت أعظم منها، بقوله: \"هي السبع المثاني\"، أي: المسماة به، جمع مثناة من التثنية لأنها تثنى في الصلاة في كل ركعة، أو لأنها تثنى بسورة أخرى، أو سميت بذلك لاشتمالها على قسمين: ثناء ودعاء، أو لما اجتمع فيها من فصاحة المباني وبلاغة المعاني، أو لأنها تثنى على مرور الزمان وتتكرر فلا تنقطع وتدرس فلا تندرس، أو لأن فوائدها تتجدد حالاً فحالاً إذ لا منتهى لها، أو جمع مثناه من الثناء لاشتمالها على ما هو ثناء على اللّه تعالى، فكأنها تثنى عليه بأسمائه الحسنى وصفاته، أو من الثنايا لأن اللّه استثناها لهذه الأمة، وغير ذلك، قوله: \"والقرآن العظيم\"، أي: وهي المسماة بذلك أيضاً، قوله: \"الذي أوتيته\"، أي: أعطيته، وتسميتها بالقرآن العظيم لجمعها سائر ما يتعلق بالموجودات دنيا وأخرى وأحكاماً وعقائد.","reference":"1-بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.ط 1-1415\n2-دليل الفالحين لطرق رياض الصالحين؛ لمحمد بن علان الشافعي، دار الكتاب العربي-بيروت.\n3-رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n4-صحيح البخاري –الجامع الصحيح-؛ للإمام أبي عبدالله محمد بن إسماعيل البخاري، عناية محمد زهير الناصر، دار طوق الن","benefits":["سورة الفاتحة أعظم سورة في كتاب الله -تبارك وتعالى-.","تفضيل بعض القرآن على بعض بما جاء عن رسول الله -صلى الله عليه وسلم- في ذلك.","حرص الرسول -صلى الله عليه وسلم- على تعليم الناس الخير، وبيانه لهم.","أن الفاتحة سبع آيات."],"wordsMeanings":[{"word":"الحمد لله رب العالمين","meaning":" سورة الفاتحة."},{"word":"السبع المثاني","meaning":" السبع الآيات التي تثنى أي تقرأ في كل ركعة من الصلاة."}],"category":"quran","bookId":"bukhari","tags":["ألا","أعلمك","أعظم","سورة","القرآن"],"source":"hadeethenc"},{"id":"he_10113","text":"عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «الْمَاهِرُ بِالْقُرْآنِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ، وَالَّذِي يَقْرَأُ الْقُرْآنَ وَيَتَتَعْتَعُ فِيهِ، وَهُوَ عَلَيْهِ شَاقٌّ، لَهُ أَجْرَانِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم أن الذي يقرأ القرآن، وهو جيّد الحفظ مُتقن له، وماهر وحاذق بقراءته، له من الثواب في الآخرة أن تكون منزلته مع الملائكة السفرة الكرام البررة، وأن الذي يقرأ القرآن ويتتعتع فيه ويتردد في تلاوته؛ لِضَعف حفظه وهو مع ذلك يتعاهده، وهو عليه شديد وشاقٌّ فله أجران؛ أجر بالقراءة وأجر للمشقة وتردده في تلاوته.","reference":"صحيح البخاري (6/ 166) (4937).\nصحيح مسلم (1/ 549) (798).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 226).\nتحفة الأحوذي بشرح جامع الترمذي، لمحمد المباركفوري (8/ 174).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص580).\nشرح رياض الصالحين، لابن عثيمين (4/ 639).\nشرح كتاب التوحيد من صحيح البخاري، لعبدالله الغنيمان (2/ 592).\nفتح الباري بشرح صحيح البخاري، لابن حجر العسقلاني (9/ 127).\nكنوز رياض الصالحين، ل","benefits":["الحث على حفظ القرآن وإتقانه وكثرة تلاوته لنوال الأجر والثواب، وبيان علو منزلة من فعل ذلك.","قال القاضي: وليس معناه أن الذي يتتعتع عليه له من الأجر أكثر من الماهر به، بل الماهر أفضل وأكثر أجرًا؛ لأنه مع السفرة وله أجور كثيرة، ولم يذكر هذه المنزلة لغيره، وكيف يلحق به من لم يعتنِ بكتاب الله تعالى وحفظه وإتقانه وكثرة تلاوته ودرايته كاعتنائه حتى مَهَرَ فيه.","قال ابن باز: الذي يقرأ القرآن وهو ماهِرٌ فيه، يُجيد قراءَته، ويحفظه جيدًا مع السَّفَرة الكرام البَرَرة، يعني: إذا كان يتلوه قولًا وعملًا، لا مجرّد التلاوة فقط، يُجيد تلاوته، ويعمل به، فهو قائم به لفظًا ومعنًى."],"wordsMeanings":[],"category":"quran","tags":["الماهر","بالقرآن","السفرة","الكرام","البررة،","والذي"],"source":"hadeethenc"},{"id":"he_10114","text":"عن عقبة بن عامر رضي الله عنه : أن رسول الله صلى الله عليه وسلم قال: «ألَمْ تَرَ آيَاتٍ أُنْزِلَتْ هذِهِ اللَّيْلَةَ لَمْ يُرَ مِثْلُهُنَّ قَطُّ؟ (قل أعوذ برب الفلق) و(قل أعوذ برب الناس)».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"عن عقبة بن عامر رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : \"ألم تر\"، أي: ألم تعلم، وهو خطاب خاص للراوي، والمراد به عام للجميع، وهي كلمة تعجب، وأشار إلى سبب التعجب، بقوله: \"لم ير مثلهن\"، أي: في بابها وهو التعوذ، وقوله: \"قط\"، لتأكيد النفي، قوله: \"قل أعوذ برب الفلق\"، و \"قل أعوذ برب الناس\"، أي: لم توجد آيات سورة كلهن تعويذ للقارىء من شر الأشرار مثل هاتين السورتين، ما تعوذ بهما متعوذ عن إيمان وصدق إلا أعاذه الله عز وجل، فالحاصل أن الإنسان ينبغي أن يتعوذ بهاتين السورتين.","reference":"1-بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.-الدمام 1415\n2-رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n3-شرح رياض الصالحين؛ للشيخ محمد بن صالح العثيمين، مدار الوطن، الرياض، 1426هـ.\n4-صحيح مسلم؛ للإمام مسلم بن الحجاج، حققه ورقمه محمد فؤاد عبدالباقي، دار عالم الكتب-الرياض، الطبعة الأولى، 1417هـ.","benefits":["فضل سورتي الفلق والناس، وأنهن من خير ما أنزل على رسول الله -صلى الله عليه وسلم-.","اقتصار النبي –صلى الله عليه وسلم- عليهما في التعويذ؛ لاشتمالهما على الجوامع في المستعاذ به والمستعاذ منه."],"wordsMeanings":[{"word":"ألم تر","meaning":" استفهام يفيد تعجبًا."},{"word":"لم يُر مثلهن","meaning":" لم يوجد آيات مثلهن، ومما اختصتا به أنه لا توجد سورة كلها تعويذ غير هاتين السورتين."},{"word":"الفلق","meaning":" الصبح."}],"category":"quran","bookId":"muslim","tags":["ألم","آيات","أنزلت","هذه","الليلة","لَمْ"],"source":"hadeethenc"},{"id":"he_10842","text":"عن عائشة رضي الله عنها ، قالت: «إنْ كانَ لَيَنْزِلُ على رسولِ اللهِ صلى الله عليه وسلم في الغَدَاةِ الباردةِ، ثم تَفِيضُ جَبْهَتُه عَرَقًا».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"تخبر أم المؤمنين عائشة رضي الله عنها في هذا الحديث أن الوحي كان ينزل على رسول الله صلى الله عليه وسلم في الصباح البارد، فيسيل العرق من مقدمة رأسه بكثرة؛ لشدة الوحي عليه.","reference":"- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- المنهاج شرح صحيح مسلم بن الحجاج، للنووي، نشر: دار إحياء التراث العربي – بيروت، الطبعة: الثانية، 1392ه.\n- شرح سنن النسائي المسمى «ذخيرة العقبى في شرح المجتبى»، المؤلف: محمد بن علي بن آدم الإثيوبي الوَلَّوِي، الناشر: دار المعراج الدولية للنشر - دار آل بروم للنشر والتوزيع, الطبعة الأولى, 1416- 1424.\n- معجم اللغة العربية","benefits":["ما كان يحصل للنبي -صلى الله عليه وسلم- من الشدة أثناء نزول الوحي؛ حتى كان جبينه يسيل من العرق في اليوم البارد.","في هذا الحديث بيان أحد الصفات التي كان ينزل بها الوحي على النبي -صلى الله عليه وسلم-."],"wordsMeanings":[{"word":"الغَداة","meaning":" أول النهار."},{"word":"تَفِيض","meaning":" تسيل بكثرة."},{"word":"جَبْهته","meaning":" مقدمة الرأس."}],"category":"quran","bookId":"muslim","tags":["كان","لينزل","على","رسول","الله","صلى"],"source":"hadeethenc"},{"id":"he_10847","text":"عن البراء بن عازب رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : «زَيِّنُوا القرآنَ بأصواتِكم».","attribution":"رواه أبو داود والنسائي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"المراد زينوا القرآن بتحسين أصواتكم عند القراءة، فإن الكلام الحسن يزداد حسنًا وزينةً بالصوت الحسن، والحكمة في ذلك المبالغة في تدبر المعاني، والتفطن لما تضمنته الآيات من الأوامر والنواهي والوعد والوعيد؛ لأن النفس ميّالة طبعًا إلى استحسان الأصوات، وربما يتفرغ الفكر مع حسن الصوت عن الشوائب، فيكون الفكر مجتمعًا، وإذا اجتمع حصل المطلوب من الخشوع والخضوع، والمراد بتحسين الصوت -في الحديث- التحسين الذي يبعث على الخشوع، لا أصوات ألحان الغناء واللَّهو التي تخرج عن حدّ القراءة.","reference":"- سنن أبي داود، تحقيق: محمد محيي الدين عبد الحميد، نشر: المكتبة العصرية، صيدا – بيروت.\n- السنن الصغرى للنسائي \"المجتبى\"، تحقيق: عبد الفتاح أبو غدة، نشر: مكتب المطبوعات الإسلامية – حلب، الطبعة: الثانية، 1406ه – 1986م.\n- مسند الإمام أحمد بن حنبل، تحقيق: شعيب الأرنؤوط - عادل مرشد، وآخرون، نشر: مؤسسة الرسالة، الطبعة: الأولى، 1421هـ - 2001م.\n- سنن ابن ماجه، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء ا","benefits":["استحباب تزيين القرآن بتحسين الصوت.","الحكمة في ذلك المبالغة في تدبر المعاني، والتفطن لما تضمنته الآيات؛ لأن النفس ميّالة طبعًا إلى استحسان الأصوات الجميلة.","التزيين في الحديث هو التحسين الذي يبعث على الخشوع، لا أصوات ألحان الغناء واللَّهو التي تخرج عن حدّ القراءة."],"wordsMeanings":[{"word":"زينوا","meaning":" من التزيين وهو التحسين, والمراد هنا تزيينه بالترتيل، والجهر به، وتحسين الصوت بالقراءة."}],"category":"quran","bookId":"abudawud","tags":["زينوا","القرآن","بأصواتكم"],"source":"hadeethenc"},{"id":"he_10853","text":"عن عبد الله بن عمرو رضي الله عنهما : أنَّ نَفَرًا كانوا جُلوسًا بباب النبي صلى الله عليه وسلم ، فقال بعضُهم: ألم يَقُلِ اللهُ كذا وكذا؟ وقال بعضُهم: ألم يَقُلِ اللهُ كذا وكذا؟ فسمِعَ ذلك رسولُ الله صلى الله عليه وسلم ، فخرج كأنَّما فُقِئَ في وجهِه حَبُّ الرُّمَّان، فقال: «بهذا أُمِرْتُم؟ أو بهذا بُعِثْتم؟ أنْ تَضْربُوا كتابَ اللهِ بعضَه ببعض؟ إنَّما ضَلَّتِ الأُمَمُ قبلكم في مثل هذا، إنَّكم لستُم ممَّا هاهنا في شيء، انظروا الذي أُمِرتم به، فاعملوا به، والذي نُهِيتُم عنه، فانتهوا».","attribution":"رواه ابن ماجه وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"كان جماعة من الصحابة جالسين عند باب النبي صلى الله عليه وسلم ، فاختلفوا في مسألة، وفي بعض الروايات أنهم اختلفوا في القدر، فجعل بعضهم يستدل على قوله بآية من كتاب الله، وجعل الآخرون يستدلون بآية من كتاب الله، فسمع رسول الله صلى الله عليه وسلم ذلك، فخرج عليهم وقد غضب واحمر وجهه احمرارًا شديدًا، كأنما عُصِر حب الرمان في وجهه صلى الله عليه وسلم ، وقال لهم: هذا الاختلاف والجدال والتنازع في القرآن ومعارضة القرآن بعضه ببعض، هل هو المقصود من خلقكم؟ أو هو الذي أمركم الله به؟ يريد أنه ليس بشيء من الأمرين، فليس هناك حاجة إليه، وأخبرهم أن سبب ضلال الأمم قبلهم في مثل هذا الأمر، ثم أرشدهم إلى ما فيه صلاحهم ونفعهم فقال: ما أمركم الله به فافعلوه وما نهاكم عنه فانتهوا عنه، هذا هو الذي خُلقتم من أجله، وهذا الذي فيه نفعكم وصلاحكم.","reference":"- مسند الإمام أحمد بن حنبل، تحقيق: شعيب الأرنؤوط - عادل مرشد، وآخرون، نشر: مؤسسة الرسالة، الطبعة: الأولى، 1421هـ - 2001م.\n- سنن ابن ماجه، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء الكتب العربية - فيصل عيسى البابي الحلبي.\n- السنة، لابن أبي عاصم، ومعه ظلال الجنة، تحقيق: محمد ناصر الدين الألباني، نشر: المكتب الإسلامي – بيروت، الطبعة: الأولى، 1400ه.\n- مرقاة المفاتيح شرح مشكاة المصابيح، لعلي بن سلطان","benefits":["النهي عن الاختلاف والجدال في القرآن.","سبب ضلال الأمم السابقة هو الجدال والاختلاف في كتاب الله -تعالى-.","الذي ينبغي أن يحرص عليه المسلم هو فعل ما أمره الله به وترك ما نهى الله عنه."],"wordsMeanings":[{"word":"فُقِئ","meaning":" عُصر."}],"category":"quran","bookId":"ibnmajah","tags":["بهذا","أمرتم؟","بهذا","بعثتم؟","تضربوا","كتاب"],"source":"hadeethenc"},{"id":"he_10854","text":"عن عبد الله بن عمرو رضي الله عنهما أن النبي صلى الله عليه وسلم قال: «لا تُجادِلوا في القرآن؛ فإنَّ جِدالًا فيه كُفرٌ».","attribution":"رواه أبو داود الطيالسي","grade":"صحيح","gradeKey":"sahih","explanation":"نهى النبي صلى الله عليه وسلم عن الجدال في القرآن؛ لأنه يؤدي إلى كفر؛ وذلك لأن الإنسان قد يسمع قراءة آية أو كلمة لم تكن عنده، ولا علم له بها فيتسرع ويخطِّئ القارئ وينسِب ما يقرؤه إلى أنه غير قرآن، أو يجادله في معنى آية لا علم له بها ويضلله، والجدال ربما صرفه عن الحق وإن ظهر له وجهه، فلذلك حُرِّم وسُمِّي كفرًا؛ لأنه يؤدي بصاحبه إلى الكفر، ومتى سلم الإنسان من ذلك كله فهو مباح أو محمود، كمن يسأل للتعلم أو لإظهار الحق، كما قال تعالى : {وجادلهم بالتي هي أحسن}.","reference":"-مسند أبي داود الطيالسي، المؤلف: أبو داود سليمان بن داود بن الجارود الطيالسي البصرى، المحقق: الدكتور محمد بن عبد المحسن التركي، الناشر: دار هجر – مصر، الطبعة: الأولى، 1419 هـ - 1999 م.\n-فيض القدير شرح الجامع الصغير، للمناوي، المكتبة التجارية الكبرى – مصر، الطبعة: الأولى.\n-سلسلة الأحاديث الصحيحة وشيء من فقهها وفوائدها، تأليف محمد ناصر الدين الألباني، الناشر: مكتبة المعارف للنشر والتوزيع، الرياض، ال","benefits":["النهي عن الجدال في القرآن.","الجدال في القرآن بما يؤدي إلى رده أو رد بعضه أو تكذيب ما جاء فيه من الحق يؤدي بصاحبه إلى الكفر.","المراد بالجدل المنهي عنه في الحديث: الجدال على الباطل, وأما طلب المغالبة لإظهار الحق, فإنه محمود كما قال -تعالى-: {وجادلهم بالتي هي أحسن}.","ينبغي على صاحب القرآن والسنة صيانتهما عن ذكر أدلتهما لمن لا يُنصِفُ من كافرٍ ومبتدع, ولا يعرضهما لمن هو أحذقُ منه بالجدل، وأبرعُ في المراء؛ لأن ذلك قد يكون سببًا في خذلان الحق."],"wordsMeanings":[{"word":"الجدال","meaning":" المناظرة والمخاصمة، والمراد هنا الجدل على الباطل."}],"category":"quran","bookId":"abudawud","tags":["تجادلوا","القرآن","فإن","جدالًا","فيه","كفر"],"source":"hadeethenc"},{"id":"he_64642","text":"عن عقبة بن عامر قال: سمعت رسول الله صلى الله عليه وسلم وهو على المنبر، يقول: \"{وأعدوا لهم ما استطعتم من قوة} [الأنفال: 60]، ألا إن القُوَّةَ الرَّميُ، ألا إن القوة الرمي، ألا إن القوة الرمي\".","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أفاد الحديث تفسير النبي صلى الله عليه وسلم للقوة المأمور باتخاذها في مجابهة الأعداء والكفرة، وهي الرمي؛ لأنه أنكى، وأبعد عن خطر العدو، وكان الرمي وقت نزول الآية الكريمة بالسهام، ولكن الآية بإعجازها أطلقت القوة؛ لتكون قوة كل زمان ومكان، وكذلك الحديث الشريف جاء إعجازه العلمي بإطلاق الرمي، الذي يشتمل الرمي بأنواعه، وأن يفسر بكل رمي يتجدد وبأي سلاح يحدث.","reference":"- صحيح مسلم؛ للإمام مسلم بن الحجاج، حققه ورقمه محمد فؤاد عبد الباقي، دار عالم الكتب-الرياض، الطبعة الأولى، 1417هـ.\n- منحة العلام في شرح بلوغ المرام: تأليف عبد الله الفوزان، طبعة دار ابن  الجوزي، الطبعة الأولى 1428.\n- توضيح الأحكام شرح بلوغ المرام: تأليف عبد الله البسام، مكتبة الأسدي، مكة المكرمة، الطبعة: الخامِسَة، 1423 هـ - 2003 م.\n- تسهيل الإلمام بفقه الأحاديث من بلوغ المرام:تأليف الشيخ صالح الف","benefits":["قال الله -تعالى-: {وأعدوا لهم ما استطعتم من قوة} [الأنفال: 60] في هذه الآية الكريمة يأمر -تعالى- عباده المؤمنين أن يقوموا بالجهاد في  سبيل الله تعالى، وأن يستعدوا له بكل ما يقدرون عليه من أسباب القوة في وجه أعداء الإسلام، والقوة تختلف باختلاف الأزمنة والأمكنة، فكانت الآية مطلقة التفسير في كل زمان بما يناسبها.","كل ما يقدر عليه المسلمون من القوة العقلية والبدنية والعلمية داخل في ذلك كله، فيدخل في هذه القوة أنواع الأسلحة من المدافع والرشاشات والطائرات المقاتلة والمدرعات والدبابات وجميع آلات القتال المناسبة.","أن النبي -صلى الله عليه وسلم- يفسر القرآن، ومن ذلك تفسيره لهذه الآية في سورة الأنفال.","يستفاد من الحديث طلب تعلم الرمي، لأنه داخل في الأمر بإعداد العدة."],"wordsMeanings":[{"word":"أعدوا","meaning":" أمر من: الإعداد، وهو تهيئة الشيء للمستقبل."},{"word":"ما استطعتم","meaning":" لفظ عام يشمل جميع إمكانات الإنسان حسب الظروف والأوضاع."},{"word":"رباط الخيل","meaning":" بكسر الراء، هو في الأصل: حبسها، واقتناؤها، ثم سمي الإقامة في ثغور البلاد، وحدودها: رباطا."},{"word":"ألا إن القوة الرمي","meaning":" يعني: أن الآية الكريمة تشير إلى أن القوة هي في الرمي؛ لأنه أنكى، وأبعد عن خطر العدو، وكان الرمي وقت نزول الآية الكريمة بالسهام، ولكن الآية بإعجازها أطلقت القوة؛ لتكون قوة كل زمان ومكان، وكذلك الحديث الشريف جاء إعجازه العلمي بإطلاق الرمي، الذي يشتمل الرمي بأنواعه، وأن يفسر بكل رمي يتجدد وبأي سلاح يحدث."}],"category":"quran","bookId":"muslim","tags":["ألا","القوة","الرمي،","ألا","القوة","الرمي،"],"source":"hadeethenc"},{"id":"he_65026","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ: أَنَّ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «لاَ تَقُومُ السَّاعَةُ حَتَّى تَطْلُعَ الشَّمْسُ مِنْ مَغْرِبِهَا، فَإِذَا طَلَعَتْ فَرَآهَا النَّاسُ آمَنُوا أَجْمَعُونَ، فَذَلِكَ حِينَ: {لاَ يَنْفَعُ نَفْسًا إِيمَانُهَا لَمْ تَكُنْ آمَنَتْ مِنْ قَبْلُ، أَوْ كَسَبَتْ فِي إِيمَانِهَا خَيْرًا} [الأنعام: 158] وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ نَشَرَ الرَّجُلاَنِ ثَوْبَهُمَا بَيْنَهُمَا فَلاَ يَتَبَايَعَانِهِ، وَلاَ يَطْوِيَانِهِ، وَلَتَقُومَنَّ السَّاعَةُ وَقَدِ انْصَرَفَ الرَّجُلُ بِلَبَنِ لِقْحَتِهِ فَلاَ يَطْعَمُهُ، وَلَتَقُومَنَّ السَّاعَةُ وَهُوَ يَلِيطُ حَوْضَهُ فَلاَ يَسْقِي فِيهِ، وَلَتَقُومَنَّ السَّاعَةُ وَقَدْ رَفَعَ أَحَدُكُمْ أُكْلَتَهُ إِلَى فِيهِ فَلاَ يَطْعَمُهَا».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر رسول الله صلى الله عليه وسلم أن من علامات الساعة الكبرى أن تطلع الشمس من المغرب بدلًا من المشرق، وعندما يراها الناس يؤمنون جميعًا، \nفعند ذلك لا ينفع الكافرَ إيمانُه، ولا ينفع العمل الصالح ولا التوبة. \nثم أخبر صلى الله عليه وسلم أن الساعة تأتي بغتة؛ حتى إنها تقوم والناس في أحوالهم وشؤون حياتهم؛ \nفتقوم الساعة والبائع والمشتري قد نشرا ثوبهما بينهما فلا يتبايعانه، ولا يطويانه، \nوتقوم الساعة والرجل قد أخذ لبن ناقته الحلوب فلا يشربه، \nوتقوم الساعة والرجل يصلح حوضه ويُطيِّنُه فلا يسقي فيه، \nوتقوم الساعة والرجل قد رفع لقمته إلى فمه ليأكل فلا يأكلها.","reference":"صحيح البخاري (8/ 106) (6506)، صحيح مسلم (1/ 137) (157)، عمدة القاري شرح صحيح البخاري (23/ 92).","benefits":["الإسلام والتوبة مقبولة ما لم تطلع الشمس من مغربها.","الحث على الاستعداد للساعة بالإيمان والعمل الصالح؛ لأن الساعة تأتي بغتة."],"wordsMeanings":[],"category":"quran","tags":["تقوم","الساعة","حتى","تطلع","الشمس","مغربها،"],"source":"hadeethenc"},{"id":"he_65035","text":"عَنْ أَبِي سَعِيدٍ الخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «يُؤْتَى بِالْمَوْتِ كَهَيْئَةِ كَبْشٍ أَمْلَحَ، فَيُنَادِي مُنَادٍ: يَا أَهْلَ الجَنَّةِ، فَيَشْرَئِبُّونَ وَيَنْظُرُونَ، فَيَقُولُ: هَلْ تَعْرِفُونَ هَذَا؟ فَيَقُولُونَ: نَعَمْ، هَذَا المَوْتُ، وَكُلُّهُمْ قَدْ رَآهُ، ثُمَّ يُنَادِي: يَا أَهْلَ النَّارِ، فَيَشْرَئِبُّونَ وَيَنْظُرُونَ، فَيَقُولُ: وهَلْ تَعْرِفُونَ هَذَا؟ فَيَقُولُونَ: نَعَمْ، هَذَا المَوْتُ، وَكُلُّهُمْ قَدْ رَآهُ، فَيُذْبَحُ ثُمَّ يَقُولُ: يَا أَهْلَ الجَنَّةِ خُلُودٌ فَلاَ مَوْتَ، وَيَا أَهْلَ النَّارِ خُلُودٌ فَلاَ مَوْتَ، ثُمَّ قَرَأَ: {وَأَنْذِرْهُمْ يَوْمَ الحَسْرَةِ إِذْ قُضِيَ الأَمْرُ وَهُمْ فِي غَفْلَةٍ} [مريم: 39]، وَهَؤُلاَءِ فِي غَفْلَةٍ أَهْلُ الدُّنْيَا {وَهُمْ لاَ يُؤْمِنُونَ} [مريم: 39]».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يبين النبي صلى الله عليه وسلم أن الموت يؤتى به يوم القيامة، كهيئة ذَكَر الضأن وفيه بياض وسواد، \nفيٌنَادى: يا أهل الجنة! فيمدُّون أعناقهم ورقابهم ويرفعون رؤوسهم وينظرون، \nفيقول لهم: هل تعرفون هذا؟ \nفيقولون: نعم، هذا الموت، وكلهم قد رآه وعرفه، \nثم ينادي المنادي: يا أهل النار، فيمدون أعناقهم ورقابهم ويرفعون رؤوسهم وينظرون، \nفيقول: هل تعرفون هذا؟ \nفيقولون: نعم، هذا الموت، وكلهم قد رآه؛ \nفيُذبَح، ثم يقول المنادي: يا أهل الجنة بقاء أبد الآبدين فلا موت، ويا أهل النار بقاء أبد الآبدين فلا موت. \nوذلك ليكون زيادة في نعيم المؤمنين، ونكاية في عذاب الكافرين.\nثم قرأ النبي صلى الله عليه وسلم: \n{وَأَنْذِرْهُمْ يَوْمَ الْحَسْرَةِ إِذْ قُضِيَ الأَمْرُ وَهُمْ فِي غَفْلَةٍ وَهُمْ لا يُؤْمِنُونَ} \nفيوم القيامة يفصل بين أهل الجنة والنار، ودخل كل إلى ما صار إليه مخلدًا فيه، \nفيتحسر المسيء ويندم إذ لم يحسن، والمقصر إذ لم يزدد من الخير.","reference":"صحيح البخاري (6/ 93) (4730)، صحيح مسلم (4/ 2188) (2849)، التوضيح شرح الجامع الصحيح (22/595)، عمدة القاري شرح صحيح البخاري (19/ 52)، البحر المحيط الثجاج (43/686).","benefits":["مصير الإنسان في الآخرة هو الخلود في الجنة أو النار.","التحذير الشديد من هول يوم القيامة وأنه يوم الحسرة والندم.","بيان دوام سرور أهل الجنة، ودوام حزن أهل النّار."],"wordsMeanings":[{"word":"كبش","meaning":" ذكر الضأن."},{"word":"أملح","meaning":" الأبيض الذي يخالطه السواد."}],"category":"quran","tags":["يؤتى","بالموت","كهيئة","كبش","أملح"],"source":"hadeethenc"},{"id":"he_65046","text":"عَنْ ‌أَبِي هُرَيْرَةَ رَضِيَ اللهُ عَنْهُ قَالَ: كَانَ أَهْلُ الْكِتَابِ يَقْرَؤُونَ التَّوْرَاةَ بِالْعِبْرَانِيَّةِ، وَيُفَسِّرُونَهَا بِالْعَرَبِيَّةِ لِأَهْلِ الْإِسْلَامِ، فَقَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «لَا تُصَدِّقُوا أَهْلَ الْكِتَابِ وَلَا تُكَذِّبُوهُمْ، وَقُولُوا: {آمَنَّا بِاللهِ وَمَا أُنْزِلَ إِلَيْنَا} [البقرة: 136] الْآيَةَ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"حذًّر النبي صلى الله عليه وسلم أمته من الاغترار بما يرويه أهل الكتاب من كتبهم، \nحيث كان اليهود على عهد النبي صلى الله عليه وسلم يقرؤون التوراة باللغة العبرية؛ وهي لغة اليهود، ويفسرونها بالعربية، \nفقال صلى الله عليه وسلم: لا تصدِّقوا أهل الكتاب ولا تكذِّبوهم، وهذا فيما لا يُعرف صدقُه من كذِبِه؛ \nوذلك لأن الله تعالى أمرنا أن نؤمن بما أنزل إلينا من القرآن، وما أنزل إليهم من الكتاب، إلا أنه لا سبيل لنا إلى أن نعلم صحيح ما يحكونه عن تلك الكتب من سقيمه إذا لم يَرِد في شريعتنا ما يوضِّح صدقَه من كذبه، \nفنتوقف، فلا نصدقهم؛ لئلا نكون شركاء معهم فيما حرَّفوه منه، ولا نكذبهم؛ فلعله يكون صحيحًا، فنكون منكرين لما أمرنا أن نؤمن به، \nوأمر النبي صلى الله عليه وسلم أن نقول: \n{آمنا بالله وما أنزل إلينا وما أنزل إلى إبراهيم وإسماعيل وإسحاق ويعقوب والأسباط وما أوتي موسى وعيسى وما أوتي النبيون من ربهم لا نفرق بين أحد منهم ونحن له مسلمون} \n[البقرة: 136].","reference":"صحيح البخاري (6/ 20) (4485)، فتح الباري لابن حجر (8/ 170).","benefits":["ما أخبر به أهل الكتاب ثلاثة أقسام: قسم يوافق القرآن والسنة فيُصدَّق، وقسم يخالف القرآن والسنة فهذا باطل ويكذَّب، وقسم ثالث ليس في القرآن والسنة ما يدل على صدقه ولا كذبه؛ فهذا يُروى، ولا يُصدَّق ولا يُكذَّب."],"wordsMeanings":[{"word":"العبرانية","meaning":" وتسمى العبرية، وهي لغة اليهود."}],"category":"quran","bookId":"bukhari","tags":["تصدقوا","أهل","الكتاب","ولا","تكذبوهم،","وقولوا:"],"source":"hadeethenc"},{"id":"he_65051","text":"عَنِ ‌ابْنِ عَبَّاسٍ رَضِيَ اللهُ عَنْهُمَا قَالَ: كَانَ النَّبِيُّ صَلَّى اللهُ عَليهِ وَسَلَّمَ لا يَعْرِفُ فَصْلَ السُّورةِ حَتَّى تَنْزِلَ عَليْهِ {بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ}.","attribution":"رواه أبو داود","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّن ابن عباس رضي الله عنهما أن سور القرآن الكريم كانت تنزل على النبي صلى الله عليه وسلم ولا يَعرف انفصالَها وانتهاءها، حتى تنزل عليه: \"بسم الله الرحمن الرحيم\"، فيَعلم أن السورة السابقة قد خُتمت، وأنها بداية لسورة جديدة.","reference":"سنن أبي داود (2/ 91) (788)، شرح سنن أبي داود للعباد (102/ 15)، التنوير شرح الجامع الصغير (8/503)، عون المعبود (2/353).","benefits":["البسملة يُفصَل بها بين السُّور، إلا بين سورة الأنفال وسورة التوبة."],"wordsMeanings":[],"category":"quran","bookId":"abudawud","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_65054","text":"عن عبد الله بن عمرو رضي الله عنهما قال: قال رسول الله صلى الله عليه وسلم: «يقالُ لصاحبِ القرآن: اقرَأ وارتَقِ، ورتِّل كما كُنْتَ ترتِّل في الدُنيا، فإن منزِلَكَ عندَ آخرِ آية تقرؤها».","attribution":"رواه أبو داود والترمذي والنسائي في الكبرى وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"أخبر النبي صلى الله عليه وسلم أنه يقال لقارئ القرآن، العامل بما فيه، الملازم له تلاوةً وحفظًا إذا دخل الجنة: \nاقرأ القرآن، وارتق بذلك في درجات الجنة، ورتل كما كنت ترتل في الدنيا بقراءته بتأنٍّ وطمأنينة؛ فإن منزلك عند آخر آية تقرؤها.","reference":"سنن أبي داود (2/ 592) (1464)، سنن الترمذي (5/ 35) (2914)، مسند أحمد (11/ 403) (6799)، السنن الكبرى للنسائي (7/ 272) (8002)، معالم السنن (1/290)، تحفة الأحوذي (8/187)، عون المعبود وحاشية ابن القيم (4/ 237).","benefits":["الجزاء على وفق الأعمال كميَّةً وكيفيَّة.","الحث على تلاوة القرآن وإتقانه وحفظه وتدبره والعمل به.","الجنة منازل ودرجات كثيرة، ينال أصحاب القرآن فيها أعلى الدرجات."],"wordsMeanings":[],"category":"quran","bookId":"abudawud","tags":["يقال","لصاحب","القرآن:","اقرأ","وارتق،","ورتل"],"source":"hadeethenc"},{"id":"he_65058","text":"عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمي رحمه الله قَالَ: حَدَّثَنَا مَنْ كَانَ يُقْرِئُنَا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَنَّهُمْ كَانُوا يَقْتَرِئُونَ مِنْ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ عَشْرَ آيَاتٍ، فَلَا يَأْخُذُونَ فِي الْعَشْرِ الْأُخْرَى حَتَّى يَعْلَمُوا مَا فِي هَذِهِ مِنَ الْعِلْمِ وَالْعَمَلِ، قَالُوا: فَعَلِمْنَا الْعِلْمَ وَالْعَمَلَ.","attribution":"رواه أحمد","grade":"حسن","gradeKey":"hasan","explanation":"كان الصحابة رضي الله عنهم يَتَلَقَّون مِن رسول الله صلى الله عليه وسلم عشر آيات مِن القرآن، ولا ينتقلون إلى غيرها حتَّى يتعلَّموا ما في هذه العشر من العلم ويعملون به، فعلموا العلم والعمل معًا.","reference":"مسند أحمد (38/ 466) (23482).","benefits":["فضل الصحابة رضي الله عنهم وحرصهم على تعلم القرآن.","تعلم القرآن يكون بالعلم والعمل بما فيه، وليس بقراءته وحفظه فقط.","العلم يكون قبل القول والعمل."],"wordsMeanings":[],"category":"quran","bookId":"ahmed","tags":["كانوا","يقترئون","رسول","الله","صلى","الله"],"source":"hadeethenc"},{"id":"he_65059","text":"عَنْ ‌أُبَيِّ بْنِ كَعْبٍ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «يَا أَبَا الْمُنْذِرِ، أَتَدْرِي أَيُّ آيَةٍ مِنْ كِتَابِ اللهِ مَعَكَ أَعْظَمُ؟» قَالَ: قُلْتُ: اللهُ وَرَسُولُهُ أَعْلَمُ. قَالَ: «يَا أَبَا الْمُنْذِرِ، أَتَدْرِي أَيُّ آيَةٍ مِنْ كِتَابِ اللهِ مَعَكَ أَعْظَمُ؟» قَالَ: قُلْتُ: {اللهُ لا إِلَهَ إِلا هُوَ الْحَيُّ الْقَيُّومُ} [البقرة: 255]. قَالَ: فَضَرَبَ فِي صَدْرِي، وَقَالَ: «وَاللهِ لِيَهْنِكَ الْعِلْمُ، أَبَا الْمُنْذِرِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"سأل النبيُّ صلى الله عليه وسلم أبيَّ بن كعب عن أعظم آية في كتاب الله، \nفتردد في الإجابة، ثم قال: هي آية الكرسي: {الله لا إله إلا هو الحي القيوم}، \nفأيَّده النبي صلى الله عليه وسلم، وضرب النبي على صدره إشارة إلى امتلائه علمًا وحكمة، ودعا له بأن يَسعدَ بهذا العلم وأن يُيَسَّر له.","reference":"صحيح مسلم (1/ 556) (810)، إكمال المعلم (3/178)، الكاشف عن حقائق السنن (5/1644)، المفهم (2/436)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (16/ 394).","benefits":["منقبة عظيمة لأبي بن كعب رضي الله عنه.","آية الكرسي أعظم آية في كتاب الله تعالى، فينبغي حفظها وتدبر معانيها والعمل بها."],"wordsMeanings":[],"category":"quran","bookId":"muslim","tags":["أبا","المنذر،","أتدري","آية","كتاب","الله"],"source":"hadeethenc"},{"id":"he_65060","text":"عَنْ ‌عَائِشَةَ رضي الله عنها: أَنَّ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَوَى إِلَى فِرَاشِهِ كُلَّ لَيْلَةٍ جَمَعَ كَفَّيْهِ، ثُمَّ نَفَثَ فِيهِمَا فَقَرَأَ فِيهِمَا: {قُلْ هُوَ اللهُ أَحَدٌ}، وَ{قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ}، وَ{قُلْ أَعُوذُ بِرَبِّ النَّاسِ}، ثُمَّ يَمْسَحُ بِهِمَا مَا اسْتَطَاعَ مِنْ جَسَدِهِ، يَبْدَأُ بِهِمَا عَلَى رَأْسِهِ وَوَجْهِهِ وَمَا أَقْبَلَ مِنْ جَسَدِهِ، يَفْعَلُ ذَلِكَ ثَلَاثَ مَرَّاتٍ.","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"كان من هديه صلى الله عليه وسلم إذا أوى إلى فراشه لينام جَمَعَ كفـيه ورفعهما -كما يفعل الداعي- ونَفَخَ فيهما من فمِه نفخًا لطيفًا مع رِيْق يسير ويقرأ السور الثلاث: \n{قل هو الله أحد} \nو{قل أعوذ برب الفلق} \nو{قل أعوذ برب الناس}، \nثم يمسح بكفيه ما استطاع من جسده؛ بادئًا برأسه ووجهه وبالجزء الأمامي من بدنه، يكرر هذا الفعل ثلاث مرات.","reference":"صحيح البخاري (6/ 190) (5017)، (7/ 133) (5748)، الكاشف عن حقائق السُّنن (5/1651)، عمدة القاري شرح صحيح البخاري (20/ 35)، التوضيح لشرح الجامع الصحيح ( 24/ 91)، النهاية في غريب الحديث والأثر (ص 929)، شرح سنن أبي داود لابن رسلان (19/268).","benefits":["استحباب قراءة سورة الإخلاص والمعوذتين قبل النوم والنفث بهنَّ، ومسح ما استطاع من جسده."],"wordsMeanings":[],"category":"quran","bookId":"bukhari","tags":["النبي","صلى","الله","عليه","وسلم","كان"],"source":"hadeethenc"},{"id":"he_65061","text":"عَنْ ‌عَدِيِّ بْنِ حَاتِمٍ عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «الْيَهُودُ مَغْضُوبٌ عَلَيْهِمْ، وَالنَّصَارَى ضُلَّالٌ».","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنَّ اليهودَ قومٌ غَضِبَ اللهُ عليهم؛ لأنهم عرفوا الحقَّ ولم يعملوا به. \nوالنصارى قومٌ ضلال؛ لأنهم عَمِلوا بغير علم.","reference":"سنن الترمذي (5/ 71) (2954)، النهاية في غريب الحديث و الأثر ( ص 548)، المنهل العذب المورود (5/250)، البحر المحيط الثجاج (9/248).","benefits":["الجَمْعُ بين العلم والعمل نجاةٌ من سبيل المغضوب عليهم والضالين.","التحذير من سبيل اليهود والنصارى، ولزوم الصراط المستقيم الذي هو الإسلام.","كل من اليهود والنصارى ضال مغضوب عليه، لكن أَخَصُّ أوصافِ اليهود الغضبُ، وأَخَصُّ أوصاف النصارى الضلال."],"wordsMeanings":[],"category":"quran","bookId":"tirmidhi","tags":["اليهود","مغضوب","عليهم،","والنصارى","ضلال"],"source":"hadeethenc"},{"id":"he_65062","text":"عَنْ ‌عَائِشَةَ رَضِيَ اللهُ عَنْهَا قَالَتْ: تَلَا رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ هَذِهِ الْآيَةَ: {هُوَ الَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ مِنْهُ آيَاتٌ مُحْكَمَاتٌ هُنَّ أُمُّ الْكِتَابِ وَأُخَرُ مُتَشَابِهَاتٌ فَأَمَّا الَّذِينَ فِي قُلُوبِهِمْ زَيْغٌ فَيَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ ابْتِغَاءَ الْفِتْنَةِ وَابْتِغَاءَ تَأْوِيلِهِ، وَمَا يَعْلَمُ تَأْوِيلَهُ إِلَّا اللَّهُ، وَالرَّاسِخُونَ فِي الْعِلْمِ يَقُولُونَ آمَنَّا بِهِ كُلٌّ مِنْ عِنْدِ رَبِّنَا وَمَا يَذَّكَّرُ إِلَّا أُولُو الْأَلْبَابِ} [آل عمران: 7]. قَالَتْ: قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «فَإِذَا رَأَيْتِ الَّذِينَ يَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ فَأُولَئِكَ الَّذِينَ سَمَّى اللهُ، فَاحْذَرُوهُمْ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"قرأ رسول الله صلى الله عليه وسلم هذه الآية: \n{هُوَ الَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ مِنْهُ آيَاتٌ مُحْكَمَاتٌ هُنَّ أُمُّ الْكِتَابِ وَأُخَرُ مُتَشَابِهَاتٌ فَأَمَّا الَّذِينَ فِي قُلُوبِهِمْ زَيْغٌ فَيَتَّبِعُونَ مَا تَشَابَهَ مِنْهُ ابْتِغَاءَ الْفِتْنَةِ وَابْتِغَاءَ تَأْوِيلِهِ وَمَا يَعْلَمُ تَأْوِيلَهُ إِلَّا اللَّهُ وَالرَّاسِخُونَ فِي الْعِلْمِ يَقُولُونَ آمَنَّا بِهِ كُلٌّ مِنْ عِنْدِ رَبِّنَا وَمَا يَذَّكَّرُ إِلَّا أُولُو الْأَلْبَابِ}، \nوفيها أخبر الله سبحانه أنه هو الذي أنزل على نبيه القرآن، الذي منه آيات واضحة الدلالة، معلومة الأحكام لا لبس فيها، هي أصل الكتاب ومرجعه، وهي المرجع عند الاختلاف، \nومنه آيات أُخر محتملة لأكثر من معنى، يلتبس معناها على بعض الناس، أو يظن أن بينها وبين الآية الأخرى تعارض، \nثم بين الله تعامل الناس مع هذا الآيات، \nفالذين في قلوبهم مَيْلٌ عن الحق فيتركون المُحْكم، ويأخذون بالمتشابه المُحْتمل، يبتغون بذلك إثارة الشبهة وإضلال الناس، ويبتغون بذلك تأويلها على ما يوافق أهواءهم، \nوأما الثابتون في العلم فإنهم يعلمون هذا المتشابه، ويردُّونه للمحكم، ويؤمنون به وأنه من عند الله سبحانه وتعالى، ولا يمكن أن يلتبس أو يتعارض، ولكن ما يتذكر بذلك ولا يتعظ إلا أصحاب العقول السليمة. \nثم قال النبي صلى الله عليه وسلم لأم المؤمنين عائشة رضي الله عنها أنها إذا رأت الذين يتبعون المتشابه فإنهم هم الذين سمَّى الله في قوله: \n{فأما الذين في قلوبهم زيغ} \nفاحذروهم ولا تصغوا إليهم.","reference":"صحيح البخاري (6/ 33) (4547)، صحيح مسلم (4/ 2053) (2665)، فتح الباري (8/211)، شرح النووي على مسلم (16/217)، النهاية في غريب الحديث والأثر (ص 407، 465)، فتح الودود في شرح سنن أبي داود (4/415)، تحفة الأبرار شرح مصابيح السنّة (1/129)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (41/ 559).","benefits":["المحكم من آيات القرآن: ما اتضحت دلالته وظهر معناه، والمتشابه: ما احتمل أكثر من معنى واحتاج إلى نظر وفهم.","التحذير مِن مخالطة أهل الزيغ وأصحاب البدع ومَن يطرح المشكلات لإضلال الناس وتشكيكهم.","في ختم الآية بقوله تعالى: {وما يذكر إلا أولو الألباب} تعريض بالزائغين، ومدح للراسخين، يعني: مَن لم يتذكَّر ويتَّعظ، واتَّبع هواه ليس مِن أولي الألباب.","اتباع المتشابه سبب لزيغ القلب.","وجوب رد الآيات المتشابهة التي قد لا يُفهم معناها إلى الآيات المحكمة.","جعل الله سبحانه بعضَ القرآن محكمًا وبعضَه متشابهًا؛ ابتلاءً للناس ليتميز أهل الإيمان من أهل الضلال.","في وقوع المتشابه في القرآن: إظهار فضل العلماء على غيرهم، وإعلام للعقول بقصورها؛ لتستسلم لبارئها وتعترف بعجزها.","فضيلة الرسوخ في العلم وضرورة الثبات فيه.","للمفسرين في الوقوف على {الله} من قوله: { وما يعلم تأويله إلا الله والراسخون في العلم } قولان، فمن وقف على {الله}، فيكون المراد بالتأويل علم حقيقة الشيء وكنهه وما لا سبيل إلى إدراكه كأمر الروح والساعة مما استأثر الله بعلمه، والراسخون في العلم يؤمنون به ويكلون حقائقه إلى الله فيسلمون ويسلمون، ومن وصل ولم يقف على {الله} ، فيكون المراد بالتأويل التفسير والكشف والإيضاح، فيكون الله يعلمه والراسخون في العلم يعلمونه أيضا، فيؤمنون بها ويردونها للمحكم."],"wordsMeanings":[],"category":"quran","tags":["فإذا","رأيت","الذين","يتبعون","تشابه","منه"],"source":"hadeethenc"},{"id":"he_65065","text":"عَنْ ‌عَائِشَةَ رضي الله عنها: أَنَّ رَجُلًا قَعَدَ بَيْنَ يَدَيِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فَقَالَ: يَا رَسُولَ اللهِ، إِنَّ لِي مَمْلُوكِينَ يَكْذِبُونَنِي وَيَخُونُونَنِي وَيَعْصُونَنِي، وَأَشْتُمُهُمْ وَأَضْرِبُهُمْ، فَكَيْفَ أَنَا مِنْهُمْ؟ قَالَ: «يُحْسَبُ مَا خَانُوكَ وَعَصَوْكَ وَكَذَّبُوكَ وَعِقَابُكَ إِيَّاهُمْ، فَإِنْ كَانَ عِقَابُكَ إِيَّاهُمْ بِقَدْرِ ذُنُوبِهِمْ كَانَ كَفَافًا، لَا لَكَ وَلَا عَلَيْكَ، وَإِنْ كَانَ عِقَابُكَ إِيَّاهُمْ دُونَ ذُنُوبِهِمْ كَانَ فَضْلًا لَكَ، وَإِنْ كَانَ عِقَابُكَ إِيَّاهُمْ فَوْقَ ذُنُوبِهِمُ اقْتُصَّ لَهُمْ مِنْكَ الْفَضْلُ»، قَالَ: فَتَنَحَّى الرَّجُلُ فَجَعَلَ يَبْكِي وَيَهْتِفُ، فَقَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «أَمَا تَقْرَأُ كِتَابَ اللهِ: {وَنَضَعُ الْمَوَازِينَ الْقِسْطَ لِيَوْمِ الْقِيَامَةِ فَلا تُظْلَمُ نَفْسٌ شَيْئًا}، الْآيَةَ»، فَقَالَ الرَّجُلُ: وَاللهِ يَا رَسُولَ اللهِ، مَا أَجِدُ لِي وَلهُمْ شَيْئًا خَيْرًا مِنْ مُفَارَقَتِهِمْ، أُشْهِدُكَ أَنَّهُمْ أَحْرَارٌ كُلُّهُمْ.","attribution":"رواه الترمذي","grade":"ضعيف","gradeKey":"daif","explanation":"جاء رجلٌ إلى النبي صلى الله عليه وسلم يشكو مِن تصرّفات عبيده، وأنهم يكذبونه في الخبر، ويخونونه في الأمانة، ويغشّون في المعاملة، ويعصونه في الأمر، وهو يشتمهم ويضربهم تأديبًا لهم، فسأله عن حاله يوم القيامة معهم؟ \nفقال عليه الصلاة والسلام: يُحسَب ما خانوك وعصوك وكذَّبوك ويحسَب عقابك لهم، فإذا تساوى مقدار العقاب مع ذنوبهم فما لك شيء، ولا عليك شيء، وإن كان مقدار عقابك لهم أقل مِن ذنوبهم، كان فضلًا وزيادةً لك في الأجر، \nوإن كان عقابك لهم أكثر من ذنوبهم عُوقِبْتَ، وأُخِذ منك القدر الزائد وأُعطي لهم، \nفتنحَّى الرجل وجعل يبكي ويعلو صوته، \nفقال له رسول الله صلى الله عليه وسلم: أما تقرأ كتاب الله: \n{ونضع الموازين القسط ليوم القيامة فلا تُظلم نفسٌ شيئًا، وإن كان مثقال حبة من خردل أتينا بها وكفى بنا حاسبين} [الأنبياء: 47]، \nفلا يُظلم أحدٌ شيئًا يوم القيامة، وتكون الموازين بين الناس بالعدل، \nفقال الرجل: والله يا رسول الله، لا أجِد لي ولهم شيئًا أفضل مِن مُفارَقتهم وتركِهم، أُشْهِدُك أنهم أحرار لوجه الله كلّهم؛ خشية الحساب والعذاب.","reference":"سنن الترمذي (5/ 227) (3165)، النهاية في غريب الحديث والأثر (ص 804)، مرقاة المفاتيح (8/3533)، تحفة الأحوذي (9/3).","benefits":["صدق الصحابي في تحريره لعبيده خوفًا من عذاب الله.","الاقتصاص من الظالم إن كان مساويًا لمقدار الظلم أو أقل منه فهو جائز، أما الزيادة فهي محرمة.","الحثُّ على حسن معاملة الخدم والضعفاء."],"wordsMeanings":[],"category":"quran","bookId":"tirmidhi","tags":["يحسب","خانوك","وعصوك","وكذبوك","وعقابك","إياهم"],"source":"hadeethenc"},{"id":"he_65071","text":"عَنِ ‌ابْنِ عَبَّاسٍ رَضِيَ اللهُ عَنْهُمَا: أَنَّ نَاسًا مِنْ أَهْلِ الشِّرْكِ، كَانُوا قَدْ قَتَلُوا وَأَكْثَرُوا، وَزَنَوْا وَأَكْثَرُوا، فَأَتَوْا مُحَمَّدًا صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا: إِنَّ الَّذِي تَقُولُ وَتَدْعُو إِلَيْهِ لَحَسَنٌ، لَوْ تُخْبِرُنَا أَنَّ لِمَا عَمِلْنَا كَفَّارَةً، فَنَزَلَ {وَالَّذِينَ لا يَدْعُونَ مَعَ اللهِ إِلَهًا آخَرَ وَلا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللهُ إِلا بِالْحَقِّ وَلا يَزْنُونَ}[الفرقان: 68]، وَنَزَلَت: {قُلْ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لا تَقْنَطُوا مِنْ رَحْمَةِ اللهِ} [الزمر: 53].","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"جاء رجالٌ مِن المشركين للنبيِّ صلى الله عليه وسلم وكانوا قد أكثروا مِن القتل والزنا، فقالوا للنبي: إنّ ما تدعو إليه مِن الإسلام وتعاليمِه شيءٌ حسنٌ، ولكن ما حالُنا وما وَقَعنا فيه مِن الشرك والكبائر، هل له كفّارة؟\n\nفنزلت الآيتان، حيث قَبِل الله من الناس التَّوبة مع كثرة ذنوبهم وعِظمِها، ولولا ذلك لاستمرُّوا على كفرهم وطغيانهم ولَمَا دخلوا في هذا الدِّين.","reference":"صحيح البخاري (6/ 125) (4810)، صحيح مسلم (1/ 113)  (122)، إرشاد الساري لشرح صحيح البخاري (7/ 319)، النهاية في غريب الحديث والأثر (ص 808).","benefits":["فضلُ الإسلام وعظمتُه وأنه يهدِمُ ما قَبله من الذنوب.","سعة رحمة الله بعباده ومغفرته وعفوه.","تحريم الشرك، وتحريم قتل النفس بغير حق، وتحريم الزنا، ووعيد مَن يَقترف هذه الذنوب.","التوبة الصادقة المقترنة بالإخلاص والعمل الصالح تكفّر جميع الكبائر بما فيها الكفر بالله تعالى.","تحريم القُنُوْطِ واليأسِ مِن رحمةِ الله سبحانه."],"wordsMeanings":[],"category":"quran","tags":["الذي","تقول","وتدعو","إليه","لحسن،","تخبرنا"],"source":"hadeethenc"},{"id":"he_65074","text":"عَنِ ‌ابْنِ عُمَرَ رضي الله عنهما: أَنَّ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ يَوْمَ فَتْحِ مَكَّةَ، فَقَالَ: «يَا أَيُّهَا النَّاسُ، إِنَّ اللهَ قَدْ أَذْهَبَ عَنْكُمْ عُبِّيَّةَ الْجَاهِلِيَّةِ وَتَعَاظُمَهَا بِآبَائِهَا، فَالنَّاسُ رَجُلَانِ: بَرٌّ تَقِيٌّ كَرِيمٌ عَلَى اللهِ، وَفَاجِرٌ شَقِيٌّ هَيِّنٌ عَلَى اللهِ، وَالنَّاسُ بَنُو آدَمَ، وَخَلَقَ اللهُ آدَمَ مِنْ تُرَابٍ، قَالَ اللهُ: {يَا أَيُّهَا النَّاسُ إِنَّا خَلَقْنَاكُمْ مِنْ ذَكَرٍ وَأُنْثَى وَجَعَلْنَاكُمْ شُعُوبًا وَقَبَائِلَ لِتَعَارَفُوا إِنَّ أَكْرَمَكُمْ عِنْدَ اللهِ أَتْقَاكُمْ إِنَّ اللهَ عَلِيمٌ خَبِيرٌ} [الحجرات: 13]».","attribution":"رواه الترمذي وابن حبان","grade":"صحيح","gradeKey":"sahih","explanation":"خَطَبَ النبيُّ صلى الله عليه وسلم الناس يومَ فتحِ مكة فقال: يا أيها الناس إن الله قد رفع وأزال عنكم كِبْرَ الجاهليةِ ونَخْوَتَها، والفخرَ بالآباء، وإنما الناس على نوعين:\n\nإما مؤمنٌ بَرٌّ تقيٌّ طائعٌ عابدٌ لله عزوجل، فهذا كريمٌ على الله، وإنْ لم يكن ذا حَسَبٍ أو نَسَبٍ عند الناس.\n\nوإما كافرٌ فاجرٌ شقيٌّ، وهذا هيِّنٌ ذليل على الله، ولا يساوي شيئًا، وإنْ كان ذا حَسَبٍ وله جاه وسلطان.\n\nوالناس كلُّهم أبناء آدم، وخلقَ اللهُ آدمَ من التراب، فلا يليق بمن أصله من تراب أن يتكبَّرَ ويُعْجَبَ بنفسه، ومصداق ذلك قول الله عز وجل: {يا أيها الناس إنا خلقناكم من ذكر وأنثى وجعلناكم شعوبا وقبائل لتعارفوا إن أكرمكم عند الله أتقاكم إن الله عليم خبير} [الحجرات: 13].","reference":"سنن الترمذي (5/ 309) (3270)، صحيح ابن حبان (9/ 137) (3828)، عون المعبود وحاشية ابن القيم (14/ 16)، النهاية في غريب الحديث والأثر (ص587).","benefits":["النهي عن التفاخر بالأنساب والأحساب."],"wordsMeanings":[{"word":"عُبية","meaning":" الكبر، وتضم عينها وتُكسر."}],"category":"quran","bookId":"tirmidhi","tags":["أيها","الناس،","الله","أذهب","عنكم","عبية"],"source":"hadeethenc"},{"id":"he_65075","text":"عَنْ ‌الزُّبَيْرِ بْنِ الْعَوَّامِ قَالَ: لَمَّا نَزَلَتْ: {ثُمَّ لَتُسْأَلُنَّ يَوْمَئِذٍ عَنِ النَّعِيمِ} [التكاثر: 8]، قَالَ الزُّبَيْرُ: يَا رَسُولَ اللهِ، وَأَيُّ النَّعِيمِ نُسْأَلُ عَنْهُ، وَإِنَّمَا هُمَا الْأَسْوَدَانِ التَّمْرُ وَالْمَاءُ؟ قَالَ: «أَمَا إِنَّهُ سَيَكُونُ».","attribution":"رواه الترمذي وابن ماجه","grade":"حسن","gradeKey":"hasan","explanation":"لما نزلت آية: \n{ثم لتسألن يومئذ عن النعيم} أي: سوف تُسألون عن القيام بِشُكْر ما أنعم الله به عليكم من النعم، قال الزبير بن العوام رضي الله عنه: يا رسول الله، أيّ نعيمٍ سنُسأل عنه؟! إنما هما نِعْمَتان لَيْسَتا ممّا يستَدِعي السؤال وهما التَّمر والماء!\n\nفقال النبي صلى الله عليه وسلم: أما إنكم ستسألون عن النَّعيم مع هذه الحالة التي أنتم عليها، فإنهما نِعمتان عظيمتان مِن نِعَم الله تعالى.","reference":"سنن الترمذي (5/ 375) (3356)، سنن ابن ماجه (5/ 262) (4158)، شرح سنن ابن ماجه للسيوطي (ص: 307)، تحفة الأحوذي (9/203)، مرشد ذوي الحجا والحاجة إلى سنن ابن ماجه والقول المكتفى على سنن المصطفى (25/ 251).","benefits":["التَّأكيد على شكر الله تعالى على النِّعم.","النّعيم ممّا سيُسأل عنه العبد يوم القيامة قليلًا كان أو كثيرًا."],"wordsMeanings":[],"category":"quran","bookId":"tirmidhi","tags":["لتسألن","يومئذ","النعيم"],"source":"hadeethenc"},{"id":"he_3571","text":"عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضيَ اللهُ عنهُ قَالَ: قَالَ لِي النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «اقْرَأْ عَلَيَّ»، قُلْتُ: يَا رَسُولَ اللَّهِ، أَأَقْرَأُ عَلَيْكَ، وَعَلَيْكَ أُنْزِلَ؟ قَالَ: «نَعَمْ» فَقَرَأْتُ سُورَةَ النِّسَاءِ حَتَّى أَتَيْتُ إِلَى هَذِهِ الآيَةِ: {فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ، وَجِئْنَا بِكَ عَلَى هَؤُلاَءِ شَهِيدًا} [النساء: 41]، قَالَ: «حَسْبُكَ الآنَ» فَالْتَفَتُّ إِلَيْهِ، فَإِذَا عَيْنَاهُ تَذْرِفَانِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"طلب النبي صلى الله عليه وسلم من عبدالله بن مسعود رضي الله عنه أن يقرأ عليه شيئًا من القرآن، فقال: يا رسول الله، كيف أقرؤه عليك وعليك أنزل؟! فقال صلى الله عليه وسلم: إني أحب أن أسمعه من غيري، فقرأ عليه من سورة النساء، فلما بلغ قوله تعالى: {فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ، وَجِئْنَا بِكَ عَلَى هَؤُلاَءِ شَهِيدًا}. \n\nأي ماذا يكون حالك وحال أمتك إذا أتينا بك شهيدًا على أمتك أنك بلغتهم رسالة ربك، فقال النبي صلى الله عليه وسلم: توقف الآن عن القراءة، قال ابن مسعود رضي الله عنه: فالتفتُّ إليه فإذا عيناه تجري دموعهما رهبة من الموقف، ورحمة بأمته.","reference":"صحيح البخاري (6/ 196) (5050).\nصحيح مسلم (1/ 551) (800).\nكنوز رياض الصالحين، لمجموعة من الباحثين (7/ 133).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 515).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 402).\nشرح رياض الصالحين، لابن عثيمين (3/ 342).","benefits":["قال النووي: استحباب استماع القراءة والإصغاء لها والبكاء عندها وتدبرها، واستحباب طلب القراءة من غيره ليستمع له، وهو أبلغ في التفهم والتدبر من قراءته بنفسه.","سماع القرآن فيه ثواب كما في تلاوته.","فضيلة عبد الله بن مسعود رضي الله عنه، حيث أحب الرسول صلى الله عليه وسلم أن يسمعه من فِيه، وهذا يدل على حرص ابن مسعود رضي الله عنه على تطلُّب القرآن وحفظه وإتقانه.","فضيلة البكاء خشية من الله عز وجل عند سماع آياته، مع التزام السكون، وحسن الصمت، وعدم الصراخ."],"wordsMeanings":[],"category":"quran","tags":["قال","النبي","صلى","الله","عليه","وسلم:"],"source":"hadeethenc"},{"id":"he_3772","text":"عن ابن مسعود رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : «لا حَسَدَ إلا في اثنتين: رجل آتاه الله مالا، فسَلَّطَه على هَلَكَتِهِ في الحَقِّ، ورجل آتاه الله حِكْمَة، فهو يقضي بها ويُعَلِّمَها».\nوعن ابن عمر رضي الله عنهما ، عن النبي صلى الله عليه وسلم قال: «لا حسد إلا في اثنتين: رجل آتاه الله القرآن، فهو يقوم به آناء الليل وآناء النهار، ورجل آتاه الله مالا، فهو ينفقه آناء الليل وآناء النهار».","attribution":"حديث ابن مسعود رضي الله عنه: متفق عليه.\nحديث ابن عمر رضي الله عنه: متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُشير النبي صلى الله عليه وسلم هنا إلى أن الحَسَدَ أنواع مختلفة فمنه حسد مَذْمُوم محرم شرعًا، وهو أن يتمنى المرء زوال النعمة عن أخيه، وحسد مباح وهو أن يرى نعمة دنيوية عند غيره فيتمنى لنفسه مثلها، وحسد محمود مستحب شرعًا، وهو أن يرى نعمة دينية عند غيره فيتمناها لنفسه. وهو ما عناه النبي صلى الله عليه وسلم بقوله: \"لا حَسَدَ إلا في اثنتين\" أي أن الحسد تختلف أنواعه وأحكامه حسب اختلاف أنواعه ولا يكون محمودًا مستحبًا شرعيًا إلا في أمرين: \nالأمر الأول: أن يكون هناك رجل غني تقي، أعطاه الله مالا حلالا، فينفقه في سبيل الله تعالى، فيتمنى أن يكون مثله، ويَغْبِطَه على هذه النعمة. \nالأمر الثاني: أن يكون هناك رجل عالم، أعطاه الله علما نافعا يعمل به، ويعلمه لغيره، ويحكم به بين الناس، فيتمنى أن يكون مثله.","reference":"كنوز رياض الصالحين، تأليف: حمد بن ناصر بن العمار ، الناشر: دار كنوز أشبيليا، الطبعة الأولى: 1430 هـ\nبهجة الناظرين، تأليف: سليم بن عيد الهلالي، نسخة الكترونية، لا يوجد بها بيانات نشر.\nنزهة المتقين، تأليف: جمعٌ من المشايخ، الناشر: مؤسسة الرسالة، الطبعة الأولى: 1397 هـ، الطبعة الرابعة عشر 1407 هـ\nرياض الصالحين، تأليف : محيي الدين يحيى بن شرف النووي ، تحقيق: د. ماهر بن ياسين الفحل ، الطبعة: الأولى، 14","benefits":["الحَسَدُ داء خطير يجب الابتعاد عنه والحذر منه.","حسد الغِبْطَة محمود إذا كان في وجوه الخير.","فضل الغني الذي لا يبخل بما آتاه الله .","الواجب شكر المُنْعِم على ما أنعم به على العبد وذلك بأن يضعها العبد في موضعها.","استحباب الإنفاق وبذل المال والخروج عنه بالكلية في وجوه الخير ما لم يؤد إلى حرمان الورثة أو سؤال الناس ونحو ذلك مما حَرَّمَه الشرع.","فضل العلم بأحكام الدين وتعليم الناس ودعوتهم إلى التفقه في الدين."],"wordsMeanings":[{"word":"الحسد","meaning":" الغبطة ، وهي: أن يتمنى مثله."},{"word":"سلطه","meaning":" مكنه الله من إنفاقه في وجوه الخير."},{"word":"هلكته","meaning":" وجوه إنفاقه ومجالات صرفه."},{"word":"في الحق","meaning":" في أنواع البر ونواحي الخير."},{"word":"حكمة","meaning":" وضع كل شيء في موضعه."},{"word":"يقضي بها","meaning":" يحكم ويفتي بين الناس بمقتضاها."},{"word":"آناء","meaning":" الآناء: الساعات"}],"category":"quran","tags":["حَسَدَ","إلا","اثنتين:","رجل","آتاه","الله"],"source":"hadeethenc"},{"id":"he_4448","text":"عن عبد الرحمن بن يزيد النَّخَعِي: «أنه حج مع ابن مسعود فرآه يَرمي الجَمْرَةَ الكبرى بسبع حصَيات، فجعل البيت عن يساره، ومِنى عن يمينه، ثم قال: هذا مَقَامُ الذي أُنْزِلَتْ عليه سورة البقرة صلى الله عليه وسلم ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"رميُ الجمار في يوم النحر وأيام التشريق عبادة جليلة، فيها معنى الخضوع لله تعالى، وامتثال أوامره والاقتداء بإبراهيم الخليل عليه الصلاة والسلام، وأول ما يبدأ به الحاج يوم النحر هو رمي الجمرة الكبرى لتكون فاتحة أعمال ذلك اليوم الجليلة، فيقف منها موقف النبي صلى الله عليه وسلم حيث الكعبة المشرفة عن يساره ومني عن يمينه واستقبلها ورماها بسبع حصيات يكبر مع كل واحدة كما وقف ابن مسعود رضي الله عنه هكذا وأخبر أن هذا هو مقام الذي أنزلت عليه سورة البقرة، صلى الله عليه وسلم.","reference":"تيسير العلام، تأليف: عبد الله بن عبد الرحمن البسام، تحقيق محمد صبحي بن حسن حلاق، مكتبة الصحابة ومكتبة التابعين، الطبعة العاشرة، 1426 هـ.\nتأسيس الأحكام شرح عمدة الأحكام، تأليف: أحمد بن يحي النجمي:  نسخة إلكترونية لا يوجد بها بيانات نشر.\nتنبيه الأفهام شرح عمدة الإحكام، تأليف: محمد بن صالح العثيمين، مكتبة الصحابة ومكتبة التابعين، الطبعة الأولى: 1426هـ.\nالإفهام في شرح عمدة الأحكام، للشيخ عبد العزيز بن","benefits":["مشروعية رمي جَمرَة العَقَبَة وحدها يوم النحر.","السُّنَّة في رمي جَمرَة العَقَبَة أن يستقبلها، بحيث تكون الكعبة عن يساره ومنى عن يمينه.","جواز رمي جَمَرَة العَقَبَة من أي مكان، سواء استقبلها، أو جعلها عن يمينه، أو عن يساره، أو من فوقها، أو من أسفلها، أو وسطها المهم أن تقع الجمار في الحوض.","يؤخذ من الحديث عدم مشروعية الوقوف للدعاء بعد رمي جمرة العقبة يوم النحر.","وجوب الرمي بسبع حصيات متعاقبات -واحدة بعد أخرى-.","شرع الرمي للتأسي به صلى الله عليه وسلم ، لا كما يعتقده العامة من رمي الشيطان.","تسمية هذه المواقف بـ\"الجمرات\" لا ما يقوله بعض الناس جهلا من تسميتها بـ\"الشيطان الكبير\" أو\" الشيطان الصغير\".","أن القرآن كلام الله منزل غير مخلوق.","جواز إضافة السورة إلى البقرة، خلافاً لمن منع ذلك.","ثبوت علو الله تعالى بذاته.","فضل ابن مسعود رضي الله عنه وحرصه على نشر السنة.","الحرص على مصاحبة ذوي العلم والفضل في سفر الحج."],"wordsMeanings":[{"word":"الْجَمْرَةَ","meaning":" مكان رمي الجمار سميت باسم الواحد منه."},{"word":"الكبرى","meaning":" وصف لجمرة العقبة، وهي أقرب الجمرات إلى مكة."},{"word":"البيت","meaning":" الكعبة."},{"word":"مَقَامُ","meaning":" موقف."}],"category":"quran","tags":["جعل","ابن","مسعود","رضي","الله","عنه"],"source":"hadeethenc"},{"id":"he_5213","text":"عن عائشة رضي الله عنها «أن رسول الله صلى الله عليه وسلم بعث رجلا على سَرِيَّةٍ فكان يَقْرَأ لأصحابه في صلاتهم، فَيَخْتِمُ بـ«قل هو الله أحد» فلما رجعوا ذكروا ذلك لرسول الله صلى الله عليه وسلم فقال: سَلُوهُ لأَيِّ شيء صَنَع ذلك؟ فسألُوه، فقال: لِأنَّها صِفَةُ الرحمن عز وجل ، فأنا أُحِب أَنْ أَقْرَأ بها، فقال رسول الله صلى الله عليه وسلم : أَخْبِرُوه: أنَّ الله تعالى يُحِبُّه».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أمَّرَ النبي صلى الله عليه وسلم بعض أصحابه على سَرِيَّة؛ لتدبيرهم والحكم بينهم، وحتى لا تكون الأمور فوضى، ويختار أقومهم دينًا وعلمًا وتدبيرًا، ولذا كان الأمراء هم الأئمة في الصلاة والمفتون؛ لفضل علمهم ودينهم، فكان يقرأ \"قل هو الله أحد\" في الركعة الثانية من كل صلاة؛ لمحبته لله وأسمائه وصفاته، ومن أحب شيئاً أكثر من ذكره.\nفلمَّا رجعوا من غزوتهم إلى النبي صلى الله عليه وسلم ، ذكروا له ذلك، فقال: سلُوه لأيِّ شيء يصنع ذلك، أهو لمحض المصادفة أم لشيء من الدواعي؟\nفقال الأمير: صنعت ذلك لاشتمالها على صفة الرحمن عز وجل ، فأنا أحب تكريرها لذلك.\nفقال رسول الله صلى الله عليه وسلم : أخبروه، أنه كما كرر هذه السورة لمحبته لها؛ وهذا لما تضمنته من صفات الله العظيمة التي دلت عليها أسماؤه المذكورة فيها: فإن الله يحبه.","reference":"تيسير العلام للبسام الناشر: مكتبة الصحابة، الإمارات - مكتبة التابعين، القاهرة الطبعة- العاشرة، 1426 هـ - 2006 م.\nتنبيه الأفهام للعثيمين، طبعة مكتبة الصحابة - الإمارات - مكتبة التابعين- القاهرة- الطبعة الأولى 1426.\nالإلمام بشرح عمدة الأحكام لإسماعيل الأنصاري -طبعة دار الفكر- دمشق -الأولى 1381.\nصحيح البخاري، أبو عبد الله محمد بن إسماعيلالجعفي البخاري - تحقيق محمد زهير بن ناصر الناصر -الناشر : دار طو","benefits":["جواز قراءة قصار المُفصَّل، حتى في غير صلاة المغرب من الفرائض.","فضل سورة الإخلاص واستحباب قراءتها.","أن تفضيل بعض القرآن على بعض عائد لما يحتوى عليه المفضَّل من تمجيد الله والثناء عليه، فهذه السورة الكريمة الجليلة تشمل توحيد الاعتقاد والمعرفة وما يجب إثباته للرب من الأحدية المنافية للشريك والصمدية المثبتة لله -تعالى- جميع صفات الكمال ونفي الوالد والولد، الذي هو من لوازم غناه ونفى الكفء المتضمن نفي المماثل ولذا فهي تعدل ثلث القرآن.","أن الأعمال يكتب ثوابها بسبب ما يصاحبها من نية صالحة، لأن النبي -صلى الله عليه وسلم- أمر بالسؤال عن القصد من تكريرها.","أنه ينبغي أن يكون أصحاب الوِلايات والقيادات من أهل العلم والفضل والدين.","أنه من أحب صفات الله وَتَذوَّق حلاوة مناجاته بها فالله يُحبه؛ لأن الجزاء من جنس العمل.","أن إخبار الوالي الأكبر عن أعمال الأمراء والعمال لقصد الإصلاح لا يُعَدُّ وشاية ولا نميمة.","مشروعية بعث السَّرَايا لقتال الكفار والتأمير عليهم.","أن أميرهم أحق بإمامتهم في الصلاة لكونه صاحب السُلْطان عليهم.","مشروعية التثبت في الأمور قبل الحكم عليها؛ لقول النبي -صلى الله عليه وسلم-: (سَلُوهُ لأَيِّ شيء صنع ذلك؟).","إثبات صفة المحبة لله -تعالى-.","جواز القراءة في الركعة الواحدة بسورتين فأكثر.","جواز تخصيص بعض القرآن بالاستكثار منه."],"wordsMeanings":[{"word":"بعث رجلًا","meaning":" أرسله أميرًا."},{"word":"سرية","meaning":" من السرى أي المشي بالليل، وهي القطعة من الجيش يرسلها القائد، أقلها خمسة رجال وأكثرها أربعمائة؛ سُميت بذلك لأنَّ غالب سيرهم يكون بالليل؛ للإرفاق بهم أو بقصد التخفي لقلتهم؛ إلا أنَّ أهل المغازي يجعلون وجود النبي -صلى الله عليه وسلم- هو المُميِّز للسرية عن الغزوة."},{"word":"فيختم بـ«قل هو الله أحد»","meaning":" ينهي القراءة بقراءة سورة (قل هو الله أحد)، إما في قراءة كل ركعة، وإما في قراءة الركعة الأخيرة."},{"word":"يصنع ذلك","meaning":" ينهي بقراءة سورة (قل هو الله أحد)."},{"word":"لأنها","meaning":" أي السورة."},{"word":"صفة الرحمن","meaning":" تحتوي على صفة الرحمن -سبحانه وتعالى- بما فيها من الأسماء الدالة على الصفات، وليس فيها ذكر لغير صفات الله -عز وجل-."},{"word":"يحبه","meaning":" المحبة في اللغة الوداد, ومحبة الله للعبد صفة من صفاته تحمل على ما تقتضيه في اللغة من غير تكييف ولا تمثيل ولا تحريف ولا تأويل ولا تعطيل."}],"category":"quran","tags":["رسول","الله","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_5658","text":"عَنِ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّمَا مَثَلُ صَاحِبِ القُرْآنِ كَمَثَلِ صَاحِبِ الإِبِلِ المُعَقَّلَةِ، إِنْ عَاهَدَ عَلَيْهَا أَمْسَكَهَا، وَإِنْ أَطْلَقَهَا ذَهَبَتْ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"شَبَّهَ النبيُّ صلى الله عليه وسلم من دَرَس القرآن وأَلِفَ تلاوته -سواء نظرًا من المصحف أو عن ظهر قلب- بصاحب الإبل المعقلة بالحبل الذي يُشَدُّ به رُكْبة البعير، إن عاهد عليها استمر إمساكه لها، وإن أطلق عُقُلَها ذهبت وانفلتت، فإذا قام صاحب القرآن فقرأه ذَكَره، وإذا لم يقم به نسيه؛ فما زال التعاهد موجودًا فالحفظ موجود.","reference":"صحيح البخاري (6/ 193) (5031).\nصحيح مسلم (1/ 543) (789).\nشرح صحيح مسلم، للنووي (6/ 77).\nفيض القدير شرح الجامع الصغير، لعبدالرؤوف المناوي (3/ 3).\nكنوز رياض الصالحين، لمجموعة من الباحثين (13/ 12).","benefits":["الحث على تعاهد القرآن وتلاوته، والحذر من تعريضه للنسيان.","المداومة على قراءة القرآن  يذلُّ له لسانه ويسهل عليه قراءته، فإذا هَجَره ثقلت عليه القراءة وشقّت عليه.","قال القاضي: ومعنى \"صاحب القرآن\" أي: الذي ألِفه، والمصاحبة: المُؤالَفة، ومنه: فلان صاحب فلان، وأصحاب الجنة وأصحاب النار.","من أساليب الدعوة ضرب الأمثال.","قال ابن حجر: وخص الإبل بالذكر؛ لأنها أشد الحيوان الإنسي نفورًا، وفي تحصيلها بعد استمكان نفورها صعوبة."],"wordsMeanings":[],"category":"quran","tags":["إنما","مثل","صاحب","القرآن","كمثل","صاحب"],"source":"hadeethenc"},{"id":"he_5775","text":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: «بَيْنَمَا جِبْرِيلُ قَاعِدٌ عِنْدَ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ سَمِعَ نَقِيضًا مِنْ فَوْقِهِ، فَرَفَعَ رَأْسَهُ، فَقَالَ: هَذَا بَابٌ مِنَ السَّمَاءِ فُتِحَ الْيَوْمَ لَمْ يُفْتَحْ قَطُّ إِلَّا الْيَوْمَ، فَنَزَلَ مِنْهُ مَلَكٌ، فَقَالَ: هَذَا مَلَكٌ نَزَلَ إِلَى الْأَرْضِ لَمْ يَنْزِلْ قَطُّ إِلَّا الْيَوْمَ، فَسَلَّمَ، وَقَالَ: أَبْشِرْ بِنُورَيْنِ أُوتِيتَهُمَا لَمْ يُؤْتَهُمَا نَبِيٌّ قَبْلَكَ: فَاتِحَةُ الْكِتَابِ، وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ، لَنْ تَقْرَأَ بِحَرْفٍ مِنْهُمَا إِلَّا أُعْطِيتَهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"كان المَلك جبريل عليه السلام قاعدًا عند النبي صلى الله عليه وسلم، فسمع صوتًا من السماء كصوت الباب إذا فُتح، فرفع جبريل رأسه وبصره إلى السماء، ثم أخبر النبي صلى الله عليه وسلم أن هذا باب من السماء فُتح اليوم، ولم يَسبق أنْ فُتح قط إلا هذا اليوم، فنزل منه ملك من الملائكة إلى الأرض، لم ينزل من قبل إلا هذا اليوم، فسلّم الملك على النبي صلى الله عليه وسلم، وقال له: \n\nأبشر بنورين أعطيتهما لم يعطهما نبي قبلك؛ وهما: سورة الفاتحة، وآخر آيتين من سورة البقرة. \n\nثم قال الملك: لن يقرأ أحد بحرف منهما إلا آتاه الله تعالى ما فيهما من الخير والدعاء والطلب.","reference":"صحيح مسلم (1/ 554) (806).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 244).\nشرح رياض الصالحين، لابن عثيمين (4/ 700).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (4/ 1464).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (2/ 760).\nكنوز رياض الصالحين، لمجموعة من الباحثين (13/ 122).","benefits":["فضل سورة الفاتحة وخواتيم سورة البقرة، والحث على قراءتهما والعمل بما فيهما.","السماء لها أبواب ينزل منها الأمر الإلهي، ولا تفتح إلا بأمر الله تعالى.","بيان كرامة النبي صلى الله عليه وسلم على ربه، حيث أكرمه بما لم يكرم الأنبياء الذين قبله، فأعطاه هذين النورين.","من أساليب الدعوة إلى الله البشارة بالخير."],"wordsMeanings":[],"category":"quran","bookId":"muslim","tags":["أبشر","بنورين","أوتيتهما","يؤتهما","نبي","قبلك:"],"source":"hadeethenc"},{"id":"he_6178","text":"عن البراء بن عازب –رضي الله عنهما- قال: كانَ رجلٌ يَقرَأُ سُورةَ الكهفِ، وعندَه فَرَسٌ مَربُوطٌ بِشَطَنَيْنِ، فَتَغَشَّتْهُ سَحَابَةٌ فَجَعَلَتْ تَدْنُو، وجَعلَ فَرَسُه يَنفِرُ منها، فلمّا أصبحَ أتَى النبيَّ صلى الله عليه وسلم فَذَكرَ ذلك له، فقالَ: «تِلكَ السَّكِينةُ تَنَزَّلَتْ للقُرآنِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"ذكر البراء بن عازب رضي الله عنهما قصة عجيبة حصلت زمن النبي صلى الله عليه وسلم ، حيث كان رجل يقرأ سورة الكهف وإلى جانبه فرس مربوطة بحبل، فغطَّاه شيء مثل الظلة؛ وجعل يقترب منه ويقترب، ففزعت الفرس مما رأته ونفرت، فلما أصبح الرجل أتى النبيَّ صلى الله عليه وسلم فذكر ذلك، فبيَّن له النبي صلى الله عليه وسلم أن تلك السكينة تنزلت عند قراءة القرآن، كرامة لهذا الصحابي الذي كان يقرأ، وشهادة من الله تعالى أن كلامه حق.\nوالرجل هو أُسيد بن حُضير رضي الله عنه .","reference":"- رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n- شرح رياض الصالحين؛ للشيخ محمد بن صالح العثيمين، مدار الوطن، الرياض، 1426هـ.\n- صحيح البخاري –الجامع الصحيح-؛ للإمام أبي عبدالله محمد بن إسماعيل البخاري، عناية محمد زهير الناصر، دار طوق النجاة، الطبعة الأولى، 1422هـ.\n- صحيح مسلم؛ للإمام مسلم بن الحجاج، حققه ورقمه محمد فؤاد ","benefits":["إن الله يُري بعض عباده بعض آياته، ليزدادوا إيماناً مع إيمانهم.","السكينة تدنو من العباد كلما كثرت قراءة القرآن.","جواز رؤية آحاد الأمة الملائكة.","فضيلة استماع القرآن."],"wordsMeanings":[{"word":"فتغشته","meaning":" غطته وعلته."},{"word":"ينفر منها","meaning":" يفر ويذهب."},{"word":"السكينة","meaning":" الطمأنينة والرحمة."},{"word":"بشطنين","meaning":" جمع شطن: بفتح الشين المعجمة والطاء المهملة: الحبل."},{"word":"تَدْنُو","meaning":" أي تقرب وتنزل."}],"category":"quran","tags":["كان","رجل","يقرأ","سورة","الكهف،","وعنده"],"source":"hadeethenc"},{"id":"he_6212","text":"عن أبي موسى الأشعري رضي الله عنه : أن رسول الله صلى الله عليه وسلم قال له: «لقد أُوتيتَ مِزْمَاراً من مزامير آل داود».\nوفي رواية لمسلم: أنّ رسول الله صلى الله عليه وسلم قال له: «لو رَأيتَنِي وأنا أستمع لقراءتك البارحة».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"عن أبي موسى الأشعري -رضي اللّه عنه- أن رسول اللّه صلى الله عليه وسلم قال له لما سمع قراءته الجميلة المرتلة: (لقد أوتيت مزمارا من مزامير آل داود)، وقوله: \"لقد أوتيت\"، أي: أعطيت، : \"مزماراً من مزامير آل داود\"، أي داود نفسه، وداود عنده صوت حسن جميل رفيع، حتى قال الله تعالى : \"يا جبال أوّبي معه والطير، وألنّا له الحديد\" [سبأ: 10]، وآل فلان قد يطلق على الشخص نفسه؛ لأن أحداً منهم لم يُعطَ من حسن الصوت ما أعطيه داود.","reference":"1/ بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.\n2/ تطريز رياض الصالحين؛ تأليف فيصل آل مبارك، تحقيق د. عبدالعزيز آل حمد، دار العاصمة-الرياض، الطبعة الأولى، 1423هـ.\n3/ دليل الفالحين لطرق رياض الصالحين؛ لمحمد بن علان الشافعي، دار الكتاب العربي-بيروت.\n4/ رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n5","benefits":["4- مكانة أبي موسى الأشعري  -رضي الله عنه- وحسن صوته ومدح النبي -صلى الله عليه وسلم- له.","1- استحباب تحسين الصوت بالقرآن؛ لأن ذلك يزيد القرآن حلاوة ونفوذاً إلى قلوب السامعين.","5-  فضل نبي الله داود -عليه السلام-.","2- استحباب الاستماع إلى القرآن والإنصات له.","3- الجهر بالعبادة قد يكون في بعض المواضع أفضل من الإسرار."],"wordsMeanings":[{"word":"مزماراً","meaning":" المراد: الصوت الحسن، وأصله الآلة، وأطلق اسمه على الصوت للمشابهة."},{"word":"آل داود","meaning":" المراد: داود النبي -عليه السلام- من أنبياء بني إسرائيل."},{"word":"البارحة","meaning":" أقرب ليلة مضت."}],"category":"quran","tags":["لقد","أوتيت","مزمارا","مزامير","داود"],"source":"hadeethenc"},{"id":"he_6260","text":"عن أبي هريرة رضي الله عنه عن النبي صلى الله عليه وسلم قال: «مِنَ القُرْآنِ سُورَةٌ ثَلاثُونَ آيَةً شَفَعَتْ لِرَجُلٍ حَتَّى غُفِرَ لَهُ، وَهِي: تبارك الذي بيده الملك». وفي رواية أبي داود: «تشفع».","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"يبين رسول اللّه –صلى الله عليه وسلم- أن هناك سورة من القرآن تتكون من ثلاثين آية شفعت لرجل حتى غفر الله له، حيث كان يقرؤها ويعتني بها، فلما مات شفعت له حتى دفع عنه عذابه، وأبهم ذكرها في بداية الحديث، ثم بينها في آخره؛ ليكون أوقع في شرفها وفخامتها، وأبلغ في المواظبة على قراءتها.","reference":"1/ بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.\n2/ تحفة الأحوذي بشرج جامع الترمذي؛ للإمام محمد عبدالرحمن المباركفوري، أشرف عليه عبدالوهاب عبداللطيف، دار الفكر.\n3/ جامع الأصول في أحاديث الرسول؛ للإمام مجد الدين ابن الأثير الجزري، حققه عبدالقادر الأرناؤوط، نشر مكتبة الحلواني وغيرها، 1392هـ.\n4/ سنن أبي داود, أبو داود سليمان بن الأشعث بن إسحاق بن بشير بن شداد بن عمرو الأزدي الس","benefits":["بيان فضل سورة الملك، والحض على حفظها وتلاوتها.","كتاب الله يشفع لمن يقرأه، ويعمل به.","إثبات عذاب القبر."],"wordsMeanings":[{"word":"شفعت","meaning":" من الشفاعة، وهي السؤال في التجاوز عن الذنوب والجرائم، وتكون فيما يتعلق بأمور الدنيا والآخرة."}],"category":"quran","bookId":"abudawud","tags":["القرآن","سورة","ثلاثون","آية","شفعت","لرجل"],"source":"hadeethenc"},{"id":"he_6828","text":"عن النواس بن سمعان رضي الله عنه قال: سمعتُ رسولَ اللهِ صلى الله عليه وسلم يقولُ: «يُؤتى يوم القيامة بالقرآن وأهلِه الذين كانوا يعملون به في الدنيا، تَقْدُمُه سورةُ البقرة وآلِ عمران، تُحاجَّانِ عن صاحِبِهِما».","attribution":"رواه مسلم، ولفظة: \"في الدنيا\" لا توجد في مسلم، ولعل النووي أخذها من ابن الأثير، انظر: جامع الأصول (8/472 رقم6242)","grade":"صحيح","gradeKey":"sahih","explanation":"حديث النواس بن سمعان رضي الله عنه أن النبي صلى الله عليه وسلم قال: \"يؤتي يوم القيامة بالقرآن، وأهله الذين كانوا يعملون به في الدنيا تقدمه سورة البقرة وآل عمران تحاجان عن صاحبهما\"، ولكن الرسول صلى الله عليه وسلم قيد في هذا الحديث قراءة القرآن بالعمل به؛ لأن الذين يقرءون القرآن ينقسمون إلى قسمين؛ قسم: لا يعمل به، فلا يؤمنون بأخباره، ولا يعملون بأحكامه هؤلاء يكون القرآن حجة عليهم، وقسم آخر: يؤمنون بأخباره ويصدقون بها، ويعملون بأحكامه، فهؤلاء يكون القرآن حجة لهم يحاج عنهم يوم القيامة، وفي هذا دليل على أن أهم شيء في القرآن العمل به، ويؤيد هذا قوله تعالى: \"كتاب أنزلناه إليك مبارك ليدبروا آياته، وليذكر أولوا الألباب\"، \"ليدبروا آياته\"، أي: يتفهمون معانيها، \"وليذكر أولوا الألباب\"، يعني: ويعملون بها، وإنما أخر العمل عن التدبر؛ لأنه لا يمكن العمل بلا تدبر إذا إن التدبر يحصل به العلم والعمل فرع عن العلم، فالمهم أن هذا هو الفائدة من إنزال القرآن أن يتلى ويعمل به يؤمن بأخباره يعمل بأحكامه يمتثل أمره يجتنب نهيه، فإذا كان يوم القيامة فإنه يحاج عن أصحابه.","reference":"1-بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.\n2-جامع الأصول في أحاديث الرسول؛ للإمام مجد الدين ابن الأثير الجزري، حققه عبدالقادر الأرناؤوط، نشر مكتبة الحلواني وغيرها، 1392هـ.\n3-رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n4-شرح رياض الصالحين؛ للشيخ محمد بن صالح العثيمين، مدار الوطن، الرياض، 1426","benefits":["فضل تلاوة القرآن، وتلاوة سورتي البقرة وآل عمران.","القرآن شفيع لأصحابه يوم القيامة.","العلم يقتضي العمل، وإلا كان حجة على صاحبه يوم القيامة."],"wordsMeanings":[{"word":"تقدمه","meaning":" تتقدمه."},{"word":"تحاجان","meaning":" تجادلان."}],"category":"quran","bookId":"muslim","tags":["يؤتى","يوم","القيامة","بالقرآن","وأهله","الذين"],"source":"hadeethenc"},{"id":"he_8401","text":"عن عبد الله بن أبي بكر بن حزم، أن في الكتاب الذي كتبه رسول الله صلى الله عليه وسلم لعَمْرو بن حَزْم: «أن لا يَمَسَّ القرآن إلا طَاهر».","attribution":"رواه مالك والدارمي","grade":"صحيح","gradeKey":"sahih","explanation":"معنى الحديث: \"في الكتاب الذي كَتَبَه رسول الله صلى الله عليه وسلم لعمرو بن حَزْم\" أي أن النبي صلى الله عليه وسلم كتب كتابا لعمرو بن حَزْم عندما كان قاضيا على نجران، كتب له كتابا مُطَوَّلا فيه كثير من أحكام الشريعة، كالفرائض والصدقات والديات، وهو كتاب مشهور تلقته الأُمُّة بالقبول. \n\"أن لا يَمَسَّ القرآن إلا طَاهر\" المراد بالمس هنا: أن يُباشره بيده من غير حائل، وبناء عليه: فإن تناوله من وراء حائل مُنفصل عنه كما لو حمله في كِيس أو شنطة أو قَلَّب صفحاته بِعُود ونحوه لم يدخل في النهي لعدم حصول المَسُّ.\nوالمراد بالقرآن هنا: ما كُتب فيه القرآن، كالألواح والأوراق والجلود، وغير ذلك، وليس المراد به الكلام؛ لان الكلام لا يُمَس بل يُسْمَع.\nو \" إلا طَاهر\" هذا اللفظ مشتَرَك بين أربعة أمور:\nالأول: المراد بالطاهر المسلم؛ كما قال تعالى : {إِنَّمَا الْمُشْرِكُونَ نَجَسٌ}.\nالثاني: المراد به الطاهرُ من النجاسة؛ كقوله صلى الله عليه وسلم في الهرَّة: \"إنَّها ليست بنجس\".\nالثالث: المراد به الطَّاهرُ من الجنابة.\nالرابع: أنَّ المراد بالطَّاهر المتوضئُ.\nكل هذه المعاني للطهارة في الشَّرع محْتَمِلَة في المراد من هذا الحديث، وليس لدينا مرجِّح لأحدها على الآخر، فالأولى حَمْلُهَا على ما فهمه الصحابة -رضوان الله عليهم-، وهو المُحْدِث حدثًا أصغر؛ وهو موافق لما ذهب إليه الجمهور، ومنهم الأئمة الأربعة وأتباعهم، وهو الاحتياط والأولى.","reference":"الموطأ، تأليف: مالك بن أنس الأصبحي، تحقيق: محمد مصطفى الأعظمي ، الناشر: مؤسسة زايد بن سلطان آل نهيان ، الطبعة: الأولى، 1425 هـ.\nسنن الدارمي، تأليف: عبد الله بن عبد الرحمن الدارمي، تحقيق: حسين سليم أسد الداراني الناشر: دار المغني للنشر والتوزيع، الطبعة: الأولى، 1412 هـ - 2000 م.\nصحيح الجامع الصغير وزيادته، تأليف: محمد ناصر الدين الألباني، الناشر: المكتب الإسلامي.\nتسهيل الإلمام بفقه الأحاديث من بلوغ","benefits":["في الحديث تعظيمُ القرآن، وأنَّه يجبُ احترامه، فلا يجوزُ مَسُّ المصحف بنجاسة، ولا يُجعَل في مكانٍ لا يليق؛ إمَّا لنجاستِهِ، وإمَّا بجانب صور، أو تعلق آياته بجانب صور، أو يُتْلَى في مكانِ لهوٍ أو عند الأغاني، أو عند أحدٍ يشرب الدخان، أو في مكان لغَطٍ وأصواتٍ، ونحو ذلك ممَّا يعرِّض كتاب الله -تعالى- للإهانة.","وجوب الوضوء عند إرادة مَسِّ المصحف.","ظاهر عموم الحديث شامل للصغير المميز، والراجح خلاف ذلك لوجود المشقة في إلزامهم بالوضوء، ولأنهم غير مُكَلَّفين، فأُبيح لهم مَسُّه لحاجة التعليم."],"wordsMeanings":[],"category":"quran","bookId":"malik","tags":["الكتاب","الذي","كتبه","رسول","الله","صلى"],"source":"hadeethenc"},{"id":"he_10119","text":"عن عمر بن الخطاب رضي الله عنه : أن النبي صلى الله عليه وسلم قال: «إن اللهَ يَرفعُ بهذا الكِتابِ أقْواماً ويَضَعُ به آخَرِينَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"عن عمر بن الخطاب رضي الله عنه أن النبي صلى الله عليه وسلم قال: \"إن الله يرفع بهذا الكتاب أقواماً ويضع به آخرين\"، يعني: معناه أن هذا القرآن يأخذه أناس يتلونه ويقرءونه، فمنهم من يرفعه الله به في الدنيا والآخرة، ومنهم من يضعهم الله به في الدنيا والآخرة، من عمل بهذا القرآن تصديقاً بأخباره، وتنفيذاً لأوامره واجتناباً لنواهيه، واهتداء بهديه، وتخلقاً بما جاء به من أخلاق -وكلها أخلاق فاضلة-، فإن الله تعالى يرفعه به في الدنيا والآخرة، وذلك لأن هذا القرآن هو أصل العلم ومنبع العلم وكل العلم، وقد قال الله تعالى: (يرفع الله الذين آمنوا منكم والذين أوتوا العلم درجات)، أما في الآخرة فيرفع الله به أقواماً في جنات النعيم.\nوأما الذين يضعهم الله به فقوم يقرءونه ويحسنون قراءته، لكنهم يستكبرون عنه -والعياذ بالله- لا يصدقون بأخباره، ولا يعملون بأحكامه يستكبرون عنه عملاً، ويجحدونه خبراً إذا جاءهم شيء من القرآن كقصص الأنبياء السابقين أو غيرهم أو عن اليوم الآخر أو ما أشبه ذلك صاروا والعياذ بالله يشككون في ذلك ولا يؤمنون، وربما يصل بهم الحال إلى الجحد مع أنهم يقرءون القرآن، وفي الأحكام يستكبرون لا يأتمرون بأمره ولا ينتهون بنهيه، هؤلاء يضعهم الله في الدنيا والآخرة، والعياذ بالله.","reference":"1- بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي.\n2- رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428هـ.\n3- شرح رياض الصالحين؛ للشيخ محمد بن صالح العثيمين، مدار الوطن، الرياض، 1426هـ.\n4- صحيح مسلم؛ للإمام مسلم بن الحجاج، حققه ورقمه محمد فؤاد عبدالباقي، دار عالم الكتب، الرياض، الطبعة الأولى، 1417هـ.\n5- نزه","benefits":["الحث على الاهتمام بكتاب الله تلاوة وحفظاً وفهماً وعملاً.","العلم يرفع صاحبه في الدنيا والآخرة، ما لا يرفعه المال ولا الملك ولا غيرهما.","الأمة المسلمة عزها وشرفها بتمسكها بدينها، والقيام بحق كتابها."],"wordsMeanings":[{"word":"يضع","meaning":" يخفض."}],"category":"quran","bookId":"muslim","tags":["الله","يرفع","بهذا","الكتاب","أقوامًا","ويضع"],"source":"hadeethenc"},{"id":"he_10834","text":"عن عمر بن الخطاب رضي الله عنه قال: سمعتُ هشامَ بن حَكِيم يَقْرَأ سورةَ الفُرقان في حياة رسول الله صلى الله عليه وسلم ، فاسْتَمَعْتُ لقراءته، فإذا هو يقْرَؤها على حروف كثيرةٍ لم يُقْرِئْنِيها رسولُ الله صلى الله عليه وسلم كذلك، فكِدْتُ أُساوِرُه في الصلاة، فانتظرتُه حتى سَلَّم، ثم لَبَّبْتُه بِرِدائِه أو بِرِدائي، فقلتُ: مَنْ أقرأكَ هذه السورةَ؟ قال: أَقْرَأنيها رسولُ الله صلى الله عليه وسلم ، قلتُ له: كذبتَ، فواللهِ إنَّ رسولَ الله صلى الله عليه وسلم أَقْرأَني هذه السورةَ التي سمعتُك تَقْرَؤُها، فانطلقتُ أقودُه إلى رسول الله صلى الله عليه وسلم فقلتُ: يا رسول الله، إنِّي سمعتُ هذا يقرَأ بسورة الفُرْقان على حروف لم تُقْرِئنيها، وأنت أقرأْتَنِي سورةَ الفُرقان، فقال رسول الله صلى الله عليه وسلم : «أَرْسِلْه يا عمر، اقرأْ يا هشام» فقَرَأ عليه القراءةَ التي سمعتُه يقرؤها، قال رسول الله صلى الله عليه وسلم : «هكذا أُنْزِلت» ثم قال رسول الله صلى الله عليه وسلم : «اقرأْ يا عمر» فقرأتُ، فقال: «هكذا أُنْزِلَت» ثم قال: «إنَّ هذا القرآنَ أُنْزِل على سبعة أحْرُف، فاقرءوا ما تيسَّر منه».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يحكي عمر بن الخطاب رضي الله عنه أنه سمع هشامَ بن حَكِيم رضي الله عنهما يقرأ سورةَ الفُرقان في حياة رسول الله صلى الله عليه وسلم ، بقراءة تختلف عما يقرؤه عمر في ألفاظ كثيرة، وقد كان عمر قد قرأ هذه السورة على رسول الله صلى الله عليه وسلم ، فظن عمر رضي الله عنه أن ذلك غلط من هشام، فكاد أن يثب عليه ويأخذ برأسه وهو في الصلاة، ولكنه صبر حتى سلَّم من صلاته، ثم أمسك بردائه وجمعه من جهة رقبته، وقال له: مَن أقرأكَ هذه السورةَ؟ قال: أَقْرَأنيها رسولُ الله صلى الله عليه وسلم ، فقال له عمر: كذبتَ، فواللهِ إنَّ رسولَ الله صلى الله عليه وسلم أقرأني هذه السورة بقراءةٍ غير التي قرأتها. ثم ذهب به يجره إلى رسول الله صلى الله عليه وسلم ، وكان عمر رضي الله عنه شديدًا في أمر الله تعالى ، فقال عمر: يا رسول الله، إنِّي سمعتُ هذا يقرأ بسورة الفُرْقان على ألفاظ لم أسمعك تقرؤها، وأنت أقرأتني سورةَ الفُرقان. فأمره رسول الله أن يطلقه، ثم أمر هشامًا أن يقرأ سورة الفرقان، فلما قرأها، قال رسول الله صلى الله عليه وسلم : «هكذا أُنْزِلت» يعني: أُنزلت هذه السورة من عند الله على ما قرأه هشام، ولم يكن مخطئا كما ظنه عمر رضي الله عنه . ثم أمر عمر أن يقرأ فقرأ فقال صلى الله عليه وسلم : «هكذا أُنْزِلَت» يعني: أن الله أنزل هذه السورة على ما قرأه عمر كما أنزلها على ما قرأه هشام. ثم قال صلى الله عليه وسلم : «إنَّ هذا القرآنَ أُنْزِل على سبعة أحرف، فاقرؤوا ما تيسَّر منه» فعمر وهشام كلاهما مصيب في قراءته؛ لأن القرآن نزل على أكثر من حرف، بل على سبعة أحرف، وليس في قراءة هشام زيادة عما عند عمر في الآيات، وإنما هناك اختلاف في الحروف فقط، ومن أجل ذلك قال لكل واحد منهما بعد ما سمع قراءته: «كذلك أُنزلت» ويوضح ذلك قوله: «إن هذا القرآن نزل على سبعة أحرف، فاقرأوا ما تيسر منه» أي: لا تتكلفوا التزام حرف واحد، فإن الله تعالى قد أوسع عليكم، ويسر لكم قراءة القرآن على سبعة أحرف، رحمة منه وفضلاً، فله الحمد والمنة، وقد اختلف العلماء في تعيين الحروف السبعة اختلافاً كثيراً، والمقصود بها -فيما يظهر والله أعلم- أوجه من أوجه لغة العرب، فالقرآن نزل على هذه الوجوه للتخفيف في أول الأمر؛ لأن العرب كانوا متفرقين وكانوا مختلفين وكلٌّ له لغته، ويكون عند هذه القبيلة ما ليس عند القبيلة الأخرى، ولكن لما جمع بينهم الإسلام، واتصل بعضهم ببعض، وذهب ما بينهم من العداوة والشحناء بسبب الإسلام، وعرف كل ما عند الآخرين من اللغة، قام عثمان بن عفان رضي الله عنه فجمع الناس على حرف واحد من الأحرف السبعة؛ وأحرق ما سوى ذلك؛ حتى لا يحصل الاختلاف.","reference":"- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422ه.\n- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- عمدة القاري شرح صحيح البخاري، لمحمود بن أحمد الحنفى بدر الدين العينى، الناشر: دار إحياء التراث العربي – بيروت.\n- إرشاد الساري لشرح صحيح البخاري، لأحمد بن محمد بن أبى بكر القسطلاني القتيبي المصري، الناشر:","benefits":["كان عمر -رضي الله عنه- شديدًا في أمر الله -تعالى-.","مشروعية التثبت في الأمور، ووقوف الحاكم بنفسه على الحقائق, وإن كان المخبِر موثوقًا به.","أُنزل القرآن على سبعة أحرف، والراجح في الحروف السبعة أنها: تأدية المعنى الواحد باللفظ المرادف, والقرآن نزل على هذه الوجوه للتخفيف في أول الأمر؛ لأن العرب كانوا متفرقين وكانوا مختلفين وكانوا متنابذين وكل له لغته، ويكون عند هذه القبيلة ما ليس عند القبيلة الأخرى، ولكن لما جمع بينهما الإسلام, واتصل بعضهم ببعض, وذهب ما بينهم من العداوة والشحناء بسبب الإسلام, وعرف كل ما عند الآخرين من اللغة, قام عثمان بن عفان -رضي الله عنه- فجمع الناس على حرف واحد من الأحرف السبعة؛ وأحرق ما سوى ذلك؛ حتى لا يحصل الاختلاف."],"wordsMeanings":[{"word":"أُساوِرُه","meaning":" آخذ برأسه أو أثب عليه."},{"word":"لَبَّبْتُه بردائه","meaning":" جمعت عليه ثيابه عند رقبته وأمسكته بها؛ لئلا ينفلت مني."},{"word":"أَرْسِلْه","meaning":" أطلقه."},{"word":"أحْرُف","meaning":" جمع حرف, والحرف لغة الطرف، وحروف التهجي سميت بذلك لأنها أطراف الكلمة، والحروف هنا معناها اللغات."}],"category":"quran","tags":["هذا","القرآن","أنزل","على","سبعة","أحرف،"],"source":"hadeethenc"},{"id":"he_10838","text":"عن عبد العزيز بن رُفَيع، قال: دخلتُ أنا وشَدَّاد بن مَعْقِل، على ابن عباس رضي الله عنهما ، فقال له شَدَّاد بن مَعْقِل: أَتَرَكَ النبيُّ صلى الله عليه وسلم مِن شيء؟ قال: «ما تَرَكَ إلَّا ما بيْن الدَّفَّتَيْن» قال: ودَخَلْنا على محمد ابن الحَنَفِيَّة، فسألناه، فقال: «ما تَرَكَ إلَّا ما بيْن الدَّفَّتَيْن».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"دخل التابعيان الجليلان عبد العزيز بن رُفَيع وشَدَّاد بن مَعْقِل على ابن عباس رضي الله عنهما ، فقال له شَدَّاد بن مَعْقِل: أَتَرَكَ النبيُّ صلى الله عليه وسلم من شيء بعد وفاته؟ فأجابه ابن عباس بأنه صلى الله عليه وسلم لم يترك بعد وفاته إلا هذا القرآن الذي بين دفتي المصحف، ودخلا على محمد ابن الحَنَفِيَّة فسألاه فقال مثل ذلك،\nوبهذا الحديث يتضح بطلان مذهب الرافضة الذين يزعمون أن القرآن قد نص على إمامة علي، ولكن الصحابة كتموه، فابن عباس هو ابن عم علي، ومحمد ابن الحنفية هو ابن علي، وهما من أشد الناس له لزومًا، فلو كان شيء مما ادعوه حقًّا لكانا أحق الناس بالاطلاع عليه، ولما وسعهما كتمانه، بل قد ورد عن علي رضي الله عنه أيضًا مثل ذلك.","reference":"- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422ه.\n- إرشاد الساري لشرح صحيح البخاري، لأحمد بن محمد بن أبى بكر بن عبد الملك القسطلاني القتيبي المصري، الناشر: المطبعة الكبرى الأميرية، مصر، الطبعة: السابعة، 1323 هـ.\n- عمدة القاري شرح صحيح البخاري، لمحمود بن أحمد بن موسى الحنفى بدر الدين العينى، الناشر: دار إحياء التراث العربي – بيروت.\n- ","benefits":["لم يترك النبي -صلى الله عليه وسلم- بعد وفاته إلا القرآن, ونفي ابن عباس -رضي الله عنهما- وابن الحنفية وارد على ما يتعلق بالنص في القرآن من إمامة علي -رضي الله عنه-.","فيه دليل على بطلان مذهب الرافضة من أن النبي -صلى الله عليه وسلم- قد أوصى لعلي بالخلافة، ولكن الصحابة كتموه، على زعمهم الفاسد.","أن رسول الله -صلى الله عليه وسلم- لم يترك من العلم شيئًا سرًا ولا مكتومًا."],"wordsMeanings":[{"word":"الدَّفَّتَيْن","meaning":" حافتي الْمُصحف، وغلافه من الجانبين."},{"word":"من شيء","meaning":" شيئًا سوى القرآن."}],"category":"quran","bookId":"bukhari","tags":["سئل","ابن","عباس","ومحمد","ابن","الحنفية:"],"source":"hadeethenc"},{"id":"he_10840","text":"عن عائشة أُمِّ المؤمنين رضي الله عنها أنَّ الحارثَ بن هشام رضي الله عنه سأل رسولَ الله صلى الله عليه وسلم فقال: يا رسولَ الله، كيف يأْتِيكَ الوَحْيُ؟ فقال رسول الله صلى الله عليه وسلم : «أحْيانًا يَأْتِيني مِثْلَ صَلْصَلَة الجَرَس، وهو أَشدُّه عليَّ، فيَفْصِمُ عنِّي وقد وَعَيْتُ عنه ما قال، وأحيانًا يتمثَّلُ لي المَلَكُ رَجُلًا فيُكَلِّمُني فأَعِي ما يقول». قالت عائشة رضي الله عنها : ولقد رأيتُه ينزِل عليه الوَحْيُ في اليومِ الشديدِ البرْدِ، فيَفْصِمُ عنه وإنَّ جَبِينَه لَيَتَفَصَّدُ عَرَقًا.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"سأل الحارث بن هشام رضي الله عنه رسول الله صلى الله عليه وسلم فقال: يا رسول الله، كيف يأتيك الوحيُ؟ فأخبره رسول الله صلى الله عليه وسلم أنه أحيانًا يأتيه الملك -وهو جبريل- بالوحي فيكون صوت الملك بالوحي مشابهًا لصوت الجرس في قوته، وهو أشد شيء وأصعبه عليه صلى الله عليه وسلم ، وتغشاه شدة وكرب شديد ثم ينكشف عنه، وقد فهم وحفظ عن الملك ما قال، وإنما يأتيه الوحي بهذا الصوت الشديد؛ ليشغله عن أمور الدنيا، ويفرغ حواسه للصوت الشديد، فكان صلى الله عليه وسلم يفهم عنه؛ لأنه لم يبق في سمعه مكان لغير صوت الملك ولا في قلبه.\nوأخبره صلى الله عليه وسلم أنه أحيانًا أخرى يأتيه جبريل في صورة رجل مثل دحية أو غيره، فيكلمه بالوحي فيفهم ما يقوله له ويحفظه.\nوأخبرت عائشة رضي الله عنها أنها كانت ترى النبي صلى الله عليه وسلم عند نزول الوحي عليه في اليوم الشديد البرد فتنكشف عنه شدة الوحي وجبينه يسيل عرقًا من شدة ما يلقاه من الكرب والمعاناة.","reference":"- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422ه.\n- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- كشف المشكل من حديث الصحيحين، لجمال الدين أبي الفرج عبد الرحمن بن علي بن محمد الجوزي، المحقق: علي حسين البواب، الناشر: دار الوطن – الرياض.\n- عمدة القاري شرح صحيح البخاري، لمحمود بن أحمد بن موسى الحنفى بدر","benefits":["شدة الوحي وصعوبته على النبي -صلى الله عليه وسلم-.","من الصفات التي كان ينزل بها الوحي على النبي -صلى الله عليه وسلم-, أن يكون صوت الملك بالوحي مشابهًا لصوت الجرس في قوته وهو أشد شيء وأصعبه عليه -صلى الله عليه وسلم-، كما كان جبريل يأتيه بالوحي في صورة رجلٍ أحيانًا.","أن السؤال عن الكيفية لطلب المعرفة أو الطمأنينة لا يقدح في اليقين.","جواز السؤال عن أحوال الأنبياء من الوحي وغيره.","أن أصحاب رسول الله -صلى الله عليه وسلم- كانوا يسألونه -صلى الله عليه وسلم- عن كثير من المعاني، وكان رسول الله -صلى الله عليه وسلم- يجيبهم، ويعلمهم، وكانت طائفة منهم تسأل، وطائفة تحفظ، وكلهم أدّى، وبلّغ ما علم، ولم يكتم حتى أكمل الله دينه."],"wordsMeanings":[{"word":"صَلْصَلَة","meaning":" صوت."},{"word":"فيَفْصِمُ عنِّي","meaning":" يُقلع عني وينجلي ما يغشاني منه."},{"word":"وَعَيْتُ","meaning":" حفظت الذي ذكره"},{"word":"يتمثَّل","meaning":" يتصوَّر."},{"word":"جَبِينه","meaning":" ما بين منبت الشعر والحاجبين."},{"word":"يَتَفَصَّدُ","meaning":" يسيل."},{"word":"الوحي","meaning":" في اللغة الإشارة والرسالة والكتابة, وكل ما ألقي إلى شخص ليعلمه وحي كيف كان, ثم غلب استعمال الوحي فيما يلقى إلى الأنبياء من عند الله -تعالى-."}],"category":"quran","tags":["أحيانًا","يأتيني","مثل","صلصلة","الجرس،","وهو"],"source":"hadeethenc"},{"id":"he_10841","text":"عن عبادة بن الصامت رضي الله عنه ، قال: «كان نبيُّ اللهِ صلى الله عليه وسلم إذا أُنْزِلَ عليه الوحيُ كُرِبَ لذلك وتَرَبَّدَ وجهُه».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبي صلى الله عليه وسلم إذا نزل عليه الوحي أصابه الكرب والشدة لذلك وتغير وجهه؛ لثقل نزول الوحي وصعوبة حصوله، وقد كان صلى الله عليه وسلم يهتم بأمر الوحي أشد الاهتمام، ويهاب مما يطالَب به من حقوق العبودية والقيام بشكر الله تعالى ويعظم أمر الله -تعالى وخبره.","reference":"- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- المنهاج شرح صحيح مسلم بن الحجاج، للنووي، نشر: دار إحياء التراث العربي – بيروت، الطبعة: الثانية، 1392ه.\n- مرقاة المفاتيح شرح مشكاة المصابيح، لعلي بن سلطان الملا الهروي القاري، الناشر: دار الفكر، بيروت – لبنان، الطبعة: الأولى، 1422هـ - 2002م.\n- المصباح المنير في غريب الشرح الكبير, أحمد بن محمد بن علي الفيومي ثم الحموي،","benefits":["ما كان يحصل للنبي -صلى الله عليه وسلم- من الكرب والتغير أثناء نزول الوحي؛ لعظم موقعه, كما قال الله -تعالى-: {إنا سنلقي عليك قولًا ثقيلًا}.","في هذا الحديث بيان أحد الصفات التي كان ينزل بها الوحي على النبي -صلى الله عليه وسلم-."],"wordsMeanings":[{"word":"كُرِبَ","meaning":" أَصَابَهُ الْكَرْبُ لِشِدَّةِ نُزُولِ الوحي عليه وَصُعُوبَةِ حُصُولِهِ."},{"word":"تَرَبَّدَ","meaning":" تغير."},{"word":"الوحي","meaning":" هو في اللغة الإشارة والرسالة والكتابة, وكل ما ألقي إلى الغير ليعلمه وحي كيف كان, ثم غلب استعمال الوحي فيما يلقى إلى الأنبياء من عند الله -تعالى-."}],"category":"quran","bookId":"muslim","tags":["كان","نبي","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_10843","text":"عن ابن عباس رضي الله عنهما في قوله تعالى: {لا تُحَرِّكْ به لسانَك} [القيامة: 16]، قال: «كان النبيُّ صلى الله عليه وسلم يُعالِجُ مِن التنزيل شِدَّةً، وكان يُحَرِّكُ شَفَتَيْهِ» فقال لي ابنُ عباس: فأنا أُحَرِّكُهما لك كما كان رسولُ الله صلى الله عليه وسلم يُحَرِّكُهما، فقال سعيد: أنا أُحَرِّكُهما كما كان ابنُ عباس يُحَرِّكُهما، فحرَّك شَفَتَيْهِ فأنزل اللهُ -عزَّ وجلَّ-: {لا تُحَرِّكْ به لسانَك لِتَعْجَلَ به إنَّ علينا جَمْعَه وقُرآنَه} [القيامة: 17]، قال: «جَمْعَه في صدرك ثم تقرؤه»، {فإذا قرأناه فاتَّبِعْ قُرآنه} [القيامة: 18] قال: «فاستمِع له وأَنْصِتْ، ثم إنَّ علينا أن تقْرَأه، قال: فكان رسول الله صلى الله عليه وسلم إذا أتاه جبريل عليه السلام استمع، فإذا انطلقَ جبريلُ قرأه النبي صلى الله عليه وسلم كما أقرَأَه».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم كان يعاني عند نزول الوحي شدة وهمًّا عظيمًا، فكان يحرك شفتيه بما قد سمعه من جبريل قبل إتمام جبريل الوحي، مخافة أن يذهب عنه جبريل قبل أن يحفظه، وقد وصف ابن عباس لتلميذه سعيد بن جبير كيفية تحريك النبي صلى الله عليه وسلم لشفتيه، مما يدل على أن ابن عباس قد شاهد رسول الله صلى الله عليه وسلم في تلك الحالة، ووصف سعيد ذلك أيضًا لتلاميذه،\nفأنزل اللهُ -عزَّ وجلَّ-: {لا تُحَرِّكْ به لسانَك لِتَعْجَلَ به إنَّ علينا جَمْعَه وقُرآنَه}، أي: لا تحرك لسانك بالقرآن لتسارع بأخذه، فإن علينا جمعه وضمه في صدرك، ثم قال تعالى : {فإذا قرأناه فاتَّبِعْ قُرآنه} أي: إذا فرغ جبريل من قراءته فاستمع وأنصت. ثم إنَّ علينا أن تقرأه كما هو، قال: فكان رسول الله صلى الله عليه وسلم بعد ذلك إذا أتاه جبريل -عليه السلام- استمع، فإذا انطلق جبريلُ قرأه النبي صلى الله عليه وسلم كما أقرأه جبريل.","reference":"- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422هـ.\n- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي - بيروت.\n- شرح كتاب التوحيد من صحيح البخاري، لعبد الله بن محمد الغنيمان، الناشر: مكتبة الدار، المدينة المنورة، الطبعة: الأولى، 1405 هـ.\n- معجم اللغة العربية المعاصرة، للدكتور أحمد مختار عبد الحميد عمر بمساعدة فريق","benefits":["بيان ما كان النبي -صلى الله عليه وسلم- يلقاه من معالجة الشدة عند نزول الوحي عليه، وذلك لثقل الوحي، كما قال الله -تعالى-: {إِنَّا سَنُلْقِي عَلَيْكَ قَوْلًا ثَقِيلًا} [المزمل: 5].","أنه -صلى الله عليه وسلم- كان يحرك شفتيه، لئلا ينسى، وقيل: إنما كان يفعل ذلك من حبه له، وحلاوته في لسانه، فنهي عن ذلك حتى يجتمع، لأن بعضه مرتبط لبعضه.","أن الله -تعالى- تكفل لرسوله -صلى الله عليه وسلم- أن لا ينسى القرآن، وأنه كان بعد نزول هذه الآية يستمع، وينصت لجبريل، فإذا انتهى جبريل من قراءته، وذهب من عنده، قرأه النبي -صلى الله عليه وسلم- على أصحابه كما أقرأه، من غير زيادة، ولا نقص، كما قال -تعالى-: {سَنُقْرِئُكَ فَلَا تَنْسَى} [الأعلى: 6].","وجوب اتباع القرآن والإنصات إليه.","أن فيه إشارة إلى أن أحدًا لا يحفظ القرآن إلا بعون الله -تعالى- وفضله، كما قال الله -تعالى-: {وَلَقَدْ يَسَّرْنَا الْقُرْآنَ لِلذِّكْرِ فَهَلْ مِنْ مُدَّكِرٍ (17)} [القمر: 17]."],"wordsMeanings":[{"word":"يُعالِج","meaning":" يتحمل ويعاني."},{"word":"لتَعْجل به","meaning":" لتأخذه على عجلة."},{"word":"قُرآنه","meaning":" قراءته."},{"word":"فاستمع له، وأنصِتْ","meaning":" الاستماع أخص من الإنصات، لأن الاستماع: الإصغاء، والإنصات: السكوت، ولا يلزم من السكوت الإصغاء، فقد يستمع، ولا ينصت، فلهذا جُمِعَ بينهما، كما قال الله -تعالى-: {فَاسْتَمِعُوا لَهُ وَأَنْصِتُوا} [الأعراف: 204]."},{"word":"في قوله -تعالى","meaning":" أي في توضيحِ معانيه، وبيان سبب نزوله."},{"word":"فَإِذَا قَرَأْنَاهُ","meaning":" أي إذا تلاه عليك جبريل -عليه السلام-."},{"word":"فَاتَّبِعْ قُرْآنَهُ","meaning":" فاستمع له، ثم اقرأه كما أقرأك."}],"category":"quran","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_10850","text":"عن عبد الله بن مسعود رضي الله عنه قال: قال النبي صلى الله عليه وسلم : «بِئْسَ ما لأحَدِهم أنْ يقول نَسِيتُ آيةَ كَيْتَ وكَيْتَ، بل نُسِّيَ، واستذكِروا القرآن، فإنه أشدُّ تَفَصِّيًا مِن صدور الرِّجال من النَّعَم».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث ذم النبي صلى الله عليه وسلم الذي يقول: نسيت آية كذا وكذا؛ لأن ذلك يُشعر بالتساهل في القرآن والتغافل عنه، ولكنه «نُسِّيَ» أي: عوقب بوقوع النسيان عليه لتفريطه في معاهدته واستذكاره، ثم أمر النبي صلى الله عليه وسلم بالمواظبة على تلاوة القرآن واستذكاره ومدارسته، فهو أشد انفلاتًا من الصدور من الإبل، وخص الإبل بالذكر لأنه أشد الحيوانات الإنسية نفورًا، وفي تحصيل الإبل بعد استمكان نفورها صعوبة.","reference":"- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422ه.\n- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- كشف المشكل من حديث الصحيحين، لجمال الدين أبي الفرج عبد الرحمن بن علي بن محمد الجوزي، المحقق: علي حسين البواب، الناشر: دار الوطن – الرياض.\n- عمدة القاري شرح صحيح البخاري، لمحمود بن أحمد بن موسى الحنفى بدر","benefits":["كراهة قول نسيت آية كذا, وهي كراهة تنزيه, وأنه لا يكره قول: أنسيتها, وإنما نهي عن قول: نسيتها؛ لأنه يتضمن التساهل فيها والتغافل عنها.","الأمر بتعاهد القرآن واستذكاره والمواظبة على تلاوته.","القرآن أشد انفلاتًا من الصدور من الإبل."],"wordsMeanings":[{"word":"كَيْتَ وكَيْتَ","meaning":" هي كلمة يعبر بها عن الجُمَل الكثيرة والحديث الطويل."},{"word":"تَفَصِّيًا","meaning":" انفلاتًا."},{"word":"النَّعَم","meaning":" الإبل."}],"category":"quran","tags":["بئس","لأحدهم","يقول","نسيت","آية","كيت"],"source":"hadeethenc"},{"id":"he_10851","text":"عن أبي أمامة الباهلي رضي الله عنه قال: سمعتُ رسول الله صلى الله عليه وسلم يقول: «اقرؤوا القرآنَ فإنَّه يأتي يوم القيامة شَفِيعًا لأصحابه، اقرؤوا الزَّهرَاوَين البقرةَ وسورةَ آل عِمران، فإنهما تأتِيان يوم القيامة كأنهما غَمَامَتان، أو كأنهما غَيَايَتانِ، أو كأنهما فِرْقانِ من طَيْر صَوافٍّ، تُحاجَّان عن أصحابهما، اقرؤوا سورة البقرة، فإن أخذها بَرَكة، وتركها حَسْرة، ولا تستطيعها البَطَلَة».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"حث النبي صلى الله عليه وسلم على مداومة قراءة القرآن؛ فإنه يشفع يوم القيامة للتالين له العاملين به، ثم أكد على قراءة سورتي البقرة وآل عمران وسماهما الزهراوين المنيرتين؛ لنورهما وهدايتهما، وأن أجر وثواب تلاوتهما وتدبر معانيهما والعمل بما فيهما يأتي يوم القيامة كسحابتين أو غيرهما، أو كأنهما جماعتين من الطير باسطات أجنحتها متصلاً بعضها ببعض، تظلان صاحبهما وتدافعان عنه. \n\nثم أكد صلى الله عليه وسلم على الاستمرار في قراءة سورة البقرة وتدبر معانيها والعمل بما فيها، وأن ذلك فيه بركة ومنفعة عظيمة في الدنيا والآخرة، وترك ذلك فيه حسرة وندامة يوم القيامة، وأن من فضل هذه السورة أن السحرة لا تقدر أن تضر من يقرأها.","reference":"صحيح مسلم (1/ 553) (804).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (4/ 1460).\nالتنوير شرح الجامع الصغير، لمحمد الصنعاني (2/ 606).\nشرح الأربعين النووية، لابن عثيمين (ص232).\nمعارج القبول بشرح سلم الوصول إلى علم الأصول، لحافظ الحكمي (2/ 846).\nالتَّحبير لإيضَاح مَعَاني التَّيسير، لمحمد الصنعاني (2/ 9).\nتطريز رياض الصالحين، لفيصل المبارك (ص579).","benefits":["الأمر بتلاوة القرآن والإكثار من ذلك، وأنه يشفع لأصحابه يوم القيامة، القارئين له، المتمسكين بهديه، القائمين بما أمر به، والتاركين لما نهى عنه.","فضل قراءة سورة البقرة وآل عمران وعظيم أجرهما.","فضل قراءة سورة البقرة، وأنها تحمي صاحبها من السحر."],"wordsMeanings":[],"category":"quran","bookId":"muslim","tags":["اقرؤوا","القرآن","فإنه","يأتي","يوم","القيامة"],"source":"hadeethenc"},{"id":"he_10913","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : إذا قرأتم: الحمد لله فاقرءوا: ﴿بسم الله الرحمن الرحيم﴾ إنها أم القرآن، وأم الكتاب، والسبع المثاني، و﴿بسم الله الرحمن الرحيم﴾ إحداها.","attribution":"رواه البيهقي والدراقطني","grade":"صحيح","gradeKey":"sahih","explanation":"يبين الحديث الشريف مشروعية قراءة البسملة قبل الفاتحة في الصلاة؛ وعلل ذلك بأنها جزء من سورة الفاتحة، والمراد قراءتها سرًا لا جهرًا، فقد ورد عدم الجهر في أحاديث أكثر وأصح، وقال الطحاوي: إن ترك الجهر بالبسملة في الصلاة تواتر عن النبي صلى الله عليه وسلم وخلفائه.","reference":"سنن الدارقطني، تحقيق: شعيب الأرنؤوط وآخرون، ط1، مؤسسة الرسالة، بيروت، لبنان، 1424 هـ.\nصحيح الجامع الصغير وزيادته للألباني، ط3، المكتب الإسلامي، بيروت، 1408هـ.\nسنن البيهقي الكبرى، أحمد بن الحسين أبو بكر البيهقي، مكتبة دار الباز، مكة المكرمة، 1414هـ – 1994م، تحقيق: محمد عبد القادر عطا.\nتوضيح الأحكام من بلوغ المرام، لعبدالله بن عبد الرحمن البسام، مكتبة الأسدي، مكة، ط الخامسة 1423هـ.","benefits":["الحديث يدل على مشروعية قراءة \"البسملة\" في الصلاة، عند إرادة قراءة الفاتحة، وذكر العلة في ذلك بأنَّها إحدى آيات الفاتحة، فهي منها.","الجهر بالبسملة معارض بأحاديث صحيحة، وذكر بعض العلماء أن ترك الجهر بالبسملة في الصلاة تواتر عن النبي -صلى الله عليه وسلم- وخلفائه."],"wordsMeanings":[{"word":"السبع المثاني","meaning":" سورة الفاتحة، وسميت الفاتحة السبع المثاني؛ لأنها تثُنى في كل صلاة أي تُقرأ وتعاد."}],"category":"quran","tags":["إذا","قرأتم:","الحمد","لله","فاقرءوا:","بسم"],"source":"hadeethenc"},{"id":"he_58176","text":"عن عائشة، أنها قالت: \"كان فِيمَا أُنْزِلُ من القرآن: (عَشْرُ رَضَعَاتٍ مَعْلُومَاتٍ يُحَرِّمْنَ)، ثم نُسِخْنَ بِخَمْسٍ مَعْلُومَاتٍ، فَتُوُفِّيَ رَسُولُ الله صلى الله عليه وسلم ، وهُنَّ فِيمَا يُقْرَأُ من القرآن\".","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث بيان أنَّ الرضاع المحرِّم كان في أول الأمر عشر رضعات نزل بها القرآن، فنسخ لفظه وحُكمه، إلى خمس رضعات يحرمن، وتوفي رسول الله صلى الله عليه وسلم وهنَّ مما يقرأ، لتَأَخَّرَ إِنْزالُ الناسخ جدًّاً، حتى خفي على بعض الناس، وكان يقرأ الآية المنسوخة على انها من القرآن.","reference":"- فتح ذي الجلال والاكرام بشرح بلوغ المرام، للشيخ ابن عثيمين، المكتبة الإسلامية - الطبعة الأولى 1427 - 2006م\n- توضِيحُ الأحكَامِ مِن بُلوُغ المَرَام، للبسام. مكتَبة الأسدي، مكّة المكرّمة. الطبعة: الخامِسَة، 1423 هـ - 2003 م\n- بلوغ المرام من أدلة الأحكام، لابن حجر.  دار القبس للنشر والتوزيع، الرياض - المملكة العربية السعودية\nالطبعة: الأولى، 1435 هـ - 2014 م\n- صحيح مسلم, ترقيم محمد فؤاد عبد الباقي, د","benefits":["أن الرضاع الذي تثبت به الحرمة خمس رضعات، وما نقص عنها فلا يُحرِّم.","إثبات علو الله تعالى؛ لأن النزول لا يكون إلا من أعلى.","أنه لا يجوز العمل بالمنسوخ.","خفاء النسخ على بعض الصحابة، وهذا لا يؤثر في حفظ القرآن الكريم."],"wordsMeanings":[{"word":"كان فيما أنزل من القرآن","meaning":" أي كانت هذه الآية سَابِقًا في القرآن."},{"word":"عشر رضعات معلومات يحرمن","meaning":" أي : أن المحرِّمَ عشر رضعات."},{"word":"نُسِخْنَ","meaning":" النسخ لغةً: الإزالة والنقل، واصطلاحًا: رفع حكمٍ شرعيٍّ، أو رفعُ لفظه بدليلٍ من الكتاب والسنة."},{"word":"معلومات","meaning":" متحققات ثابتات."},{"word":"وهن فيما يقرأ من القرآن","meaning":" أي: أنَّ النَّسْخ بِخَمْس رَضَعاتٍ تَأَخَّرَ إِنْزالُه جدًّاً، حتى خفي على بعض الناس، وكان يقرأ الآية المنسوخة على انها من القرآن."}],"category":"quran","bookId":"muslim","tags":["كان","فيما","أنزل","القرآن:","(عشر","رضعات"],"source":"hadeethenc"},{"id":"he_58197","text":"عن أبي جحيفة رضي الله عنه قال: قلت لعلي رضي الله عنه : هل عندكم شيء من الوحي إلا ما في كتاب الله؟ قال: «لا والذي فَلَقَ الحَبَّةَ، وبَرَأَ النَّسْمَةَ، ما أعلمه إلا فَهْمَاً يُعطيه الله رجلا في القرآن، وما في هذه الصحيفة»، قلت: وما في الصحيفة؟ قال: «العَقْلُ، وفِكَاكُ الأَسير، وأن لا يُقتَلَ مسلم بكافر».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"سأل أبوجحيفة رضي الله عنه عليًّا رضي الله عنه : هل خصكم النبي صلى الله عليه وسلم بعلم أو شيء مكتوب عندكم دون غيركم من الناس، وإنما سأله أبو جحيفة عن ذلك لأن جماعة من الشيعة كانوا يزعمون أن عند أهل البيت لا سيما عليًّا أشياء من الوحي خصهم النبي صلى الله عليه وسلم بها لم يطلع غيرهم عليها، وقد سأل عليًّا عن هذه المسألة غير واحد، فأجابه علي رضي الله عنه حالفًا يمينًا كانت تحلفه العرب، وهو الحلف بالله الذي خلق الإنسان وشق الحب، بأنه ليس عندهم شيء غير الفهم الذي يؤتيه الله عبده، غير كتاب كتبه عن رسول الله صلى الله عليه وسلم ، فيه أحكام الديات وتخليص أسرى المسلمين من الأسر، وأن لا يقتل مسلم بكافر، وذلك لأن الكافر ليس كفؤاً للمسلم ليقتل به، بل هو دونه.","reference":"صحيح البخاري، عناية محمد زهير الناصر، دار طوق النجاة، الطبعة الأولى، 1422هـ.\nتوضيح الأحكام شرح بلوغ المرام: تأليف عبد الله البسام، مكتبة الأسدي، مكة المكرمة، الطبعة: الخامِسَة، 1423 هـ - 2003 م.\nتسهيل الإلمام بفقه الأحاديث من بلوغ المرام: تأليف الشيخ صالح الفوزان، عناية عبد السلام السليمان، مؤسسة الرسالة، الطبعة الأولى.\nفتح ذي الجلال والإكرام بشرح بلوغ المرام للشيخ ابن عثيمين، المكتبة الإسلامية ال","benefits":["أنه لا يقتل مسلم بكافر، فإن الكافر غير مكافىء للمسلم.","مفهومه أن الكافر يقتل بالمسلم وهو إجماع العلماء؛ ويؤيده ما في الصحيح: \"أن النبي -صلى الله عليه وسلم- قتل يهوديًّا رضخ رأس جارية من الأنصار\"، ولأن المسلم أعلى رتبة بإسلامه من الكافر.","وجوب فك الأسير المسلم.","ما امتن الله به على أهل السنة من ظهور كذب الرافضة في دعواهم أن عند أهل البيت قرآنًا سوى هذا المصحف.","أن الله يمن على من يشاء من عباده بنعمة الفهم.","جواز الإقسام بلا قسم إذا كان الأمر مهمًّا واقتضت المصلحة ذلك.","احتفاظ علي -رضي الله عنه- بالسنة وعنايته بها وكتابته لها.","حرص أبي جحيفة -رضي الله عنه- على السؤال والعلم.","تحمل العاقلة -وهم عصبة الرجل من الذكور الذين يرثونه- للدية."],"wordsMeanings":[{"word":"والذي فلق الحبة","meaning":" وهذا من أيمان العرب، ومعنى: فلق الحبة: شقها في الأرض حتى تثمر، فكان منها حب كثير، وكل شيء شققته فقد فلقته."},{"word":"وبرأ","meaning":" خلق."},{"word":"النسمة","meaning":" الإنسان والنفس."},{"word":"العقل","meaning":" الدية."},{"word":"أو ما في هذه الصحيفة","meaning":" أي الورقة المكتوبة."},{"word":"وفِكاك الأسير","meaning":" أن فيها حكم تخليص الأسير من يد العدو، والترغيب في ذلك."}],"category":"quran","bookId":"bukhari","tags":["سئل","علي","رضي","الله","عنه","عندكم"],"source":"hadeethenc"},{"id":"he_64607","text":"عن علي بن أبي طالب رضي الله عنه أنه قال: «أنا أَوَّلُ من يَجْثُو بين يَدَيِ الرحمن للخُصُومة يوم القيامة» وقال قيس بن عباد: وفيهم أُنْزِلَتْ : {هذان خصمان اخْتَصَمُوا في ربهم} [الحج: 19] قال: \"هم الذين تَبَارَزُوا يوم بَدْرٍ: حمزة، وعلي، وَعُبَيْدَةُ، أو أبو عبيدة بن الحارث، وَشَيْبَةُ بن رَبِيعَةَ، وعتبة بن رَبِيعَةَ، والوليد بن عُتْبَةُ\".","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أفاد هذا الأثر عن علي رضي الله عنه أنه أخبر عن نفسه بأنه أول من يجلس على ركبتيه يوم القيامة للخصومة بين يدي رب العالمين، وأن هذه الآية (هذان خصمان اختصموا في ربهم) نزلت فيه وفي حمزة وأبي عبيدة رضي الله عنهم ، لما بارزوا رؤوس الكفر يوم غزوة بدر وهم شيبة بن ربيعة وعتبة بن ربيعة والوليد بن عتبة، فدل ذلك على جواز المبارزة والمبارزة -المقاتلة بالسيوف بين اثنين قبل المعركة- قبل بدء المعركة.","reference":"صحيح البخاري -الجامع الصحيح-؛ للإمام أبي عبد الله محمد بن إسماعيل البخاري، عناية محمد زهير الناصر، دار طوق النجاة، الطبعة الأولى، 1422هـ.\nالبدرُ التمام شرح بلوغ المرام، الحسين بن محمد بن سعيد، المعروف بالمَغرِبي، المحقق: علي بن عبد الله الزبن: دار هجر الطبعة: الأولى، 1414 هـ - 1994 م.\nإرشاد الساري لشرح صحيح البخاري، أحمد بن محمد بن أبى بكر القسطلاني القتيبي المصري، المطبعة الكبرى الأميرية، مصر- ال","benefits":["جواز المبارزة لمن علم في نفسه الكفاءة، وأما من ليس كفأً فلا يبارز؛ لئلا يعرض نفسه للقتل بحالة لم يتَّخذ لها الحيطة والحذر، و لئلا يَفُتَّ في عضد جيش المسلمين، ويكسر قلوبهم.","للمبارزة شرطان: العلم بكيفية المبارزة والقوة."],"wordsMeanings":[{"word":"يجثو","meaning":" يجلس على ركبتيه."},{"word":"وفيهم","meaning":" أي في حمزة وصاحبيه وعتبة وصاحبيه."}],"category":"quran","bookId":"bukhari","tags":["قول","علي","أبي","طالب","رضي","الله"],"source":"hadeethenc"},{"id":"he_65174","text":"عَنْ أَبِي هُرَيْرَةَ، قَالَ: قَالَ رَسُولُ اللَّهِ -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ-: \"مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا لَهُ مَنْزِلَانِ: مَنْزِلٌ فِي الْجَنَّةِ، وَمَنْزِلٌ فِي النَّارِ، فَإِذَا مَاتَ فَدَخَلَ النَّارَ، وَرِثَ أَهْلُ الْجَنَّةِ مَنْزِلَهُ\" فَذَلِكَ قَوْلُهُ عز وجل : {أُولَئِكَ هُمْ الْوَارِثُونَ} [المؤمنون: 10].","attribution":"رواه ابن ماجه","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم أن كل أحد له منزلان هما: منزل في الجنة ومنزل في النار، ثم إذا مات ودخل النار فقد سكن منزله الذي في النار ويرث أهل الجنة منزله الذي في الجنة، وهذا القول هو تفسيرٌ من النبي صلى الله عليه وسلم للآية: {أُولَئِكَ هُمْ الْوَارِثُونَ} والوارثون هم الآخذون ما تركه الآخرون، فهم أخذوا وورثوا بيت الكافر في الجنة منه.","reference":"سنن ابن ماجه (5/ 389) (4341)، حاشية السندي على سنن ابن ماجه (2/ 595)، مرشد ذوي الحجا والحاجة إلى سنن ابن ماجه (26/403).","benefits":["دليل على تفسير القرآن بالسنة.","كل أحد له منزلان في الجنة وفي النار وفي هذا الحث على العمل الصالح لدخول منزل الجنة."],"wordsMeanings":[{"word":"الوارثون","meaning":" الآخذون ما تركه الآخرون."}],"category":"quran","bookId":"ibnmajah","tags":["منكم","أحد","إلا","منزلان"],"source":"hadeethenc"},{"id":"he_65214","text":"عن عائشة، زوج النبي صلى الله عليه وسلم أنها كانت لا تسمع شيئا لا تعرفه، إلا راجعت فيه حتى تعرفه، وأن النبي صلى الله عليه وسلم قال: «من حوسب عذب» قالت عائشة: فقلت أوليس يقول الله تعالى: {فسوف يحاسب حسابا يسيرا} [الانشقاق: 8] قالت: فقال: «إنما ذلك العرض، ولكن: من نوقش الحساب يهلك».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"عن عائشة رضي الله عنها زوج النبي صلى الله عليه وسلم أي زوجته والأول أفصح، أنها كانت لا تسمع شيئًا لا تعرفه إلا راجعت فيه حتى تعرفه، أي سألت عنه حتى تعرفه، وهذا من حرصها على التعلم، وأن النبي صلى الله عليه وسلم قال: من حوسب عذب، وفيه معنيان: إما أنَّ نفس مناقشة الحساب يوم عرض الذنوب والتوقيف على قبيح ما سلف تعذيب وتوبيخ، أو أنه مفضٍ إلى استحقاق العذاب، إذ لا حسنة للعبد يعملها إلا من عند الله وبفضله وإقداره له عليها وهدايته لها، وأن الخالص لوجهه تعالى من الأعمال قليل، قالت عائشة: فقلت أوليس يقول الله تعالى: {فسوف يحاسب حسابًا يسيرًا} قوله: (يسيرًا) أي سهلًا هيّنًا لا يناقش فيه ولا يعترض بما يشق عليه كما يناقش أصحاب الشمال، ووجه المعارضة بين الحديث والآية أن الحديث عام في تعذيب من حوسب، والآية تدل على عدم تعذيب بعضهم، وهم أصحاب اليمين، قالت عائشة: فقال: إنما ذلك العرض أي: الإبراز والإظهار، ولكن من نوقش الحساب من المناقشة وهي الاستقصاء في الحساب حتى لا يترك منه شيء، يهلك أي: أن التقصير غالب على العباد، فمن استقصي عليه ولم يسامح هلك وأدخل النار، ولكن الله تعالى يعفو ويغفر ما دون الشرك لمن شاء.","reference":"صحيح البخاري (1/ 32) (103)، صحيح مسلم (4/ 2204) (2876)، عمدة القاري شرح صحيح البخاري (2/ 138).","benefits":["بيان فضيلة عائشة رضي الله عنها وحرصها على التعلم، وأن رسول الله صلى الله عليه وسلم ما كان يتضجر من مراجعتها.","إثبات الحساب والعرض.","إثبات العذاب يوم القيامة.","جواز المناظرة ومقابلة السنة بالكتاب بقصد البحث عن الحق والتعلم مع التأدب في الطرح.","تفاوت الناس في الحساب يوم القيامة."],"wordsMeanings":[{"word":"راجعت فيه","meaning":" سألت عنه."},{"word":"إنما ذلك العرض","meaning":" الإبراز والإظهار."},{"word":"نوقش الحساب","meaning":" من المناقشة، وهي الاستقصاء في الحساب."}],"category":"quran","tags":["نوقش","الحساب","يهلك"],"source":"hadeethenc"},{"id":"he_65218","text":"عَنْ جُنْدُبِ بْنِ عَبْدِ اللَّهِ رَضيَ اللهُ عنهُ قَالَ: كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِتْيَانٌ حَزَاوِرَةٌ، فَتَعَلَّمْنَا الإِيمَانَ قَبْلَ أَنْ نَتَعَلَّمَ القُرْآنَ، ثُمَّ تَعَلَّمْنَا القُرْآنَ، فَازْدَدْنَا بِهِ إِيمَانًا.","attribution":"رواه ابن ماجه","grade":"صحيح","gradeKey":"sahih","explanation":"قال جندب بن عبد الله رضي الله عنه: كنا مع النبي صلى الله عليه وسلم ونحن فِتْيَان قاربْنا البلوغ، أقوياء أشداء، فتعلَّمنا عند النبي صلى الله عليه وسلم الإيمان قبل أن نتعلَّم القرآن، ثم تعلَّمنا القرآن؛ فازددنا به إيمانًا.","reference":"سنن ابن ماجه (1/ 42) (61).\nمشارق الأنوار الوهاجة ومطالع الأسرار البهاجة في شرح سنن الإمام ابن ماجه (2/ 255).\nمرشد ذوي الحجا والحاجة إلى سنن ابن ماجه والقول المكتفى على سنن المصطفى (1/ 227).","benefits":["بيان أن الإيمان يزيد وينقص.","ترتيب الأولويات عند تربية النشء، والحرص على ملئهم بالإيمان.","القرآن يزيد الإيمانَ، ويتنوَّر به القلب، وينشرح به الصدر."],"wordsMeanings":[],"category":"quran","bookId":"ibnmajah","tags":["كنا","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_65223","text":"عن عبد الله بن عمرو قال: كان نبيُّ الله -صلَّى الله عليه وسلم- يُحدِّثنا عن بني إسرائيلَ حتى يُصبحَ، ما يقومُ إلا إلى عُظمِ صلاة.","attribution":"رواه أبو داود","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبي صلى الله عليه وسلم يحدث الصحابة عن بني إسرائيل، ومعلوم أن حديث النبي صلى الله عليه وسلم عن بني إسرائيل هو إخبار منه صلى الله عليه وسلم فهو حديث نبوي، فإذا ثبت هذا الخبر عن بني إسرائيل بإسناد صحيح متصل إلى رسول الله صلى الله عليه وسلم فإنه يُصدَّق هذا الخبر، ويعتبر هذا الخبر صدقًا ما دام ثابتًا عن رسول الله عليه الصلاة والسلام، وأما إذا لم يكن ثابتًا عن النبي صلى الله عليه وسلم فإنه لا يصدق ولا يكذب، وقال النبي عليه الصلاة والسلام: (إذا حدَّثكم أهلُ الكتاب بشيء فلا تصدقوهم ولا تكذبوهم، {وَقُولُوا آمَنَّا بِالَّذِي أُنْزِلَ إِلَيْنَا وَأُنْزِلَ إِلَيْكُمْ} [العنكبوت:46]) إلا أن يكون ذلك الحديث الذي جاء عن بني إسرائيل باطلًا كأشياء تضاف إلى الأنبياء لا تليق بهم، فهذه لا يتردد في تكذيبها، بل الواجب هو المبادرة إلى تكذيبها وعدم تصديقها.\nوقوله: (كان يحدثنا عن بني إسرائيل حتى يصبح) لعل هذا حصل في بعض الليالي، ومعلوم أن هذا كان بعد صلاة الليل، وليس معنى ذلك أنه يكون من أول الليل إلى آخره، وأنه يشغل بذلك عن صلاة الليل، فقد كان صلى الله عليه وسلم مداومًا عليها، وكان صلى الله عليه وسلم يصلي من أول الليل ومن وسطه ومن آخره حتى انتهى وتره صلوات الله وسلامه وبركاته عليه إلى السحر، وخلاصة ذلك: أن هذا كان في بعض الأحيان وليس دائمًا وأبدًا.\nوقوله: (وما يقوم إلا إلى عُظْم صلاة) يعني: إلى صلاة فريضة، وقوله: (حتى يصبح) معناه: أنه يقوم إلى صلاة الفجر.","reference":"سنن أبي داود (5/ 504) (3663)، شرح سنن أبي داود للعباد (415/ 5)، شرح سنن أبي داود لابن رسلان (15/115).","benefits":["الإخبار عن الأمم السابقة وقصصهم للاتعاظ بهم.","تعدد ذكر بني إسرائيل في القرآن الكريم والأحاديث النبوية تعليمًا وإرشادًا لأمة الإسلام.","الاهتمام بصلاة الفريضة وعدم الانشغال عنها بأي شيء آخر."],"wordsMeanings":[{"word":"حتى يُصبح","meaning":" حتى يقوم لصلاة الفجر."},{"word":"عُظم صلاة","meaning":" صلاة فريضة."}],"category":"quran","bookId":"abudawud","tags":["كان","نبيُّ","الله","-صلَّى","الله","عليه"],"source":"hadeethenc"},{"id":"he_65231","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «مَا مِنَ الأَنْبِيَاءِ نَبِيٌّ إِلَّا أُعْطِيَ مَا مِثْلهُ آمَنَ عَلَيْهِ البَشَرُ، وَإِنَّمَا كَانَ الَّذِي أُوتِيتُ وَحْيًا أَوْحَاهُ اللَّهُ إِلَيَّ، فَأَرْجُو أَنْ أَكُونَ أَكْثَرَهُمْ تَابِعًا يَوْمَ القِيَامَةِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"ذكر النبي صلى الله عليه وسلم أن الأنبياء كلهم أيَّدَهم الله وأعطاهم الآيات والمعجزات الخوارق التي يستدل بها على نبوته وتقتضي إيمان من شاهدها بصدقهم، وأنه مغلوب عليه في التحدي بحيث لا يستطيع دفعها عن نفسه، لكن قد يجحد فيعاند.\n\nوإنما هو صلى الله عليه وسلم آيته ومعجزته القرآن الذي أوحاه الله إليه؛ لما اشتمل عليه من الإعجاز الواضح المستمر لكثرة فائدته وعموم نفعه، لاشتماله على الدعوة والحجة والإخبار بما سيكون، فعم نفعه من حضر ومن غاب ومن وجد ومن سيوجد، ثم قال: فأرجو أن أكون أكثرهم أتباعًا يوم القيامة.","reference":"صحيح البخاري (6/ 182) (4981).\nصحيح مسلم (1/ 134) (152).\nعمدة القاري شرح صحيح البخاري (25/ 25).\nشرح النووي على مسلم (2/ 188).","benefits":["إثبات الآيات للأنبياء، وهذا من رحمة الله تعالى وفضله على الأمم.","بيان عظم معجزة النبي صلى الله عليه وسلم.","بيان عظم منزلة النبي صلى الله عليه وسلم وأفضليته على سائر الأنبياء.","قال ابن حجر في قوله: \"وَإِنَّمَا كَانَ الَّذِي أُوتِيتُ وَحْيًا أَوْحَاهُ اللَّهُ إِلَيَّ\": وليس المراد حصر معجزاته فيه، ولا أنه لم يؤتَ من المعجزات ما أوتي مَن تقدَّمه، بل المراد أنه المعجزة العظمى التي اختص بها دون غيره.","قال النووي: \"(فَأَرْجُو أَنْ أَكُونَ أَكْثَرَهُمْ تَابِعًا) علم من أعلام النبوة، فإنه أخبر صلى الله عليه وسلم بهذا في زمن قلة المسلمين، ثم منَّ الله تعالى وفتح على المسلمين وبارك فيهم حتى انتهى الأمر واتسع الأمر في المسلمين إلى هذه الغاية المعروفة ولله الحمد."],"wordsMeanings":[],"category":"quran","tags":["الأنبياء","نبي","إلا","أعطي","مثله","آمن"],"source":"hadeethenc"},{"id":"he_66529","text":"عَنْ أَبِي نَجِيحٍ العِرْبَاضِ بْنِ سَارِيَةَ رضي الله عنه قَالَ: وَعَظَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْعِظَةً وَجِلَتْ مِنْهَا القُلُوبُ، وَذَرَفَتْ مِنْهَا العُيُونُ، فَقُلْنَا: يَا رَسُولَ اللهِ! كَأَنَّهَا مَوْعِظَةُ مُوَدِّعٍ؛ فَأَوْصِنَا، قَالَ: «أُوصِيكُمْ بِتَقْوَى اللَّهِ، وَالسَّمْعِ وَالطَّاعَةِ، وَإِنْ تَأَمَّرَ عَلَيْكُمْ عَبْدٌ، فَإِنَّهُ مَنْ يَعِشْ مِنْكُمْ بَعْدِي فَسَيَرَى اخْتِلَافًا كَثِيرًا، فَعَلَيْكُمْ بِسُنَّتِي وَسُنَّةِ الخُلَفَاءِ الرَّاشِدِينَ المَهْدِيينَ، عَضُّوا عَلَيْهَا بِالنَّوَاجِذِ، وَإِيَّاكُمْ وَمُحْدَثَاتِ الأُمُورِ؛ فَإِنَّ كُلَّ بِدْعَةٍ ضَلَالَةٌ».","attribution":"رواه أبو داود والترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"وَعَظَ النبيُّ صلى الله عليه وسلم أصحابَه مَوعظةً بَلِيْغَةً خافتْ منها القلوبُ ودَمَعتْ منها العيونُ، فقالوا: يا رسول الله كأنها مَوعظةُ مُودِّعٍ لِمَا رأوا مِن مبالغتِه صلى الله عليه وسلم في الموعظة، فطلبوا وصيةً ليتمسكوا بها مِن بعده، قال: أوصيكم بتقوى الله عز وجل، وذلك بفعل الواجبات وترك المحرمات، والسمع والطاعة، أي: للأمراء، وإنْ تَأَمَّر عليكم عَبْدٌ أو استولى عليكم، أي صار أدنى الخَلْقِ أميرًا عليكم فلا تَسْتَنْكِفُوا عن ذلك وأطيعوه، مخافةَ إثارةِ الفتن، فإنه مَن يعِش منكم فسيرى اختلافًا كثيرًا، ثم بَيَّنَ لهم المَخْرَجَ مِن هذا الاختلاف، وذلك بالتمسُّك بِسُنَّتِهِ وسُنّةِ الخلفاء الراشدين المهديين مِن بعده، أبي بكر الصديق، وعمر بن الخطاب، وعثمان بن عفان، وعلي بن أبي طالب رضي الله عنهم أجمعين، والعَضُّ عليها بالنواجذ أي –الأضراس الأخيرة-: يعني بذلك الجِدُّ في لزوم السنة والتمسك بها، وحَذَّرَهم من الأمور المُحدَثة المُبْتَدَعة في الدِّين، فإنِّ كلَّ بدعةٍ ضلالةٌ.","reference":"الأربعون النووية (ص: 89) (ح28).\nسنن أبي داود (7/ 16) (4607).\nسنن الترمذي (4/ 408) (2676).\nسنن ابن ماجه (1/ 28) (42).\n مسند أحمد (28/ 367) (17142).\nتحفة الأحوذي (7/ 366).\nعون المعبود وحاشية ابن القيم (12/ 235).\nشرح الأربعين النووية للعثيمين (ص: 278).","benefits":["أهمية التَّمَسُّكِ بالسُّنّة واتباعها.","العناية بالمواعظ وترقيق القلوب.","الأمر باتباع الخُلَفاء الراشدين المهديين الأربعة مِن بعده، وهم أبو بكر وعمر وعثمان وعلي رضي الله عنهم.","النهيُ عن الابتداع في الدِّين، وأنّ كل البدع ضلالة.","السمع والطاعة لمَن تولَّى أمر المؤمنين في غير معصية.","أهمية تقوى الله عز وجل في كل الأوقات والأحوال.","الاختلاف واقع في هذه الأمة، وعند حدوثِهِ يلزم الرجوعُ إلى سُنّة رسول الله صلى الله عليه وسلم والخلفاء الراشدين."],"wordsMeanings":[],"category":"mustalah","bookId":"abudawud","tags":["أوصيكم","بتقوى","الله،","والسمع","والطاعة،","وإن"],"source":"hadeethenc"},{"id":"he_3686","text":"عن عبد الله بن عمرو رضي الله عنهما أن النبي صلى الله عليه وسلم قال: «بَلِّغُوا عَنِّي وَلَوْ آيَةً، وَحَدِّثُوا عَنْ بَنِي إِسْرَائِيلَ وَلَا حَرَجَ، وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يأمرُ النبيُّ صلى الله عليه وسلم بتبليغ العلم عنه من كتاب أو سنة، ولو كان الشيء قليلًا كآية من القرآن أو حديث، بشرط أن يكون عالمًا بما يبلِّغُ به ويدعو إليه. \nثم بيَّن صلى الله عليه وسلم أنه لا بأس بالتحديث عن بني إسرائيل بما وقع لهم من وقائع بما لا يتعارض مع شرعنا. \nثم حذَّر من الكذب عليه، وأنَّ من كذَب عليه متعمِّدًا فليتخذْ لنفسه مَنزلًا في النار.","reference":"صحيح البخاري (4/ 170) (3461).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 464).\nنزهة المتقين، لمصطفى الخن وغيره (2/ 951).\nشرح رياض الصالحين، لابن عثيمين (5/ 429).","benefits":["الترغيب في تبليغ شريعة الله، وأن المرء عليه أنْ يؤديَ ما حفِظَ وفَهِمَ ولو كان يسيرًا.","وجوب طلب العلم الشرعي؛ ليتمكَّن من عبادة الله وتبليغ شريعته بصورة صحيحة.","وجوب التأكد من صحة أي حديث قبل تبليغه أو نشره حذرًا من الدخول في هذا الوعيد الشديد.","الحث على الصدق في الكلام والحيطة في الحديث، حتى لا يقع في الكذب، وخاصة في شرع الله عز وجل."],"wordsMeanings":[{"word":"لا حرج","meaning":" لا إثم ولا ذنب."},{"word":"بنو إسرائيل","meaning":" هم بنو يعقوب بن إسحاق بن إبراهيم، فإسرائيل لقب ليعقوب. والمراد أتباع دينهم من اليهود والنصارى."}],"category":"mustalah","bookId":"bukhari","tags":["بلغوا","عني","ولو","آية،","وحدثوا","بني"],"source":"hadeethenc"},{"id":"he_65005","text":"عن المقدام بن معدِيْكَرِب رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «أَلَا هَلْ عَسَى رَجُلٌ يَبْلُغُهُ الْحَدِيثُ عَنِّي وَهُوَ مُتَّكِئٌ عَلَى أَرِيكَتِهِ فَيَقُولُ: بَيْنَنَا وَبَيْنَكُمْ كِتَابُ اللهِ، فَمَا وَجَدْنَا فِيهِ حَلَالًا اسْتَحْلَلْنَاهُ، وَمَا وَجَدْنَا فِيهِ حَرَامًا حَرَّمْنَاهُ، وَإِنَّ مَا حَرَّمَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَمَا حَرَّمَ اللهُ».","attribution":"رواه أبو داود والترمذي وابن ماجه","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم أنه قد اقترب زمان يكون فيه صنف من الناس جالس، أحدهم متكئ على فراشه، يبلغه الحديث عن النبي صلى الله عليه وسلم، فيقول: الذي يَفْصِلُ بيننا وبينكم في الأمور هو القرآن الكريم فهو يكفينا، فما وجدنا فيه من حلال عملنا به، وما وجدنا فيه من حرام ابتعدنا عنه. \nثم بَيَّن النبي صلى الله عليه وسلم أن كل شيء حرّمه أو نهى عنه في سنته فهو في الحكم مثل ما حرّمه الله في كتابه؛ لأنه المبلغ عن ربه.","reference":"سنن أبي داود (7/ 13) (4604)، سنن الترمذي (4/ 399) (2664)، سنن ابن ماجه (1/ 9) (12)، نخب الأفكار في تنقيح مباني الأخبار في شرح معاني الآثار (13/ 154).","benefits":["تعظيم السنة كما يُعَظَّم القرآن ويؤخذ بها.","طاعة الرسول هي طاعة لله ومعصيته هي معصية لله تعالى.","ثبوت حُجِيّة السنة والرد على من يَرُدُّ السُّننَ أو ينكرها.","مَن أعرض عن السُّنَّة وادعى الاقتصار على القرآن فهو مُعرِضٌ عنهما جميعًا كاذبٌ في دعوى اتباع القرآن.","من دلائل نبوته صلى الله عليه وسلم إخباره عن شيء بأنه سيقع في المستقبل، ووقع كما أخبر."],"wordsMeanings":[],"category":"mustalah","bookId":"abudawud","tags":["ألا","عسى","رجل","يبلغه","الحديث","عني"],"source":"hadeethenc"},{"id":"he_65057","text":"عن العِرْباضِ بن ساريةَ رضي الله عنه قال: قام فينا رسول الله صلى الله عليه وسلم ذات يوم، فوَعَظَنا مَوعظةً بليغةً وَجِلتْ منها القلوبُ، وذَرَفتْ منها العيونُ، فقيل: يا رسول الله، وعظتَنَا موعظةَ مُودِّعٍ فاعهد إلينا بعهد. فقال: «عليكم بتقوى الله، والسمع والطاعة، وإن عبدًا حبشيًّا، وسترون من بعدي اختلافًا شديدًا، فعليكم بسنتي وسنة الخلفاء الراشدين المهديين، عَضُّوا عليها بالنواجِذ، وإياكم والأمور المحدثات، فإن كل بدعة ضلالة».","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"وَعَظَ النبيُّ صلى الله عليه وسلم أصحابَه مَوعظةً بَلِيْغَةً خافتْ منها القلوبُ ودَمَعتْ منها العيونُ، \nفقالوا: يا رسول الله كأنها مَوعظةُ مُودِّعٍ لِمَا رأوا مِن مبالغتِه صلى الله عليه وسلم في الموعظة، فطلبوا وصيةً ليتمسكوا بها مِن بعده، \nقال: أوصيكم بتقوى الله عز وجل، وذلك بفعل الواجبات وترك المحرمات، \nوالسمع والطاعة، أي: للأمراء، وإنْ تَأَمَّر عليكم عَبْدٌ أو استولى عليكم، أي صار أدنى الخَلْقِ أميرًا عليكم فلا تَسْتَنْكِفُوا عن ذلك وأطيعوه، مخافةَ إثارةِ الفتن، فإنه مَن يعِش منكم فسيرى اختلافًا كثيرًا، \nثم بَيَّنَ لهم المَخْرَجَ مِن هذا الاختلاف، وذلك بالتمسُّك بِسُنَّتِهِ وسُنّةِ الخلفاء الراشدين المهديين مِن بعده، أبي بكر الصديق، وعمر بن الخطاب، وعثمان بن عفان، وعلي بن أبي طالب رضي الله عنهم أجمعين، والعَضُّ عليها بالنواجذ أي –الأضراس الأخيرة-: يعني بذلك الجِدُّ في لزوم السنة والتمسك بها، \nوحَذَّرَهم من الأمور المُحدَثة المُبْتَدَعة في الدِّين، فإنِّ كلَّ بدعةٍ ضلالةٌ.","reference":"الأربعون النووية (ص: 89) (ح28)، سنن أبي داود (7/ 16) (4607)، سنن الترمذي (4/ 408) (2676)، سنن ابن ماجه (1/ 28) (42)، مسند أحمد (28/ 367) (17142)، تحفة الأحوذي (7/ 366)، عون المعبود وحاشية ابن القيم (12/ 235)، شرح الأربعين النووية للعثيمين (ص: 278).","benefits":["أهمية التَّمَسُّكِ بالسُّنّة واتباعها.","العناية بالمواعظ وترقيق القلوب.","الأمر باتباع الخُلَفاء الراشدين المهديين الأربعة مِن بعده، وهم أبو بكر وعمر وعثمان وعلي رضي الله عنهم.","النهيُ عن الابتداع في الدِّين، وأنّ كل البدع ضلالة.","السمع والطاعة لمَن تولَّى أمر المؤمنين في غير معصية.","أهمية تقوى الله عز وجل في كل الأوقات والأحوال.","الاختلاف واقع في هذه الأمة، وعند حدوثِهِ يلزم الرجوعُ إلى سُنّة رسول الله صلى الله عليه وسلم والخلفاء الراشدين."],"wordsMeanings":[],"category":"mustalah","bookId":"abudawud","tags":["عليكم","بتقوى","الله،","والسمع","والطاعة،","وإن"],"source":"hadeethenc"},{"id":"he_6982","text":"عَنْ سَمُرَةَ بْنِ جُنْدَبٍ وَالْمُغِيرَةِ بْنِ شُعْبَةَ رضي الله عنهما قَالَا: قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «مَنْ حَدَّثَ عَنِّي بِحَدِيثٍ يُرَى أَنَّهُ كَذِبٌ، فَهُوَ أَحَدُ الْكَاذِبِينَ».","attribution":"رواه مسلم في مقدمته","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أن مَن نَقَلَ عنه حديثًا وهو يعلم أو يظن أو يغلِب على ظنه أنه كذبٌ عليه صلى الله عليه وسلم؛ فالراوي له يُشاركُ البادي بهذا الكذب.","reference":"صحيح مسلم (1/ 8).","benefits":["التثبُّت من الأحاديث المروية عن النبي صلى الله عليه وسلم، والتأكد من صحتها قبل روايتها.","صفة الكذب تُطلق على كل من اختَرَعَ الكذب وعلى مَن قام بنقلِه ونشره بين الناس.","يحرم رواية الحديث الموضوع على مَن عَرَف كونَه موضوعًا، أو غلب على ظنه وضعُه إلا إذا كان للتحذير منه."],"wordsMeanings":[],"category":"mustalah","bookId":"muslim","tags":["حدث","عني","بحديث","يرى","أنه","كذب،"],"source":"hadeethenc"},{"id":"he_10849","text":"عن أبي سعيد الخدري أن رسول الله صلى الله عليه وسلم قال: «لا تكتبوا عني، ومَن كتب عني غيرَ القرآن فَلْيَمْحُه، وحدِّثوا عنِّي ولا حَرَج، ومَن كذب عليَّ -قال همام: أحسِبه قال: مُتعمِّدًا- فَلْيَتَبوَّأ مَقْعَدَه مِن النار».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"نهى النبي صلى الله عليه وسلم أصحابه أن يكتبوا عنه شيئًا، ومن كتب عنه شيئًا غير القرآن فليمحه، ثم أذن لهم أن يحدثوا عنه ولا إثم عليهم في ذلك، شريطة أن يتحروا الصدق فيما ينقلونه عنه صلى الله عليه وسلم ، وحذرهم بأن من كذب عليه متعمدًا فجزاؤه نار جهنم. \nوالنهي عن كتابة الحديث منسوخ؛ وذلك أنه صلى الله عليه وسلم نهى عنه في أول الأمر، فلأن الأحاديث تكثر وقد يفوت الحفظ شيئًا منها أجاز الكتابة، وقد قال صلى الله عليه وسلم في خطبته: «اكتبوا لأبى شاه» لما استكتبه، وجاء عنه صلى الله عليه وسلم أنه أذن لعبد الله بن عمرو في الكتابة، وقد أمر صلى الله عليه وسلم أمته بالتبليغ، فإذا لم يُكتب ذهب العلم، وقيل: إن هذا النهي إنما هو لكتابة الحديث مع القرآن فى صحيفة واحدة لئلا يختلط به، فيشتبه على القارئ، وقيل: إنّه خاصّ بوقت نزول القرآن خشية التباسه بغيره، ثم أذن فيه بعد ذلك.\nوالاحتمال الأول وهو النسخ أقرب.","reference":"- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي - بيروت.\n- مختار الصحاح، لزين الدين أبو عبد الله محمد بن أبي بكر بن عبد القادر الحنفي الرازي، تحقيق: يوسف الشيخ محمد، نشر: المكتبة العصرية - الدار النموذجية، بيروت – صيدا، لطبعة: الخامسة، 1420هـ - 1999م.\n- النهاية في غريب الحديث والأثر، لابن الأثير، نشر: المكتبة العلمية - بيروت، 1399هـ - 1979م، تحقيق: طاهر أحمد الزاوى - محمود م","benefits":["إباحة الحديث عنه -صلى الله عليه وسلم-، وتبليغ ما سمع منه، وقد جاءت الآثار بالحض على التبليغ والأمر به.","التحذير من التساهل عند الحديث عنه -صلى الله عليه وسلم- مما لم يتحقق منه، والتنبيه على التحرز في ذلك لئلا يقع في الكذب.","الوعيد الشديد على من كذب على النبي -صلى الله عليه وسلم- متعمدًا.","مشروعية كتابة القرآن والسنة وغيرهما من العلم.","النهي عن كتابة الحديث النبوي منسوخ, أو هو محمول على كتابته مع القرآن في صحيفة واحدة لكيلا يحصل خلط بينهما, أو أنه خاصّ بوقت نزول القرآن خشية التباسه بغيره."],"wordsMeanings":[{"word":"ولا حرج","meaning":" ولا إثم عليكم."},{"word":"فليتبوَّأ مقعده من النار","meaning":" ينزل منزله من النار."}],"category":"mustalah","bookId":"muslim","tags":["تكتبوا","عني،","ومن","كتب","عني","غير"],"source":"hadeethenc"},{"id":"he_65043","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ مَن كَذَبَ عليه مُتعمدًا بنِسبةِ قولٍ أو فعلٍ له كَذبًا، فإنّ له في الآخرة مَجلسًا في النار؛ جزاء له على كذبه عليه.","reference":"صحيح البخاري (1/ 33) (110)، صحيح مسلم (1/ 10) (3)، إكمال المعلم (1/111)، شرح النووي على مسلم (1/65)، المفهم (1/32)، عمدة القاري شرح صحيح البخاري (2/ 151)، شرح مقدمة سنن ابن ماجه (5/ 8).","benefits":["الكَذب على النبيِّ صلى الله عليه وسلم بالقصد والعَمْد سببٌ لدخول النار.","الكذب على النبي عليه الصلاة والسلام ليس كالكذب على سائر الناس، لِمَا يَترتَّب على ذلك من مفاسد عظيمة في الدين والدنيا.","التحذير من نشر الأحاديث قبل التثبُّت والتأكد من صحة نسبتها إلى النبي صلى الله عليه وسلم."],"wordsMeanings":[],"category":"mustalah","tags":["كذب","علي","متعمدا","فليتبوأ","مقعده","النار"],"source":"hadeethenc"},{"id":"he_65076","text":"عَنْ ‌أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ: «سَيَكُونُ فِي آخِرِ أُمَّتِي أُنَاسٌ يُحَدِّثُونَكُمْ مَا لَمْ تَسْمَعُوا أَنْتُمْ وَلَا آبَاؤُكُمْ، فَإِيَّاكُمْ وَإِيَّاهُمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم بأنه سيَظهر أُناسٌ في آخِر أُمتِه يَفْتَرون الكذب، ويقولون ما لم يقلْه أحدٌ من قبلهم، فيُخبِرون بالأحاديث المكذوبة والمُخْتَلَقة، فأمَرَنا عليه الصلاة والسلام أنْ نَبْتَعِدَ عنهم ولا نجالسهم، ولا نسمع أحاديثهم؛ لئلا يتقرر ذلك الحديث المختلق في النفوس، فنعجز عن التخلُّص منه.","reference":"صحيح مسلم (1/ 12) (6)، قرة عين المحتاج في شرح مقدمة صحيح مسلم بن الحجاج (2/ 8).","benefits":["فيه عَلَم من أعلام النبوة، حيث إن النبي صلى الله عليه وسلم أخبر بما سيقع في أمته، فكان كما أخبر.","الابتعاد عمّن يَكْذِبُ على رسول الله صلى الله عليه وسلم وعلى دين الإسلام، وعدم الاستماع لكذبهم.","التحذير من قبولِ الأحاديث أو نشرِها إلا بعد التأكُّد من صحتِها وثبوتِها."],"wordsMeanings":[{"word":"فإياكم إياهم","meaning":" أمر بالابتعاد عنهم."}],"category":"mustalah","bookId":"muslim","tags":["سيكون","آخر","أمتي","أناس","يحدثونكم","تسمعوا"],"source":"hadeethenc"},{"id":"he_65077","text":"عن عبدِ الله بن عمرو رضي الله عنهما قال: كنتُ أكتبُ كلَّ شيءٍ أسمعُه من رسولِ الله صلَّى الله عليه وسلم أُريدُ حفْظَه، فنهتْني قريشٌ، وقالوا: أتكْتبُ كلَّ شيءٍ تَسمَعُه من رسول الله صلَّى الله عليه وسلم، ورسولُ الله صلَّى الله عليه وسلم بَشَرٌ يتكلَّمُ في الغضَبِ والرِّضا؟ فأمسَكتُ عن الكتاب، فذكرتُ ذلك لرسول الله صلَّى الله عليه وسلم، فأومأ بإصبَعِه إلى فيه، فقال: «اكتُبْ، فوالذي نفسي بيدِه، ما يَخرُجُ منه إلا حقٌّ».","attribution":"رواه أبو داود","grade":"صحيح","gradeKey":"sahih","explanation":"قال عبدُ الله بن عَمْرو رضي الله عنه: كنتُ أكتبُ كلَّ شيءٍ أسمعه مِن رسول الله صلى الله عليه وسلم لكي أحفَظَه بالكتابة، فنهاني رجالٌ من قريش، وقالوا: رسولُ الله صلى الله عليه وسلم بشرٌ يتكلَّم في الرِّضا والغضب، وقد يُخطئ، فتوقَّفت عن الكتابة.\n\nفأخبرتُ النبيَّ صلى الله عليه وسلم بما قالوه، فأشار بإصبعه إلى فَمِهِ فقال: اكتب، فوالذي نفسي بيده ما يَخرجُ منه إلّا حقّ على كل حال، وفي الرِّضا والغضب.\n\nوقد قال تعالى عن نبيه صلى الله عليه وسلم:\n﴿وَمَا یَنطِقُ عَنِ ٱلۡهَوَىٰۤ * إِنۡ هُوَ إِلَّا وَحۡیࣱ یُوحَىٰ﴾ [النجم ٣-٤].","reference":"سنن أبي داود (5/ 489) (3646)، شرح سنن أبي داود للعباد (412/ 21).","benefits":["النبي صلى الله عليه وسلم معصوم فيما يُبَلِّغُه عن ربه عز وجل، في الرضا والغضب.","حرص الصحابة رضي الله عنهم على حفظِ السنة وتبليغِها.","جواز الحلف ولو بغير تحليفٍ لمصلحة، كتوكيد أمر.","كتابة العلم من أهم الأسباب التي تحفظ العلم."],"wordsMeanings":[],"category":"mustalah","bookId":"abudawud","tags":["اكتب،","فوالذي","نفسي","بيده،","يخرج","منه"],"source":"hadeethenc"},{"id":"he_3633","text":"عن وَاثِلَةَ بن الأَسْقَعِ ـ رضي الله عنه ـ مرفوعاً: «إن من أعظم الفِرَى أن يَدَّعِيَ الرجلُ إلى غير أبيه، أو يُرِي عَيْنَهُ ما لم تَرَ، أو يقول على رسول الله صلى الله عليه وسلم ما لم يَقْلْ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"إن من أشدِّ الكذبِ على الله تعالى : أن يَنْسبَ الرجل نفسه إلى غير أبيه الحقيقي أو يَنْسِبَه أحدٌ إلى غير أبيه فيُقِرَّه على ذلك. فهذا من أشدِّ أنواع الكذب، وإن من أعظم الكذب وأشده عند الله تعالى كذلك أن يدعي المرء أنه رأى في المنام شيئًا ولم يره أصلًا، وإن من أعظم الكذب وأشده عند الله تعالى أيضًا أن ينسب للنبي صلى الله عليه وسلم قولًا أو فعلًا أو تقريرًا ولم يوجد منه صلى الله عليه وسلم .","reference":"- صحيح البخاري، للإمام محمد بن إسماعيل البخاري، تحقيق محمد الناصر، دار طوق النجاة.\n- بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي- الطبعة الأولى1418ه.\n- نزهة المتقين شرح رياض الصالحين؛ تأليف د. مصطفى الخِن وغيره، مؤسسة الرسالة-بيروت، الطبعة الرابعة عشرة، 1407هـ.\n- كنوز رياض الصالحين»، لحمد بن ناصر العمار، دار كنوز إشبيليا- الطبعة الأولى1430ه.\n- دليل الفالحين لطرق رياض الصالح","benefits":["أن الانتساب إلى غير أبيه كبيرة؛لأن فيها تضييعًا للأنساب، وإدخال على الأسر ما ليس منه، ويترتب على ذلك محاذير شرعية كثيرة.","الكذب في الرؤيا كبيرة؛ لأنه كذِبٌ على الله -تعالى-.","الكذب على رسول الله -صلى الله عليه وسلم- كبيرة من كبائر الذنوب.","حرص الإسلام على تربية أتباعه على الصدق في كل الأحوال في النوم واليقظة، ومع الله -تعالى- ومع رسوله -صلى الله عليه وسلم- ومع النفس؛ فالصدق منجاة وطمأنينة وسكينة."],"wordsMeanings":[{"word":"الفرى","meaning":" الكذبة العظيمة."},{"word":"أن يدعي الرجل إلى غير أبيه","meaning":" هو أن يَتْنَسِب الإنسان إلى غير أبيه وعشيرته."},{"word":"أن يري عينه ما لم تر","meaning":" يكذب في رؤياه."}],"category":"mustalah","bookId":"bukhari","tags":["أعظم","الفِرَى","يَدَّعِيَ","الرجل","إلى","غير"],"source":"hadeethenc"},{"id":"he_65211","text":"عن زيد بن ثابت قال: سمعت رسول الله صلى الله عليه وسلم يقول: \"نضر الله امرأ سمع منا حديثا فحفظه حتى يبلغه، فرب حامل فقه إلى من هو أفقه منه، ورب حامل فقه ليس بفقيه\".","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"نضر الله امرأً هذا دعاء من النبي صلى الله عليه وسلم لمن اشتغل بسنته عليه الصلاة والسلام وبلغها وعمل بها أن يجعله ذا نضرة وبهجة، بحيث يكون وجهه مشرقًا مضيئًا في الدنيا والآخرة، فتكون عليه البهجة في الدنيا، ويكون ذا نضرة وبهجة في الآخرة، ونضر أي نَعَّم وأشرق وأضاء، سمع منا حديثا أي سمع حديثا من النبي صلى الله عليه وسلم، فحفظه حتى يبلغه من التبليغ، أي أوصل المقالة المسموعة إلى الناس، وعلّمهم إياها، فرب حامل فقه أي علم ومن معه علم وفقه، إلى من هو أفقه منه أي أدّاه وبلغه إلى من هو أفقه وأعلم منه وأقدر على الاستنباط، فيستنبط منه ما لا يفهمه الحامل، ففيه إشارة إلى فائدة النقل، ورب حامل فقه وعلم ليس بفقيه أي أن الإنسان قد يحفظ الشيء ولكنه ليس عنده ما يكون عند غيره من الناس ممن يتلقاه من جهة قوة الفهم وقوة الاستنباط أو الحرص على الاستنباط والقصد إلى الاستنباط.","reference":"سنن أبي داود (5/ 501) (3660)، سنن الترمذي (4/ 330) (2656)، سنن ابن ماجه (1/ 156) (230)، مسند أحمد (35/ 467) (21590)، معالم السنن (4/178)، التنوير شرح الجامع الصغير (10/504)، تحفة الأحوذي (7/348)، شرح سنن أبي داود للعباد (1/ 12)، مشارق الأنوار الوهاجة ومطالع الأسرار البهاجة في شرح سنن الإمام ابن ماجه (4/ 372).","benefits":["فضل تحمل السنة وتلقيها ونشرها.","فضل نشر العلم.","شرف الحديث وفضله ودرجة طلابه.","المحافظة على تعلم وتعليم حديث رسول الله صلى الله عليه وسلم.","أهمية الاستنباط وأهمية الفهم.","كراهة اختصار الحديث لمن ليس بالمتناهي في الفقه لما في ذلك من قطع طريق الاستنباط والاستدلال لمعاني الكلام من طريق التّفهّم.","فضل الصحابة رضوان الله عليهم، فهم من سمعوا حديث رسول الله صلى الله عليه وسلم وبلغوه لنا."],"wordsMeanings":[{"word":"نضر الله امرأً","meaning":" نضر نعَّم وأشرق وأضاء."},{"word":"فحفظه حتى يبلغه","meaning":" أوصل المقالة المسموعة إلى الناس."},{"word":"فرب حامل فقه إلى من هو أفقه منه","meaning":" فرب مبلغ العلم إلى من هو أعلم."}],"category":"mustalah","bookId":"abudawud","tags":["نضر","الله","امرأ","سمع","منا","حديثا"],"source":"hadeethenc"},{"id":"he_65220","text":"عن محمود بن الربيع قال: «عَقَلتُ من النبي صلى الله عليه وسلم مَجَّةً مَجَّها في وجهي وأنا ابن خمس سنين من دلو».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"قال محمود بن الربيع وهو من صغار الصحابة رضي الله عنهم: عقلت أي عرفت وحفظت من النبي صلى الله عليه وسلم مجة، والمج إرسال الماء من الفم بالنفخ، وقيل لا يكون مجًّا حتى تُباعِد به، وكذلك مَجَّ لعابَه، والمجاجة والمجاج الريق الذي تمجه من فيك، مجها في وجهي وأنا ابن خمس سنين، وقد توفي النبي عليه الصلاة والسلام وهو ابن خمس سنين، واستفيد من هذه الرواية أن الواقعة التي ضبطها كانت في آخر سنة من حياة النبي عليه الصلاة والسلام، وأن ابن خمس سنين يصحُّ أن يتحمَّل العلم، من دلو أي أن النبي صلى الله عليه وسلم أخذ الماء من الدلو، وهذه مداعبة نبوية، وقد لا تكون مقبولة من كل الناس، ولكن كان الصحابة رضي الله عنهم يحرصون على آثاره إرادة بركته عليه الصلاة والسلام لهم ولأولادهم.","reference":"صحيح البخاري (1/ 26) (77)، صحيح مسلم (1/ 456) (33)، عمدة القاري شرح صحيح البخاري (2/ 72).","benefits":["بركة النبي عليه الصلاة والسلام، وكان الصحابة رضي الله عنهم يحرصون على آثاره إرادة بركته عليه الصلاة والسلام لهم ولأولادهم.","فيه جواز سماع الصغير وضبطه للسنن.","جواز مداعبة الصبي."],"wordsMeanings":[{"word":"عقلت","meaning":" عرفت وحفظت."},{"word":"مجة","meaning":" المج الريق الذي تمجه من فيك."}],"category":"mustalah","tags":["عقلت","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_65346","text":"عن أبي سلمة عن عبد الله بن سلام قال: قعدنا نفرٌ من أصحاب رسول الله صلى الله عليه وسلم فتذاكرنا، فقلنا: لو نعلم أيَّ الأعمال أحبُّ إلى الله لعملناه، فأنزل الله تعالى {سبح لله ما في السموات وما في الأرض وهو العزيز الحكيم يا أيها الذين آمنوا لم تقولون ما لا تفعلون}، قال عبد الله بن سلام: فقرأها علينا رسول الله صلى الله عليه وسلم. قال أبو سلمة: فقرأها علينا ابن سلام.","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"روى أبو سلمة أن عبد الله بن سلام رضي الله عنه قال: جلسنا جماعة من أصحاب رسول الله صلى الله عليه وسلم فتذاكرنا وتدارسنا، فقلنا: لو كنا نعلم ما هي أحبُّ الأعمال إلى الله تعالى لعملناه، وهذا من حرصهم على مرضات الله، فأنزل الله تعالى {سبح لله ما في السموات وما في الأرض وهو العزيز الحكيم، يا أيها الذين آمنوا لم تقولون ما لا تفعلون}، فوعظهم الله وحذرهم أن يقولوا ما لا يفعلون، قال عبد الله بن سلام: فقرأ علينا رسول الله صلى الله عليه وسلم السورة، وقال أبو سلمة: فقرأ علينا ابن سلام السورة، وتسلسل ذلك في الرواة حتى عُرف الحديث باسم (المسلسل بقراءة سورة الصف).","reference":"سنن الترمذي (5/ 268) (3309)، النهاية في غريب الحديث والأثر (ص 931).","benefits":["التحذير الشديد من قول الإنسان ما لا يفعل.","بيان سبب نزول سورة الصف."],"wordsMeanings":[{"word":"قعدنا","meaning":" جلسنا."},{"word":"نفر","meaning":" الجماعة والرهط، يطلق على الجماعة من الرجال خاصة ما بين الثلاثة إلى العشرة."},{"word":"تذاكرنا","meaning":" تدارسنا."}],"category":"mustalah","bookId":"tirmidhi","tags":["المسلسل","بقراءة","سورة","الصف"],"source":"hadeethenc"},{"id":"he_65212","text":"عن ابنِ عباس، قال: قال رسولُ الله -صلَّى الله عليه وسلم-: \"تَسمَعُونَ، ويُسمَعُ منكم، ويُسمَعُ ممن يَسمَعُ مِنكُم\".","attribution":"رواه أبو داود","grade":"صحيح","gradeKey":"sahih","explanation":"قال رسول الله صلى الله عليه وسلم: تسمعون أي من النبي صلى الله عليه وسلم، وهذا خطاب للصحابة؛ لأنهم هم الذين سمعوا كلام رسول الله صلى الله عليه وسلم منه، فكل من سمع كلامه عليه الصلاة والسلام مباشرة في حياته فإنه من أصحابه، ومن رآه ولم يسمع منه فهو من أصحابه عليه الصلاة والسلام كذلك، ويسمع منكم أي: التابعون يسمعون من الصحابة، فالذين سمعوا الصحابة هم التابعون، والذين رأوا الصحابة هم التابعون، ويسمع ممن يسمع منكم أي: أتباع التابعين يسمعون من التابعين الذين سمعوا من الصحابة، وهكذا كل جيل يسمع ممن قبله، وممن تقدمه ممن أدركه، وهكذا فيكون شرع الله الذي جاء به رسول الله صلى الله عليه وسلم يتناقله الناس منذ زمن الصحابة، ويعملون به ويعبدون الله عز وجل وفقًا لهذا الحق والهدى.\nوهذا الحديث ليس فيه دلالة على قلة أهمية السماع بعد عهد أتباع التابعين؛ لأن الأحاديث قد دونت في الكتب، فلا يدل على تقليل أهمية السماع، وإنما كما هو معلوم حصل بعد ذلك تدوين للكتب، وصار الناس يتوارثون هذه الكتب، والسماع كان موجودًا ولا زال إلى عصرنا هذا، واقتصار النبي صلى الله عليه وسلم على أتباع التابعين فكأن المقصود منه الإشارة إلى الطبقات الثلاث التي هي خير القرون.","reference":"سنن أبي داود (5/ 500) (3659)، شرح سنن أبي داود للعباد (414/ 27)، شرح سنن أبي داود لابن رسلان (15/110).","benefits":["فضل نشر العلم.","فضل القرون الثلاثة الأولى الصحابة والتابعين وأتباع التابعين.","أن كل جيل وكل طبقة تنشر وتورث العلم للطبقة التي بعدها."],"wordsMeanings":[{"word":"تسمعون","meaning":" يسمع الصحابة من النبي صلى الله عليه وسلم."},{"word":"يُسمع منكم","meaning":" التابعون يسمعون من الصحابة."},{"word":"يسمع ممن يسمع منكم","meaning":" أتباع التابعين يسمعون من التابعين."}],"category":"mustalah","bookId":"abudawud","tags":["تسمعون","ويسمع","منكم","ويُسمَعُ","ممن","يَسمَعُ"],"source":"hadeethenc"},{"id":"he_65042","text":"عن علي قال: قال النبي صلى الله عليه وسلم: «لا تكذبوا علي، فإنه من كذب علي فليلج النار».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"نهى رسول الله صلى الله عليه وسلم أمّته عن أن تقول عنه ما لم يقُل أو يفعَل، وهو عامّ في كلّ كذبٍ، سواء كان عليه أو له، والكذب على الله داخل تحت الكذب على الرسول عليه الصَّلاة والسَّلام، ثمّ بيّن أنّه مَن يفعل هذا ويكذِب عليه فعاقبته ومآله أنّه يَلِج النّار، أي: يدخلها، والمعنى: أنّ هذا جزاؤه إن جازاه، وإلّا فقد يجازى به وقد يعفو الله عنه، ولا يقطع عليه بدخول النار، وهكذا سبيل كلّ ما جاء مِن الوعيد بالنار لأصحاب الكبائر غير الكفر، ثم إنْ جوزي وأُدخِل النّار فلا يخلد فيها؛ بل لا بدّ مِن خروجه منها بفضل الله تعالى ورحمته، وليس هذا تهوينًا مِن هذا الجُرم العظيم وقد قال صلى الله عليه وسلم: (إن كذبًا عليَّ ليس كَكَذِبٍ على أحد) رواه البخاري ومسلم.","reference":"صحيح البخاري","benefits":["النهي عن الكذب على النبي صلى الله عليه وسلم.","تعظيم حرمة الكذب على النبي صلى الله عليه وسلم.","بيان إثم مَن كذب على النبي صلى الله عليه وسلم.","لا فرق في تحريم الكذب على النبي عليه الصلاة والسلام بين ما كان في الأحكام وما لا حُكمَ فيه كالترغيب والترهيب، فكله حرام من أكبر الكبائر بإجماع المسلمين المعتد بهم.","مَن روى حديثا وعلم أو ظنَّ أنه موضوع فهو داخل في هذا الوعيد إذا لم يبين حال رواته وضعفهم.","مَن روى حديثًا يعلم ضَعفَه فلا يذكره بصيغة الجزم، نحو: قال أو فعل أو أمر، ونحو ذلك، بل يقول: روي عنه كذا، أو قيل عنه كذا، وهكذا.","أنّ ممّا يُخشى دخوله في النهي: اللَّحْن وشِبْهه، ولهذا قال العلماء رضي الله عنهم: ينبغي للرّاوي أن يعرف مِن النحو واللغة والأسماء ما يسلَم به مِن قول ما لم يقل."],"wordsMeanings":[{"word":"فليلج النار","meaning":" يدخل النار."}],"category":"mustalah","tags":["تكذبوا","علي"],"source":"hadeethenc"},{"id":"he_65078","text":"عن طلحة قال: مررتُ مع رسول الله صلى الله عليه وسلم بقوم على رؤوس النخل، فقال: «ما يصنع هؤلاء؟» فقالوا: يلقحونه، يجعلون الذكر في الأنثى فيَلْقَح. فقال رسول الله صلى الله عليه وسلم: «ما أظن يغني ذلك شيئًا» قال فأخبروا بذلك فتركوه، فأخبر رسول الله صلى الله عليه وسلم بذلك فقال: «إن كان ينفعهم ذلك فليصنعوه، فإني إنما ظننت ظنًّا، فلا تؤاخذوني بالظن، ولكن إذا حدثتكم عن الله شيئًا، فخذوا به، فإني لن أكذب على الله عز وجل».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"روى طلحة رضي الله عنه أنّه مَرَّ مع النبي صلى الله عليه وسلم بقومٍ وهم على رؤوس النَّخل، فسأل عليه الصَّلاة والسلام ما الذي يصنعونه؟ فأجابوه: بأنهم يلقحون النَّخل، أي: يجعلون الذَّكر في الأنثى فيَلْقَح ويخرج رطبًا، فقال رسول الله صلَّى الله عليه وسلَّم: ما أظنّ ذلك التَّأبير يُغْنِي شيئًا، وإنما قال النبي صلى الله عليه وسلم هذا؛ لأنَّه لم يكن عنده علمٌ باستِمرار هذه العادة، فإنّه لم يكن ممّن عانى الزِّراعة ولا الفلاحة، ولا باشر شيئًا مِن ذلك، فخَفِيَت عليه تلك العادة المتعلِّقة بأمر دنيويّ محض، فأخبروا القوم بما قاله رسول الله صلى الله عليه وسلم فتركوا التَّلقيح، فأخبر رسولُ الله صلَّى الله عليه وسلَّم بتركهم التَّلقيح، فقال: إن كان ينفعهم ذلك فليصْنَعوه، فإني إنما ظننت ظنًّا في هذا الرأي الدّنيويّ الذي لا علاقة له بالوحي والشَّرع، فلا تؤاخذوني بالظَّنّ، وهذا منه صلى الله عليه وسلم بيان لِمَن ضَعُف عقلُه؛ مخافة أن يُزِلَّه الشيطان فيكذِّب النبي صلى الله عليه وسلم فيكفر، وغاية ما جرى فوات مصلحة دنيويَّة خاصة بقوم محصورين لا يعرفها مَن لم يُباشِرها، ولا كان مِن أهلها، فقال عليه الصلاة والسلام: ولكن إذا حدثتكم عن الله شيئًا فخذوا به، فهذا أمر جزم بوجوب الأخذ عنه في كلّ أحواله مِن الغضب والرضا، والمرض والصحة، فإني لن أكذب على الله عز وجل، أي: لا يقع منه فيما يبلغه عن الله كذب ولا غلط، لا سهوًا ولا عمدًا، وأمّا الكذب العمد المحض فلم يقع قط منه في خبر مِن الأخبار، ولا جرَّب عليه شيءٌ مِن ذلك منذ أنشأه الله تعالى، وإلى أن توفّاه الله تعالى، وقد كان في صِغَره معروفًا بالصِّدق والأمانة، ومجانبة أهل الكذب والخيانة، حتى إنّه كان يسمى في الجاهلية بالصّادق الأمين، يشهد له بذلك كلّ مَن عرفه وإن كان مِن أعدائه، وأما أمور الدّنيا التي لا تعلّق لها بالدِّين فهو فيها واحد مِن البشر.","reference":"صحيح مسلم","benefits":["عصمة رسول الله صلى الله عليه وسلم عن الخطأ فيما يبلغه عن الله تعالى.","النبي صلى الله عليه وسلم قد يخطئ في أمور الدنيا الخالصة التي لا تعلق لها بالدين، فهو فيها واحد من البشر.","كرم أخلاقه صلى الله عليه وسلم واعتذاره لما لا يجب الاعتذار فيه.","خطورة تكذيب النبي صلى الله عليه وسلم، فمن كذَّبه في شيء من الدين فهو كافر."],"wordsMeanings":[{"word":"على رؤوس النخل","meaning":" فوق النخل."},{"word":"يلقحون","meaning":" يضعون طلع الذكر في طلع الأنثى أول ما ينشق."},{"word":"يغني","meaning":" ينفع."}],"category":"mustalah","bookId":"muslim","tags":["يصنع","هؤلاء؟"],"source":"hadeethenc"},{"id":"he_66512","text":"عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: «بُنِيَ الإِسْلَامُ عَلَى خَمْسٍ: شَهَادَةِ أَنْ لَا إلَهَ إلَّا اللَّهُ وَأَنَّ مُحَمَّدًا ‌عَبْدُهُ ‌وَرَسُولُهُ، وَإِقَامِ الصَّلَاةِ، وَإِيتَاءِ الزَّكَاةِ، وَحَجِّ الْبَيْتِ، وَصَوْمِ رَمَضَانَ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"شَبَّهَ النبيُّ صلى الله عليه وسلم الإسلامَ بِبِناءٍ مُحْكَمٍ بأركانه الخمسة الحاملة لذلك البُنيان، وبقية خصال الإسلام كتتمة البنيان، وأولُ هذه الأركان: الشهادتان؛ شهادة أن لا إله إلا الله وأنَّ محمدًا رسول الله، وهما ركن واحد؛ لا تنفك إحداهما عن الأخرى، ينطق العبد بهما معترفًا بوحدانية الله واستحقاقه للعبادة وحده دون ما سواه، وعاملًا بمقتضاها، ومؤمنًا برسالة محمد صلى الله عليه وسلم مُتَّبِعًا له. والركن الثاني: إقامة الصلاة، وهي الصلوات الخمس المفروضات في اليوم والليلة: الفجر، والظهر، والعصر، والمغرب، والعشاء، بشروطها وأركانها وواجباتها. والركن الثالث: إخراج الزكاة المفروضة، وهي عبادة ماليَّة واجبة في كل مال بَلَغَ قَدْرًا مُحَدّدًا في الشرع، تُعطى لمستحقيها. والركن الرابع: الحج، وهو قَصْدُ مكة لإقامة المَناسك، تَعبُّدًا لله عز وجل. والركن الخامس: صوم رمضان، وهو الإمساك عن الأكل والشرب وغيرهما من المفطرات بِنِيَّةِ التعبُّد لله، من طلوع الفجر إلى غروب الشمس.","reference":"صحيح البخاري (1/ 11) (8).\nصحيح مسلم (1/ 45) (16)، و(1/ 88) (82).\nفتح الباري لابن رجب (1/ 22).\nجامع العلوم والحكم (1/147).\nشرح الأربعين لابن العطّار (ص 62).\nشرح الأربعين النووية لعبد الكريم الخضير (ص 87).\nفتح القوي المتين في شرح الأربعين للعباد (ص 29).\nشرح الأربعين النووية لصالح آل الشيخ (ص 91 - 95).\nالتحفة الربانية لإسماعيل الأنصاري (ص 12).","benefits":["تلازم الشهادتين، فلا تصح أحدهما إلا بالأخرى؛ لذا جعلهما ركنًا واحدًا.","الشهادتان هما أساس الدين، فلا يُقبل قولٌ ولا عملٌ إلا بهما."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["بني","الإسلام","على","خمس"],"source":"hadeethenc"},{"id":"he_66513","text":"عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ قَالَ: حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ الصَّادِقُ المَصْدُوقُ: «إِنَّ أَحَدَكُمْ يُجْمَعُ خَلْقُهُ فِي بَطْنِ أُمِّهِ أَرْبَعِينَ يَوْمًا، ثُمَّ يَكُونُ عَلَقَةً مِثْلَ ذَلِكَ، ثُمَّ يَكُونُ مُضْغَةً مِثْلَ ذَلِكَ، ثُمَّ يُرْسَلُ إلَيْهِ المَلَكُ فَيَنْفُخُ فِيهِ الرُّوحَ، وَيُؤْمَرُ بِأَرْبَعِ كَلِمَاتٍ: بِكَتْبِ رِزْقِهِ، وَأَجَلِهِ، وَعَمَلِهِ، وَشَقِيٍّ أَوْ سَعِيدٍ؛ فَوَالَّذِي لَا إلَهَ غَيْرُهُ إنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ الجَنَّةِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا إلَّا ذِرَاعٌ فَيَسْبِقُ عَلَيْهِ الكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ فَيَدْخُلُهَا، وَإِنَّ أَحَدَكُمْ لَيَعْمَلُ بِعَمَلِ أَهْلِ النَّارِ حَتَّى مَا يَكُونُ بَيْنَهُ وَبَيْنَهَا إلَّا ذِرَاعٌ، فَيَسْبِقُ عَلَيْهِ الكِتَابُ فَيَعْمَلُ بِعَمَلِ أَهْلِ الجَنَّةِ فَيَدْخُلُهَا».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"قال ابن مسعود: حدثنا رسول الله صلى الله عليه وسلم وهو الصادق في قوله، والمصدوق حيث صَدَقَه الله تعالى، قال: إن أحدكم يُجمع خلقه، وذلك أن الرجل إذا أتى أهله فمَنِيُّه المتفرِّق يُجمع في بطن المرأة أربعين يومًا نطفة، ثم يكون علقة وهي الدم الغليظ الجامد، وهذا في الأربعين الثانية، ثم يكون مضغة وهي قطعة من اللحم قدر ما يُمضَغ، وهذا في الأربعين الثالثة، ثم يرسِل الله إليه الملك، فينفخ فيه الروح بعد انتهاء الأربعين الثالثة، ويُؤمر الملك أن يكتب أربع كلمات وهي: رزقه، وهو ما مقدار ما سيحصل عليه من النعم في عمره، وأجله، وهو مدة بقائه في الدنيا، وعمله، ما هو؟ وشقيٌ أو سعيد. ثم أقسم النبي صلى الله عليه وسلم أن الواحد ليعمل بعمل أهل الجنة ويكون عمله صالحًا، أي فيما يظهر للناس، ويظل كذلك حتى ما يكون بينه وبين الجنة إلا ذراع، أي: ما يبقى بينه وبين أن يصلها إلا كمن بقي بينه وبين موضع من الأرض ذراع، فيغلب عليه الكتاب وما قُدِّر عليه فعند ذلك يعمل بعمل أهل النار فيُختم له به فيدخل النار؛ لأن شرط قبول عمله أن يثبت عليه ولا يُبدِّل، وآخر من الناس يعمل أعمال أهل النار حتى يقترب من أن يدخلها، وكأن بينه وبين النار مقدار ذراع من الأرض، فيغلب عليه الكتاب وما قُدِّر عليه فيعمل بعمل أهل الجنة فيختم له بذلك فيدخل الجنة.","reference":"صحيح البخاري (9/ 135) (7454)، (4/ 111) (3208).\nصحيح مسلم (4/ 2036) (2643).\nعمدة القاري شرح صحيح البخاري (15/ 130).\nشرح الأربعين النووية للعثيمين (ص: 84).","benefits":["بيان مراحل خلق الإنسان.","الإيمان بالقضاء والقدر.","الخوف من سوء العاقبة، والحث على سؤال الله الثبات إلى الممات.","التحذير من الاغترار بصور الأعمال؛ فإنما الأعمال بالخواتيم.","هذا الحديث في حق من لا يعمل إخلاصًا وإيمانًا، بل يعمل بعمل أهل الجنة فيما يبدو للناس فقط، أما من يعمل بعمل أهل الجنة حقيقة، إخلاصًا وإيمانًا، فالله تعالى أعدل وأكرم وأرحم من أن يخذله في نهاية عمره، قال تعالى: {يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ وَيُضِلُّ اللَّهُ الظَّالِمِينَ وَيَفْعَلُ اللَّهُ مَا يَشَاءُ}."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["أحدكم","يجمع","خلقه","بطن","أمه","أربعين"],"source":"hadeethenc"},{"id":"he_66514","text":"عَنْ أُمِّ المُؤْمِنِينَ أُمِّ عَبْدِ اللَّهِ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا، قَالَتْ: قَالَ: رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّم: «مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ مِنْهُ فَهُوَ رَدٌّ».\nوَفِي رِوَايَةٍ لِمُسْلِمٍ: «مَنْ عَمِلَ عَمَلًا لَيْسَ عَلَيْهِ أَمْرُنَا فَهُوَ رَدٌّ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ مَن اخترَعَ في الدِّينِ أو عَمِلَ عملًا لم يَدُل عليه دليلٌ من الكتاب والسنة، فهو مَردودٌ على صاحبِه غير مقبول عند الله.","reference":"صحيح البخاري (3/ 184) (2697).\nصحيح مسلم (3/ 1343) (1718).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص16).\nشرح الأربعين النووية، لابن عثيمين (ص96).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص38).","benefits":["العبادات مبناها على ما جاء في الكتاب والسنة، فلا نعبد الله تعالى إلا بما شَرَعَ لا بالبدع والمُحْدَثات.","الدين ليس بالرأي والاستحسان، وإنما بالاتباع للرسول صلى الله عليه وسلم.","هذا الحديث دليلٌ على كمال الدين.","البدعة هي كل ما أُحْدِثَ في الدين ولم يَكنْ على عهدِ النبي صلى الله عليه وسلم وأصحابه من عقيدةٍ أو قولٍ أو عملٍ.","هذا الحديث أصلٌ من أصول الإسلام، وهو كالميزان للأعمال، فكما أنَّ كلَّ عَمَلٍ لا يُراد به وجه الله تعالى، فليس لعامله فيه ثواب، فكذلك كلُّ عمل لا يكون وِفْقَ ما جاء به رسول الله صلى الله عليه وسلم فهو مردود على عامله.","الحديث قاعدة في رد البدع المحدثات والمنكرات الواقعات.","المُحْدَثات المنهي عنها ما كان من أمور الدين وليس الدنيا."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["أحدث","أمرنا","هذا","ليس","منه","فهو"],"source":"hadeethenc"},{"id":"he_66517","text":"عَنْ أَبِي هُرَيْرَةَ عَبْدِ الرَّحْمَنِ بْنِ صَخْرٍ رَضِيَ اللَّهُ عَنْهُ قَالَ: سَمِعْت رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّم يَقُولُ: «مَا نَهَيْتُكُمْ عَنْهُ فَاجْتَنِبُوهُ، وَمَا أَمَرْتُكُمْ بِهِ فَافْعَلُوا مِنْهُ مَا اسْتَطَعْتُمْ، فَإِنَّمَا أَهْلَكَ الَّذِينَ مِنْ قَبْلِكُمْ كَثْرَةُ مَسَائِلِهِمْ، وَاخْتِلَافُهُمْ عَلَى أَنْبِيَائِهِمْ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"بين لنا رسول الله صلى الله عليه وسلم أنه إذا نهانا عن شيء وجب علينا اجتنابه بدون استثناء، وإذا أمرنا بشيء فعلينا أن نفعل منه ما نطيق.\n\nثم حذرنا حتى لا نكون كبعض الأمم السابقة حينما أكثروا من الأسئلة على أنبيائهم مع مخالفتهم لهم فعاقبهم الله بأنواع من الهلاك والدمار، فينبغي أن لا نكون مثلهم حتى لا نهلك كما هلكوا.","reference":"صحيح البخاري (9/ 94) (7288).\nصحيح مسلم (2/ 975) (1337).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 236).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 181).\nشرح رياض الصالحين، لابن عثيمين (2/ 268).","benefits":["الحديث قاعدة في بيان الواجب في إتيان المأمور واجتناب المحظور.","النهي لم يرخص في ارتكاب شيء منه، والأمر قيد بالاستطاعة؛ لأن الترك مقدور والفعل يحتاج إلى قدرة على إيجاد الفعل المأمور به.","النهي عن كثرة السؤال، قد قسم العلماء السؤال إلى قسمين: أحدهما: ما كان على وجه التعليم لما يحتاج إليه من أمر الدين، فهذا مأمور به ومن هذا النوع أسئلة الصحابة. والثاني: ما كان على وجه التعنت والتكلف وهذا هو المنهي عنه.","تحذير هذه الأمة من مخالفة نبيها، كما وقع في الأمم التي قبلها.","المنهي عنه يشمل القليل والكثير؛ لأنه لا يتأتّى اجتنابه إلا باجتناب قليله وكثيره، فمثلًا: نهانا عن الرِّبا فيشمل قليله وكثيره.","ترك الأسباب المفضية إلى المحرم؛ لأن ذلك من معنى الاجتناب.","لا ينبغي للإنسان إذا سمع أمر الرسول صلى الله عليه وسلم أن يقول: هل هو واجب أم مستحبّ، بل عليه بالمبادرة إلى الفعل؛ لقوله: «فَأْتُوا مِنْهُ مَا استَطَعْتُمْ».","كثرة المسائل سبب للهلاك ولا سيّما في الأمور التي لا يمكن الوصول إليها مثل المسائل الغيبية، وكيفية أحوال يوم القيامة، لا تكثر السؤال فيها فتهلك، وتكون متنطّعًا متعمّقًا."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["نهيتكم","عنه","فاجتنبوه،","وما","أمرتكم","فافعلوا"],"source":"hadeethenc"},{"id":"he_66518","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «إنَّ اللَّهَ طَيِّبٌ لَا يَقْبَلُ إلَّا طَيِّبًا، وَإِنَّ اللَّهَ أَمَرَ المُؤْمِنِينَ بِمَا أَمَرَ بِهِ المُرْسَلِينَ، فَقَالَ تَعَالَى: {يَا أَيُّهَا الرُّسُلُ كُلُوا مِنْ الطَّيِّبَاتِ وَاعْمَلُوا صَالِحًا}، وَقَالَ تَعَالَى: {يَا أَيُّهَا الَّذِينَ آمَنُوا كُلُوا مِنْ طَيِّبَاتِ مَا رَزَقْنَاكُمْ} ثُمَّ ذَكَرَ الرَّجُلَ، يُطِيلُ السَّفَرَ، أَشْعَثَ، أَغْبَرَ، يَمُدُّ يَدَيْهِ إلَى السَّمَاءِ: يَا رَبِّ! يَا رَبِّ! وَمَطْعَمُهُ حَرَامٌ، وَمَشْرَبُهُ حَرَامٌ، وَمَلْبَسُهُ حَرَامٌ، وَغُذِيَ بِالحَرَامِ، فَأَنَّى يُسْتَجَابُ لَذلك».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنَّ الله طيب قُدُّوس مُنَزَّهٌ عن النقائص والعيوب ومُتَّصِف بالكَمَالات، ولا يقبل من الأعمال والأقوال والاعتقادات إلا ما كان طيبًا، وهو الخالص لله، الموافق لهدي النبي صلى الله عليه وسلم، ولا ينبغي أن يتقرب إلى الله إلا بذلك، ومن أعظم ما يَحصُل به طِيْبة الأعمال للمؤمن طِيْبُ مَطعَمِه، وأن يكون من حلال، فبذلك يَزكُو عملُه، ولذا أمر الله المؤمنين بالذي أمر به المرسلين من أكل الحلال وعمل الصالحات، فقال: {يَا أَيُّهَا الرُّسُلُ كُلُوا مِنَ الطَّيِّبَاتِ وَاعْمَلُوا صَالِحًا، إِنِّي بِمَا تَعْمَلُونَ عَلِيمٌ} وقال: {يَا أَيُّهَا الَّذِينَ آمَنُوا كُلُوا مِنْ طَيِّبَاتِ مَا رَزَقْنَاكُمْ}.\nثم حَذَّرَ صلى الله عليه وسلم من أكل الحرام الذي يُفسِد العمل ويَمنع قبولَه مهما بَذل من أسباب القبول الظاهرة؛ منها:\nأولًا: إطالة السفر في وجوه الطاعات كحج وجهاد وصلة رحم وغير ذلك.\nثانيًا: مُتفرِّق الشعر لعدم تمشيطه، مُتغيِّر لونه ولون ثيابه من التراب، فهو مضطر.\nثالثًا: يرفع يديه إلى السماء بالدعاء.\nرابعًا: يتوسل إلى الله بأسمائه ويُلِحُّ في ذلك: يا رب يا رب!\nومع هذه الأسباب لإجابة الدعاء لم يسمع له؛ وذلك لأن مَطعومَه ومشروبَه وملبوسَه حرام، وغذي بالحرام، فبعيد أن يستجاب لمن هذه صفته، وكيف يستجاب له؟!","reference":"صحيح مسلم (2/ 703) (1015).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، لإسماعيل الأنصاري (ص27).\nشرح الأربعين النووية، لابن عثيمين (ص141).\nالأحاديث الأربعين النووية مع ما زاد عليها ابن رجب وعليها الشرح الموجز المفيد (ص22).","benefits":["كمال الله عزّ وجل في ذاته، وصفاته، وأفعاله، وأحكامه.","الأمر بإخلاص العمل لله عز وجل، والمتابعة للنبي صلى الله عليه وسلم.","استعمال ما يُشجِّع على العمل، حيث قال النبي صلى الله عليه وسلم: \"إِنَّ الله أَمَرَ المُؤمنينَ بِمَا أَمَرَ بِهِ المُرسَلِيْنَ\"، فإذا علم المؤمن أن هذا من مأمورات المرسلين فإنه يتقوَّى ويتشجّع على الامتثال.","من موانع استجابة الدعاء أكل الحرام.","من أسباب إجابة الدعاء خمسة أشياء: أحدها: إطالة السفر لما فيه من الانكسار الذي هو من أعظم أسباب الإجابة، الثاني: حالة الإضطرار، الثالث: مَدُّ اليدين إلى السماء، الرابع: الإلحاح على الله بتكرير ذكر ربوبيته، وهو من أعظم ما يُطلَب به إجابة الدعاء، الخامس: إطابة المأكل والمشرب.","أكل الحلال الطيِّب من الأسباب المُعينة للعمل الصالح.","قال القاضي: الطيب ضد الخبيث، فإذا وصف به تعالى أريد به أنه مُنزَّه عن النقائص مُقدَّس عن الآفات، وإذا وُصِف به العبد مطلقًا أريد به أنه المُتعرِّي عن رذائل الأخلاق وقبائح الأعمال والمتحلي بأضداد ذلك، وإذا وُصف به الأموال أريد به كونه حلالًا من خيار الأموال."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["الله","طيب","يقبل","إلا","طيبا،","وإن"],"source":"hadeethenc"},{"id":"he_66522","text":"عَنْ أَبِي العَبَّاسِ، عَبْدِ الله بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ: كُنْت خَلْفَ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَوْمًا، فَقَالَ: «يَا غُلَامِ! إنِّي أُعَلِّمُك كَلِمَاتٍ: احْفَظِ اللَّهَ يَحْفَظْكَ، احْفَظِ الله تَجِدْهُ تُجَاهَكَ، إذَا سَأَلْتَ فَاسْأَلِ اللهَ، وَإِذَا اسْتَعَنْتَ فَاسْتَعِنْ بِاَللهِ، وَاعْلَمْ أَنَّ الأُمَّةَ لَوْ اجْتَمَعَتْ عَلَى أَنْ يَنْفَعُوكَ بِشَيْءٍ لَمْ يَنْفَعُوكَ إلَّا بِشَيْءٍ قَدْ كَتَبَهُ اللَّهُ لَكَ، وَإِنِ اجْتَمَعُوا عَلَى أَنْ يَضُرُّوكَ بِشَيْءٍ لَمْ يَضُرُّوكَ إلَّا بِشَيْءٍ قَدْ كَتَبَهُ اللَّهُ عَلَيْكَ؛ رُفِعَتِ الأَقْلَامُ، وَجَفَّتِ الصُّحُفُ».\nوَفِي رِوَايَةِ غَيْرِ التِّرْمِذِيِّ: «احْفَظِ اللهَ تَجِدْهُ أَمَامَكَ، تَعَرَّفْ إلَى اللهِ فِي الرَّخَاءِ يَعْرِفْكَ فِي الشِّدَّةِ، وَاعْلَمْ أَنَّ مَا أَخْطَأَكَ لَمْ يَكُنْ لِيُصِيبَكَ، وَمَا أَصَابَك لَمْ يَكُنْ لِيُخْطِئَكَ، وَاعْلَمْ أَنَّ النَّصْرَ مَعَ الصَّبْرِ، وَأَنْ الفَرَجَ مَعَ الكَرْبِ، وَأَنَّ مَعَ العُسْرِ يُسْرًا».","attribution":"رواه الترمذي وغيره","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ ابنُ عباس رضي الله عنه أنه كان صغيرًا راكبًا مع النبي صلى الله عليه وسلم، فقال له عليه الصلاة والسلام: إني أُعلِّمك أمورًا وأشياءَ ينفعك الله بها:\nاحفظ الله بِحفظِ أوامرِه واجتنابِ نواهيه، بحيث يَجِدُكَ في الطاعات والقربات، ولا يجدُكَ في المعاصي والآثام، فإن فعلتَ ذلك كان جزاؤك أن يحفظَك الله من مكاره الدنيا والآخرة، وينصرَك في مُهماتِك أينما توجَّهتَ.\nوإذا أردتَ أن تسأل شيئًا، فلا تسألْ إلا الله فإنه وحده الذي يُجيب السائلين.\nوإذا أردتَ العونَ فلا تستعنْ إلا بالله.\nولْيكُن عندك يقينٌ أنه لن تحصل لك منفعة ولو اجتمع على منفعتِك أهلُ الأرض جميعًا إلا ما كتبه الله لك، ولن يحصُلَ عليك ضرر ولو اجتمع على ضرك أهلُ الأرض جميعًا إلا ما قدَّره الله عليك.\nوأن هذا الأمر قد كَتَبه الله عز وجل وقدّره وِفْقَ ما اقتضته حكمته وعلمه، ولا تبديل لما كتبه الله.\nوأن من احفظ الله بِحفظِ أوامرِه واجتنابِ نواهيه؛ فإن الله سبحانه أمام العبد يعلم ما هو عليه وينصره ويؤيده. وأن الإنسان إذا أطاع الله في الرخاء فإن الله يجعل له عند الشدة فرجًا ومخرجًا، وليرض كل عبد بما قدره الله عليه من خير وشر. ومع الشدائد والمحن يلتزم العبد الصبر، فإن الصبر مفتاح الفرج، وأن الكرب إذا اشتد جاء الفرج من الله، وأن العسر إذا حصل أعقبه الله باليسر.","reference":"سنن الترمذي (4/ 284) (2516).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص42).\nشرح الأربعين النووية، لابن عثيمين (ص200).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص69).","benefits":["أهمية تعليم الصغار والأطفال أمورَ الدين من التوحيد والآداب وغير ذلك.","الجزاء من جنس العمل.","الأمر بالاعتماد على الله، والتوكل عليه دون غيره، وهو نعم الوكيل.","الإيمان بالقضاء والقدر والرضا به، وأن الله قدر كل شيء.","من أضاع أمر الله فإن الله يُضَيِّعُه ولا يَحفظُه.","البشارة العظيمة أن الإنسان إذا أصابه العسر فلينتظر اليسر.","تسلية العبد عند حصول المصيبة، وفوات المحبوب في قوله: «وَاعْلَم أن مَا أَصَابَكَ لَمْ يَكُن لِيُخطِئكَ، وَمَا أخطأَكَ لَمْ يَكُن لِيصيبَك» فالجملة الأولى تسلية في حصول المكروه، والثانية تسلية في فوات المحبوب."],"wordsMeanings":[],"category":"aqidah","bookId":"tirmidhi","tags":["غلام","إني","أعلمك","كلمات:","احفظ","الله"],"source":"hadeethenc"},{"id":"he_66524","text":"عَنْ أَبِي عَمْرٍو- وَقِيلَ: أَبِي عَمْرَةَ-، سُفْيَانَ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَ: قُلْتُ: يَا رَسُولَ اللهِ، قُلْ لِي فِي الْإِسْلَامِ قَوْلًا لَا أَسْأَلُ عَنْهُ أَحَدًا غَيْرَكَ، قَالَ: «قُلْ: آمَنْتُ بِاللهِ، ثُمَّ اسْتَقِمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"سَأَلَ الصحابيُّ سفيانُ بنِ عبدِ الله رضي الله عنه النبيَّ صلى الله عليه وسلم أنْ يُعَلِّمَه قولًا جامِعًا لمعاني الإسلام يَتَمَسَّكُ به ولا يَسأل عنه غيرَه؟ فقال له صلى الله عليه وسلم: قل: وَحَّدْتُ اللهَ، وآمنتُ أنه ربي وإلهي وخالقي ومعبودي الحق لا شريك له، ثم ينقاد لطاعة الله بأداء فرائض الله وترك محارم الله ويستمر عليها.","reference":"صحيح مسلم (1/ 65) (38).\nمسند أحمد (24/ 141) (15416).\nالمفهم (1/137).\nجامع العلوم والحكم (1/507).\nفتح القوي المتين للعباد (ص 76).\nشرح الأربعين النووية لعبد الكريم الخضير (ص 285).\nشرح الأربعين لصالح آل الشيخ (ص 305).","benefits":["أصلُ الدين هو الإيمان بالله بروبيته وألوهيته وأسمائه وصفاته.","أهمية الاستقامة بعد الإيمان، والاستمرار في العبادة، والثبات على ذلك.","الإيمان شرط لقبول الأعمال .","الإيمان بالله، يشمل ما يجب اعتقادُه من عقائد الإيمان وأصوله، وما يتبع ذلك من أعمال القلوب، والانقياد والاستسلام لله باطنًا وظاهرًا.","الاستقامةُ مُلازَمَةُ الطريق، بفعل الواجبات وترك المنهيات."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["الإسلام","قولا","أسأل","عنه","أحدا","غيرك،"],"source":"hadeethenc"},{"id":"he_66525","text":"عَنْ أَبِي عَبْدِ اللَّهِ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ رَضِيَ اللَّهُ عَنْهُمَا: أَنَّ رَجُلًا سَأَلَ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَقَالَ: أَرَأَيْتَ إِذَا صَلَّيْتُ المَكْتُوبَاتِ، وَصُمْتُ رَمَضَانَ، وَأَحْلَلْتُ الحَلَالَ، وَحَرَّمْتُ الحَرَامَ، وَلَمْ أَزِدْ عَلَى ذَلِكَ شَيْئًا، أَأَدْخُلُ الجَنَّةَ؟ قَالَ: «نَعَمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبي صلى الله عليه وسلم أن من صلى الصلوات الخمس المفروضات ولم يزد عليها شيئًا من النوافل، وصام رمضان ولم يتطوع، واعتقد حِلَّ الحلال وفَعَله، واعتقد حُرمة الحرام واجتنبه، أنه يدخل الجنة.","reference":"صحيح مسلم (1/ 44) (15).\nجامع العلوم والحكم (1/513). \nشرح الأربعين النووية للعثيمين (ص: 215).\nفتح القوي المتين في شرح الأربعين للعباد (ص 77).","benefits":["حرص المسلم على فعل الفرائض وترك المحرمات، وأن تكون غايته دخول الجنة.","أهمية فعل الحلال واعتقاد حِلَّه، وتحريم الحرام واعتقاد حرمته.","فعل الواجبات وترك المحرمات سبب لدخول الجنة."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["أرأيت","إذا","صليت","المكتوبات،","وصمت","رمضان،"],"source":"hadeethenc"},{"id":"he_66530","text":"عَنْ مُعَاذِ بْنِ جَبَلٍ رَضِيَ اللهُ عَنْهُ قَالَ: قُلْت يَا رَسُولَ اللَّهِ! أَخْبِرْنِي بِعَمَلٍ يُدْخِلُنِي الجَنَّةَ وَيُبَاعِدْنِي مِنْ النَّارِ، قَالَ: «لَقَدْ سَأَلْتَ عَنْ عَظِيمٍ، وَإِنَّهُ لَيَسِيرٌ عَلَى مَنْ يَسَّرَهُ اللَّهُ عَلَيْهِ: تَعْبُدُ اللَّهَ لَا تُشْرِكُ بِهِ شَيْئًا، وَتُقِيمُ الصَّلَاةَ، وَتُؤْتِي الزَّكَاةَ، وَتَصُومُ رَمَضَانَ، وَتَحُجُّ البَيْتَ، ثُمَّ قَالَ: أَلَا أَدُلُّكَ عَلَى أَبْوَابِ الخَيْرِ، الصَّوْمُ جُنَّةٌ، وَالصَّدَقَةُ تُطْفِئُ الْخَطِيئَةَ كَمَا يُطْفِئُ المَاءُ النَّارَ، وَصَلَاةُ الرَّجُلِ مِنْ جَوْفِ اللَّيْلِ، ثُمَّ تَلَا: {تَتَجَافَى جُنُوبُهُمْ عَنِ الْمَضَاجِعِ} حَتَّى {بَلَغَ يَعْمَلُونَ}، ثُمَّ قَالَ: أَلَا أُخْبِرُك بِرَأْسِ الأَمْرِ وَعَمُودِهِ وَذِرْوَةِ سَنَامِهِ، فَقُلْتُ: بَلَى يَا رَسُولَ اللَّهِ، قَالَ: رَأْسُ الأَمْرِ الإِسْلَامُ، وَعَمُودُهُ الصَّلَاةُ، وَذِرْوَةُ سَنَامِهِ الجِهَادُ، ثُمَّ قَالَ: أَلَا أُخْبِرُك بِمِلَاكِ ذَلِكَ كُلِّهِ، فقُلْت: بَلَى يَا رَسُولَ اللَّه! فَأَخَذَ بِلِسَانِهِ وَقَالَ: كُفَّ عَلَيْك هَذَا، قُلْت: يَا نَبِيَّ اللَّهِ! وَإِنَّا لَمُؤَاخَذُونَ بِمَا نَتَكَلَّمُ بِهِ، فَقَالَ: ثَكِلَتْكَ أُمُّكَ وَهَلْ يَكُبُّ النَّاسَ عَلَى وُجُوهِهِمْ أَوْ قَالَ عَلَى مَنَاخِرِهِمْ إلَّا حَصَائِدُ أَلسِنَتِهِمْ»!","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"قال معاذٌ رضي الله عنه: كنتُ مع النبي صلى الله عليه وسلم في سَفَر، فأصبحت يومًا قريبًا منه ونحن نسير، فقلت: يا رسول الله أَخْبِرني بعمل يُدخلني الجنة ويباعدني عن النار، قال: لقد سألتني عن عمل عظيم فِعْلُه على النفوس، وإنه لَهَيِِّنٌ سَهْلٌ على مَن يَسَّرَه الله عليه؛ أَدِّ فرائض الإسلام:\nالأول: تعبد الله وحده ولا تشرك به شيئًا.\nالثاني: تُقيم الصلوات الخمس المفروضات في اليوم والليلة: الفجر، والظهر، والعصر، والمغرب، والعشاء، بشروطها وأركانها وواجباتها.\nالثالث: تُخرِج الزكاة المفروضة، وهي عبادة مالية واجبة في كل مال بلغَ قدرًا مُحددًا في الشرع، تعطى لمستحقيها.\nالرابع: تصوم رمضان، وهو الإمساك عن الأكل والشرب وغيرهما من المفطرات بنية التعبد، من طلوع الفجر إلى غروب الشمس.\nالخامس: تحج البيت بقَصْد مكة لإقامة المناسك، تعبُّدًا لله عز وجل.\nثم قال صلى الله عليه وسلم: أَلَا أُعَرِّفُك على الطريق المُوصِلة لأبواب الخير؟ وذلك بإتْبَاع تلك الفرائض بالنوافل:\nأولًا: صوم التطوع، وهو مانع من الوقوع في المعاصي وذلك بكسر الشهوة، وإضعاف القوة.\nثانيًا: صدقة التطوع تطفئ الخطيئة بعد اقترافها وتُذْهِبُها وتَمحو أثرَها.\nثالثًا: صلاة التهجد في ثلث الليل الآخر، ثم قرأ صلى الله عليه وسلم قوله تعالى: {تتجافى جنوبهم} أي: تتباعد {عن المضاجع} أي: المراقد {يدعون ربهم} بالصلاة والذكر والقراءة والدعاء، {خوفا وطمعا ومما رزقناهم ينفقون، فلا تعلم نفس ما أخفي لهم من قرة أعين} أي ما تَقَرُّ به أعينُهم يوم القيامة وفي الجنة من نعيم، {جزاء بما كانوا يعملون}.\nثم قال صلى الله عليه وسلم: أَلَا أُخْبِرُك بأصل الدين؟ وعموده الذي يعتمد عليه؟ وذروة سنامه؟\nقال معاذ رضي الله عنه: بلى يا رسول الله.\nقال النبي صلى الله عليه وسلم: رأس الأمر: الإسلام وهو الشهادتان، وبهما يصبح مع الإنسان أصل الدين. وعموده: الصلاة، فلا إسلام بلا صلاة، كما أنه لا يكون البيت بلا عمود، فمن صلى قوي دينه وارتفع؛ وذروة سنامه وارتفاعه بالجهاد وبذل الجَهد في قتال أعداء الدين لإعلاء كلمة الله.\nثم قال صلى الله عليه وسلم: ألا أخبرك بإحكام وإتقان ما مضى؟ فأخذ صلى الله عليه وسلم بلسانه، وقال: امنع هذا ولا تَكَلَّمَ بما لا يَعنيك. قال معاذ: هل يؤاخِذُنا ويحاسبنا ربُّنا ويعاقبنا بكل ما نتكلَّم به؟!\nقال صلى الله عليه وسلم: فَقَدَتْك أمُّك! وليس المراد به الدعاء عليه، ولكنها من كلام العرب لِتَنبيهه إلى أَمر كان ينبغي أن ينتبه له ويعرفه، ثم قال: وهل يُلقِي الناسَ ويُسقِطُهم على وجوههم في النار إلا حصائد ألسنتهم من الكفر والقذف والشتم والغيبة والنميمة والبهتان ونحوها.","reference":"سنن الترمذي (4/ 362) (2616).\nسنن ابن ماجه (5/ 116) (3973).\nمسند أحمد (36/ 344) (22016).\nالتحفة الربانية، لإسماعيل الأنصاري (ص67).\nشرح الأربعين النووية، للعثيمين (ص291).\nالأحاديث الأربعين النووية مع ما زاد عليها ابن رجب وعليها الشرح الموجز المفيد، لعبد الله بن صالح المحسن (ص57).","benefits":["حرص الصحابة رضي الله عنهم على العِلْم، ولهذا يَكثُرُ منهم سؤال النبي صلى الله عليه وسلم عنه.","فقه الصحابة رضي الله عنهم لعلمهم أنَّ الأعمال سبب لدخول الجنة.","السؤال الذي صَدَر من معاذ رضي الله عنه سؤال عظيم؛ لأنه في الحقيقة هو سِرُّ الحياة والوجود، فكل موجود في هذه الدنيا من بني آدم أو من الجنّ غايته إما الجنة وإما النار، فلذلك كان هذا السؤال عظيمًا.","ترتُّب دخوله الجنة على الإتيان بأركان الإسلام الخمسة، وهي: الشهادتان والصلاة والزكاة والصيام والحج.","رأس الدين وأغلى المُهمّات وأعلى الواجبات توحيد الله، بعبادته وحده لا شريك له.","رحمة الله بعباده أنْ فتح لهم أبواب الخير ليتزوَّدوا من أسباب الأجر ومغفرة الذنوب.","فضل التقرب بالنوافل بعد أداء الفرائض.","الصلاة من الإسلام بمنزلة العمود الذي تقوم عليه الخَيْمَة، يَذهب الإسلام بذهابها، كما تسقط الخيمة بسقوط عمودها.","وجوب حفظ اللسان عما يضر الإنسان في دينه.","كَفُّ اللسان وضبطُه وحَبسُه هو أصل الخير كله."],"wordsMeanings":[],"category":"aqidah","bookId":"tirmidhi","tags":["لقد","سألت","عظيم،","وإنه","ليسير","على"],"source":"hadeethenc"},{"id":"he_66533","text":"عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرْوِي عَنْ رَبِّهِ تَبَارَكَ وَتَعَالَى، قَالَ: «إنَّ اللهَ كَتَبَ الحَسَنَاتِ وَالسَّيِّئَاتِ، ثُمَّ بَيَّنَ ذَلِكَ، فَمَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا؛ كَتَبَهَا اللهُ عِنْدَهُ حَسَنَةً كَامِلَةً، وَإِنْ هَمَّ بِهَا فَعَمِلَهَا؛ كَتَبَهَا اللهُ عِنْدَهُ عَشْرَ حَسَنَاتٍ إلَى سَبْعِمِائَةِ ضِعْفٍ إلَى أَضْعَافٍ كَثِيرَةٍ، وَإِنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا؛ كَتَبَهَا اللهُ عِنْدَهُ حَسَنَةً كَامِلَةً، وَإِنْ هَمَّ بِهَا فَعَمِلَهَا؛ كَتَبَهَا اللهُ سَيِّئَةً وَاحِدَةً».","attribution":"رواه البخاري ومسلم في صحيحيهما بهذه الحروف","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ الرسولُ صلى الله عليه وسلم أنَّ الله قَدَّر الحسناتِ والسيئاتِ ثم بَيَّنَ للمَلَكين كيف يكتبانها: فمَن أراد وقصد وعَزَم على فعل الحسنة كُتبتْ له حسنة واحدة وإن لم يعملْها، فإن عَمِلها فإنها تُضاعف بعشر أمثالها إلى سبعمائة ضِعفٍ إلى أضعاف كثيرة، والزيادة بحسب ما في القلب من الإخلاص وتَعَدِّي النَّفْع ونحو ذلك. ومَن أراد وقصد وعزم على فعل السيئة ثم تَرَكها لله كُتبت له حسنة، وإن تركها تشاغلًا عنها مع عدم فعل أسبابها لم تُكتب شيئًا، وإن تركها عَجزًا عنها كُتبتْ عليه نِيَّتُه، وإن عملها كُتبت له سيئة واحدة.","reference":"صحيح البخاري (8/ 103) (6491).\nصحيح مسلم (1/ 118) (131).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص85).\nشرح الأربعين النووية، لابن عثيمين (ص368).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص125).\nفتح الباري، لابن حجر (11/ 324).","benefits":["هذا الحديث مما يرويه النبي صلى الله عليه وسلم عن ربه، ويسمى بالحديث القدسي أو الإلهي، وهو الذي لفظه ومعناه من الله، غير أنه ليست فيه خصائص القرآن التي امتاز بها عما سواه ، من التعبد بتلاوته والطهارة له والتحدي والإعجاز وغير ذلك.","إثبات كتابة الله تعالى الحسنات والسيئات، ثم بيانه ذلك لعباده حتى يعلموا ذلك، ويكونوا على بصيرة من أمرهم، فيمتثلوا أمره ويجتنبوا نهيه على هدى من ربّهم.","بيانُ فضل الله تعالى العظيم على هذه الأمة في كتابة الحسنات ومضاعفتها، وعدم كتابة السيئات إلا بعد فعلها وكتابتها سيئة واحدة.","الزيادة في مضاعفة الحسنات بحسب ما في القلب من الإخلاص وتَعَدِّي النَّفْع ونحو ذلك، فيضاعفها الله برحمته وفضله.","بيان الفضل الذي يترتب للعبد على ترك السيئة وهِجران لذته، وترك شهوته من أجل ربه عز وجل رغبةً في ثوابه، ورهبةً من عقابه.","من لطف الله تعالى بالأمة أن ضاعف لها حسناتها ولم يضاعف سيئاتها.","كتابة الملائكة لجميع الأعمال من أعمال القلوب والجوارح."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["الله","كتب","الحسنات","والسيئات،","بين","ذلك"],"source":"hadeethenc"},{"id":"he_66534","text":"عَنْ أَبِي هُرَيْرَة رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُول اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «إنَّ اللَّهَ تَعَالَى قَالَ: مَنْ عَادَى لِي وَلِيًّا فَقْد آذَنْتُهُ بِالحَرْبِ، وَمَا تَقَرَّبَ إلَيَّ عَبْدِي بِشَيْءٍ أَحَبَّ إلَيَّ مِمَّا افْتَرَضْتُ عَلَيْهِ، وما يَزَالُ عَبْدِي يَتَقَرَّبُ إلَيَّ بِالنَّوَافِلِ حَتَّى أُحِبَّهُ، فَإِذَا أَحْبَبْتُهُ كُنْتُ سَمْعَهُ الَّذِي يَسْمَعُ بِهِ، وَبَصَرَهُ الَّذِي يُبْصِرُ بِهِ، وَيَدَهُ الَّتِي يَبْطِشُ بِهَا، وَرِجْلَهُ الَّتِي يَمْشِي بِهَا، وَإِنْ سَأَلَنِي لَأُعْطِيَنَّهُ، وَلَئِنْ اسْتَعَاذَنِي لَأُعِيذَنَّهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم في الحديثِ القُدْسِيِّ أنَّ الله عز وجل قال: مَن آذى وَليًّا من أوليائي وأغضبَه وأبغضَه فقد أَعْلمتُه وأعلنتُ له العداوة.\nوالوليُّ هو: المؤمنُ التَّقي، وعلى قدر ما للعبد من الإيمان والتقوى يكون نصيبُه من ولاية الله. وما تقرَّب المسلم إلى ربِّه بشيء أحب إليه مما افترضه وأوجبه عليه من فعل الطاعات وترك المحرمات، وما يزال المسلم يتقرّب إلى ربه بالنوافل مع الفرائض؛ حتى ينال محبة الله. فإذا أحبه الله كان الله مُسددًا له في هذه الأعضاء الأربعة:\nيُسدِّدُه في سمعه، فلا يسمع إلا ما يرضي الله.\nويُسدده في بصره، فلا ينظر إلا إلى ما يحب الله النظر إليه ويرضاه.\nويُسدده في يده، فلا يعمل بيده إلا ما يرضي الله.\nويُسدده في رجله، فلا يمشي إلا إلى ما يرضي الله، ولا يسعى إلا إلى ما فيه الخير.\nومع هذا إنْ سأل اللهَ شيئًا فإنَّ الله يعطيه ما سأل، فيكون مجابَ الدعوة، ولئن استعاذ بالله ولجأ إليه طلبًا للحماية، فإن الله سبحانه يُعيذه ويحميه مما يخاف.","reference":"صحيح البخاري (8/ 105) (6502).\nالإفصاح عن معاني الصحاح، ليحيى بن هبيرة (7/ 302).\nجامع العلوم والحكم في شرح خمسين حديثا من جوامع الكلم، لابن رجب (2/ 330).\nعمدة القاري شرح صحيح البخاري، لمحمود بدر الدين العينى (23/ 88).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي بن سلطان القاري (4/ 1544).\nتاج العروس من جواهر القاموس، للزبيدي (17/ 81).\nشرح رياض الصالحين، لابن عثيمين (2/ 59).\nمجموع فتاوى ومقالات متنوعة، ل","benefits":["هذا الحديث ممّا يَرويه النبيُّ صلى الله عليه وسلم عن ربه، ويُسمّى بالحديث القُدْسِي أو الإلهي، وهو الذي لَفْظُه ومعناه مِن الله، غير أنه ليست فيه خصائصُ القرآن التي امتاز بها عما سواه، من التعبُّدِ بتلاوتِه والطهارة له والتَّحَدِّي والإعجاز، وغير ذلك.","النهي عن إيذاء أولياء الله والترغيب في حُبِّهم، والاعتراف بفضلهم.","الأمر بمعاداة أعداء الله وتحريم موالاتهم.","مَن ادَّعَى ولايةَ اللهِ بدون اتّباع شرعِه فهو كاذبٌ في دعواه.","تُنالُ ولايةُ الله بفعل الواجبات وترك المحرمات.","مِن أسباب محبة الله للعبد وإجابة دعوته فِعْلُ النوافل بعد القيام بالواجبات وترك المحرمات.","الدلالة على شرف الأولياء ورفعة منزلتهم."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["الله","تعالى","قال:","عادى","وليا","فقد"],"source":"hadeethenc"},{"id":"he_66535","text":"عَنْ أَبِي مُحَمَّدٍ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ العَاصِ رَضِيَ اللَّهُ عَنْهُمَا، قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى يَكُونَ هَوَاهُ تَبَعًا لِمَا جِئْتُ بِهِ».","attribution":"رويناه في كتاب الحجة بإسناد صحيح","grade":"قال النووي: حديث صحيح","gradeKey":"sahih","explanation":"بين النبي صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أن الإنسان لا يكونا مؤمنًا كامل الإيمان الواجب حتى تكون محبته تابعة لما جاء به الرسول صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ من الأوامر والنواهي وغيرها، فيحب ما أمر به، ويكْرَهُ ما نَهَى عنه.","reference":"الحجة على تارك المحجة لأبي الفتح نصر بن إبراهيم المقدسي، برقم (25).\nفتح الباري لابن حجر (13/289).\nجامع العلوم والحكم (3/1146).\nشرح النووي على مسلم (1/77).","benefits":["الحديث قاعدة في التسليم للشرع والانقياد له.","تحذير الإنسان من أن من يحكم العقل أو العادة ويقدمه على ما جاء به الرسول صلى الله عليه وسلم، ففاعل ذلك قد نُفي الإيمان عنه.","وجوب تحكيم الشريعة في كل شيء، لقوله: «لِمَا جِئتُ به».","أن الإيمان يزيد بالطاعة وينقص بالمعصية."],"wordsMeanings":[],"category":"aqidah","tags":["يؤمن","أحدكم","حتى","يكون","هواه","تبعا"],"source":"hadeethenc"},{"id":"he_66537","text":"عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رضي الله عنهما قال: قال رَسولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «أَرْبَعٌ مَنْ كُنَّ فِيهِ كَانَ مُنَافِقًا، وَإِنْ كَانَتْ خَصْلَةٌ مِنْهُنَّ فِيهِ كَانَتْ فِيهِ خَصْلَةٌ مِنَ النِّفَاقِ حَتَّى يَدَعَهَا: مَنْ إِذَا حَدَّثَ كَذَبَ، وإِذَا وَعَدَ أَخْلَفَ، وإذَا خَاصَمَ فَجَرَ، وَإِذَا عَاهَدَ غَدَرَ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"حَذَّرَ النبيُّ صلى الله عليه وسلم مِن أربعِ خِصال إذا اجتمعت في مسلم كان شديدَ الشَّبَهِ بالمنافقين بسبب هذه الخصال، وهذا فيمن كانت هذه الخصال غالبةً عليه، وأما من يَنْدُرُ فليس داخلًا فيه، وهي:\n\nالأولى: إذا حَدَّث تعمَّد الكذب وعدم الصدق في كلامه.\n\nالثانية: إذا عاهد عهدًا لم يُوْفِ به، وغَدَرَ بصاحبِه.\n\nالثالثة: إذا وَعَدَ وَعْدًا لم يَفِ به وأَخلَفَه.\n\nالرابعة: إذا تَخَاصَم وتَشَاجَرَ مع أحد كان خصامُه شديدًا، ومالَ عن الحق، واحتال في رده وإبطاله، وقال الباطلَ والكذبَ.\n\nفإنّ النفاق هو إظهار ما يُبطِنُ خلافَه، وهذا المعنى موجود في صاحب هذه الخصال، ويكون نفاقُه في حق مَن حَدَّثه، ووعدَه، وائتمنَه، وخاصمَه، وعاهدَه من الناس، لا أنه منافق في الإسلام فيظهره وهو يبطن الكفر، ومن كانت فيه خصلة من هذه الخصال؛ كان فيه صفة من النفاق حتى يَتْركَها.","reference":"صحيح البخاري (1/ 16) (34).\nصحيح مسلم (1/ 78) (58).\nالمفهم لما أشكل من تلخيص كتاب مسلم (1/ 250).\nبهجة قلوب الأبرار (ص 26).\nالبحر المحيط الثجاج (2/370).","benefits":["بيان بعض علامات المنافق للتخويف والتحذير من الوقوع فيها.","المقصود من الحديث: أن هذه الخصالَ خصالُ نفاق، وصاحبُها شبيهٌ بالمنافقين في هذه الخصال، ومتخلِّق بأخلاقهم، لا أنه منافق يظهر الإسلام وهو يبطن الكفر، وقيل هذا محمول على من غَلَبت عليه هذه الخصال وتهاونَ بها، واستخفَّ بأمرها؛ فإن من كان كذلك كان فاسد الاعتقاد غالبًا.","قال الغزالي: أصل الديانة منحصر في ثلاث: القول، والفعل، والنية، فنبَّه على فساد القول بالكذب، وعلى فساد الفعل بالخيانة، وعلى فساد النية بالخُلْف؛ لأن خُلْفَ الوعد لا يقدح إلا إذا كان العزم عليه مقارنًا للوعد، أما لو كان عازمًا ثم عرض له مانع أو بدا له رأيٌ فهذا لم توجد منه صورة النفاق.","النفاق نوعان: نفاق اعتقاديٌّ يُخرِجُ صاحبَه عن الإيمان، وهو إظهار الإسلام وإخفاء الكفر، ونفاق عَمَلِيٌّ، وهو التشبُّه بالمنافقين في أخلاقهم، وهذا لا يُخرِجُ صاحبَه عن الإيمان، إلا أنه كبيرة من الكبائر.","قال ابن حجر: وقد أجمع العلماء على أن من كان مُصدِّقًا بقلبه ولسانه وفعل هذه الخصال لا يُحكَم عليه بكفر، ولا هو مُنافق يخلد في النار.","قال النووي: وقال جماعة من العلماء: المراد به المنافقون الذين كانوا في زمن النبي صلى الله عليه وسلم فحدَّثوا بإيمانهم، وكذَّبوا، واؤتمنوا على دينهم فخانوا، ووعدوا في أمر الدين ونصره فأخلفوا، وفَجَروا في خصوماتهم."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["أربع","فيه","كان","منافقا،","وإن","كانت"],"source":"hadeethenc"},{"id":"he_3272","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنْ رَسُولِ اللهِ صلى الله عليه وسلم أنه قال: «وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَا يَسْمَعُ بِي أَحَدٌ مِنْ هَذِهِ الْأُمَّةِ يَهُودِيٌّ وَلَا نَصْرَانِيٌّ، ثُمَّ يَمُوتُ وَلَمْ يُؤْمِنْ بِالَّذِي أُرْسِلْتُ بِهِ إِلَّا كَانَ مِنْ أَصْحَابِ النَّارِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يَحْلِفُ النبيُّ صلى الله عليه وسلم بالله أنه لا يَسمعُ به أَحَدٌ مِن هذه الأمة، يَهوديٌّ أو نصرانيٌّ أو غيرُهما تَبْلُغُه دعوةُ النبي صلى الله عليه وسلم ثم يموت ولم يؤمن به إلا كان من أصحاب النار خالدًا فيها أبدًا.","reference":"صحيح مسلم (1/ 134) (153).\nشرح النووي على مسلم (2/ 186).\nالإفصاح عن معاني الصحاح، لابن هبيرة (8/ 192).\nطرح التثريب في شرح التقريب، لعبد الرحيم العراقي (7/ 159).","benefits":["عموم رسالةِ النبيِّ صلى الله عليه وسلم إلى جميع العالم، ووجوب اتِّباعِه، ونسخ جميع الشرائع بشرعه.","مَن كَفَرَ بالنبي صلى الله عليه وسلم لم ينفعه زَعْمُه إيمانَه بغيرِه من الأنبياء صلوات الله عليهم أجمعين.","من لم يَسمع بالنبي صلى الله عليه وسلم، ولم تَبْلغْه دعوةُ الإسلام فهو معذور، وأَمْرُه في الآخرة إلى الله تعالى.","يتحقق الانتفاع بالإسلام وإن كان قُبيل الموت، ولو في المرض الشديد، ما لم تبلغ الروح الحلقوم.","تصحيح دين الكفار -ومنهم اليهود والنصارى- كُفْرٌ.","ذكر اليهودي والنصراني -في الحديث- تنبيهًا على من سواهما؛ وذلك لأن اليهود والنصارى لهم كتاب، فإذا كان هذا شأنهم، فغيرهم ممن لا كتاب له أولى، فكلُّهم يجب عليهم الدخول في دينه وطاعته صلى الله عليه وسلم."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["والذي","نفس","محمد","بيده","يسمع","أحد"],"source":"hadeethenc"},{"id":"he_3330","text":"عن عائشة أم المؤمنين وعبد الله بن عباس رضي الله عنهما قالا: لَمَّا نَزَلَ بِرَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ طَفِقَ يَطْرَحُ خَمِيصَةً لَهُ عَلَى وَجْهِهِ، فَإِذَا اغْتَمَّ بِهَا كَشَفَهَا عَنْ وَجْهِهِ، فَقَالَ وَهُوَ كَذَلِكَ: «لَعْنَةُ اللَّهِ عَلَى اليَهُودِ وَالنَّصَارَى، اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ» يُحَذِّرُ مَا صَنَعُوا.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"تُخبِرُنا عائشةُ أم المؤمنين وابنُ عباس رضي الله عنهما أنه حينما حَضرتْ النبيَّ صلى الله عليه وسلم الوفاةُ جعل يضع قطعةَ قماشٍ على وجهه، فإذا صعُب عليه التَّنفُّس بسبب سكرات الموت أزالها عن وجهه، فقال في تلك الحال الشديدة: لَعَنَ اللهُ اليهود والنصارى، وطَرَدَهم من رحمته؛ وذلك لأنهم اتخذوا قبور أنبيائهم مساجد؛ وذلك بالبناء عليها أو الصلاة عندها أو إليها. ولولا خطورة الأمر لَمَا ذكره في مثل هذا المقام، لذا نهى النبيُّ صلى الله عليه وسلم أمتَه عن مشابهة ذلك الفعل؛ لأنه من فعل اليهود والنصارى، ولأنه ذريعة موصلة للشرك بالله عز وجل.","reference":"صحيح البخاري (1/ 95) (435)،  (2/ 102) (1390).\nصحيح مسلم (1/ 377) (531)، (1/ 376) (529).\nالملخص في شرح كتاب التوحيد، للشيخ صالح الفوزان (ص170).\nالجديد في شرح كتاب التوحيد، لمحمد بن عبد العزيز السليمان القرعاوي (ص185).","benefits":["أن هذا من وصاياه الأخيرة مما يدل على أهميتها والعناية بها.","النهي الأكيد، والتحريم الشديد من اتخاذ القبور مساجد، وقصد الصلاة عندها غير صلاة الجنازة؛ فذلك ذريعة إلى تعظيم الميت والطواف بقبره والتمسح بأركانه والنداء باسمه، وكل ذلك من الشرك ووسائله.","شدة اهتمام رسول الله صلى الله عليه وسلم واعتنائه بالتوحيد وخوفِه مِن تعظيم القبور؛ لأن ذلك يفضي إلى الشرك.","أن الله -تعالى- صان نبيه -عليه الصلاة والسلام- عن أن يُعْمَلَ الشرك عند قبره، فألهم أصحابه ومن بعدهم، أن يصونوا قبره من أن يبرز.","النهي عن التشبه باليهود والنصارى، وأن البناء على القبور من سننهم.","من اتخاذ القبور مساجد الصلاة عندها وإليها، ولو لم يُبْنَ مسجدٌ."],"wordsMeanings":[],"category":"aqidah","tags":["لعنة","الله","على","اليهود","والنصارى،","اتخذوا"],"source":"hadeethenc"},{"id":"he_3336","text":"عن أبي هريرة رضي الله عنه عن النبي صلى الله عليه وسلم: «اللهُمَّ لَا تَجْعَلْ قَبْرِي وَثَنًا، لَعَنَ اللهُ قَوْمًا اتَّخَذُوا قُبُورَ أَنْبِيَائِهِمْ مَسَاجِدَ».","attribution":"رواه أحمد","grade":"صحيح","gradeKey":"sahih","explanation":"دعا النبيُّ صلى الله عليه وسلم ربَّه أن لا يجعَلْ قَبْره مثلَ الصَّنمِ الذي يَعبُدُه النَّاسُ بتَعظيمِه واستِقبالِه في السُّجودِ، ثم أخبر صلى الله عليه وسلم بأنَّ اللهَ أَبْعَدَ وطَرَدَ من رحمتِه مَن اتخذَ  قبورَ الأنبياءِ مساجد؛ لأنَّ اتخاذَها مساجدَ ذريعةٌ إلى عِبادَتِها والاعتِقادِ فيها.","reference":"مسند أحمد (12/ 314) (7358).\nفتح المجيد شرح كتاب التوحيد، لعبد الرحمن التميمي (1/ 434).\nالقول المفيد على كتاب التوحيد، لمحمد بن عثيمين (1/ 434).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص178).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص194).\nالتمهيد لشرح كتاب التوحيد، لصالح آل الشيخ (ص51).\nمشكاة المصابيح، للتبريزي (1/ 234).","benefits":["مجاوزة الحد الشرعي في قبور الأنبياء والصالحين يجعلُها تُعبد من دون الله، فيَجِبُ الحَذرُ من وسائل الشرك.","لا يجوز قَصْدُ القبور لتعظيمِها والعبادةِ عندها مهما كان قُرْبُ صاحبِها من الله تعالى.","تحريم بناء المساجد على القبور.","تحريم الصلاة عند القبور ولو لم يُبْنَ مسجدٌ إلا صلاة الجنازة التي لم يُصلّ عليها."],"wordsMeanings":[{"word":"وثنًا","meaning":" والوثن كل ما عُبد من دون الله كالقبور والأشجار والحيطان والأحجار ونحوِها."}],"category":"aqidah","bookId":"ahmed","tags":["اللهم","تجعل","قبري","وثنا"],"source":"hadeethenc"},{"id":"he_3339","text":"عن أنس بن مالك رضي الله عنه عن النبي صلى الله عليه وسلم أنه قال: \"إن عِظَمَ الجزاءِ مع عِظَمِ البلاءِ، وإن الله تعالى إذا أحب قوما ابتلاهم، فمن رَضِيَ فله الرِضا، ومن سَخِطَ فله السُّخْطُ\".","attribution":"رواه الترمذي وابن ماجه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبرنا النبي صلى الله عليه وسلم في هذا الحديث أن المؤمن قد يحل به شيء من المصائب في نفسه أو ماله أو غير ذلك، وأن الله سيثيبه على تلك المصائب إذا هو صبر، وأنه كلما عظمت المصيبة وعظم خطرها عظم ثوابها من الله، ثم يبين صلى الله عليه وسلم بأن المصائب من علامات حب الله للمؤمن، وأن قضاء الله وقدره نافذان لا محالة، ولكن من صبر ورضي، فإن الله سيثيبه على ذلك برضاه عنه وكفى به ثوابا، وأن من سخط وكره قضاء الله وقدره، فإن الله يسخط عليه وكفى به عقوبة.","reference":"كتاب التوحيد للإمام محمد بن عبد الوهاب، ت: د. دغش العجمي، مكتبة أهل الأثر, الطبعة الخامسة, 1435ه.\nالجديد في شرح كتاب التوحيد، لمحمد بن عبد العزيز السليمان القرعاوي, ت: محمد بن أحمد سيد, مكتبة السوادي، الطبعة: الخامسة، 1424ه.\nالملخص في شرح كتاب التوحيد، دار العاصمة، الرياض، الطبعة: الأولى 1422هـ - 2001م.\nجامع الترمذي، ت: أحمد شاكر, شركة مكتبة ومطبعة مصطفى البابي, الطبعة: الثانية، 1395هـ.\nصحيح الجام","benefits":["أن المصائب مكفرات للذنوب ما لم يترتب عليها ترك واجب كترك الصبر أو فعل محرم كشق الجيوب أو لطم الخدود.","إثبات صفة المحبة لله على وجه يليق بجلاله.","أن البلاء للمؤمن من علامات الإيمان.","إثبات صفة الرضا والسخط لله على وجه يليق بجلاله.","استحباب الرضا بقضاء الله وقدره.","تحريم السخط من قضاء الله وقدره.","الحث على الصبر على المصائب.","الإنسان قد يكره الشيء وهو خيرٌ له.","إثبات الحكمة لله سبحانه في أفعاله.","الجزاء من جنس العمل."],"wordsMeanings":[{"word":"إن عظم الجزاء مع عظم البلاء","meaning":" أي كلما عظم بلاؤه عظم ثوابه."},{"word":"ابتلاهم","meaning":" أي اختبر إيمانهم بالمصائب."},{"word":"فمن رضي","meaning":" أي رضي بقضاء الله وقدره."},{"word":"فله الرضا","meaning":" أي له الرضا من الله -تعالى-."},{"word":"سخط","meaning":" السخط من الشيء الكراهية له وعدم الرضا به."},{"word":"فله السخط","meaning":" أي فله السخط من الله -تعالى-."}],"category":"aqidah","bookId":"tirmidhi","tags":["عظم","الجزاء","عظم","البلاء،","وإن","الله"],"source":"hadeethenc"},{"id":"he_3342","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «قَالَ اللهُ تَبَارَكَ وَتَعَالَى: أَنَا أَغْنَى الشُّرَكَاءِ عَنِ الشِّرْكِ، مَنْ عَمِلَ عَمَلًا أَشْرَكَ فِيهِ مَعِي غَيْرِي تَرَكْتُهُ وَشِرْكَهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أنَّ الله تبارك وتعالى قال بأنه أغنى الشركاء عن الشرك، فهو الغني عن كل شيء، وأنَّ الإنسانَ إذا عَمِل عملًا من الطاعات وجَعَلَه لله ولغير الله؛ تَركَه اللهُ ولم يقبلْه منه، وردَّه على صاحبِه؛ \nفيجبُ إخلاصُ العمل لله تعالى؛ لأنه سبحانه لا يَقبل إلا ما كان خالصًا لوجهِه الكريم.","reference":"صحيح مسلم (4/ 2289) (2985).\nشرح النووي على مسلم (18/ 115).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص287).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص325).","benefits":["التحذير من الشرك بجميع أشكاله، وأنه مانعٌ من قبول العمل.","استشعار غنى الله وعظمته مما يعين على الإخلاص في العمل."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["أنا","أغنى","الشركاء","الشرك،","عمل","عملا"],"source":"hadeethenc"},{"id":"he_3347","text":"عن جندب رضي الله عنه قال: سَمِعْتُ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ يَمُوتَ بِخَمْسٍ وَهُوَ يَقُولُ «إِنِّي أَبْرَأُ إِلَى اللهِ أَنْ يَكُونَ لِي مِنْكُمْ خَلِيلٌ فَإِنَّ اللهَ تَعَالَى قَدِ اتَّخَذَنِي خَلِيلًا كَمَا اتَّخَذَ إِبْرَاهِيمَ خَلِيلًا، وَلَوْ كُنْتُ مُتَّخِذًا مِنْ أُمَّتِي خَلِيلًا لَاتَّخَذْتُ أَبَا بَكْرٍ خَلِيلًا! أَلَا وَإِنَّ مَنْ كَانَ قَبْلَكُمْ كَانُوا يَتَّخِذُونَ قُبُورَ أَنْبِيَائِهِمْ وَصَالِحِيهِمْ مَسَاجِدَ، أَلَا فَلَا تَتَّخِذُوا الْقُبُورَ مَسَاجِدَ! إِنِّي أَنْهَاكُمْ عَنْ ذَلِكَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم عن مكانتِه عند الله تعالى، وأنها بَلَغتْ أعلى درجات المحبة، كما نالها إبراهيم عليه السلام، ولذلك نفى أن يكون له خليلٌ غيرُ الله؛ لأنَّ قلبه امتلأ من محبة الله تعالى وتعظيمه ومعرفته، فلا يَتَّسع لأحد غير الله، ولو كان له خليلٌ من الخلق لكان أبا بكر الصديق رضي الله عنه.\n\nثم حَذَّر من مجاوزة الحد الجائز في المحبة كما فعلت اليهود والنصارى في قبور أنبيائهم وصالحيهم حتى صيّروها آلهة شركية تُعبَد من دون الله، وشَيَّدوا على قبورهم مساجد ومعابد، ونهى صلى الله عليه وسلم أمته أن يفعلوا مثل فعلهم.","reference":"صحيح مسلم (1/ 377) (532).\nشرح النووي على مسلم (5/ 13).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص188).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص172).","benefits":["فضل أبي بكر الصديق رضي الله عنه، وأنه أفضل الصحابة وأولى الناس بخلافة رسول الله صلى الله عليه وسلم بعد موته.","بناء المساجد على القبور من منكرات الأمم السابقة.","النهي عن اتخاذ القبور أمكنة للعبادة يُصلى عندها أو إليها ويُبنى عليها مساجد أو قبابٌ، حذرًا من الوقوع في الشرك بسبب ذلك.","التحذير من الغلو في الصالحين لإفضائه إلى الشرك.","خطورة ما حذَّر منه النبي صلى الله عليه وسلم حيث أكَّد عليه قبل موته بخمس ليال."],"wordsMeanings":[{"word":"بخمس","meaning":" خمس ليال."},{"word":"إني أبرأ","meaning":" أمتنع وأنكر."},{"word":"من كان قبلكم","meaning":" يعني: اليهود والنصارى."}],"category":"aqidah","bookId":"muslim","tags":["إني","أبرأ","إلى","الله","يكون","منكم"],"source":"hadeethenc"},{"id":"he_3354","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قال: قال رَسُولُ الله صلى الله عليه وسلم: «إِنَّ اللهَ يَغَارُ، وَإِنَّ الْمُؤْمِنَ يَغَارُ، وَغَيْرَةُ اللهِ أَنْ يَأْتِيَ الْمُؤْمِنُ مَا حَرَّمَ عَلَيْهِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ الله يغار ويُبْغِضُ ويَكره، كما أن المؤمن يغار ويبغض ويكره، وأنَّ سببَ غيرةِ الله أنْ يأتيَ المؤمن ما حَرَّمَ الله عليه من الفواحش كالزنا واللواط والسرقة وشرب الخمر وغيرها من الفواحش.","reference":"صحيح البخاري (7/ 35) (5223).\nصحيح مسلم (4/ 2114) (2761).\nتطريز رياض الصالحين، لفيصل المبارك (ص62).\nشرح رياض الصالحين، لابن عثيمين (1/ 496).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 96).\nصفات الله عز وجل الواردة في الكتاب والسنة،  لعلوي السَّقَّاف (ص267).","benefits":["الحذر من غضب الله وعقوبته إذا انتُهِكت مَحارِمُه."],"wordsMeanings":[],"category":"aqidah","tags":["الله","يغار،","وإن","المؤمن","يغار،","وغيرة"],"source":"hadeethenc"},{"id":"he_3359","text":"عن ابْنِ عُمَرَ رضي الله عنهما أنه سَمِعَ رَجُلًا يَقُولُ: لَا وَالْكَعْبَةِ، فَقَالَ ابْنُ عُمَرَ: لَا يُحْلَفُ بِغَيْرِ اللَّهِ، فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: «مَنْ حَلَفَ بِغَيْرِ اللهِ فَقَدْ كَفَرَ أَوْ أَشْرَكَ».","attribution":"رواه أبو داود والترمذي وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبر النبيُّ صلى الله عليه وسلم أنَّ مَن حَلَف بغير الله وأسمائه وصفاته فقد كَفرَ بالله أو أشرك؛ لأن الحَلِفَ يقتضي تَعظيمَ المحلوفِ به، والعظمةُ إنَّما هي للهِ وحْدَه؛ فلا يُحلَفُ إلَّا باللهِ وأسمائِه وصِفاتِه سُبحانَه، وهذا الحلف من الشرك الأصغر؛ لكن لو أنَّ الحالِفَ عظَّم ما حَلَف به كتَعظيمِ اللهِ تعالى أو أشدَّ؛ فحينئذٍ يكونُ مِن الشِّركِ الأكبرِ.","reference":"سنن الترمذي (3/ 194) (1535).\nسنن أبي داود (5/ 154- 155) (3251).\nمسند أحمد (9/ 249) (5346)، (9/ 275) (5375)، (10/ 249) (6072).\nفتح المجيد شرح كتاب التوحيد، لعبد الرحمن التميمي (ص413).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (2/ 214).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص326).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص365).\nالتمهيد لشرح كتاب التوحيد، لصالح آل الشيخ (ص452).\nفتاوى اللجنة ","benefits":["التعظيم بالحلف حقّ لله سبحانه وتعالى فلا يُحلَف إلا بالله وأسمائه وصفاته.","حرص الصحابة على الأمر بالمعروف والنهي عن المنكر، وخصوصًا إذا كان المنكر مما يتعلق بالشرك أو الكفر."],"wordsMeanings":[{"word":"من حلف","meaning":" الحلف: اليمين، وهي توكيد الحكم بذكر معظّم تطمئن له نفس المخاطب."},{"word":"كفر أو أشرك","meaning":" يحتمل أن يكون هذا شكًّا من الراوي، ويحتمل أن تكون \"أو\" بمعنى الواو فيكون كفر وأشرك."}],"category":"aqidah","bookId":"abudawud","tags":["حلف","بغير","الله","فقد","كفر","أشرك"],"source":"hadeethenc"},{"id":"he_3366","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «‌إِنَّ ‌أَثْقَلَ صَلَاةٍ عَلَى الْمُنَافِقِينَ صَلَاةُ الْعِشَاءِ وَصَلَاةُ الْفَجْرِ، وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا، وَلَقَدْ هَمَمْتُ أَنْ آمُرَ بِالصَّلَاةِ فَتُقَامَ، ثُمَّ آمُرَ رَجُلًا فَيُصَلِّيَ بِالنَّاسِ، ثُمَّ أَنْطَلِقَ مَعِي بِرِجَالٍ مَعَهُمْ حُزَمٌ مِنْ حَطَبٍ إِلَى قَوْمٍ لَا يَشْهَدُونَ الصَّلَاةَ، فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ بِالنَّارِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم عن المنافقين وتَكَاسُلِهم عن حضور الصلاة، خاصة صلاتي العشاء والفجر، وأنهم لو يعلمون قَدْرَ الأجر والثواب في حضورهما مع جماعة المسلمين لأتوهما ولو حَبْوًا كَحَبْوِ الطفل بالأيدي والركب.\n\n \nولقد عَزَمَ النبيُّ صلى الله عليه وسلم بأن يأمر بالصلاة فتقام، ويَجعل رجلًا يؤم الناسَ مكانه، ثم ينطلق ومعه من يحمل حُزَمًا من حطبٍ إلى رجال لا يشهدون صلاة الجماعة فيُحرِّق عليهم بيوتهم بالنار؛ لشدة ما ارتكبوه من الإثم في ذلك، -ولكنه لم يفعل- لما في البيوت من النساء والصبيان الأبرياء وغيرهم من المعذورين، الذين لا ذنب لهم.","reference":"صحيح مسلم (1/ 451) (651).\nصحيح البخاري (1/ 132) (657).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (1/ 88).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص107).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 136).","benefits":["خطورة التَّخَلُّف عن صلاة الجماعة في المسجد.","المنافقون لم يقصدوا بعبادتهم إلا الرياء والسمعة، فلا يأتون إلى الصلاة إلا حين يشاهدهم الناس.","عِظَم الثواب في صلاتي العشاء والفجر مع الجماعة، وأنهما جديرتان بالإتيان إليهما ولو حبوًا.","الحفاظ على صلاة العِشاء والفجر سلامة من النفاق، والتخلف عنهما من صفات المنافقين."],"wordsMeanings":[{"word":"المنافقين","meaning":" الذين يظهرون الإسلام ويبطنون الكفر."},{"word":"ولو يعلمون","meaning":" علم إيمان ويقين."},{"word":"فتُقَام","meaning":" ينادى لها بالإقامة."},{"word":"حُزَمٌ","meaning":" جمع حزمة، وهو ما جُمع وشُدَّ بحبل ونحوه."}],"category":"aqidah","tags":["أثقل","صلاة","على","المنافقين","صلاة","العشاء"],"source":"hadeethenc"},{"id":"he_3375","text":"عَنْ عَبْدِ اللَّهِ بن مسعودٍ رضي الله عنه قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: «إِنَّ مِنْ شِرَارِ النَّاسِ مَنْ تُدْرِكُهُ السَّاعَةُ وَهُمْ أَحْيَاءٌ، وَمَنْ يَتَّخِذُ الْقُبُورَ مَسَاجِدَ».","attribution":"رواه أحمد","grade":"حسن","gradeKey":"hasan","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم عن شِرَار الناس، وأنهم مَن تقومُ الساعةُ عليهم وهم أحياءٌ، والذين يتَّخذون القبور مساجد، يُصَلُّون عندها وإليها.","reference":"مسند أحمد (6/ 394) (3844).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص191).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص176).\nأحكام الجنائز، للألباني (1/ 217).","benefits":["تحريم بناء المساجد على القبور؛ لأنه وسيلةٌ إلى الشرك.","تحريم الصلاة عند القبور ولو بدون بناء؛ لأن المسجد اسم لما يسجد فيه ولو لم يكن فيه بناء.","مَن اتخذ قبورَ الصالحين مساجدَ للصلاة فيها فهو من شرار الخلق، وإنْ زعم أنَّ قصدَه التقرُّبُ إلى الله تعالى."],"wordsMeanings":[],"category":"aqidah","bookId":"ahmed","tags":["شرار","الناس","تدركه","الساعة","وهم","أحياء،"],"source":"hadeethenc"},{"id":"he_3381","text":"عَنْ مَحْمُودِ بْنِ لَبِيدٍ رضي الله عنه أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّ أَخْوَفَ مَا أَخَافُ عَلَيْكُمُ الشِّرْكُ الْأَصْغَرُ» قَالُوا: وَمَا الشِّرْكُ الْأَصْغَرُ يَا رَسُولَ اللهِ؟ قَالَ: «الرِّيَاءُ، يَقُولُ اللهُ عز وجل لَهُمْ يَوْمَ الْقِيَامَةِ إِذَا جُزِيَ النَّاسُ بِأَعْمَالِهِمْ: اذْهَبُوا إِلَى الَّذِينَ كُنْتُمْ تُرَاؤُونَ فِي الدُّنْيَا، فَانْظُرُوا هَلْ تَجِدُونَ عِنْدَهُمْ جَزَاءً؟».","attribution":"رواه أحمد","grade":"حسن","gradeKey":"hasan","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ أكثرَ شيءٍ يَخافُه على أُمّتِه: الشرك الأصغر وهو: الرياء؛ بأنْ يعمل من أجل الناس. \nثم أخبر عن عقوبةِ المرائين يوم القيامة بأنْ يقال لهم: اذهبوا إلى مَن كنتم تعملون لأجلهم، فانظروا هل يملكون إثابتَكم ومَنْحَ الأجرِ لكم على ذلك العمل؟!","reference":"مسند أحمد (39/ 39) (23630).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص57).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص45).","benefits":["وجوب إخلاص العمل لله عز وجل، والحَذَر من الرياء.","شدة شفقتِه صلى الله عليه وسلم على أمته وحرصه على هدايتِهم ونصحه لهم.","إذا كان هذا خوفُه صلى الله عليه وسلم وهو يُخاطب الصحابةَ وهم ساداتُ الصالحين فالخوفُ على مَن بعدهم أشدّ."],"wordsMeanings":[],"category":"aqidah","bookId":"ahmed","tags":["أخوف","أخاف","عليكم","الشرك","الأصغر","قالوا:"],"source":"hadeethenc"},{"id":"he_3384","text":"عن عدي بن حاتم رضي الله عنه : \"أنه سمع النبي صلى الله عليه وسلم يقرأ هذه الآية: \"اتَّخَذُوا أَحْبَارَهُمْ وَرُهْبَانَهُمْ أَرْبَابًا مِنْ دُونِ اللَّهِ وَالْمَسِيحَ ابْنَ مَرْيَمَ وَمَا أُمِرُوا إِلاَّ لِيَعْبُدُوا إِلَهًا وَاحِدًا لا إِلَهَ إِلاَّ هُوَ سُبْحَانَهُ عَمَّا يُشْرِكُونَ\" فقلت له: إنا لسنا نعبدهم، قال: أليس يُحَرِّمُونَ ما أحل الله فتُحَرِّمُونَهُ؟ ويُحِلُّونَ ما حَرَّمَ الله فتُحِلُّونَهُ؟ فقلت: بلى، قال: فتلك عبادتهم\".","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"حينما سمع هذا الصحابي الجليل تلاوة الرسول -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ- لهذه الآية التي فيها الإخبار عن اليهود والنصارى: بأنهم جعلوا علماءهم وعبّادهم آلهة لهم يشرعون لهم ما يخالف تشريع الله فيطيعونهم في ذلك، استشكل معناها، لأنه كان يظن أن العبادة مقصورة على السجود ونحوه، فبين له الرسول -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ- أن من عبادة الأحبار والرهبان: طاعتهم في تحريم الحلال وتحليل الحرام، خلاف حكم الله تعالى ورسوله -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ-.","reference":"كتاب التوحيد، للإمام محمد بن عبد الوهاب، ت: د. دغش العجمي. مكتبة أهل الأثر, الطبعة الخامسة, 1435ه.\nالجديد في شرح كتاب التوحيد، لمحمد بن عبد العزيز السليمان القرعاوي, ت: محمد بن أحمد سيد, مكتبة السوادي، الطبعة: الخامسة، 1424ه.\nالملخص في شرح كتاب التوحيد، للشيخ صالح الفوزان, دار العاصمة, الطبعة الأولى، 1422ه.\nسلسلة الأحاديث الصحيحة، للألباني, مكتبة المعارف, الطبعة الأولى, 1415ه.\nجامع الترمذي, ت: أحم","benefits":["أن طاعة العلماء وغيرهم من المخلوقين في تغيير أحكام الله -إذا كان المطيع يعرف مخالفتهم لشرع الله- شركٌ أكبر.","أن التحليل والتحريم حقٌّ لله -تعالى-.","بيان لنوع من أنواع الشرك وهو شرك الطاعة.","مشروعية تعليم الجاهل.","أن معنى العبادة واسعٌ يشمل كل ما يحبه الله ويرضاه من الأقوال والأعمال الظاهرة والباطنة.","بيان ضلال الأحبار والرهبان.","إثبات شرك اليهود والنصارى.","أن أصل دين الرسل واحد وهو التوحيد.","أن طاعة المخلوق في معصية الخالق عبادة له.","وجوب الاستفسار من أهل العلم عما خفي حكمه.","حرص الصحابة على العلم."],"wordsMeanings":[{"word":"اتخذوا","meaning":" جعلوا."},{"word":"أحبارهم","meaning":" علماء اليهود."},{"word":"ورهبانهم","meaning":" عباد النصارى."},{"word":"أربابًا من دون الله","meaning":" حيث اتبعوهم في تحليل ما حرّم الله وتحريم ما أحلّ."},{"word":"لسنا نعبدهم","meaning":" ظن أن العبادة يراد بها التقرب إليهم بالسجود ونحوه فقط."},{"word":"أليس يحرمون... إلخ","meaning":" بيانٌ لمعنى اتخاذهم أربابًا."},{"word":"سبحانه عما يشركون","meaning":" أي تنزيها له عن الإشراك به في طاعته وعبادته."}],"category":"aqidah","bookId":"tirmidhi","tags":["أليس","يحرمون","أحل","الله","فتحرمونه؟","ويحلون"],"source":"hadeethenc"},{"id":"he_3390","text":"عَنِ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ: قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ لِمُعَاذِ بْنِ جَبَلٍ، حِينَ بَعَثَهُ إِلَى الْيَمَنِ: «إِنَّكَ سَتَأْتِي قَوْمًا أَهْلَ كِتَابٍ، فَإِذَا جِئْتَهُمْ فَادْعُهُمْ إِلَى أَنْ يَشْهَدُوا أَنْ لَا إِلَهَ إِلَّا اللهُ، وَأَنَّ مُحَمَّدًا رَسُولُ اللهِ، فَإِنْ هُمْ أَطَاعُوا لَكَ بِذَلِكَ، فَأَخْبِرْهُمْ أَنَّ اللهَ قَدْ فَرَضَ عَلَيْهِمْ خَمْسَ صَلَوَاتٍ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ، فَإِنْ هُمْ أَطَاعُوا لَكَ بِذَلِكَ، فَأَخْبِرْهُمْ أَنَّ اللهَ قَدْ فَرَضَ عَلَيْهِمْ صَدَقَةً تُؤْخَذُ مِنْ أَغْنِيَائِهِمْ فَتُرَدُّ عَلَى فُقَرَائِهِمْ، فَإِنْ هُمْ أَطَاعُوا لَكَ بِذَلِكَ، فَإِيَّاكَ وَكَرَائِمَ أَمْوَالِهِمْ، وَاتَّقِ دَعْوَةَ الْمَظْلُومِ، فَإِنَّهُ لَيْسَ بَيْنَهُ وَبَيْنَ اللهِ حِجَابٌ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"لما أَرسلَ النبيُّ صلى الله عليه وسلم معاذَ بن جبل رضي الله عنه إلى بلاد اليمن داعيًا إلى الله ومُعلِّمًا، بَيَّنَ له أنه سيواجه قومًا من النصارى؛ ليكون على استعداد لهم، ثم ليبدأ في دعوتهم بالأهم فالأهم، فيدعوهم إلى إصلاح العقيدة أولًا؛ بأن يشهدوا أن لا إله إلا الله، وأن محمدا رسول الله؛ لأنهم بها يدخلون الإسلام، فإذا انقادوا لذلك أمرهم بإقام الصلاة؛ لأنها أعظم الواجبات بعد التوحيد، فإذا أقاموها أمر أغنياءهم بدفع زكاة أموالهم إلى فقرائهم.\n\nثم حذّره من أخذ أفضل المال؛ لأن الواجب الوسط.\n\nثم أوصاه باجتناب الظلم؛ لئلا يدعو عليه المظلوم، فإن دعوته مستجابة.","reference":"صحيح البخاري (2/ 119) (1458)، (2/ 128) (1496)، (9/ 114) (7372).\nصحيح مسلم (1/ 50) (19).\nفتح الباري لابن حجر (13/ 349).\nالملخص في شرح كتاب التوحيد، لصالح فوزان (ص54).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص64).","benefits":["معنى شهادة أن لا إله إلا الله هو إفراد الله بالعبادة، وترك عبادة ما سواه.","معنى شهادة أن محمدًا رسول الله هو الإيمان به وبما جاء به وتصديقه وأنه آخر رسل الله إلى البشرية.","مخاطبة العالِم ومَن لديه شُبهات ليست كمخاطبة الجاهل؛ لذا نَبَّه معاذًا بقوله: \"إنك تأتي قومًا أهل كتاب\".","أهمية أن يكون المسلم على بصيرة من دينه؛ ليَتَخلَّص من شُبهات المشبِّهين، وذلك بطلب العلم.","بطلان دين اليهود والنصارى بعد بعثة الرسول صلى الله عليه وسلم، وأنهم ليسوا من أهل النجاة يوم القيامة حتى يدخلوا في دين الإسلام، ويؤمنوا بالنبي صلى الله عليه وسلم."],"wordsMeanings":[],"category":"aqidah","tags":["إنك","ستأتي","قوما","أهل","كتاب،","فإذا"],"source":"hadeethenc"},{"id":"he_3402","text":"عن جابر رضي الله عنه أن رسول الله صلى الله عليه وسلم سئل عن النُّشْرَةِ؟ فقال: هي من عمل الشيطان.","attribution":"رواه أبو داود وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"أن النبي -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ- سئل عن علاج المسحور على الطريقة التي كانت تعملها الجاهلية، مثل: حل السحر بالسحر ما حكم ذلك، فأجاب -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ- بأنه من عمل الشيطان أو بواسطته؛ لأنه يكون بأنواع سحرية واستخداماتٍ شيطانيةٍ، فهي شركية ومحرمة.\nأما النشرة الجائزة: فهي فك السحر بالرقية أو بالبحث عنه، وفكه باليد مع قراءة القرآن أو بالأدوية المباحة.","reference":"1- الملخص في شرح كتاب التوحيد، صالح بن فوزان بن عبد الله الفوزان، دار العاصمة، الرياض، الطبعة: الأولى، 1422هـ - 2001م.\n2- الجديد في شرح كتاب التوحيد، محمد بن عبد العزيز السليمان القرعاوي، تحقيق: محمد بن أحمد سيد، مكتبة السوادي، الطبعة: الخامسة، 1424هـ - 2003م.\n3- سنن أبي داود، سليمان بن الأشعث أبوداود، تحقيق: محمد محيي الدين عبد الحميد، المكتبة العصرية، صيدا، بيروت.\n4- مسند الإمام أحمد بن حنبل، أح","benefits":["مشروعية سؤال العلماء عما أشكل حكمه؛ حذرًا من الوقوع في المحذور.","النهي عن النشرة على الصفة التي تعملها الجاهلية؛ لأنها سحر والسحر كفر.","أن أعمال الشيطان كلها محرمة."],"wordsMeanings":[{"word":"سئل عن النشرة","meaning":" أي: النشرة التي كان أهل الجاهلية يعملونها."},{"word":"هي من عمل الشيطان","meaning":" لأنهم ينشرون عن المسحور بأنواع من السحر، واستخداماتٍ شيطانية، وهي كذلك من الأعمال التي يحبها الشيطان."},{"word":"النُّشْرة","meaning":" نوع من العلاج والرقية يعالَج به من كان يظن أن به مسًّا من السحر؛ سميت بذلك لأنها ينشر بها عنه ما خامره من الداء، أي: يُكشف ويزال."}],"category":"aqidah","bookId":"abudawud","tags":["رسول","الله","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3406","text":"عَن عُمَرَ بنِ الخَطَّابِ رَضِيَ اللَّهُ عَنْهُ قال: سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: «لَا تُطْرُونِي كَمَا أَطْرَتِ النَّصَارَى ابْنَ مَرْيَمَ؛ فَإِنَّمَا أَنَا عَبْدُهُ، فَقُولُوا: عَبْدُ اللهِ وَرَسُولُهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"ينهى النبي صلى الله عليه وسلم عن الإفراط ومجاوزة الحد الشرعي في مدحه ووصفه بأوصاف الله تعالى وأفعاله الخاصة به، أو أنه يعلم الغيب، أو يدعا مع الله، كما فعلت النصارى مع عيسى ابن مريم عليه السلام. \nثم بين أنه عبد من عباد لله، وأمر بأن نقول عنه: عبد الله ورسوله.","reference":"صحيح البخاري (4/ 167) (3445).\nعمدة القاري شرح صحيح البخاري، محمود بن أحمد بدر الدين العيني (16/ 37).\nفتح الباري، لابن حجر (6/ 490).\nمنار القاري شرح مختصر صحيح البخاري، حمزة محمد قاسم (4/ 208).","benefits":["التحذير من مُجاوزةِ الحد الشرعي في التعظيم والمدح؛ لأن ذلك يُفضي إلى الشرك.","ما حذَّر منه النبي صلى الله عليه وسلم قد وقع في هذه الأمة، فغَلَتْ طائفة بالرسول الله صلى الله عليه وسلم، وطائفة في أهل البيت، وطائفة في الأولياء، فوقعوا في الشرك.","وَصَفَ رسولُ الله صلى الله عليه وسلم نفسَه بأنه عبدُ الله؛ ليبيِّن أنه عبدٌ مَربوبٌ لله لا يجوز أن يُصرفَ له شيءٌ من خصائص الرب.","وَصَفَ رسولُ الله صلى الله عليه وسلم نفسه بأنه رسولُ الله؛  ليبين أنه رسولٌ مُرسلٌ من عند الله فيجبُ تصديقُه ومتابعتُه."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["تطروني","كما","أطرت","النصارى","ابن","مريم؛"],"source":"hadeethenc"},{"id":"he_3414","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّهُ قَالَ: قِيلَ: يَا رَسُولَ اللهِ، مَنْ أَسْعَدُ النَّاسِ بِشَفَاعَتِكَ يَوْمَ الْقِيَامَةِ؟ قَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «لَقَدْ ظَنَنْتُ يَا أَبَا هُرَيْرَةَ أَنْ لَا يَسْأَلَنِي عَنْ هَذَا الْحَدِيثِ أَحَدٌ أَوَّلُ مِنْكَ؛ لِمَا رَأَيْتُ مِنْ حِرْصِكَ عَلَى الْحَدِيثِ، أَسْعَدُ النَّاسِ بِشَفَاعَتِي يَوْمَ الْقِيَامَةِ، مَنْ قَالَ لَا إِلَهَ إِلَّا اللهُ خَالِصًا مِنْ قَلْبِهِ أَوْ نَفْسِهِ»».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم أنَّ أسعد الناس بشفاعتِه يوم القيامة هو من قال: \"لا إله إلا الله\" خالصًا من قبله، أي لا معبود بحق إلا الله، وأن يكون سالمًا من الشرك ومن الرياء.","reference":"صحيح البخاري (1/ 31) (99).\nمنار القاري شرح مختصر صحيح البخاري، لحمزة محمد قاسم (1/ 197).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (1/ 343).","benefits":["إثبات الشفاعة للنبي صلى الله عليه وسلم في الآخرة وأنها لا تكون إلا للموحِّدين.","شفاعته صلى الله عليه وسلم هي تَوَسُّلُه إلى الله تعالى لِمَن استحقَّ النارَ مِن الموحّدين أنْ لا يَدخلَها، ومَن دخلَها أن يَخرج منها.","فضل كلمة التوحيد الخالصة لله تعالى وعظيم أثرها.","تحقيق كلمة التوحيد يكون بالعلم بمعناها، والعمل بمقتضاها.","فضل أبي هريرة رضي الله عنه، وحِرصُه على العِلم."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["أسعد","الناس","بشفاعتي","يوم","القيامة،","قال"],"source":"hadeethenc"},{"id":"he_3416","text":"عن عبد الله بن عمرو بن العاص - رضي الله عنه- مرفوعاً: \"مَن ردته الطِّيَرَة عن حاجته فقد أشرك، قالوا: فما كفارة ذلك؟ قال: أن تقول: اللهم لا خير إلا خيرك، ولا طَيْرَ إِلَّا طَيْرُكَ ولا إله غيرك\".","attribution":"رواه أحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يخبرنا رسول الله صلى الله عليه وسلم في هذا الحديث أن من منعه التشاؤم عن المضي فيما يعتزم فإنه قد أتى نوعًا من الشرك، ولما سأله الصحابة عن كفارة هذا الإثم الكبير أرشدهم إلى هذه العبارات الكريمة في الحديث التي تتضمن تفويض الأمر إلى الله تعالى ونفي القدرة عمن سواه.","reference":"1- فتح المجيد شرح كتاب التوحيد، مطبعة السنة المحمدية، القاهرة، مصر، الطبعة: السابعة، 1377هـ - 1957م.\n2- القول المفيد على كتاب التوحيد، دار ابن الجوزي، المملكة العربية السعودية، الطبعة: الثانية, محرم، 1424ه.\n3- الملخص في شرح كتاب التوحيد، دار العاصمة الرياض، الطبعة: الأولى 1422هـ - 2001م.\n4- الجديد في شرح كتاب التوحيد، مكتبة السوادي، جدة، المملكة العربية السعودية، الطبعة: الخامسة، 1424هـ - 2003م.\n5","benefits":["إثبات شرك من ردته الطيرة عن حاجته.","قبول توبة المشرك.","الإرشاد إلى ما يقوله من وقع في التطير.","أن الخير والشر مقدر من الله -تعالى-."],"wordsMeanings":[{"word":"كفارة ذلك","meaning":" يغفر إثم ما يقع من الطيرة."},{"word":"لا إله غيرك","meaning":" لا معبود بحقٍّ سواك."},{"word":"ردته","meaning":" منعته."},{"word":"الطيرة","meaning":" هي التشاؤم بما يسمع أو يرى."},{"word":"عن حاجته","meaning":" أي غرضه الذي عزم عليه."},{"word":"فقد أشرك","meaning":" أي أتى شركا حيث اعتقد أن لما تطير به تأثيرا في الخير والشر."},{"word":"لا خير إلا خيرك","meaning":" أي لا يرجى الخير إلا منك دون من سواك."},{"word":"ولا طير إلا طيرك","meaning":" أي أن الطير ملكك ومخلوقك لا يأتي بخير ولا يدفع شرا."}],"category":"aqidah","bookId":"ahmed","tags":["مَن","ردته","الطيرة","حاجته","فقد","أشرك،"],"source":"hadeethenc"},{"id":"he_3417","text":"عَنْ عُبَادَةَ رَضِيَ اللَّهُ عَنْهُ عَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ: «مَنْ شَهِدَ أَنْ لَا إِلَهَ إِلَّا اللهُ وَحْدَهُ لَا شَرِيكَ لَهُ، وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ، وَأَنَّ عِيسَى عَبْدُ اللهِ وَرَسُولُهُ وَكَلِمَتُهُ أَلْقَاهَا إِلَى مَرْيَمَ وَرُوحٌ مِنْهُ، وَالْجَنَّةُ حَقٌّ، وَالنَّارُ حَقٌّ، أَدْخَلَهُ اللهُ الْجَنَّةَ عَلَى مَا كَانَ مِنَ الْعَمَلِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُنا رسولُ الله صلى الله عليه وسلم أنَّ مَن نَطَقَ بكلمةِ التوحيد عارفًا لمعناها عاملًا بمقتضاها، \nوشهد بعبودية محمد صلى الله عليه وسلم ورسالته، واعترف بعبودية عيسى ورسالته، \nوأنَّ الله خلقه بقوله \"كن\" فكان، وأنه روح من الأرواح التي خلقها الله، \nوَبَرَّأَ أُمَّهُ مِمّا نَسَبَه إليها اليهود، \nوآمن بأن الجنة حق، وأن النار حق، معتقدًا وجودهما، وأنهما نعيم الله وعذابه، \nومات على ذلك؛ فمصيره إلى الجنة وإن كان مقصِّرًا في الطاعات، وله ذنوب.","reference":"صحيح البخاري (4/ 165) (3435).\nصحيح مسلم (1/ 57) (28).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص25).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص36).","benefits":["الله تعالى خَلَقَ عيسى ابن مريم بكلمة (كُنْ) من غير أب.","الجمع بين كون عيسى ومحمد صلى الله عليهما وسلم عبدي الله ورسوليه، فهما رسولان لا يكذبان، وعبدان لا يُعْبَدان.","فضل التوحيد وتكفيره للذنوب، وأنَّ مصيرَ الموحِّد الجنةُ وإنْ وقع منه بعض الذنوب."],"wordsMeanings":[{"word":"لا إله إلا الله","meaning":" لا معبود بحق إلا الله."},{"word":"ألقاها إلى مريم","meaning":" أرسل بها جبريل إليها فنفخ فيها من روحه بإذن الله عز وجل."}],"category":"aqidah","tags":["أدخله","الله","الجنة","على","كان","العمل"],"source":"hadeethenc"},{"id":"he_3418","text":"عن جابر بن عبد الله رضي الله عنهما قال: سمعت رسول الله صلى الله عليه وسلم يقول: «مَنْ لَقِيَ اللهَ لَا يُشْرِكُ بِهِ شَيْئًا دَخَلَ الْجَنَّةَ، وَمَنْ لَقِيَهُ يُشْرِكُ بِهِ دَخَلَ النَّارَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم أنَّ مَن مات لا يشرك بالله شيئًا فمصيرُه إلى الجنة وإنْ عُذِّبَ على بعضِ ذنوبِه، وأنَّ مَن مات وهو يشرك بالله شيئًا خُلِّد في النار.","reference":"صحيح مسلم (1/ 94) (93).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص49).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص60).","benefits":["فضل التوحيد، وأنه سبب للنجاة من الخلود في النار.","قُرْب الجنة والنار من العبد، وأنه ليس بينه وبينهما إلا الموت.","التحذير من الشرك قليله وكثيرة؛ لأن النجاة من النار بتَجَنُّبِه.","العِبرة في الأعمال بخواتِيمِها."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["لقي","الله","يشرك","شيئا","دخل","الجنة،"],"source":"hadeethenc"},{"id":"he_3419","text":"عَنْ عَبْدِ اللهِ بنِ مَسْعُودٍ رضي الله عنه قال: قَالَ النَّبِيُّ صلى الله عليه وسلم كَلِمَةً وَقُلْتُ أُخْرَى، قَالَ النَّبِيُّ صلى الله عليه وسلم: «مَنْ مَاتَ وَهُوَ يَدْعُو مِنْ دُونِ اللهِ نِدًّا دَخَلَ النَّارَ» وَقُلْتُ أَنَا: مَنْ مَاتَ وَهُوَ لَا يَدْعُو لِلهِ نِدًّا دَخَلَ الْجَنَّةَ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُنا النبيُّ صلى الله عليه وسلم أنَّ مَن صَرَفَ شيئًا مما يجب أن يكون لله إلى غيره، كدعاء غير الله تعالى، أو الاستغاثة بغيره، ومات على ذلك فإنه من أهل النار. \nوزاد ابن مسعود رضي الله عنه أن من مات وهو لا يشرك بالله شيًا فإنَّ مَصيرَه إلى الجنة.","reference":"صحيح البخاري (6/ 23) (4497).\nصحيح مسلم (1/ 94) (92).\nفتح المجيد شرح كتاب التوحيد، لعبد الرحمن التميمي (ص76).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (1/ 120).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص47).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص59).\nالتمهيد لشرح كتاب التوحيد، لصالح آل الشيخ (ص42).","benefits":["الدعاء عبادةٌ لا يُصرف إلا لله تعالى.","فضل التوحيد، وأنَّ مَن مات عليه دخل الجنة، وإنْ عُذِّبَ على بعض ذنوبه.","خطر الشرك، وأنَّ مَن مات عليه دخل النار."],"wordsMeanings":[{"word":"يدعو","meaning":" يشمل نوعي الدعاء وهما: دعاء العبادة ودعاء المسألة."},{"word":"ندًّا","meaning":" الند: هو الشبيه والنظير في الألوهية أو الربوبية أو الأسماء والصفات."}],"category":"aqidah","tags":["مات","وهو","يدعو","دون","الله","ندا"],"source":"hadeethenc"},{"id":"he_3420","text":"عن عبد الله بن مسعود قال: قال رسول الله صلى الله عليه وسلم: «هَلَكَ الْمُتَنَطِّعُون» قالها ثلاثًا.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم عن خَيْبَةِ وخَسارة المُتَشَدِّدين -على غير هدى وعلم- في دينِهم ودنياهم، وفي أقوالهم وأفعالهم، المتجاوزين بها الحدَّ الشرعيَّ الذي جاء به النبي صلى الله عليه وسلم.","reference":"صحيح مسلم (4/ 2055) (2670).\nالجديد في شرح كتاب التوحيد، للقرعاوي (ص180).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص167).","benefits":["تحريم التشدُّد والتكلُّف في الأمور كلِّها، والحث على اجتنابه في كل شيء؛ لا سيَّما في العبادات وتعظيم الصالحين.","طلب الأكمل في العبادة وغيرها أمر محمود؛ ويكون بمتابعة الشرع.","استحباب تأكيد الأمر الهام؛ لأن النبي صلى الله عليه وسلم كرَّر هذه الجملة ثلاثًا.","سماحة الإسلام ويُسْره."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["هلك","المتنطعون"],"source":"hadeethenc"},{"id":"he_3421","text":"عن ابن عباس رضي الله عنهما في قول الله تعالى : (وَقَالُوا لا تَذَرُنَّ آلِهَتَكُمْ وَلا تَذَرُنَّ وَدًّا وَلا سُوَاعًا وَلا يَغُوثَ وَيَعُوقَ وَنَسْرًا) قال: \"هذه أسماء رجال صالحين من قوم نوح، فلما هَلَكوا أَوحى الشَّيطان إلى قَومِهِم أنِ انْصِبُوا إلى مَجَالِسِهِم الَّتي كانوا يَجْلِسون فيها أنصَابًا، وسَمُّوها بأسمَائِهِم، فَفَعَلُوا، ولم تُعْبَد، حتَّى إِذَا هَلَك أُولئك ونُسِيَ العلم عُبِدت\".","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يفسر ابن عباس رضي الله عنهما هذه الآية الكريمة بأن هذه الآلهة التي ذكر الله تعالى أن قوم نوح تواصوا بالاستمرار على عبادتها بعدما نهاهم نبيهم نوح -عليه السلام- عن الشرك بالله- أنها في الأصل أسماء رجال صالحين منهم، غلوا فيهم بتسويل الشيطان لهم حتى نصبوا صورهم، فآل الأمر بهذه الصور إلى أن صارت أصناماً تعبد من دون الله.","reference":"-الملخص في شرح كتاب التوحيد، دار العاصمة، الرياض، الطبعة: الأولى، 1422هـ - 2001م.\n-الجديد في شرح كتاب التوحيد، مكتبة السوادي، جدة، المملكة العربية السعودية، الطبعة: الخامسة، 1424هـ - 2003م.\n-صحيح البخاري، المحقق: محمد زهير بن ناصر الناصر، الناشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422هـ.","benefits":["أن الغلو في الصالحين سببٌ لعبادتهم من دون الله وترك الدين بالكلية.","التحذير من التصوير وتعليق الصور، لا سيما صور العظماء.","التحذير من مكر الشيطان وعرضه الباطل في صورة الحق.","التحذير من البدع والمحدثات ولو حسُن قصد فاعلها.","أن التصوير من الوسائل إلى الشرك فيجب الحذر من تصوير ذوات الأرواح.","معرفة قدر وجود العلم ومضرة فقده.","أن سبب فقد العلم هو موت العلماء.","التحذير من التقليد، وأنه قد يؤول بأهله إلى المروق من الإسلام.","قدم الشرك في الأمم السابقة.","أن هذه الأسماء الخمسة المذكورات من معبودات قوم نوح.","بيان تكاتف وتعاون أهل الباطل على باطلهم.","جواز الدعاء على الكفار على سبيل العموم."],"wordsMeanings":[{"word":"لا تذرن آلهتكم","meaning":" لا تتركوا عبادتها."},{"word":"ولا تذرن وداً ولا سواعا ولا يغوث","meaning":" أي: ولا تتركوا هؤلاء خصوصاً."},{"word":"فلما هلكوا","meaning":" أي: مات أولئك الصالحون وحزن عليهم قومهم حزناً شديداً."},{"word":"أوحى الشيطان إلى قومهم","meaning":" أي: وسوس وألقى إليهم."},{"word":"أنصاباً","meaning":" أي: أصناماً مصورة على صورهم."},{"word":"حتى إذا هلك أولئك","meaning":" أي: الذين نصبوها ليتذكروا برؤيتها أفعال أصحابها فينشطوا على العبادة."},{"word":"ونُسي العلم","meaning":" أي: زالت المعرفة وغلب الجهال الذين لا يميزون بين الشرك والتوحيد."},{"word":"عُبدت","meaning":" أي: تلك الأصنام لما قال لهم الشيطان: إن آباءكم كانوا يعبدونها."},{"word":"وقد أضلوا كثيرا","meaning":" وقد أضل رؤساؤهم بهذه الأصنام كثيرًا من الناس."},{"word":"ولا تزد الظالمين إلا ضلالًا","meaning":" أي إلا عذابًا أو ضياعًا."}],"category":"aqidah","bookId":"bukhari","tags":["قول","الله","تعالى","(وَقَالُوا","تَذَرُنَّ","آلِهَتَكُمْ"],"source":"hadeethenc"},{"id":"he_4186","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ أَنْظَرَ مُعْسِرًا، أَوْ وَضَعَ لَهُ، أَظَلَّهُ اللهُ يَوْمَ الْقِيَامَةِ تَحْتَ ظِلِّ عَرْشِهِ يَوْمَ لَا ظِلَّ إِلَّا ظِلُّهُ».","attribution":"رواه الترمذي وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"أَخبَرَ النبيُّ عليه الصلاة والسلام أنّ مَن أمهل مديونًا أو حطَّ عنه من دَينه، فجزاؤه: أنّ الله يُظلُّه تحت عرشه يوم القيامة الذي تدنو فيه الشمس من رؤوس العباد ويشتدُّ عليهم حرُّها، \nفلا يجد أحدٌ ظِلًّا إلا مَن أَظله الله.","reference":"سنن الترمذي (2/ 575) (1306).\nمسند أحمد (14/ 329) (8711).\nكنوز رياض الصالحين، لمجموعة من الباحثين (16/ 412).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 459).\nفيض القدير شرح الجامع الصغير، للمناوي (6/ 89).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (2/ 947).","benefits":["فضل التيسير على عباد الله تعالى، وأنه من الأسباب المُنجِيَة من أهوال يوم القيامة.","الجزاء من جنس العمل."],"wordsMeanings":[{"word":"عرشه","meaning":" العرش هو المخلوق العظيم الذي استوى عليه الرحمن، ولا يقدر قدرَه إلا الله عز وجل."}],"category":"aqidah","bookId":"tirmidhi","tags":["أنظر","معسرا،","وضع","له،","أظله","الله"],"source":"hadeethenc"},{"id":"he_4204","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ يُرِدِ اللهُ بِهِ خَيْرًا يُصِبْ مِنْهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أنَّ الله إذا أراد بأحدٍ من عباده المؤمنين خيرًا ابتلاهم في أنفسهم وأموالهم وأهلهم، لِمَا يحصل فيه للمؤمن من اللجوء إلى الله تعالى بالدعاء، وتكفير السيئات، ورِفْعَة الدرجات.","reference":"صحيح البخاري (7/ 115) (5645).\nكنوز رياض الصالحين، لمجموعة من الباحثين (1/ 509).\nبهجة الناظرين، لسليم الهلالي (1/ 98).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص45).\nنزهة المتقين، مجموعة من المشايخ (1/ 71).\nشرح رياض الصالحين، لابن عثيمين (1/ 244).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (3/ 1127).","benefits":["أن المؤمن مُعرَّض لأنواع من البلاء.","الابتلاء قد يكون أمارة حُبِّ الله لعبده، حتى يرفع درجته، ويُعْلِي مَرتبته، ويكفِّر خطيئته.","الحث على الصبر عند المصائب وعدم الجزع."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["يرد","الله","خيرا","يصب","منه"],"source":"hadeethenc"},{"id":"he_4295","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ: «دَعُونِي مَا تَرَكْتُكُمْ، إِنَّمَا هَلَكَ مَنْ كَانَ قَبْلَكُمْ بِسُؤَالِهِمْ وَاخْتِلَافِهِمْ عَلَى أَنْبِيَائِهِمْ، فَإِذَا نَهَيْتُكُمْ عَنْ شَيْءٍ فَاجْتَنِبُوهُ، وَإِذَا أَمَرْتُكُمْ بِأَمْرٍ فَأْتُوا مِنْهُ مَا اسْتَطَعْتُمْ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"ذَكَرَ النبيُّ صلى الله عليه وسلم أنّ الأحكام الشرعية على أقسام ثلاثة: ما سُكت عنه، ونواهي، وأوامر. \n\nفأما الأول: وهو ما سَكَتَ الشرعُ عنه: حيث لا حُكْم، وأنّ الأصل في الأشياء عدم الوجوب؛ \nفأما في عهده صلى الله عليه وسلم فيجب تركُ السؤال عن شيء لم يقع خشية أن ينزل به وجوب أو تحريم، فإن الله تركَها رحمة بالعباد، \nوأما بعد موته صلى الله عليه وسلم فإن كان السؤال على وجه الاستفتاء أو التعليم لما يحتاج إليه من أمر الدين فهو جائز بل مأمور به، وإن كان على وجه التَّعَنُّت والتكلُّف فهو المراد بترك السؤال عنه في هذا الحديث؛ وذلك لأنه قد يُفضي إلى مثل ما وقع لبني إسرائيل، إذ أُمروا أن يذبحوا بقرة فلو ذبحوا أيَّ بقرة لامتثلوا، ولكنهم شددوا فشُدِّد عليهم. \n\nالثاني: النواهي؛ وهي: ما يثاب تاركه، ويعاقب فاعله، فيجب اجتنابُها كلها. \n\nالثالث: الأوامر؛ وهو ما يثاب فاعله، ويعاقب تاركه، فيجب أن يفعل منه قدر الاستطاعة.","reference":"صحيح البخاري (9/ 94) (7288).\nصحيح مسلم (2/ 975) (1337).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 236).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 181).\nشرح رياض الصالحين، لابن عثيمين (2/ 268).","benefits":["ينبغي الانشغال بالأهم  المُحتاج إليه، وترك ما لا يحتاج إليه في الحال، وعدم الاشتغال بالسؤال عما لم يقع.","حرمة السؤال الذي ربما أوصل إلى تعقيد المسائل، وفتح باب الشبهات المفضية إلى كثرة الاختلاف.","الأمر بترك كل المنهيات؛ لأنه لا مشقة في تركها، ولذلك كان النهي عنه عامًّا.","الأمر بفعل المأمور به على قدر الاستطاعة؛ لأنه قد يلزم منه مشقة أو يعجز عنه؛ ولذا كان الأمر به على قدر الاستطاعة.","النهي عن كثرة السؤال، قد قسم العلماء السؤال إلى قسمين: أحدهما: ما كان على وجه التعليم لما يحتاج إليه من أمر الدين، فهذا مأمور به ومن هذا النوع أسئلة الصحابة، والثاني: ما كان على وجه التعنت والتكلف وهذا هو المنهي عنه.","تحذير هذه الأمة من مخالفة نبيها، كما وقع في الأمم التي قبلها.","كثرة السؤال مما لا يُحتاج إليه والاختلاف على الأنبياء سببٌ للهلاك، ولا سيّما في الأمور التي لا يمكن الوصول إليها، مثل: مسائل الغيب التي لا يعلمها إلا الله، وأحوال يوم القيامة.","النهي عن السؤال في شِداد المسائل، قال الأوزاعي: إن الله إذا أراد أن يحرم عبده بركة العلم ألقى على لسانه المغاليط، فلقد رأيتهم أقلَّ الناس علمًا، وقال ابن وهب: سمعت مالكًا يقول: المِراء في العلم يذهب بنور العلم من قلب الرجل."],"wordsMeanings":[],"category":"aqidah","tags":["دعوني","تركتكم،","إنما","هلك","كان","قبلكم"],"source":"hadeethenc"},{"id":"he_4322","text":"عن ابن عباس رضي الله عنهما عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فِيمَا يَرْوِي عَنْ رَبِّهِ عَزَّ وَجَلَّ قَالَ: قَالَ: «إِنَّ اللهَ كَتَبَ الْحَسَنَاتِ وَالسَّيِّئَاتِ، ثُمَّ بَيَّنَ ذَلِكَ، فَمَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا كَتَبَهَا اللهُ لَهُ عِنْدَهُ حَسَنَةً كَامِلَةً، فَإِنْ هُوَ هَمَّ بِهَا فَعَمِلَهَا كَتَبَهَا اللهُ لَهُ عِنْدَهُ عَشْرَ حَسَنَاتٍ إِلَى سَبْعِمِائَةِ ضِعْفٍ، إِلَى أَضْعَافٍ كَثِيرَةٍ، وَمَنْ هَمَّ بِسَيِّئَةٍ فَلَمْ يَعْمَلْهَا كَتَبَهَا اللهُ لَهُ عِنْدَهُ حَسَنَةً كَامِلَةً، فَإِنْ هُوَ هَمَّ بِهَا فَعَمِلَهَا كَتَبَهَا اللهُ لَهُ سَيِّئَةً وَاحِدَةً».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ الرسولُ صلى الله عليه وسلم أنَّ الله قَدَّر الحسناتِ والسيئاتِ ثم بَيَّنَ للمَلَكين كيف يكتبانها: فمَن أراد وقصد وعَزَم على فعل الحسنة كُتبتْ له حسنة واحدة وإن لم يعملْها، فإن عَمِلها فإنها تُضاعف بعشر أمثالها إلى سبعمائة ضِعفٍ إلى أضعاف كثيرة، والزيادة بحسب ما في القلب من الإخلاص وتَعَدِّي النَّفْع ونحو ذلك. ومَن أراد وقصد وعزم على فعل السيئة ثم تَرَكها لله كُتبت له حسنة، وإن تركها تشاغلًا عنها مع عدم فعل أسبابها لم تُكتب شيئًا، وإن تركها عَجزًا عنها كُتبتْ عليه نِيَّتُه، وإن عملها كُتبت له سيئة واحدة.","reference":"صحيح البخاري (8/ 103) (6491).\nصحيح مسلم (1/ 118) (131).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص85).\nشرح الأربعين النووية، لابن عثيمين (ص368).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص125).\nفتح الباري، لابن حجر (11/ 324).","benefits":["هذا الحديث مما يرويه النبي صلى الله عليه وسلم عن ربه، ويسمى بالحديث القدسي أو الإلهي، وهو الذي لفظه ومعناه من الله، غير أنه ليست فيه خصائص القرآن التي امتاز بها عما سواه ، من التعبد بتلاوته والطهارة له والتحدي والإعجاز وغير ذلك.","إثبات كتابة الله تعالى الحسنات والسيئات، ثم بيانه ذلك لعباده حتى يعلموا ذلك، ويكونوا على بصيرة من أمرهم، فيمتثلوا أمره ويجتنبوا نهيه على هدى من ربّهم.","بيانُ فضل الله تعالى العظيم على هذه الأمة في كتابة الحسنات ومضاعفتها، وعدم كتابة السيئات إلا بعد فعلها وكتابتها سيئة واحدة.","الزيادة في مضاعفة الحسنات بحسب ما في القلب من الإخلاص وتَعَدِّي النَّفْع ونحو ذلك، فيضاعفها الله برحمته وفضله.","بيان الفضل الذي يترتب للعبد على ترك السيئة وهِجران لذته، وترك شهوته من أجل ربه عز وجل رغبةً في ثوابه، ورهبةً من عقابه.","من لطف الله تعالى بالأمة أن ضاعف لها حسناتها ولم يضاعف سيئاتها.","كتابة الملائكة لجميع الأعمال من أعمال القلوب والجوارح."],"wordsMeanings":[],"category":"aqidah","tags":["الله","كتب","الحسنات","والسيئات،","بين","ذلك،"],"source":"hadeethenc"},{"id":"he_4555","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «إِنَّ اللهَ لَا يَنْظُرُ إِلَى صُوَرِكُمْ وَأَمْوَالِكُمْ، وَلَكِنْ يَنْظُرُ إِلَى قُلُوبِكُمْ وَأَعْمَالِكُمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَِّنُ النبيُّ صلى الله عليه وسلم أنَّ اللهَ سبحانه وتعالى لا يَنظُرُ إلى صور العبادِ وأجسامِهم، هل هي جميلةٌ أو ذَميمةٌ؟ هلْ هي كَبيرةٌ أو صَغيرةٌ؟ أو صَحيحةٌ أو سَقيمةٌ؟ \nولا يَنظُرُ إلى أموالهم، هل هي كثيرة أو قليلة؟ فالله عزَّ وجلَّ لا يُؤاخِذُ عبادَه ولا يُحاسبُهم على هذه الأمورِ وتَفاوُتِهم فيها، ولكنْ يَنظُرُ إلى قُلوبِهم وما فيها من التَّقْوى واليقينِ، والصدقِ والإخلاصِ، أو قصدِ الرياءِ والسُّمعةِ، وينظُرُ إلى أعمالِهم من حيثُ صلاحُها وفسادُها؛ فيثيبُ ويُجازي عليها.","reference":"صحيح مسلم (2564) (4/ 1986).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 40).\nتطريز رياض الصالحين، لفيصل المبارك (ص14).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 25).","benefits":["الاعتناء بإصلاح القلب، وتطهيره عن كل وصف مذموم.","صلاح القلب بالإخلاص، وصلاح العمل بمتابعة النبي عليه الصلاة والسلام، وهما محل النظر والاعتبار عند الله تعالى.","لا يغتر الإنسان بماله ولا بجماله ولا ببدنه ولا بشيء من مظاهر هذه الدنيا.","التحذير من الركون إلى الظاهر دون إصلاح الباطن."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["الله","ينظر","إلى","صوركم","وأموالكم،","ولكن"],"source":"hadeethenc"},{"id":"he_4563","text":"عن عمر بن الخطاب رضي الله عنه قال: بَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ إِذْ طَلَعَ عَلَيْنَا رَجُلٌ شَدِيدُ بَيَاضِ الثِّيَابِ، شَدِيدُ سَوَادِ الشَّعَرِ، لَا يُرَى عَلَيْهِ أَثَرُ السَّفَرِ، وَلَا يَعْرِفُهُ مِنَّا أَحَدٌ، حَتَّى جَلَسَ إِلَى النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَأَسْنَدَ رُكْبَتَيْهِ إِلَى رُكْبَتَيْهِ، وَوَضَعَ كَفَّيْهِ عَلَى فَخِذَيْهِ، وَقَالَ: يَا مُحَمَّدُ، أَخْبِرْنِي عَنِ الْإِسْلَامِ، فَقَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «الْإِسْلَامُ أَنْ تَشْهَدَ أَنْ لَا إِلَهَ إِلَّا اللهُ، وَأَنَّ مُحَمَّدًا رَسُولُ اللهِ، وَتُقِيمَ الصَّلَاةَ، وَتُؤْتِيَ الزَّكَاةَ، وَتَصُومَ رَمَضَانَ، وَتَحُجَّ الْبَيْتَ إِنِ اسْتَطَعْتَ إِلَيْهِ سَبِيلًا» قَالَ: صَدَقْتَ، قَالَ: فَعَجِبْنَا لَهُ، يَسْأَلُهُ وَيُصَدِّقُهُ، قَالَ: فَأَخْبِرْنِي عَنِ الْإِيمَانِ، قَالَ: «أَنْ تُؤْمِنَ بِاللهِ، وَمَلَائِكَتِهِ، وَكُتُبِهِ، وَرُسُلِهِ، وَالْيَوْمِ الْآخِرِ، وَتُؤْمِنَ بِالْقَدَرِ خَيْرِهِ وَشَرِّهِ» قَالَ: صَدَقْتَ، قَالَ: فَأَخْبِرْنِي عَنِ الْإِحْسَانِ، قَالَ: «أَنْ تَعْبُدَ اللهَ كَأَنَّكَ تَرَاهُ، فَإِنْ لَمْ تَكُنْ تَرَاهُ فَإِنَّهُ يَرَاكَ» قَالَ: فَأَخْبِرْنِي عَنِ السَّاعَةِ، قَالَ: «مَا الْمَسْؤُولُ عَنْهَا بِأَعْلَمَ مِنَ السَّائِلِ» قَالَ: فَأَخْبِرْنِي عَنْ أَمَارَتِهَا، قَالَ: «أَنْ تَلِدَ الْأَمَةُ رَبَّتَهَا، وَأَنْ تَرَى الْحُفَاةَ الْعُرَاةَ الْعَالَةَ رِعَاءَ الشَّاءِ يَتَطَاوَلُونَ فِي الْبُنْيَانِ» قَالَ: ثُمَّ انْطَلَقَ، فَلَبِثْتُ مَلِيًّا ثُمَّ قَالَ لِي: «يَا عُمَرُ، أَتَدْرِي مَنِ السَّائِلُ؟» قُلْتُ: اللهُ وَرَسُولُهُ أَعْلَمُ، قَالَ: «فَإِنَّهُ جِبْرِيلُ، أَتَاكُمْ يُعَلِّمُكُمْ دِينَكُمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ عمر بن الخطاب رضي الله عنه أنّ جبريل عليه السلام خرج على الصحابة رضي الله عنهم بصورةِ رجلٍ لا يُعرف، ومن صفاته أنّ ثيابَه شديدة البياض، وشعرَه شديد السواد، لا يُرى عليه أَثَرُ السَّفَر من ظهور التعب، والغبار، وتفرُّق الشَّعَر، واتساخ الثياب، ولا يَعرفه أحدٌ من الحاضرين، وهم جلوس عند النبي صلى الله عليه وسلم، فَجَلسَ بين يدي النبي صلى الله عليه وسلم جِلْسَة المُتَعلِّم، فسأله عن الإسلام، فأجابه بهذه الأركان التي تتضمن الإقرار بالشهادتين، والمحافظة على الصلوات الخمس، وأداء الزكاة لمستحقيها، وصيام شهر رمضان، وأداء فريضة الحج على المستطيع.\n\nفقال السائل: صدقت، فاستغرب الصحابةُ من سؤالِه الدَّالِّ على عَدَمِ معرفتِه فيما يَظهر ثم تصديقِه.\n\nثم سأله عن الإيمان، فأجابه بهذه الأركان الستة المتضمنة الإيمان بوجود الله تعالى وصفاته، وإفراده بأفعاله كالخلق، وإفراده بالعبادة، وأن الملائكة التي خلقها الله من نور عباد مُكْرَمون لا يعصون الله تعالى وبأمره يعملون، والإيمان بالكتب المنزلة على الرُّسُل من عند الله تعالى، كالقرآن والتوراة والإنجيل وغيرها، وبالرسل المبلِّغين عن الله دينَه، ومنهم نوح وإبراهيم وموسى وعيسى وآخرهم محمد صلى الله عليهم وسلم، وغيرهم من الأنبياء والرسل، والإيمان باليوم الآخر، ويدخل فيه ما بعد الموت من القبر والحياة البرزخية، وأن الإنسان يُبعث بعد الموت ويُحاسب، ويكون مصيره إما إلى الجنة أو النار، والإيمان بأنَّ الله قدَّرَ الأشياء حسبما سَبَق به علمُه واقتضته حكمتُه وكتابته لذلك، ومشيئته له، ووقوعها على حسب ما قدَّرها، وخلقَه لها.\n \nثم سأله عن الإحسان، فأخبره أن الإحسان أن يَعبُدَ اللهَ كأنه يراه، فإن لم يَتَحقَّق له الوصولُ إلى هذه المنزلة فلْيَعبُدِ اللهَ تعالى كأنَّ اللهَ يُشاهدُه، فالأولى منزلة المشاهدة، وهي أعلى، والثانية منزلة المراقبة.\n\nثم سأله متى الساعة؟ فبيَّن النبيُّ صلى الله عليه وسلم أنَّ عِلْمَ الساعة ممّا استأثر الله بعلمه، فلا يعلمه أحد من الخلق، لا المسؤول عنها ولا السائل.\n\nثم سأله عن علامات الساعة؟ فبين أنَّ مِن علاماتِها كثرةَ السراري وأولادِها، أو كثرةَ عقوقِ الأولاد لأمهاتِهم يعاملونهن معاملة الإماء، وأن رعاةَ الغنم والفقراء تُبسط لهم الدنيا في آخر الزمان، فيتفاخرون في زخرفة المباني وتشييدِها.\n\nثم أخبر النبيُّ صلى الله عليه وسلم أنَّ السائل هو جبريل جاء لتعليم الصحابة هذا الدين الحنيف.","reference":"صحيح مسلم (1/ 36) (8).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص7).\nشرح الأربعين النووية، لابن عثيمين (ص19).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص15).\nالأحاديث الأربعون النووية وعليها الشرح الموجز المفيد، لعبد الله المحسن (ص7).\nتاج العروس من جواهر القاموس، للزبيدي (2/ 460).","benefits":["حُسْن خُلُقِ النبي صلى الله عليه وسلم، وأنه يجلس مع أصحابه ويجلسون إليه.","مشروعية الرفق بالسائل وتقريبه، ليتمكن من السؤال غير مُنْقَبِضٍ ولا خائف.","الأدب مع المعلِّم كما فعل جبريل عليه السلام، حيث جلس أمام النبي صلى الله عليه وسلم جِلْسَة المتأدِّب ليأخذ منه.","أركان الإسلام خمسة، وأصولَ الإيمان ستة.","عند اجتماع الإسلام والإيمان يُفسَّر الإسلام بالأمور الظاهرة، والإيمان بالأمور الباطنة.","بيان أن الدين درجات متفاوتة، فالدرجة الأولى :الإسلام، والثانية :الإيمان، والثالثة: الإحسان، وهو أعلاها.","الأصل في السائل عدم العلم، والجهل هو الباعث على السؤال، لذلك عَجِب الصحابةُ من سؤالِه وتصديقِه.","البدء بالأهمِّ فالأهمِّ؛ لأنَّه بُدىء بالشهادَتين في تفسير الإسلام، وبُدىء بالإيمان بالله في تفسير الإيمان.","سؤال أهل العلم ما لا يجهله السائل، ليعلم غيره.","علم الساعة مِمَّا استأثر الله بعلمه."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["الإسلام","تشهد","إله","إلا","الله،","وأن"],"source":"hadeethenc"},{"id":"he_4792","text":"عَنْ عَائِشَةَ رضي الله عنها قَالَتْ: قَالَ رَسُولُ اللهِ صلى الله عليه وسلم: «مَنْ أَحْدَثَ فِي أَمْرِنَا هَذَا مَا لَيْسَ فِيهِ فَهُوَ رَدٌّ» متفق عليه.\nولمسلم: «مَنْ عَمِلَ عَمَلًا لَيْسَ عَلَيْهِ أَمْرُنَا فَهُوَ رَدٌّ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ مَن اخترَعَ في الدِّينِ أو عَمِلَ عملًا لم يَدُل عليه دليلٌ من الكتاب والسنة، فهو مَردودٌ على صاحبِه غير مقبول عند الله.","reference":"صحيح البخاري (3/ 184) (2697).\nصحيح مسلم (3/ 1343) (1718).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص16).\nشرح الأربعين النووية، لابن عثيمين (ص96).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص38).","benefits":["العبادات مبناها على ما جاء في الكتاب والسنة، فلا نعبد الله تعالى إلا بما شَرَعَ لا بالبدع والمُحْدَثات.","الدين ليس بالرأي والاستحسان، وإنما بالاتباع للرسول صلى الله عليه وسلم.","هذا الحديث دليلٌ على كمال الدين.","البدعة هي كل ما أُحْدِثَ في الدين ولم يَكنْ على عهدِ النبي صلى الله عليه وسلم وأصحابه من عقيدةٍ أو قولٍ أو عملٍ.","هذا الحديث أصلٌ من أصول الإسلام، وهو كالميزان للأعمال، فكما أنَّ كلَّ عَمَلٍ لا يُراد به وجه الله تعالى، فليس لعامله فيه ثواب، فكذلك كلُّ عمل لا يكون وِفْقَ ما جاء به رسول الله صلى الله عليه وسلم فهو مردود على عامله.","المُحْدَثات المنهي عنها ما كان من أمور الدين وليس الدنيا."],"wordsMeanings":[],"category":"aqidah","tags":["أحدث","أمرنا","هذا","ليس","فيه","فهو"],"source":"hadeethenc"},{"id":"he_4810","text":"عن أبي ذر رضي الله عنه: عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فِيمَا رَوَى عَنِ اللهِ تَبَارَكَ وَتَعَالَى أَنَّهُ قَالَ: «يَا عِبَادِي إِنِّي حَرَّمْتُ الظُّلْمَ عَلَى نَفْسِي، وَجَعَلْتُهُ بَيْنَكُمْ مُحَرَّمًا، فَلَا تَظَالَمُوا، يَا عِبَادِي كُلُّكُمْ ضَالٌّ إِلَّا مَنْ هَدَيْتُهُ، فَاسْتَهْدُونِي أَهْدِكُمْ، يَا عِبَادِي كُلُّكُمْ جَائِعٌ إِلَّا مَنْ أَطْعَمْتُهُ، فَاسْتَطْعِمُونِي أُطْعِمْكُمْ، يَا عِبَادِي كُلُّكُمْ عَارٍ إِلَّا مَنْ كَسَوْتُهُ، فَاسْتَكْسُونِي أَكْسُكُمْ، يَا عِبَادِي إِنَّكُمْ تُخْطِئُونَ بِاللَّيْلِ وَالنَّهَارِ وَأَنَا أَغْفِرُ الذُّنُوبَ جَمِيعًا فَاسْتَغْفِرُونِي أَغْفِرْ لَكُمْ، يَا عِبَادِي إِنَّكُمْ لَنْ تَبْلُغُوا ضَرِّي فَتَضُرُّونِي، وَلَنْ تَبْلُغُوا نَفْعِي فَتَنْفَعُونِي، يَا عِبَادِي لَوْ أَنَّ أَوَّلَكُمْ وَآخِرَكُمْ وَإِنْسَكُمْ وَجِنَّكُمْ كَانُوا عَلَى أَتْقَى قَلْبِ رَجُلٍ وَاحِدٍ مِنْكُمْ مَا زَادَ ذَلِكَ فِي مُلْكِي شَيْئًا، يَا عِبَادِي لَوْ أَنَّ أَوَّلَكُمْ وَآخِرَكُمْ وَإِنْسَكُمْ وَجِنَّكُمْ كَانُوا عَلَى أَفْجَرِ قَلْبِ رَجُلٍ وَاحِدٍ مَا نَقَصَ ذَلِكَ مِنْ مُلْكِي شَيْئًا، يَا عِبَادِي لَوْ أَنَّ أَوَّلَكُمْ وَآخِرَكُمْ وَإِنْسَكُمْ وَجِنَّكُمْ قَامُوا فِي صَعِيدٍ وَاحِدٍ فَسَأَلُونِي فَأَعْطَيْتُ كُلَّ إِنْسَانٍ مَسْأَلَتَهُ مَا نَقَصَ ذَلِكَ مِمَّا عِنْدِي إِلَّا كَمَا يَنْقُصُ الْمِخْيَطُ إِذَا أُدْخِلَ الْبَحْرَ، يَا عِبَادِي إِنَّمَا هِيَ أَعْمَالُكُمْ أُحْصِيهَا لَكُمْ ثُمَّ أُوَفِّيكُمْ إِيَّاهَا، فَمَنْ وَجَدَ خَيْرًا فَلْيَحْمَدِ اللهَ، وَمَنْ وَجَدَ غَيْرَ ذَلِكَ فَلَا يَلُومَنَّ إِلَّا نَفْسَهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبيِّنُ النبيُّ صلى الله عليه وسلم أنَّ الله سبحانه وتعالى قال بأنه حَرَّم الظلم على نفسه، وجعل الظلم محرّمًا بين خلقِه فلا يَظلم أحد أحدًا، \nوأن الخلقَ كلَّهم ضالون عن طريق الحق إلا بهداية الله وتوفيقه، ومن سَألَها اللهَ وفقَه وهداه، \nوأن الخلق فقراء إلى الله محتاجون إليه في جميع حوائجهم، ومن سأل الله قضى حاجته وكفاه، \nوأنهم يذنبون بالليل والنهار، والله تعالى يستر ويتجاوز عند سؤال العبد المغفرة، \nوأنهم لا يستطيعون أن يضروا الله أو ينفعوه بشيء، \nوأنهم لو كانوا على أتقى قلب رجل واحد ما زادت تقواهم في ملك الله، \nولو كانوا على أفجر قلب رجل واحد ما نقص فجورهم من ملكه شيئًا؛ لأنهم ضعفاء فقراء إلى الله، محتاجون إليه في كل حال وزمان ومكان، وهو الغني سبحانه، \nوأنهم لو قاموا في مقام واحد إنسُهم وجنُّهم، أولُهم وآخِرُهم يسألون اللهَ فأعطى كلَّ واحد منهم ما سأل، ما نقص ذلك مما عند الله شيئًا، كالإبرة لو أُدْخِلت البحرَ ثم أُخْرِجت لم يَنقص البحر بذلك شيء، وهذا لكمال غناه سبحانه.\n\nوأن الله سبحانه يحفظ أعمالَ العبادِ ويُحصيها عليهم، ثم يُوفِّيهم إياها يوم القيامة، فمن وجد جزاء عمله خيرًا فليحمد الله على توفيقه لطاعته، ومن وجد جزاء عمله شيئًا غير ذلك فلا يلومَنَّ إلا نفسَه الأمارةَ بالسوءِ التي قادتْه إلى الخُسران.","reference":"صحيح مسلم (4/ 1994) (2577).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص52).\nشرح الأربعين النووية، لابن عثيمين (ص235).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص82).\nالأحاديث الأربعون النووية وعليها الشرح الموجز المفيد، لعبد الله المحسن (ص46).","benefits":["هذا الحديث مما يرويه النبي صلى الله عليه وسلم عن ربه، ويسمى بالحديث القدسي أو الإلهي، وهو الذي لفظه ومعناه من الله، غير أنه ليست فيه خصائص القرآن التي امتاز بها عما سواه ، من التعبد بتلاوته والطهارة له والتحدي والإعجاز وغير ذلك.","ما يحصل للعباد من علم أو اهتداء، فبهداية الله وتعليمه.","ما أصاب العبد من خير فمن فضل الله تعالى، وما أصابه من شر فمن نفسه وهواه.","من أحسن فبتوفيق الله، وجزاؤه فضل من الله فله الحمد، ومن أساء فلا يلومن إلا نفسه."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["عبادي","إني","حرمت","الظلم","على","نفسي،"],"source":"hadeethenc"},{"id":"he_4811","text":"عن ابن عباس رضي الله عنهما قال: كُنْتُ خَلْفَ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَوْمًا، فَقَالَ: «يَا غُلَامُ، إِنِّي أُعَلِّمُكَ كَلِمَاتٍ، احْفَظِ اللهَ يَحْفَظْكَ، احْفَظِ اللهَ تَجِدْهُ تُجَاهَكَ، إِذَا سَأَلْتَ فَاسْأَلِ اللهَ، وَإِذَا اسْتَعَنْتَ فَاسْتَعِنْ بِاللهِ، وَاعْلَمْ أَنَّ الْأُمَّةَ لَوِ اجْتَمَعَتْ عَلَى أَنْ يَنْفَعُوكَ بِشَيْءٍ، لَمْ يَنْفَعُوكَ إِلَّا بِشَيْءٍ قَدْ كَتَبَهُ اللهُ لَكَ، وَلَوِ اجْتَمَعُوا عَلَى أَنْ يَضُرُّوكَ بِشَيْءٍ، لَمْ يَضُرُّوكَ إِلَّا بِشَيْءٍ قَدْ كَتَبَهُ اللهُ عَلَيْكَ، رُفِعَتِ الْأَقْلَامُ وَجَفَّتِ الصُّحُفُ».","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ ابنُ عباس رضي الله عنه أنه كان صغيرًا راكبًا مع النبي صلى الله عليه وسلم، فقال له عليه الصلاة والسلام: إني أُعلِّمك أمورًا وأشياءَ ينفعك الله بها:\n\nاحفظ الله بِحفظِ أوامرِه واجتنابِ نواهيه، بحيث يَجِدُكَ في الطاعات والقربات، ولا يجدُكَ في المعاصي والآثام، فإن فعلتَ ذلك كان جزاؤك أن يحفظَك الله من مكاره الدنيا والآخرة، وينصرَك في مُهماتِك أينما توجَّهتَ.\n\nوإذا أردتَ أن تسأل شيئًا، فلا تسألْ إلا الله فإنه وحده الذي يُجيب السائلين.\n\nوإذا أردتَ العونَ فلا تستعنْ إلا بالله.\n\nولْيكُن عندك يقينٌ أنه لن تحصل لك منفعة ولو اجتمع على منفعتِك أهلُ الأرض جميعًا إلا ما كتبه الله لك، ولن يحصُلَ عليك ضرر ولو اجتمع على ضرك أهلُ الأرض جميعًا إلا ما قدَّره الله عليك.\n\nوأن هذا الأمر قد كَتَبه الله عز وجل وقدّره وِفْقَ ما اقتضته حكمته وعلمه، ولا تبديل لما كتبه الله.","reference":"سنن الترمذي (4/ 284) (2516).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص42).\nشرح الأربعين النووية، لابن عثيمين (ص200).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص69).","benefits":["أهمية تعليم الصغار والأطفال أمورَ الدين من التوحيد والآداب وغير ذلك.","الجزاء من جنس العمل.","الأمر بالاعتماد على الله، والتوكل عليه دون غيره، وهو نعم الوكيل.","الإيمان بالقضاء والقدر والرضا به، وأن الله قدر كل شيء.","من أضاع أمر الله فإن الله يُضَيِّعُه ولا يَحفظُه."],"wordsMeanings":[{"word":"خلف النبي -صلى الله عليه وسلم","meaning":" أي على دابته رديفًا."},{"word":"غلام","meaning":" الصبي من حين يولد إلى أن يقارب سنَّ البلوغ."}],"category":"aqidah","bookId":"tirmidhi","tags":["غلام،","إني","أعلمك","كلمات،","احفظ","الله"],"source":"hadeethenc"},{"id":"he_4947","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «كُلُّ أُمَّتِي يَدْخُلُونَ الْجَنَّةَ إِلَّا مَنْ أَبَى»، قَالُوا: يَا رَسُولَ اللهِ، وَمَنْ يَأْبَى؟ قَالَ: «مَنْ أَطَاعَنِي دَخَلَ الْجَنَّةَ، وَمَنْ عَصَانِي فَقَدْ أَبَى».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم أنَّ كلَّ أُمَّتِه يدخلون الجنة إلا مَن امتنع!\n\nفقال الصحابة رضي الله عنهم: ومَن يمتنع يا رسول الله؟!\n\nفأجابهم عليه الصلاة والسلام: أنَّ مَن انقاد واتَّبع وأطاعَ الرسولَ صلى الله عليه وسلم دَخَلَ الجنة، وأما مَن عصى ولم يَنْقَدْ للشرع فقد امتنع من دخول الجنة بأعمالِه السيئة.","reference":"صحيح البخاري (9/ 92) (7280).\nفيض القدير شرح الجامع الصغير، للمناوي، المكتبة التجارية الكبرى – مصر، الطبعة: الأولى.\nبهجة الناظرين شرح رياض الصالحين لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nالتيسير بشرح الجامع الصغير، للمناوي، مكتبة الإمام الشافعي، الرياض، ط3.","benefits":["أن طاعة الرسول صلى الله عليه وسلم من طاعة الله، ومعصيته من معصية الله.","طاعة النبي صلى الله عليه وسلم توجب الجنة، ومعصيته توجب النار.","بشارة للطائعين من هذه الأمة، وأنهم كلَّهم يدخلون الجنة إلا من عصى الله ورسوله.","شفقته صلى الله عليه وسلم على أُمته، وحرصه على هدايتهم."],"wordsMeanings":[],"category":"aqidah","bookId":"bukhari","tags":["أمتي","يدخلون","الجنة","إلا","أبى"],"source":"hadeethenc"},{"id":"he_5353","text":"عن ابنِ عُمَرَ رضي الله عنهما قال: قال رسولُ الله صلَّى الله عليه وسلم: «مَن تَشَبَّهَ بِقَوْمٍ فَهُوَ مِنْهُمْ».","attribution":"رواه أبو داود وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ مَن تَشَبَّهَ بقومٍ من الكفارِ أو الفُسَّاق أو الصالحين -وذلك بأنْ يَفعَلَ شيئًا من خصائصِهم من العقائد أو العبادات أو العادات- فهو منهم؛ لأنَّ التَّشَبُّهَ بهم في الظاهر يؤدِّي إلى التشبه بهم في الباطن، ولا شك أنَّ التشبهَ بالقوم ناتجٌ عن إعجاب، وقد يؤدِّي إلى محبتهم وتعظيمهم والركون إليهم، وهذا قد يَجرُّ المرءَ إلى أنْ يتشبه بهم حتى في الباطن والعبادة -والعياذ بالله-.","reference":"سنن أبي داود (6/ 144) (4031).\nمسند أحمد (9/ 126) (5115).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 363).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 157).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (6/ 335).\nمشكاة المصابيح، للتبريزي (2/ 1246).","benefits":["التحذير من التشبُّه بالكفار والفساق.","الحث على التشبه بالصالحين والاقتداء بهم.","التشبه في الظاهر يورث المحبة في الباطن.","يَنالُ الإنسان من الوعيد والإثم بحسب التشبه ونوعه.","النهي عن التشبه بالكفار في دينهم وفي عاداتهم المختصة بهم، أما ما لم يكن كذلك كتعلُّم الصناعات ونحوها فلا يدخل في النهي."],"wordsMeanings":[],"category":"aqidah","bookId":"abudawud","tags":["تشبه","بقوم","فهو","منهم"],"source":"hadeethenc"},{"id":"he_5359","text":"عَنْ عَبْدِ اللهِ بنِ مَسْعُودٍ رضي الله عنه قال: سَأَلْتُ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: أَيُّ الذَّنْبِ أَعْظَمُ عِنْدَ اللهِ؟ قَالَ: «أَنْ تَجْعَلَ لِلهِ نِدًّا وَهُوَ خَلَقَكَ» قُلْتُ: إِنَّ ذَلِكَ لَعَظِيمٌ، قُلْتُ: ثُمَّ أَيُّ؟ قَالَ: «وَأَنْ تَقْتُلَ وَلَدَكَ؛ تَخَافُ أَنْ يَطْعَمَ مَعَكَ» قُلْتُ: ثُمَّ أَيُّ؟ قَالَ: «أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"سُئِلَ النبيُّ صلى الله عليه وسلم عن أَعْظَمِ الذنوب فقال: \nأعظمُها الشركُ الأكبر، وهو أن تجعل لله مَثِيْلًا أو نظيرًا في ألوهيته أو ربوبيته أو أسمائه وصفاته، وهذا الذنب لا يغفره الله تعالى إلا بالتوبة، وإن مات صاحبه عليه فهو مُخَلَّدٌ في النار. \nثم قَتْلُ المرءِ ولدَه خشيةَ أن يأكل معه، وقتلُ النفس حرام، لكن يعظم إثمه إذا كان المقتول ذا رَحِمٍ من القاتل، ويعظم إثمه أيضًا حين يكون مقصودُ القاتل الخشيةَ من أنْ يشاركه المقتول في رزق الله. \nثم أنْ يُزانيَ الرجل بزوجة جاره بأنْ يُحاول التَّغْرِيرَ بزوجة جاره حتى يَزنيَ بها وتنقاد له، \nوالزنا حرام ولكن يعظم إثمه إذا كانت المزنيُّ بها زوجةَ الجار الذي أوصى الشرع بالإحسان إليه وبره وحسن صحبته.","reference":"صحيح البخاري (6/ 18) (4477).\nصحيح مسلم (1/ 90) (86).\nشرح النووي على مسلم (2/ 79).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (6/ 288).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 335).","benefits":["تفاوت الذنوب في العِظَم، كما أن الأعمال الصالحة تَتَفاوت في الفضل.","أعظم الذنوب: الشرك بالله تعالى، ثم قتل الولد خشية أن يطعم معك، ثم أن تُزاني زوجة جارك.","الرزق بيد الله وقد تَكَفَّلَ سبحانه بأرزاق المخلوقين.","عِظَم حق الجار، وأنَّ أذيتَه أَعظم إثمًا من أذية غيرِه.","الخالق هو المستحق للعبادة وحده لا شريك له."],"wordsMeanings":[],"category":"aqidah","tags":["سألت","النبي","صلى","الله","عليه","وسلم:"],"source":"hadeethenc"},{"id":"he_5365","text":"عن أبي أيوب الأنصاري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا يَحِلُّ لِرَجُلٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثِ لَيَالٍ، يَلْتَقِيَانِ، فَيُعْرِضُ هَذَا وَيُعْرِضُ هَذَا، وَخَيْرُهُمَا الَّذِي يَبْدَأُ بِالسَّلَامِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"نهى النبيُّ صلى الله عليه وسلم عن هَجْر المسلم أخاه المسلمَ أكثر من ثلاث ليال، يلتقي كلٌّ منهما بالآخر ولا يسلم عليه ولا يكلمه.\n\nوأفضل هذين المتخاصمين مَن يُحاوِل إزالةَ الهجر، ويبدأ بالسلام، والمراد بالهجر هنا الهجر لحظ النفس، أما الهجر لحق الله تعالى كهجر العصاة والمبتدعة وقرناء السوء، فهذا لا يُؤقَّت بوقت، وإنما هو معلق بالمصلحة في الهجر، ويزول بزوالها.","reference":"صحيح البخاري (8/ 21) (6077).\nصحيح مسلم (4/ 1984) (2560).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 111).\nفتح ذي الجلال والإكرام بشرح بلوغ المرام، لابن عثيمين (6/ 293).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 339).","benefits":["إباحة الهجر في الثلاثة أيام فما دونها، مراعاة للطباع البشرية، فعُفي عن الهجر في الثلاث ليذهب ذلك العارض.","فضل السلام، وأنه يُزيل ما في النفوس، وأنه علامة على المحبة.","حرص الإسلام على الأخوة والألفة بين أهله."],"wordsMeanings":[],"category":"aqidah","tags":["يحل","لرجل","يهجر","أخاه","فوق","ثلاث"],"source":"hadeethenc"},{"id":"he_5375","text":"عن أبي صِرْمة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ ضَارَّ ضَارَّ اللهُ بِهِ، وَمَنْ شَاقَّ شَقَّ اللهُ عَلَيْهِ».","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"حَذَّرَ النبيُّ صلى الله عليه وسلم مِن إدخالِ المَضَرَّة على المسلم، أو إلحاق المَشَقَّة به في أي أمر من أموره؛ في نفسه أو ماله أو أهله، وأنَّ من فعل ذلك فإن الله يُجازيه ويعاقبُه من جِنْسِ عملِه.","reference":"سنن أبي داود (5/ 477) (3635).\nسنن الترمذي (3/ 495) (1940).\nسنن ابن ماجه (3/ 432) (2342).\nمسند أحمد (25/ 34) (15755).\nمساوئ الأخلاق، للخرائطي (ص: 274) (583).\nتوضيح الأحكام مِن بلوغ المرام، للبسام (7/ 445).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (6/ 396).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 261).","benefits":["تحريم الإضرار بالمسلم وإلحاق المشقة به.","انتقام الله لعباده."],"wordsMeanings":[],"category":"aqidah","bookId":"abudawud","tags":["ضار","ضار","الله","به،","ومن","شاق"],"source":"hadeethenc"},{"id":"he_5657","text":"عن جَرِيْر بنِ عبدِ الله رضي الله عنه قال: كُنَّا عِنْدَ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَنَظَرَ إِلَى الْقَمَرِ لَيْلَةً -يَعْنِي الْبَدْرَ- فَقَالَ: «إِنَّكُمْ سَتَرَوْنَ رَبَّكُمْ كَمَا تَرَوْنَ هَذَا الْقَمَرَ، لَا تُضَامُونَ فِي رُؤْيَتِهِ، فَإِنِ اسْتَطَعْتُمْ أَنْ لَا تُغْلَبُوا عَلَى صَلَاةٍ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَا فَافْعَلُوا» ثُمَّ قَرَأَ: «{وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ}»","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كان الصحابةُ مع النبيِّ صلى الله عليه وسلم ذات ليلةٍ فنَظَرَ إلى القمر -ليلة الرابع عشر-، فقال: \nإنَّ المؤمنين سيرون ربَّهم حقيقةً بالعين دون اشتباه، وأنهم لا يتزاحمون ولا يصيبهم تعب ولا مشقة عند رؤيته تعالى. \nثم قال رسول الله صلى الله عليه وسلم: \nفإن استطعتم قطعَ الأسبابِ التي تَصرفُكم عن صلاةِ الفجر وصلاةِ العصر فافعلوا، وأتوا بهما كاملتين في وقتهما في جماعة، فإن ذلك من أسباب النظر إلى وجه الله عز وجل، \nثم قرأ صلى الله عليه وسلم الآية: \n{وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ الْغُرُوبِ}.","reference":"صحيح البخاري (1/ 115) (554)، (6/ 139) (4851).\nصحيح مسلم (1/ 439) (633).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 259).\nتذكرة المؤتسي شرح عقيدة الحافظ عبد الغني المقدسي، لعبدالرزاق البدر (ص177).\nشرح رياض الصالحين، لابن عثيمين (6/ 734).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 776).\nكنوز رياض الصالحين، لمجموعة من الباحثين (13/ 271).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص1091)","benefits":["البشرى لأهل الإيمان برؤية الله تعالى في الجنة.","مِن أساليب الدعوة: التوكيدُ والترغيبُ وضَرْبُ الأمثال."],"wordsMeanings":[],"category":"aqidah","tags":["إنكم","سترون","ربكم","كما","ترون","هذا"],"source":"hadeethenc"},{"id":"he_5811","text":"عن أبي موسى رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «إِنَّ اللهَ لَيُمْلِي لِلظَّالِمِ، حَتَّى إِذَا أَخَذَهُ لَمْ يُفْلِتْهُ» قَالَ: ثُمَّ قَرَأَ: «{وَكَذَلِكَ أَخْذُ رَبِّكَ إِذَا أَخَذَ الْقُرَى وَهِيَ ظَالِمَةٌ إِنَّ أَخْذَهُ أَلِيمٌ شَدِيدٌ}[هود: 102]»","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُحَذِّرُ النبيُّ صلى الله عليه وسلم من التَّمادِي في الظلم بالمعاصي والشرك وظلم الناس في حقوقهم، فإن الله تعالى يُمْهِلُ الظالمَ ويؤخِّرُه ويُطيل له في عُمُرِه ومالِه فلا يُعاجِلُه العقوبةَ؛ فإنْ لم يتب أَخَذَه ولم يُطْلِقْه ولم يَتْرُكْه لكثرة ظلمه.\n\nثم قرأ صلى الله عليه وسلم: {وكذلك أخذ ربك إذا أخذ القرى وهي ظالمة إن أخذه أليم شديد} [هود: 102].","reference":"صحيح البخاري (6/ 74) (4686).\nصحيح مسلم (4/ 1997) (2583).\nشرح رياض الصالحين، لابن عثيمين (2/ 496).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 303).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 231).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص165).\nمرقاة المفاتيح، علي القاري (8/ 3200).","benefits":["على العاقل المبادرة إلى التوبة، وأن لا يَأمَنْ من مَكْرِ الله إذا كان مُقيمًا على الظلم.","إمهال الله عز وجل للظالمين وعدم مُعاجَلتِهم بالعقوبة استدراجًا لهم ومضاعفة للعذاب إن لم يتوبوا.","الظلم من أسباب عقوبة الله للأمم.","إذا أهلك الله قرية فقد يكون فيها صالحون، فهؤلاء يُبعثون يوم القيامة على ما ماتوا عليه من الصلاح، ولا يضرهم أنْ شَمِلَتْهم العقوبةُ."],"wordsMeanings":[],"category":"aqidah","tags":["الله","ليملي","للظالم،","حتى","إذا","أخذه"],"source":"hadeethenc"},{"id":"he_5934","text":"عن أبي الهيَّاج الأسدي قال: قَالَ لِي ‌عَلِيُّ بْنُ أَبِي طَالِبٍ: أَلَا أَبْعَثُكَ عَلَى مَا بَعَثَنِي عَلَيْهِ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ؟ أَنْ لَا تَدَعَ تِمْثَالًا إِلَّا طَمَسْتَهُ، وَلَا قَبْرًا مُشْرِفًا إِلَّا سَوَّيْتَهُ.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبيُّ صلى عليه وسلم يُرسِلُ أصحابَه بألَّا يَتركوا «تمثالًا» -وهو صورة ما كان ذا روح مُجَسَّمة أو غير مجسمة- إلا أزالوه أو محوه.\n\nوألَّا يتركوا قبرًا مُرتفعًا إلا سَوَّوه بالأرض، وهَدَموا ما عليه من البناء، أو جَعَلوه مُسَطَّحًا لا يُرفَعُ عن الأرض رَفعًا كثيرًا، بل يُرفَع نحو شِبْر.","reference":"صحيح مسلم (2/ 666) (969).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (2/ 446).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص402).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص447).\nكتاب التوحيد، للإمام محمد بن عبد الوهاب (ص138).","benefits":["تحريم التصوير لذوات الأرواح؛ لأنها من وسائل الشرك.","مشروعية إزالة المنكر باليد لمن له سلطة أو قدرة على ذلك.","حرص النبي صلى الله عليه على إزالة كل ما يدل على آثار الجاهلية، من التصاوير والتماثيل والأبنية على القبور."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["ألا","أبعثك","على","بعثني","عليه","رسول"],"source":"hadeethenc"},{"id":"he_5981","text":"عن عمران بن حصين رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «‌لَيْسَ ‌مِنَّا ‌مَنْ ‌تَطَيَّرَ أَوْ تُطُيِّرَ لَهُ، أَوْ تَكَهَّنَ أَوْ تُكُهِّنَ لَهُ، أَوْ سَحَرَ أَوْ سُحِرَ لَهُ، وَمَنْ عَقَدَ عُقْدَةً، وَمَنْ أَتَى كَاهِنًا فَصَدَّقَهُ بِمَا يَقُولُ فَقَدْ كَفَرَ بِمَا أُنْزِلَ عَلَى مُحَمَّدٍ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ».","attribution":"رواه البزار","grade":"حسن","gradeKey":"hasan","explanation":"تَوَعَّدَ النبيُّ صلى الله عليه وسلم مَن فَعَلَ مِن أمته بعضَ الأفعال بقوله: \"ليس منّا\" ومنها: \n\nالأول: \"من تَطَيَّرَ أو تُطُيِّرَ له\" وأصله: إطلاق الطير عند الشروع في عَمَلٍ مِن سَفَر أو تجارة أو غير ذلك، فإنْ طَارَ جِهةَ اليمين تَفاءَلَ ومَضى لِمَا يريد، وإنْ طار جهة الشمال تشاءم وكَفَّ عما يريد، فلا يجوز فِعْلُ هذا بِنفسِهِ أو تَكليف مَن يَفعله له، ويدخل في ذلك التشاؤم مِن أي شيء، مسموعًا كان أو مرئيًّا، من الطيور أو الحيوانات أو أصحاب العاهات أو الأرقام أو الأيام أو غير ذلك. \n\nوالثاني: \"من تَكَهَّنَ أو تُكُهِّنَ له\" فمَن ادَّعى عِلْمَ الغيب باستخدام النجوم وغيرها، أو جاء إلى مَن يَدَّعي علمَ الغيب كالكاهن ونحوه، فَصَدَّقه بما يقول بادعائه علم الغيب، فقد كَفَرَ بما أُنزل على محمد صلى الله عليه وسلم. \n\nوالثالث: \"من سحر أو سحر له\" وهو مَن عَمِلَ السحر بنفسه، أو كَلَّف مَن يَعمل له سحرًا؛ لينفع به أحدًا أو يضرَّه، أو عَقَدَ عُقدةً بربط الخيط والسحر عليه بقراءة التعويذات المحرمة عليه والنفث فيه.","reference":"مسند البزار = البحر الزخار (9/ 52) (3578).\nشرح السنة للبغوي (12/ 182).\nمجموع الفتاوى (35/ 173).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (1/ 543).\nالتمهيد لشرح كتاب التوحيد، لصالح آل الشيخ (ص315).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص242).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص217).","benefits":["وجوب التوكل على الله والإيمان بقضاء الله وقدره، وتحريم الطيرة والتشاؤم والسحر والكهانة، أو سؤال أصحابها ذلك.","ادعاء علم الغيب من الشرك الذي ينافي التوحيد.","تحريم تصديق الكهان والذهاب إليهم، ويلحق بذلك قراءة ما يُسمى بالكَفِّ والفِنْجَان والبروج والنظر فيها ولو على سبيل الاطلاع."],"wordsMeanings":[],"category":"aqidah","tags":["ليس","منا","تطير","تطير","له،","تكهن"],"source":"hadeethenc"},{"id":"he_5986","text":"عن بعض أزواج النبي صلى الله عليه وسلم عن النبي صلى الله عليه وسلم قال: «مَنْ أَتَى عَرَّافًا فَسَأَلَهُ عَنْ شَيْءٍ لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ لَيْلَةً».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُحَذِّرُ النبيُّ صلى الله عليه وسلم من إتيان العرّاف -هو اسم عام للكاهن والمُنِّجم والرَّمَّال ونحوهم، ممن يَسْتَدِلُّ على معرفة الغيب بمقدمات يستعملها -، وأنَّ مُجَرَّدَ سؤالِهِ عن شيء من أمور الغيب سيَحْرِمُه الله به ثوابَ صلاته أربعين يومًا؛ وذلك عقوبة له على هذا الإثم والذنب الكبير.","reference":"صحيح مسلم (4/ 1751) (2230).\nمسند أحمد (27/ 197) (16638).\nالجديد في شرح كتاب التوحيد، للقرعاوي (ص238).\nالملخص في شرح كتاب التوحيد، للفوزان (ص213).","benefits":["تحريم الكَهَانة، والذهاب إلى الكُهان وسؤالهم عن المغيبات.","قد يُحْرَمُ الإنسانُ مِن ثواب الطاعة عقوبة له على فعل المعصية.","يَدْخُلُ في الحديث ما يُسمّى بالأبراج والنظر فيها، وقراءة الكَفِّ والفنجان -ولو على سبيل الاطلاع فقط-؛ لأن ذلك كلَّه من الكهانة ومن دعوى علم الغيب.","إذا كان هذا جزاءَ مَن أتى العَرّاف، فكيف بجزاء العراف نفسه؟","صلاة أربعين يومًا تَقَعُ مُجزئة لا يَجِبُ قضاؤها، ولكن لا ثواب فيها."],"wordsMeanings":[],"category":"aqidah","bookId":"muslim","tags":["أتى","عرافا","فسأله","شيء","تقبل","صلاة"],"source":"hadeethenc"},{"id":"he_5989","text":"عن ابن عباس رضي الله عنهما قال: قال رسول الله صلى الله عليه وسلم: «من اقتبَسَ علْمًا مِنَ النُّجُومِ اقْتبَسَ شُعبَة مِن السِّحرِ، زادَ ما زادَ».","attribution":"رواه أبو داود وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ مَن تَعَلَّم وأَخَذَ من علم النجوم والأبراج والاستدلال بحركاتها ودخولها وخروجها على الحوادث الأرضية من موت فلان أو حياته أو مرضه، ونحو ذلك مما سيقع في المستقبل، فقد تَعَلَّمَ جزءًا من السحر، وأنه كلَّما أكثر الإنسان هذا العلم فقد أكثر من السحر.","reference":"سنن أبي داود (6/ 50) (3905).\nسنن ابن ماجه (4/ 670) (3726).\nمسند أحمد (3/ 454) (2000).\nالجديد في شرح كتاب التوحيد، للقرعاوي (ص230).\nالملخص في شرح كتاب التوحيد، للفوزان (ص206).","benefits":["تحريم التنجيم الذي هو الإخبار عن المستقبل اعتمادًا على أحوال النجوم؛ لأنه من ادعاء علم الغيب.","أن التنجيم المُحَرَّم من أنواع السحر المنافي للتوحيد، بخلاف النظر في النجوم لمعرفة الاتجاهات أو القِبْلة أو دخول المواسم والشهور فهو مباح.","كلما زاد في تَعَلُّمِه للتنجيم فهو يزيد من تَعَلُّمِ شُعَبِ السحر.","للنجوم ثلاث فوائد ذكرها الله في كتابه: زينة للسماء، وعلامات يهتدى بها، ورجوم للشياطين."],"wordsMeanings":[{"word":"من اقتبسَ","meaning":" من تعلّم."},{"word":"شعبة","meaning":" طائفة وقطعة."}],"category":"aqidah","bookId":"abudawud","tags":["اقتبس","علما","النجوم","اقتبس","شعبة","السحر،"],"source":"hadeethenc"},{"id":"he_6049","text":"عن عبد الله بن مسعود رضي الله عنه عن النبي صلى الله عليه وسلم أنه قال: \"أكبر الكبائر: الإشراك بالله، والأمن من مَكْرِ الله، والقُنُوطُ من رحمة الله، واليَأْسُ من رَوْحِ الله\".","attribution":"رواه عبد الرزاق","grade":"إسناده صحيح","gradeKey":"sahih","explanation":"ذكر رسول الله -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ- في هذا الحديث ذنوبًا تعتبر من كبائر الذنوب، وهي: أن يُجعل لله سبحانه شريكٌ في ربوبيته أوعبوديته وبدأ به؛ لأنه أعظم الذنوب، وقطع الرجاء والأمل من الله؛ لأن ذلك إساءة ظنٍّ بالله وجهل بسعة رحمته، والأمن من استدراجه للعبد بالنعم حتى يأخذه على غفلة، وليس المراد بهذا الحديث حصر الكبائر فيما ذكر؛ لأن الكبائر كثيرة، لكن المراد بيان أكبرها.","reference":"كتاب التوحيد، محمد بن عبد الوهاب، تحقيق: دغش العجمي، مكتبة أهل الأثر، الطبعة: الخامسة 1435هـ.\nالجديد في شرح كتاب التوحيد، محمد بن عبد العزيز السليمان القرعاوي، تحقيق: محمد بن أحمد سيد، مكتبة السوادي، الطبعة: الخامسة 1424هـ، 2003م.\nالملخص في شرح كتاب التوحيد، صالح بن فوزان بن عبد الله الفوزان، دار العاصمة، الرياض، الطبعة: الأولى 1422هـ، 2001م.\nجامع معمر بن راشد، معمر بن أبي عمرو راشد الأزدي، نزيل ا","benefits":["انقسام الذنوب إلى كبائر وصغائر.","أن الشرك أعظم الذنوب وأكبر الكبائر.","تحريم الأمن من مكر الله -سبحانه- واليأس من رحمته، وأنهما من أكبر الكبائر.","جواز وصف الله -تعالى- بالمكر في مقابلة الماكرين، وهذه صفة كمال، والمذموم هو المكر بمن لا يستحق أن يُمكر به.","أن الواجب على العبد أن يكون بين الخوف والرجاء، فإذا خاف لا ييأس، وإذا رجا لا يأمن.","إثبات صفة الرحمة لله -تعالى- على وجه يليق بجلاله.","وجوب إحسان الظن بالله -عز وجل-."],"wordsMeanings":[{"word":"الكبائر","meaning":" جمع كبيرة، وهي: كل ذنب توعّد الله صاحبه بنارٍ أو لعنةٍ أو غضبٍ أو عذابٍ أو نفي الإيمان أو رتب الله عليه حداً في الدنيا."},{"word":"واليأس من روح الله","meaning":" أي قطع الرجاء والأمل من الله، فيما يقصد الإنسان ويخافه ويرجوه."},{"word":"الأمن من مكر الله","meaning":" أي: من استدراجه للعبد، أو سلبه ما أعطاه من الإيمان."},{"word":"الشرك بالله","meaning":" عبادة غير الله معه، أو صرف شيء من أنواع العبادة لغير الله -تعالى-."}],"category":"aqidah","tags":["أكبر","الكبائر:","الإشراك","بالله،","والأمن","مكر"],"source":"hadeethenc"},{"id":"he_6468","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «الْإِيمَانُ بِضْعٌ وَسَبْعُونَ -أَوْ بِضْعٌ وَسِتُّونَ- شُعْبَةً، فَأَفْضَلُهَا قَوْلُ لَا إِلَهَ إِلَّا اللهُ، وَأَدْنَاهَا إِمَاطَةُ الْأَذَى عَنِ الطَّرِيقِ، وَالْحَيَاءُ شُعْبَةٌ مِنَ الْإِيمَانِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم أنَّ الإيمانَ شُعَبٌ وخِصَالٌ كثيرة، تشتمل على أعمالٍ واعتقاداتٍ وأقوالٍ.\n\nوأنَّ أعلى خِصال الإيمان وأفضلَها قول: «لا إله إلا الله»، عالمًا بمعناها، عاملًا بمقتضاها، مِن أنّ الله هو الإله الواحد الأحد المستحق للعبادة وحده دون ما سواه.\n\nوأن أقلَّ أعمال الإيمان هو تَنْحِيَةُ كلِّ ما يؤذي الناسَ في طرقاتِهم.\n\nثم أخبر صلى الله عليه وسلم أنَّ الحياءَ مِن خِصال الإيمان، وهو خُلُقٌ يبعث على فعل الجميل وترك القبيح.","reference":"صحيح البخاري (1/ 11) (9).\nصحيح مسلم (1/ 63) (35).\nنزهة المتقين شرح رياض الصالحين (1/ 154).\nشرح رياض الصالحين، لابن عثيمين (2/ 169).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص106).\nبهجة الناظرين شرح رياض الصالحين، لسليم لهلالي (1/ 205).","benefits":["الإيمان مراتب بعضها أفضل من بعض.","الإيمان قول وعمل واعتقاد.","الحياء من الله تعالى يقتضي: ألّا يراكَ حيث نهاك، وألّا يَفْقِدَكَ حيث أمرك.","ذِكْرُ العدد لا يعني الاقتصار عليه، بل يدلُّ على كثرة أعمال الإيمان، فإن العرب قد تذكر للشيء عددًا ولا تريد نفي ما سواه."],"wordsMeanings":[{"word":"بِضْع","meaning":" من ثلاثة إلى تسعة."},{"word":"شعبة","meaning":" خصلة."}],"category":"aqidah","tags":["الإيمان","بضع","وسبعون","بضع","وستون","شعبة،"],"source":"hadeethenc"},{"id":"he_6761","text":"عن أبي بَشير الأنصاري رضي الله عنه: أَنَّهُ كَانَ مَعَ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ، قَالَ: فَأَرْسَلَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ رَسُولًا -وَالنَّاسُ فِي مَبِيتِهِمْ-: «لَا يَبْقَيَنَّ فِي رَقَبَةِ بَعِيرٍ قِلَادَةٌ مِنْ وَتَرٍ أَوْ قِلَادَةٌ إِلَّا قُطِعَتْ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبيُّ صلى الله عليه وسلم في بعض أسفاره، والناسُ في مكان نومِهم الذي يَبِيْتُون فيه في رِحالِهم وخيامِهم، فأَرْسَلَ شخصًا إلى الناس يأمرهم بِقَطْع القَلَائد التي تُعَلَّق على البعير سواء كانت من الوَتَر -وَتَر القَوْس- أو من غيره كالجَرَس أو النعل، وذلك لأنهم كانوا يُقَلِّدونها حذرًا من العين، فأُمِرُوا بقطعها؛ لأنها لا تَرُدُّ عنهم شيئًا، وأنَّ النفعَ والضرَّ بيد الله وحده لا شريك له.","reference":"صحيح البخاري (4/ 59) (3005).\nصحيح مسلم (3/ 1672) (2115).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (1/ 179).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص77).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص89).","benefits":["تحريم تعليق الأوتار والقلائد لجلب النفع أو دفع الضر؛ لأن ذلك من الشرك.","ربط القلادة من غير الوتر إذا كان للزينة أو لقيادة الدابة أو لربطها به فلا بأس به.","وجوب إنكار المنكر بحسب الاستطاعة.","وجوب تعلق القلب بالله وحده لا شريك له."],"wordsMeanings":[{"word":"وتر","meaning":" مفرد أوتار، وهو ما يشد به القوس كانت العرب تعلقه تتقي به العين."},{"word":"قلادة","meaning":" ما يعلق في رقبة البعير وغيره، كالجرس والنعل، بنية دفع العين."}],"category":"aqidah","tags":["يبقين","رقبة","بعير","قلادة","وتر","قلادة"],"source":"hadeethenc"},{"id":"he_6763","text":"عن عبد الله بن عكيم رضي الله عنه مرفوعاً: «مَنْ تَعَلَّقَ شيئا وُكِلَ إليه».","attribution":"رواه أحمد والترمذي","grade":"حسن","gradeKey":"hasan","explanation":"من التفت بقلبه أو فعله أو بهما جميعا إلى شيء يرجو منه النفع أو دفع الضر وكله الله إلى ذلك الشيء الذي تعلَّقه، فمن تعلَّق بالله كفاه ويسَّر له كل عسير، ومن تعلق بغيره وكله الله إلى ذلك الشيء وخذله.","reference":"الملخص في شرح كتاب التوحيد، دار العاصمة الرياض، الطبعة: الأولى 1422هـ- 2001م.\nالجديد في شرح كتاب التوحيد، مكتبة السوادي، جدة، المملكة العربية السعودية، الطبعة: الخامسة، 1424هـ - 2003م.\nمسند الإمام أحمد بن حنبل، تحقيق: شعيب الأرنؤوط - عادل مرشد، وآخرون، نشر: مؤسسة الرسالة، الطبعة: الأولى، 1421هـ - 2001م.\nسنن الترمذي، نشر: شركة مكتبة ومطبعة مصطفى البابي الحلبي – مصر، الطبعة: الثانية، 1395هـ - 1975م.","benefits":["النهي عن التعلق بغير الله -تعالى-.","وجوب التعلق بالله في جميع الأمور.","بيان مضرة الشرك وسوء عاقبته.","أن الجزاء من جنس العمل.","أن نتيجة العمل ترجع إلى العامل خيرا أو شرا.","خذلان من انصرف عن الله وطلب النفع من غيره."],"wordsMeanings":[{"word":"من تعلق شيئا","meaning":" أي التفت قلبُه إلى شيءٍ يعتقد أنه ينفعه أو يدفع عنه."},{"word":"وُكِل إليه","meaning":" أي وكله الله إلى ذلك الشيء الذي تعلَّقَه من دونه وخذله."}],"category":"aqidah","bookId":"tirmidhi","tags":["تعلق","شيئا","وُكل","إليه"],"source":"hadeethenc"},{"id":"he_66510","text":"عَنْ أَبِي ثَعْلَبَةَ الخُشَنِيِّ جُرْثُومِ بن نَاشِرٍ رَضِيَ اللَّهُ عَنْهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَال: «إِنَّ اللَّهَ فَرَضَ فَرَائِضَ فَلَا تُضَيِّعُوهَا، وَحَدَّ حُدُودًا فَلَا تَعْتَدُوهَا، وَحَرَّمَ أَشْيَاءَ فَلَا تَنْتَهِكُوهَا، وَسَكَتَ عَنْ أَشْيَاءَ رَحْمَةً لَكُمْ غَيْرَ نِسْيَانٍ فَلَا تَبْحَثُوا عَنْهَا».","attribution":"رواه الدارقطني في سننه، وغيره","grade":"قال النووي: حديث حسن","gradeKey":"hasan","explanation":"يخبر النبي صلى الله عليه وسلم أن الله أوجب أشياء وفرض فرائض فالتزموها ولا تفرطوا فيها بالترك أو التهاون فيها، وجعل لكم حواجز وزواجر مقدرةً تحجزكم وتزجركم عما لا يرضاه، فلا تزيدوا عليها عمَّا أمر به الشرع، وحرم محرمات فلا تتناولوها ولا تقربوها، وما عدا ذلك تركها وسكت عنها رحمة بعباده، فتبقى على أصل إباحتها فلا تبحثوا عنها.","reference":"سنن الدارقطني (4396).\nالمعجم الكبير للطبراني (22/221).\nجامع العلوم والحكم (ص617).\nشرح الأربعين النووية للعثيمين (ص309).\nتوضيح الأحكام من بلوغ المرام (6/ 210).","benefits":["الحديث دليل على أن الله هو المشرع فالأمر بيده سبحانه.","تضمن الحديث قواعد الشرع حكمًا وإباحةً؛ إذ الحكم الشرعي إمَّا مسكوتٌ عنه أو متكلَّم به، وهو إما: مأمورٌ به وجوبًا أو ندبًا، أو منهيٌّ عنه تحريمًا أو كراهةً، أو مباحٌ.","أن ما سكت الله عنه فلم يفرضه، ولم يحده، ولم ينه عنه فهو الحلال.","حسن بيان النبي صلى الله عليه وسلم حيث ساق الحديث بهذا التقسيم الواضح البين .","وجوب المحافظة على فرائض الله تعالى.","تحريم التعدي على حدود الله تعالى."],"wordsMeanings":[],"category":"fiqh","tags":["الله","فرض","فرائض","فلا","تضيعوها،","وحد"],"source":"hadeethenc"},{"id":"he_66519","text":"عَنْ أَبِي مُـحَمَّدٍ الحَسَنِ بْنِ عَلِيِّ بْنِ أَبِي طَالِبٍ - سِبْطِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَيْحَانَتِهِ-، قَالَ: حَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: «دَعْ مَا يَرِيبُك إلَى مَا لَا يَرِيبُكَ».","attribution":"رواه الترمذي والنسائي","grade":"صحيح","gradeKey":"sahih","explanation":"أَمَرَ النبيُّ صلى الله عليه وسلم بِتَرْك ما تَشُكُّ فيه مِن الأقوال والأعمال أنه مَنهيٌّ عنه أو لا، أهو حرام أو حلال، إلى ما لا شَكَّ فيه مما تَيَقَّنت حُسْنَه وحِلَّه.","reference":"سنن النسائي (8/ 327) (5711).\nسنن الترمذي (4/ 286) (2518).\nمسند أحمد (3/ 248) (1723).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، لإسماعيل الأنصاري (ص29).\nشرح الأربعين النووية، لابن عثيمين (ص153).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين للنووي وابن رجب (ص56).","benefits":["على المسلم بناء أموره على اليقين وترك المشكوك فيه، وأن يكون في دينه على بصيرة.","النهي عن الوقوع في الشبهات.","إذا أردتَ الطمأنينةَ والاستراحة فاترك المشكوك فيه واطرحه جانبًا.","رحمة الله بعباده إذ أمرَهم بما فيه راحة النفس والبال ونهاهم عمّا فيه قَلَقٌ وحَيْرة."],"wordsMeanings":[],"category":"fiqh","bookId":"tirmidhi","tags":["يريبك","إلى","يريبك"],"source":"hadeethenc"},{"id":"he_66521","text":"عَنْ أَبِي يَعْلَى شَدَّادِ بْنِ أَوْسٍ رَضِيَ اللَّهُ عَنْهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّ اللهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ، فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا القِتْلَةَ، وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذِّبْحَةَ، وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ، وَلْيُرِحْ ذَبِيحَتَهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم أن الله تعالى أوجبَ علينا الإحسانَ في كل الأشياء، والإحسان: هو مراقبة الله على الدوام، في عبادته وفي بذل الخير وكف الأذى عن المخلوقين، ومن ذلك الإحسان في القتل والذبح.\nفالإحسان في القتل عند القصاص: بأن يختار أسهلَ الطُّرُق وأخَفَّها وأسرعَها زهوقًا للمقتول.\nوالإحسان في الذبح عند الذكاة: بأن يرفق بالبهيمة بإحداد الآلة، وألّا تُحَدَّ أمام الذبيحة وهي تنظر إليها، وألَّا تُذبح وهناك من الماشية ما ينظر إليها.","reference":"صحيح مسلم (3/ 1548) (1955).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص38).\nشرح الأربعين النووية، لابن عثيمين (ص185).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص65).\nفتح الباري، لابن حجر (9/ 644).\nشرح النووي على مسلم (13/ 107).","benefits":["رحمة الله عزّ وجل ولطفه بالخلق.","إحسان القتل والذبح بأن يكون على الوجه المشروع.","كمال الشريعة واشتمالها على كل خير، ومن ذلك رحمة الحيوان والرفق به.","النهي عن المُثْلة بالإنسان بعد قتله.","تحريم كل ما فيه تعذيب للحيوان."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["الله","كتب","الإحسان","على","شيء"],"source":"hadeethenc"},{"id":"he_66526","text":"عَنْ أَبِي مَالِكٍ الحَارِثِ بْنِ عَاصِمٍ الأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ: «الطُّهُورُ شَطْرُ الْإِيمَانِ، وَالْحَمْدُ لِلهِ تَمْلَأُ الْمِيزَانَ، وَسُبْحَانَ اللهِ وَالْحَمْدُ لِلهِ تَمْلَآنِ -أَوْ تَمْلَأُ- مَا بَيْنَ السَّمَاءِ وَالأَرْضِ، وَالصَّلَاةُ نُورٌ، وَالصَّدَقَةُ بُرْهَانٌ، وَالصَّبْرُ ضِيَاءٌ، وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ، كُلُّ النَّاسِ يَغْدُو، فَبَايِعٌ نَفْسَهُ فَمُعْتِقُهَا أَوْ مُوبِقُهَا»","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر النبي صلى الله عليه وسلم: أن طهارة الظاهر تكون بالوضوء والغسل وهي شرط في الصلاة. وأن قول: \" الحمد لله تملا الميزان\" وهو الثناء عليه سبحانه، ووصفه بصفات الكمال توزن يوم القيامة فتملأ ميزان الأعمال. وأن قول: \"سبحان الله والحمد لله\" وهو تنزيهه عن كل نَقْصٍ ووصفه بالكمال التام الذي يليق بجلاله مع محبته وتعظيمه تملأ ما بين السموات والأرض. وأن \"الصلاة نور\" للعبد في قلبه، وفي وجهه، وفي قبره، وفي حشره. وأن \"الصدقة برهان\" ودليل على صدق إيمان المؤمن، واختلافه عن المنافق الذي يمتنع منها لكونه لا يصدق بموعودها. وأن \"الصبر ضياء\" -وهو حبس النفس عن الجَزَع والتَّسَخُّط - نور يحصل معه حرارة وإحراق، كضياء الشمس؛ لأنه شاق ويحتاج إلى مجاهدة النفس وحبسها عما تهواه؛ فلا يزال صاحبه مستضيئًا مهتديًا مستمرًّا على الصواب. وهو صبر على طاعة الله، وعن معصيته، وصبر على المصائب وأنواع المكاره في الدنيا. وأن \"القرآن حجة لك\" بتلاوته والعمل به، أو \"حجة عليك\" بتركه دون عمل أو تلاوة. ثم أخبر صلى الله عليه وسلم أن كل الناس يسعون وينتشرون ويقومون من نومهم ويخرجون من بيوتهم لأعمالهم المختلفة، فمنهم من يستقيم على طاعة الله فيُعْتِق نفسَه من النار، ومنهم من ينحرف عن ذلك ويقع في المعاصي فيهلكها بدخولها النار.","reference":"صحيح مسلم (1/ 203) (223).\nشرح الأربعين لابن دقيق العيد (ص 84).\nشرح الأربعين النووية للعثيمين (ص: 231).\nالرياض الزكية شرح الأربعين النووية للخضير (ص 293).\nفتح القوي المتين في شرح الأربعين للعباد (ص 79).","benefits":["الطهارة طهارتان: طهارة الظاهر تكون بالوضوء والغسل، وطهارة الباطن تكون بالتوحيد والإيمان والعمل الصالح.","أهمية المحافظة على الصلاة فهي نور للعبد في الدنيا ويوم القيامة.","الصدقة دليل على صدق الإيمان.","أهمية العمل بالقرآن وتصديقه ليكون حجة لك لا عليك.","النفس إن لم تشغلها بالطاعة شغلتك بالمعصية.","كل إنسان لا بد أن يعمل؛ فإما أن يعتق نفسه بالطاعة، أو يوبقها بالمعصية.","الصبر يحتاج إلى تَحَمُّلٍ واحتسابٍ وفيه مشقة."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["الطهور","شطر","الإيمان،","والحمد","لله","تملأ"],"source":"hadeethenc"},{"id":"he_66531","text":"عَنْ أَبِي سَعِيدٍ سَعْدِ بْنِ مَالِكِ بْنِ سِنَانٍ الخُدْرِيّ رَضِيَ اللَّهُ عَنْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «لَا ضَرَرَ وَلَا ضِرَارَ».","attribution":"رواه ابن ماجه، والدارقطني، وغيرهما مسندًا","grade":"حسن","gradeKey":"hasan","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنه يَجِبُ دفعُ الضررِ بمختلف أنواعه ومظاهره عن النفس وعن الآخرين، فلا يَحِلُّ لأحدٍ أن يُؤذيَ نفسَه أو غيرَه على حد سواء.\nولا يَحلُّ له أن يقابِلَ الضررَ بالضرر؛ لأن الضررَ لا يُزال بالضرر إلا على سبيل القصاص دون تعدٍّ.","reference":"سنن الدارقطني (4/ 51) (3079).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص74).\nشرح الأربعين النووية، لابن عثيمين (ص325).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص112).","benefits":["النهي عن المجازاة بأكثر من المِثْل.","لم يأمر اللهُ عبادَه بشيء يضرُّهم.","الحديث قاعدة في تحريم الضرر، والضرار بالقول أو بالفعل أو بالترك.","من قواعد الشريعة: أن \"الضرر يُزال\"، فالشريعة لا تُقِرُّ الضرر، وتنكر الإضرار."],"wordsMeanings":[],"category":"fiqh","bookId":"ibnmajah","tags":["ضرر","ولا","ضرار"],"source":"hadeethenc"},{"id":"he_66532","text":"عَن ابنِ عباسٍ رضي الله عنهما أنَّ رسولَ اللهِ صلي الله عليه وسلم قال: «لَو يُعطَى النّاسُ بدَعواهُم لادَّعَى رِجالٌ أموالَ قَومٍ ودِماءَهُم، لَكِنَّ البَيِّنَةَ على المُدَّعِى، واليَمينَ على مَن أنكَرَ».","attribution":"رواه البيهقي، وغيره هكذا، وبعضه في الصحيحين","grade":"حسن","gradeKey":"hasan","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنه لو يُعطى الناس بمُجَرَّدِ دَعواهم مِن غير أدلّة ولا قرائن لادَّعى أُناسٌ أموالَ قومٍ ودماءَهم، ولكن يجب على المُدَّعِي تقديمُ البينةِ والدليلِ بما يُطالِب، فإن لم يكن له بينة فتُعرَضُ الدعوى على المُدَّعَى عليه، فإن أنكرها فعليه الحَلِفُ ويَبْرَأ.","reference":"السنن الكبرى للبيهقي تحقيق التركي (21/ 242 - 243) (21243).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص76).\nشرح الأربعين النووية، لابن عثيمين (ص328).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، لعبد المحسن البدر (ص114).","benefits":["قال ابن دقيق العيد: وهذا الحديث أصل من أصول الأحكام، وأعظم مرجع عند التنازع والخصام.","الشريعة جاءت لحماية أموال الناس ودمائهم عن التلاعب.","القاضي لا يَحكم بعلمه وإنما يَرجع إلى البينات.","كل من ادّعى دعوى خالية عن برهان فهي مردودة، وسواء كانت في الحقوق والمعاملات أو في مسائل الإيمان والعلم."],"wordsMeanings":[],"category":"fiqh","tags":["يعطى","الناس","بدعواهم","لادعى","رجال","أموال"],"source":"hadeethenc"},{"id":"he_66536","text":"عَنْ أَبِي بُرْدَةَ، عَنْ أَبِيهِ أَبِي مُوسَى الأَشْعَريِّ رَضِيَ اللَّهُ عَنْهُ: أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَهُ إِلَى اليَمَنِ، فَسَأَلَهُ عَنْ أَشْرِبَةٍ تُصْنَعُ بِهَا، فَقَالَ: وَمَا هِيَ؟، قَالَ: «البِتْعُ وَالمِزْرُ»، فَقِيلَ لِأَبِي بُرْدَةَ: مَا البِتْعُ؟ قَالَ: نَبِيذُ العَسَلِ، وَالمِزْرُ: نَبِيذُ الشَّعِيرِ، فَقَالَ: «كُلُّ مُسْكِرٍ حَرَامٌ» خرجه البخاري.\nوَخَرَّجَهُ مُسْلِمٌ وَلَفْظُهُ: قَالَ: بَعَثَنِي رَسُولُ اَلله أَنَا وَمُعَاذٌ إِلَى اَليَمَنِ، فَقُلْتُ: يَا رَسُولُ اَللَّهِ! إِنَّ شَرَابًا يُصْنَعُ بِأَرْضِنَا يُقَال لَهُ: المِزَرُ مِنَ الشَّعِيرِ، وَشَرَابٌ يُقَالُ لَهُ: البِتْعُ مِنَ العَسَلِ، فَقَالَ: «كُلُّ مُسْكِرٍ حَرَامٌ». \nوَفِي رِوَايَةٍ لِمُسْلِمٍ: «فَقَالَ: كُلُّ مَا أَسْكَرَ عَنِ الصَّلَاةِ فَهُوَ حَرَامٌ». \nوَفِي رِوَايَةٍ لَهُ: «وَكَانَ رَسُولُ الله قَدْ أُعْطِيَ جَوَامِعَ الكَلِمِ بِخَوَاتِمِهِ، فَقَالَ: أَنْهَى عَنْ كُلِّ مُسْكِرٍ أَسْكَرَ عَنْ الصَّلَاةِ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر أبو موسى الأشعري رضي الله عنه أن النبي صلى الله عليه وسلم أرسله إلى اليمن، فسأله عن أشربة تصنع بها هل هي حرام، فاستفسر النبي صلى الله عليه وسلم عنها. \nفقال أبو موسى رضي الله عنه: هي البتع: نبيذ العسل، والمزر: نبيذ الشعير. \nفقال النبي صلى الله عليه وسلم وكان قد أوتي جوامع الكلم: «كل مسكر حرام».","reference":"صحيح البخاري (7/ 104) (5575).\nصحيح مسلم (3/ 1587) (2003).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (8/ 519).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (5/ 418).\nتوضِيحُ الأحكَامِ مِن بُلوُغ المَرَام، للبسام (6/ 307).\nمعالم السنن، وهو شرح سنن أبي داود، للخطابي (4/ 264).\nالفتح الرباني لترتيب مسند الإمام أحمد بن حنبل الشيباني، للساعاتي (16/ 116).\nفيض القدير شرح الجامع الصغير، للمن","benefits":["النبيذ: هو الماء الذي يلقى فيه التمر أو العسل أو الشعير ونحوها؛ فيكتسب منها طعمًا ومذاقًا حلوًا، وقد يتخمر بعد ذلك ويصبح مسكرًا.","الحديث قاعدة في تحريم جميع أنواع المسكرات كالخمر والحشيشة وغيرها.","أهمية السؤال عن ما يحتاج إليه المسلم.","كان أول ما حرمت الخمر عند حضور وقت الصلاة لما صلى بعض المهاجرين وقرأ في صلاته فخلط في قراءته؛ فنزل قوله تعالى: {يَا أَيُّهَا الَّذِينَ آمَنُوا لَا تَقْرَبُوا الصَّلَاةَ وَأَنْتُمْ سُكَارَى حَتَّى تَعْلَمُوا مَا تَقُولُونَ} [النساء: 43].  وكان منادي رسول الله صلى الله عليه وسلم ينادي: لا يقرب الصلاةَ سكران. ثم إن الله حرمها على الإطلاق بقوله: {يَا أَيُّهَا الَّذِينَ آمَنُوا إِنَّمَا الْخَمْرُ وَالْمَيْسِرُ وَالْأَنْصَابُ وَالْأَزْلَامُ رِجْسٌ مِنْ عَمَلِ الشَّيْطَانِ فَاجْتَنِبُوهُ لَعَلَّكُمْ تُفْلِحُونَ 90 إِنَّمَا يُرِيدُ الشَّيْطَانُ أَنْ يُوقِعَ بَيْنَكُمُ الْعَدَاوَةَ وَالْبَغْضَاءَ فِي الْخَمْرِ وَالْمَيْسِرِ وَيَصُدَّكُمْ عَنْ ذِكْرِ اللَّهِ وَعَنِ الصَّلَاةِ فَهَلْ أَنْتُمْ مُنْتَهُونَ} [المائدة: 90، 91].","أن الله تعالى حرَّم الخمر لما تشتمل عليه من الأضرار والمفاسد العظيمة.","العبرة في التحريم وجود صفة الإسكار؛ فإذا اتصف النبيذ بالإسكار فهو محرم، وإذا لم يتصف بالإسكار فهو مباح."],"wordsMeanings":[],"category":"fiqh","bookId":"bukhari","tags":["مسكر","حرام"],"source":"hadeethenc"},{"id":"he_2758","text":"عن أبي هريرة رضي الله عنه قال: سمعت النبي صلى الله عليه وسلم يقول: «مَنْ حَجَّ لِلهِ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَيَوْمِ وَلَدَتْهُ أُمُّهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّن النبي صلى الله عليه وسلم أنَّ مَنْ حَجَّ لله تعالى ولم يرفث، والرَّفَث الجماع ومقدماته من التقبيل والمباشرة، ويطلق أيضًا على القول الفاحش، ولم يفسق، بفعل المعاصي والسيئات، \nومن الفسوق فعل محظورات الإحرام، رَجع من حَجِّهِ مغفورًا له، كما يولد الصّبِي سالمًا من الذنوب.","reference":"صحيح البخاري (2/ 133) (1521).\nصحيح مسلم (2/ 983) (1350).\nرياض الصالحين من كلام سيد المرسلين (ص358) (1274).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 401).\nكنوز رياض الصالحين، لمجموعة من الباحثين (15/ 378).\nشرح رياض الصالحين، للشيخ محمد بن صالح العثيمين (5/ 321).\nشرح النووي على مسلم (9/ 119).\nإكمال المعلم بفوائد مسلم، للقاضي عياض (4/ 462).","benefits":["الفُسُوق وإن كان ممنوعًا في جميع الأحوال، فيتأكد النهيُ عنه في الحج تعظيمًا لمناسك الحج.","الإنسان يولد بدون خطايا مُبرَّءًا من الذنوب؛ فهو لا يحمل خطيئة غيره."],"wordsMeanings":[{"word":"كيوم ولدته أمه","meaning":" أي  رجع من حجه بغير ذنوب."}],"category":"fiqh","tags":["لله","فلم","يرفث","ولم","يفسق","رجع"],"source":"hadeethenc"},{"id":"he_3088","text":"عن عَائِشَةَ رضيَ الله عنها قالت: إِنِّي سمعْتُ رسولَ الله صلى الله عليه وسلم يقول: «لَا صَلَاةَ بِحَضْرَةِ الطَّعَامِ، وَلَا هُوَ يُدَافِعُهُ الْأَخْبَثَانِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"نَهى رسولُ الله صلى الله عليه وسلم عن الصلاة بحضور الطعام الذي تَتُوْقُ نَفسُ المُصلي إليه، ويَتعلق قلبُه به.\n\n\nوكذلك نهى عن الصلاة مع مدافعة الأخبثين -وهما البول والغائط--، لانشغاله بمدافعة الأذى.","reference":"صحيح مسلم (1/ 393) (560).\nشرح النووي على مسلم (5/ 46).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص96).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 123).","benefits":["ينبغي للمصلي إبعاد كلِّ ما يَشْغَلُه في صلاته قبل الدخول فيها."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["صلاة","بحضرة","الطعام،","ولا","يدافعه","الأخبثان"],"source":"hadeethenc"},{"id":"he_3107","text":"عن أبِي هُرَيرةَ رضي الله عنه أنَّ رسول الله صلى الله عليه وسلمَ قال: «إذا قُلْتَ لِصَاحِبِكَ: أَنْصِتْ، يومَ الجمعةِ، والْإِمامُ يَخْطُبُ، فَقَدْ لَغَوْتَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ مِن الآداب الواجبة لِمَن حَضَرَ خطبةَ الجمعة: الإنصاتَ للخطيب؛ ليتدبَّر المواعظ، وأنَّ مَن تَكَلَّمَ -ولو بأقلِّ شيء- والإمام يخطب، فقال لغيره: \"اسكت\" و\"استمع\"، فقد فاته فَضْلُ صلاةِ الجمعة.","reference":"صحيح البخاري (2/ 13) (934).\nصحيح مسلم (2/ 583) (851).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص244).\nتنبيه الأفهام، للعثيمين (2/ 307).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (1/ 195).\nفتح الباري، لابن حجر (2/ 409).\nتاج العروس من جواهر القاموس، لمحمّد الحسيني الزَّبيدي (39/ 463).","benefits":["تحريم الكلام حال سماع الخطبة، ولو بالنهي عن المنكر أو ردِّ السلام وتشميت العاطس.","يُستثنى مِن هذا مَن يخاطِبُ الإمامَ أو يُخاطِبُهُ الإمامُ.","جواز الكلام بين الخطبتين عند الحاجة.","إذا ذُكِرَ النبيُّ صلى الله عليه وسلم والإمامُ يَخطب فإنك تُصلي عليه وتُسلِّم سِرًّا، وكذلك التأمين على الدعاء."],"wordsMeanings":[{"word":"أَنْصِتْ","meaning":" اسكت عن الكلام."},{"word":"لَغَوْتَ","meaning":" لغا أتى بقول ساقط، ليس فيه فائدة."}],"category":"fiqh","tags":["إذا","قلت","لصاحبك:","أنصت،","يوم","الجمعة،"],"source":"hadeethenc"},{"id":"he_3144","text":"عن أبِي هريرة رضي اللَّه عنه: سمعتُ النبِيّ صلى الله عليه وسلم يقول: «الفِطْرَةُ خمسٌ: الخِتَانُ والاستحدادُ وقصُّ الشَّارِبِ وتقليمُ الأظفارِ وَنَتْفُ الآبَاطِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم خمسَ خصالٍ من دينِ الإسلام وسنن المرسلين:\n\nأولها: الختان، وهو قطع جِلْدَةٍ زائدةٍ على الذَّكَرِ فوق الحَشَفَة، وقطعُ رأسِ جِلدةٍ في فرج الأنثى فوق مَحَلِّ الإيلاج. \n\nوثانيها: الاستحداد، وهو حَلْقُ شَعَرِ العَانَة الذي حول القُبُل. \n\nوثالثها: قص الشارب، وهو قصُّ ما نبت على شفة الرجل العليا بحيث تظهر الشفة. \n\nورابعها: قص الأظفار. \n\nوخامسها: نتف الإبط.","reference":"صحيح البخاري (7/ 160) (5891).\nصحيح مسلم (1/ 222) (257).\nعمدة الأحكام (ص44) (30).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (1/ 45).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص58).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 72).","benefits":["سُنَنُ المرسلين التي يُحِبُّها الله ويرتضيها ويأمر بها تدعو إلى الكمال والنزاهة والجمال.","مشروعية تَعَاهُدِ هذه الأشياء، وعدم الغفلة عنها.","لهذه الخصال فوائد دينية ودنيوية، منها: تحسين الهيئة، وتنظيف البدن، والاحتياط للطهارة، ومخالفة الكفار، وامتثال أمر الله.","ذُكِرَ في أحاديث أخرى زيادةُ خصالٍ للفطرةِ غيرِ هذه الخمس، مثل: إعفاء اللحية، والسواك، وغيرها."],"wordsMeanings":[],"category":"fiqh","tags":["الفطرة","خمس:","الختان","والاستحداد","وقص","الشارب"],"source":"hadeethenc"},{"id":"he_3279","text":"عن ابن عمر رضي الله عنهما عن النبي صلى الله عليه وسلم قال: «أحْفُوا الشَّوَارِبَ وأَعْفُوا اللِّحَى».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يَأْمُرُ النبيُّ صلى الله عليه وسلم بِالأخْذِ مِن الشَّارِبِ وألَّا يُتْرَكَ بل يُقَصّ منه، ويُبالَغ في ذلك.\n\nوفي المقابل يَأمر بإِعفاءِ اللحية وتركِها مَوْفُوْرة.","reference":"صحيح البخاري (7/ 160) (5892).\nصحيح مسلم (1/ 222) (259).\nرياض الصالحين (ص338) (1205).\nبهجة الناظرين شرح رياض الصالحين،  لسليم الهلالي (2/ 345).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن (2/ 853).\nشرح رياض الصالحين، لابن عثيمين (5/ 228).\nكنوز رياض الصالحين، لمجموعة من الباحثين (14/ 507).\nتطريز رياض الصالحين،  لفيصل آل مبارك (ص676).\nمنار القاري شرح مختصر صحيح البخاري، لحمزة محمد قاسم (5/ 236).","benefits":["تحريم حَلْقِ اللحية."],"wordsMeanings":[],"category":"fiqh","tags":["أحفوا","الشوارب","وأعفوا","اللحى"],"source":"hadeethenc"},{"id":"he_3313","text":"عَنْ ‌حُمْرَانَ مَوْلَى عُثْمَانَ بْنِ عَفَّانَ رضي الله عنه: أَنَّهُ رَأَى عُثْمَانَ بْنَ عَفَّانَ دَعَا بِوَضُوءٍ، فَأَفْرَغَ عَلَى يَدَيْهِ مِنْ إِنَائِهِ، فَغَسَلَهُمَا ثَلَاثَ مَرَّاتٍ، ثُمَّ أَدْخَلَ يَمِينَهُ فِي الْوَضُوءِ، ثُمَّ تَمَضْمَضَ وَاسْتَنْشَقَ وَاسْتَنْثَرَ، ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا، وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ ثَلَاثًا، ثُمَّ مَسَحَ بِرَأْسِهِ، ثُمَّ غَسَلَ كُلَّ رِجْلٍ ثَلَاثًا، ثُمَّ قَالَ: رَأَيْتُ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَتَوَضَّأُ نَحْوَ وُضُوئِي هَذَا، وَقَالَ: «مَنْ تَوَضَّأَ نَحْوَ وُضُوئِي هَذَا ثُمَّ صَلَّى رَكْعَتَيْنِ لَا يُحَدِّثُ فِيهِمَا نَفْسَهُ غَفَرَ اللهُ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"عَلَّمَ عثمانُ رضي الله عنه صفةَ وضوءِ النبيِّ صلى الله عليه وسلم بطريقة عَمَليّة؛ ليكون أبلغ إيضاحًا، فطلب ماءً في إناء، فَصَبَّ على يديه ثلاثَ مرات، وبعد ذلك أدخل يدَه اليمنى في الإناء، وأخذ بها ماءً فأدَارَه في فَمِه وأخرجه، ثم سحب الماء بِنَفَسِهِ إلى باطن أَنفِهِ، ثم أخرجه ونثره، ثم غَسَلَ وجهَه ثلاث مرات، ثم غسل يديه مع المِرْفقين ثلاثًا، ثم أَمَرَّ يده على رأسه مَبلولةً بالماء مرة واحدة، ثم غسل رجليه مع الكعبين ثلاثًا.\n\n\nفلما فرغ رضي الله عنه أخبرهم أنه رأى النبيَّ صلى الله عليه وسلم توضأ مثل هذا الوضوء، وبشَّرهم صلى الله عليه وسلم أنه مَن توضأ مثل وضوئه، وصلى ركعتين، خاشعًا مُحْضرًا قلبَه بين يدي ربه عز وجل فيهما، فإن الله يجازيه على هذا الوضوء الكامل وهذه الصلاة الخالصة بغفران ما سبق من ذنوبه.","reference":"صحيح البخاري (1/ 44) (164).\nصحيح مسلم (1/ 204) (226).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (1/ 16).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص26).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 24).","benefits":["استحباب غسل اليدين قبل إدخالهما في الإناء في ابتداء الوضوء، وإن لم يكن قائمًا من النوم، فإن كان مستيقظًا من نوم الليل فيجب غسلهما.","ينبغي للمعلم أنْ يَسلك أقرب الطرق إلى الفهم ورسوخ العلم لدى المتعلم، ومن ذلك التعليم بالفعل.","ينبغي للمصلي دفع الخواطر المتعلِّقة بأشغال الدنيا، فتمام الصلاة وكمالها في حضور القلب فيها، وإلا فالأفكار يتعذر السلامة منها، فعليه أن يجاهد نفسه ولا يسترسل في ذلك.","استحباب التيامن في الوضوء.","مشروعية الترتيب بين التمضمض والاستنشاق والاستنثار.","استحباب غسل الوجه واليدين والرجلين ثلاثًا، والواجب مرة.","مغفرة الله ما سبق من الذنوب يترتب على مجموع الأمرين: الوضوء، وصلاة ركعتين، على الصفة المذكورة في الحديث.","لكل عضو من أعضاء الوضوء حد: فحد الوجه: من منابت شعر الرأس المعتاد، إلى ما نزل من اللحية والذقن طولًا، ومن الأذن إلى الأذن عرضًا. وحد اليد: من أطراف الأصابع إلى المرفق وهو المفصل بين الساعد والعَضُد. وحد الرأس: من منابت الشعر المعتاد من جوانب الوجه إلى أعلى الرقبة، ومسح الأذنين من الرأس. وحد الرِّجْل: القدم كاملة مع المفصل بينها وبين الساق."],"wordsMeanings":[{"word":"مولى عثمان","meaning":" عتيقه، فحمران كان مملوكًا لعثمان رضي الله عنه فأعتقه عثمان."},{"word":"وَضُوء","meaning":" الماء الذي يتوضأ به. وأصل الوضوء من الوضاءة، وهي الحسن والنظافة فسمي وضوء الصلاة وضوءًا؛ لأنه يُنَظِّف صاحبه."},{"word":"غفر له","meaning":" غفر الله له، والمغفرة ستر الذنب والتجاوز عنه."}],"category":"fiqh","tags":["توضأ","نحو","وضوئي","هذا","صلى","ركعتين"],"source":"hadeethenc"},{"id":"he_3534","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ: «لَا يَقْبَلُ اللهُ صَلَاةَ أَحَدِكُمْ إِذَا أَحْدَثَ حَتَّى يَتَوَضَّأَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيّنَ النبيُّ صلى الله عليه وسلم أنَّ مِن شروط صِحةِ الصلاةِ: الطهارةُ، فيَجبُ على مَن أرادَ الصلاةَ أنْ يتوضأ إنْ كان قد حصل منه ناقِضٌ من نواقض الوضوء؛ كالغائط أو البول أو النوم أو غيرِها.","reference":"صحيح البخاري (9/ 23) (6954).\nصحيح مسلم (1/ 204) (225).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص17).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 11).","benefits":["صلاةُ المُحْدِثِ لا تُقبل حتى يتطهرَ بالغسل من الحَدَث الأكبر وبالوضوء من الأصغر.","الوضوء هو أَخْذُ ماءٍ وإدارته في الفم وإخراجه، ثم سحب الماء بنَفَسه إلى باطن أنفه، ثم إخراجه ونثره، ثم غسل وجهه ثلاث مرات، ثم غسل يديه مع المرفقين ثلاثًا، ثم مسح جميع رأسه مرة واحدة، ثم غسل رجليه مع الكعبين ثلاثًا."],"wordsMeanings":[{"word":"لا يقبَل","meaning":" لا يعتبر ولا يعتد."}],"category":"fiqh","tags":["يقبل","الله","صلاة","أحدكم","إذا","أحدث"],"source":"hadeethenc"},{"id":"he_3588","text":"عن عائشة رضي الله عنها قالت: قال رسول الله صلى الله عليه وسلم: «السِّوَاكُ مَطْهَرَةٌ لِلْفَمِ، مَرْضَاةٌ لِلرَّبِّ».","attribution":"رواه النسائي وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرنا النبيُّ صلى الله عليه وسلم أنَّ تنظيفَ الأسنانِ بِعُوْدِ شجرةِ الأَرَاك ونحوِه يُطَهِّر الفَمَ من الأوساخ والروائح الكريهة، \nوأنه مِن أسباب رضا الله عن العبد؛ لأن فيه طاعة لله واستجابة لأمره، ولما فيه من النظافة التي يحبها الله تعالى.","reference":"سنن النسائي (1/ 10) (5).\nمسند أحمد (40/ 240) (24203).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 342).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 852).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص675).","benefits":["فضيلة التَّسَوُّك، وترغيب النبي صلى الله عليه وسلم أمَّته الإكثار منه.","الأفضل في التسوُّك استعمال عُوْد شجر الأراك، واستعمل الفرشاة والمعجون يقومُ مقامَه."],"wordsMeanings":[],"category":"fiqh","bookId":"nasai","tags":["السواك","مطهرة","للفم،","مرضاة","للرب"],"source":"hadeethenc"},{"id":"he_3591","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم كان يقول: «الصَّلَوَاتُ الْخَمْسُ، وَالْجُمُعَةُ إِلَى الْجُمُعَةِ، وَرَمَضَانُ إِلَى رَمَضَانَ، مُكَفِّرَاتٌ مَا بَيْنَهُنَّ إِذَا اجْتَنَبَ الْكَبَائِرَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر النبي صلى الله عليه وسلم أن الصلوات الخمس المفروضة في اليوم والليلة، وصلاة الجمعة كل أسبوع، وصوم شهر رمضان كل عام، مكفرات لما بينها من صغائر الذنوب بشرط اجتناب الكبائر، \nأما الكبائر كالزنا وشرب الخمر فلا تُكفر إلا بالتوبة.","reference":"صحيح مسلم (1/ 209) (233).\nشرح رياض الصالحين، لابن عثيمين (2/ 183).\nنزهة المتقين بشرح رياض الصالحين، لمصطفى سعيد الخن (1/ 158).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص108).\nبهجة الناظرين شرح رياض الصالحين، لسليم بن عيد الهلالي  (1/ 209).","benefits":["الذنوب منها صغائر ومنها كبائر.","تكفير الصغائر مشروط باجتناب الكبائر.","الكبائر هي الذنوب التي ورد فِيهِا حد فِي الدُّنْيَا، أَو جَاءَ فِيهِا وَعِيد فِي الْآخِرَة؛ بالعَذَاب، أَو الغضب، أَو كان فيها تهديدٌ، أَو لعنٌ لفَاعلِها، كالزنى وشرب الخمر."],"wordsMeanings":[{"word":"مكفرات","meaning":" ماحيات."}],"category":"fiqh","bookId":"muslim","tags":["الصلوات","الخمس،","والجمعة","إلى","الجمعة،","ورمضان"],"source":"hadeethenc"},{"id":"he_3854","text":"عن عبد الله بن عمرو رضي الله عنهما عن النبي صلى الله عليه وسلم قال: «لَيْسَ الْوَاصِلُ بِالْمُكَافِئِ، وَلَكِنِ الْوَاصِلُ الَّذِي إِذَا قُطِعَتْ رَحِمُهُ وَصَلَهَا».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم بأنَّ الإنسانَ الكامِلَ في صِلَةِ الرَّحِم والإحسانِ إلى الأقاربِ ليس هو الشخصُ الذي يُقابِلُ الإحسانَ بالإحسان، بل الواصِلُ حقيقةً الكامِلُ في صلة الرحم هو الذي إذا قُطِعَتْ رَحِمُه وَصَلَها، وإن أساؤوا إليه فإنه يُقابِلُهم بالإحسان إليهم.","reference":"صحيح البخاري (8/ 6) (5991).\nمنار القاري شرح مختصر صحيح البخاري، لحمزة محمد قاسم (5/ 242).\nبهجة الناظرين، لسليم الهلالي (1/ 397).\nنزهة المتقين، لمصطفى الخن وغيره (1/ 311).\nشرح رياض الصالحين، لابن عثيمين (3/ 190).","benefits":["صِلَةُ الرَّحِم الكاملة شَرْعًا أنْ تَصِلَ مَن قَطَعَك منهم، وتَعفوَ عمَّن ظَلمك، وتعطي من حرمك، وليست صِلَة المقابلة والمجازاة.","صلة الرَّحم تكون بالزيارة واللقاء والتواصل، وإيصال ما أمكن من الخير من المال والدعاء والأمر بالعروف والنهي عن المنكر ونحوِها، ودفع ما أمكن من الشر عنهم."],"wordsMeanings":[{"word":"المكافئ","meaning":" الذي يكافئهم على صلتهم له، إن وصلوه وصلهم وإن قطعوه قطعهم."},{"word":"وصلها","meaning":" بَرَّها وأَحَسَن إليها."}],"category":"fiqh","bookId":"bukhari","tags":["ليس","الواصل","بالمكافئ،","ولكن","الواصل","الذي"],"source":"hadeethenc"},{"id":"he_4196","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ»","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أنَّ مَن صام شهر رمضان إيمانًا بالله، وتصديقًا بفَرْضِيَّةِ الصيام وما أعدَّ الله تعالى للصائمين مِن جَزيل الأجور والثواب، قاصدًا به وجهَ الله تعالى لا رياء ولا سُمْعَة، غُفرتْ له ذنوبُه الماضية.","reference":"صحيح البخاري (1/ 16) (38).\nصحيح مسلم (1/ 523) (760).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 361).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 868).\nكنوز رياض الصالحين، لمجموعة من الباحثين (15/ 40).\nشرح رياض الصالحين، لابن عثيمين (5/ 270).","benefits":["فضل الإخلاص وأهميته في صيام رمضان وغيره من الأعمال الصالحة."],"wordsMeanings":[],"category":"fiqh","tags":["صام","رمضان","إيمانا","واحتسابا","غفر","تقدم"],"source":"hadeethenc"},{"id":"he_4202","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ يَقُمْ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ»","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم عن فضل قيام ليلة القدر التي تكون في العشر الأواخر من رمضان، وأنَّ مَن اجتهد فيها بالصلاة والدعاء وقراءة القرآن والذكر، مؤمنًا بها وبما جاء في فضلها، راجيًا بعمله ثوابَ الله تعالى، لا رياء ولا سُمعة، فإنه يُغفر له ما سَبَقَ مِن ذنوبِه.","reference":"صحيح البخاري (1/ 16) (35).\nصحيح مسلم (1/ 523) (760).\nكنوز رياض الصالحين، لمجموعة من الباحثين (14/ 435).\nبهجة الناظرين، لسليم الهلالي (2/ 337).\nنزهة المتقين، (2/ 846).\nشرح النووي على مسلم (6/ 40).\nشرح رياض الصالحين، لابن عثيمين (5/ 220).\nشرح صحيح البخاري، لابن بطال (4/ 21).","benefits":["فضل ليلة القَدْر والحَث على  قيامها.","الأعمال الصالحة لا تُقبل إلا مع صِدْقِ النيَّات.","فضل الله ورحمته، فإنّ مَن قام ليلة القدر إيمانًا واحتسابًا غُفر له ما تقدم من ذنبه."],"wordsMeanings":[{"word":"إيمانًا","meaning":" تصديقًا بالله وبوعده."},{"word":"احتسابًا","meaning":" طلبًا للثواب والأجر من الله عز وجل."}],"category":"fiqh","tags":["يقم","ليلة","القدر","إيمانا","واحتسابا","غفر"],"source":"hadeethenc"},{"id":"he_4314","text":"عن النُّعمان بن بَشير رضي الله عنه قال: سَمِعْتُ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَقُولُ -وَأَهْوَى النُّعْمَانُ بِإِصْبَعَيْهِ إِلَى أُذُنَيْهِ-: «إِنَّ الْحَلَالَ بَيِّنٌ وَإِنَّ الْحَرَامَ بَيِّنٌ، وَبَيْنَهُمَا مُشْتَبِهَاتٌ لَا يَعْلَمُهُنَّ كَثِيرٌ مِنَ النَّاسِ، فَمَنِ اتَّقَى الشُّبُهَاتِ اسْتَبْرَأَ لِدِينِهِ وَعِرْضِهِ، وَمَنْ وَقَعَ فِي الشُّبُهَاتِ وَقَعَ فِي الْحَرَامِ، كَالرَّاعِي يَرْعَى حَوْلَ الْحِمَى يُوشِكُ أَنْ يَرْتَعَ فِيهِ، أَلَا وَإِنَّ لِكُلِّ مَلِكٍ حِمًى، أَلَا وَإِنَّ حِمَى اللهِ مَحَارِمُهُ، أَلَا وَإِنَّ فِي الْجَسَدِ مُضْغَةً، إِذَا صَلَحَتْ صَلَحَ الْجَسَدُ كُلُّهُ، وَإِذَا فَسَدَتْ فَسَدَ الْجَسَدُ كُلُّهُ، أَلَا وَهِيَ الْقَلْبُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم قاعدةً عامةً في الأشياء، وأنها تنقسم في الشريعة إلى ثلاثة أقسام: حَلال بَيِّن، وحرام بَيِّن، وأمور مشتبهات غير واضحة الحكم من حيث الحِلِّ والحُرْمة، لا يعلم حُكمَها كثير من الناس.\n\nفمَن ترك تلك الأشياء المشتبهة عليه سَلِم دينُه بالبُعد عن الوقوع في الحرام، وسَلِم له عِرضُه من كلام الناس بما يَعيبون عليه بسبب ارتكابه هذا المشتبه. \nومَن لم يجتنب المشتبهات فقد عَرَّض نفسَه إما بالوقوع في الحرام، أو نيل الناس من عرضه. \nوضرب الرسول صلى الله عليه وسلم مثلًا ليُبيِّن حال من يرتكب الشبهات وأنه كالراعي يرعى ماشيتَه قُرْبَ أرضٍ قد حماها صاحبها، فتوشك ماشيةُ الراعي أن ترعى في هذا الحمى لقربها منه، فكذلك من يفعل ما فيه شبهة، فإنه بذلك يقترب من الحرام فيوشك أن يقع فيه. \nوبعدها أخبر النبي صلى الله عليه وسلم أن في الجسد مضغة (وهي القلب) يصلح الجسد بصلاحها، ويفسد بفسادها.","reference":"صحيح البخاري (1/ 20) (52).\nصحيح مسلم (3/ 1219) (1599).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص18).\nشرح الأربعين النووية، لابن عثيمين (ص105).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص41).\nفتح الباري لابن حجر (4/ 291).\nشرح النووي على مسلم (11/ 28).","benefits":["الترغيب في ترك المشتبِه، الذي لم يَتبيّن حكمُه."],"wordsMeanings":[],"category":"fiqh","tags":["الحلال","بين","وإن","الحرام","بين"],"source":"hadeethenc"},{"id":"he_4319","text":"عن شداد بن أوس رضي الله عنه قال: ثِنْتَانِ حَفِظْتُهُمَا عَنْ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّ اللهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ، فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ، وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ، وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ، فَلْيُرِحْ ذَبِيحَتَهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبرُ النبيُّ صلى الله عليه وسلم أن الله تعالى أوجبَ علينا الإحسانَ في كل الأشياء، والإحسان: هو مراقبة الله على الدوام، في عبادته وفي بذل الخير وكف الأذى عن المخلوقين، ومن ذلك الإحسان في القتل والذبح.\n\nفالإحسان في القتل عند القصاص: بأن يختار أسهلَ الطُّرُق وأخَفَّها وأسرعَها زهوقًا للمقتول.\n\nوالإحسان في الذبح عند الذكاة: بأن يرفق بالبهيمة بإحداد الآلة، وألّا تُحَدَّ أمام الذبيحة وهي تنظر إليها، وألَّا تُذبح وهناك من الماشية ما ينظر إليها.","reference":"صحيح مسلم (3/ 1548) (1955).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص38).\nشرح الأربعين النووية، لابن عثيمين (ص185).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص65).\nفتح الباري، لابن حجر (9/ 644).\nشرح النووي على مسلم (13/ 107).","benefits":["رحمة الله عزّ وجل ولطفه بالخلق.","إحسان القتل والذبح بأن يكون على الوجه المشروع.","كمال الشريعة واشتمالها على كل خير، ومن ذلك رحمة الحيوان والرفق به.","النهي عن المُثْلة بالإنسان بعد قتله.","تحريم كل ما فيه تعذيب للحيوان."],"wordsMeanings":[{"word":"الشفرة","meaning":" السكين العريضة."}],"category":"fiqh","bookId":"muslim","tags":["الله","كتب","الإحسان","على","شيء"],"source":"hadeethenc"},{"id":"he_4711","text":"عن أبي سعيد الخدري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَا ضَرَرَ وَلَا ضِرَارَ، مَنْ ضَارَّ ضَرَّهُ اللَّهُ، وَمَنْ شَاقَّ شَقَّ اللَّهُ عَلَيْهِ».","attribution":"رواه الدارقطني","grade":"صحيح بشواهده","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنه يَجِبُ دفعُ الضررِ بمختلف أنواعه ومظاهره عن النفس وعن الآخرين، فلا يَحِلُّ لأحدٍ أن يُؤذيَ نفسَه أو غيرَه على حد سواء.\n\nولا يَحلُّ له أن يقابِلَ الضررَ بالضرر؛ لأن الضررَ لا يُزال بالضرر إلا على سبيل القصاص دون تعدٍّ.\n\nثم بيَّنَ النبيُّ صلى الله عليه وسلم الوعيدَ بحصول الضرر لمن يَضرُّ بالناس، وبحصول المشقة لمن يَشقُّ على الناس.","reference":"سنن الدارقطني (4/ 51) (3079).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص74).\nشرح الأربعين النووية، لابن عثيمين (ص325).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص112).","benefits":["النهي عن المجازاة بأكثر من المِثْل.","لم يأمر اللهُ عبادَه بشيء يضرُّهم.","تحريم الضرر والضرار بالقول أو بالفعل أو بالترك.","الجزاء من جنس العمل، فمن ضارَّ ضارَّه الله، ومن شاقَّ شاقَّه الله.","من قواعد الشريعة: أن \"الضرر يُزال\"، فالشريعة لا تُقِرُّ الضرر، وتنكر الإضرار."],"wordsMeanings":[],"category":"fiqh","tags":["ضرر","ولا","ضرار،","ضار","ضره","الله،"],"source":"hadeethenc"},{"id":"he_4725","text":"عن أبي هريرة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «ما نهيتكم عنه فاجتنبوه، وما أمرتكم به فأْتُوا منه ما استطعتم، فإنما أَهلَكَ الذين من قبلكم كثرةُ مسائلهم واختلافهم على أنبيائهم».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"دلنا رسول الله صلى الله عليه وسلم أنه إذا نهانا عن شيء وجب علينا اجتنابه بدون استثناء، وإذا أمرنا بشيء فعلينا أن نفعل منه ما نطيق.\nثم حذرنا حتى لا نكون كبعض الأمم السابقة حينما أكثروا من الأسئلة على أنبيائهم مع مخالفتهم لهم فعاقبهم الله بأنواع من الهلاك والدمار، فينبغي أن لا نكون مثلهم حتى لا نهلك كما هلكوا.","reference":"-التحفة الربانية في شرح الأربعين حديثًا النووية، مطبعة دار نشر الثقافة، الإسكندرية، الطبعة: الأولى، 1380 هـ.\n-شرح الأربعين النووية، للشيخ ابن عثيمين، دار الثريا للنشر.\n-فتح القوي المتين في شرح الأربعين وتتمة الخمسين، دار ابن القيم، الدمام المملكة العربية السعودية، الطبعة: الأولى، 1424هـ/2003م.\n-الفوائد المستنبطة من الأربعين النووية، للشيخ عبد الرحمن البراك، دار التوحيد للنشر، الرياض.\n-شرح الأربعين","benefits":["الأمر بامتثال الأوامر، واجتناب النواهي.","النهي لم يرخص في ارتكاب شيء منه، والأمر قيد بالاستطاعة؛ لأن الترك مقدور والفعل يحتاج إلى قدرة على إيجاد الفعل المأمور به.","النهي عن كثرة السؤال، قد قسم العلماء السؤال إلى قسمين: أحدهما: ما كان على وجه التعليم لما يحتاج إليه من أمر الدين، فهذا مأمور به ومن هذا النوع أسئلة الصحابة. والثاني: ما كان على وجه التعنت والتكلف وهذا هو المنهي عنه.","تحذير هذه الأمة من مخالفة نبيها، كما وقع في الأمم التي قبلها.","المنهي عنه يشمل القليل والكثير، لأنه لا يتأتّى اجتنابه إلا باجتناب قليله وكثيره، فمثلاً: نهانا عن الرّبا فيشمل قليله وكثيره.","ترك الأسباب المفضية إلى المحرم، لأن ذلك من معنى الاجتناب.","الإنسان له استطاعة وقدرة، لقوله: \"مَا استَطَعْتُمْ\" فيكون فيه رد على الجبرية الذين يقولون: إن الإنسان لا استطاعة له، لأنه مجبر على عمله، حتى الإنسان إذا حرّك يده عند الكلام، فيقولون تحريك اليد ليس باستطاعته، بل مجبر، ولا ريب أن هذا قول باطل يترتب عليه مفاسد عظيمة.","لا ينبغي للإنسان إذا سمع أمر الرسول -صلى الله عليه وسلم- أن يقول: هل هو واجب أم مستحبّ؟ لقوله: \"فَأْتُوا مِنْهُ مَا استَطَعْتُمْ\".","ما أمر به النبي -صلى الله عليه وسلم- أو نهى عنه فإنه شريعة، سواء كان ذلك في القرآن أم لم يكن، فُيعمل بالسنة الزائدة على القرآن أمراً أو نهياً.","كثرة المسائل سبب للهلاك ولا سيّما في الأمور التي لا يمكن الوصول إليها مثل مسائل الغيب كأسماء الله وصفاته، وأحوال يوم القيامة، لاتكثر السؤال فيها فتهلك، وتكون متنطّعًا متعمّقًا.","الأمم السابقة هلكوا بكثرة المسائل، وهلكوا بكثرة الاختلاف على أنبيائهم."],"wordsMeanings":[{"word":"نهيتكم","meaning":" النهي: طلب الكفّ على وجه الاستعلاء."},{"word":"فاجتنبوه","meaning":" اتركوه."},{"word":"من قبلكم","meaning":" من الأمم السابقة."},{"word":"واختلافهم","meaning":" مخالفتهم."},{"word":"مسائلهم","meaning":" أسئلتهم."}],"category":"fiqh","tags":["مانهيتكم","عنه","فاجتنبوه،","وما","أمرتكم","فأْتُوا"],"source":"hadeethenc"},{"id":"he_4965","text":"عن ابن عمر رضي الله عنهما قال: قال رسول الله صلى الله عليه وسلم: «مَا زَالَ يُوصِينِي جِبْرِيلُ بِالْجَارِ، حَتَّى ظَنَنْتُ أَنَّهُ سَيُوَرِّثُهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم بأنَّ جبريل ما زال يُكرِّر عليه ويأمُرُه بالاعتناء بالجار، الذي هو قريب الدار، مسلمًا أو كافرًا، قريبًا أو غير قريب، بحفظ حقِّه وعدم أذيَّتِه، والإحسان إليه والصبر على أذاه، حتى ظنَّ صلى الله عليه وسلم مِن تعظيم حق الجار وتَكرار جبريل لذلك أنه سينزلُ الوحيُ بإعطائه من مال جاره الذي يَخلُفُه بعد وفاتِه.","reference":"صحيح البخاري (8/ 10) (6014)، (8/ 10) (6015).\nصحيح مسلم (4/ 2025) (2624)، (4/ 2025) (2625).\nنزهة المتقين شرح رياض الصالحين (1/ 300).\nشرح رياض الصالحين، لابن عثيمين (3/ 175).","benefits":["عِظَم حق الجار ووجوب مراعاة ذلك.","التأكيد على حق الجار بالوصية يقتضي ضرورة إكرامه والتودُّد والإحسان إليه، ودفع الضر عنه، وعيادته عند المرض، وتهنئته عند المسرة، وتعزيته عند المصيبة.","كلما كان بابُ الجار أقرب كان حقُّه آكد.","كمال الشريعة فيما جاءت به مما فيه صلاح المجتمع من الإحسان إلى الجيران ودفع الضرر عنهم."],"wordsMeanings":[],"category":"fiqh","tags":["زال","يوصيني","جبريل","بالجار،","حتى","ظننت"],"source":"hadeethenc"},{"id":"he_5273","text":"عن عبد الله بن مسعود رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «إنَّ الرُّقَى والتَمائِمَ والتِّوَلَةَ شِرْكٌ».","attribution":"رواه أبو داود وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أشياءَ فِعلُها مِن الشرك؛ ومنها: \n\nأولاً: الرقى: الكلام الذي يَسْتَشْفِي به أهلُ الجاهلية المُحتوي على الشرك.\n\nثانياً: التمائم من الخَرَز ونحوه: التي تُعَلَّق على الأطفال والبهائم وغيرهم لدفع العَين. \n\nثالثاً: التِّوَلة: التي تُصنع لتُحبِّب أحد الزوجين إلى الآخر.\n\nفهذه الأمور من الشرك؛ لأنها مِن جَعْل الشيء سببًا، وهو ليس بسببٍ شرعيٍّ ثَبَتَ بالدليل، ولا بسببٍ حسيٍّ ثبت بالتجربة. \nأما الأسباب الشرعية كقراءة القرآن، أو الحسية كالأدوية التي ثبتت بالتجربة، فهي جائزة مع اعتقاد أنها أسباب، وأن النفع والضر بيد الله.","reference":"سنن أبي داود (6/ 31) (3883).\nسنن ابن ماجه (4/ 554) (3530).\nمسند أحمد (6/ 110) (3615).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص91).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص79).\nالقول المفيد على كتاب التوحيد، لابن عثيمين (1/ 180).","benefits":["صيانة التوحيد والعقيدة عما يُخِلُّ بها.","تحريم استعمال الرقى الشركية والتمائم والتولة.","اعتقاد الإنسان في هذه الثلاث أنها أسباب: هو شرك أصغر؛ لأنه جعل ما ليس بسببٍ سببًا، أما إن اعتقد أنها تنفع وتضر بذاتها فهو شرك أكبر.","التحذير من فعل الأسباب الشركية والمحرمة.","تحريم الرقى وأنها من الشرك إلا ما كان منها مشروعًا.","ينبغي تعلُّق القلب بالله وحده، فمنه الضر والنفع وحده لا شريك له، فلا يأتي بالخير إلا الله ولا يدفع الشر إلا الله تعالى.","الرقى الجائزة هي المتضمنة لثلاثة شروط: 1- أن يعتقد أنها سبب ولا تنفع إلا بإذن الله. 2- أن تكون بالقرآن وأسماء الله وصفاته والأدعية النبوية والأدعية المشروعة. 3- أن تكون بلغة مفهومة ولا تحتوي على طَلَاسِمَ وشَعْوَذةٍ."],"wordsMeanings":[],"category":"fiqh","bookId":"abudawud","tags":["الرقى","والتمائم","والتولة","شرك"],"source":"hadeethenc"},{"id":"he_5364","text":"عن عائشة رضي الله عنها قالت: قال النبي صلى الله عليه وسلم: «لَا تَسُبُّوا الْأَمْوَاتَ، فَإِنَّهُمْ قَدْ أَفْضَوْا إِلَى مَا قَدَّمُوا».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم حُرْمةَ سبِّ الأموات والوقوع في أعراضهم، وأنَّ هذا من مَسَاوِئ الأخلاق، فإنهم وَصَلُوا إلى ما قدَّموه من أعمال صالحة أو طالحة، وكما أنّ هذا السبَّ لا يبلغهم فإنّه إنما يؤذي الأحياء.","reference":"صحيح البخاري (2/ 104) (1393).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (2/ 631).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (4/ 385).\nتوضيح الأحكام من بلوغ المرام، للبسام (3/ 277).","benefits":["الحديث دليل على تحريم سب الأموات.","ترك سب الأموات فيه مراعاة لمصلحة الأحياء، والحفاظ على سلامة المجتمع من التشاحن والتباغض.","الحكمة من النهي عن سبهم أنهم وصلوا إلى ما قدموا فلا ينفع سبهم، وفيه إيذاء لأقاربه الأحياء.","أنه لا ينبغي للإنسان أن يقول ما لا مصلحة فيه."],"wordsMeanings":[{"word":"أفضوا إلى ما قدموا","meaning":" صاروا إلى ما قدموا من أعمالهم."}],"category":"fiqh","bookId":"bukhari","tags":["تسبوا","الأموات،","فإنهم","أفضوا","إلى","قدموا"],"source":"hadeethenc"},{"id":"he_5435","text":"عن جُندب بن عبد الله القَسْرِِي رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ صَلَّى صَلَاةَ الصُّبْحِ فَهُوَ فِي ذِمَّةِ اللهِ، فَلَا يَطْلُبَنَّكُمُ اللهُ مِنْ ذِمَّتِهِ بِشَيْءٍ، فَإِنَّهُ مَنْ يَطْلُبْهُ مِنْ ذِمَّتِهِ بِشَيْءٍ يُدْرِكْهُ، ثُمَّ يَكُبَّهُ عَلَى وَجْهِهِ فِي نَارِ جَهَنَّمَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ مَن صلى الفجر فهو في حِفْظ الله وحراستِه وحمايته، يدافع عنه، وينتصر له.\n\nثم حَذَّرَ عليه الصلاة والسلام مِن نَقْضِ هذا العهدِ وإبطاله، إما بترك صلاة الفجر، أو بالتعرُّض لمصليها والاعتداء عليه، فإنَّ مَن فَعَلَ ذلك فقد خَرَِقَ هذا الجِوار، واستحق الوعيد الشديد بأن يَطلُبَه الله بما فَرَّطَ في حقه، ومَن يطلبه الله يُدركه، ثم يلقيه على وجهه في النار.","reference":"صحيح مسلم (1/ 454) (657).\nالمعجم الأوسط (4/ 5) (3464).\nنزهة المتقين شرح رياض الصالحين (1/ 249).\nشرح رياض الصالحين، لابن عثيمين (2/ 561).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 323).","benefits":["بيان أهمية صلاة الفجر وفضيلتها.","التحذير الشديد من التعرض بسوء لمن صلى الفجر.","انتقام الله تعالى ممن يتعرض لعباده الصالحين."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["صلى","صلاة","الصبح","فهو","ذمة","الله"],"source":"hadeethenc"},{"id":"he_5512","text":"عن أبي هريرة رضي الله عنه عن رسول الله صلى الله عليه وسلم قال: «مَا نَقَصَتْ صَدَقَةٌ مِنْ مَالٍ، وَمَا زَادَ اللهُ عَبْدًا بِعَفْوٍ إِلَّا عِزًّا، وَمَا تَوَاضَعَ أَحَدٌ لِلهِ إِلَّا رَفَعَهُ اللهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ الصدقةَ لا تُنقِصُ المالَ، بل تَدْفَعُ عنه الآفات، ويُعَوِّض اللهُ صاحبَها الخيرَ العظيم، فتكون زيادةً لا نقصًا.\n\nوما زاد العفوُ مع القدرة على الانتقام أو المؤاخذة صاحبَه إلا قوةً وعزةً.\n\nوما تواضع وتَذَلَّل أحدٌ لوجه الله، لا خوفًا من أحد، ولا مداراة له، ولا طلبًا لمنفعة منه، إلا كان جزاؤه العُلُوَّ والشرفَ.","reference":"صحيح مسلم (4/ 2001) (2588).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 501).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 354).\nفتح ذي الجلال والإكرام، لابن عثيمين (6/ 438).\nسبل السلام بشرح بلوغ المرام، للصنعاني (2/ 692).","benefits":["الخير والفلاح في امتثال الشريعة وفعل الخير وإن ظن بعض الناس أنه بخلاف ذلك."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["نقصت","صدقة","مال،","وما","زاد","الله"],"source":"hadeethenc"},{"id":"he_5792","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «أَكْمَلُ الْمُؤْمِنِينَ إِيمَانًا أَحْسَنُهُمْ خُلُقًا، وَخَيْرُكُمْ خَيْرُكُمْ لِنِسَائِهِمْ».","attribution":"رواه أبو داود والترمذي وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ أَكْمَلَ الناس إيمانًا مَن حَسُنَ خُلُقُه، وذلك بطَلَاقَةِ الوجه، وبذل المعروف، وحسن الكلام، وكف الأذى.\n\n\nوخَيْرَ المؤمنين خيرُهم لنسائِهِ، كزَوجتِه وبَناتِه وأخواتِه وقَريباتِه؛ لأنهن مِن أحقِّ الناس بحُسْنِ الخُلُق.","reference":"سنن أبي داود (7/ 70) (4682).\nسنن الترمذي (2/ 454) (1162).\nمسند أحمد ط الرسالة (12/ 364) (7402).\nسلسلة الأحاديث الصحيحة وشيء من فقهها وفوائدها، للألباني (1/ 573).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 362).\nشرح رياض الصالحين، لابن عثيمين (3/ 130).\nكنوز رياض الصالحين، لمجموعة من الباحثين (5/ 234).","benefits":["فضيلة الأخلاق الحسنة وأنها من الإيمان.","العمل من الإيمان، والإيمان يزيد وينقص.","إكرام الإسلام للمرأة والترغيب في الإحسان إليها."],"wordsMeanings":[],"category":"fiqh","bookId":"abudawud","tags":["أكمل","المؤمنين","إيمانا","أحسنهم","خلقا،","وخيركم"],"source":"hadeethenc"},{"id":"he_5794","text":"عن عبد الله بن عمرو رضي الله عنهما أن رسول الله صلى الله عليه وسلم قال: «الدُّنْيَا مَتَاعٌ، وَخَيْرُ مَتَاعِ الدُّنْيَا الْمَرْأَةُ الصَّالِحَةُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ الدنيا بما فيها إنما هي شيءٌ يُتَمَتَّعُ به حينًا من الوقت ثم يزول، وأنَّ أفضلَ متاعِها الزوجةُ الصالحةُ، التي إذا نَظَرَ إليها سَرَّتْه، وإذا أَمَرَها أطاعتْه، وإذا غاب عنها حَفِظَتْه في نفسِها ومالِهِ.","reference":"صحيح مسلم (2/ 1090) (1467).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 365).\nكشف المشكل من حديث الصحيحين، لابن الجوزي (4/ 129).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخن وغيره (1/ 286).","benefits":["جواز التَّمَتُّعِ بطَيِّبَاتِ الدنيا التي أحلَّها الله لعباده دون سَرَفٍ أو مَخِيْلَة.","الترغيب في اختيار الزوجة الصالحة؛ لأنها عَوْنٌ للزوج على طاعة ربه.","خير متاع الدنيا ما كان في طاعة الله أو أعان عليها."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["الدنيا","متاع،","وخير","متاع","الدنيا","المرأة"],"source":"hadeethenc"},{"id":"he_5805","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «قَالَ اللهُ: أَنْفِقْ يَا ابْنَ آدَمَ أُنْفِقْ عَلَيْكَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يَخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ الله تبارك وتعالى قال: أنفق يا ابن آدم -من النفقات الواجبة والمستحبة- أُوَسِّعْ عليك وآتِك عِوَضًا عن ذلك وأباركْ لك فيه.","reference":"صحيح البخاري (7/ 62) (5352).\nصحيح مسلم (2/ 690) (993).\nشرح النووي على مسلم (7/ 79).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 603).","benefits":["الحث على الصدقة والإنفاق في سبيل الله.","الإنفاق في وجوه الخير من أعظم أسباب البركة في الرزق ومضاعفته، وإخلاف الله على العبد ما أنفقه.","هذا الحديث مما يرويه النبي صلى الله عليه وسلم عن ربه، ويسمى بالحديث القدسي أو الإلهي، وهو الذي لفظه ومعناه من الله، غير أنه ليست فيه خصائص القرآن التي امتاز بها عما سواه، من التعبد بتلاوته والطهارة له والتحدي والإعجاز وغير ذلك."],"wordsMeanings":[],"category":"fiqh","tags":["قال","الله:","أنفق","ابن","آدم","أنفق"],"source":"hadeethenc"},{"id":"he_6021","text":"عن عقبة بن عامر رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «أَحَقُّ الشُّرُوطِ أَنْ تُوفُوا بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ أولى الشروط بالوفاء هو ما كان سببًا في حِلِّ التَّمَتُّعِ بالمرأة، وهي الشروط المباحة التي تطلبها الزوجة في عقد النكاح.","reference":"صحيح البخاري (3/ 190) (2721).\nصحيح مسلم (2/ 1035) (1418).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (2/ 63).\nتيسير العلام شرح عمدة الأحكام، لعبد الله البسام (ص573).","benefits":["وجوب الوفاء بالشروط التي التزم بها أحد الزوجين للآخر، إلا شرطًا حَرَّمَ حلالًا أو أَحَلَّ حرامًا.","الوفاء بشروط النكاح آكَدُ من غيرها؛ لأنها في مُقابل استحلال الفروج.","عظم مكانة الزواج في الإسلام، حيث أَكَّدَ على الوفاء بشروطه."],"wordsMeanings":[],"category":"fiqh","tags":["أحق","الشروط","توفوا","استحللتم","الفروج"],"source":"hadeethenc"},{"id":"he_6203","text":"عَنْ ‌أَبِي الزُّبَيْرِ قَالَ: كَانَ ‌ابْنُ الزُّبَيْرِ يَقُولُ فِي دُبُرِ كُلِّ صَلَاةٍ حِينَ يُسَلِّمُ: «لَا إِلَهَ إِلَّا اللهُ وَحْدَهُ لَا شَرِيكَ لَهُ، لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ، لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللهِ، لَا إِلَهَ إِلَّا اللهُ، ‌وَلَا ‌نَعْبُدُ ‌إِلَّا إِيَّاهُ، لَهُ النِّعْمَةُ وَلَهُ الْفَضْلُ وَلَهُ الثَّنَاءُ الْحَسَنُ، لَا إِلَهَ إِلَّا اللهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ» وَقَالَ: «كَانَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يُهَلِّلُ بِهِنَّ دُبُرَ كُلِّ صَلَاةٍ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"كان رسولُ الله صلى الله عليه وسلم يُهلِّلُ بعد تسليمِه من كلِّ صلاةٍ مكتوبةٍ بهذا الذكر العظيم، ومعناه: \n\n\"لا إله إلا الله\": يعني لا معبود بحق إلا الله. \n\n\"وحده لا شريك له\" أي: إنه لا مشارك له في ألوهيته وربوبيته وأسمائه وصفاته. \n\n\"له الملك\" أي: له الملك المُطْلَق العام الشامل الواسع، ملك السموات والأرض وما بينهما. \n\n\"وله الحمد\" أي: هو المُتصف بالكمال المطلق، المحمود بالكمال محبةً وتعظيمًا على كل حال، في السراء، وفي الضراء. \n\n\"وهو على كل شيء قدير\": فقُدرته كاملة وتامَّة من كل وجهٍ، لا يُعجزه شيءٌ، ولا يمتنع عليه أمرٌ من الأمور. \n\n\"لا حول ولا قوة إلا بالله\" أي: لا تَحَوُّل من حالٍ إلى حال، ومن معصية الله إلى طاعته، ولا قوة إلا بالله فهو المعين وعليه التُّكْلان. \n\n\"لا إله إلا الله، ولا نعبد إلا إياه\": تأكيد على معنى الألوهية ونفي الشرك، وأنه لا يستحق العبادة سواه. \n\n\"له النعمة وله الفضل\": فهو الذي يخلق النِّعَم ويملكها، ويتفضَّل بها على من يشاء من عباده.\n\n\"وله الثناء الحسن\": على ذاته وصفاته وأفعاله ونعمه، وعلى كل حال.\n\n\"لا إله إلا الله، مخلصين له الدين\": أي موحِّدين لا رياء ولا سمعة في طاعة الله. \n\n\"ولو كره الكافرون\"، أي: ثابتين على توحيد الله وعبادته ولو كره الكافرون.","reference":"صحيح مسلم (1/ 415) (594).\nسبل السلام شرح بلوغ المرام، للصنعاني (1/ 293).\nكنوز رياض الصالحين، لمجموعة من الباحثين (17/ 61).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 973).\nبهجة الناظرين، لسليم الهلالي (2/ 499).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (2/ 762).\nشرح رياض الصالحين، لابن عثيمين (5/ 492).","benefits":["استحباب المحافظة على هذا الذكر بعد كل صلاة مكتوبة.","المسلم يَعْتَزُّ بدينِهِ ويُظْهِرُ شعائرَه، ولو كره الكافرون.","إذا وَرَدَتْ في الحديث كلمةُ: \"دُبر الصلاة\"، فإن كان ما في الحديث ذِكْرًا فالأصل أن يكون بعد السلام، وإن كان دعاءً فيكون قبل السلام من الصلاة."],"wordsMeanings":[{"word":"الثناء","meaning":" تكرار المدح والذكر."}],"category":"fiqh","bookId":"muslim","tags":["كان","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_6255","text":"عن ابن عباس رضي الله عنهما قال: قال رسول الله صلى الله عليه وسلم: «ما مِنْ أيَّامٍ العمَلُ الصَّالِحُ فيها أحبُّ إلى اللهِ مِن هذه الأيام» يعني أيامَ العشر، قالوا: يا رسُولَ الله، ولا الجهادُ في سبيلِ الله؟ قال: «ولا الجهادُ في سبيلِ الله، إلا رجلٌ خَرَجَ بنفسِه ومالِه فلم يَرْجِعْ من ذلك بشيءٍ».","attribution":"رواه البخاري وأبو داود، واللفظ له","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ العملَ الصالح في العشر أيام الأولى من شهر ذي الحجة أفضل من سائر أيام السنة.\n\nوسَألَ الصحابةُ رضي الله عنهم النبيَّ صلى الله عليه وسلم عن الجهاد في غير هذه الأيام العشر هل هو أفضل أم الأعمال الصالحة في هذه الأيام؟ لِمَا تَقَرَّرَ عندهم أن الجهاد من أفضل الأعمال.\n\nفأجاب صلى الله عليه وسلم: بأنَّ العمل الصالح في هذه الأيام أفضل من الجهاد في غيرها، إلا رجل خرج مجاهدًا ومخاطرًا بنفسِهِ ومالِهِ في سبيل الله، فَفَقَدَ مالَه وفاضت روحُه في سبيل الله، \nفهذا هو الذي يَفْضُل على العمل الصالح في هذه الأيام الفاضلة.","reference":"صحيح البخاري (2/ 20) (969).\nسنن أبي داود (4/ 102) (2438).\nفتح الباري بشرح صحيح البخاري، لابن حجر (2/ 459).\nتطريز رياض الصالحين، لفيصل آل المبارك (ص699).\nشرح رياض الصالحين، لابن عثيمين (5/ 301).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 884).\nكنوز رياض الصالحين، لمجموعة من الباحثين (15/ 234).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 382).","benefits":["فضل العمل الصالح في عشر ذي الحجة، فعلى المسلم أن يغتنم هذه الأيام ويكثر فيها الطاعات، من ذكر الله عز وجل، وقراءة القرآن، والتكبير والتهليل والتحميد، والصلاة والصدقة والصيام، وجميع أعمال البِرّ."],"wordsMeanings":[{"word":"الجهاد","meaning":" هو مقاتلة الكفار لإبلاغ دين الله تعالى للناس أو للدفاع عن الإسلام وأهله."}],"category":"fiqh","bookId":"bukhari","tags":["أيام","العمل","الصالح","فيها","أحب","إلى"],"source":"hadeethenc"},{"id":"he_6261","text":"عن بريدة بن الحصيب رضي الله عنه أنه قال: بَكِّرُوا بِصَلَاةِ الْعَصْرِ، فَإِنَّ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «مَنْ تَرَكَ صَلَاةَ الْعَصْرِ فَقَدْ حَبِطَ عَمَلُهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"حَذَّرَ النبيُّ صلى الله عليه وسلم مِن تأخيرِ صلاةِ العصر عن وقتها مُتَعمِّدًا، وأنَّ من فعل ذلك بَطَل وفَسَدَ عملُه وذهب سُدًى.","reference":"صحيح البخاري (1/ 115) (553).\nمسند أحمد (38/ 152) (23045).\nشرح رياض الصالحين، لابن عثيمين (5/ 56).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 777).\nفيض القدير شرح الجامع الصغير (3/ 206).\nبهجة الناظرين، لسليم الهلالي (2/ 260).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص614).","benefits":["الحث على المحافظة على صلاة العصر في أول وقتها والمبادرة إلى ذلك.","الوعيد الشديد لمن ترك صلاة العصر، وتفويتها عن وقتها أعظم من تفويت غيرها، فإنها الصلاة الوسطى المخصوصة بالأمر في قوله تعالى: (حَافِظُواْ عَلَى الصَّلَوَاتِ والصَّلاَةِ الْوُسْطَى) [البقرة: 238]."],"wordsMeanings":[],"category":"fiqh","bookId":"bukhari","tags":["ترك","صلاة","العصر","فقد","حبط","عمله"],"source":"hadeethenc"},{"id":"he_6263","text":"عن عثمان بن عفان رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ خَرَجَتْ خَطَايَاهُ مِنْ جَسَدِهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِهِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ مَن توضَّأ مع مُراعاةِ سُننِ الوضوء وآدابِه، كان ذلك من أسبابِ تكفيرِ السيئات وحَطِّ الخطايا، «حتى تخرج» ذنوبُه من تحت أظفار يديه ورجليه.","reference":"صحيح مسلم (1/ 216) (245).\nشرح رياض الصالحين، لابن عثيمين (5/ 9).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 763).\nبهجة الناظرين، سليم الهلالي (2/ 247).","benefits":["الحث على الاعتناء بتعلُّم الوضوء وسننه وآدابه، والعمل بذلك.","فضل الوضوء، وأنه كفارة للذنوب الصغائر، أما الكبائر فلا بد من التوبة.","شرط خروج الخطايا هو إكمال الوضوء والإتيان به بدون إخلال كما بينه النبي -صلى الله عليه وسلم-.","تكفير الذنوب في هذا الحديث مُقيَّدٌ باجتناب الكبائر والتوبة منها، قال تعالى: (إِنْ تَجْتَنِبُوا كَبَائِرَ مَا تُنْهَوْنَ عَنْهُ نُكَفِّرْ عَنْكُمْ سَيِّئَاتِكُمْ) [النساء:31]."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["توضأ","فأحسن","الوضوء","خرجت","خطاياه","جسده"],"source":"hadeethenc"},{"id":"he_6460","text":"عن أبي مسعود رضي الله عنه عن النبي صلى الله عليه وسلم قال: «إِذَا أَنْفَقَ الرَّجُلُ عَلَى أَهْلِهِ يَحْتَسِبُهَا فَهُوَ لَهُ صَدَقَةٌ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنه إذا أَنْفَقَ الرجلُ على أهلِهِ الذين تَلْزَمُهُ نفقتُهم كزوجِهِ ووالديه وولدِهِ وغيرهم وهو يَتقرَّب بذلك إلى الله تعالى ويحتسب عنده أجرَ ما يُنفِق فإنّ له أجرَ الصدقة.","reference":"صحيح البخاري (1/ 20) (55).\nصحيح مسلم (2/ 695) (1002).\nكنوز رياض الصالحين، لمجموعة من الباحثين (5/ 334).\nشرح رياض الصالحين، لابن عثيمين (3/ 157).\nنزهة المتقين بشرح رياض الصالحين، لمصطفى الخن وغيره (1/ 293).\nبهجة الناظرين شرح رياض الصالحين، سليم الهلالي (1/ 375).","benefits":["حصول الأجر والثواب بالإنفاق على الأهل.","المؤمن يبتغي في عملِه وجهَ الله وما عنده من الأجر والثواب.","ينبغي استحضار النية الصالحة في كل عمل، ومن ذلك حال الإنفاق على الأهل."],"wordsMeanings":[],"category":"fiqh","tags":["إذا","أنفق","الرجل","على","أهله","يحتسبها"],"source":"hadeethenc"},{"id":"he_8914","text":"عن ابن عمر رضي الله عنهما: أَنَّ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنِ الْقَزَعِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"نَهى النبيُّ صلى الله عليه وسلم عن حَلْقِ بَعض شَعر الرأس وتركِ بعضه.\n\nوالنهيُ عامٌّ للذكور الصغار والكبار، أما المرأةُ فليس لها أن تَحلِقَ شعرَ رأسِها.","reference":"صحيح البخاري (7/ 163) (5921).\nصحيح مسلم (3/ 1675) (2120).\nنزهة المتقين (2/ 1126).\nكنوز رياض الصالحين، لمجموعة من الباحثين (19/ 380).\nشرح رياض الصالحين، لابن عثيمين (6/ 381).","benefits":["اهتمام الشريعة الإسلامية بِمَظْهَرِ الإنسان."],"wordsMeanings":[],"category":"fiqh","tags":["رسول","الله","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_10044","text":"عن أبي هريرة رضي الله عنه مرفوعًا: «اسْتَنْزِهوا من البول؛ فإنَّ عامَّة عذاب القبر منه».","attribution":"رواه الدارقطني","grade":"صحيح","gradeKey":"sahih","explanation":"يبين لنا النبي صلى الله عليه وسلم في هذا الحديث أحد أسباب عذاب القبر، وهو الأكثر شيوعاً، ألا وهو عدم الاستنزاه والطهارة من البول.","reference":"سنن الدارقطني،أبو الحسن علي بن عمر الدارقطني، تحقيق: شعيب الارنؤوط وآخرون، نشر: مؤسسة الرسالة، بيروت، لبنان، الطبعة: الأولى، 1424هـ، 2004م.\nإرواء الغليل في تخريج أحاديث منار السبيل، محمد ناصر الدين الألباني، إشراف: زهير الشاويش، المكتب الإسلامي، بيروت، الطبعة: الثانية 1405هـ، 1985م.\nتوضيح الأحكام مِن بلوغ المرام، عبد الله بن عبد الرحمن البسام، مكتبة الأسدي، مكة المكرّمة، الطبعة: الخامِسَة 1423هـ، ","benefits":["الحرص على التنزه والابتعاد من البول، بأن لا يصيبه في بدنه ولا ثوبه .","الأفضل المبادرة بغسله، والطهارة منه بعد إصابته؛ لئلا تصاحبه النجاسة، أما وجوب إزالتها فيكون عند الصلاة.","أن البول نجس، فإذا أصاب بدناً أو ثوباً أو بقعة، نجسها؛ فلا تصح بذلك الصلاة؛ لأن الطهارة من النجاسة أحد شروطها.","أن ترك التنزه من البول من كبائر الذنوب.","ثبوت عذاب القبر، وهو ثابت بالكتاب والسنة والإجماع.","إثبات الجزاء في الآخرة، فأول مراحل الآخرة هي القبور، فالقبر: إما روضة من رياض الجنة، أو حفرة من حفر النار."],"wordsMeanings":[{"word":"استنزهوا","meaning":" اطلبوا النزاهة بابتعادكم عن البول."},{"word":"عامة","meaning":" أكثر."}],"category":"fiqh","tags":["استنزهوا","البول؛","فإن","عامة","عذاب","القبر"],"source":"hadeethenc"},{"id":"he_10647","text":"عن أبي مَرْثَدٍ الغَنَوِيّ رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «لَا تَجْلِسُوا عَلَى الْقُبُورِ، وَلَا تُصَلُّوا إِلَيْهَا».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"نَهى النبيُّ صلى الله عليه وسلم عن الجُلوسِ على القبور.\n\nكما نهى عن الصلاةِ إلى القبور، بأن يكون القبر في جهة قِبْلة المُصلي؛ لأن ذلك من وسائل الشرك.","reference":"صحيح مسلم (2/ 668) (972).\nتوضيح الأحكام مِن بلوغ المرام، لعبد الله البسام (2/ 30).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لمحمد العثيمين (1/ 522).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (4/ 285).","benefits":["النهي عن الصلاة في المقابر أو بينها أو إليها إلا صلاة الجنازة كما ثبت بالسنة.","النهي عن الصلاة إلى القبور سَدًّا لذريعة الشرك.","نهى الإسلام عن الغُلوِّ في القبور وعن امْتِهانها، فلا إفْرَاط ولا تَفْريط.","حُرمة المُسلم باقية بعد موته، لقوله صلى الله عليه وسلم: (كَسْرُ عَظْمِ المَيّت كَكَسْرِه حيًّا)."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["تجلسوا","على","القبور،","ولا","تصلوا","إليها"],"source":"hadeethenc"},{"id":"he_10887","text":"عَنْ عَائِشَةَ أُمِّ المؤمنين رضي الله عنها: أَنَّ أُمَّ سَلَمَةَ ذَكَرَتْ لِرَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَنِيسَةً رَأَتْهَا بِأَرْضِ الْحَبَشَةِ، يُقَالُ لَهَا مَارِيَةُ، فَذَكَرَتْ لَهُ مَا رَأَتْ فِيهَا مِنَ الصُّوَرِ، فَقَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «أُولَئِكَ قَوْمٌ إِذَا مَاتَ فِيهِمُ الْعَبْدُ الصَّالِحُ، أَوِ الرَّجُلُ الصَّالِحُ، بَنَوْا عَلَى قَبْرِهِ مَسْجِدًا، وَصَوَّرُوا فِيهِ تِلْكَ الصُّوَرَ، أُولَئِكَ شِرَارُ الْخَلْقِ عِنْدَ اللهِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"ذَكَرَتْ أُمُّ المؤمنين أُمُّ سَلَمَة رضي الله عنها للنبيِّ صلى الله عليه وسلم أنها لمَّا كانت بأرض الحَبَشة رأتْ كَنِيسة -يُقال لها مَارِيَة- فيها صورٌ وزَخارِفُ وتصاويرُ؛ تَعَجُّبًّا من ذلك! \nفبَيَّنَ النبيُّ صلى الله عليه وسلم أسباب وضع هذه الصور؛ \nفقال: إن هؤلاء الذين تذكرين كانوا إذا مات فيهم الرجلُ الصالحُ بَنَوا على قبره مَسجدًا يُصَلُّون فيه، وصَوَّرُوا تلك الصور، \nوبَيَّنَ أنَّ فاعلَ ذلك شَرُّ الخلقِ عند الله تعالى؛ لأنَّ فِعلَه يؤدِّي إلى الشرك بالله تعالى.","reference":"صحيح البخاري (1/ 94) (434).\nصحيح مسلم (1/ 375) (528).\nمرقاة المفاتيح، لعلي القاري (7/ 2857).\nتوضيح الأحكام مِن بلوغ المرام، لعبد الله البسام (2/ 115).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (1/ 598).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (2/ 469).\nتيسير العلام شرح عمدة الأحكام، لعبد الله البسام (ص290).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص183).\nالملخص في شرح كتاب ا","benefits":["تحريم بناء المساجد على القُبور، أو الصلاة عندها، أو دَفن الموتى في المساجد؛ سَدَّا لذَريعة الشِّرك.","بناء المساجد على القُبور، ونَصب الصُّور فيها، هو عمل اليَّهود والنَّصارى، وأنَّ من فعل هذا، فقد شَابَهَهم.","تحريم اتخاذ الصُّور لذَوَات الأرواح.","مَن بَنى مسجدًا على قَبر وصَوَّر فيه التصاوير، فهو مِن شَرِّ خَلْقِ الله تعالى.","حِماية الشَّريعة لجَنَاب التوحيد حماية كاملة، بسد جميع الوسائل التي قد تُؤدي إلى الشِّرك.","النهي عن الغلو في الصالحين؛ لأنه سببٌ للوقوع في الشرك."],"wordsMeanings":[],"category":"fiqh","tags":["أولئك","قوم","إذا","مات","فيهم","العبد"],"source":"hadeethenc"},{"id":"he_10925","text":"عن ابنِ عَبَّاسٍ رضي الله عنهما عن النبيِّ صلى الله عليه وسلم قال: «أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ: عَلَى الْجَبْهَةِ وَأَشَارَ بِيَدِهِ عَلَى أَنْفِهِ، وَالْيَدَيْنِ، وَالرُّكْبَتَيْنِ، وَأَطْرَافِ الْقَدَمَيْنِ، وَلَا نَكْفِتَ الثِّيَابَ وَالشَّعَرَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم بأنَّ اللهَ أَمَرَه عند الصلاة أنْ يَسجُدَ على سبعةٍ من أعضاء الجسم؛ وهي: \n\nأولاً: الجبهة: وهي: صفحة الوجه فوق الأنف والعينين، \nوأشار صلى الله عليه وسلم بيده إلى أنفِه، مُبَيِّنًا أن الجَبْهةَ والأنف عضو واحد من السبعة، وتأكيدًا على أنَّ الساجِد يُلامِسُ بأنفِه الأرضَ. \n\nالعضو الثاني والثالث: اليدان. \n\nالرابع والخامس: الرُّكْبتان. \n\nالسادس والسابع: أصابع القدمين. \n\nوأَمَرَنا أنْ لا نَربِطَ شعورنًا، أو نَجمعَ ثيابَنا بعضَها على بعض عند السجود على الأرض صيانةً لها؛ بل نُرسِلُها حتى تقع على الأرض، فتسجد مع الأعضاء.","reference":"صحيح البخاري (1/ 162) (812).\nصحيح مسلم (1/ 354) (490).\nالمنهاج شرح صحيح مسلم، للنووي (4/ 206).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (2/ 718).\nسبل السلام شرح بلوغ المرام، للصنعاني (1/ 270).\nتوضيح الأحكام مِن بلوغ المرام، لعبد الله البسام (2/ 229).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (2/ 115).\nمنار القاري، لحمزة قاسم (2/ 202).","benefits":["وجوب السُّجود في الصلاة على الأعَضاء السَّبعة.","كراهية جَمْعِ وضَمِّ الثَّوب والشَّعَر في الصلاة.","يجب على المصلي أن يطمئن في صلاته، وذلك بأنْ يضع أعضاء السجود السبعة على الأرض، ويستقر عليها حتى يأتي بالذكر المشروع.","النهيُ عن كَفِّ الشَّعَرِ خاصٌّ بالرجال دون النساء؛ لأن المرأة في الصلاة مأمورة بالتستر."],"wordsMeanings":[{"word":"ولا نَكْفِت","meaning":" الكَفت: الجَمع والضَّم."}],"category":"fiqh","tags":["أمرت","أسجد","على","سبعة","أعظم"],"source":"hadeethenc"},{"id":"he_10930","text":"عن ابن عباس رضي الله عنهما: كان النبي صلى الله عليه وسلم يقول بين السجدتين: «اللَّهمَّ اغْفِرْ لي، وارْحَمْنِي، وعافِني، واهْدِني، وارزقْنِي».","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"حسن بشواهده","gradeKey":"hasan","explanation":"كان النبيُّ صلى الله عليه وسلم يدعو بين السَّجدتَين في صلاتِه بهذه الدعوات الخمس التي يحتاج المسلم إليها حاجة عظيمة، واشتملت على خَيرَي الدنيا والآخرة، مِنْ طَلَبِ المغفرة وستر الذنوب والتجاوز عنها، وإسباغ الرحمة، والعافية من الشبهات والشهوات والأمراض والأسقام، وسؤال الله الهداية للحق والثبات عليه، والرزق من الإيمان والعلم والعمل الصالح، ومن المال الحلال الطيب.","reference":"سنن أبي داود (2/ 138) (850).\nسنن الترمذي (1/ 317) (284).\nسنن ابن ماجه (2/ 64) (898).\nمسند أحمد (5/ 72) (2895).\nمشكاة المصابيح، للتبريزي (1/ 283).\nسبل السلام شرح بلوغ المرام، لمحمد الصنعاني (1/ 274).\nتوضيح الأحكام مِن بلوغ المرام، لعبد الله البسام (2/ 240).","benefits":["مشروعية هذا الدعاء في الجلسة التي بين السَّجدتين.","فضل هذه الأدعية لِمَا اشتملتْ عليه من خيري الدنيا والآخرة."],"wordsMeanings":[],"category":"fiqh","bookId":"abudawud","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_10947","text":"عن ثَوْبَانَ رضي الله عنه قال: كَانَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ إِذَا انْصَرَفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ ثَلَاثًا، وَقَالَ: «اللَّهُمَّ أَنْتَ السَّلَامُ، وَمِنْكَ السَّلَامُ، تَبَارَكْتَ ذَا الْجَلَالِ وَالْإِكْرَامِ»، قَالَ الْوَلِيدُ: فَقُلْتُ لِلْأَوْزَاعِيِّ: كَيْفَ الْاسْتِغْفَارُ؟ قَالَ: تَقُولُ: أَسْتَغْفِرُ اللهَ، أَسْتَغْفِرُ اللهَ.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبيُّ صلى الله عليه وسلم يقول إذا انتهى من صلاته: أستغفر الله، أستغفر الله، أستغفر الله.\n\nثم يُعَظِّم ربَّه بقوله: \"اللَّهمَّ أنتَ السَّلامُ، ومنْكَ السَّلامُ، تباركْتَ ذا الجَلالِ والإكرامِ \" فالله السالم الكامل في صفاته، المنزَّهُ عنَ كل عيب ونَقصٍ، وتَطْلُبُ منه سبحانه السَّلامةَ منْ شُرورِ الدُّنيا والآخرةِ لا مِنْ غَيره، وهو سبحانه قد تَكاثَرَ خَيْرُه في الدارين، صاحب العظَمةِ والإحسانِ.","reference":"صحيح مسلم (1/ 414) (591).\nمرعاة المفاتيح شرح مشكاة المصابيح، لعبيد الله المباركفوري (3/ 317).\nسبل السلام، للصنعاني (1/ 294).\nتوضيح الأحكام مِن بلوغ المرام، لعبد الله البسام (2/ 301).","benefits":["استحباب الاستغفار عَقِبَ الصلاةِ والمداومة عليه.","استحباب الاستغفار لاستكمال النقص في العبادة وجَبْرًا للطاعة والتقصير فيها."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["اللهم","أنت","السلام،","ومنك","السلام،","تباركت"],"source":"hadeethenc"},{"id":"he_10951","text":"عن عمران بن حصين رضي الله عنه قال: كَانَتْ بِي بَوَاسِيرُ، فَسَأَلْتُ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ عَنِ الصَّلَاةِ، فَقَالَ: «صَلِّ قَائِمًا، فَإِنْ لَمْ تَسْتَطِعْ فَقَاعِدًا، فَإِنْ لَمْ تَسْتَطِعْ فَعَلَى جَنْبٍ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ الأصلَ في الصلاةِ القيامُ، إلّا في حال عدم الاستطاعة فيُصلِّي جالسًا، وإنْ لم يستطع الصلاةَ جالسًا فله أن يُصلِّي على جَنْبِه.","reference":"صحيح البخاري (2/ 48) (1117).\nتوضيح الأحكام من بلوغ المرام، لعبدالله البسام (2/ 322).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (3/ 202).","benefits":["الصلاة لا تسقط ما دام العقلُ ثابتًا، فيكون الانتقال من حال إلى حال حسب  الاستطاعة.","سماحة ويُسْر الإسلام في أنَّ العبدَ يفعل من العبادة ما يستطيع."],"wordsMeanings":[{"word":"بواسير","meaning":" جمع باسور، وهو ورم يصيب مقعدة الإنسان."}],"category":"fiqh","bookId":"bukhari","tags":["قائما،","فإن","تستطع","فقاعدا،","فإن","تستطع"],"source":"hadeethenc"},{"id":"he_11287","text":"عن أبي هريرة رضي الله عنه قال: أَتَى النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ أَعْمَى، فَقَالَ: يَا رَسُولَ اللهِ، إِنَّهُ لَيْسَ لِي قَائِدٌ يَقُودُنِي إِلَى الْمَسْجِدِ، فَسَأَلَ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرَخِّصَ لَهُ فَيُصَلِّيَ فِي بَيْتِهِ، فَرَخَّصَ لَهُ، فَلَمَّا وَلَّى دَعَاهُ، فَقَالَ: «هَلْ تَسْمَعُ النِّدَاءَ بِالصَّلَاةِ؟» فَقَالَ: نَعَمْ، قَالَ: «فَأَجِبْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أتَى رجُلٌ أعْمَى إلى النبيِّ صلى الله عليه وسلم، فقال: يا رسول الله ليس عندي مَن يُساعدني ويأخذ بيدي إلى المسجد، في الصلوات الخمس، يريد أنْ يُرخِّصَ له النبيُّ صلى الله عليه وسلم في ترك الجماعة، فَرَخَّصَ له، فلمَّا أَدْبَرَ ناداه وقال: هل تسمع الأذان بالصلاة؟ قال: نعم، قال: فأجب المُنادي بالصلاة.","reference":"صحيح مسلم (1/ 452) (653).\nشرح النووي على مسلم (5/ 155).\nفتح ذي الجلال والإكرام، شرح بلوغ المرام، لابن عثيمين (2/ 254).","benefits":["وجوب صلاة الجماعة؛ لأن الرُّخصة لا تكون إلا من شيء لازم وواجب.","قوله: «فأجب» لمن يسمع النداء يدل على وجوب صلاة الجماعة؛ لأن الأصل بالأمر للوجوب."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["تسمع","النداء","بالصلاة؟","فقال:","نعم،","قال:"],"source":"hadeethenc"},{"id":"he_11310","text":"عن علي بن أبي طالب، ومعاذ بن جبل رضي الله عنهما مرفوعًا: «إذا أتى أحدُكم الصلاةَ والإمامُ على حال، فلْيصنعْ كما يصنع الإمامُ».","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"إذا أتى أحدكم الصلاة والإمام على حال من قيام أو ركوع أو سجود أو قعود، فليوافق الإمام فيما هو فيه من القيام أو الركوع أو غير ذلك، ولا ينتظر حتى يقوم الإمام كما يفعله العوام.","reference":"سنن الترمذي، محمد بن عيسى الترمذي، تحقيق وتعليق: أحمد محمد شاكر، ومحمد فؤاد عبد الباقي، وإبراهيم عطوة عوض، شركة مكتبة ومطبعة مصطفى البابي الحلبي، مصر، الطبعة الثانية، 1395هـ - 1975م.\nنيل الأوطار، محمد بن علي الشوكاني اليمني، تحقيق: عصام الدين الصبابطي، الناشر: دار الحديث، مصر، الطبعة الأولى، 1413هـ - 1993م.\nصحيح الجامع الصغير وزيادته، محمد ناصر الدين الألباني، المكتب الإسلامي، بيروت، الطبعة الثالث","benefits":["مشروعية دخول اللاحق مع الإمام في أي جزء من أجزاء الصلاة أدركه، من غير فرق بين الركوع والسجود والقعود."],"wordsMeanings":[],"category":"fiqh","bookId":"tirmidhi","tags":["إذا","أتى","أحدكم","الصلاة","والإمام","على"],"source":"hadeethenc"},{"id":"he_58060","text":"عن عبد الله بن مسعود رضي الله عنه قال: عَلَّمَنَا رَسُوْلُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ خُطْبَةَ الحَاجَةِ: إِنَّ الحَمْدَ للهِ، نَسْتَعِيْنُهُ وَنَسْتَغْفِرُهُ، وَنَعُوْذُ بِهِ مِنْ شُرُوْرِ أَنْفُسِنَا، مَنْ يَهْدِ اللهُ فَلَا مُضِلَّ لَهُ، وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ، وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا الله، وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُوْلُهُ، {يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمُ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ والأرحام إن الله كان عليكم رقيبا} [النساء: 1]، {يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ} [آل عمران: 102]، {يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا (70) يُصْلِحْ لَكُمْ أَعْمَالَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَمَنْ يُطِعِ اللَّهَ وَرَسُولَهُ فَقَدْ فَازَ فَوْزًا عَظِيمًا} [الأحزاب:70 - 71].","attribution":"رواه أبو داود والترمذي والنسائي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ ابنُ مَسْعُودٍ رضي الله عنه أنَّ النبيَّ صلى الله عليه وسلم عَلَّمَهم خُطبةَ الحاجَة، وهي التي تُقال عند افتتاح الكلام في الخُطَبِ وبَينَ يَدَيْ حاجَتِهم، كخطبة النكاح وخطبة الجمعة وغيرها، \nوهذه الخطبةُ اشتملتْ على معانٍ عظيمة من بيان استحقاق الله لجميع أنواع الحَمْد، وطلب الاستعانة منه وحده لا شريك له، وستر الذنوب والتجاوز عنها، والالتجاء إليه من كل الشرور، شرور النفس وغيرها.\n\nثم أَخْبَرَ النبيُّ صلى الله عليه وسلم أنَّ الهدايةَ بيدِ الله، فمَنْ هداه فلا مُضِلَّ له، ومَن أَضَلَّه فلا هادي له.\n\nثم ذَكَرَ شهادةَ التوحيد وأنه لا معبود بحق إلا الله، وشهادة الرسالة بأنَّ محمدًا عبدُ الله ورسولُه.\n\nوختم هذه الخطبة بهذه الآيات الثلاث المشتملة على الأمر بتقوى الله جل وعلا بفعل أوامره واجتناب نواهيه ابتغاء وجه الله، وأنَّ جزاءَ مَن فَعََلَ ذلك صلاحُ الأعمالِ والأقوالِ وتكفيِر السيئات ومغفرة الذنوب والحياة الطيبة في الدنيا والفوز بالجَنَّةَ يومَ القيامةِ.","reference":"سنن أبي داود (3/ 456) (2118).\nسنن الترمذي (2/ 398) (1105).\nسنن النسائي (3/ 104) (1404).\nسنن ابن ماجه (3/ 87) (1892).\nمسند أحمد (6/ 262) (3720).\nذخيرة العقبى في شرح المجتبى، للإثيوبي (16/ 231).\nعون المعبود شرح سنن أبي داود، للعظيم آبادي (6/ 108).\nتوضِيحُ الأحكَامِ مِن بُلوُغ المَرَام، للبسام (5/ 241).","benefits":["استحباب افتتاح خطب النكاح والجمعة وغيرها بهذه الخطبة.","الخطبة ينبغي أن تكونَ مشتملةً على الحَمْد والشهادتين وبعض الآيات القرآنية.","تعليم النبي صلى الله عليه وسلم لأصحابه ما يحتاجونه في دينهم."],"wordsMeanings":[],"category":"fiqh","bookId":"abudawud","tags":["علمنا","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_58066","text":"عن أبي موسى رضي الله عنه أن النبي صلى الله عليه وسلم قال: «لا نِكَاحَ إِلّا بِوَليٍّ».","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ المرأةَ لا يَصِحُّ زواجُها إلا بولي يقوم بعقد النكاح.","reference":"سنن أبي داود (3/ 427) (2085).\nسنن الترمذي (2/ 392) (1101).\nسنن ابن ماجه (3/ 79) (1881).\nمسند أحمد (32/ 280) (19518).\nالبدرُ التمام شرح بلوغ المرام، للمَغرِبي (7/ 57).\nإرواء الغليل في تخريج أحاديث منار السبيل، للألباني (6/ 237).\nتوضِيح الأحكام من بلوغ المَرَام، للبسام (5/ 262).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (7/ 222).\nفتح ذي الجلال والإكرام بشرح بلوغ المرام، لابن عثيمين (4/ 469).","benefits":["الولي شرطٌ في صِحة النكاح، فإنْ حَصَلَ بلا ولي، أو زَوَّجَت المرأةُ نفسَها، لم يصح النكاح.","الولي هو أقرب الرجال إلى المرأة، فلا يزوجها وليٌّ بعيد مع وجود أقرب منه.","يُشترط في الولي: التكليف، والذكورية، والرشد في معرفة مصالح النكاح، واتفاق الدين بين الولي والمولى عليها، فمن لم يتَّصف بهذه الصفات فليس أهلًا للولاية في عقد النكاح."],"wordsMeanings":[{"word":"لا نكاح","meaning":" لا نكاح صحيح ومعتبر شرعًا."},{"word":"الوَلِيُّ","meaning":" هو أقرب الرجال إلى المرأة من عصبتها الذين يرثونها، كالأب والأخ."}],"category":"fiqh","bookId":"abudawud","tags":["نكاح","إلا","بولي"],"source":"hadeethenc"},{"id":"he_64637","text":"عن عبد الله بن عمرو رضي الله عنهما عن النبي صلى الله عليه وسلم قال: «مَنْ قَتَلَ مُعَاهَدًا ‌لَمْ ‌يَرَحْ ‌رَائِحَةَ الْجَنَّةِ، وَإِنَّ رِيحَهَا تُوجَدُ مِنْ مَسِيرَةِ أَرْبَعِينَ عَامًا».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم الوعيدَ الشديدَ على أنَّ مَن قَتَلَ مُعاهَدًا -وهو مَن دخل من الكفار إلى دار الإسلام بِعَهْدٍ وأمان- بأنه لن يَشمَّ رائحةَ الجنة، وإنَّ ريحَها يكون على بُعدِ مسيرة أربعين عامًا.","reference":"صحيح البخاري\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (8/ 232).\nتوضيح الأحكام شرح بلوغ المرام، للبسام (6/ 90).\nفتح ذي الجلال والإكرام بشرح بلوغ المرام، لابن عثيمين (5/ 520).\nسبل السلام، لمحمد الصنعاني (2/ 501).","benefits":["تحريم قتل المُعاهَد والذِّمِّي والمُستأمَن من الكفار، وأنه كبيرة من كبائر الذنوب.","المعاهد: هو مَن أُخِذَ عليه العهد من الكفار وهو يقيم في بلاده لا يحارب المسلمين ولايحاربونه، والذِّمِّي: هو من استوطن دارَ المسلمين ودفع الجزية، والمستأمَن: هو مَن دخل دار المسلمين بعهد وأمان لوقت محدد.","التحذير من خيانة العهود مع غير المسلمين."],"wordsMeanings":[],"category":"fiqh","bookId":"bukhari","tags":["قتل","معاهدا","يرح","رائحة","الجنة،","وإن"],"source":"hadeethenc"},{"id":"he_64689","text":"عن أبي هريرة رضي الله عنه قال: لَعَنَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ الرَّاشِيَ وَالْمُرْتَشِيَ فِي الْحُكْمِ.","attribution":"رواه الترمذي وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"دعا النبيُّ صلى الله عليه وسلم بالطرد والإبعاد من رحمة الله عز وجل لدافع الرشوة وآخذها وقابضها.\n\n\nومن ذلك ما يُدفع للقُضاة ليَحِيْفُوا في الحُكْم الذي يَتَولونه؛ ليتوصل به المُعطي إلى مراده بغير حق.","reference":"سنن الترمذي (3/ 15) (1336).\nمسند أحمد (15/ 8) (9023).\nتوضيح الأحكام مِن بلوغ المرام، للبسام (7/ 188).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (6/ 172).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (9/ 450).\nسبل السلام شرح بلوغ المرام، للصنعاني (2/ 577).","benefits":["يَحْرُمُ بذل الرشوة، وأخذُهَا، والتوسُّطُ فيها، والإعانةُ عليها؛ لما فيها من التعاون على الباطل.","الرشوة من كبائر الذنوب؛ لأنَّ رسول الله صلى الله عليه وسلم لعن آخذَها ومعطيَها.","الرشوة في باب القضاء والحُكْم أعظم جُرْمًا، وأشد إثمًا؛ لما فيها من الظلم والحكم بغير ما أنزل الله."],"wordsMeanings":[{"word":"لعن","meaning":" حقيقة اللعن الدعاء بالطرد والإبعاد عن رحمة الله تعالى."},{"word":"الراشي","meaning":" هو دافع الرشوة."},{"word":"المرتشي","meaning":" آخذ الرشوة."},{"word":"في الحكم","meaning":" في القضاء."}],"category":"fiqh","bookId":"tirmidhi","tags":["لعن","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_65000","text":"عَنْ عَبْدِ اللهِ بنِ عُمَر رضي الله عنهما قال: قال رسولُ الله صلى الله عليه وسلم: «بُنِيَ الْإِسْلَامُ عَلَى خَمْسٍ: شَهَادَةِ أَنْ لَا إِلَهَ إِلَّا اللهُ، وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ، وَإِقَامِ الصَّلَاةِ، وَإِيتَاءِ الزَّكَاةِ، وَحَجِّ الْبَيْتِ، وَصَوْمِ رَمَضَانَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"شَبَّهَ النبيُّ صلى الله عليه وسلم الإسلامَ بِبِناءٍ مُحْكَمٍ بأركانه الخمسة الحاملة لذلك البُنيان، وبقية خصال الإسلام كتتمة البنيان، \nوأولُ هذه الأركان: الشهادتان؛ شهادة أن لا إله إلا الله وأنَّ محمدًا رسول الله، وهما ركن واحد؛ لا تنفك إحداهما عن الأخرى، ينطق العبد بهما معترفًا بوحدانية الله واستحقاقه للعبادة وحده دون ما سواه، وعاملًا بمقتضاها، ومؤمنًا برسالة محمد صلى الله عليه وسلم مُتَّبِعًا له. \nوالركن الثاني: إقامة الصلاة، وهي الصلوات الخمس المفروضات في اليوم والليلة: الفجر، والظهر، والعصر، والمغرب، والعشاء، بشروطها وأركانها وواجباتها. \nوالركن الثالث: إخراج الزكاة المفروضة، وهي عبادة ماليَّة واجبة في كل مال بَلَغَ قَدْرًا مُحَدّدًا في الشرع، تُعطى لمستحقيها. \nوالركن الرابع: الحج، وهو قَصْدُ مكة لإقامة المَناسك، تَعبُّدًا لله عز وجل. \nوالركن الخامس: صوم رمضان، وهو الإمساك عن الأكل والشرب وغيرهما من المفطرات بِنِيَّةِ التعبُّد لله، من طلوع الفجر إلى غروب الشمس.","reference":"صحيح البخاري (1/ 11) (8)، صحيح مسلم (1/ 45) (16)، و(1/ 88) (82)، فتح الباري لابن رجب (1/ 22)، جامع العلوم والحكم (1/147)، شرح الأربعين لابن العطّار (ص 62)، شرح الأربعين النووية لعبد الكريم الخضير (ص 87)، فتح القوي المتين في شرح الأربعين للعباد (ص 29)، شرح الأربعين النووية لصالح آل الشيخ (ص 91 - 95)، التحفة الربانية لإسماعيل الأنصاري (ص 12).","benefits":["تلازم الشهادتين، فلا تصح أحدهما إلا بالأخرى؛ لذا جعلهما ركنًا واحدًا.","الشهادتان هما أساس الدين، فلا يُقبل قولٌ ولا عملٌ إلا بهما."],"wordsMeanings":[],"category":"fiqh","tags":["بني","الإسلام","على","خمس"],"source":"hadeethenc"},{"id":"he_65003","text":"عن جابر رضي الله عنه: أَنَّ رَجُلًا سَأَلَ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَقَالَ: أَرَأَيْتَ إِذَا صَلَّيْتُ الصَّلَوَاتِ الْمَكْتُوبَاتِ، وَصُمْتُ رَمَضَانَ، وَأَحْلَلْتُ الْحَلَالَ، وَحَرَّمْتُ الْحَرَامَ، وَلَمْ أَزِدْ عَلَى ذَلِكَ شَيْئًا، أَأَدْخُلُ الْجَنَّةَ؟ قَالَ: «نَعَمْ»، قَالَ: وَاللهِ لَا أَزِيدُ عَلَى ذَلِكَ شَيْئًا.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبي صلى الله عليه وسلم أن من صلى الصلوات الخمس المفروضات ولم يزد عليها شيئًا من النوافل، وصام رمضان ولم يتطوع، واعتقد حِلَّ الحلال وفَعَله، واعتقد حُرمة الحرام واجتنبه، أنه يدخل الجنة.","reference":"صحيح مسلم (1/ 44) (15).\nجامع العلوم والحكم (1/513). شرح الأربعين النووية للعثيمين (ص: 215).\nفتح القوي المتين في شرح الأربعين للعباد (ص 77).","benefits":["حرص المسلم على فعل الفرائض وترك المحرمات، وأن تكون غايته دخول الجنة.","أهمية فعل الحلال واعتقاد حِلَّه، وتحريم الحرام واعتقاد حرمته.","فعل الواجبات وترك المحرمات سبب لدخول الجنة."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["أرأيت","إذا","صليت","الصلوات","المكتوبات،","وصمت"],"source":"hadeethenc"},{"id":"he_65004","text":"عن أبي مالكٍ الأشعريِّ رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «الطُّهُورُ شَطْرُ الْإِيمَانِ، وَالْحَمْدُ لِلهِ تَمْلَأُ الْمِيزَانَ، وَسُبْحَانَ اللهِ وَالْحَمْدُ لِلهِ تَمْلَآنِ -أَوْ تَمْلَأُ- مَا بَيْنَ السَّمَاوَاتِ وَالْأَرْضِ، وَالصَّلَاةُ نُورٌ، وَالصَّدَقَةُ بُرْهَانٌ، وَالصَّبْرُ ضِيَاءٌ، وَالْقُرْآنُ حُجَّةٌ لَكَ أَوْ عَلَيْكَ، كُلُّ النَّاسِ يَغْدُو، فَبَايِعٌ نَفْسَهُ فَمُعْتِقُهَا أَوْ مُوبِقُهَا».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر النبي صلى الله عليه وسلم: أن طهارة الظاهر تكون بالوضوء والغسل وهي شرط في الصلاة. \nوأن قول: \" الحمد لله تملا الميزان\" وهو الثناء عليه سبحانه، ووصفه بصفات الكمال توزن يوم القيامة فتملأ ميزان الأعمال. \nوأن قول: \"سبحان الله والحمد لله\" وهو تنزيهه عن كل نَقْصٍ ووصفه بالكمال التام الذي يليق بجلاله مع محبته وتعظيمه تملأ ما بين السموات والأرض. \nوأن \"الصلاة نور\" للعبد في قلبه، وفي وجهه، وفي قبره، وفي حشره. \nوأن \"الصدقة برهان\" ودليل على صدق إيمان المؤمن، واختلافه عن المنافق الذي يمتنع منها لكونه لا يصدق بموعودها. \nوأن \"الصبر ضياء\" -وهو حبس النفس عن الجَزَع والتَّسَخُّط - نور يحصل معه حرارة وإحراق، كضياء الشمس؛ لأنه شاق ويحتاج إلى مجاهدة النفس وحبسها عما تهواه؛ فلا يزال صاحبه مستضيئًا مهتديًا مستمرًّا على الصواب. وهو صبر على طاعة الله، وعن معصيته، وصبر على المصائب وأنواع المكاره في الدنيا. \nوأن \"القرآن حجة لك\" بتلاوته والعمل به، أو \"حجة عليك\" بتركه دون عمل أو تلاوة. \nثم أخبر صلى الله عليه وسلم أن كل الناس يسعون وينتشرون ويقومون من نومهم ويخرجون من بيوتهم لأعمالهم المختلفة، \nفمنهم من يستقيم على طاعة الله فيُعْتِق نفسَه من النار، ومنهم من ينحرف عن ذلك ويقع في المعاصي فيهلكها بدخولها النار.","reference":"صحيح مسلم (1/ 203) (223)، شرح الأربعين لابن دقيق العيد (ص 84)، شرح الأربعين النووية للعثيمين (ص: 231)، الرياض الزكية شرح الأربعين النووية للخضير (ص 293)، فتح القوي المتين في شرح الأربعين للعباد (ص 79)","benefits":["الطهارة طهارتان: طهارة الظاهر تكون بالوضوء والغسل، وطهارة الباطن تكون بالتوحيد والإيمان والعمل الصالح.","أهمية المحافظة على الصلاة فهي نور للعبد في الدنيا ويوم القيامة.","الصدقة دليل على صدق الإيمان.","أهمية العمل بالقرآن وتصديقه ليكون حجة لك لا عليك.","النفس إن لم تشغلها بالطاعة شغلتك بالمعصية.","كل إنسان لا بد أن يعمل؛ فإما أن يعتق نفسه بالطاعة، أو يوبقها بالمعصية.","الصبر يحتاج إلى تَحَمُّلٍ واحتسابٍ وفيه مشقة."],"wordsMeanings":[],"category":"fiqh","bookId":"muslim","tags":["الطهور","شطر","الإيمان،","والحمد","لله","تملأ"],"source":"hadeethenc"},{"id":"he_65672","text":"عن ابن عباس رضي الله عنهما أنه سمع النبي صلى الله عليه وسلم يقول: «لا يَخْلُوَنَّ رجلٌ بامرأةٍ، ولا تسافِرَنَّ امرأةٌ إلا ومعها محرمٌ»، فقام رجل فقال: يا رسول الله، ‌اكتتبت في غزوة كذا وكذا، وخرجت امرأتي حاجة، قال: «اذهب فحج مع امرأتك».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"نهى الرسول صلى الله عليه وسلم على أن يخلو رجل بامرأة أجنبية عنه، فإن الشيطان ثالثهما إن خلا بها، ونهى أن تسافر المرأة سفرًا طويلًا أو قصيرًا وليس معها محرم أو زوج لها؛ لتأمن على نفسها، فقال رجل: يا رسول الله، كتبت اسمي في جملة من يخرج في غزوة كذا وكذا، وخرجت امرأتي لتحج، فأمره عليه الصلاة والسلام أن يحج مع امرأته، فقدم الأهم لأن الغزو يقوم غيره فيه مقامه بخلاف الحج معها وليس لها محرم غيره.\nوقوله صلى الله عليه وسلم للرجل انطلق فحج مع امرأتك هو فسخ لما كان التزم من المضي للجهاد، ويدل على تأكد أمر صيانة النساء في الأسفار، وعلى أن الزوج أحق بالسفر مع زوجته من ذوي رحمها، فهو لم يسأله: هل لها محرم أم لا؟ ولكن الشرط أن يكون معها زوج أو محرم، فلا يجب الحج على امرأة ليس لها من يحج بها.","reference":"صحيح البخاري (4/ 59) (3006)، صحيح مسلم (2/ 978) (1341)، النهاية في غريب الحديث والأثر (202) (791)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (24/ 321) (24/ 318)، إرشاد الساري لشرح صحيح البخاري (8/ 116) (5/ 140)، المفهم لما أشكل من تلخيص كتاب مسلم (3/ 453).","benefits":["النهي عن سفر المرأة بدون محرم لحج أو غيره.","تحريم الخلوة بالأجنبية.","جواز الخلوة بالمرأة إذا كان معها زوج أو محرم.","فيه تقديم الأهم فالأهم، من الأمور المتعارضة، فإنه لما عرض له الغزو والحج رجح الحج؛ لأن امرأته لا يقوم غيره مقامه في السفر معها، بخلاف الغزو.","الحج في حق مثله أفضل من الجهاد؛ لأنه اجتمع له مع حج التطوع في حقه تحصيل حج الفرض لامرأته، وكان اجتماع ذلك له أفضل من الجهاد الذي يحصل المقصود منه بغيره.","مشروعية كتابة من يشارك في الجيش.","نظر الإمام لرعيته بالمصلحة."],"wordsMeanings":[{"word":"لا يخلون","meaning":" لا ينفرد بها."},{"word":"محرم","meaning":" المحرم من لا يحل له نكاحها من الأقارب، كالأب والابن والأخ والعم ومن يجري مجراهم."},{"word":"اكتتبت","meaning":" أي: كتب اسمي في جملة الغزاة."}],"category":"fiqh","tags":["يَخْلُوَنَّ","رجلٌ","بامرأةٍ،","ولا","تسافِرَنَّ","امرأةٌ"],"source":"hadeethenc"},{"id":"he_66511","text":"عَنْ أَمِيرِ المُؤْمِنِينَ أَبِي حَفْصٍ عُمَرَ بْنِ الخَطَّابِ رضي الله عنه قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: «إنَّمَا الأَعْمَالُ بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إلَى اللَّهِ وَرَسُولِهِ، وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَنْكِحُهَا فَهِجْرَتُهُ إلَى مَا هَاجَرَ إلَيْهِ».","attribution":"رواه إماما المحدثين أبو عبد الله محمد بن إسماعيل بن إبراهيم بن المغيرة بن بردزبه البخاري،  وأبو الحسين مسلم بن الحجاج بن مسلم القشيري النيسابوري في صحيحيهما اللذين هما أصح الكتب المصنفة","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ كل الأعمال معتبرة بالنية، وهذا الحكم عام في جميع الأعمال من العبادات والمعاملات، فمن قصد بعمله منفعةً لم يَنَلْ إلا تلك المنفعة ولا ثواب له، ومن قصد بعمله التقرب إلى الله تعالى نال من عمله المثوبة والأجر ولو كان عملًا عاديًّا، كالأكل والشرب.\n\nثم ضرب صلى الله عليه وسلم مثلًا لبيان تأثير النية في الأعمال مع تساويهما في الصورة الظاهرة، فبَيَّن أنَّ من قصد بهجرته وترك وطنه ابتغاء مرضات ربه، فهجرته هجرة شرعية مقبولة يثاب عليها لصدق نيته، ومن قصد بهجرته منفعةً دنيوية، من مال، أو جاه، أو تجارة، أو زوجة، فلا ينال من هجرته إلا تلك المنفعة التي نواها، ولا نصيب له من الأجر والثواب.","reference":"صحيح البخاري (9/ 22) (6953)، (1/ 6) (1).\nصحيح مسلم (3/ 1515) (1907).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص5).\nشرح الأربعين النووية، لابن عثيمين (ص5).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص8).\nشرح النووي على مسلم (13/ 54).\nتاج العروس من جواهر القاموس، للزبيدي (7/ 196).","benefits":["الحث على الإخلاص، فإن الله لا يقبل من العمل إلا ما ابتُغي به وجهه.","الأعمال التي يُتَقَرَّبُ بها إلى الله عز وجل إذا فعلها المكلف على سبيل العادة ليس له ثواب عليها، حتى يقصِدَ بها التقرب إلى الله.","النية يفرق بها بين العبادات بعضها عن بعض وأيضًا العبادات عن العادات."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["إنما","الأعمال","بالنيات،","وإنما","لكل","امرئ"],"source":"hadeethenc"},{"id":"he_66515","text":"عَنْ أَبِي عَبْدِ اللَّهِ النُّعْمَانِ بْنِ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُ، قَالَ: سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّم يَقُولُ: «إنَّ الحَلَالَ بَيِّنٌ، وَإِنَّ الحَرَامَ بَيِّنٌ، وَبَيْنَهُمَا مُشْتَبِهَاتٌ لَا يَعْلَمُهُنَّ كَثِيرٌ مِنَ النَّاسِ، فَمَنْ اتَّقَى الشُّبُهَاتِ اسْتَبْرَأَ لِدِينِهِ وَعِرْضِهِ، وَمَنْ وَقَعَ فِي الشُّبُهَاتِ وَقَعَ فِي الحَرَامِ، كَالرَّاعِي يَرْعَى حَوْلَ الحِمَى يُوشِكُ أَنْ يَرْتَعَ فِيهِ، أَلَا وَإِنَّ لِكُلِّ مَلِكٍ حِمًى، أَلَّا وَإِنَّ حِمَى اللَّهِ مَحَارِمُهُ، أَلَّا وَإِنَّ فِي الجَسَدِ مُضْغَةً إذَا صَلَحَتْ صَلَحَ الجَسَدُ كُلُّهُ، وَإذَا فَسَدَتْ فَسَدَ الجَسَدُ كُلُّهُ، أَلَا وَهِيَ القَلْبُ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم قاعدةً عامةً في الأشياء، وأنها تنقسم في الشريعة إلى ثلاثة أقسام: حَلال بَيِّن، وحرام بَيِّن، وأمور مشتبهات غير واضحة الحكم من حيث الحِلِّ والحُرْمة، لا يعلم حُكمَها كثير من الناس.\nفمَن ترك تلك الأشياء المشتبهة عليه سَلِم دينُه بالبُعد عن الوقوع في الحرام، وسَلِم له عِرضُه من كلام الناس بما يَعيبون عليه بسبب ارتكابه هذا المشتبه. ومَن لم يجتنب المشتبهات فقد عَرَّض نفسَه إما بالوقوع في الحرام، أو نيل الناس من عرضه. وضرب الرسول صلى الله عليه وسلم مثلًا ليُبيِّن حال من يرتكب الشبهات وأنه كالراعي يرعى ماشيتَه قُرْبَ أرضٍ قد حماها صاحبها، فتوشك ماشيةُ الراعي أن ترعى في هذا الحمى لقربها منه، فكذلك من يفعل ما فيه شبهة، فإنه بذلك يقترب من الحرام فيوشك أن يقع فيه. وبعدها أخبر النبي صلى الله عليه وسلم أن في الجسد مضغة (وهي القلب) يصلح الجسد بصلاحها، ويفسد بفسادها.","reference":"صحيح البخاري (1/ 20) (52).\nصحيح مسلم (3/ 1219) (1599).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص18).\nشرح الأربعين النووية، لابن عثيمين (ص105).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص41).\nفتح الباري لابن حجر (4/ 291).\nشرح النووي على مسلم (11/ 28).","benefits":["الحديث قاعدة في اتقاء الشبهات.","الترغيب في ترك المشتبِه، الذي لم يَتبيّن حكمُه."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["الحلال","بين،","وإن","الحرام","بين"],"source":"hadeethenc"},{"id":"he_66520","text":"عَنْ أَبِي حَمْزَةَ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ -خَادِمِ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ- عَنْ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «لاَ يُؤْمِنُ أَحَدُكُمْ، حَتَّى يُحِبَّ لِأَخِيهِ مَا يُحِبُّ لِنَفْسِهِ»","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنّه لا يَتَحقّق الإيمانُ الكامل لأحدٍ من المسلمين حتى يُحبَّ لأخيه ما يحب لنفسه من الطاعات وأنواع الخيرات في الدين والدنيا، ويكره له ما يكره لنفسه، فإن رأى في أخيه المسلم نقصًا في دينه، اجتهد في إصلاحه، وإنْ رأى فيه خيرًا سدَّده وأعانه، ونصحَه في أمر دينِه أو دنياه.","reference":"صحيح البخاري (1/ 12) (13).\nصحيح مسلم (1/ 67) (45).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، مطبعة دار نشر الثقافة، الإسكندرية، الطبعة: الأولى، 1380 هـ.\nشرح الأربعين النووية، للشيخ ابن عثيمين، دار الثريا للنشر.\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، دار ابن القيم، الدمام المملكة العربية السعودية، الطبعة: الأولى، 1424هـ/2003م.\nالفوائد المستنبطة من الأربعين النووية، للشيخ عبد الرحمن ا","benefits":["وجوب محبة المرء لأخيه ما يحبُّ لنفسه؛ لأن نفي الإيمان عمن لا يحب لأخيه ما يحب لنفسه يدل على وجوب ذلك.","الأُخوّة في الله فوق أخوّة النسب، فحقُّها أوجب.","تحريم كل ما ينافي هذه المحبة من الأقوال والأفعال كالغش والغيبة والحسد والعدوان على نفس المسلم أو ماله أو عرضه.","استخدام بعض الألفاظ المحفِّزة على الفعل؛ لقوله \"لأخيه\".","قال الكِرْماني رحمه الله: ومن الإيمان أيضًا أنْ يُبغِضَ لأخيه ما يبغض لنفسه من الشر، ولم يذكره؛ لأنَّ حب الشيء مستلزم لبغض نقيضه، فترك التنصيص عليه اكتفاء."],"wordsMeanings":[],"category":"fadail","tags":["يؤمن","أحدكم،","حتى","يحب","لأخيه","يحب"],"source":"hadeethenc"},{"id":"he_66523","text":"عَنْ أَبِي مَسْعُودٍ عُقْبَةَ بْنِ عَمْرٍو الأَنْصَارِيِّ البَدْرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ: «إِنَّ مِمَّا أَدْرَكَ النَّاسُ مِنْ كَلاَمِ النُّبُوَّةِ الأُولَى: إِذَا لَمْ تَسْتَحْيِ فَاصْنَعْ مَا شِئْتَ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنَّ مما جاء فيه الوصية عن الأنبياء المتقدِّمين، وتَدَاوَلَه الناس بينهم وتوارثوه عنهم قرنًا بعد قرن، حتى وصل إلى أوّل هذه الأمة، انظر إلى ما تريد أنْ تَفعلَه، فإنْ كان ممّا لا يُستَحى منه فافعله، وإنْ كان ممّا يُستَحى منه فَدَعْه؛ فإنَّ المانع مِن فِعْل القبائح هو الحياء، فمَن لم يكن له حياءٌ، انْهَمَك في كلّ فَحْشاء ومُنكر.","reference":"صحيح البخاري (8/ 29) (6120).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (2/ 1252).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص1045).\nشرح رياض الصالحين، لابن عثيمين (6/ 656).","benefits":["الحياء أصل الأخلاق الكريمة.","الحياء صفة من صفات الأنبياء عليهم السلام، وهو من المأثور عنهم.","الحياء هو الذي يجعل المرء المسلم يفعل ما يُجَمِّلُ ويَزِيْن، ويَترك ما يُدّنِّس ويَشَيْن.","قال النووي: الأمر فيه للإباحة، أي: إذا أردت فعل شيء فإن كان مما لا تستحي إذا فعلتَه من الله ولا من الناس فافعله، وإلا فلا، وعلى هذا مدار الإسلام، وتوجيه ذلك أنَّ المأمورَ به الواجب والمندوب يُستحيَى مِن تَرْكِه، والمنهي عنه الحرام والمكروه يُستحيى من فعله، وأما المباح فالحياء من فعله جائز، وكذا مِن تركه، فتضمن الحديث الأحكام الخمسة، وقيل: هو أمرُ تهديد، ومعناه: إذا نُزِع مِنك الحياء فافعل ما شئت؛ فإنّ الله مجازيك عليه، وقيل: هو أمرٌ بمعنى الخبر، أي: مَن لا يَستحيي يَصنع ما أراد."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["مما","أدرك","الناس","كلام","النبوة","الأولى:"],"source":"hadeethenc"},{"id":"he_66538","text":"عَنْ عُمَرَ بْنِ الخَطَّابِ رَضِيَ اللَّهُ عَنْهُ عَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ: «لَوْ أَنَّكُمْ كُنْتُمْ تَوَكَّلُونَ عَلَى اللهِ حَقَّ تَوَكُّلِهِ لَرَزَقَكُمْ كَمَا يَرْزَقُ الطَّيْرَ تَغْدُو خِمَاصًا وَتَرُوحُ بِطَانًا».","attribution":"رواه الإمام أحمد، والترمذي، والنسائي، وابن ماجه، وابن حبان في صحيحه، والحاكم","grade":"صحيح","gradeKey":"sahih","explanation":"يَحُثُّنا النبيُّ صلى الله عليه وسلم أن نَعتَمِد على الله عز وجل في استجلاب المنافع ودفع المضار في أمور الدنيا والدين، فإنه لا يُعطي ولا يَمنع ولا يَضر ولا يَنفع إلا هو سبحانه وتعالى، وأن نفعل الأسباب التي تَجْلُب المنافع وتدفع المضار مع صدق الاعتماد على الله، فمتى فعلنا ذلك رزَقَنا اللهُ كما يرزق الطير التي تخرج صباحًا وهي جياع، ثم تعود مساءً وهي ممتلئة البطون، وهذا الفعلُ من الطير نوعٌ من الأسباب في السعي لطلب الرزق، دون التواكل والتكاسل.","reference":"سنن الترمذي (4/ 151) (2344).\nسنن ابن ماجه (5/ 266) (4164).\nمسند أحمد (1/ 332) (205).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص103).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص152).\nالأحاديث الأربعون النووية وعليها الشرح الموجز المفيد، لعبد الله المحسن (ص91).","benefits":["فضيلة التوكل، وأنه من أعظم الأسباب التي يُسْتَجْلَبُ بها الرزق.","التوكل لا ينافي فعل الأسباب، فإنه أخبر أن التوكل الحقيقي لا يضادُّه الغدوُّ والرَّوَاحُ في طلب الرزق.","اهتمام الشريعة بأعمال القلوب؛ لأن التوكل عمل قلبيٌّ.","التعلق بالأسباب فقط نقصٌ في الدين، وترك الأسباب نقصٌ في العقل."],"wordsMeanings":[],"category":"fadail","bookId":"tirmidhi","tags":["أنكم","كنتم","توكلون","على","الله","توكله"],"source":"hadeethenc"},{"id":"he_66540","text":"عَنِ النَّوَّاسِ بْنِ سِمْعَانَ رَضِيَ اللهُ عَنْهُ عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «البِرُّ: حُسْنُ الخُلُقِ، وَالإِثْمُ مَا حَاكَ فِي صَدْرِكَ، وَكَرِهْتَ أَنْ يَطَّلِعَ عَلَيْهِ النَّاسُ».   \nوَعَنْ وَابِصَةَ بْنِ مَعْبَدٍ رَضِيَ اللَّهُ عَنْهُ قَالَ: أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فَقَالَ: «جِئْتَ تَسْأَلُ عَنِ البِرِّ وَالإِثْمِ»، قُلْتُ: نَعَمْ، قَالَ: «اسْتَفْتِ قَلْبَكَ، البِرُّ: مَا اطْمَأَنَّتْ إلَيْهِ النَّفْسُ، وَاطْمَأَنَّ إلَيْهِ القَلْبُ، وَالإِثْمُ: مَا حَاكَ فِي نَفْسِكَ وَتَرَدَّدَ فِي الصَّدْرِ، وَإِنْ أَفْتَاكَ النَّاسُ وَأَفْتَوْكَ».","attribution":"الحديث الأول: رواه مسلم، والحديث الثاني: رواه أحمد والدارمي.","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم عن البر والإثم، فقال: إن أعظم خصال البر حسن الخُلُق مع الله بالتقوى، ومع الخَلْق باحتمال الأذى، وقلة الغضب، وبسط الوجه، وطيب الكلام، والصلة والطاعة واللطف والمبرة وحسن العشرة والصحبة. وأن البر ما سكن إليه القلب والنفس.\nوأما الإثم فما تحرك في النفس من المشتبهات وتردد دون أن ينشرح الصدر له، وحصل في القلب منه الشك، والخوف من كونه ذنبًا، ولم تُرد أن تظهره لكونه قبيحًا لأعيان وأماثل الناس وكُمَّلِهم، وذلك لأن النفس بطبعها تحب اطلاع الناس على خيرها، فإذا كَرِهَت الاطلاع على بعض أفعالها فهو إثم لا خير فيه؛ وإن أفتاك الناس فلا تأخذ بفتواهم ما دامت علامة الشبهة تتردد في نفسك  فإن الفتوى لا تزيل الشبهة ما دامت الشبهة صحيحة وكان المفتي يفتي بغير علم؛ أما إذا كانت الفتوى بناء على دليل شرعي فالواجب على المستفتي الرُّجوعُ إليه، وإنْ لم ينشرح له صدرُه.","reference":"صحيح مسلم (4/ 1980) (2553).\nالتحفة الربانية في شرح الأربعين حديثًا النووية التحفة الربانية (ص62).\nشرح الأربعين النووية، لابن عثيمين (ص267).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للنووي وابن رجب رحمهما الله (ص92).","benefits":["الحثُّ على مكارم الأخلاق؛ لأنّ حسن الخلق من أعظم خصال البر.","الحق والباطل لا يلتبس أمرُهما على المؤمن، بل يعرف الحق بالنور الذي في قلبه، وينفر عن الباطل فينكره.","من علامات الإثم قلق القلب واضطرابه، وكراهة اطلاع الناس عليه.","قال السندي: هذا في المشتبهات من الأمور التي لا يعلم الناس فيها بتعيين أحد الطرفين؛ وإلا فالمأمور به في الشرع من غير ظهور دليل فيه على خلاف ذلك من البر، والمنهي عنه كذلك من الإثم، ولا حاجة فيهما إلى استفتاء القلب وطمأنينته.","المخاطَب في الحديث أصحاب الفطرة السليمة، لا أصحاب القلوب المنكوسة التي لا تعرف معروفًا ولا تنكر منكرًا إلا ما أُشرِبتْ من هواها.","قال الطيبي: قيل فُسِّرَ البر في الحديث بمعان شتى، ففسَّره في موضع بما اطمأنت إليه النفس واطمأن إليه القلب، وفسره في موضع بالإيمان، وفي موضع بما يقربك إلى الله، وهنا بحسن الخلق، وفسر حسن الخلق: باحتمال الأذى وقلة الغضب وبسط الوجه وطيب الكلام، وكلها متقاربة في المعنى."],"wordsMeanings":[],"category":"fadail","bookId":"muslim","tags":["البر:","حسن","الخلق،","والإثم","حاك","صدرك،"],"source":"hadeethenc"},{"id":"he_66541","text":"عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ رَضِيَ اللَّهِ عَنْهُ قَالَ: أَتَى النَّبِيَّ رَجُلٌ، فَقَالَ: يَا رَسُولَ اللَّهِ! إِنَّ شَرَائِعَ الإِسْلَامِ قَدْ كَثُرَتْ عَلَيْنَا، فَبَابٌ نَتَمَسَّكُ بِهِ جَامِعٌ؟ قَالَ: «لاَ يَزَالُ لِسَانُكَ رَطْبًا مِنْ ذِكْرِ اللَّهِ». \nوفي رواية: مِنْ حَدِيثِ مُعَاذِ بْنِ جَبَلٍ رَضِيَ اللَّهُ عَنْهُ: آخِرُ مَا فَارَقْتُ عَلَيْهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ قُلْتُ: أَيُّ الأَعْمَالِ خَيْرٌ وَأَقْرَبُ إِلَى اللَّهِ؟ قَالَ: «أَنْ تَمُوتَ وَلِسَانُكَ رَطْبٌ مِنْ ذِكْرِ اللَّهِ عَزَّ وَجَلَّ».","attribution":"رواه أحمد والترمذي وابن ماجه وابن حبان","grade":"صحيح","gradeKey":"sahih","explanation":"شَكَى رجلٌ إلى النبيِّ صلى الله عليه وسلم بأن نوافل العبادات قد كَثرت عليه حتى عجز عنها لضعفه، ثم سألَ النبيَّ صلى الله عليه وسلم أنْ يَدلَّه على عملٍ يسيرٍ مُسْتجلِبٍ لثواب كثير يتعلق به ويستمسك.\nفأرشده صلى الله عليه وسلم بأن يكون لسانه طَرِيًّا متحركًا من دوام ذكر الله سبحانه وتعالى في كل وقت وحال؛ من تسبيح وتحميد واستغفار ودعاء ونحو ذلك.","reference":"سنن الترمذي (5/ 318) (3375).\nسنن ابن ماجه (4/ 707) (3793).\nمسند أحمد (29/ 226) (17680).\nجامع العلوم والحكم في شرح خمسين حديثا من جوامع الكلم، لابن رجب الحنبلي (2/ 510).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، لإسماعيل الأنصاري (ص104).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للنووي وابن رجب (ص154).\nالأحاديث الأربعون النووية وعليها الشرح الموجز المفيد، لعبد الله بن صالح المحسن (ص93).","benefits":["فضل المداومة على ذكر الله تعالى.","من عظيم فضل الله تيسير أسباب الأجر.","تفاضل العباد في نصيبهم من أبواب البر والخير.","كثرة ذكر الله باللسان تسبيحًا وتحميدًا وتهليلًا وتكبيرًا وغير ذلك مع مواطأة القلب يقوم مقام كثير من نوافل الطاعات.","مراعاته صلى الله عليه وسلم للسائلين بإجابة كلٍّ بما يناسبه."],"wordsMeanings":[],"category":"fadail","bookId":"tirmidhi","tags":["يزال","لسانك","رطبا","ذكر","الله"],"source":"hadeethenc"},{"id":"he_2941","text":"عن أبي بكرة رضي الله عنه قال: قال النبي صلى الله عليه وسلم: «‌أَلَا ‌أُنَبِّئُكُمْ بِأَكْبَرِ الْكَبَائِرِ؟» ثَلَاثًا، قَالُوا: بَلَى يَا رَسُولَ اللهِ، قَالَ: «الْإِشْرَاكُ بِاللهِ، وَعُقُوقُ الْوَالِدَيْنِ» وَجَلَسَ وَكَانَ مُتَّكِئًا، فَقَالَ: «أَلَا وَقَوْلُ الزُّورِ»، قَالَ: فَمَا زَالَ يُكَرِّرُهَا حَتَّى قُلْنَا: لَيْتَهُ سَكَتَ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أصحابَه عن أعظم الكبائر، فذَكرَ هذه الثلاث:\n\n1. الإشراك بالله: وهو صَرْفُ أيِّ نوعٍ من أنواع العبادة لغير الله، وتسويةُ غيرِ الله بالله في ألوهيته وربوبيته وأسمائه وصفاته. \n\n2. عقوق الوالدين: وهو كلُّ أذى للأبوين، قولًا كان أو فعلًا، وترك الإحسان إليهما. \n\n3. قول الزور ومنه شهادة الزور: وهو كل قول مُزوَّر ومكذوب يراد به انتقاص مَن وقع عليه بأخذ ماله أو الاعتداء على عرضه أو نحو ذلك.\n\nوقد كَرَّر النبيُّ صلى الله عليه وسلم التحذيرَ من قول الزور تنبيهًا على استقباحِه وآثارِه السيئة على المجتمع، حتى قال الصحابة: ليته سكت؛ شَفقةً عليه، وكراهية لِما يُزعجه.","reference":"صحيح البخاري (3/ 172) (2654)، (8/ 4) (5976)، (8/ 62) (6273-6274).\nصحيح مسلم (1/ 91) (87).\nعمدة الأحكام من كلام خير الأنام صلى الله عليه وسلم (ص257) (380).\nشرح النووي على مسلم (2/ 81).\nالإلمام بشرح عمدة الأحكام لإسماعيل الأنصاري (2/ 149).\nتيسير العلام شرح عمدة الأحكام للبسام (ص703).\nأعلام السنة المنشورة لاعتقاد الطائفة الناجية المنصورة، لحافظ بن أحمد الحكمي (ص111).","benefits":["أعظم الذنوب الشركُ بالله؛ لأنه جعلَه صَدْرَ الكبائر وأكبرَها، ويؤكد هذا قوله تعالى {إن الله لا يَغْفِرُ أن يشرَكَ به وَيَغْفِرُ مَا دونَ ذلِكَ لِمَنْ يشَاء}.","عظم حقوق الوالدين، إذ قَرَنَ حقَّهما بحق الله تعالى.","الذنوب تنقسم إلى كبائر وصغائر، والكبيرة هي: كلُّ ذنب فيه عقوبة دنيوية، كالحدود واللعن، أو وعيد أُخروي، كالوعيد بدخول النار، وأن الكبائر دركات بعضها أغلظ من بعض في التحريم، وصغائر الذنوب هي ما سوى الكبائر."],"wordsMeanings":[{"word":"ألا أنبئكم","meaning":" أَلا أخبركم."}],"category":"fadail","tags":["ألا","أنبئكم","بأكبر","الكبائر؟"],"source":"hadeethenc"},{"id":"he_3017","text":"عن المِقدام بن معدي كرب رضي الله عنه عن النبي صلى الله عليه وسلم قال: «إِذَا أَحَبَّ الرَّجُلُ أَخَاهُ فَلْيُخْبِرْهُ أَنَّهُ يُحِبُّهُ».","attribution":"رواه أبو داود والترمذي والنسائي في الكبرى وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّن النبي صلى الله عليه وسلم أحد الأسباب التي تُقوِّي العلاقة بين المؤمنين وتنشر المحبة بينهم، وهو أنه إذا أحبَّ أحدٌ أخاه فليخبره بأنه يحبه.","reference":"سنن أبي داود (7/ 444) (5124).\nسنن الترمذي (4/ 199) (2392).\nالسنن الكبرى للنسائي (9/ 87) (9963).\nمسند أحمد (28/ 408) (17171).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 450).\nتطريز رياض الصالحين، لفيصل المبارك (ص258).\nرياض الصالحين للنووي، (ص138) (383).\nسلسلة الأحاديث الصحيحة وشيء من فقهها وفوائدها، للألباني (1/ 777).\nفيض القدير شرح الجامع الصغير، للمناوي (1/ 247).\nكنوز رياض الصالحين، لمجمو","benefits":["فضل المحبة الخالصة لله تعالى، لا لمصلحة دنيوية.","استحباب إخبار المحبوب في الله بحبِّه، لتزداد المحبة والألفة.","إشاعة المحبة بين المؤمنين يقوّي الأخوة الإيمانية، ويحافظ على المجتمع من التفكُّك والفُرْقة."],"wordsMeanings":[],"category":"fadail","bookId":"abudawud","tags":["إذا","أحب","الرجل","أخاه","فليخبره","أنه"],"source":"hadeethenc"},{"id":"he_3044","text":"عن عبد الله بن عمرو بن العاص رضي الله عنهما عن النبي صلى الله عليه وسلم قال: «الْكَبَائِرُ: الْإِشْرَاكُ بِاللهِ، وَعُقُوقُ الْوَالِدَيْنِ، وَقَتْلُ النَّفْسِ، وَالْيَمِينُ الْغَمُوسُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم كبائر الذنوب، وهي التي تُوُعِّدَ فاعلُها بوعيد شديد في الدنيا أو الآخرة. \n\nفأوَّلُها \"الإِشرَاكُ بِالله\": وهو صَرْفُ أيِّ نوع من أنواع العبادة لغير الله، وتسوية غير الله بالله فيما هو من خصائص الله في ألوهيته وربوبيته وأسمائه وصفاته. \n\nوثانيها \"عُقُوقُ الوَالِدَينِ\": وهو كلُّ ما يوجب الأذى للأبوين قولًا كان أو فعلًا، وترك الإحسان إليهما. \n\nوثالثها \"قَتْل النَّفْس\": بغير حق، كالقتل ظلمًا وعدوانًا. \n\nورابعها \"اليَمِين الغَمُوسُ\": وهي الحلف كاذبًا على علم منه بكذبه، سميت بذلك؛ لأنَّها تَغْمِسُ صاحبَها في الإِثم أو في النار.","reference":"صحيح البخاري (8/ 137) (6675).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 408).\nرياض الصالحين للنووي (ص125) (337).\nكنوز رياض الصالحين، لمجموعة من الباحثين (5/ 610).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص964).","benefits":["اليمين الغموس لا كفارة لها؛ لشدة خطرها وجرمها، وإنما فيها التوبة.","الاقتصار على ذكر هذه الكبائر الأربع في الحديث لعظيم إثمها، وليس لحصرها.","الذنوب تنقسم إلى كبائر وصغائر، والكبيرة هي: كلُّ ذنب فيه عقوبة دنيوية، كالحدود واللعن، أو وعيد أُخروي، كالوعيد بدخول النار، وأن الكبائر دركات بعضها أغلظ من بعض في التحريم، وصغائر الذنوب هي ما سوى الكبائر."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["الكبائر:","الإشراك","بالله،","وعقوق","الوالدين،","وقتل"],"source":"hadeethenc"},{"id":"he_3135","text":"عَنْ أَبِي هُرَيْرَةَ قَالَ: قَالَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «السَّاعِي عَلَى الأَرْمَلَةِ وَالمِسْكِينِ، كَالْمُجَاهِدِ فِي سَبِيلِ اللَّهِ، أَوِ القَائِمِ اللَّيْلَ الصَّائِمِ النَّهَارَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ الذي يقوم بمصالِحِ المرأةِ التي مات عنها زوجُها وليس لها أحدٌ يقوم بشؤونِها، والمسكينِ المُحتاج، ويُنفِقُ عليهم محتسبًا الأجرَ عند الله تعالى، فهو في الأجر كالمجاهد في سبيل الله، أو كالقائم في صلاة التهجد الذي لا يَتعب، الصائم الذي لا يفطر.","reference":"صحيح البخاري (7/ 62) (5353).\nصحيح مسلم (4/ 2286) (2982).\nبهجة الناظرين شرح رياض الصالحين، لسليم بن عيد الهلالي (1/ 351).\nتطريز رياض الصالحين، لفيصل بن عبد العزيز المبارك (ص198).\nرياض الصالحين (ص107) (265).\nشرح رياض الصالحين، لابن عثيمين (3/ 99).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (275).","benefits":["الحثُّ على التعاون والتكافل وسَدّ حاجات الضعفاء.","العبادة تشمل كلَّ عمل صالح، ومن العبادة السعي على الأرملة والمسكين.","قال ابن هبيرة: والمراد أن الله تعالى يجمع له ثواب الصائم والقائم والمجاهد في دفعة؛ وذلك أنه قام للأرملة مقام زوجها ...، وقام على ذلك المسكين الذي عجز عن قيامه بنفسه، فأنفق هذا فضل قوته، وتصدق بجَلَدِه، فكان نفعه إذًا  يكافئ الصوم والقيام والجهاد."],"wordsMeanings":[],"category":"fadail","tags":["الساعي","على","الأرملة","والمسكين،","كالمجاهد","سبيل"],"source":"hadeethenc"},{"id":"he_3331","text":"عن أبي هريرة رضي الله عنه عن النبي صلى الله عليه وسلم قال: «اجْتَنِبُوا السَّبْعَ الْمُوبِقَاتِ»، قَالُوا: يَا رَسُولَ اللهِ وَمَا هُنَّ؟ قَالَ: «الشِّرْكُ بِاللهِ، وَالسِّحْرُ، وَقَتْلُ النَّفْسِ الَّتِي حَرَّمَ اللهُ إِلَّا بِالْحَقِّ، وَأَكْلُ الرِّبَا، وَأَكْلُ مَالِ الْيَتِيمِ، وَالتَّوَلِّي يَوْمَ الزَّحْفِ، وَقَذْفُ الْمُحْصَنَاتِ الْمُؤْمِنَاتِ الْغَافِلَاتِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يأمرُ رسولُ الله صلى الله عليه وسلم أمَّتَه بالابتعاد عن سبع جرائم ومَعاصٍ مهلكاتٍ، ولما سُئل عنها: ما هي؟ بيّنها بأنها:\n\n أولًا: الشرك بالله، باتخاذ النظير والمثيل له سبحانه من أي شكل كان، وصَرْف أي عبادة من العبادات لغير الله تعالى، وبدأ بالشرك؛ لأنه أعظم الذنوب.\n\nثانيًا: السحر -وهو عبارة عن عُقََد ورُقَى وأدوية وتدخينات-، يؤثِّر في بَدَن المسحور بالقتل أو بالمرض، أو يفرِّق بين الزوجين، وهو عمل شيطاني، وكثير منه لا يُتَوَصَّل إليه إلا بالشرك والتقرّب إلى الأرواح الخبيثة بشيء مما تحب.\n\nثالثًا: قتل النفس التي منع الله من قتلها إلا بمسوِّغٍ شرعي يُنفِّذُه الحاكم.\n\nرابعًا: تناول الربا بأكلٍ أو بغيره من وجوه الانتفاع.\n\nخامسًا: التعدِّي على مال الصغير الذي مات أبوه وهو دون البلوغ.\n\nسادسًا: الفرار من المعركة مع الكفار.\n\nسابعًا: اتهام الحرائر العفيفات بالزنا، وكذلك اتهام الرجال.","reference":"صحيح البخاري (4/ 10) (2766).\nصحيح مسلم (1/ 92) (89).\nشرح صحيح البخارى لابن بطال (8/ 489).\nالملخص في شرح كتاب التوحيد، للشيخ صالح الفوزان (ص201).","benefits":["الكبائر ليست محصورة في سبع، وتخصيص هذه السبع لِعِظَمِها وخطرِها.","جواز قتل النفس إذا كان بحقٍّ، كالقصاص والردة والزنا بعد إحصان، وينفِّذه الحاكم الشرعي."],"wordsMeanings":[],"category":"fadail","tags":["اجتنبوا","السبع","الموبقات"],"source":"hadeethenc"},{"id":"he_3350","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «لَا تَجْعَلُوا بُيُوتَكُمْ قُبُورًا، وَلَا تَجْعَلُوا قَبْرِي عِيدًا، وَصَلُّوا عَلَيَّ؛ فَإِنَّ صَلَاتَكُمْ تَبْلُغُنِي حَيْثُ كُنْتُمْ».","attribution":"رواه أبو داود","grade":"حسن","gradeKey":"hasan","explanation":"يَنهى النبيُّ صلى الله عليه وسلم عن تعطيل البيوت من الصلاة فتكون كالمقابر التي لا يصلى فيها.\n\nونهى عن تَكرار زيارة قبره والاجتماع عنده على وجهٍ معتاد؛ لأن ذلك وسيلةٌ إلى الشرك.\n\nوأمر بالصلاة والسلام عليه في أي مكان من الأرض؛ لأن ذلك يبلغه من القريب والبعيد على حدٍّ سواء، فلا حاجة إلى التردد إلى قبره.","reference":"سنن أبي داود (3/ 385) (2042).\nالجديد في شرح كتاب التوحيد، لمحمد القرعاوي (ص202).\nالملخص في شرح كتاب التوحيد، لصالح الفوزان (ص185).","benefits":["النهي عن تعطيل البيوت من عبادة الله تعالى.","المنع من السفر لزيارة قبر النبي عليه الصلاة والسلام؛ لأنه أمر بالصلاة عليه وأخبر أنها تبلغه، وإنما تُشَدُّ الرحال لقصد المسجد والصلاة فيه.","تحريم جعل زيارة قبر النبي صلى الله عليه وسلم عيدًا، بتكرير زيارته على وجه مخصوص في زمن مخصوص، وكذلك زيارة كل قبر.","كرامة النبي صلى الله عليه وسلم على ربه، بمشروعية الصلاة والسلام عليه في كل زمان ومكان.","حيث أن النهي عن الصلاة عند القبور قد تقرر عند الصحابة؛ لذا نهى النبي صلى الله عليه وسلم أن تجعل البيوت مثل المقابر لا يُصلى فيها."],"wordsMeanings":[{"word":"ولا تجعلوا قبري عيدًا","meaning":" العيد: ما يعتاد مجيئه وقصده من زمان ومكان، أي: لا تتخذوا قبري محل اجتماعٍ تترددون إليه وتعتادونه للصلاة والدعاء وغير ذلك."}],"category":"fadail","bookId":"abudawud","tags":["تجعلوا","بيوتكم","قبورا،","ولا","تجعلوا","قبري"],"source":"hadeethenc"},{"id":"he_3475","text":"عن سهل بن سعد رضي الله عنه عن رسول الله صلى الله عليه وسلم قال: «مَنْ يَضْمَنْ لِي مَا بَيْنَ لَحْيَيْهِ وَمَا بَيْنَ رِجْلَيْهِ أَضْمَنْ لَهُ الْجَنَّةَ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم عن أمرين إذا التزَمَ المسلمُ بهما فإنه يدخل الجنة:\n\nالأول: حفظ اللسان من التكلم بما يغضب الله تعالى.\n\nوالثاني: حفظ الفرج من الوقوع في الفاحشة.\n\nلأن هذين العضوين يكثر وقوع المعاصي بهما.","reference":"صحيح البخاري (8/ 100) (6474).\nبهجة الناظرين شرح رياض الصالحين، تأليف سليم الهلالي (3/ 9).\nنزهة المتقين شرح رياض الصالحين، تأليف د. مصطفى الخِن وغيره (2/ 1035).\nكنوز رياض الصالحين، لمجموعة من الباحثين (18/ 85).\nشرح رياض الصالحين، لابن عثيمين (6/ 117).\nإرشاد الساري لشرح صحيح البخاري، للقسطلاني (9/ 272).","benefits":["حفظ اللسان والفرج سبيلٌ لدخول الجنة.","خُصَّ اللسان والفرج؛ لأنهما أعظم مَصدَر للبلاء على الإنسان في الدنيا والآخرة."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["يضمن","بين","لحييه","وما","بين","رجليه"],"source":"hadeethenc"},{"id":"he_3567","text":"عن جابر رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «أَفْضَلُ الذِّكْرِ: لَا إِلَهَ إِلَّا اللهُ، وَأَفْضَلُ الدُّعَاءِ: الْحَمْدُ لِلهِ».","attribution":"رواه الترمذي والنسائي في الكبرى وابن ماجه","grade":"حسن","gradeKey":"hasan","explanation":"يُخبرُنا النبيُّ صلى الله عليه وسلم أن أفضل الذكر: \"لا إله إلا الله\" ومعناها لا معبود بحق إلا الله، وأن أفضل الدعاء: \"الحمد لله\" وهي الاعتراف بأن المُنعم هو الله سبحانه، المُستحِق للوصف الكامل الجميل.","reference":"سنن الترمذي (5/ 393) (3383).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (2/ 984).\nزاد المعاد في هدي خير العباد، ابن قيم الجوزية (1/ 36).","benefits":["الحث على الإكثار من ذكر الله بكلمة التوحيد، والدعاء بالحمد."],"wordsMeanings":[],"category":"fadail","bookId":"tirmidhi","tags":["أفضل","الذكر:","إله","إلا","الله،","وأفضل"],"source":"hadeethenc"},{"id":"he_3581","text":"عن ابن مسعود رضي الله عنه قال: قال النبي صلى الله عليه وسلم: «الْجَنَّةُ أَقْرَبُ إِلَى أَحَدِكُمْ مِنْ شِرَاكِ نَعْلِهِ، وَالنَّارُ مِثْلُ ذَلِكَ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أَخبَرَ النبيُّ صلى الله عليه وسلم أنَّ الجنة والنار قريبتان من الإنسان كقُربِ سَيْرِ الحِذاء الذي يكون على ظَهر القَدَم؛ لأنه قد يفعل طاعةً من رضوان الله عز وجل يدخل بها الجنة، أو معصيةً تكون سببًا لدخول النار.","reference":"صحيح البخاري (8/ 102) (6488).\nشرح رياض الصالحين، لابن عثيمين (2/ 99).\nفتح الباري، لابن حجر(11/ 321).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 186).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 136).","benefits":["الترغيب في الخير وإن قلَّ، والترهيب عن الشر وإن قلَّ.","لا بد للمسلم في حياته من الجمع بين الرجاء والخوف، وسؤال الله سبحانه دومًا الثبات على الحق حتى يَسْلَمَ ولا يَغْتَرَّ بحالِه."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["الجنة","أقرب","إلى","أحدكم","شراك","نعله،"],"source":"hadeethenc"},{"id":"he_3701","text":"عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ وَعَنْ أَبِي هُرَيْرَةَ رضي الله عنهما عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ: «مَا يُصِيبُ الْمُسْلِمَ مِنْ نَصَبٍ وَلَا وَصَبٍ وَلَا هَمٍّ وَلَا حُزْنٍ وَلَا أَذًى وَلَا غَمٍّ حَتَّى الشَّوْكَةِ يُشَاكُهَا إِلَّا كَفَّرَ اللهُ بِهَا مِنْ خَطَايَاهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ الرسولُ صلى الله عليه وسلم أنَّ ما يُصاب به المسلمُ مِن أمراضٍ وهمومٍ وأحزانٍ وكروبٍ ومصائبَ وشدائدَ وخوفٍ وجوعٍ -حتى لو كانت شوكة تُصيبه فَتُؤْلِمُه-، يكونُ ذلك كفارةً لذنوبه وحطًّا لخطاياه.","reference":"صحيح البخاري (7/ 114) (5641).\nصحيح مسلم (4/ 1992) (2572).\nكنوز رياض الصالحين، لمجموعة من الباحثين (1/ 489).\nشرح رياض الصالحين، لابن عثيمين (1/ 242).\nشرح النووي على مسلم (16/ 126).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص44).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 96).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 70).","benefits":["بيان فضل الله على عباده المؤمنين ورحمته بهم بغفران الذنوب بأقل ضرر يصيبهم.","ينبغي للمسلم أن يَحْتَسِبَ عند الله ما يُصيبه، ويَصبر على كل صغيرة وكبيرة، لتكون له رفعة في الدرجات وكفارة للسيئات."],"wordsMeanings":[{"word":"نصب","meaning":" التعب."},{"word":"وصب","meaning":" المرض ."}],"category":"fadail","tags":["يصيب","المسلم","نصب","ولا","وصب","ولا"],"source":"hadeethenc"},{"id":"he_3702","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «حُجِبَتِ النَّارُ بِالشَّهَوَاتِ، وَحُجِبَتِ الْجَنَّةُ بِالْمَكَارِهِ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُبيِّنُ النبيُّ صلى الله عليه وسلم أنَّ النارَ مَحفوفةٌ مُحاطةٌ بالأمور التي تَشتَهيها النفس مِن فِعْل المحرّمات أو التقصير في الواجبات، فمن أَتْبعَ نفسَه هواها في ذلك استحقَّ النار.\n\n \nوأنَّ الجنةَ محفوفةٌ محاطةٌ بالأمور التي تَكرهها النفس؛ كالمُواظَبةِ على المأمورات وترك المحرمات والصبر على ذلك، فإذا صبر وجاهد نفسه على فعل الطاعة وترك المعصية؛ دخل الجنة.","reference":"صحيح البخاري (8/ 102) (6487).\nصحيح مسلم (4/ 2174) (2822).\nسنن أبي داود (7/ 122) (4744).\nسنن الترمذي (4/ 274) (2560).\nسنن النسائي (7/ 3) (3763).\nكنوز رياض الصالحين، لمجموعة من الباحثين (2/ 449).\nشرح رياض الصالحين، لابن عثيمين (2/ 87).\nالمنهاج شرح صحيح مسلم بن الحجاج، للنووي (17/ 165).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 183).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 134","benefits":["من أسباب الوقوع في الشهوات تزيينُ الشيطانِ المنكرَ والقبيحَ، حتى تراه النفس حسنًا فتَميلُ إليه.","الأمر بالابتعاد عن الشهوات المحرمة؛ لأنها الطريق إلى النار، والصبر على المكاره؛ لأنها الطريق إلى الجنة.","فضل مجاهدة النفس والاجتهاد في العبادة والصبر على المكاره والمشاق التي تحيط بالطاعات."],"wordsMeanings":[{"word":"حُجبت","meaning":" حُفت وأُحيطت."}],"category":"fadail","bookId":"bukhari","tags":["حجبت","النار","بالشهوات،","وحجبت","الجنة","بالمكاره"],"source":"hadeethenc"},{"id":"he_3706","text":"عن أبي هريرة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «حَقُّ الْمُسْلِمِ عَلَى الْمُسْلِمِ خَمْسٌ: رَدُّ السَّلَامِ، وَعِيَادَةُ الْمَرِيضِ، وَاتِّبَاعُ الْجَنَائِزِ، وَإِجَابَةُ الدَّعْوَةِ، وَتَشْمِيتُ الْعَاطِسِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبيِّنُ النبيُّ صلى الله عليه وسلم بعضَ حقوق المسلم على أخيه المسلم:\n\n\nأول هذه الحقوق: ردُّ السلام لمن ألقى عليك السلام.\n\nالحق الثاني: عيادة المريض وزيارته.\n\n الحق الثالث: اتباع الجنازة من بيته إلى المصلَّى إلى المقبرة حتى تُدفن.\n\n الحق الرابع: إجابة الدعوة إذا دعاه إلى وليمة عرس وغير ذلك.\n\n الحق الخامس: تَشميت العاطس، وهو أن يقول له إذا حَمِدَ الله: يرحمُك الله، ثم يقول العاطسُ: يهديكم الله ويُصلح بالَكم.","reference":"صحيح البخاري (2/ 71) (1240).\nصحيح مسلم (4/ 1704) (2162).\nكنوز رياض الصالحين، لمجموعة من الباحثين (4/ 512).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 327).\nنزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين (1/ 253).\nشرح رياض الصالحين، لابن عثيمين (2/ 591).\nبهجة قلوب الأبرار، لابن سعدي (ص81).","benefits":["عظمة الإسلام في تأكيد الحقوق بين المسلمين وتوثيق الأُخوَّة والمحبة بينهم."],"wordsMeanings":[],"category":"fadail","tags":["المسلم","على","المسلم","خمس:","السلام،","وعيادة"],"source":"hadeethenc"},{"id":"he_3716","text":"عن جابر رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «رَحِمَ اللهُ رَجُلًا سَمْحًا إِذَا بَاعَ، وَإِذَا اشْتَرَى، وَإِذَا اقْتَضَى».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"دعا النبي صلى الله عليه وسلم بالرحمة لكل من كان:\n\nسهلًا جَوَادًا سَخِيًّا في بيعِه، فلا يُشدِّد على المشتري في سعرها ويعامله بخُلُقٍ حَسَن.\n\n\nسهلًا جوادًا سَخِيًّا إذا اشترى، فلا يَبْخَس ويُقَلِّل من قيمة البِضَاعَة.\n\n\nسهلًا جوادًا سخيًا إذا طَالَبَ بقضاءِ الدُّيون التي له، فلا يُشدِّد على الفقير والمُحتاج، بل يُطالِبه برفق ولُطف، ويُنْظِر المُعسر.","reference":"صحيح البخاري (3/ 57) (2076).\nنزهة المتقين (2/ 944).\nكنوز رياض الصالحين، لمجموعة من الباحثين (16/ 386).\nمنار القاري، لحمزة محمد قاسم (3/ 258).\nشرح رياض الصالحين، لابن عثيمين (5/ 405).","benefits":["مِن مَقاصد الشريعة الحِفاظ على ما يُصلِحُ العلاقاتِ بين الناس.","الترغيب في استعمال معالي الأخلاق في المعاملات بين الناس من البيع والشراء ونحو ذلك."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["رحم","الله","رجلا","سمحا","إذا","باع،"],"source":"hadeethenc"},{"id":"he_3753","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «كان رجلٌ يُدَايِنُ الناسَ، فكان يقول لفتاه: إذا أتيتَ مُعسِرًا فتجاوز عنه، لعل اللهَ يَتجاوزُ عنا، فلقي اللهَ فتجاوز عنه».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم عن رجُلٍ كان يتعامل مع الناس بالقَرْض، أو يَبِيعُهم بالآجِل، وكان يقول لغلامه الذي يَتَقاضى الدُّيون التي عند الناس: \nإذا أتيتَ مَدِيْنًا ولم يكن عنده ما يقضي به الدَّين الذي عليه لعجزه \"فَتَجَاوَزْ عنه\"؛ إما بإمهالِه وعدم الإلحاح في المطالبة، أو بقبول ما عنده ولو مع ما فيه مِن نَقْص، وذلك رَغْبةٌ منه وطَمَعٌ في أنْ يتجاوزَ اللهُ عنه ويعفوَ عنه.\n\nفلما ماتَ عفا اللهُ عنه وتجاوزَ عن سيئاتِه.","reference":"صحيح البخاري (4/ 176) (3480).\nصحيح مسلم (3/ 1196) (1562).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 458).\nالتنوير شرح الجامع الصغير، للصنعاني (8/ 123).\nكنوز رياض الصالحين، لمجموعة من الباحثين (16/ 402).\nمرقاة المفاتيح شرح مشكاة المصابيح، للقاري (5/ 1953).\nنزهة المتقين شرح رياض الصالحين (2/ 945).","benefits":["الإحسان في معاملة الناس والعفو عنهم والتجاوز عن معسرهم من أعظم أسباب نجاة العبد يوم القيامة.","الإحسان إلى الخلق والإخلاص لله والرجاء في رحمته من أسباب مغفرة الذنوب."],"wordsMeanings":[{"word":"يداين","meaning":" يكثر من التعامل مع الناس بالدين."},{"word":"فتاه","meaning":" غلامه الذي يكلفه بالعمل."},{"word":"أتيت معسرًا","meaning":" لمطالبته بما عليه."}],"category":"fadail","tags":["كان","رجل","يداين","الناس،","فكان","يقول"],"source":"hadeethenc"},{"id":"he_4191","text":"عن أنس رضي الله عنه مرفوعاً: «من خَرج في طلب العلم فهو في سَبِيلِ الله حتى يرجع».","attribution":"رواه الترمذي","grade":"حسن","gradeKey":"hasan","explanation":"معنى الحديث: أن مَنْ خَرج من بيته أو بلده؛ بَحثا عن العلم الشرعي، فهو في حكم من خرج للجهاد في سبيل الله تعالى ، حتى يعود إلى أهله؛ لأنه كالمجاهد في إحياء الدِّين وإذلال الشيطان وإتعاب النَفْس.","reference":"جامع الترمذي، تحقيق وتعليق:أحمد محمد شاكر وآخرون، مكتبة ومطبعة مصطفى البابي الحلبي، ط2، مصر، 1395هـ.\nدليل الفالحين لطرق رياض الصالحين، لمحمد علي بن محمد بن علان، ط4، اعتنى بها: خليل مأمون شيحا، دار المعرفة، بيروت، 1425ه.\nرياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428هـ.\nرياض الصالحين، ط4، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بير","benefits":["أن طلب العلم جهاد في سبيل الله.","لطالب العلم أجْر المجاهد في ميادين القتال؛ لأن كلا منهما يقوم بما يُقَوِّي شريعة الله ويدفع عنها ما ليس منها.","فيه أن من خرج في طلب العلم، فله ثواب ممشاه ذهابا وإيابا إلى أن يرجع إلى أهله."],"wordsMeanings":[{"word":"في سَبِيلِ الله","meaning":" بمثابة المجاهد لإعلاء كلمة الله -تعالى-."},{"word":"حتى يَرجع","meaning":" يعود لمكانه الذي خَرَج منه."}],"category":"fadail","bookId":"tirmidhi","tags":["خَرج","طلب","العلم","فهو","سَبِيلِ","الله"],"source":"hadeethenc"},{"id":"he_4302","text":"‌عَنْ ‌أَبِي ‌ذَرٍّ، ‌جُنْدُبِ ‌بْنِ ‌جُنَادَةَ، ‌وَأَبِي ‌عَبْدِ ‌الرَّحْمَنِ، ‌مُعَاذِ بْنِ جَبَلٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «اتَّقِ اللَّهَ حَيْثُمَا كُنْت، وَأَتْبِعْ السَّيِّئَةَ الْحَسَنَةَ تَمْحُهَا، وَخَالِقْ النَّاسَ بِخُلُقٍ حَسَنٍ».","attribution":"رواه الترمذي","grade":"قال الترمذي: حديث حسن","gradeKey":"hasan","explanation":"يأمر النبي صلى الله عليه وسلم بثلاثة أمور:\n\nالأول: تقوى الله وذلك بفعل الواجبات، وترك المحرمات، في كل مكان وزمان وحال، في السر والعلانية، وفي العافية والبلاء وغير ذلك.\n\nالثاني: إذا وقعت في سيئة، فافعل بعدها حسنة من صلاة وصدقة وبر وصلة وتوبة وغير ذلك، فإن ذلك يمحو السيئة. \n\nالثالث: عامل الناس بأخلاق حسنة، مِنْ تبسم في وجوههم، ورفق ولين وبذل معروف وكف أذى.","reference":"الأربعون النووية (ص100) (ح18).\nسنن الترمذي (3/ 526) (1987).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، لإسماعيل الأنصاري (ص40).\nشرح الأربعين النووية، لابن عثيمين (ص195).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، لعبد المحسن البدر (ص67).","benefits":["فضل الله عزّ وجل على العباد في رحمته ومغفرته وعفوه.","اشتمل الحديث على الحقوق الثالثة: حق الله بالتقوى، وحق النفس بفعل الحسنات بعد السيئات، وحق الناس بالمعاملة بالأخلاق الحسنة.","الترغيب في فعل الحسنات بعد السيئات، وحسن الخلق من خصال التقوى، وإنما أفرد بالذكر للحاجة إلى بيانها."],"wordsMeanings":[],"category":"fadail","bookId":"tirmidhi","tags":["اتق","الله","حيثما","كنت،","وأتبع","السيئة"],"source":"hadeethenc"},{"id":"he_4304","text":"عن أبي بَكرة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «إِذَا الْتَقَى الْمُسْلِمَانِ بِسَيْفَيْهِمَا فَالْقَاتِلُ وَالْمَقْتُولُ فِي النَّارِ»، فَقُلْتُ: يَا رَسُولَ اللهِ هَذَا الْقَاتِلُ، فَمَا بَالُ الْمَقْتُولِ؟ قَالَ: «إِنَّهُ كَانَ حَرِيصًا عَلَى قَتْلِ صَاحِبِهِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبر النبي صلى الله عليه وسلم أنه إذا التقى المسلمان بسيفيهما، قاصدًا كلٌّ منهما إتلافَ صاحبِه؛ فالقاتل في النار بسبب مباشرته قتلَ صاحبه،\nواستشكل الصحابةُ المقتولَ: كيف يكون في النار؟ فأخبر النبيُّ صلى الله عليه وسلم أنه أيضًا في النار لحرصِه على قتلِ صاحبه، ولم يَمنعه من القتلِ إلا مبادرةُ القاتل وسبقِه له.","reference":"صحيح البخاري (1/ 15) (31).\nصحيح مسلم (4/ 2213) (2888).\nنزهة المتقين شرح رياض الصالحين، (1/ 26).\nشرح رياض الصالحين، لابن عثيمين شرح رياض الصالحين لابن عثيمين (1/ 71).\nالمعجم الوسيط، (1/ 166).","benefits":["استحقاق العقاب على مَن عَزَمَ على المعصية بقلبه وباشَرَ أسبابَها.","التحذير الشديد من اقتتال المسلمين والوعيد عليه بالنار.","القتال بين المسلمين بحق لا يَدخل في الوعيد، مثل قتال البُغَاة والمُفسدين.","مُرتكب الكبيرة لا يَكْفُرُ بمجرَّد فعلها؛ لأن النبي صلى الله عليه وسلم سمَّى المُتقاتلَينِ مُسلِمَينِ.","إذا التقى المسلمان بأيِّ وسيلة يكون بها القتل، فقَتَلَ أحدُهما الآخرَ فالقاتل والمقتول في النار، وذِكْرُ السيفِ في الحديث على سبيل التمثيل."],"wordsMeanings":[{"word":"فما بالُ","meaning":" البال: الحال والشأن."}],"category":"fadail","tags":["إذا","التقى","المسلمان","بسيفيهما","فالقاتل","والمقتول"],"source":"hadeethenc"},{"id":"he_4560","text":"عن عمر بن الخطاب رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ، وَإِنَّمَا لِامْرِئٍ مَا نَوَى، فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللهِ وَرَسُولِهِ، فَهِجْرَتُهُ إِلَى اللهِ وَرَسُولِهِ، وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوِ امْرَأَةٍ يَتَزَوَّجُهَا، فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ».\nوفي لفظ للبخاري: «إِنَّمَا الْأَعْمَالُ بِالنِّيَّاتِ، وَإِنَّمَا لِكُلِّ امْرِئٍ مَا نَوَى».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ كل الأعمال معتبرة بالنية، وهذا الحكم عام في جميع الأعمال من العبادات والمعاملات، فمن قصد بعمله منفعةً لم يَنَلْ إلا تلك المنفعة ولا ثواب له، ومن قصد بعمله التقرب إلى الله تعالى نال من عمله المثوبة والأجر ولو كان عملًا عاديًّا، كالأكل والشرب.\n\nثم ضرب صلى الله عليه وسلم مثلًا لبيان تأثير النية في الأعمال مع تساويهما في الصورة الظاهرة، فبَيَّن أنَّ من قصد بهجرته وترك وطنه ابتغاء مرضات ربه، فهجرته هجرة شرعية مقبولة يثاب عليها لصدق نيته، ومن قصد بهجرته منفعةً دنيوية، من مال، أو جاه، أو تجارة، أو زوجة، فلا ينال من هجرته إلا تلك المنفعة التي نواها، ولا نصيب له من الأجر والثواب.","reference":"صحيح البخاري (9/ 22) (6953)، (1/ 6) (1).\nصحيح مسلم (3/ 1515) (1907).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص5).\nشرح الأربعين النووية، لابن عثيمين (ص5).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص8).\nشرح النووي على مسلم (13/ 54).\nتاج العروس من جواهر القاموس، للزبيدي (7/ 196).","benefits":["الحث على الإخلاص، فإن الله لا يقبل من العمل إلا ما ابتُغي به وجهه.","الأعمال التي يُتَقَرَّبُ بها إلى الله عز وجل إذا فعلها المكلف على سبيل العادة ليس له ثواب عليها، حتى يقصِدَ بها التقرب إلى الله."],"wordsMeanings":[],"category":"fadail","tags":["إنما","الأعمال","بالنيات،","وإنما","لكل","امرئ"],"source":"hadeethenc"},{"id":"he_4709","text":"عن أبي هريرة رضي الله عنه: أَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: أَوْصِنِي، قَالَ: «لَا تَغْضَبْ» فَرَدَّدَ مِرَارًا قَالَ: «لَا تَغْضَبْ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"طَلبَ أحدُ الصحابة رضوان الله عليهم من النبي صلى الله عليه وسلم أن يَدُلَّه على شيء ينفعه، فأمره ألّا يغضب، ومعنى ذلك أن يَجتنبَ الأسبابَ التي تحمله على الغضب، وأن يَضبطَ نفسَه إذا حَصَل له الغضب، فلا يَتَمادى مع غضبه بالقتل أوالضرب أوالسب ونحو ذلك. \n\nوردَّدَ الرجلُ طَلَبَ الوصيةِ مَرَّات، فلم يَزِدْه صلى الله عليه وسلم في الوصية على \"لا تغضب\".","reference":"صحيح البخاري (8/ 28) (6116).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص36).\nشرح الأربعين النووية، لابن عثيمين (ص181).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص64).\nالمعجم الوسيط، (2/ 1038).\nتاج العروس من جواهر القاموس، للزبيدي (3/ 485).","benefits":["التحذير من الغضب وأسبابه، فإنه جِماعُ الشر، والتحرُّزُ منه جماعُ الخير.","الغضب لله كالغضب عند انتهاك محارم الله من الغضب المحمود.","تَكرار الكلام عند الحاجة حتى يَعِيَه السامعُ ويُدرك أهميتَه.","فضيلة طلب الوصية من العالِم."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["تغضب"],"source":"hadeethenc"},{"id":"he_4721","text":"عن عمر بن الخطاب رضي الله عنه قال: إنه سمع نبي الله صلى الله عليه وسلم يقول: «لَو أَنَّكُمْ تَتَوَكَّلُونَ عَلَى اللهِ حَقَّ تَوَكُّلِهِ، لَرَزَقَكُمْ كَمَا يَرْزُقُ الطَّيْرَ، تَغْدُو خِمَاصًا وَتَرُوحُ بِطَانًا».","attribution":"رواه الترمذي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يَحُثُّنا النبيُّ صلى الله عليه وسلم أن نَعتَمِد على الله عز وجل في استجلاب المنافع ودفع المضار في أمور الدنيا والدين، فإنه لا يُعطي ولا يَمنع ولا يَضر ولا يَنفع إلا هو سبحانه وتعالى، \nوأن نفعل الأسباب التي تَجْلُب المنافع وتدفع المضار مع صدق الاعتماد على الله، فمتى فعلنا ذلك رزَقَنا اللهُ كما يرزق الطير التي تخرج صباحًا وهي جياع، ثم تعود مساءً وهي ممتلئة البطون، وهذا الفعلُ من الطير نوعٌ من الأسباب في السعي لطلب الرزق، دون التواكل والتكاسل.","reference":"سنن الترمذي (4/ 166) (2344).\nسنن ابن ماجه (5/ 266) (4164).\nمسند أحمد (1/ 332) (205).\nالتحفة الربانية في شرح الأربعين حديثًا النووية (ص103).\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، للعباد (ص152).\nالأحاديث الأربعون النووية وعليها الشرح الموجز المفيد، لعبد الله المحسن (ص91).","benefits":["فضيلة التوكل، وأنه من أعظم الأسباب التي يُسْتَجْلَبُ بها الرزق.","التوكل لا ينافي فعل الأسباب، فإنه أخبر أن التوكل الحقيقي لا يضادُّه الغدوُّ والرَّوَاحُ في طلب الرزق.","اهتمام الشريعة بأعمال القلوب؛ لأن التوكل عمل قلبيٌّ.","التعلق بالأسباب فقط نقصٌ في الدين، وترك الأسباب نقصٌ في العقل."],"wordsMeanings":[],"category":"fadail","bookId":"tirmidhi","tags":["أنكم","تتوكلون","على","الله","توكله،","لرزقكم"],"source":"hadeethenc"},{"id":"he_4817","text":"عن أبي هريرة رضي الله عنه عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فِيمَا يَحْكِي عَنْ رَبِّهِ عَزَّ وَجَلَّ، قَالَ: «أَذْنَبَ عَبْدٌ ذَنْبًا، فَقَالَ: اللَّهُمَّ اغْفِرْ لِي ذَنْبِي، فَقَالَ تَبَارَكَ وَتَعَالَى: أَذْنَبَ عَبْدِي ذَنْبًا، فَعَلِمَ أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ، وَيَأْخُذُ بِالذَّنْبِ، ثُمَّ عَادَ فَأَذْنَبَ، فَقَالَ: أَيْ رَبِّ اغْفِرْ لِي ذَنْبِي، فَقَالَ تَبَارَكَ وَتَعَالَى: عَبْدِي أَذْنَبَ ذَنْبًا، فَعَلِمَ أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ، وَيَأْخُذُ بِالذَّنْبِ، ثُمَّ عَادَ فَأَذْنَبَ، فَقَالَ: أَيْ رَبِّ اغْفِرْ لِي ذَنْبِي، فَقَالَ تَبَارَكَ وَتَعَالَى: أَذْنَبَ عَبْدِي ذَنْبًا، فَعَلِمَ أَنَّ لَهُ رَبًّا يَغْفِرُ الذَّنْبَ، وَيَأْخُذُ بِالذَّنْبِ، اعْمَلْ مَا شِئْتَ فَقَدْ غَفَرْتُ لَكَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يروي النبي صلى الله عليه وسلم عن ربه أن العبد إذا فعل ذنبًا ثم قال: اللهم اغفر لي ذنبي، قال الله تعالى: فَعَلَ عبدي ذنبًا، فعَلِمَ أنَّ له ربًّا يغفر الذنب، فيستره ويتجاوز عنه، أو يعاقب عليه، قد غفرت له. \nثم عاد العبد فأذنب، فقال: رب اغفر لي ذنبي، فقال الله: فعل عبدي ذنبًا، فعلم أن له ربًّا يغفر الذنب، فيستره ويتجاوز عنه، أو يعاقب عليه، قد غفرت لعبدي. \nثم عاد العبد فأذنب، فقال: رب اغفر لي ذنبي، فقال الله: فعل عبدي ذنبًا، فعلم أن له ربًّا يغفر الذنب، فيستره ويتجاوز عنه، أو يعاقب عليه، قد غفرت لعبدي، فليفعل ما شاء ما دام أنه كلّما أذنب ترك الذنب وندم وعزم على عدم العودة فيه لكن تغلبه نفسه فيقع في الذنب مرة أخرى، فما دام يفعل هكذا يذنب ويتوب فسأغفر له، فإن التوبة تهدم ما قبلها.","reference":"صحيح البخاري (9/ 145) (7507).\nصحيح مسلم (4/ 2112) (2758).\nنزهة المتقين شرح رياض الصالحين (1/ 383).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 493).\nالنهاية في غريب الحديث والأثر، لابن الأثير(674).","benefits":["سعة رحمة الله بعباده وأنَّ الإنسان مهما أذنب ومهما فعل إذا تاب إليه وأناب إليه تاب اللهُ عليه.","المؤمن بالله تعالى يأمل عفوَ ربِّه، ويخاف عقوبتَه، فيبادر إلى التوبة ولا يستمر على المعصية.","شروط التوبة الصحيحة: الإقلاع عن الذنب، والندم عليه، والعزم على عدم العودة إلى الذنب، وإذا كانت التوبة من مظالم العباد في مال أو عرض أو نفس، فتزيد شرطًا رابعًا، وهو: التَّحَلُّل من صاحب الحق، أو إعطاؤه حقَّه.","أهمية العلم بالله الذي يجعل العبد عالمًا بأمور دينه فيتوب كلّما أخطأ، فلا ييأس ولا يتمادى."],"wordsMeanings":[],"category":"fadail","tags":["أذنب","عبد","ذنبا،","فقال:","اللهم","اغفر"],"source":"hadeethenc"},{"id":"he_4935","text":"عن عبد الله بن عمرو رضي الله عنهما قال: قال رسول الله صلى الله عليه وسلم: «إِنَّ الْمُقْسِطِينَ عِنْدَ اللهِ عَلَى مَنَابِرَ مِنْ نُورٍ، عَنْ يَمِينِ الرَّحْمَنِ عَزَّ وَجَلَّ، وَكِلْتَا يَدَيْهِ يَمِينٌ، الَّذِينَ يَعْدِلُونَ فِي حُكْمِهِمْ وَأَهْلِيهِمْ وَمَا وَلُوا».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أنّ الذين يَحكُمُون بالعدل والحق بين الناس الذين تحت إِمْرَتِهم وحكمِهم وأهلهم، أنهم يجلسون على مقاعدَ عاليةٍ رفيعةٍ قد خُلقتْ من نور، إكرامًا لهم يوم القيامة. \nوهذه المنابر عن يمين الرحمن تعالى، وكلتا يديه سبحانه يمينٌ.","reference":"صحيح مسلم (3/ 1458) (1827).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 547).\nتطريز رياض الصالحين، لفيصل المبارك (ص428).\nكنوز رياض الصالحين، لمجموعة من الباحثين (9/ 314).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 710).\nشرح رياض الصالحين، لابن عثيمين (3/ 640).","benefits":["فضل العدل والحث عليه.","العدل عامٌّ يشمل جميع الولايات والحكم بين الناس حتى العدل بين الزوجات والأولاد وغير ذلك.","بيان منزلة العادلين يوم القيامة.","تفاوت منازل أهل الإيمان يوم القيامة كل حسب عمله.","أسلوب الترغيب من أساليب الدعوة التي ترغِّب المدعو في الطاعة."],"wordsMeanings":[{"word":"المقسطين","meaning":" العادلين."},{"word":"في حكمهم","meaning":" في قضائهم."},{"word":"ما وَلُوا","meaning":" الذي كانت لهم عليه ولاية."}],"category":"fadail","bookId":"muslim","tags":["المقسطين","عند","الله","على","منابر","نور،"],"source":"hadeethenc"},{"id":"he_4939","text":"عَنْ جَرِيرٍ رضي الله عنه عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «مَنْ يُحْرَمِ الرِّفْقَ يُحْرَمِ الْخَيْرَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنّ مَن يُحرَم الرفق فلم يوفق له في أمور الدين والدنيا وفيما يتصرَّف فيه لنفسه، وفيما يتصرَّف فيه مع غيره، فقد مُنِعَ الخيرَ كله.","reference":"صحيح مسلم (4/ 2003) (2592).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 532).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص416).\nشرح رياض الصالحين، لابن عثيمين (3/ 592).\nكنوز رياض الصالحين، لمجموعة من الباحثين (9/ 152).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 687).\nفيض القدير شرح الجامع الصغير، للمناوي (6/ 241).","benefits":["فضل الرِّفق والحث على التخلُّق به، وذم العنف.","الرفق به انتظام خير الدارين واتساع أمرهما، وفي العنف ضد ذلك.","الرفق ناتج عن حسن الخلق والسلامة، والعنف ناتج عن الغضب والفَظَاظة، ولذا أثنى صلى الله عليه وسلم على الرفق وبالغ فيه.","قال سفيان الثوري رحمه الله لأصحابه: أتدرون ما الرفق؟ هو أن تضع الأمور مواضعها، الشدة في موضعها، واللين في موضعه، والسيف في موضعه، والسوط في موضعه."],"wordsMeanings":[],"category":"fadail","bookId":"muslim","tags":["يحرم","الرفق","يحرم","الخير"],"source":"hadeethenc"},{"id":"he_5326","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «أَتَدْرُونَ مَا الْغِيبَةُ؟»، قَالُوا: اللهُ وَرَسُولُهُ أَعْلَمُ، قَالَ: «ذِكْرُكَ أَخَاكَ بِمَا يَكْرَهُ»، قِيلَ: أَفَرَأَيْتَ إِنْ كَانَ فِي أَخِي مَا أَقُولُ؟ قَالَ: «إِنْ كَانَ فِيهِ مَا تَقُولُ فَقَدِ اغْتَبْتَهُ، وَإِنْ لَمْ يَكُنْ فِيهِ فَقَدْ بَهَتَّهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم حقيقة الغيبة المُحرَّمة، وهي: ذِكْرُ المسلم الغائب بما يَكره، سواء كان من صفاته الخَلْقية أو الخُلُقية، مثل: الأعور الغشاش الكذاب، ونحو ذلك من صفات الذم، ولو كانت تلك الصفة موجودة فيه.\n\nوأما إذا لم تكنْ فيه الصفةُ فهذا أشدُّ من الغيبة، وهو البُهْتَان، أي: الافتراء على الإنسان بما ليس فيه.","reference":"صحيح مسلم (4/ 2001) (2589).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (6/ 378).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 237).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 428).","benefits":["حُسْن تعليم النبي صلى الله عليه وسلم، حيث يُلقي المسائل على طريقة السؤال.","حُسْن أدب الصحابة مع النبي صلى الله عليه وسلم، حين قالوا: الله ورسوله أعلم.","قول المسؤول عن ما لا يعلمه: الله أعلم.","صيانة الشريعة للمجتمع بحفظ الحقوق والأخوة بينهم.","الغيبة محرمة إلا في بعض الأحوال للمصلحة؛ ومن ذلك: دفع الظلم، بحيث يَذكرُ المظلومُ مَن ظَلَمَه عند من يستطيع الأخذ بحقه، فيقول: ظلمني فلان، أو فعل بي كذا، ومنها: المشاورة في أمر الزواج أو المشاركة أو المجاورة، ونحو ذلك."],"wordsMeanings":[],"category":"fadail","bookId":"muslim","tags":["أتدرون","الغيبة؟،","قالوا:","الله","ورسوله","أعلم،"],"source":"hadeethenc"},{"id":"he_5331","text":"عن خَولة الأنصاريةِ رضي الله عنها قالت: سمعت النبي صلى الله عليه وسلم يقول: «إِنَّ رِجَالًا يَتَخَوَّضُونَ فِي مَالِ اللهِ بِغَيْرِ حَقٍّ، فَلَهُمُ النَّارُ يَوْمَ الْقِيَامَةِ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم عن أناسٍ يَتَصَرَّفُون في أموال المسلمين بالباطل، ويأخذونها بغير حق، وهذا معنى عامٌّ في المال من حيث جَمْعِهِ وكسبِهِ من غير حِلِّه، وإنفاقه في غير مواضعه الصحيحة، ويدخل في ذلك أكل أموال اليتامى وأموال الوَقْف وجَحْد الأمانات والأخذ بغير استحقاق من الأموال العامة.\n\nثم أخبر صلى الله عليه وسلم أن جزاءهم النار يوم القيامة.","reference":"صحيح البخاري (4/ 85) (3118).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (6/ 372).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 231).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 424).","benefits":["المال الذي بأيدي الناس هو مال الله، استَخْلَفَهم عليه لينفقوه بالطرق المشروعة، ويجتنبوا التصرف فيه بالباطل، وهذا عامٌّ في الولاة وغيرهم من سائر الناس.","تشديد الشرع في المال العام،  وأنه من ولي منه شيئًا فإنه سيحاسب يوم القيامة على جِبَايَتِه وإنفاقه.","يدخل في هذا الوعيد مَن يتصرَّفُ تصرُّفًا غير شرعي في المال سواء كان ماله أو مال غيره."],"wordsMeanings":[],"category":"fadail","bookId":"bukhari","tags":["رجالا","يتخوضون","مال","الله","بغير","حق،"],"source":"hadeethenc"},{"id":"he_5332","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّ صلى الله عليه وسلم قَالَ: «إِيَّاكُمْ وَالظَّنَّ؛ فَإِنَّ الظَّنَّ أَكْذَبُ الْحَدِيثِ، وَلَا تَحَسَّسُوا، وَلَا تَجَسَّسُوا، وَلَا تَحَاسَدُوا، وَلَا تَدَابَرُوا، وَلَا تَبَاغَضُوا، وَكُونُوا عِبَادَ اللهِ إِخْوَانًا».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يَنْهَى النبيُّ صلى الله عليه وسلم ويُحَذِّرُ مِن بعضِ ما يؤدِّي إلى الفُرْقة والعداوة بين المسلمين، \nومن ذلك: \n\n(الظن) وهو تُهمةٌ تقَعُ في القَلبِ بلا دَليلٍ، وبَيَّنَ أنه مِن أَكْذَب الحديث. \n\nوعن (التَّحَسُّس): وهو البحث عن عورات الناس بالعين أو الأذن. \n\nو(التَّجَسُّس): وهو البحث عن ما خفي من الأمور، وأكثر ما يقال ذلك في الشر. \n\nوعن: (الحسد) وهو كراهية حصول النعمة للآخرين. \n\nوعن: (التدابر) بأنْ يَعْرِضَ بعضُهم عن بعض، فلا يسلِّم ولا يزور أخاه المسلم، \n\nوعن: (التباغض) والكراهية والنفرة، كأذية الآخرين، والعبوس وسوء المقابلة. \n\nثم قال كلمة جامعة تصلح بها أحوال المسلمين بعضهم مع بعض: (وكونوا عباد الله إخوانًا) \nفالأخوة رابطة تلتئم بها العلاقات بين الناس، وتزيد المحبة والأُلْفة بينهم.","reference":"صحيح البخاري (8/ 19) (6064).\nصحيح مسلم (4/ 1985) (2563).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 219).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 414).\nفتح ذي الجلال والإكرام بشرح بلوغ المرام، لابن عثيمين (6/ 363).","benefits":["لا يَضُرُّ الظنُّ السيءُ بمَن ظهرتْ منه علاماتُه، وعلى المؤمن أن يكون كَيِّسًا فَطِنًا لا يَنْخدع بأهل السوء والفسوق.","المراد التحذير من التهمة التي تستقر في النفس، ومن الإصرار عليها، أما ما يَعرِض في النفس ولا يستقر فهذا لا يُكلف به.","تحريم أسباب التنافر والقطيعة بين أفراد المجتمع المسلم، من التجسس والحسد ونحوِهما.","الوصية بمعاملة المسلم معاملة الأخ في النصيحة والتَّوَادّ."],"wordsMeanings":[],"category":"fadail","tags":["إياكم","والظن؛","فإن","الظن","أكذب","الحديث"],"source":"hadeethenc"},{"id":"he_5344","text":"عن أنس بن مالك رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : «كلُّ بني آدم خَطَّاءٌ، وخيرُ الخَطَّائِينَ التوابون».","attribution":"رواه الترمذي وابن ماجه والدارمي وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"لا يخلو الإنسان من الخطيئة، لما فُطر عليه من الضعف، وعدم الانقياد لمولاه في فعل ما دعاه إليه، وترك ما نهاه عنه، لكنه تعالى فتح باب التوبة لعباده، وأخبر أن خير الخطائين هم المكثرون من التوبة.","reference":"سنن الترمذي، محمد بن عيسى الترمذي، تحقيق وتعليق: أحمد محمد شاكر ومحمد فؤاد عبد الباقي وإبراهيم عطوة عوض، شركة مكتبة ومطبعة مصطفى البابي الحلبي، مصر الطبعة الثانية، 1395هـ - 1975 م.\nسنن ابن ماجه: ابن ماجه أبو عبد الله محمد بن يزيد القزويني، تحقيق: محمد فؤاد عبد الباقي، دار إحياء الكتب العربية، فيصل عيسى البابي الحلبي.\nمسند الإمام أحمد بن حنبل المحقق: شعيب الأرنؤوط - عادل مرشد، وآخرون إشراف: د عبد ا","benefits":["من شأن ابن آدم الخطأ والوقوع في الذنب.","الواجب على المؤمن إذا تلبس بمعصية أن يبادر بالتوبة."],"wordsMeanings":[{"word":"خطَّاء","meaning":" الرجل الخطَّاء هو الملازم للخطأ."},{"word":"التوّابون","meaning":" التواب: العبد الكثير التوبة.والتوبة: هي ترك الذنب لقبحه والندم على ما فرط منه، والعزيمة على ترك المعاودة، وتدارك ما أمكنه أن يتدارك من الأعمال بالإعادة."}],"category":"fadail","bookId":"tirmidhi","tags":["بني","آدم","خطاء،","وخير","الخطائين","التوابون"],"source":"hadeethenc"},{"id":"he_5346","text":"عن جابر بن عبد الله رضي الله عنهما عن النبي صلى الله عليه وسلم قال: «كُلُّ مَعْرُوفٍ صَدَقَةٌ».","attribution":"رواه البخاري من حديث جابر، ورواه مسلم من حديث حذيفة","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ كلَّ إحسانٍ ونَفْعِ للآخرين مِن قول أو عمل يكون صدقةً، وفيه الأجر والثواب.","reference":"صحيح البخاري (8/ 11) (6021).\nصحيح مسلم (2/ 697) (1005).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 117).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 341).","benefits":["أن الصَّدَقة لا تنحصر فيما يخرجه الإنسان من ماله، بل تشمل كلَّ خير يفعله الإنسان أو يقوله ويوصله إلى الآخرين.","فيه الترغيب في بذل المعروف وكل ما فيه نفع للآخرين.","عدم احتقار شيءٍ من المعروف، ولو كان يسيرًا."],"wordsMeanings":[{"word":"معروف","meaning":" المعروف اسم جامع لكل ما فيه نفع للآخرين من قول أو فعل."}],"category":"fadail","bookId":"bukhari","tags":["معروف","صدقة"],"source":"hadeethenc"},{"id":"he_5348","text":"عن أبي ذر رضي الله عنه قال: قال لي النبي صلى الله عليه وسلم: «لَا تَحْقِرَنَّ مِنَ الْمَعْرُوفِ شَيْئًا، وَلَوْ أَنْ تَلْقَى أَخَاكَ بِوَجْهٍ طَلْقٍ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"حَثَّ النبيُّ صلى الله عليه وسلم على فعل المعروف، وأن لا يحتقره ولو كان قليلًا، ومن ذلك طلاقة الوجه بالابتسامة عند اللقاء، فينبغي للمسلم أن يحرص عليه؛ لما فيه من إِيْنَاس الأخ المسلم وإدخال السرور عليه.","reference":"صحيح مسلم (4/ 2026) (2626).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 119).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 341).\nنزهة المتقين شرح رياض الصالحين، (1/ 572).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 20).","benefits":["فضل التَّحابِّ بين المؤمنين، والابتسامة والبِشْر عند اللقاء.","كمال هذه الشريعة وشمولها، وأنها جاءت بكل ما فيه صلاح المسلمين وتوحيد كلمتهم.","الحث على فعل المعروف وإن قَلَّ.","استحباب إدخال السرور على  المسلمين؛ لما في ذلك من تحقيق الأُلْفَة بينهم."],"wordsMeanings":[],"category":"fadail","bookId":"muslim","tags":["تحقرن","المعروف","شيئا،","ولو","تلقى","أخاك"],"source":"hadeethenc"},{"id":"he_5351","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «لَيْسَ الشَّدِيدُ بِالصُّرَعَةِ، إِنَّمَا الشَّدِيدُ الَّذِي يَمْلِكُ نَفْسَهُ عِنْدَ الْغَضَبِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ القوةَ الحقيقيةَ ليست قوةَ الجَسَد، أو الذي يَصْرَعُ غيرَه من الأقوياء، وإنما القويُّ الشديدُ هو الذي جاهَدَ نفسَه وقَهَرَها حينما يَشتدُّ به الغضبُ؛ لأنَّ هذا يدل على قوّة تَمَكُّنِهِ من نفسه وتَغَلُّبِه على الشيطان.","reference":"صحيح البخاري (8/ 28) (6114).\nصحيح مسلم (4/ 2014) (2609).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 198).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 394).\nنزهة المتقين شرح رياض الصالحين، (538).\nبهجة الناظرين شرح رياض الصالحين، للهلالي (1/ 698).","benefits":["فضيلة الحِلْم وضَبْط النفس عند الغضب، وأنه من الأعمال الصالحة التي حَثَّ عليها الإسلام.","مجاهدة النفس عند الغضب أشدُّ من مجاهدة العدو.","تغيير الإسلام لمفهوم القوة الجاهلي إلى أخلاق كريمة، فأشد الناس قوّة هو مَن مَلَكَ زِمَام نفسِه.","الابتعاد عن الغضب؛ لما يسبِّبُه من الأضرار على الأفراد والمجتمع."],"wordsMeanings":[],"category":"fadail","tags":["ليس","الشديد","بالصرعة،","إنما","الشديد","الذي"],"source":"hadeethenc"},{"id":"he_5354","text":"عن أبي مسعود الأنصاري رضي الله عنه قال: جَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فَقَالَ: إِنِّي أُبْدِعَ بِي فَاحْمِلْنِي، فَقَالَ: «مَا عِنْدِي»، فَقَالَ رَجُلٌ: يَا رَسُولَ اللهِ، أَنَا أَدُلُّهُ عَلَى مَنْ يَحْمِلُهُ، فَقَالَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"جاء رجلٌ إلى النبي صلى الله عليه وسلم فقال: إني هَلَكَتْ راحلتي، فاحملني على دابةٍ، وأعطني مركوبًا يوصلني، فاعتذر له النبي صلى الله عليه وسلم أنه ليس عنده شيء يحمله عليه، فقال رجلٌ وكان حاضرًا: يا رسول الله، أنا أَدُلُّه على مَن يَحمله، فأخبرَ رسولُ الله صلى الله عليه وسلم أنه شريكٌ للمتصدِّق في الأجر، لأنه دلَّ المحتاجَ عليه.","reference":"صحيح مسلم (3/ 1506) (1893).\nشرح النووي على مسلم (11/ 166).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 349).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (6/ 298).","benefits":["الحث على الدلالة على الخير.","الحضُّ على فعل الخير من أسباب تَكَافُل المجتمع المسلم وتكامله.","سَعَة فضل الله تعالى.","الحديث قاعدة عامة فيدخل فيه كلُّ أعمال الخير.","الإنسان إذا لم يتمكَّن مِن تحقيق رغبة السائل، فإنه يَدُلُّه على غيره."],"wordsMeanings":[],"category":"fadail","bookId":"muslim","tags":["على","خير","فله","مثل","أجر","فاعله"],"source":"hadeethenc"},{"id":"he_5367","text":"عن جُبَير بن مُطْعِم رضي الله عنه أنه سمع النبي صلى الله عليه وسلم يقول: «لَا يَدْخُلُ الْجَنَّةَ قَاطِعُ رَحِمٍ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أنَّ مَن قَطَع عن أقاربه ما يَجِب لهم من الحقوق، أو آذاهم وأساء إليهم، فهو مُستحق ألَّا يدخلَ الجنة.","reference":"صحيح مسلم (4/ 1981) (2556).\nصحيح البخاري (8/ 5) (5984).\nشرح النووي على مسلم (16/ 113).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 90).\nفتح ذي الجلال والإكرام بشرح بلوغ المرام، لابن عثيمين (6/ 277).","benefits":["قطيعة الرحم كبيرة من كبائر الذنوب.","صلة الرحم تكون حسب المتعارف عليه، فتختلف باختلاف الأمكنة والأزمنة والأشخاص.","صلة الرحم تكون بالزيارة، والصدقة، والإحسان إليهم، وعيادة المرضى، وأمرهم بالمعروف، ونهيهم عن المنكر، وغير ذلك.","كلما كانت قطيعة الرحم في الأقرب كانت أشدَّ إثمًا."],"wordsMeanings":[],"category":"fadail","tags":["يدخل","الجنة","قاطع","رحم"],"source":"hadeethenc"},{"id":"he_5368","text":"عن حذيفة رضي الله عنه قال: سمعت النبي صلى الله عليه وسلم يقول: «لَا يَدْخُلُ الْجَنَّةَ قَتَّاتٌ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ صلى الله عليه وسلم أنَّ النَّمَّامَ الذي ينقل الكلام بين الناس بقصد الإفساد بينهم بأنه مُستحِقٌّ للعقاب بألَّا يدخلَ الجنة.","reference":"صحيح البخاري (8/ 17) (6056).\nصحيح مسلم (1/ 101) (105).\nشرح رياض الصالحين، لابن عثيمين (6/ 145).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (6/ 401).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 452).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 273).","benefits":["النميمة من كبائر الذنوب.","النهي عن النميمة؛ لما فيها من الإفساد والضرر بين الأفراد والجماعات."],"wordsMeanings":[],"category":"fadail","tags":["يدخل","الجنة","قتات"],"source":"hadeethenc"},{"id":"he_5372","text":"عن أنس بن مالك رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ أَحَبَّ أَنْ يُبْسَطَ لَهُ فِي رِزْقِهِ، وَيُنْسَأَ لَهُ فِي أَثَرِهِ، فَلْيَصِلْ رَحِمَهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يَحُثُّ النبيُّ صلى الله عليه وسلم على صِلة الأقاربِ بالزيارة والإكرام البدني والمالي وغير ذلك، وأنها سببٌ في سَعة الرزق وطول العمر.","reference":"صحيح البخاري (8/ 5) (5986).\nصحيح مسلم (4/ 1982) (2557).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 320).\nشرح رياض الصالحين، لابن عثيمين (3/ 188).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (6/ 275).\nتطريز رياض الصالحين، لفيصل المبارك (ص224).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 81).","benefits":["الرَّحِم هم الأقارب من جهة الأب والأم، وكلما كان أقرب كان أولى بالصلة.","الجزاء من جنس العمل، فمَن وَصَل رَحِمَه بالبر والإحسان، وَصَله الله في عُمْره ورزقه.","صلة الرحم سببٌ لِبَسْطِ الرِّزق وتوسيعه، وسببٌ لطول العمر، وإن كان الأجلُ والرزقُ محددًا إلا أنه قد يكون بركة في الرزق والعمر، فيفعل في عمره أكثر وأنفع مما يفعله غيرُه، وقيل زيادة الرزق والعمر زيادة حقيقية. والله أعلم."],"wordsMeanings":[],"category":"fadail","tags":["أحب","يبسط","رزقه،","وينسأ","أثره،","فليصل"],"source":"hadeethenc"},{"id":"he_5382","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «أَقْرَبُ مَا يَكُونُ الْعَبْدُ مِنْ رَبِّهِ وَهُوَ سَاجِدٌ، فَأَكْثِرُوا الدُّعَاءَ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ أقربَ ما يكون العبد من ربه وهو ساجد؛ وذلك أنّ المصليَ يَضعُ أعلى وأشرف ما في جسده على الأرض خضوعًا وتَذَلُّلًا وتواضعًا لله عز وجل وهو ساجد.\n\nوقد أمر صلى الله عليه وسلم بالإكثار من الدعاء في السجود، فيجتمع في ذلك التَذَلُّلُ لله بالقول والفعل.","reference":"صحيح مسلم (1/ 350) (482).\nشرح رياض الصالحين، لابن عثيمين (5/ 509).\nتطريز رياض الصالحين، لفيصل المبارك (ص780).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 506).","benefits":["الطاعة تزيدُ العبدَ قُرْبًا مِن الله سبحانه وتعالى.","استحبابِ كثرةِ الدعاء في السجود؛ لأنه من مواطن الإجابة."],"wordsMeanings":[],"category":"fadail","bookId":"muslim","tags":["أقرب","يكون","العبد","ربه","وهو","ساجد،"],"source":"hadeethenc"},{"id":"he_5437","text":"عن أبي هريرة رضي الله عنه عن رسول الله صلى الله عليه وسلم قال: «مَنْ كَانَ يُؤْمِنُ بِاللهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ، وَمَنْ كَانَ يُؤْمِنُ بِاللهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ جَارَهُ، وَمَنْ كَانَ يُؤْمِنُ بِاللهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ العبدَ المؤمن بالله واليوم الآخر الذي إليه معاده وفيه مجازاته بعمله، يَحُثُّه إيمانُه على فعل هذه الخصال: \n\nالأولى: القول الحسن: من التسبيح والتهليل، والأمر بالمعروف، والنهي عن المنكر، والإصلاح بين الناس، فإنْ لم يفعل فلْيلزم السكوت ويَكُف أذاه ويحفظ لسانه. \n\nالثاني: إكرام الجار: بالإحسان إليه وعدم إيذائه.\n\nالثالث: إكرام الضيف القادم لزيارتك: بطِيْبِ الكلام وإطعام الطعام ونحو ذلك.","reference":"صحيح البخاري (8/ 11) (6018).\nصحيح مسلم (1/ 68) (47).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، (ص34).\nشرح الأربعين النووية، لابن عثيمين (ص176).\nشرح النووي على مسلم (2/ 18).","benefits":["الإيمان بالله واليوم الآخر أَصْلٌ لكلِّ خير، ويَبعث على فعل الخير.","التحذير من آفات اللسان.","دين الإسلام دين الأُلفة والكرم.","هذه الخصال من شُعَب الإيمان ومن الآداب المحمودة.","كثرة الكلام قد تَجُرُّ إلى المكروه أو المحرَّم، والسلامة في عدم الكلام إلا في الخير."],"wordsMeanings":[],"category":"fadail","tags":["كان","يؤمن","بالله","واليوم","الآخر","فليقل"],"source":"hadeethenc"},{"id":"he_5439","text":"عن جرير بن عبد الله رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «مَنْ لَا يَرْحَمِ النَّاسَ لَا يَرْحَمْهُ اللهُ عَزَّ وَجَلَّ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ الذي لا يرحمُ الناسَ لا يرحمُه اللهُ عز وجل، فرحمةُ العبد للخَلق من أكبر الأسباب التي تُنالُ بها رحمةُ الله تعالى.","reference":"صحيح البخاري (8/ 10) (6013).\nصحيح مسلم (4/ 1809) (2319).\nشرح رياض الصالحين، لابن عثيمين (2/ 553).\nنزهة المتقين شرح رياض الصالحين (1/ 247).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 319).","benefits":["الرحمة مطلوبة لسائر المخلوقات، لكن خص الناس بالذكر اهتمامًا بهم.","الله هو الرحيم ويرحم عبادَه الرُّحَماء، فالجزاء من جنس العمل.","الرحمة بالناس تشمل إيصال الخير لهم ودفع الشر عنهم ومعاملتهم بالحسنى."],"wordsMeanings":[],"category":"fadail","tags":["يرحم","الناس","يرحمه","الله","وجل"],"source":"hadeethenc"},{"id":"he_5474","text":"عن عائشة رضي الله عنها عن النبي صلى الله عليه وسلم قال: «إِنَّ أَبْغَضَ الرِّجَالِ إِلَى اللهِ الْأَلَدُّ الْخَصِمُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ الله تبارك وتعالى يُبغِض مِن الناس شديدَ الخُصُومةِ وكثيرِها، الذي لا يَقبلُ الانقيادَ للحق، ويُحاولُ دفعَه بجَدَلِه، أو يخاصم بحق لكنَّه يُبالِغُ في الخصومة ويخرج عن حدِّ الاعتدال، ويجادل بغير علم.","reference":"صحيح البخاري (3/ 131) (2457).\nصحيح مسلم (4/ 2054) (2668).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 476).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 308).\nفتح ذي الجلال والإكرام، لابن عثيمين (6/ 416).\nسبل السلام بشرح بلوغ المرام، للصنعاني (2/ 685).","benefits":["لا يدخلُ في بابِ الخصومات المذمومةِ مطالبةُ المظلوم بحقٍّ له بطريق المرافعات الشرعية.","الجدل والخصومة من آفات اللسان التي تُسبب الفرقة والتدابر بين المسلمين.","المجادلة محمودة إذا كانت في الحق وأسلوبها حسن، وتكون مذمومة إذا كانت لرد الحق وتثبيت الباطل، أو كانت بغير حجة ولا برهان."],"wordsMeanings":[],"category":"fadail","tags":["أبغض","الرجال","إلى","الله","الألد","الخصم"],"source":"hadeethenc"},{"id":"he_66516","text":"عَنْ أَبِي رُقَيَّةَ تَمِيمِ بْنِ أَوْسٍ الدَّارِيِّ رَضِيَ اللَّهُ عَنْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ: «الدِّينُ النَّصِيحَةُ» قُلْنَا: لِمَنْ؟ قَالَ: «لِلهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخبَرَ النبيُّ صلى الله عليه وسلم بأنَّ الدين قائمٌ على الإخلاص والصدق، حتى يؤدَّى كما أوجب الله، كاملًا دون تقصير أو غش.\nفقيل للنبي صلى الله عليه وسلم: لمن تكون النصيحة؟ فقال:\n\nأولًا: النصيحة لله سبحانه وتعالى: بإخلاص العمل له، وعدم الإشراك به، وأن نؤمن بربوبيته وألوهيته وأسمائه وصفاته، وتعظيم أمره، والدعوة إلى الإيمان به.\n\nثانيًا: النصيحة لكتابه وهو القرآن الكريم: بأن نعتقد أنه كلامُه، وآخِرُ كتبِه، وأنه ناسخ لجميع الشرائع قبله، ونعظِّمه، ونتلوه حق تلاوته، ونعمل بمُحْكَمِه، ونسلم بمتشابهه، ونَذُبُّ عن تأويل المُحرِّفين له، ونعتبر بمواعظه، وننشر علومه، وندعو إليه.\n\nثالثًا: النصيحة لرسوله محمد صلى الله عليه وسلم: بأن نعتقدَ أنه آخِرُ الرسل، ونصدِّقَه فيما جاء به، ونَمتَثِلَ أمرَه، ونجتنبَ نهيَه، وأن لا نتعبدَ لله إلا بما جاء به، ونُعظِّمَ حقَّه، ونوقرَه، ونَبُثَّ دعوته، ونَنشُرَ شريعتَه، ونَنفيَ التُّهَمَ عنه.\n\nرابعًا: النصيحة لأئمة المسلمين: بمعاونتهم على الحق، وعدم منازعتهم الأمر، والسمع والطاعة لهم في طاعة الله.\n\nخامسًا: النصيحة للمسلمين: بالإحسان إليهم ودعوتهم، وكَفِّ الأذى عنهم، ومحبة الخير لهم، والتعاون معهم على البر والتقوى.","reference":"صحيح مسلم (1/ 74) (55).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص21).\nشرح الأربعين النووية، لابن عثيمين (ص115).\nشرح النووي على مسلم (2/ 37).","benefits":["الأمر بالنصيحة للجميع.","عِظَم منزلة النصيحة من الدين.","اشتمال الدين على الاعتقادات والأقوال والأعمال.","من النصيحة تصفية النفس من الغش للمنصوح له وإرادة الخير له.","حسن تعليم الرسول صلى الله عليه وسلم حيث يذكر الشيء مُجملًا ثم يُفصّله.","البداءة بالأهم فالأهم، حيث بدأ النبي صلى الله عليه وسلم بالنصيحة لله، ثم لكتابه، ثم لرسوله صلى الله عليه وسلم ثم لأئمة المسلمين، ثم عامتهم."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["الدين","النصيحة"],"source":"hadeethenc"},{"id":"he_66527","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «كُلُّ سُلَامَى مِنَ النَّاسِ عَلَيْهِ صَدَقَةٌ، كُلَّ يَوْمٍ تَطْلُعُ فِيهِ الشَّمْسُ تَعْدِلُ بَيْنَ الِاثْنَيْنِ صَدَقَةٌ، وَتُعِينُ الرَّجُلَ فِي دَابَّتِهِ فَتَحْمِلُهُ عَلَيْهَا أَوْ تَرْفَعُ لَهُ عَلَيْهَا مَتَاعَهُ صَدَقَةٌ، وَالكَلِمَةُ الطَّيِّبَةُ صَدَقَةٌ، وَكُلُّ خُطْوَةٍ تَمْشِيهَا إِلَى الصَّلَاةِ صَدَقَةٌ، وَتُمِيطُ الأَذَى عَنِ الطَّرِيقِ صَدَقَةٌ».","attribution":"رواه البخاري ومسلم","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ على كلِّ مسلم مُكلَّف كلّ يوم بعدد كل مفصل من مفاصل عظامه صدقة تطوع لله تعالى على سبيل الشكر له على العافية، وأن جعل عظامه مفاصل يتمكن بها من القبض والبسط، وأنّ تلك الصدقة تتأدّى بأعمال البر كلها ولا تتوقف على إعطاء مال، ومنها: عدلك وإصلاحك بيـن متخاصمين صدقةٌ، وفي إعانتك لعاجز في دابته فتحمله عليها أو ترفع له متاعه صدقةٌ، والكلمة الطيبة من ذكر ودعاء وسلام وغيرها صدقةٌ، وبكل خطوةٍ تمشيها إلى الصلاة صدقةٌ، وإزالة ما يُتَأذّى به عن الطريق صدقةٌ.","reference":"صحيح البخاري (4/ 56) (2989).\nصحيح مسلم (1/ 498) (720).\nالتحفة الربانية في شرح الأربعين حديثًا النووية، مطبعة دار نشر الثقافة، الإسكندرية، الطبعة: الأولى، 1380 هـ.\nشرح الأربعين النووية، للشيخ ابن عثيمين، دار الثريا للنشر.\nفتح القوي المتين في شرح الأربعين وتتمة الخمسين، دار ابن القيم، الدمام المملكة العربية السعودية، الطبعة: الأولى، 1424هـ/2003م.\nالفوائد المستنبطة من الأربعين النووية، للشيخ عبد الرح","benefits":["تركيب عظام الآدمي وسلامتها من أعظم نعم الله تعالى عليه، فيحتاج كل عظم منها إلى تصدق عنه بخصوصه ليتم شكر تلك النعمة.","الترغيب في تجديد الشكر كل يوم لدوام تلك النعم.","الترغيب في المداومة على النوافل والصدقات كل يوم.","فضل الإصلاح بين الناس.","الحث على معونة الرجل أخاه؛ لأن معونته إياه صدقة.","الحث على حضور الجماعات والمشي إليها، وعمارة المساجد بذلك.","وجوب احترام طرق المسلمين بتجنب ما يؤذيهم أو يضر بهم."],"wordsMeanings":[{"word":"سُلامى","meaning":" بضم السين المهملة وتخفيف اللام مع القصر، وهي المفاصل، وقد ثبت في صحيح مسلم أنها ثلاثمائة وستون:"}],"category":"da3wah","bookId":"bukhari","tags":["سلامى","الناس","عليه","صدقة"],"source":"hadeethenc"},{"id":"he_3061","text":"عن عُبَادَةَ بن الصَّامتِ رضي الله عنه قال: بَايَعْنَا رسولَ اللهِ صلى الله عليه وسلم على السَّمْعِ وَالطَّاعَةِ فِي الْعُسْرِ وَالْيُسْرِ، وَالْمَنْشَطِ وَالْمَكْرَهِ، وعلى أَثَرَةٍ علينا، وعلى أَلَّا نُنَازِعَ الْأَمْرَ أهلَه، وعلى أَنْ نَقُولَ بِالْحَقِّ أينما كُنَّا، لا نَخَافُ في الله لَوْمَةَ لَائِمٍ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخَذَ النبيُّ صلى الله عليه وسلم العهدَ والميثاقَ من الصحابة في الانقياد لأولي الأمر والحُكَّام في السهل والصعب وحالة الغنى والفقر، وسواء كانت أوامرهم مما تهواه النفس أو تكرهه، حتى ولو استأثر الولاةُ على الرعية بالمال العام أو المناصب أو غير ذلك، فإنه يجب لهم السمع والطاعة بالمعروف، وأن لا يخرجوا عليهم لأن الفتنة والفساد في قتالهم أعظم وأشد من الفساد الحاصل بظلمهم، ومما عاهدوا عليه أن يقولوا الحقَّ في أيِّ مكانٍ مُخلِصين في ذلك لله لا يخافون مَن يَلُوْمُهم.","reference":"صحيح البخاري (9/ 47) (7055-7056)، (9/ 77) (7199، 7200).\nصحيح مسلم (3/ 1470) (1709).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 277).\nرياض الصالحين، للنووي (ص83) (186).\nشرح رياض الصالحين، لابن عثيمين (2/ 419).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 202).","benefits":["ثمرة السمع والطاعة لولاة الأمر اجتماعُ كلمةِ المسلمين ونَبْذُ الفُرْقة.","وجوب السمع والطاعة لولاة الأمور في غير معصية الله في اليُسْر والعُسْر، والمنشط والمكره والأَثَرَةِ التي يستأثرون بها.","وجوب قول الحق أينما كُنَّا، من غير أن نخاف في الله لومة لائم."],"wordsMeanings":[],"category":"da3wah","tags":["بايعنا","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_3481","text":"عَنْ أُمِّ سَلَمَةَ أُمِّ المُؤمنين رضي الله عنها: أَنَّ رَسُولَ اللهِ صلى الله عليه وسلم قَالَ: «سَتَكُونُ أُمَرَاءُ فَتَعْرِفُونَ وَتُنْكِرُونَ، فَمَنْ عَرَفَ بَرِئَ، وَمَنْ أَنْكَرَ سَلِمَ، وَلَكِنْ مَنْ رَضِيَ وَتَابَعَ» قَالُوا: أَفَلَا نُقَاتِلُهُمْ؟ قَالَ: «لَا، مَا صَلَّوْا».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ عليه الصلاة والسلام أنه يُولَّى علينا أمراء، نَعرف بعضَ أعمالِهم؛ لموافقتِها ما عُرِف من الشرع، ونُنْكر بعضَها؛ لمخالفتِه ذلك، \nفمَن كَرِهَ بقلبِه المنكر ولم يَقدر على الإنكار؛ فقد برىء من الإثم والنفاق، \nومن قدر على الإنكار باليد أو باللسان فأنكر عليهم ذلك فقد سَلِم مِن المعصية والمشاركة فيها، \nولكنْ مَن رضي فِعْلَهم وتابَعَهم عليه يهلك كما هلكوا.\n\n\nثم سألوا النبي صلى الله عليه وسلم: ألا نقاتل وُلاةَ الأمرِ الذين هذه صفتُهم؟ فنهاهم عن ذلك، وقال: لا، ما أقاموا فيكم الصلاة.","reference":"صحيح مسلم (3/ 1480) (1854).\nالمفهم لما أشكل من تلخيص كتاب مسلم (4/ 64).\nالبحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (32/ 206).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 279).\nتطريز رياض الصالحين، لفيصل بن عبد العزيز المبارك (ص150).\nالشرح الممتع على زاد المستقنع، لابن عثيمين (11/ 323).\nشرح رياض الصالحين، لابن عثيمين (2/ 435).\nنزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين (1/","benefits":["من دلالات نبوة النبي صلى الله عليه وسلم إخباره عما سيقع من المغيبات ووقوعه كما أخبر.","لا يجوز الرضا عن المنكر ولا المشاركة فيه، ويجب إنكاره.","إذا أَحدَثَ الأمراءُ ما يُخَالف الشريعة فلا تجوز طاعتُهم في ذلك.","عدم جواز الخروج على ولاة الأمر المسلمين؛ لما يَتَرَتَّب على ذلك مِن المَفسدةِ وسَفْكِ الدماء وذهابِ الأمن، فَتَحَمُّلُ مُنكرِ الولاةِ العصاة، والصبرُ على أذاهم أَهْوَنُ من ذلك.","الصلاةُ شأنُها عظيمٌ، فهي الفارقة بين الكفر والإسلام."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["ستكون","أمراء","فتعرفون","وتنكرون،","فمن","عرف"],"source":"hadeethenc"},{"id":"he_3553","text":"عن أبي موسى الأشعري رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: «إِذَا مَرِضَ الْعَبْدُ أَوْ سَافَرَ كُتِبَ لَهُ مِثْلُ مَا كَانَ يَعْمَلُ مُقِيمًا صَحِيحًا».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم عن فضل الله ورحمته، وأنَّ المسلمَ إذا كان من عادته أن يعمل عملًا صالحًا حال صحته وإقامته ثم حَصَلَ له عذر فمرض فلم يَقدرْ على الإتيان به، أو انشغل بالسَّفر عنه، أو أي عذر؛ فإنه يكتب له الأجر كاملًا، كما لو عَمِلَه في حال الصحة والإقامة.","reference":"صحيح البخاري (4/ 57) (2996).\nشرح رياض الصالحين، لابن عثيمين (1/ 36).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 211).\nبهجة قلوب الأبرار وقرة عيون الأخيار في شرح جوامع الأخبار، لعبد الرحمن السعدي (ص83).","benefits":["سعة فضل الله على عباده.","الحث على الاجتهاد في الطاعات واستغلال الأوقات في حال الصحة والفراغ."],"wordsMeanings":[],"category":"da3wah","bookId":"bukhari","tags":["إذا","مرض","العبد","سافر","كتب","مثل"],"source":"hadeethenc"},{"id":"he_4309","text":"عن تميم الداري رضي الله عنه أن النبي صلى الله عليه وسلم قال: «الدِّينُ النَّصِيحَةُ» قُلْنَا: لِمَنْ؟ قَالَ: «لِلهِ وَلِكِتَابِهِ وَلِرَسُولِهِ وَلِأَئِمَّةِ الْمُسْلِمِينَ وَعَامَّتِهِمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أَخبَرَ النبيُّ صلى الله عليه وسلم بأنَّ الدين قائمٌ على الإخلاص والصدق، حتى يؤدَّى كما أوجب الله، كاملًا دون تقصير أو غش.\n\nفقيل للنبي صلى الله عليه وسلم: لمن تكون النصيحة؟ فقال: \n\nأولًا: النصيحة لله سبحانه وتعالى: بإخلاص العمل له، وعدم الإشراك به، وأن نؤمن بربوبيته وألوهيته وأسمائه وصفاته، وتعظيم أمره، والدعوة إلى الإيمان به. \n\nثانيًا: النصيحة لكتابه وهو القرآن الكريم: بأن نعتقد أنه كلامُه، وآخِرُ كتبِه، وأنه ناسخ لجميع الشرائع قبله، ونعظِّمه، ونتلوه حق تلاوته، ونعمل بمُحْكَمِه، والتسليم بمتشابهه، ونَذُبُّ عن تأويل المُحرِّفين له، ونعتبر بمواعظه، ونشر علومه، والدعوة إليه. \n\nثالثًا: النصيحة لرسوله محمد صلى الله عليه وسلم: بأن نعتقدَ أنه آخِرُ الرسل، ونصدِّقَه فيما جاء به، ونَمتَثِلَ أمرَه، ونجتنبَ نهيَه، وأن لا نتعبدَ لله إلا بما جاء به، ونُعظِّمَ حقَّه، ونوقرَه، ونَبُثَّ دعوته، ونَنشُرَ شريعتَه، ونَنفيَ التُّهَمَ عنه. \n\nرابعًا: النصيحة لأئمة المسلمين: بمعاونتهم على الحق، وعدم منازعتهم الأمر، والسمع والطاعة لهم في طاعة الله. \n\nخامسًا: النصيحة للمسلمين: بالإحسان إليهم ودعوتهم، وكَفِّ الأذى عنهم، ومحبة الخير لهم، والتعاون معهم على البر والتقوى.","reference":"صحيح مسلم (1/ 74) (55).\nالتحفة الربانية في شرح الأربعين حديثا النووية (ص21).\nشرح الأربعين النووية، لابن عثيمين (ص115).\nشرح النووي على مسلم (2/ 37).","benefits":["الأمر بالنصيحة للجميع.","عِظَم منزلة النصيحة من الدين.","اشتمال الدين على الاعتقادات والأقوال والأعمال.","من النصيحة تصفية النفس من الغش للمنصوح له وإرادة الخير له.","حسن تعليم الرسول صلى الله عليه وسلم حيث يذكر الشيء مُجملًا ثم يُفصّله.","البداءة بالأهم فالأهم، حيث بدأ النبي صلى الله عليه وسلم بالنصيحة لله، ثم لكتابه، ثم لرسوله صلى الله عليه وسلم ثم لأئمة المسلمين، ثم عامتهم."],"wordsMeanings":[{"word":"النصيحة","meaning":" تصفية النفس من الغش للمنصوح له وإرادة الخير له."}],"category":"da3wah","bookId":"muslim","tags":["الدين","النصيحة"],"source":"hadeethenc"},{"id":"he_5330","text":"عن عائشة رضي الله عنها قالت: سمعتُ من رسول الله صلى الله عليه وسلم يقول في بيتي هذا: «اللَّهُمَّ مَنْ وَلِيَ مِنْ أَمْرِ أُمَّتِي شَيْئًا فَشَقَّ عَلَيْهِمْ فَاشْقُقْ عَلَيْهِ، وَمَنْ وَلِيَ مِنْ أَمْرِ أُمَّتِي شَيْئًا فَرَفَقَ بِهِمْ فَارْفُقْ بِهِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"دعا رسولُ الله صلى الله عليه وسلم على كلِّ مَن ولي أمرًا من أمور المسلمين صغيرًا كان أم كبيرًا، وسواء كانت هذه الولاية ولاية عامة، أو كانت ولاية جزئية خاصة، وأَدْخَلَ عليهم المشقة ولم يرفق بهم، أنّ الله تعالى يُجازيه مِن جِنْس عمله بأن يشقَّ عليه.\n\nوأنَّ مَن رَفَقَ بهم ويَسَّرَ أمورَهم أن الله يرفِقُ به ويُيَسِّر أمورَه.","reference":"صحيح مسلم (3/ 1458) (1828).\nفتح ذي الجلال والاكرام بشرح بلوغ المرام، لابن عثيمين (6/ 367).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (10/ 224).\nتوضيح الأحكام من بلوغ المرام، للبسام (7/ 419).","benefits":["يجب على من تولّى شيئًا من أمور المسلمين أن يرفق بهم ما استطاع.","الجزاء من جنس العمل.","ميزانُ ما يُعْتَبَرُ من الرفق أو الشدة هو ما لم يخالف الكتاب والسنة."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["اللهم","ولي","أمر","أمتي","شيئا","فشق"],"source":"hadeethenc"},{"id":"he_5335","text":"عن مَعقِلِ بن يَسار المُزَنِيّ رضي الله عنه قال: إني سمعت رسول الله صلى الله عليه وسلم يقول: «مَا مِنْ عَبْدٍ يَسْتَرْعِيهِ اللهُ رَعِيَّةً، يَمُوتُ يَوْمَ يَمُوتُ وَهُوَ غَاشٌّ لِرَعِيَّتِهِ، إِلَّا حَرَّمَ اللهُ عَلَيْهِ الْجَنَّةَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أنَّ كلَّ أحدٍ جَعَلَه الله تعالى واليًا ومسؤولًا على الناس، سواء كانت ولاية عامّة كالأمير، أو ولاية خاصة كالرجل في بيته والمرأة في بيتها، فقَصَّرَ في حق رعيته، وغَشَّها ولم ينصحْ لها، فَضَيَّعَ حقوقَها الدينية والدنيوية، فقد استحقَّ هذه العقوبة الشديدة.","reference":"صحيح البخاري (9/ 64) (7150).\nصحيح مسلم (1/ 125) (142).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 706).\nفيض القدير شرح الجامع الصغير، للمناوي (5/ 488).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 543).","benefits":["هذا الوعيد ليس خاصًّا بالإمام الأعظم ونُوَّابِه، بل هو عامٌّ في كل مَن استرعاه الله رعية.","الواجب على كل مَن وَلي شيئًا من أمر المسلمين أن يَنصحَ لهم، وأن يجتهد في أداء الأمانة، وأن يَحذَرَ الخيانة.","عِظَم مسؤولية كلِّ مَن ولي رعية عامّة أو خاصّة، كبيرة أو صغيرة."],"wordsMeanings":[],"category":"da3wah","tags":["عبد","يسترعيه","الله","رعية،","يموت","يوم"],"source":"hadeethenc"},{"id":"he_58218","text":"عن أبي هريرة رضي الله عنه عن النبي صلى الله عليه وسلم أنه قال: «مَنْ ‌خَرَجَ ‌مِنَ ‌الطَّاعَةِ، وَفَارَقَ الْجَمَاعَةَ فَمَاتَ، مَاتَ مِيتَةً جَاهِلِيَّةً، وَمَنْ قَاتَلَ تَحْتَ رَايَةٍ عِمِّيَّةٍ، يَغْضَبُ لِعَصَبَةٍ، أَوْ يَدْعُو إِلَى عَصَبَةٍ، أَوْ يَنْصُرُ عَصَبَةً، فَقُتِلَ، فَقِتْلَةٌ جَاهِلِيَّةٌ، وَمَنْ خَرَجَ عَلَى أُمَّتِي، يَضْرِبُ بَرَّهَا وَفَاجِرَهَا، وَلَا يَتَحَاشَى مِنْ مُؤْمِنِهَا، وَلَا يَفِي لِذِي عَهْدٍ عَهْدَهُ، فَلَيْسَ مِنِّي وَلَسْتُ مِنْهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ مَن خَرَجَ عن طاعة ولاة الأمور، وفارق جماعة الإسلام المُتَّفِقة على بيعة الإمام، فمات على تلك الحال من المفارقة وعدم الطاعة، مات ميتة أهل جاهلية، الذين كانوا لا يطيعون أميرًا ولا يَنْضَمُّونَ إلى جماعة واحدة، بل كانوا فِرَقًا وعصائب يقاتل بعضهم بعضًا.\n\n \nوأخبر صلى الله عليه وسلم أنَّ مَن قاتل تحت راية لا يَستَبينُ فيها وجه الحق من الباطل، يغضب لمحض التَّعَصُّبِ لقومه أو قبيلته، لا لنصرة الدين والحق، فيقاتل تعصُّبًا بغير بصيرة وعلم، فإذا قُتِل على تلك الحال، كانت كقتلة الجاهلية.\n\n\nوأنَّ مَن خرج على أمته صلى الله عليه وسلم يَضربُ صالحَها، وفاجرَها، ولا يبالي بما يفعله ولا يخاف عقوبتَه مِن قَتْلِ مؤمنِها، ولا يفي لأصحاب العهد من الكفار أو ولاة الأمور بعهدِهم بل يَنقضُها، فهو ليس مني ولست منه.","reference":"صحيح مسلم.\nشرح النووي على مسلم (12/ 238).\nتوضيح الأحكام من بلوغ المرام، للبسام (6/ 179).\nسبل السلام، لمحمد الصنعاني (2/ 374).\nمنحة العلام شرح بلوغ المرام، لعبد الله الفوزان (8/ 338).\nمرقاة المفاتيح شرح مشكاة المصابيح، لعلي القاري (6/ 2395).","benefits":["النهي عن التشبه بأحوال أهل الجاهلية.","وجوب طاعة ولاة الأمور في غير معصية الله عز وجل.","التحذير شديد لمن خرج عن طاعة الإمام، وفارق جماعة المسلمين، فإذا مات على هذه الحال، مات ميتة جاهلية.","النهي عن قتال العصبية.","وجوب الوفاء بالعهود.","في الطاعة ولزوم الجماعة الخير الكثير، والأمن والطمأنينة، وصلاح الأحوال.","هذا الوعيد في الحديث يدل على أن هذه الأعمال من كبائر الذنوب."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["خرج","الطاعة،","وفارق","الجماعة","فمات،","مات"],"source":"hadeethenc"},{"id":"he_58223","text":"عن عرفجة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «مَنْ أَتَاكُمْ وَأَمْرُكُمْ جَمِيعٌ عَلَى رَجُلٍ وَاحِدٍ، يُرِيدُ أَنْ يَشُقَّ عَصَاكُمْ، أَوْ يُفَرِّقَ جَمَاعَتَكُمْ، فَاقْتُلُوهُ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ النبيُّ صلى الله عليه وسلم أنَّ المسلمين إذا اجتمعوا على حاكمٍ واحد، وجماعة واحدة، ثم جاء مَن يريد أن يُنازِعَه الحُكْمَ، أو أراد تفريقَ المسلمين لأكثر من جماعة، وجب عليهم منعُه وقتالُه؛ دفعًا لشرِّه وحقنًا لدماء المسلمين.","reference":"صحيح مسلم (3/ 1480) (1852).\nمنحة العلام في شرح بلوغ المرام، لعبد الله الفوزان (8/ 349).\nتوضيح الأحكام شرح بلوغ المرام، للبسام (6/ 329).\nفتح ذي الجلال والإكرام بشرح بلوغ المرام، لابن عثيمين (5/ 302).\nالمفاتيح في شرح المصابيح، الحسين المُظْهِري (4/ 295).","benefits":["وجوب السمع والطاعة لولي أمر المسلمين في غير معصية، وتحريم الخروج عليه.","مَن خَرَجَ على إمام المسلمين وجماعتهم فإنه يجب قتاله مهما كانت منزلته شَرَفًا ونَسَبًا.","الحث على الاجتماع وعدم التفرُّق والاختلاف."],"wordsMeanings":[{"word":"وأمركم جميع","meaning":" كلمتكم مجتمعة على إمام واحد، وأنتم يد واحدة."},{"word":"يشق عصاكم","meaning":" أصل العصا الاجتماع والائتلاف، والمراد هنا أنه يريد تفريق جماعتكم التي اجتمعت على إمام واحد."}],"category":"da3wah","bookId":"muslim","tags":["أتاكم","وأمركم","جميع","على","رجل","واحد،"],"source":"hadeethenc"},{"id":"he_65001","text":"عن أبي سعيد الخُدْريِّ رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «‌مَنْ ‌رَأَى ‌مِنْكُمْ ‌مُنْكَرًا فَلْيُغَيِّرْهُ بِيَدِهِ، فَإِنْ لَمْ يَسْتَطِعْ فَبِلِسَانِهِ، فَإِنْ لَمْ يَسْتَطِعْ فَبِقَلْبِهِ، وَذَلِكَ أَضْعَفُ الْإِيمَانِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"يأمر النبي صلى الله عليه وسلم بتغيير المنكر -وهو كل ما نهى الله عنه ورسوله- حسب الاستطاعة، \nفإذا رأى منكرًا فيجب عليه تغييره باليد إن كان له قدرة، \nفإن عجز عن ذلك فليغيره بلسانه بأن ينهى مرتكبه ويُبيِّن له ضرره ويرشده إلى الخير بدل هذا الشر، \nفإن عجز عن هذه المرتبة فليغيره بقلبه بأن يَكرَه هذا المنكر ويَعزِم أنه لو قدر على تغييره لفعل، \nوالتغيير بالقلب أضعف مراتب الإيمان في تغيير المنكر.","reference":"صحيح مسلم (1/ 69).\nجامع العلوم والحكم (2/245).\nالمعين على تفهم الأربعين (ص 393).\nشرح الأربعين النووية للعثيمين (ص: 336).\nالبحر المحيط الثجاج (2/204).\nفتح القوي المتين للعباد (ص 116).","benefits":["الحديث أصل في بيان مراتب تغيير المنكر.","الأمر بالتَّدَرُّج في النهي عن المنكر، كلٌّ بحسب استطاعته وقدراته.","النهي عن المنكر باب عظيم في الدين ولا يسقط عن أحد، ويُكَلَّف به كل مسلم بحسب استطاعته.","الأمر بالمعروف والنهي عن المنكر من خصال الإيمان، والإيمان يزيد وينقص.","يشترط في النهي عن المنكر: العلم بكون ذلك الفعل منكرًا.","يشترط في تغيير المنكر: أن لا يترتب عليه منكر أعظم منه.","للنهي عن المنكر آداب وشروط ينبغي على المسلم أن يتعلمها.","إنكار المنكر يحتاج إلى سياسة شرعية، وإلى علم وبصيرة.","عدم الإنكار بالقلب يدل على ضعف الإيمان."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["رأى","منكم","منكرا","فليغيره","بيده،","فإن"],"source":"hadeethenc"},{"id":"he_3045","text":"عَنْ أَبِي سَعِيدٍ الخُدْرِيِّ رضي الله عنه أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّ مِنْ أَعْظَمِ الجِهَادِ كَلِمَةَ عَدْلٍ عِنْدَ سُلْطَانٍ جَائِرٍ».","attribution":"رواه أبو داود والترمذي وابن ماجه وأحمد","grade":"حسن لغيره","gradeKey":"hasan","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ مِن أعظم وأنفع أنواع الجهاد في سبيل الله تعالى كلمةُ عدلٍ وحقٍّ عند سلطان أو أمير جائر ظالم؛ لأنه عمل بشعيرة الأمر بالمعروف والنهي عن المنكر، سواء كان بقول أو كتابة أو فعل أو غير ذلك مما تحصل به المصلحة وتندفع المفسدة.","reference":"سنن الترمذي (4/ 45) (2174).\nسنن أبي داود (6/ 400) (4344).\nسنن ابن ماجه (5/ 144) (4011).\nمسند أحمد (17/ 227) (11143).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 283).\nشرح رياض الصالحين، لابن عثيمين (2/ 453).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 216).","benefits":["الأمر بالمعروف والنهي عن المنكر من الجهاد.","نُصْحُ الحاكم من أعظم الجهاد، ولكن يجب أن يكون بعلم وحكمة وتثبت.","قال الخطَّابي: وإِنَّما صار ذلك أفضل الجهاد؛ لأنّ من جاهَدَ العدوَّ كان مُتردِّدًا بين الرَّجاءِ والخوْفِ لا يدري هل يَغلِبُ أو يُغْلَبُ، وَصَاحِبُ السُّلطان مقهورٌ في يدِهِ فهو إذا قال الحقَّ وَأَمَرَهُ بِالمعروفِ فقد تَعَرَّضَ للتَّلَفِ، وَأَهْدَفَ نَفْسَهُ للهلاكِ، فصار ذلك أَفضل أنواع الجهادِ مِن أجلِ غَلَبَةِ الخوفِ، وقيل: إنما كان أفضل الجهاد؛ لأنَّ وليَّ الأمرِ لو أخَذَ بِكَلمَتِه لربَّما عمَّ النفعُ عددًا كبيرًا من الناسِ فتحصُلُ المصلحةُ."],"wordsMeanings":[],"category":"da3wah","bookId":"abudawud","tags":["أعظم","الجهاد","كلمة","عدل","عند","سلطان"],"source":"hadeethenc"},{"id":"he_3154","text":"عن أبي سفيان صخر بن حرب رضي الله عنه قال: قال هِرَقل: فماذا يَأمُرُكُم -يعني: النبي صلى الله عليه وسلم- قال أبو سفيان: قلت: يقول: «اعبدُوا الله وَحدَه لاَ تُشرِكُوا بِهِ شَيئًا، وَاترُكُوا ما يَقُول آبَاؤُكُم، ويَأمُرُنَا بِالصَّلاَة، والصِّدق، والعَفَاف، والصِّلَة».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"هذا حديث أبي سفيان صخر بن حرب رضي الله عنه المشهور مع هرقل، كان أبو سفيان وقتئذ مشركًا، حيث لم يسلم إلا متأخرًا، فيما بين صلح الحديبية وفتح مكة، قَدِم أبو سفيان ومعه جماعة من قريش إلى هرقل في الشام، وهرقل كان ملك النصارى في ذلك الوقت، وكان قد قرأ في التوراة والإنجيل وعرف الكتب السابقة، وكان ملكًا ذكيًا، فلما سمع بأبي سفيان ومن معه وهم قادمون من الحجاز دعا بهم، وجعل يسألهم عن حال النبي صلى الله عليه وسلم وعن نسبه، وعن أصحابه، وعن توقيرهم له، وعن وفائه صلى الله عليه وسلم ، وكلما ذكر شيئا أخبروه عرف أنه النبي الذي أخبرت به الكتب السابقة، ولكنه - والعياذ بالله- شح بملكه فلم يسلم للحكمة التي أرادها الله عز وجل .\nوكان فيما سأل أبا سفيان سؤاله عمَّا كان يأمرهم به النبي صلى الله عليه وسلم فأخبره بأنه يأمرهم أن يعبدوا الله ولا يشركوا به شيئا، فلا يعبدوا غير الله، لا ملكًا ولا رسولاً، ولا شجرًا ولا حجرًا، ولا شمساً ولا قمرًا، ولا غير ذلك، فالعبادة لله وحده، وهذه دعوة الرسل، فجاء النبي صلى الله عليه وسلم بما جاءت به الأنبياء من قبله بعبادة الله وحده لا شريك له.\nويقول: \"اتركوا ما كان عليه آباؤكم\" وهذا من الصدع بالحق، فكل ما كان آباؤهم من عبادة الأصنام أمرهم النبي صلى الله عليه وسلم بتركه، وأما ما كان عليه آباؤهم من الأخلاق الفاضلة؛ فإنه لم يأمرهم بتركه.\nوقوله: \"وكان يأمرنا بالصلاة\" الصلاة صلة بين العبد وبين ربه، وهي آكد أركان الإسلام بعد الشهادتين، وبها يتميز المؤمن من الكافر، فهي العهد الذي بيننا وبين المشركين والكافرين، كما قال النبي -عليه الصلاة والسلام-: \"العهد الذي بيننا وبينهم الصلاة، فمن تركه فقد كفر\" \nوقوله: \"وكان يأمرنا بالصدق\" كان النبي صلى الله عليه وسلم يأمر أمته بالصدق، وهذا كقوله تعالى : (يا أيها الذين آمنوا اتقوا الله وكونوا مع الصادقين). والصدق خلق فاضل، ينقسم إلى قسمين:\nصدق مع الله، وصدق مع عباد الله، وكلاهما من الأخلاق الفاضلة. \nوقوله \"العفاف\" أي: العفة، والعفة نوعان: عفة عن شهوة الفرج، وعفة عن شهوة البطن.\nأما العفة الأولى: فهي أن يبتعد الإنسان عما حرم عليه من الزنى ووسائله وذرائعه.\nأما النوع الثاني من العفاف: فهو العفاف عن شهوة البطن، أي: عما في أيدي الناس، والتعفف عن سؤالهم، بحيث لا يسأل الإنسانُ أحدًا شيئًا؛ لأن السؤال مذلة، والسائل يده دنيا، سفلى، والمعطي يده عليا، فلا يجوز أن تسأل أحدا إلا ما لابد منه.\nأما قوله: \"الصلة\": فهي أن يصل المرء ما أمر الله به أن يوصل من الأقارب الأدنى فالأدنى، وأعلاهم الوالدان، فإن صلة الوالدين بر وصلة، والأقارب لهم من الصلة بقدر ما لهم من القرب، فالأخ أوكد صلة من العم، والعم أشد صلة من عم الأب، وصلة الرحم تحصل بكل ما تعارف عليه الناس.","reference":"بهجة الناظرين شرح رياض الصالحين، لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nتطريز رياض الصالحين، للشيخ فيصل المبارك، ط1، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة، الرياض، 1423هـ.\nدليل الفالحين لطرق رياض الصالحين، لمحمد علي بن محمد بن علان، ط4،  اعتنى بها: خليل مأمون شيحا، دار المعرفة، بيروت، 1425هـ.\nرياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428","benefits":["الصدق من أشرف مكارم الأخلاق، وهو محبوب عند الخالق والمخلوق.","ملازمة الرسول -صلى الله عليه وسلم- للصدق وشهرته به، وشهادة الأعداء له بذلك.","رأس هذا الدين توحيد الله -عز وجل- وعدم الإشراك به، وهو أصل الفضائل.","التحذير من التقليد في الباطل، ويتأكَّد ذلك في أمور الدين.","الرسل جميعا أرسلوا من أجل بيان التوحيد الحق، والتحذير من الشرك وإزالته.","الله -سبحانه- يأمر بكل ما يصلح البشر ويعود عليهم بالخير في الدنيا والآخرة.","الحديث يؤكد على شمول الإسلام ودعوته إلى العبادة والتوحيد ومكارم الأخلاق."],"wordsMeanings":[{"word":"هِرَقل","meaning":" ملك الروم، ولقبه قيصر، وكتب إليه رسول الله -صلى الله عليه وسلم- يدعوه للإسلام، وكان ذلك سنة ست من الهجرة."},{"word":"أبو سفيان","meaning":" أبو سفيان صخر بن حرب بن أمية بن عبد شمس بن عبد مناف القرشي الأموي المكي، ولد قبل الفيل بعشر سنين، وأسلم ليلة الفتح وكان من المؤلفة، ثم حسن إسلامه، وشهد حنيناً، ثم شهد الطائف وفُقِئَت عينه يومئذٍ، وفقئت عينه الأخرى يوم اليرموك، استعمله النبي -صلى الله عليه وسلم- على نجران."},{"word":"ما يَقُول آبَاؤُكُم","meaning":" جميع ما كانوا عليه في أمور الجاهلية، أما مكارم الأخلاق فقد جاء رسول الله -صلى الله عليه وسلم- ليتمها."},{"word":"العَفَاف","meaning":" الكف عن المحارم وخوارم المروءة."},{"word":"الصِّلَة","meaning":" صلة الأرحام، وكل ما أمر الله -تعالى- به أن يوصل، وذلك بالبر والإكرام."}],"category":"da3wah","tags":["اعبدوا","الله","وحده","تشركوا","شيئا،","واتركوا"],"source":"hadeethenc"},{"id":"he_3156","text":"عَنِ ابْنِ مَسْعُودٍ رضي الله عنه عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «سَتَكُونُ أَثَرَةٌ وَأُمُورٌ تُنْكِرُونَهَا» قَالُوا: يَا رَسُولَ اللَّهِ فَمَا تَأْمُرُنَا؟ قَالَ: «تُؤَدُّونَ الحَقَّ الَّذِي عَلَيْكُمْ، وَتَسْأَلُونَ اللَّهَ الَّذِي لَكُمْ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنه سيتولى على المسلمين وُلاةٌ يَستأثِرون بأموال المسلمين وغيرِها مِن أمور الدنيا، يَصْرِفُونها كما شاؤوا ويمنعون المسلمين حقَّهم فيها. \nوسيكون منهم في الدِّين أمورٌ تُنْكَر. \nفسَألَ الصحابةُ رضي الله عنهم: ماذا يفعلون في تلك الحال؟ \nفأخبرهم صلى الله عليه وسلم أنه لا يمنعكم انفرادُهم بالمال أنْ تَمْنَعوا ما يجب عليكم نحوَهم من السمع والطاعة، بل اصبروا واسمعوا وأطيعوا ولا تنازعوهم الأمر، واسألوا الحق الذي لكم من الله، وأن يُصلحَهم ويَدفعَ شرَّهم وظلمَهم.","reference":"صحيح البخاري (4/ 199) (3603).\nصحيح مسلم (3/ 1472) (1843).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 720).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص52).\nكنوز رياض الصالحين، لمجموعة من الباحثين (9/ 402).\nشرح رياض الصالحين، لابن عثيمين (1/ 280).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 554).","benefits":["الحديثُ من دلائل نبوَّتِه صلى الله عليه وسلم حيث أخبر بما سيكون في أمته فوقع كما أخبر.","جوازُ إعلام المُبتلى بما يُتَوَقَع له من البلاء؛ لِيُوَطِّنَ نفسَه فإذا أتاه كان صابرًا محتسبًا.","الاعتصام بالكتاب والسنة مخرج من الفتن والاختلاف.","الحث على السمع والطاعة لولاة الأمور بالمعروف، وعدم الخروج عليهم، وإنْ وقع منهم ظلم.","استعمال الحكمة واتباع السنة في زمن الفتن.","على الإنسان القيام بالحق الذي عليه وإنْ حَصَل عليه شيء من الظلم.","فيه دليلٌ على القاعدة: يختار أهون الشرين أو أخف الضررين."],"wordsMeanings":[{"word":"الأَثَرَة","meaning":" الاستئثار عليهم بأمور الدنيا والانفراد بها، عمن له فيه حق."}],"category":"da3wah","tags":["ستكون","أثرة","وأمور","تنكرونها","قالوا:","رسول"],"source":"hadeethenc"},{"id":"he_3229","text":"عن عبد الله بن عبَّاس رضي الله عنهما قال: «أُمِرَ الناس أن يكون آخر عَهْدِهِمْ بالبيت، إلا أنه خُفِّفَ عن المرأة الحائض».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"لهذا البيت الشريف تعظيم وتكريم؛ فهو رمز لعبادة الله والخضوع والخشوع بين يديه، فكان له في الصدور مهابة، وفِى القلوب إجلال، وتعلق، ومودة.\nولذا أمر النبي صلى الله عليه وسلم الحاج قبل السفر أن يكون آخر عهده به، وهذا الطواف الأخير هو طواف الوداع، إلا المرأة الحائض؛ فلكونها تلوث المسجد بدخولها سقط عنها الطواف بلا فداء، وهذا النص في الحج فلا يتناول العمرة.","reference":"تيسير العلام شرح عمدة الأحكام، عبد الله بن عبد الرحمن البسام، تحقيق: محمد صبحي حلاق، مكتبة الصحابة، الأمارات، مكتبة التابعين، القاهرة، الطبعة: العاشرة 1426هـ.\nتنبيه الأفهام شرح عمدة الأحكام، محمد بن صالح العثيمين، مكتبة الصحابة، الإمارات، الطبعة: الأولى 1426هـ.\nالإفهام في شرح عمدة الأحكام لابن باز، تحقيق: سعيد القحطاني، مؤسسة عبد العزيز بن باز الخيرية، الرياض، الطبعة: الأولى 1435هـ.\nخلاصة الكلام ش","benefits":["أن طواف الوداع يكون آخر شئون الحاج؛ لأن هذا معنى الوداع، وشراء بعض الأشياء في طريقه إلى السفر، أو انتظار الرفقة، أو نحو ذلك من التأخر اليسير لا يضر.","عظم حُرْمة الكعبة.","أن الحائض ليس عليها طواف للوداع، ولا دم بتركه.","تيسير الشريعة الإسلامية."],"wordsMeanings":[{"word":"أُمِرَ الناس","meaning":" أمرهم النبي -صلى الله عليه وسلم-، والمراد بالناس: الحجاج المسافرون إلى أهاليهم بعد تمام النسك."},{"word":"عَهْدِهِمْ","meaning":" التقائهم."},{"word":"بالبيت","meaning":" بالطواف بالبيت، أي الكعبة."},{"word":"خُفِّف","meaning":" خفف النبي -صلى الله عليه وسلم-."},{"word":"الحائض","meaning":" التي أصابها الحيض حين خروجها من مكة."}],"category":"da3wah","tags":["أُمِرَ","الناس","يكون","آخر","عَهْدِهِمْ","بالبيت،"],"source":"hadeethenc"},{"id":"he_3341","text":"عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَا عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «مَثَلُ القَائِمِ عَلَى حُدُودِ اللَّهِ وَالوَاقِعِ فِيهَا، كَمَثَلِ قَوْمٍ اسْتَهَمُوا عَلَى سَفِينَةٍ، فَأَصَابَ بَعْضُهُمْ أَعْلاَهَا وَبَعْضُهُمْ أَسْفَلَهَا، فَكَانَ الَّذِينَ فِي أَسْفَلِهَا إِذَا اسْتَقَوْا مِنَ المَاءِ مَرُّوا عَلَى مَنْ فَوْقَهُمْ، فَقَالُوا: لَوْ أَنَّا خَرَقْنَا فِي نَصِيبِنَا خَرْقًا وَلَمْ نُؤْذِ مَنْ فَوْقَنَا، فَإِنْ يَتْرُكُوهُمْ وَمَا أَرَادُوا هَلَكُوا جَمِيعًا، وَإِنْ أَخَذُوا عَلَى أَيْدِيهِمْ نَجَوْا، وَنَجَوْا جَمِيعًا».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"ضَرَبَ النبيُّّ صلى الله عليه وسلم مَثَلًا للقائمين بحدود الله، المستقيمين على أمر الله، الآمرين بالمعروف، الناهين عن المنكر، \nومثل الواقعين في حدود الله التاركين للمعروف، المرتكبين للمنكر، وأثر ذلك في نجاة المجتمع، كمثل قوم ركبوا في سفينة، فاقترعوا على مَن يَجلس أعلى السفينة ومَن يَجلس أسفلَها، فنال بعضُهم أعلاها، وبعضُهم أسفلَها، وكان الذين في الأسفل إذا أرادوا جَلْبَ الماءِ مَرُّوا على من فوقهم، \nفقال الذين في الأسفل: لو أنَّا خَرَقْنا خرقًا في مكاننا في الأسفل نستقي منه، حتى لا نؤذي من فوقنا، فلو تركهم مَن بالأعلى يَفعلون ذلك، لَغَرِقَت السفينةُ بهم جميعًا، ولو قاموا بنهيهم عن ذلك ومنعوهم، لنجى الفريقان جميعًا.","reference":"صحيح البخاري (3/ 139) (2493).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 277).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص149).\nشرح رياض الصالحين، لابن عثيمين (2/ 430).\nكنوز رياض الصالحين، مجموعة من الباحثين (4/ 39).\nنزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين (1/ 210).","benefits":["أهمية الأمر بالمعروف والنهي عن المنكر في حفظِ المجتمعات ونجاتِها.","من طُرُقِ التعليم ضَرْبُ الأمثال، لتقريب المعاني للعقول بصورة المحسوس.","فِعْلُ المنكرِ الظاهرِ مع عدم الإنكار عليه مفسدةٌ تعود على الجميع بالضرر.","هلاك المجتمع مُتَرَتِّب على ترك أصحاب المنكر يعيثون في الأرض فسادًا.","التصرف الخاطئ والنية الحسنة لا تكفي في صلاح العمل.","المسؤولية في المجتمع المسلم مشتركة لا تُناط بفرد بعينه.","تعذيب العامة بذنوب الخاصة إن لم تُنكر.","أصحاب المنكرات يُظهرون مُنكرَهم في قالب خير للمجتمع كما أهل النفاق."],"wordsMeanings":[],"category":"da3wah","bookId":"bukhari","tags":["مثل","القائم","على","حدود","الله","والواقع"],"source":"hadeethenc"},{"id":"he_3344","text":"عن علي بن أبي طالب رضي الله عنه قال: \"حدثوا الناس بما يعرفون، أتريدون أن يُكذَّب اللهُ ورسولهُ؟\".","attribution":"أخرجه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يرشد أمير المؤمنين علي بن أبي طالب رضي الله عنه إلى أنه لا ينبغي أن يحدث عامة الناس إلا بما هو معروف ينفع الناس في أصل دينهم وأحكامه من التوحيد وبيان الحلال والحرام ويُترك ما يشغل عن ذلك؛ مما لا حاجة إليه أو كان مما قد يؤدي إلى رد الحق وعدم قبوله مما يشتبه عليهم فهمه، ويصعب عليهم إدراكه.","reference":"كتاب التوحيد للإمام محمد بن عبد الوهاب، ت: د. دغش العجمي، مكتبة أهل الأثر, الطبعة الخامسة, 1435ه.\nالجديد في شرح كتاب التوحيد، لمحمد بن عبد العزيز السليمان القرعاوي, ت: محمد بن أحمد سيد, مكتبة السوادي، الطبعة: الخامسة، 1424ه.\nالملخص في شرح كتاب التوحيد، للشيخ صالح الفوزان, دار العاصمة, الطبعة الأولى، 1422ه.\nصحيح البخاري, ترقيم محمد فؤاد عبد الباقي, دار طوق النجاة, الطبعة: الأولى، 1422هـ.","benefits":["أنه إذا خشي ضررٌ من تحديث الناس ببعض ما لا يفهمون؛ فلا ينبغي تحديثهم بذلك وإن كان حقاً.","ما يؤدي إلى الحرام فهو حرام.","لا يجوز تحديث الناس بما لا تدركه عقولهم."],"wordsMeanings":[{"word":"بما يعرفون","meaning":" بما لا يفتنهم مما لا تدركه عقولهم."}],"category":"da3wah","bookId":"bukhari","tags":["حدثوا","الناس","بما","يعرفون،","أتريدون","يُكذَّب"],"source":"hadeethenc"},{"id":"he_3470","text":"عَنْ أَبِي بَكْرٍ الصِّدِّيقِ رضي الله عنه أَنَّهُ قَالَ: أَيُّهَا النَّاسُ، إِنَّكُمْ تَقْرَؤُونَ هَذِهِ الآيَةَ: {يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لاَ يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ}، وَإِنِّي سَمِعْتُ رَسُولَ اللهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ: «إِنَّ النَّاسَ إِذَا رَأَوْا الظَّالِمَ فَلَمْ يَأْخُذُوا عَلَى يَدَيْهِ أَوْشَكَ أَنْ يَعُمَّهُمُ اللَّهُ بِعِقَابٍ مِنْهُ».","attribution":"رواه أبو داود والترمذي والنسائي في الكبرى وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ أبو بكر الصديق رضي الله عنه: أن الناس يقرؤون هذه الآية: \n\n{يَا أَيُّهَا الَّذِينَ آمَنُوا عَلَيْكُمْ أَنْفُسَكُمْ لاَ يَضُرُّكُمْ مَنْ ضَلَّ إِذَا اهْتَدَيْتُمْ} [المائدة: 105].\n\nويفهمون منها أنّ على الإنسان السعي في إصلاح نفسه فقط، وأنه لا يضره بعد ذلك ضلال من ضل، وأنهم غير مطالَبين بالأمر بالمعروف والنهي عن المنكر! \n\nفأعلمهم أنها ليست كذلك، وأنه سمع النبي صلى الله عليه وسلم يقول: \nإن الناس إذا رأوا الظالم فلم يمنعوه من ظلمه، وعندهم القدرة على منعه، يوشك أن يعمَّ الله الجميعَ بعقاب من عنده، الفاعل للمنكر، والساكت عنه.","reference":"سنن الترمذي (4/ 40) (2168).\nسنن أبي داود (6/ 393) (4338).\nالسنن الكبرى للنسائي (10/ 88) (11092).\nسنن ابن ماجه (5/ 139) (4005).\nمسند أحمد (1/ 197) (16).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 286).\nكنوز رياض الصالحين، مجموعة من الباحثين (4/ 126).\nشرح رياض الصالحين، لابن عثيمين (2/ 454).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 218).","benefits":["واجب المسلمين التناصح والأمر بالمعروف والنهي عن المنكر.","عقاب الله العام يشمل الظالم لظلمه، ويشمل الساكت عن الإنكار إن كان قادرًا على الإنكار.","تعليم العامة وإفهامهم النصوص القرآنية على الوجه الصحيح لها.","أنه يجب على الإنسان العناية بفهم كتاب الله عز وجل، حتى لا يفهمه على غير ما أراد الله تعالى.","الاهتداء لا يتحقق مع ترك الأمر بالمعروف والنهي عن المنكر.","التفسير الصواب للآية: الزموا حفظ أنفسكم عن المعاصي، فإذا حفظتم أنفسكم لم يضركم إذا عجزتم عن الأمر بالمعروف والنهي عن المنكر ضلال من ضل بارتكاب المناهي إذا اهتديتم إلى اجتنابها."],"wordsMeanings":[],"category":"da3wah","bookId":"abudawud","tags":["الناس","إذا","رأوا","الظالم","فلم","يأخذوا"],"source":"hadeethenc"},{"id":"he_3531","text":"عن حذيفة بن اليمان رضي الله عنهما عن رسول الله صلى الله عليه وسلم أنه قال: «وَالَّذِي نَفسِي بِيَدِه، لَتَأْمُرُنَّ بِالمَعرُوف، وَلَتَنهَوُنَّ عَنِ المُنْكَر؛ أَو لَيُوشِكَنَّ الله أَن يَبْعَثَ عَلَيكُم عِقَاباً مِنْه، ثُمَّ تَدعُونَه فَلاَ يُسْتَجَابُ لَكُم».","attribution":"رواه الترمذي وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"قوله -عليه الصلاة والسلام-: \"والذي نفسي بيده\" هذا قسم، يقسم فيه النبي صلى الله عليه وسلم بالله؛ لأنه هو الذي أَنْفُسُ العباد بيده جل وعلا ، يهديها إن شاء، ويضلها إن شاء، ويميتها إن شاء، ويبقيها إن شاء، فالأنفس بيد الله هداية وضلالة، وإحياء وإماتة وتصرفًا وتدبيرًا في كل شيء، كما قال الله -تبارك وتعالى-: (ونفس وما سواها، فألهمها فجورها وتقواها)، فالأنفس بيد الله وحده؛ ولهذا أقسم النبي صلى الله عليه وسلم ، وكان يقسم كثيرًا بهذا القسم: (والذي نفسي بيده)، وأحيانًا يقول: \"والذي نفس محمد بيده\"؛ لأن نفس محمد صلى الله عليه وسلم أطيب الأنفس، فأقسم بها؛ لكونها أطيب الأنفس.\nثم ذكر المقسم عليه، وهو أن نقوم بالأمر بالمعروف والنهي عن المنكر؛ أو يعمنا الله بعقاب من عنده، حتى ندعوه فلا يستجيب لنا، وهذا بيان لأهمية الأمر بالمعروف كالصلاة والزكاة وأداء الحقوق، وأهمية النهي عن المنكر كالزنى والرب وسائر المحرمات، وذلك بالفعل لمن له سلطة كالأب في بيته ورجال الحسبة والشرطة، أو بالقول الحسن وهذا لكل أحد، أو بالقلب مع مفارقة مكان المنكر، وهذا لمن لا يستطيع الإنكار بالفعل أو بالقول.","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الدمام، الطبعة: الأولى 1415هـ.\nسنن الترمذي، محمد بن عيسى الترمذي، تحقيق وتعليق: أحمد محمد شاكر، ومحمد فؤاد عبد الباقي، وإبراهيم عطوة عوض، شركة مكتبة ومطبعة مصطفى البابي الحلبي، مصر، الطبعة: الثانية، 1395هـ- 1975م.\nرياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق ماهر الفحل، دار ابن كثير، دمشق، بيروت، الطبعة","benefits":["جواز القسم دون أن يطلب من الإنسان أن يقسم.","وجوب الأمر بالمعروف والنهي عن المنكر وهو فرض، وهو من أهم واجبات الدين وفروضه.","يعم شؤم المنكر وبلاؤه فاعله وغيره.","الأمر بالمعروف والنهي عن المنكر صمام أمان من غضب الله وعقابه.","إذا لم يُنكَر المنكر عمَّ شؤمه وبلاؤه بجور الولاة أو تسليط الأعداء، أو غير ذلك.","من عقوبات التفريط بترك الأمر بالمعروف والنهي عن المنكر عدم استجابة الدعاء."],"wordsMeanings":[{"word":"وَالَّذِي نَفسِي بِيَدِه","meaning":" أي: والله، وأتى بالقسم لتوكيد الأمر الذي بعده."},{"word":"لَيُوشِكَنَّ","meaning":" مضارع أوشك، وهو من أفعال المقاربة، بمعنى يقرب ويكاد."}],"category":"da3wah","bookId":"tirmidhi","tags":["والذي","نفسي","بيده،","لتأمرن","بالمعروف،","ولتنهون"],"source":"hadeethenc"},{"id":"he_4568","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «كُلُّ سُلاَمَى مِنَ النَّاسِ عَلَيْهِ صَدَقَةٌ، كُلَّ يَوْمٍ تَطْلُعُ فِيهِ الشَّمْسُ يَعْدِلُ بَيْنَ الِاثْنَيْنِ صَدَقَةٌ، وَيُعِينُ الرَّجُلَ عَلَى دَابَّتِهِ فَيَحْمِلُ عَلَيْهَا أَوْ يَرْفَعُ عَلَيْهَا مَتَاعَهُ صَدَقَةٌ، وَالكَلِمَةُ الطَّيِّبَةُ صَدَقَةٌ، وَكُلُّ خُطْوَةٍ يَخْطُوهَا إِلَى الصَّلاَةِ صَدَقَةٌ، وَيُمِيطُ الأَذَى عَنِ الطَّرِيقِ صَدَقَةٌ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ على كلِّ مسلم مُكلَّف كلّ يوم بعدد كل مفصل من مفاصل عظامه صدقة تطوع لله تعالى على سبيل الشكر له على العافية، وأن جعل عظامه مفاصل يتمكن بها من القبض والبسط، \nوأنّ تلك الصدقة تتأدّى بأعمال البر كلها ولا تتوقف على إعطاء مال، ومنها: \nعدلك وإصلاحك بيـن متخاصمين صدقةٌ،\nوفي إعانتك لعاجز في دابته فتحمله عليها أو ترفع له متاعه صدقةٌ، \nوالكلمة الطيبة من ذكر ودعاء وسلام وغيرها صدقةٌ،\nوبكل خطوةٍ تمشيها إلى الصلاة صدقةٌ، \nوإزالة ما يُتَأذّى به عن الطريق صدقةٌ.","reference":"صحيح البخاري (4/ 56) (2989).\nصحيح مسلم (1/ 498) (720).\n-التحفة الربانية في شرح الأربعين حديثًا النووية، مطبعة دار نشر الثقافة، الإسكندرية، الطبعة: الأولى، 1380 هـ.\n-شرح الأربعين النووية، للشيخ ابن عثيمين، دار الثريا للنشر.\n-فتح القوي المتين في شرح الأربعين وتتمة الخمسين، دار ابن القيم، الدمام المملكة العربية السعودية، الطبعة: الأولى، 1424هـ/2003م.\n-الفوائد المستنبطة من الأربعين النووية، للشيخ عبد ","benefits":["تركيب عظام الآدمي وسلامتها من أعظم نعم الله تعالى عليه، فيحتاج كل عظم منها إلى تصدق عنه بخصوصه ليتم شكر تلك النعمة.","الترغيب في تجديد الشكر كل يوم لدوام تلك النعم.","الترغيب في المداومة على النوافل والصدقات كل يوم.","فضل الإصلاح بين الناس.","الحث على معونة الرجل أخاه؛ لأن معونته إياه صدقة.","الحث على حضور الجماعات والمشي إليها، وعمارة المساجد بذلك.","وجوب احترام طرق المسلمين بتجنب ما يؤذيهم أو يضر بهم."],"wordsMeanings":[{"word":"سُلامى","meaning":" بضم السين المهملة وتخفيف اللام مع القصر، وهي المفاصل، وقد ثبت في صحيح مسلم أنها ثلاثمائة وستون."}],"category":"da3wah","tags":["سلامى","الناس","عليه","صدقة"],"source":"hadeethenc"},{"id":"he_4931","text":"عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: \"يُصَلُّونَ لكم، فإن أصابوا فلكم، وإن أخطأوا فلكم وعليهم\".","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم أن هناك أئمة يعني أمراء يصلون لكم، فإن أحسنوا فلكم ولهم الأجر، وإن أساءوا فلكم الأجر على الصلاة وعليهم وزر الإساءة فيها، وهذا وإن كان في الأمراء فإنه يشمل أيضًا أئمة المساجد، كل منهم على حسب إحسانه للصلاة أو إساءتها، وفي الحديث إشارة إلى أنه يجب الصبر على ولاة الأمر وإن أساءوا في الصلاة وإن لم يصلوها على وقتها، فإن الواجب ألا نشذ عنهم وأن نؤخر صلاة الجماعة كما يؤخرون، وحينئذ يكون تأخيرنا للصلاة عن أول وقتها يكون تأخيرًا بعذر لأجل موافقة الجماعة وعدم الشذوذ ويكون بالنسبة لنا كأننا صلينا في أول الوقت، والتأخير مشروط بألا يخرج وقت الصلاة، وأن الشذوذ عن الناس وعن ولاة الأمور والبعد عنهم وإثارة الناس عليهم ونشر مساوئهم كل هذا مجانب للدين الإسلامي.","reference":"صحيح البخاري، تحقيق: محمد زهير بن ناصر الناصر، ط1، دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم: محمد فؤاد عبد الباقي)، 1422ه.\nصحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، دار إحياء التراث العربي، بيروت.\nنزهة المتقين، تأليف: جمعٌ من المشايخ، الناشر: مؤسسة الرسالة، الطبعة الأولى، 1397هـ، الطبعة الرابعة عشر، 1407هـ.\nبهجة الناظرين، تأليف: سليم بن عيد الهلالي، الناشر: دار ابن الجوزي، سنة النشر: 1418هـ -","benefits":["الرد على من يزعم أنه إذا فسدت صلاة الإمام فسدت صلاة المأموم، وصحة صلاة المأمومين قال بها الجمهور من الفقهاء.","في الحديث إشارة إلى أنه يجب الصبر على ولاة الأمر وإن أساءوا في الصلاة وإن لم يصلوها على وقتها فإن الواجب ألا نشذ عنهم وأن لا نؤخر الصلاة كما يؤخرونها.","بيان فضل صلاة الجماعة.","الإمام ضامن بمعنى أنه يتحمل خطأ بعض المأمومين خلفه، ولا يحملون خطأه فتصح صلاتهم دونه عند وجود خلل في الصلاة."],"wordsMeanings":[{"word":"يصلون لكم","meaning":" يصلي الأئمة لإقامة الجماعة لكم."},{"word":"فلكم","meaning":" الأجر لكم ولهم أيضًا."},{"word":"فلكم وعليهم","meaning":" إن أخطأوا فلكم الأجر وعليهم الوزر."}],"category":"da3wah","bookId":"bukhari","tags":["يصلون","لكم،","فإن","أصابوا","فلكم،","وإن"],"source":"hadeethenc"},{"id":"he_4938","text":"عن عائشة رضي الله عنها قَالَتْ: سَمِعْتُ رَسُولَ اللهِ -صَلّى اللهُ عَلَيْهِ وسَلَّم- يقُولُ في بيتي هَذَا: «اللهم من وَلِيَ من أمر أمتي شيئًا فَشَقَّ عليهم، فَاشْقُقْ عليه، ومن وَلِيَ من أمر أمتي شيئًا فَرَفَقَ بهم، فَارْفُقْ به».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث بيان عظم أمر الولاية، وقد دعا النبي صلى الله عليه وسلم أنَّ مَن ولي مِن أمر الناس شيئاً فضيَّق عليهم أن يعامله الله بالمثل، ومن عاملهم بالعدل والانصاف والرحمة واللين أن يجازيه على ذلك، والجزاء من جنس العمل.","reference":"صحيح مسلم, ترقيم محمد فؤاد عبد الباقي, دار إحياء التراث العربي, بيروت.\nشرح رياض الصالحين، لابن عثيمين, دار مدار الوطن للنشر، الرياض, الطبعة، 1426هـ.\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي, دار ابن الجوزي.\nتطريز رياض الصالحين، لفيصل بن عبد العزيز المبارك النجدي, تحقيق: عبد العزيز آل حمد, دار العاصمة, الطبعة الأولى، 1423هـ.\nكنوز رياض الصالحين، بإشراف حمد العمار, دار كنوز إشبيليا, الطبعة الأو","benefits":["اهتمام النبي -صلى الله عليه وسلم- بأمور أمته.","التنبيه لولاة الأمور على السعي في مصالح الرعية.","إذا شق الحاكم على أمته أوقعه الله في المشاق.","أنَّ أسلوب الترغيب والترهيب من أساليب الدعوة النافعة."],"wordsMeanings":[{"word":"شق عليهم","meaning":" ضيَّق وشدد عليهم بغير حق."},{"word":"فاشقق عليه","meaning":" أوقعه في المشاق."},{"word":"فرفق بهم","meaning":" لان لهم وعطف عليهم ورعى حقوقهم."},{"word":"فارفق به","meaning":" أي افعل به ما فيه الرفق له مجازاة له بمثل فعله."}],"category":"da3wah","bookId":"muslim","tags":["اللهم","ولي","أمر","أمتي","شيئا","فشق"],"source":"hadeethenc"},{"id":"he_4953","text":"عن الزبير بن عدي، قال: أَتَيْنَا أنسَ بنَ مَالِكٍ رضي الله عنه فَشَكَوْنَا إليه ما نَلْقَى من الحَجَّاجِ، فقال: «اصْبِرُوا، فإنه لا يأتي زمانٌ إلا والذي بعده شَرٌّ منه حَتَّى تَلْقَوا رَبَّكُم» سمعتُه من نَبِيِّكُم صلى الله عليه وسلم .","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"جاء الزبير بن عدي ومعه جماعة إلى أنس بن مالك رضي الله عنه خادم رسول الله صلى الله عليه وسلم ، يشكون إليه ما يجدون من الحجاج بن يوسف الثقفي، أحد الأمراء لخلفاء بني أمية، وكان جبارًا عنيدًا معروفًا بالظلم وسفك الدماء، فأمرهم أنس رضي الله عنه بالصبر على جور ولاة الأمور، وأخبرهم أنه لا يأتي على الناس زمان إلا والذي بعده أشر منه حتى يلقوا ربهم، وأنه سمعه من رسول الله صلى الله عليه وسلم .\nوالشر ليس شرًّا مطلقًا عامًّا، بل قد يكون شرًّا في بعض المواضع، ويكون خيرًا في مواضع أخرى.","reference":"- دليل الفالحين لطرق رياض الصالحين، لابن علان، نشر دار الكتاب العربي.\n- نزهة المتقين شرح رياض الصالحين، نشر: مؤسسة الرسالة، الطبعة: الرابعة عشر، 1407هـ - 1987م.\n- شرح رياض الصالحين، لابن عثيمين، نشر: دار الوطن للنشر، الرياض، الطبعة: 1426هـ.\n- بهجة الناظرين شرح رياض الصالحين، للهلالي، نشر: دار ابن الجوزي.\n- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم ترقيم محمد فؤاد عبد الباق","benefits":["جواز شكوى الإمام أو الحاكم لأهل العلم.","القيادة الحقيقية للناس كامنة في أهل العلم.","ولاية الحجاج بن يوسف الثقفي ظالمة.","استحباب الصبر على المحن، والمبادرة بالأعمال الصالحة.","انتشار الفساد في آخر الزمان.","عدم الخروج على ولاة الأمور وإن ظلموا وجاروا.","في الحديث دليل على دفع المفسدة الكبرى بالمفسدة الصغرى، فالصبر على ظلم الحاكم خير من سفك دماء المسلمين."],"wordsMeanings":[{"word":"اصبروا","meaning":" أي: على ما تلقون منه."},{"word":"تلقوا ربكم","meaning":" يدرككم الموت."}],"category":"da3wah","bookId":"bukhari","tags":["اصْبِرُوا،","فإنه","يأتي","زمانٌ","إلا","والذي"],"source":"hadeethenc"},{"id":"he_5037","text":"عَنْ وَائِلٍ الْحَضْرَمِيِّ قَالَ: سَأَلَ سَلَمَةُ بْنُ يَزِيدَ الْجُعْفِيُّ رضي الله عنه رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَقَالَ: يَا نَبِيَّ اللهِ، أَرَأَيْتَ إِنْ قَامَتْ عَلَيْنَا أُمَرَاءُ يَسْأَلُونَا حَقَّهُمْ وَيَمْنَعُونَا حَقَّنَا، فَمَا تَأْمُرُنَا؟ فَأَعْرَضَ عَنْهُ، ثُمَّ سَأَلَهُ، فَأَعْرَضَ عَنْهُ، ثُمَّ سَأَلَهُ فِي الثَّانِيَةِ أَوْ فِي الثَّالِثَةِ، فَجَذَبَهُ الْأَشْعَثُ بْنُ قَيْسٍ، وَقَالَ: «اسْمَعُوا وَأَطِيعُوا، فَإِنَّمَا عَلَيْهِمْ مَا حُمِّلُوا، وَعَلَيْكُمْ مَا حُمِّلْتُمْ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"سُئِلَ النبيُّ صلى الله عليه وسلم عن الأمراء الذين يَطلبون حَقَّهم من الناس مِن السمع والطاعة، ويَمنعون الحقَّ الذي عليهم؛ مِن بَذْل العدل وإعطاء الغنيمة ورد المظالم والتسوية، فما تأمرنا أن نفعل معهم؟ \n\nفأعْرَضَ النبيُّ صلى الله عليه وسلم عنه؛ كأنه كَرِهَ هذه المسائل، لكنْ أعادَ السائلُ عليه مرة ثانية وثالثة، فَجَذَبَ الأشعثُ بنُ قيس رضي الله عنه السائلَ لِيُسْكِتَه.\n\nفأجاب النبيُّ صلى الله عليه وسلم، وقال: اسمعوا لقولِهم، وأطيعوا أمرَهم؛ فإنما عليهم ما حُمِّلوا وما كُلِّفوا مِن العدل وإعطاء حق الرعية، وعليكم ما حُمِّلْتُم من الطاعة وأداء الحقوق والصبر على البلية.","reference":"صحيح مسلم (3/ 1474) (1846).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 719).\nشرح رياض الصالحين، لابن عثيمين (3/ 664).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص432).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 553).","benefits":["الأمر بالسمع والطاعة للأمراء على كل حال فيما يرضي الله عز وجل، وإن لم يقوموا بحق الرعية.","تقصير الحكّام في واجبهم لا يُسَوِّغُ تقصيرَ الناس بالمقابل في واجباتهم؛ فكلٌّ مسؤولٌ عن عملِه، ومؤاخذ عن تقصيره.","الدين ليس مبنيًّا على المُقايَضَة، وإنما على الالتزام بما وَجَب وإنْ قَصَّرَ الآخَرُ بما وجب عليه في المقابل، كما ورد في هذا الحديث."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["اسمعوا","وأطيعوا،","فإنما","عليهم","حملوا،","وعليكم"],"source":"hadeethenc"},{"id":"he_5345","text":"عن عبد الله بن عمرو رضي الله عنهما قال: كنا مع رسول الله - صلى الله عليه وسلم- في سفر، فَنَزَلنَا مَنْزِلًا، فَمِنَّا مَنْ يُصلِح خِبَاءَه، ومِنَّا من يَنتَضِل، ومِنَّا مَن هو في جَشَرِهِ، إِذْ نادى مُنادي رسول الله صلى الله عليه وسلم : الصَّلاةُ جَامِعَةٌ. فاجْتَمَعنَا إلى رسول الله - صلى الله عليه وسلم - فقال: «إِنَّه لَمْ يَكُن نبي قبْلِي إِلاَّ كَان حَقًّا عليه أَنْ يَدُلَّ أُمَّتَه عَلَى خَيرِ مَا يَعْلَمُهُ لَهُم، ويُنذِرَهُم شّرَّ ما يعلمه لهم، وإِنَّ أُمَّتُكُم هذه جَعَل عَافِيَتَهَا في أوَّلِها، وَسَيُصِيبُ آخِرَهَا بَلاَءٌ وأُمُورٌ تُنكِرُونَهَا، وتَجِيءُ فِتنَةٌ يُرَقِّقُ بَعْضُهَا بَعضًا، وتَجِيءُ الفتنة فيقول المؤمن: هذه مُهلِكَتِي، ثُمَّ تَنْكَشِف، وتجيء الفتنة فيقول المؤمن: هَذِه هذِه. فمَنْ أَحَبَّ أنْ يُزَحْزَحَ عن النار، ويدخل الجنة، فَلْتَأْتِه مَنِيَتُهُ وهو يؤمن بالله واليوم الآخر، وَلْيَأتِ إِلى النَّاسِ الَّذِي يُحِبُّ أَنْ يُؤْتَى إليه، ومَنْ بَايَع إِمَامًا فَأَعْطَاه صَفْقَةَ يَدِهِ، وَثَمْرَةَ قلْبِهِ، فَلْيُطِعُه إِن اسْتَطَاع، فَإِن جَاء آخَرُ يُنَازِعُه فَاضْرِبُوا عُنُقَ الآخَرِ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث أنه يجب على الدعاة ما يجب على الأنبياء من بيان الخير والحث عليه ودلالة الناس إليه وبيان الشر والتحذير منه، وفيه أن صدر هذه الأمة حصل لها الخير والسلامة من الابتلاء، وأنه سيصيب آخر هذه الأمة من الشر والبلاء ما تجعل الفتن القادمة تهون الفتن السابقة، وأن النجاة منها يكون بالتوحيد والاعتصام بالسنة، وحسن معاملة الناس، والالتزام ببيعة الحاكم، وعدم الخروج عليه، وقتال من يريد تفريق جماعة المسلمين.","reference":"- رياض الصالحين من كلام سيد المرسلين؛ للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير-دمشق، الطبعة الأولى، 1428ه .\n- دليل الفالحين لطرق رياض الصالحين؛ لمحمد بن علان الشافعي، دار الكتاب العربي-بيروت\n- بهجة الناظرين شرح رياض الصالحين؛ تأليف سليم الهلالي، دار ابن الجوزي- الطبعة الأولى1418ه\n- نزهة المتقين شرح رياض الصالحين؛ تأليف د. مصطفى الخِن وغيره، مؤسسة الرسالة-بيروت، الطبعة الرابعة عشر","benefits":["استحباب جمع الناس وإخبارهم بما يهمهم.","من واجب الحكام والعلماء تنبيه الأمة وتحذيرها من الأخطار.","معجزة النبي - صلى الله عليه وسلم - بإخباره عن حدوث فتن متتالية يجر بعضها بعضاً، وكل فتنة أفظع من سابقتها.","آخر هذه الأمة سينحرف عن منهج السلف الذي فيه العافية من الفتن، والعصمة من الضلال، والهداية من الغي.","المؤمن يحافظ على دينه ويبقى على أصالته؛ فلا يخوض في الفتن، ولا يجرفه تيار الفساد والإفساد.","الحث على التزام الإيمان، وسلوك سبل الهداية، والمعاملة الحسنة والخلق الطيب، وأنَّ ذلك يقيه شر الفتن والوقوع في جهنم.","يجب على الإنسان ألا يفعل مع الناس إلا ما يحب أن يفعلوه معه.","وجوب السمع والطاعة، والحذر من الخروج على ولاة الأمر.","وجوب قتال الفئة الباغية التي تخرج على الإمام وتشق عصا الطاعة وتفرق جماعة المسلمين، وذلك للحفاظ على وحدة صف الجماعة المسلمة وعدم تفريق كلمتها."],"wordsMeanings":[{"word":"منزلاً","meaning":" موضعاً نستريح فيه."},{"word":"خباءه","meaning":" البيت من وبر أو شعر أو صوف يكون على عمودين أو ثلاثة."},{"word":"الصلاة جامعة","meaning":" احضروا لتصلوا مجتمعين."},{"word":"فقال","meaning":" أي بعد ما صلينا."},{"word":"إنه لم يكن","meaning":" أي لم يوجد."},{"word":"حقًّا عليه","meaning":" أي واجبًا."},{"word":"أن ينذرهم","meaning":" من الإنذار أي : يحذرهم."},{"word":"أمتكم هذه","meaning":" يعني الأمة المحمدية."},{"word":"عافيتها","meaning":" العافية : أن تسْلم من الأسقام والبلايا."},{"word":"في أولها","meaning":" عصر الصحابة والتابعين وتابعي التابعين."},{"word":"آخرها","meaning":" ما بعد القرون الثلاثة السابقة."},{"word":"بلاء","meaning":" محنة وابتلاء."},{"word":"أمور تنكرونها","meaning":" أي مستحدثة ومبتدعة ومخالفة للشرع."},{"word":"وتجيء الفتنة","meaning":" أي العظيمة في الدين."},{"word":"مهلكتي","meaning":" فيها هلاكي."},{"word":"ثم تنكشف","meaning":" أي تذهب."},{"word":"هذه هذه","meaning":" أي هذه الفتنة هي أعظم الفتن."},{"word":"يُزَحْزح","meaning":" يُبعد ويُنحى."},{"word":"فلتأته منيته","meaning":" فليحرص أن يأتيه الموت وهو على الحال الموصوف."},{"word":"وليأت","meaning":" أي ليجيء."},{"word":"صَفْقَةَ يده","meaning":" عهده وميثاقه؛ لأن المتعاهدين يضع أحدهما يده في يد الآخر."},{"word":"ثمرة قلبه","meaning":" عقده وعزمه."},{"word":"فإن جاء آخر ينازعه","meaning":" أي خرج عن طاعته ونازعه في الملك."},{"word":"فاضربوا عنق","meaning":" فاقتلوا."}],"category":"da3wah","bookId":"muslim","tags":["بايع","إماما","فأعطاه","صفقة","يده،","وثمرة"],"source":"hadeethenc"},{"id":"he_5412","text":"عن عدي بن عميرة الكندي رضي الله عنه مرفوعاً: «من اسْتَعْمَلْنَاهُ منكم على عمل، فكَتَمَنَا مِخْيَطًا فما فوقه، كان غُلُولا يأتي به يوم القيامة». فقام إليه رجلٌ أسودُ من الأنصار، كأني أنظر إليه، فقال: يا رسول الله، اقبل عني عَمَلَكَ، قال: «وما لك؟» قال: سمعتك تقول كذا وكذا، قال: «وأنا أقوله الآن: من اسْتَعْمَلْنَاهُ على عمل فلْيَجِيْء بقليله وكثيره، فما أُوتِيَ منه أَخَذَ، وما نهي عنه انْتَهَى».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"من استعملناه منكم على عمل من جمع مال الزكاة أو الغنائم أو غير ذلك، فأخفى منه إبرة فما أصغر منها كان غلولا يأتي به يوم القيامة، فقام إليه رجل من الأنصار يستأذنه في أن يترك العمل الذي كلفه صلى الله عليه وسلم به، فقال له النبي صلى الله عليه وسلم: وما لك. قال: سمعتك تقول: كذا وكذا. فقال: وأنا أقوله الآن، من استعملناه منكم على عمل فليأت بقليله وكثيره، فما أعطي من أجره أخذه، وما نهي عنه ولم يكن من حقه امتنع عن أخذه.","reference":"دليل الفالحين لطرق رياض الصالحين، لابن علان، نشر دار الكتاب العربي.\nنزهة المتقين شرح رياض الصالحين، نشر: مؤسسة الرسالة، الطبعة: الرابعة عشر، 1407ه 1987م.\nكنوز رياض الصالحين، نشر: دار كنوز إشبيليا، الطبعة: الأولى، 1430ه 2009م.\nبهجة الناظرين شرح رياض الصالحين، للهلالي، نشر: دار ابن الجوزي.\nالمعجم الوسيط، نشر: دار إحياء التراث العربي، بيروت – لبنان، الطبعة: الثانية.\nسنن أبي داود، تحقيق: محمد محيي الد","benefits":["الوعيد الشديد لمن خان في عمله أو وظيفته في قليل أو كثير.","من اؤتمن على أموال الأمة عليه أن يصونها ويؤديها إلى مستحقيها ولا يختص نفسه بشيء منها، وإن حدثته نفسه بالخيانة وأَخَذَ شيئًا منها وجب عليه رده، وإلا افتضح يوم القيامة على رؤوس الأشهاد.","وجوب البعد عن الإمارة والوظيفة لمن لمس من نفسه عدم الثقة والقدرة على القيام بها بأمانة وإخلاص.","ولاة الأمور ينبغي أن يعرفوا الجهات التي يرد منها المال العام فيأخذوا ما هو حلال، وما لم يجز أخذه يرد إلى أهله.","جواز نعت الرجل بما فيه للمعرفة إذا لم يكن ذلك يغضبه، ولذلك قال في الحديث: فقام إليه رجل أسود من الأنصار."],"wordsMeanings":[{"word":"كتمنا مخيطا","meaning":" أي: أخفاه."},{"word":"مخيطا فما فوقه","meaning":" إبرة أو ما هو أصغر منها."},{"word":"غلولا","meaning":" الغلول: أخذ الشيء خُفية وخيانة."},{"word":"اقبل عني عملك","meaning":" ائذن لي أن أستقيل من العمل الذي وليتني عليه."},{"word":"كذا وكذا","meaning":" من ألفاظ الكنايات يكنى بها عن المجهول، وعما لا يراد التصريح به، وما سبق ذكره."},{"word":"فليجئ","meaning":" فليأت."},{"word":"أوتي","meaning":" أعطي أجره."},{"word":"ما نهي عنه انتهى","meaning":" ما بين له أن أخذه غير جائز انتهى من أخذه."}],"category":"da3wah","bookId":"muslim","tags":["مَنِ","اسْتَعْمَلْنَاهُ","مِنْكُمْ","على","عَمَلٍ،","فَكَتَمَنَا"],"source":"hadeethenc"},{"id":"he_5795","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّ الدِّينَ يُسْرٌ، وَلَنْ يُشَادَّ الدِّينَ أَحَدٌ إِلَّا غَلَبَهُ، فَسَدِّدُوا وَقَارِبُوا، وَأَبْشِرُوا، وَاسْتَعِينُوا بِالْغَدْوَةِ وَالرَّوْحَةِ وَشَيْءٍ مِنَ الدُّلْجَةِ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"بَيَّنَ النبيُّ صلى الله عليه وسلم أنَّ دينَ الإسلامِ مبنيٌّ على التيسير والسهولة في كل شؤونه، ويتأكد التيسير عند وجود سبب العجز والحاجة، ولأنَّ التعمُّقَ في الأعمال الدينية وترك الرفق عاقبتُه العجز والانقطاع عن العمل كله أو بعضه،\n \nثم حث صلى الله عليه وسلم على التوسط من غير مبالغة؛ فلا يُقصِّر العبد فيما أُمر به، ولا يتحمل ما لا يطيقه، فإن عجز عن العمل بالأكمل؛ فالعمل على ما يَقْرُبُ منه.\n\nوبشَّر صلى الله عليه وسلم بالثواب الجزيل على العمل الدائم وإن قلَّ لمَن عجز عن العمل بالأكمل؛ لأن العجز إذا لم يكن من صنيعه فلا يستلزم نقص أجره. \n\nوحيث أن الدنيا في الحقيقة دار سفر ونُقْلة إلى الآخرة أمر صلى الله عليه وسلم بالاستعانة على مداومة العبادة بإيقاعها في الأوقات الثلاثية المنشطة: \n\nالأول: الغَدوة: بسير أول النهار؛ ما بين صلاة الفجر وطلوع الشمس. \n\nالثاني: الرَّوحة: بالسير بعد الزوال. \n\nالثالث: الدُّلْجة: بسير الليل كله أو بعضه، ولأن عمل الليل أشق من عمل النهار أمر ببعضه بقوله: وشيءٍ من الدلجة.","reference":"صحيح البخاري (1/ 16) (39).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 219).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص115).","benefits":["يُسر وسماحة الشريعة الإسلامية وتوسُّطها بين الإفراط والتفريط.","على العبد أن يأتي بالأمر بقدر استطاعته، من دون تساهل أو تشديد.","على العبد أن يختار أوقات النشاط في العبادة، وهذه الأوقات الثلاثة بخصوصها هي أروح ما يكون فيها البدن للعبادة.","قال ابن حجر العسقلاني: كأنه صلى الله عليه وسلم خاطب مسافرًا إلى مقصدٍ، وهذه الأوقات الثلاثة أطيب أوقات المسافر، فنبهه على أوقات نشاطه؛ لأن المسافر إذا سافر الليل والنهار جميعًا عجز وانقطع، وإذا تحرَّى السير في هذه الأوقات المنشطة أمكنته المداومة من غير مشقة.","قال ابن حجر: الإشارة في هذا الحديث إلى الأخذ بالرخصة الشرعية، فإنّ الأخذ بالعزيمة في موضع الرخصة تَنَطُّعٌ، كمن يترك التيمم عند العجز عن استعمال الماء فيفضي به استعماله إلى حصول الضرر.","قال ابن المنير: في هذا الحديث عَلَمٌ من أعلام النبوة، فقد رأينا ورأى الناس قبلنا أن كل متنطع في الدين ينقطع، وليس المراد مَنْعِ طلب الأكمل في العبادة فإنه من الأمور المحمودة، بل منع الإفراط المؤدّي إلى الملال، أو المبالغة في التطوع المفضي إلى ترك الأفضل، أو إخراج الفرض عن وقته كمَن بات يصلي الليل كلَّه فنام عن صلاة الصبح في الجماعة، أو إلى أن طلعت الشمس فخرج وقت الفريضة."],"wordsMeanings":[],"category":"da3wah","bookId":"bukhari","tags":["الدين","يسر،","ولن","يشاد","الدين","أحد"],"source":"hadeethenc"},{"id":"he_5819","text":"عَنْ عَبْدِ اللَّهِ بنِ عُمرَ رَضِيَ اللَّهُ عَنْهُما أَنَّ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «كُلُّكُمْ رَاعٍ فَمَسْئُولٌ عَنْ رَعِيَّتِهِ، فَالأَمِيرُ الَّذِي عَلَى النَّاسِ رَاعٍ وَهُوَ مَسْئُولٌ عَنْهُمْ، وَالرَّجُلُ رَاعٍ عَلَى أَهْلِ بَيْتِهِ وَهُوَ مَسْئُولٌ عَنْهُمْ، وَالمَرْأَةُ رَاعِيَةٌ عَلَى بَيْتِ بَعْلِهَا وَوَلَدِهِ وَهِيَ مَسْئُولَةٌ عَنْهُمْ، وَالعَبْدُ رَاعٍ عَلَى مَالِ سَيِّدِهِ وَهُوَ مَسْئُولٌ عَنْهُ، أَلاَ فَكُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْئُولٌ عَنْ رَعِيَّتِهِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنَّ على كلِّ مسلم في المجتمع مسؤوليةً يرعاها ويَتَحَمّلُها، \nفالإمامُ والأمير راعٍ فيما استرعاه الله، فعليه حفظُ شرائعهم، وحمايتُهم ممّن جارَ عليهم، ومجاهدة عدوهم، وعدم تضييع حقوقهم،\nوالرجل في أهل بيته مُكَلَّف بالقيام عليهم بالنفقة، وحسن المعاشرة، وتعليمهم وتأديبهم،\nوالمرأة في بيت زوجها راعية بحسن تدبير بيته، وتربية أولاده، وهي مسؤولة عن ذلك،\nوالخادم المملوك والأجير مسؤول في مال سيده بالقيام بحفظ ما في يده منه، وخدمته، وهو مسؤول عن ذلك،\nفكل أحد راع فيما استُرْعِيَ عليه، وكل أحد مسؤول عن رعيته.","reference":"صحيح البخاري (3/ 150) (2554).\nصحيح مسلم (3/ 1459) (1829).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 369).\nإرشاد الساري لشرح صحيح البخاري، القسطلاني (4/ 326).","benefits":["المسؤولية في المجتمع المسلم عامَّة، وكلٌّ بِحَسَبِهِ وقدرتِه ومسؤوليتِه.","عِظَمُ مسؤولية المرأة، وذلك بالقيام بحقِّ بيت زوجها وواجباتِها نحو أولادِها."],"wordsMeanings":[],"category":"da3wah","tags":["كلكم","راع","فمسئول","رعيته،"],"source":"hadeethenc"},{"id":"he_6368","text":"عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم : «عليك السمع والطاعة في عُسْرِكَ ويُسرك، ومَنْشَطِكَ ومَكْرَهِكَ، وأثَرَة ٍعليك».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث أنه يجب على المسلم السمع والطاعة للحكام على كل حال، ما لم يُؤمر بمعصية أو يُكلف بما لا يطيق، ولو كان في ذلك مشقة عليه أحياناً، أو ضياع لبعض حقوقه، تقديما للمصلحة العامة على المصلحة الخاصة.","reference":"صحيح مسلم, ترقيم محمد فؤاد عبد الباقي, دار إحياء التراث العربي, بيروت.\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين, مؤسسة الرسالة, الطبعة الرابعة عشر, 1407ه.\nدليل الفالحين لطرق رياض الصالحين، لمحمد بن علان الصديقي, دار الكتاب العربي.\nتطريز رياض الصالحين، لفيصل بن عبد العزيز المبارك النجدي, تحقيق: عبد العزيز آل حمد, دار العاصمة , الطبعة: الأولى، 1423 هـ.\nبهجة الناظرين شرح رياض الصالحين، لسل","benefits":["من أهداف الدعوة تقديم المصلحة العامة على المصلحة الخاصة.","وجوب طاعة الحاكم على كل الأحوال ما لم يأمر بمعصية.","أنَّ وقوع الظلم من جهة الحاكم لا يجيز الخروج عليه."],"wordsMeanings":[{"word":"عليك","meaning":" أي الزم."},{"word":"السمع والطاعة","meaning":" القبول والانقياد لقول ولي الأمر وأمره."},{"word":"عسرك ويسرك","meaning":" فقرك وغناك."},{"word":"منشطك","meaning":" الأمر الذي تنشط له وتُؤْثر فعله."},{"word":"مكرهك","meaning":" ما يشق عليك فعله ولا تحبه."},{"word":"وأثرة عليك","meaning":" أي وإن اختص الأمراء واستأثروا بالدنيا، ولم يوصلوك إلى حقك مما عندهم."}],"category":"da3wah","bookId":"muslim","tags":["عليك","السمع","والطاعة","عسرك","ويسرك،","ومنشطك"],"source":"hadeethenc"},{"id":"he_6369","text":"عن ابن عمر رضي الله عنهما قال: كنا إذا بايعنا رسول الله صلى الله عليه وسلم على السمع والطاعة، يقول لنا: «فيما استطعتم».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر ابن عمر رضي الله عنهما أنهم إذا بايعوا النبي صلى الله عليه وسلم أمرهم بالسمع والطاعة، وقيد الطاعة بالاستطاعة، وأنه إذا كُلف المسلم بما لا يستطيع من ولي أمره فلا طاعة عليه، (لا يكلف الله نفسًا إلا وسعها).","reference":"صحيح البخاري، ط دار طوق النجاة المصورة عن الطبعة السلطانية، الطبعة الأولى 1422.\nصحيح مسلم, ترقيم محمد فؤاد عبد الباقي, دار إحياء التراث العربي, بيروت.\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين, مؤسسة الرسالة, الطبعة الرابعة عشر, 1407ه.\nدليل الفالحين لطرق رياض الصالحين، لمحمد بن علان الصديقي, دار الكتاب العربي.\nكنوز رياض الصالحين بإشراف حمد العمار, دار كنوز إشبيليا, الطبعة الأولى, 1430ه.\n","benefits":["أنَّ وجوب السمع والطاعة على قدر الاستطاعة.","حث ولي الأمر على الإشفاق على الرعية، اقتداء بشفقته ورحمته -صلى الله عليه وسلم-.","جواز التلقين عند المبايعة."],"wordsMeanings":[{"word":"بايعنا","meaning":" من البيعة : وهي المعاقدة والمعاهدة على طاعة ونصرة الحاكم الأول."},{"word":"السمع والطاعة","meaning":" القبول والانقياد لقول ولي الأمر وأمره."},{"word":"يقول لنا","meaning":" أي مُلَقِّنا."},{"word":"فيما استطعتم","meaning":" أي خصصوا المبايعة بقولكم: فيما استطعنا."}],"category":"da3wah","tags":["كنا","إذا","بايعنا","رسول","الله","صلى"],"source":"hadeethenc"},{"id":"he_6370","text":"عن ابن عمر رضي الله عنهما مرفوعاً: «على المرء المسلم السمع والطاعة فيما أحب وكَرِهَ، إلا أن يُؤمر بمعصية، فإذا أُمِرَ بمعصية فلا سمع ولا طاعة».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث بيان وجوب السمع والطاعة للحاكم فيما يأمر به، سواء كان أمره مما نحب أو نكره، إلا أن نُؤمر بمعصية فإنه لا سمع ولا طاعة في هذه المعصية فقط.","reference":"صحيح البخاري، عناية محمد زهير الناصر، دار طوق النجاة، الطبعة الأولى، 1422هـ.\nصحيح مسلم؛ للإمام مسلم بن الحجاج، حققه ورقمه محمد فؤاد عبد الباقي، دار عالم الكتب-الرياض، الطبعة الأولى، 1417هـ.\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين, مؤسسة الرسالة, الطبعة الرابعة عشر, 1407ه.\nدليل الفالحين لطرق رياض الصالحين، لمحمد بن علان الصديقي, دار الكتاب العربي.\nكنوز رياض الصالحين، بإشراف حمد العمار, ","benefits":["وجوب الالتزام لإمام المسلمين بالسمع والطاعة.","ينبغي التنازل عن الرغبات والمصالح الشخصية لوحدة الأمة الاسلامية وتماسكها.","إذا أُمر العبد بمعصية فلا سمع ولا طاعة؛ لأنه لا طاعة لمخلوق في معصية الخالق.","دلَّ هذا الحديث على أهمية المحافظة على حرمات الله -تعالى-."],"wordsMeanings":[{"word":"على المرء المسلم","meaning":" أي يجب عليه."},{"word":"السمع والطاعة","meaning":" القبول والانقياد لولي الأمر."},{"word":"فيما أحب","meaning":" أي موافقا لمراد المأمور."},{"word":"وكره","meaning":" أي شقَّ عليه وكرهته نفسه."},{"word":"فلا سمع ولا طاعة","meaning":" أي فلا تسمعوا ولا تطيعوا له في هذه المعصية."}],"category":"da3wah","tags":["على","المرء","المسلم","السمع","والطاعة","فيما"],"source":"hadeethenc"},{"id":"he_6371","text":"عن أبي بكرة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: «من أهان السلطان أهانه الله».","attribution":"رواه الترمذي","grade":"حسن","gradeKey":"hasan","explanation":"في هذ الحديث تحريم الاستخفاف بأوامر السلطان؛ لما يترتب عليه من الوعيد الشديد من إذلال الله له في الدنيا والآخرة، والجزاء من جنس العمل.","reference":"سنن الترمذي، محمد بن عيسى الترمذي، تحقيق: أحمد محمد شاكر وآخرين، دار إحياء التراث العربي، بيروت.\nسلسلة الأحاديث الصحيحة وشيء من فقهها وفوائدها، محمد ناصر الدين الألباني، مكتبة المعارف للنشر والتوزيع، الرياض، 1415هـ.\nنزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين، مؤسسة الرسالة، بيروت، الطبعة: الرابعة عشرة-  1407هـ، 1987م.\nتطريز رياض الصالحين، فيصل بن عبد العزيز المبارك، تحقيق: عبد العزيز بن عب","benefits":["الحث على توقير واحترام ذوي الهيئات من الحكام والعلماء؛ لتصبح لهم هيبة في النفوس، فيُسمع قولهم ويطاع أمرهم.","التنفير من احتقارهم، والهزء بهم، وعدم طاعتهم.","من أهداف الدعوة حفظ الأمن والاستقرار في المجتمع المسلم."],"wordsMeanings":[{"word":"أهان","meaning":" استخفَّ."},{"word":"السلطان","meaning":" كلَّ ذي سلطة وولاية لشيء من أمور المسلمين."},{"word":"أهانه الله","meaning":" أذلَّه الله في الدنيا، وعذبه في الآخرة."}],"category":"da3wah","bookId":"tirmidhi","tags":["أهان","السلطان","أهانه","الله"],"source":"hadeethenc"},{"id":"he_6382","text":"عن أنس بن مالك رضي الله عنه قال رسول الله صلى الله عليه وسلم : «اسمعوا وأطيعوا، وإن استعمل عليكم عبد حبشي، كأن رأسه زبيبة».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"الزموا السمع والطاعة لولاة الأمور، حتى لو استعمل عليكم عبد حبشي أصلًا وفرعًا وخلقةً، كأن رأسه زبيبة، وهذا من باب المبالغة في كون هذا العامل عبدًا حبشيًا أصلاً وفرعًًا، قوله: ((وإن استعمل)) يشمل الأمير الذي هو أمير السلطان، وكذلك السلطان.\nفلو فرض أن سلطانا غلب الناس واستولى وسيطر وليس من العرب؛ بل كان عبدًا حبشيًا فإن علينا أن نسمع ونطيع.\nفهذا الحديث يدل على وجوب طاعة ولاة الأمور إلا في معصية الله، لما في طاعتهم من الخير والأمن والاستقرار وعدم الفوضى وعدم اتباع الهوى. أما إذا عصي ولاة الأمور في أمر تلزم طاعتهم فيه؛ فإنه تحصل الفوضى، ويحصل إعجاب كل ذي رأي برأيه، ويزول الأمن، وتفسد الأمور، وتكثر الفتن.","reference":"صحيح البخاري -الجامع الصحيح-، للإمام أبي عبد الله محمد بن إسماعيل البخاري، عناية محمد زهير الناصر، دار طوق النجاة، الطبعة الأولى، 1422هـ.\nتطريز رياض الصالحين لفيصل بن عبد العزيز المبارك النجدي, تحقيق: عبد العزيز آل حمد, دار العاصمة , الطبعة: الأولى، 1423 هـ.\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي, دار ابن الجوزي.\nشرح رياض الصالحين لابن عثيمين , دار مدار الوطن للنشر، الرياض, الطبعة : 1426 ه","benefits":["وجوب طاعة ولي الأمر فيما ليس بمعصية دون النظر إلى لونه أو جنسه.","لا يجوز تولية العبد الإمامة، وإنما ذُكر في الحديث من باب المبالغة في الطاعة، أو إذا تغلب قهرًا.","من أهداف الدعوة جمع كلمة المسلمين، والعمل على ما يحقق وحدة المجتمع الإسلامي.","أنه إن لم نسمع ونطع حصلت الفوضى وزال النظام وزال الأمن وحل الخوف.","استدل البخاري بهذا الحديث على جواز إمامة المفتون والمبتدع."],"wordsMeanings":[{"word":"اسمعوا","meaning":" أي ما قال أمراؤكم."},{"word":"وأطيعوا","meaning":" أي أطيعوهم في غير معصية."},{"word":"استعمل","meaning":" أُمِّر عليكم ووظف."},{"word":"عبد حبشي","meaning":" مملوك أسود."},{"word":"رأسه زبيبة","meaning":" أسود صغير جعد الشعر."}],"category":"da3wah","bookId":"bukhari","tags":["اسمعوا","وأطيعوا،","وإن","استعمل","عليكم","عبد"],"source":"hadeethenc"},{"id":"he_6383","text":"عن أبي هريرة رضي الله عنه مرفوعاً: «من أطاعني فقد أطاع الله، ومن عصاني فقد عصى الله، ومن يطع الأمير فقد أطاعني، ومن يعص الأمير فقد عصاني».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"بيَّن النبي صلى الله عليه وسلم أن طاعته من طاعة الله، والنبي -عليه الصلاة والسلام- لا يأمر إلا بالشرع الذي شرعه الله تعالى له ولأمته، فإذا أمر بشيء؛ فهو شرع الله سبحانه وتعالى ، فمن أطاعه فقد أطاع الله، ومن عصاه فقد عصى الله.\nوالأمير إذا أطاعه الإنسان فقد أطاع الرسول صلى الله عليه وسلم ، وإذا عصاه فقد عصى الرسول صلى الله عليه وسلم ؛ لأن النبي صلى الله عليه وسلم هو الذي أمر بذلك في أكثر من حديث؛ إلا أن يأمر بمعصية.","reference":"صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422ه.\nصحيح مسلم, ترقيم محمد فؤاد عبد الباقي, دار إحياء التراث العربي, بيروت.\nنزهة المتقين شرح رياض الصالحين لمجموعة من الباحثين, مؤسسة الرسالة, الطبعة الرابعة عشر, 1407ه.\nتطريز رياض الصالحين لفيصل بن عبد العزيز المبارك النجدي, تحقيق: عبد العزيز آل حمد, دار العاصمة , الطبعة: الأولى، 1423","benefits":["التأكيد على طاعة الأمراء في غير معصية؛ لأنها من طاعة الله ورسوله.","السمع والطاعة تجب للإمام الأعظم، ومن قام الإمام بتوليته ولاية خاصة.","طاعة أولي الأمر في المعروف قربة إلى الله يثاب عليها المرء.","أنَّ طاعة الأمراء تجلب الخير والأمن والاستقرار وعدم الفوضى وعدم اتباع الهوى.","أنَّ معصية الأمراء تجلب الفوضى ويحصل إعجاب كل ذي رأي برأيه، ويزول الأمن وتفسد الأمور وتكثر الفتن.","من يطع الرسول فقد أطاع الله؛ لأن الرسول -صلى الله عليه وسلم- يأمر بطاعة الله سبحانه؛ وإن الله أمر بطاعة الرسول -صلى الله عليه وسلم-."],"wordsMeanings":[{"word":"من أطاعني","meaning":" أي : عَمِل بما أَمرته به وترك ما نهيته عنه."},{"word":"ومن عصاني","meaning":" أي : خالف بفعل ما نهيت عنه أو ترك ما أمرت به."},{"word":"الأمير","meaning":" كلُّ من له ولاية سواء الخليفة أو غيره."}],"category":"da3wah","tags":["أطاعني","فقد","أطاع","الله،","ومن","عصاني"],"source":"hadeethenc"},{"id":"he_6384","text":"عن عوف بن مالك رضي الله عنه مرفوعاً: «خِيَارُ أئمتكم الذين تحبونهم ويحبونكم، وتُصَلُّون عليهم ويصلون عليكم. وشِرَارُ أئمتكم الذين تبُغضونهم ويبغضونكم، وتلعنونهم ويلعنونكم!»، قال: قلنا: يا رسول الله، أفلا نُنَابِذُهُم؟ قال: «لا، ما أقاموا فيكم الصلاة. لا، ما أقاموا فيكم الصلاة».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"دلَّ هذا الحديث على أنَّ مِن حكام المسلمين مَن هم أهل صلاح ومنهم مَن هم أهل فسق وقلة ديانة، ومع ذلك لا يجوز الخروج عليهم ما داموا محافظين على إقامة شعائر الإسلام وآكدها الصلاة.","reference":"صحيح مسلم, ترقيم محمد فؤاد عبد الباقي, دار إحياء التراث العربي, بيروت.\nشرح رياض الصالحين لابن عثيمين , دار مدار الوطن للنشر، الرياض, الطبعة : 1426 هـ.\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي, دار ابن الجوزي.\nتطريز رياض الصالحين لفيصل بن عبد العزيز المبارك النجدي, تحقيق: عبد العزيز آل حمد, دار العاصمة , الطبعة: الأولى، 1423 هـ.\nكنوز رياض الصالحين بإشراف حمد العمار, دار كنوز إشبيليا, الطبعة ا","benefits":["حث ولاة الأمور على العدل في الرعية لتحقيق الألفة بينهم.","حث الناس على طاعة ولاة الأمر في غير معصية.","وجوب المناصحة بين الحكام والرعية؛ لأنها تجلب المودة والألفة، ويسود الأمن والرخاء.","استحباب الدعاء للحاكم المسلم بالتوفيق والسداد.","تحريم الخروج على ولاة الأمور وإن جاروا، وذلك بإجماع الفقهاء.","فيه دليل على تعظيم الصلاة."],"wordsMeanings":[{"word":"خيار","meaning":" أفضل."},{"word":"أئمتكم","meaning":" ولاة أمركم."},{"word":"الذين تحبونهم","meaning":" لحسن سيرتهم فيكم ورفقهم بكم."},{"word":"ويحبونكم","meaning":" لامتثالكم."},{"word":"تصلون عليهم","meaning":" تدعون لهم."},{"word":"تلعنونهم","meaning":" أي لسوء أعمالهم."},{"word":"ويلعنونكم","meaning":" مجازاة لما فعلتم معهم."},{"word":"ننابذهم","meaning":" نخالفهم بترك الطاعة لهم."}],"category":"da3wah","bookId":"muslim","tags":["خيار","أئمتكم","الذين","تحبونهم","ويحبونكم،","وتصلون"],"source":"hadeethenc"},{"id":"he_8893","text":"عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم مر عليه حمار قد وُسِمَ في وجهه، فقال:«لعن الله الذي وسمه». \nوفي رواية لمسلم أيضا: نهى رسول الله صلى الله عليه وسلم عن الضرب في الوجه، وعن الوسم في الوجه»","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"في هذا الحديث النهي الأكيد والوعيد الشديد فيمن وسَم حيوانًا في وجهه وكذا الضرب في الوجه. قد عَدَّه العلماء -رحمهم الله- من كبائر الذنوب\nوعلل العلماء للنهي؛ بأن الوجه لطيف يجمع المحاسن، وأعضاؤه نفيسة لطيفة وأكثر الإدراك بها فقد يبطلها ضرب الوجه وقد ينقصها وقد يشوه الوجه والشين فيه فاحش لأنه بارز ظاهر لا يمكن ستره ومتى ضربه لا يسلم من شين غالبا.","reference":"نزهة المتقين، تأليف: جمعٌ من المشايخ، الناشر: مؤسسة الرسالة، الطبعة الأولى: 1397 هـ الطبعة الرابعة عشر 1407 هـ.\nبهجة الناظرين، تأليف: سليم بن عيد الهلالي، الناشر: دار ابن الجوزي ، سنة النشر:  1418 هـ- 1997م.\nصحيح مسلم، تحقيق: محمد فؤاد عبد الباقي الناشر: دار إحياء التراث العربي – بيروت.\nرياض الصالحين، تأليف: محيي الدين يحيى بن شرف النووي ، تحقيق: د. ماهر بن ياسين الفحل ، الطبعة: الأولى، 1428 هـ.\nا","benefits":["النهي عن الوَسْم في الوجه.","فيه النهي عن ضرب الوجه، ولو للتأديب.","جواز لعن من وسَم في الوجه.","الوسم في الوجه من كبائر الذنوب؛ لأن فاعله استحق اللعن.","الأمر بالرفق بالحيوان.","فيه جواز وسْم الحيوان في غير الوجه."],"wordsMeanings":[{"word":"وسم","meaning":" الوسم العلامة، وتكون بالكي غالبًا."}],"category":"da3wah","bookId":"muslim","tags":["نَهى","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_58257","text":"عن أبي هريرة، قال: قال رسول الله صلى الله عليه وسلم : «إذا ضَرَبَ أَحَدُكُمْ أخاه فَلْيَجْتَنِب الوجْهَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"معنى الحديث أنه إذا ضرب أحدكم شخصاً تأديباً أو تعزيراً له أو في حد من حدود الله تعالى أو لخصومة أو غير ذلك فليحذر أن يضربه على وجهه، وليبتعد عن ذلك كل البعد، ولو في إقامة حد من حدود الله؛ لما لوجه بني آدم من الكرامة، فهو أشرف الأعضاء، وهو الَّذي تحصل به المواجهة، وضربه عليه إمَّا أن يتلف منه عضوًا، وإمَّا أنْ يُحْدِثَ فيه شَيْئًا؛ فالواجب اجتنابه، ويحرم الضرب فيه، سواء أكان الضرب بحقٍّ، أو عن طريق الاعتداء.","reference":"- صحيح البخاري، تحقيق: محمد زهير بن ناصر الناصر، ط1، دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم: محمد فؤاد عبد الباقي)، (1422ه).\n- صحيح مسلم, ترقيم محمد فؤاد عبد الباقي, دار إحياء التراث العربي, بيروت.\n- تسهيل الالمام، للشيخ صالح الفوزان. طبعة الرسالة. الطبعة الأولى 1427 – 2006 م\n- فتح ذي الجلال والاكرام بشرح بلوغ المرام، للشيخ ابن عثيمين، المكتبة الإسلامية - الطبعة الأولى 1427 - 2006م\n- توضِ","benefits":["وجوب اتقاء الوجه عند الضرب في أي حال من الأحوال.","أنَّ إقامة الحدود لا يقصد بها إهانة المسلم، ولا يقصد إتلافه وقتله، وإنما يراد بها تطهيره من الذنب الذي وقع منه، كما يقصد بها ردعه عن أن يعود إليه، ولينزجر من تسوَّل له نفسه أن يعمل عمله.","مشروعية الضرب وجوازه إذا وجد سببه، وهو عقوبة مشروعة.","اجتناب الضرب في المواضع التي فيها خطورة."],"wordsMeanings":[{"word":"إذا ضرب أحدكم","meaning":" في حدٍ أو تعزير أو غيرهما."},{"word":"أخاه","meaning":" خادمه ومملوكه وكل من له ولاية عليه لتأديبه أو غيره."},{"word":"فليجتنب الوجه","meaning":" فليحذر أن يضربه على وجهه، وليبتعد عن ذلك كل البعد، ولو في إقامة حد من حدود الله -تعالى-."}],"category":"da3wah","tags":["إذا","ضرب","أحدكم","أخاه","فليجتنب","الوجه"],"source":"hadeethenc"},{"id":"he_64681","text":"عن أبي هريرة رضي الله عنه عن النبي صلى الله عليه وسلم قال: «إنكم سَتَحْرِصُونَ على الإِمَارَة، وستكون نَدَامَةً يوم القيامة، فَنِعْمَ المُرْضِعَةُ وَبِئْسَتِ الفَاطِمَةُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"هذا الحديث ينبه على عظم شأن الإمارة -وما هو في حكمها كالقضاء- وكثرة تبعاتها ومسؤولياتها في الدار الآخرة، والتحذير من طلبها والحرص عليها، وهذا مقيد بمن دخل فيها بسعي منه وحرص عليها وكان غير أهلٍ لها، بخلاف من وُكِلت إليه ولم يسعَ لها وكان أهلا لها وعدل فيها فإنه سيُعان عليها كما جاء في أحاديث أخرى، وقد شبهت الإمارة في الحديث بأنها نعم المرضعة بما تدر من منافع المال والجاه ونفاذ الحكم، وبئس الفاطمة بتبعاتها يوم القيامة وحسراتها.","reference":"- صحيح البخاري، تأليف: محمد بن إسماعيل البخاري، تحقيق: محمد زهير الناصر، الناشر: دار طوق النجاة الطبعة: الأولى، 1422هـ\n- توضيح الأحكام مِن بلوغ المرام، تأليف: عبد الله بن عبد الرحمن بن صالح البسام، الناشر: مكتبة الأسدي، مكة المكرّمة الطبعة: الخامِسَة، 1423 هـ - 2003 م\n- تسهيل الإلمام بفقه الأحاديث من بلوغ المرام، تأليف: صالح بن فوزان بن عبد الله الفوزان، الطبعة: الأولى، 1427 ه _ 2006 م\n- فتح ذي ال","benefits":["طالب ولاية القضاء أو غيرها من الولايات له إحدى حالتين: إحداهما: أنْ يقصد من الحصول عليها الجاه والرئاسة والمال، فهذا هو المذموم، وهو الَّذي وردت الأحاديث الصحيحة بذمِّه ومنعه، ومنع طالب الولاية فيها.الثانية: أنْ يطلب القضاء أو الولاية؛ لأنَّها متعينة عليه؛ لأَنَّه لا يوجد من هو أهل لها وللقيام بها، وإذا تركها تولاَّها من لا يقوم بها، ولا يحسنها، فيطلبها بهذه النية، وهو القصد الحسن؛ فهذا مثاب مأجور معان عليها.","أن ما ذكره النبي -صلى الله عليه وسلم- من الحرص بعده على الإمارة والتقاتل عليها قد حصل كما أخبر, وذلك من أعلام نبوته -صلى الله عليه وسلم-.","الحرص على الولاية هو السبب في اقتتال الناس عليها، حتى سفكت الدماء، واستبيحت الأموال والفروج، وعظم الفساد في الأرض بذلك، ووجه الندم أنه قد يقتل أو يعزل أو يموت، فيندم على الدخول فيها؛ لأنه يطالب بالتبعات التي ارتكبها، وقد فاته ما حرص عليه بمفارقته."],"wordsMeanings":[{"word":"ستحرصون","meaning":" ستشتد رغبتكم في الإمارة."},{"word":"الإمارة","meaning":" بكسر الهمزة، هي منصب الأمير, ويدخل فيها الإمارة العظمى, وهي الخلافة وولاية أمر الأمة, والصغرى وهي الولاية على بعض البلاد, كما يدخل في ذلك ولاية القضاء."},{"word":"ندامة","meaning":" أسفًا وحزنًا وأسىً."},{"word":"فنعم - بئس","meaning":" : نعم وبئس فعلان ماضيان، وهما جامدان لا يتصرفان، جاءا لإفادة المدح أو الذم."},{"word":"المرضعة","meaning":" وصف المرأة إذا كان لها ولدٌ ترضعه، ورضع الثدي إذا مصَّه، والمراد هنا تشبيه منافع الإمارة العاجلة الزَّائلة بالرضاع في مدته القصيرة."},{"word":"الفاطمة","meaning":" يُقال: فطمت المرأة الرضيع تفطمه فطماً، أي: فصلت المرضعة الرضيع عن الرضاع، شبَّه انقطاع منافع الإمارة بالفطام."}],"category":"da3wah","bookId":"bukhari","tags":["إنكم","ستحرصون","على","الإمارة،","وستكون","ندامة"],"source":"hadeethenc"},{"id":"he_65025","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «وَالَّذِي نَفْسِي بِيَدِهِ، لَيُوشِكَنَّ أَنْ يَنْزِلَ فِيكُمْ ابْنُ مَرْيَمَ حَكَمًا مُقْسِطًا، فَيَكْسِرَ الصَّلِيبَ، وَيَقْتُلَ الخِنْزِيرَ، وَيَضَعَ الجِزْيَةَ، وَيَفِيضَ المَالُ حَتَّى لاَ يَقْبَلَهُ أَحَدٌ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُقْسِمُ النبيُّ صلى الله عليه وسلم على قُرْبِ نزول عيسى بن مريم عليه السلام لِيَحْكُمَ بين الناس بالعدل بالشريعة المحمدية، \nوأنه سيكسر الصليب الذي تُعظِّمُه النصارى، \nوأنَّ عيسى عليه السلام يَقْتُل الخنزير، \nوأنه عليه السلام يضع الجزية ويحمل الناس كلهم على الدخول في الإسلام. \nوأنَّ المالَ سيفيض فلا يقبله أحد؛ وذلك لكثرته، واستغناء كلِّ أَحدٍ بما في يديه، ونزول البركات وتوالي الخيرات.","reference":"صحيح البخاري (3/ 82) (2222)، صحيح مسلم (1/ 135) (155)، شرح النووي على مسلم (1/471)، التوضيح (14/555)، عمدة القاري شرح صحيح البخاري (12/ 35).","benefits":["إثبات نزول عيسى عليه السلام آخر الزمان، وأنه من علامات الساعة.","شريعة النبي صلى الله عليه وسلم لا ينسخها غيرها.","نزول البركات في المال آخر الزمان، مع زُهد النّاس فيه.","البشارة ببقاء الدين الإسلامي حيث يحكم به عيسى عليه السلام في آخر الزمان."],"wordsMeanings":[],"category":"da3wah","tags":["والذي","نفسي","بيده،","ليوشكن","ينزل","فيكم"],"source":"hadeethenc"},{"id":"he_65044","text":"عن أَنَسَ بْنَ مَالِكٍ رضي الله عنه قال: بينما نحن جلوس مع النبي صلى الله عليه وسلم في المسجد دخل رجل على جمل، فأناخه في المسجد ثم عقله، ثم قال لهم: أيكم محمد؟ والنبي صلى الله عليه وسلم متكئ بين ظهرانيهم، فقلنا: هذا الرجل الأبيض المتكئ. فقال له الرجل: يا ابن عبد المطلب فقال له النبي صلى الله عليه وسلم: «قد أجبتك». فقال الرجل للنبي صلى الله عليه وسلم: إني سائلك فمشدد عليك في المسألة، فلا تجد علي في نفسك؟ فقال: «سل عما بدا لك» فقال: أسألك بربك ورب من قبلك، آلله أرسلك إلى الناس كلهم؟ فقال: «اللهم نعم». قال: أنشدك بالله، آلله أمرك أن نصلي الصلوات الخمس في اليوم والليلة؟ قال: «اللهم نعم». قال: أنشدك بالله، آلله أمرك أن نصوم هذا الشهر من السنة؟ قال: «اللهم نعم». قال: أنشدك بالله، آلله أمرك أن تأخذ هذه الصدقة من أغنيائنا فتقسمها على فقرائنا؟ فقال النبي صلى الله عليه وسلم: «اللهم نعم». فقال الرجل: آمنت بما جئت به، وأنا رسول من ورائي من قومي، وأنا ضمام بن ثعلبة أخو بني سعد بن بكر.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر أنس بن مالك رضي الله عنه: بينما الصحابة جلوس مع النبي صلى الله عليه وسلم في المسجد إذ دخل رجل على جمل، فأبركَه ثم ربطَه، \nثمّ سألهم: أيُّكم محمد؟ \nوالنبي صلى الله عليه وسلم متكئ بين القوم، فقلنا: هذا الرَّجل الأبيض المتَّكئ، \nفقال له الرَّجل: يا ابن عبد المطلب، \nفقال له النبي صلى الله عليه وسلم: سمعتك، فسل أُجبْك. \nفقال الرجل للنبي صلى الله عليه وسلم: إني سائلك فَمُشَدِّد عليك في المسألة، فلا تجد عليَّ في نفسك.\n أي: فلا تغضب عليَّ ولا يصبْك ضيق، \nفقال: سل عَمّا تريد، \nفقال: أسألك بِربِّك وربِّ مَن قبلك، آلله أرسلَك إلى الناس؟ \nفقال: اللَّهم نعم، تأكيدًا لِصِدقه، \nقال الرَّجل: أنشدك بالله، أي: أسألك بالله، آلله أمرَك أن نُصلِّي الصَّلوات الخمس في اليوم واللَّيلة؟ وهي الصَّلوات المفروضة، \nقال: اللَّهم نعم، \nقال: أنشدك بالله، آلله أمرَك أن نصوم هذا الشَّهر مِن السنة؟ أي: شهر رمضان، \nقال: اللَّهم نعم، \nقال: أنشدك بالله، آلله أمرك أن تأخذ هذه الصَّدقة مِن أغنيائنا فتقسمها على فقرائنا؟ وهي الزكاة، \nفقال النبي صلى الله عليه وسلم: اللهم نعم، \nفأسلم ضمام، وأخبر النبي صلى الله عليه وسلم أنه سيدعو قومه للإسلام. ثم عرف نفسه وأنه ضمام بن ثعلبة من بني سعد بن بكر.","reference":"صحيح البخاري (1/ 23) (63)، صحيح مسلم (1/ 41) (12)، شرح ابن بطال (1/145)، عمدة القاري شرح صحيح البخاري (2/ 22).","benefits":["تواضع النبي عليه الصَّلاة والسّلام؛ إذ لم يستطع الرَّجل أن يُفرِّق بينه وبين أصحابه.","حسن خلق النبي عليه السلام، وتلطفه في الرد على السائل، وأن حسن الرد من أسباب قبول الدعوة.","جواز تعريف الرجل بصفة من البياض والحمرة، والطول والقصر، ونحو ذلك مما لا يقصد به العيب، إن لم يَكره ذلك.","جواز دخول الكافر المسجد للحاجة.","لم يذكر الحج في الحديث لأنه قد يكون لم يفرض وقت مجيئه.","حرص الصحابة على دعوة الناس؛ فبمجرد إسلامه حرص على دعوة قومه."],"wordsMeanings":[],"category":"da3wah","tags":["وأنا","ضمام","ثعلبة","أخو","بني","سعد"],"source":"hadeethenc"},{"id":"he_65702","text":"عن أنس قال: قال رسول الله صلى الله عليه وسلم: (مَثَلُ أمتي مَثَلُ المطر لا يُدرى أولُه خيرٌ أم آخرُه).","attribution":"رواه الترمذي","grade":"حسن لطرقه","gradeKey":"hasan","explanation":"شبه النبي صلى الله عليه وسلم هذه الأمة بالمطر، وبيَّن وجه التشبيه، وهو أنه لا يُعلم هل أول المطر فيه النفع، وبه يحصل الزرع وامتلاء العيون والآبار ونحوها، أم آخره؟ فكذلك أمته صلى الله عليه وسلم لا يُعلم هل يكون النفع في أولها أم آخرها، ومعناه أن هذا يقع بعد نزول عيسى صلى الله عليه وسلم حين تظهر البركةُ ويكْثُر الخير، ويظهر الدين بحيث يتشكك الرائي: هل هؤلاء أفضل من أوائل الأمة أم الأوائل أفضل؟ وهذا فيما يظهر للرائي، وإِلا فأول الأمة أفضل في الحقيقة؛ لأدلة أخرى، كحديث: (خير الناس قرني) متفق عليه.\nوالسبب في كون القرن الأول خير القرون أنهم كانوا غرباء في إيمانهم؛ لكثرة الكفار حينئذٍ، مع صبرهم على أذاهم وتمسكهم بدينهم، فكذلك أواخرهم إذا أقاموا الدين وتمسكوا به وصبروا على الطاعة حين ظهور المعاصي والفتن كانوا أيضًا عند ذلك غرباء، وزكت أعمالهم في ذلك الزمان، كما زكت أعمال أولئك.","reference":"سنن الترمذي (4/ 449) (2869)، فتاوى النووي (ص250)، مجموع الفتاوى (2/ 227)، فتح الباري لابن حجر (7/ 6-7)،التيسير بشرح الجامع الصغير (2/ 374).","benefits":["بيان تفاوت خيرية أمة محمد صلى الله عليه وسلم.","هدي النبي صلى الله عليه وسلم في ضرب الأمثال."],"wordsMeanings":[{"word":"مثل المطر","meaning":" في نفعه."},{"word":"لا يدرى أوله خير","meaning":" لا يدرى هل أوله أنفع أو آخره."}],"category":"da3wah","bookId":"tirmidhi","tags":["مَثَلُ","أمتي","مَثَلُ","المطر","يُدرى","أولُه"],"source":"hadeethenc"},{"id":"he_66184","text":"عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ: بَعَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَاسْتَعْمَلَ رَجُلًا مِنَ الأَنْصَارِ، وَأَمَرَهُمْ أَنْ يُطِيعُوهُ، فَغَضِبَ، فَقَالَ: أَلَيْسَ أَمَرَكُمُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُطِيعُونِي؟ قَالُوا: بَلَى، قَالَ: فَاجْمَعُوا لِي حَطَبًا، فَجَمَعُوا، فَقَالَ: أَوْقِدُوا نَارًا، فَأَوْقَدُوهَا، فَقَالَ: ادْخُلُوهَا، فَهَمُّوا، وَجَعَلَ بَعْضُهُمْ يُمْسِكُ بَعْضًا، وَيَقُولُونَ: فَرَرْنَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنَ النَّارِ، فَمَا زَالُوا حَتَّى خَمَدَتِ النَّارُ، فَسَكَنَ غَضَبُهُ، فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ، فَقَالَ: «لَوْ دَخَلُوهَا مَا خَرَجُوا مِنْهَا إِلَى يَوْمِ القِيَامَةِ؛ الطَّاعَةُ فِي المَعْرُوفِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أرسل النبي صلى الله عليه وسلم جيشًا، وجعل رجلًا من الأنصار أميرًا عليهم، وأمرهم بطاعته، فغضب عليهم الأمير وقال لهم: ألم يأمركم النبي صلى الله عليه وسلم أن تطيعوني؟\n\nقالوا: بلى، قال: فقد أمرتكم أن تجمعوا حطبًا وتوقدوا نارًا ثم تدخلوا فيها، فجمعوا الحطب وأوقدوا النار، فلما أرادوا الدخول فيها، جعل ينظر بعضهم إلى بعض.\n\n وقالوا: إننا ما اتبعنا النبي صلى الله عليه وسلم إلا فرارًا من النار فهل ندخلها؟ وبينما هم كذلك انطفأ لهيب النار، وذهب عن الأمير غضبه.\n\n فأخبر النبي صلى الله عليه وسلم بذلك فقال: لو أطاعوه ودخلوا النار التي أوقدوها لعذبوا فيها ولم يخرجوا منها مدة الدنيا، ولا طاعة لمخلوق في معصية الخالق؛ إنما تجب الطاعة في المعروف لا في المعصية.","reference":"صحيح البخاري (5/ 161) (4340).\nصحيح مسلم (3/ 1469) (1840).\nإرشاد الساري لشرح صحيح البخاري (10/ 220).","benefits":["بيان أن الطاعة إنما هي في المعروف ولا تكون في المعصية، ولو كان الآمر ممن تجب طاعته.","العاصي الموحِّد متوَعَّدٌ بالنار، وقد يغفر الله له.","مشروعية التأمير في الغزو، وكذلك في السفر."],"wordsMeanings":[],"category":"da3wah","tags":["دخلوها","خرجوا","منها","إلى","يوم","القيامة؛"],"source":"hadeethenc"},{"id":"he_66191","text":"عَنْ عَوْفِ بْنِ مَالِكٍ عَنْ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «خِيَارُ أَئِمَّتِكُمُ الَّذِينَ تُحِبُّونَهُمْ وَيُحِبُّونَكُمْ، وَيُصَلُّونَ عَلَيْكُمْ وَتُصَلُّونَ عَلَيْهِمْ، وَشِرَارُ أَئِمَّتِكُمُ الَّذِينَ تُبْغِضُونَهُمْ وَيُبْغِضُونَكُمْ، وَتَلْعَنُونَهُمْ وَيَلْعَنُونَكُمْ»، قِيلَ: يَا رَسُولَ اللهِ، أَفَلَا نُنَابِذُهُمْ بِالسَّيْفِ؟ فَقَالَ: «لَا، مَا أَقَامُوا فِيكُمُ الصَّلَاةَ، وَإِذَا رَأَيْتُمْ مِنْ وُلَاتِكُمْ شَيْئًا تَكْرَهُونَهُ، فَاكْرَهُوا عَمَلَهُ، وَلَا تَنْزِعُوا يَدًا مِنْ طَاعَةٍ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"قال النبي صلى الله عليه وسلم: أفضل ولاة أموركم الذين يرفقون بكم، ويعدلون بينكم، فتودونهم وتطيعونهم، وهم كذلك يَوَدُّونكم؛ لأنهم يرون آثار عدلهم باديةً عليكم، وتدعون لهم، ويدعون لكم أو يصلون عليكم إذا متم، وتصلون عليهم إذا ماتوا عن طوع ورغبة، وشر أئمتكم الذين تكرهونهم ويكرهونكم، وتدعون عليهم بالطرد من رحمة الله تعالى، ويدعون عليكم بذلك، قيل له: يا رسول الله، فهل ننقض عهدهم ونخرج عليهم بالسيف في هذه الحالة؟ فقال: لا، ما حافظوا على الصلوات المعهودة بحدودها وأحكامها، وداموا على ذلك وأظهروه، وإذا رأيتم من أمرائكم فعلًا تكرهونه فاكرهوا الفعل الذي يفعله، ولا تتركوا طاعته؛ لما في ذلك من فوات مصالح الدنيا والدين.","reference":"صحيح مسلم (3/ 1481) (1855)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (32/ 218).","benefits":["بيان خيار الأئمة، وهم الذين تحبهم رعيتهم، ويحبونهم، وشرارهم، وهم الذين يكونون بعكس ذلك.","قدر عظم الصلاة، فإن الأئمة وإن كانوا ضد رعيتهم، إلا أنه لا يجوز لأحد أن يخرج عليهم ما داموا يقيمون الصلاة.","كفر تارك الصلاة؛ لقوله عليه الصلاة والسلام: (إلا أن تروا كفرًا بواحًا عندكم من الله فيه برهان) متفق عليه، مع قوله هنا في المسألة نفسها: (لا ما أقاموا فيكم الصلاة)،وفي رواية: (لا ما صلَّوا).","شرط الإسلام في صحة الرئاسة والمُلك.","وجوب إنكار المنكر على ولاة الأمور، ولكن لا يبيح ذلك نزع اليد من الطاعة، بل يجب الصبر عليهم."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["خيار","أئمتكم","الذين","تحبونهم","ويحبونكم","ويصلون"],"source":"hadeethenc"},{"id":"he_66197","text":"عَنْ حُذَيْفَةَ رَضيَ اللهُ عنهُ عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «إِنَّهَا سَتَكُونُ أُمَرَاءُ يَكْذِبُونَ وَيَظْلِمُونَ، فَمَنْ صَدَّقَهُمْ بِكَذِبِهِمْ وَأَعَانَهُمْ عَلَى ظُلْمِهِمْ فَلَيْسَ مِنَّي، وَلَسْتُ مِنْهُ، وَلَا يَرِدُ عَلَيَّ الْحَوْضَ، وَمَنْ لَمْ يُصَدِّقْهُمْ بِكَذِبِهِمْ وَلَمْ يُعِنْهُمْ عَلَى ظُلْمِهِمْ فَهُوَ مِنِّي، وَأَنَا مِنْهُ، وَسَيَرِدُ عَلَيَّ الْحَوْضَ».","attribution":"رواه أحمد","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم أنه سيتولى على الناس بعد موته أمراء يَكذبون في الكلام فيقولون ما لا يفعلون، ويظلمون في الحكم، فمن دخل عليهم وصدّقهم بكذبهم، أو أعانهم بفعل الظلم أو قوله كالإفتاء لهم تقرُّبًا لهم ورجاء ما عندهم؛ فأنا بريء منه وليس مني، ولست منه، ولا يأتي عليّ حوض الكوثر يوم القيامة، ومن لم يدخل عليهم ويصدقهم بكذبهم ويعنهم على ظلمهم فهو مني، وأنا منه، وسيرد علي الحوض يوم القيامة.","reference":"مسند أحمد (38/ 295) (23260).\nذخيرة العقبى في شرح المجتبى (32/ 334).","benefits":["السلاطين إذا دُخِلَ عليهم بالتوجيه والإرشاد وتخفيف الشر؛ هذا هو المطلوب، أما إذا دخل عليهم ليعينهم على الظلم ويصدقهم بالكذب فهذا هو المذموم.","بيان الوعيد لمن أعان أميرًا على ظلمه.","هذا الوعيد في الحديث يدل على تحريم هذا الفعل، وأنه من كبائر الذنوب.","الحث على التعاون على البر والتقوى، وعدم التعاون على الإثم والعدوان.","إثبات الحوض لنبينا محمد صلى الله عليه وسلم، وأن أمته تَرِدُ عليه."],"wordsMeanings":[],"category":"da3wah","bookId":"ahmed","tags":["إنها","ستكون","أمراء","يكذبون","ويظلمون،","فمن"],"source":"hadeethenc"},{"id":"he_66256","text":"عَنْ أَبِي هُرَيْرَةَ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «الْمُسْتَشَارُ مُؤْتَمَنٌ».","attribution":"رواه أبو داود والترمذي وابن ماجه","grade":"صحيح","gradeKey":"sahih","explanation":"المستشار الذي طلب منه المشورة والرأي الأصلح أمين فيما يُسأل عنه من الأمور، فلا ينبغي له أن يخون المستشير بإظهار المفسدة للمستشير وكتمان المصلحة عنه، وبناءً عليه فلا يستشير الإنسان من كانت له مصلحة تعارضه في الأمر المستشار فيه، وينبغي كونه مجربًا أو عالمًا بذلك الأمر.","reference":"سنن أبي داود (7/ 446) (5128)، سنن الترمذي (4/ 422) (2822)، سنن ابن ماجه (4/ 681) (3745)، مرشد ذوي الحجا والحاجة إلى سنن ابن ماجه والقول المكتفى على سنن المصطفى (22/ 142) (22/ 145)، شرح سنن أبي داود لابن رسلان (19/ 399).","benefits":["على من طُلبت منه المشورة أن يكون أمينًا في ما يقول، فلا يجوز له الغش والخيانة.","لا غرامة على المستشار إذا وقع في الخطأ فيما أشار به، كما أن الأمين لا يغرم إذا تلفت الوديعة عنده من غير تقصير منه ولا تعدٍّ."],"wordsMeanings":[],"category":"da3wah","bookId":"abudawud","tags":["المستشار","مؤتمن"],"source":"hadeethenc"},{"id":"he_3004","text":"عن عَبْد الرَّحْمَنِ بْن سَمُرَةَ رضي الله عنه أن رسول الله صلى الله عليه وسلم قال له: «يا عبد الرحمن بن سَمُرَة، لا تَسْأَلِ الإِمَارَةَ؛ فإنك إن أُعْطِيتَها عن مَسْأَلَةٍ وُكِلْتَ إليها، وإن أُعْطِيتَهَا عن غير مَسْأَلَةٍ أُعِنْتَ عليها، وإذا حَلَفْتَ على يمينٍ فرأيتَ غيرها خيرًا منها، فَكَفِّرْ عن يمينك، وَأْتِ الذي هو خير».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"نهى رسول الله صلى الله عليه وسلم عن سؤال الإمارة؛ لأنَّ مَن أعطيها عن مسألةٍ خُذِلَ وتُرِكَ لِرَغْبَتِه في الدنيا وتفضيلها على الآخرة، وأن من أُعْطِيَها عَنْ غَيْرِ مسألةٍ أعانَهُ اللهُ علَيها، وأنَّ الحَلف على شيء لا يكون مانعًا عن الخير، فإن رأى الحالفُ الخيرَ في غيرِ الحلف فلَه التَّخَلُص من الحلف بالكفارة ثم يأت الخير.","reference":"1- صحيح البخاري، محمد بن إسماعيل البخاري الجعفي، تحقيق: محمد زهير الناصر، دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم: محمد فؤاد عبد الباقي)، الطبعة: الأولى 1422هـ.\n2- صحيح مسلم، مسلم بن الحجاج القشيري النيسابوري، تحقيق محمد فؤاد عبد الباقي، دار إحياء التراث العربي، بيروت، الطبعة: 1423هـ.\n3- الإلمام بشرح عمدة الأحكام، إسماعيل بن محمد الأنصاري، دار الفكر، دمشق، الطبعة: الأولى 1381 هـ.\n4- تيسير ","benefits":["كراهةُ طَلَبِ الإِمَارة والولاية.","أنَّ مَنْ جَاءَتْه الوِلايَة بِلا طَلَبٍ ولا اسْتِشْرَافٍ، فَسَيُعَانُ عليها.","أَنَّ مَنْ حَلَفَ أَنْ لَا يَفْعَلَ كذا، أَو أَنْ يفعله، ثم رأى الخير في غير الذي حلف عليه: إما الفعل وإما الترك، فَليَأتِ الذي هو خير، ولْيكَفِّر عن يمينه.","جوازُ التَّكفير قبل الْحنْثِ."],"wordsMeanings":[{"word":"لا تسأل","meaning":" لا تطلب."},{"word":"الإمارة","meaning":" الوِلَايَة."},{"word":"مسألة","meaning":" سُؤَال."},{"word":"وُكلت إليها","meaning":" أَسْلَمَتْ لهَا، ولم يكن معك إعانة."},{"word":"أُعِنْتَ عليها","meaning":" أعانك الله على أثقالها، فتصيب الصواب والحق في قولك وفعلك."}],"category":"da3wah","tags":["عبدَ","الرحمَنِ","بْنَ","سَمُرَةَ،","تَسْأَلْ","الإِمَارَةَ؛"],"source":"hadeethenc"},{"id":"he_3011","text":"عن عائشة رضي الله عنها مرفوعًا: «إِذَا أَرَادَ اللهُ بِالأمِيرِ خَيرًا، جَعَلَ لَهُ وَزِيرَ صِدقٍ، إِنْ نَسِيَ ذَكَّرَهُ، وَإِنْ ذَكَرَ أَعَانَهُ، وَإِذَا أَرَادَ بِهِ غَيرَ ذَلِكَ جَعَلَ لَهُ وَزِيرَ سُوءٍ، إِنْ نَسِيَ لَمْ يُذَكِّرهُ، وَإِنْ ذَكَرَ لَمْ يُعِنْهُ».","attribution":"رواه أبو داود","grade":"صحيح","gradeKey":"sahih","explanation":"يبين رسول الله صلى الله عليه وسلم في هذا الحديث أنّ الله تعالى: \"إذا أراد بالأمير خيراً\"، وفسِّرت هذه الخيرية لمن وُفِّق لوزير صدق من الأمراء بخيرية التوفيق لخيري الدارين، كما فسرت هذه الخيرية بالجنة. \nوقوله: \"جعل له وزير صدق\" أي في القول والفعل، والظاهر والباطن، وأضافه إلى الصدق؛ لأنَّه الأساس في الصُحبة وغيرها.\nفــ\"إن نسي\" أي: هذا الأمير، فإن نسي ما يحتاج إليه -والنسيان من طبيعة البشر-، أو ضلّ عن حكم شرعي، أو قضية مظلوم، أو مصالح لرعية، \"ذكَّره\" أي: هذا الوزير الصادق وهداه.\n\"وإن ذكر\" الأمير ذلك، \"أعانه\" عليه بالرأي والقول والفعل. \nوأما قوله: \"وإذا أراد به غير ذلك\" أي: غير الخير، بأن أراد به شرّاً، كانت النتيجة \"جعل له وزير سوء\" والمراد: وزير سوء في القول، والفعل، نظير ما سبق في ضده.\n\"إن نسي\" أي: ترك مالا بد منه \"لم يذكِّره\" به؛ لأنه ليس عنده من النور القلبي ما يحمله على ذلك. \n\"وإن ذكر لم يعنه\" بل يسعى في صرفه عنه؛ لشرارة طبعه، وسوء صنعه.","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الدمام، الطبعة: الأولى 1415هـ.\nتطريز رياض الصالحين، فيصل بن عبد العزيز المبارك، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة للنشر والتوزيع، الرياض، الطبعة: الأولى 1423هـ، 2002م.\nدليل الفالحين لطرق رياض الصالحين، محمد علي بن البكري بن علان، اعتنى بها: خليل مأمون شيحا، دار المعرفة، بيروت، الطبعة: الرابعة 1425هـ.\nرياض الصالحي","benefits":["وجود فئة صالحة حول الحاكم ترشده إلى الخير وتعينه عليه دليل توفيق الله -تعالى ورضاه عنه-، وفي ذلك عون على إقامة العدل.","الحث على اتخاذ وزير صالح، وأن ذلك من علامة سعادة الوالي، والتحذير من وزير السوء، وأنه علامة على شقاوة الوالي.","تحذير الحكام من بطانة الشر؛ فإنها سبب للإفساد والطغيان.","لا يقتصر هذا الأمر على الرئيس أو الأمير، بل ينطبق على كل صاحب ولاية عامة على أمر من أمور المسلمين."],"wordsMeanings":[{"word":"وَزِير","meaning":" هو الصاحب المؤازر الذي يلتجيء الأمير إلى رأيه وتدبيره، ويحمل عنه شيئًا من أثقاله."},{"word":"صِدق","meaning":" صادق ناصح."},{"word":"إِنْ نَسِيَ","meaning":" أي: شيئًا مما يجب فعله، ويحقق مصلحة الأمة."},{"word":"وَإِذَا أَرَادَ بِهِ غَيرَ ذَلِكَ","meaning":" أراد به شرًّا."},{"word":"سُوءٍ","meaning":" سيِّء يميل إلى الشر والفساد، ويرغِّب في ظلم الحاكم للرعية."}],"category":"da3wah","bookId":"abudawud","tags":["إذا","أراد","الله","بالأمير","خيرا،","جعل"],"source":"hadeethenc"},{"id":"he_3012","text":"عن أبي سعيد الخدري وأبي هريرة رضي الله عنهما مرفوعاً: \"ما بعث الله من نبي ولا اسْتَخْلَفَ من خليفة إلا كانت له بطانتان: بطانة تأمره بالمعروف وتَحُضُّهُ عليه، وبطانة تأمره بالشر وتَحُضُّهُ عليه، والمعصوم من عصم الله\".","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي -عليه الصلاة والسلام- أن الله ما بعث من نبي ولا استخلف من خليفة إلا كان له بطانتان: بطانة خير تأمره بالخير وتحثه عليه، وبطانة سوء تدله على السوء وتأمره به، والمحفوظ من تأثير بطانة الشر هو من حفظه الله تعالى .","reference":"صحيح البخاري، محمد بن إسماعيل البخاري الجعفي، تحقيق: محمد زهير الناصر، دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم: محمد فؤاد عبد الباقي)، الطبعة: الأولى 1422هـ.\nبهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الطبعة: الأولى 1418 هـ، 1997م.\nنزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين، مؤسسة الرسالة، بيروت، الطبعة: الرابعة عشر، 1407هـ، 1987م.\nرياض الصالحين من كلام س","benefits":["الأمر بيد الله -تعالى- يؤتي ملكه من يشاء وينزع الملك ممن يشاء، ويهدي من يشاء ويضل من يشاء.","من واجب الحاكم أن يتخيَّر البطانة الصالحة، التي هي عنوان سعادته.","العبد إما أن يكون داعية إلى الله يأمر بالمعروف ويحض عليه، وينهى عن المنكر ويحذر منه، أو يدعو إلى الشيطان وحزبه.","الخواص والبطانة منهم أهل صلاح وخير يأمرون بطاعة الله ورسوله، وينهون عن الشر ويذكرون بلقاء الله، ومنهم أهل فساد وشر على العكس من ذلك.","لا سبيل إلى اتقاء شر بطانة السوء إلا بالاعتصام بالله ولزوم تطبيق شرعه."],"wordsMeanings":[{"word":"خَلِيفَة","meaning":" حاكم أو ذو ولاية."},{"word":"كَانَت","meaning":" وُجدت."},{"word":"بطَانَتَان","meaning":" فئتان من الأعوان، وبطانة الرجل: صاحب سره الذي يشاوره في أحواله."},{"word":"تَأمُرُهُ بِالمَعرُوفِ","meaning":" تشير عليه بما عرف واستحسن من العدل وغيره."},{"word":"تَأمُرُهُ بِالشَرِّ","meaning":" تدعوه إليه."},{"word":"تَحُضُّهُ","meaning":" تحُثه."},{"word":"المَعْصُومُ","meaning":" المحفوظ من تأثير بطانة الشر."},{"word":"مَنْ عَصَمَ الله","meaning":" حفظه الله، إما بنور النبوة والوحي أو الاهتداء بشرع الله -تعالى-."}],"category":"da3wah","bookId":"bukhari","tags":["بعث","الله","نبي،","ولا","استخلف","خليفة"],"source":"hadeethenc"},{"id":"he_3082","text":"عن شقيق بن سلمة رحمه الله قال: كان ابن مسعود رضي الله عنه يُذَكِّرُنا في كل خميس، فقال له رجل: يا أبا عبد الرحمن، لَوَدِدْتُ أنك ذَكَّرْتَنا كل يوم، فقال: أما إنه يمنعني من ذلك أني أكره أن أُمِلَّكُم، وإني أَتَخَوَّلُكُم بالمَوْعِظَةِ، كما كان رسول الله صلى الله عليه وسلم يَتَخَوَّلُنَا بها مَخَافَةَ السَّآمَةِ علينا.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر شقيق بن سلمة رحمه الله أن ابن مسعود رضي الله عنه كان يعظهم كل خميس، فقال له رجل: إننا لنحب أن تعظنا كل يوم، فقال: إن الذي يمنعني من ذلك كراهية أن أوقعكم في الملل والضجر، وإني أتعهدكم بالموعظة وأتفقد حال احتياجكم إليها كما كان يفعل رسول الله صلى الله عليه وسلم معنا، خشية أن يوقعنا في الملالة، إذ لا تأثير للموعظة عند الملالة.","reference":"بهجة الناظرين شرح رياض الصالحين، لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nرياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428هـ.\nشرح رياض الصالحين، للشيخ ابن عثيمين، دار الوطن للنشر، الرياض، 1426هـ.\nصحيح البخاري، تحقيق: محمد زهير بن ناصر الناصر، ط1، دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم: محمد فؤاد عبد الباقي)، 1422هـ.\nصحيح مسلم، تحقيق: محمد فؤاد ع","benefits":["الاقتصاد في الوعظ والإرشاد؛ لأن من طبائع النفوس الملل مما يداوم عليه وإن كان محبوباً لها.","بيان أن أحب الأعمال إلى الله أدومها وإن قل.","استحباب التخول في الوعظ خشية الملال.","استحباب أوقات النشاط للتعليم والموعظة.","استحباب أن يجعل الواعظ موعظته مشوقة حتى يُقبِل الناس على استماعها ولا يكون ذلك إلا بالعلم المصاحب للعمل.","عدم استجابة الواعظ لكل ما يطلب منه بل يقدر بنفسه مقدار ما يصلح في كل أمر من الأمور؛ لأنه ينظر من بصيرة علمه، والناس يتعاملون باندفاع عواطفهم.","حرص الصحابة على متابعة الرسول -صلى الله عليه وسلم- في أقواله وأفعاله."],"wordsMeanings":[{"word":"يُذَكِّرُنَا","meaning":" أي بالتكاليف الشرعية أو يذكر لنا ثواب الطاعات وعقاب المعاصي."},{"word":"لَوَدِدْتُ","meaning":" لأحببت."},{"word":"بِالْمَوعِظَةِ","meaning":" الوعظ: هو ذكر الأحكام الشرعية مقرونة بالترغيب أو الترهيب."},{"word":"يَتَخَوَّلُنَا","meaning":" يتعهدنا."},{"word":"السَّآمَةِ","meaning":" الملل أو المشقة."}],"category":"da3wah","tags":["كان","ابن","مسعود","رضي","الله","عنه"],"source":"hadeethenc"},{"id":"he_3303","text":"عَنْ صُهَيْبٍ رَضيَ اللهُ عنه أَنَّ رَسُولَ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: \"كَانَ مَلِكٌ فِيمَنْ كَانَ قَبْلَكُمْ، وَكَانَ لَهُ سَاحِرٌ، فَلَمَّا كَبِرَ، قَالَ لِلْمَلِكِ: إِنِّي قَدْ كَبِرْتُ، فَابْعَثْ إِلَيَّ غُلَامًا أُعَلِّمْهُ السِّحْرَ، فَبَعَثَ إِلَيْهِ غُلَامًا يُعَلِّمُهُ، فَكَانَ فِي طَرِيقِهِ إِذَا سَلَكَ رَاهِبٌ فَقَعَدَ إِلَيْهِ وَسَمِعَ كَلَامَهُ، فَأَعْجَبَهُ، فَكَانَ إِذَا أَتَى السَّاحِرَ مَرَّ بِالرَّاهِبِ وَقَعَدَ إِلَيْهِ، فَإِذَا أَتَى السَّاحِرَ ضَرَبَهُ، فَشَكَا ذَلِكَ إِلَى الرَّاهِبِ، فَقَالَ: إِذَا خَشِيتَ السَّاحِرَ، فَقُلْ: حَبَسَنِي أَهْلِي، وَإِذَا خَشِيتَ أَهْلَكَ فَقُلْ: حَبَسَنِي السَّاحِرُ، فَبَيْنَمَا هُوَ كَذَلِكَ إِذْ أَتَى عَلَى دَابَّةٍ عَظِيمَةٍ قَدْ حَبَسَتِ النَّاسَ، فَقَالَ: الْيَوْمَ أَعْلَمُ آلسَّاحِرُ أَفْضَلُ أَمِ الرَّاهِبُ أَفْضَلُ؟ فَأَخَذَ حَجَرًا، فَقَالَ: اللهُمَّ إِنْ كَانَ أَمْرُ الرَّاهِبِ أَحَبَّ إِلَيْكَ مِنْ أَمْرِ السَّاحِرِ فَاقْتُلْ هَذِهِ الدَّابَّةَ، حَتَّى يَمْضِيَ النَّاسُ، فَرَمَاهَا فَقَتَلَهَا، وَمَضَى النَّاسُ، فَأَتَى الرَّاهِبَ فَأَخْبَرَهُ، فَقَالَ لَهُ الرَّاهِبُ: أَيْ بُنَيَّ أَنْتَ الْيَوْمَ أَفْضَلُ مِنِّي، قَدْ بَلَغَ مِنْ أَمْرِكَ مَا أَرَى، وَإِنَّكَ سَتُبْتَلَى، فَإِنِ ابْتُلِيتَ فَلَا تَدُلَّ عَلَيَّ، وَكَانَ الْغُلَامُ يُبْرِئُ الْأَكْمَهَ وَالْأَبْرَصَ، وَيُدَاوِي النَّاسَ مِنْ سَائِرِ الْأَدْوَاءِ، فَسَمِعَ جَلِيسٌ لِلْمَلِكِ كَانَ قَدْ عَمِيَ، فَأَتَاهُ بِهَدَايَا كَثِيرَةٍ، فَقَالَ: مَا هَاهُنَا لَكَ أَجْمَعُ، إِنْ أَنْتَ شَفَيْتَنِي، فَقَالَ: إِنِّي لَا أَشْفِي أَحَدًا إِنَّمَا يَشْفِي اللهُ، فَإِنْ أَنْتَ آمَنْتَ بِاللهِ دَعَوْتُ اللهَ فَشَفَاكَ، فَآمَنَ بِاللهِ فَشَفَاهُ اللهُ، فَأَتَى الْمَلِكَ فَجَلَسَ إِلَيْهِ كَمَا كَانَ يَجْلِسُ، فَقَالَ لَهُ الْمَلِكُ: مَنْ رَدَّ عَلَيْكَ بَصَرَكَ؟ قَالَ: رَبِّي، قَالَ: وَلَكَ رَبٌّ غَيْرِي؟ قَالَ: رَبِّي وَرَبُّكَ اللهُ، فَأَخَذَهُ فَلَمْ يَزَلْ يُعَذِّبُهُ حَتَّى دَلَّ عَلَى الْغُلَامِ، فَجِيءَ بِالْغُلَامِ، فَقَالَ لَهُ الْمَلِكُ: أَيْ بُنَيَّ قَدْ بَلَغَ مِنْ سِحْرِكَ مَا تُبْرِئُ الْأَكْمَهَ وَالْأَبْرَصَ، وَتَفْعَلُ وَتَفْعَلُ، فَقَالَ: إِنِّي لَا أَشْفِي أَحَدًا، إِنَّمَا يَشْفِي اللهُ، فَأَخَذَهُ فَلَمْ يَزَلْ يُعَذِّبُهُ حَتَّى دَلَّ عَلَى الرَّاهِبِ، فَجِيءَ بِالرَّاهِبِ، فَقِيلَ لَهُ: ارْجِعْ عَنْ دِينِكَ، فَأَبَى، فَدَعَا بِالْمِئْشَارِ، فَوَضَعَ الْمِئْشَارَ فِي مَفْرِقِ رَأْسِهِ، فَشَقَّهُ حَتَّى وَقَعَ شِقَّاهُ، ثُمَّ جِيءَ بِجَلِيسِ الْمَلِكِ فَقِيلَ لَهُ: ارْجِعْ عَنْ دِينِكَ، فَأَبَى فَوَضَعَ الْمِئْشَارَ فِي مَفْرِقِ رَأْسِهِ، فَشَقَّهُ بِهِ حَتَّى وَقَعَ شِقَّاهُ، ثُمَّ جِيءَ بِالْغُلَامِ فَقِيلَ لَهُ ارْجِعْ عَنْ دِينِكَ، فَأَبَى فَدَفَعَهُ إِلَى نَفَرٍ مِنْ أَصْحَابِهِ، فَقَالَ: اذْهَبُوا بِهِ إِلَى جَبَلِ كَذَا وَكَذَا، فَاصْعَدُوا بِهِ الْجَبَلَ، فَإِذَا بَلَغْتُمْ ذُرْوَتَهُ، فَإِنْ رَجَعَ عَنْ دِينِهِ، وَإِلَّا فَاطْرَحُوهُ، فَذَهَبُوا بِهِ فَصَعِدُوا بِهِ الْجَبَلَ، فَقَالَ: اللهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ، فَرَجَفَ بِهِمِ الْجَبَلُ فَسَقَطُوا، وَجَاءَ يَمْشِي إِلَى الْمَلِكِ، فَقَالَ لَهُ الْمَلِكُ: مَا فَعَلَ أَصْحَابُكَ؟ قَالَ: كَفَانِيهِمُ اللهُ، فَدَفَعَهُ إِلَى نَفَرٍ مِنْ أَصْحَابِهِ، فَقَالَ: اذْهَبُوا بِهِ فَاحْمِلُوهُ فِي قُرْقُورٍ، فَتَوَسَّطُوا بِهِ الْبَحْرَ، فَإِنْ رَجَعَ عَنْ دِينِهِ وَإِلَّا فَاقْذِفُوهُ، فَذَهَبُوا بِهِ، فَقَالَ: اللهُمَّ اكْفِنِيهِمْ بِمَا شِئْتَ، فَانْكَفَأَتْ بِهِمِ السَّفِينَةُ فَغَرِقُوا، وَجَاءَ يَمْشِي إِلَى الْمَلِكِ، فَقَالَ لَهُ الْمَلِكُ: مَا فَعَلَ أَصْحَابُكَ؟ قَالَ: كَفَانِيهِمُ اللهُ، فَقَالَ لِلْمَلِكِ: إِنَّكَ لَسْتَ بِقَاتِلِي حَتَّى تَفْعَلَ مَا آمُرُكَ بِهِ، قَالَ: وَمَا هُوَ؟ قَالَ: تَجْمَعُ النَّاسَ فِي صَعِيدٍ وَاحِدٍ، وَتَصْلُبُنِي عَلَى جِذْعٍ، ثُمَّ خُذْ سَهْمًا مِنْ كِنَانَتِي، ثُمَّ ضَعِ السَّهْمَ فِي كَبِدِ الْقَوْسِ، ثُمَّ قُلْ: بِاسْمِ اللهِ رَبِّ الْغُلَامِ، ثُمَّ ارْمِنِي، فَإِنَّكَ إِذَا فَعَلْتَ ذَلِكَ قَتَلْتَنِي، فَجَمَعَ النَّاسَ فِي صَعِيدٍ وَاحِدٍ، وَصَلَبَهُ عَلَى جِذْعٍ، ثُمَّ أَخَذَ سَهْمًا مِنْ كِنَانَتِهِ، ثُمَّ وَضَعَ السَّهْمَ فِي كَبْدِ الْقَوْسِ، ثُمَّ قَالَ: بِاسْمِ اللهِ، رَبِّ الْغُلَامِ، ثُمَّ رَمَاهُ فَوَقَعَ السَّهْمُ فِي صُدْغِهِ، فَوَضَعَ يَدَهُ فِي صُدْغِهِ فِي مَوْضِعِ السَّهْمِ فَمَاتَ، فَقَالَ النَّاسُ: آمَنَّا بِرَبِّ الْغُلَامِ، آمَنَّا بِرَبِّ الْغُلَامِ، آمَنَّا بِرَبِّ الْغُلَامِ، فَأُتِيَ الْمَلِكُ فَقِيلَ لَهُ: أَرَأَيْتَ مَا كُنْتَ تَحْذَرُ؟ قَدْ وَاللهِ نَزَلَ بِكَ حَذَرُكَ، قَدْ آمَنَ النَّاسُ، فَأَمَرَ بِالْأُخْدُودِ فِي أَفْوَاهِ السِّكَكِ، فَخُدَّتْ وَأَضْرَمَ النِّيرَانَ، وَقَالَ: مَنْ لَمْ يَرْجِعْ عَنْ دِينِهِ فَأَحْمُوهُ فِيهَا، أَوْ قِيلَ لَهُ: اقْتَحِمْ، فَفَعَلُوا حَتَّى جَاءَتِ امْرَأَةٌ وَمَعَهَا صَبِيٌّ لَهَا فَتَقَاعَسَتْ أَنْ تَقَعَ فِيهَا، فَقَالَ لَهَا الْغُلَامُ: يَا أُمَّهْ اصْبِرِي فَإِنَّكِ عَلَى الْحَقِّ\".","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر النبي صلى الله عليه وسلم أنه كان ملك فيمن كان قبلنا من الأمم، وكان له ساحر، فلما كبر الساحر، قال للملك: \n\nإني قد كبرت، فأرسل إلي شابًا أعلمه السحر. \n\nفبعث الملك إليه شابًا يعلمه، فكان في طريق الشاب إذا ذهب للساحر راهبٌ فقعد إليه مرة وسمع كلامه، فأعجبه، فكان إذا أتى الساحر مر بالراهب وقعد إليه، فإذا أتى الساحر ضربه لتأخره، فشكا ذلك إلى الراهب، فقال: إذا خشيت الساحر، فقل: حبسني أهلي، وإذا خشيت أهلك فقل: حبسني الساحر، فبينما هو كذلك إذ أتى على دابة عظيمة قد منعت الناس من المضي، فقال: اليوم أعلم آلساحر أفضل أم الراهب أفضل؟ \n\nفأخذ حجرًا، فقال: اللهم إن كان أمر الراهب أحب إليك من أمر الساحر فاقتل هذه الدابة، حتى يمضي الناس، فرماها فقتلها، ومضى الناس، فأتى الراهب فأخبره، فقال له الراهب: \n\nأي بني أنت اليوم أفضل مني، قد بلغ من أمرك ما أرى، وإنك ستبتلى، فإن ابتليت فلا تدل علي، وكان الغلام يبرئ الأكمه والأبرص، ويداوي الناس من سائر الأمراض بإذن الله، فسمع جليس للملك كان قد فقد بصره، فأتاه بهدايا كثيرة، فقال للغلام: \n\nكل ما هاهنا من الهدايا لك إن أنت شفيتني. \n\nفقال: إني لا أشفي أحدًا إنما يشفي الله، فإن أنت آمنت بالله دعوت الله فشفاك، فآمن بالله فشفاه الله، فأتى الملك فجلس إليه كما كان يجلس، فقال له الملك: من رد عليك بصرك؟ \n\nقال: ربي، قال: ولك رب غيري؟ \n\nقال: ربي وربك الله. \n\nفأخذه فلم يزل يعذبه حتى دل على الغلام، فجيء بالغلام، فقال له الملك: \n\nأي بني قد بلغ من سحرك ما تبرئ الأكمه والأبرص، وتفعل وتفعل. \n\nفقال: إني لا أشفي أحدًا، إنما يشفي الله، فأخذه فلم يزل يعذبه حتى دل على الراهب. \n\nفجيء بالراهب، فقيل له: ارجع عن دينك، فأبى، فدعا بالمنشار، فوضعه في مفرق رأسه، فشقه به نصفين. \n\nثم جيء بجليس الملك فقيل له: ارجع عن دينك، فأبى فوضع المنشار في مفرق رأسه، فشقه به نصفين. \n\nثم جيء بالغلام فقيل له ارجع عن دينك، فأبى فدفعه إلى رجال من أصحابه بين الثلاثة والعشرة. \n\nفقال: اذهبوا به إلى جبل كذا وكذا، فاصعدوا به الجبل، فإذا بلغتم أعلاه، فإن رجع عن دينه، وإلا فاطرحوه، فذهبوا به فصعدوا به الجبل. \n\nفقال الغلام: اللهم اكفنيهم بما شئت، فرجف بهم الجبل وتحرك حركة شديدة فسقطوا، وجاء يمشي إلى الملك. \n\nفقال له الملك: ما فعل أصحابك؟ \n\nقال: كفانيهم الله. \n\nفدفعه إلى نفر من أصحابه، فقال: اذهبوا به فاحملوه في سفينة صغيرة، فتوسطوا به البحر، فإن رجع عن دينه وإلا فاقذفوه في البحر. \n\nفذهبوا به، فقال: اللهم اكفنيهم بما شئت، فانقلبت بهم السفينة فغرقوا، وجاء يمشي إلى الملك. \n\nفقال له الملك: ما فعل أصحابك؟ \n\nقال: كفانيهم الله، فقال الغلام للملك: إنك لا تستطيع قتلي حتى تفعل ما آمرك به. \n\nقال: وما هو؟ \n\nقال: تجمع الناس في أرض بارزة، وتصلبني على جذع شجرة، ثم خذ سهمًا من كنانتي، ثم ضع السهم في مقبض القوس، ثم قل: باسم الله رب الغلام، ثم ارمني، فإنك إذا فعلت ذلك قتلتني، فجمع الناس في مكان واحد، وصلبه على جذع، ثم أخذ سهمًا من كنانته، ثم وضع السهم في وسط القوس، ثم قال: باسم الله رب الغلام، ثم رماه فوقع السهم في صدغه بين عينه وأذنه، فوضع يده في صدغه في موضع السهم فمات.\n\n فقال الناس: آمنا برب الغلام، آمنا برب الغلام، آمنا برب الغلام. \n\nفأُتي الملك فقيل له: أرأيت ما كنت تخاف؟ \n\nقد والله نزل بك ما خفت وهو اتباع الناس للغلام وإيمانهم بربه أجمعون، فأمر بشق الأرض شقوقًا عظيمة مستطيلة في أبواب الطرق، وأوقد وأشعل النيران فيها، وقال: من لم يرجع عن دينه فاطرحوه فيها، ففعلوا ما أمرهم الملك به، حتى جاءت امرأة ومعها صبي لها فتوقفت ولزمت موضعها وكرهت الدخول في النار، فقال لها صبيها: \n\nيا أمه اصبري فإنك على الحق.","reference":"صحيح مسلم (4/ 2299) (3005).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 86).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص39).\nكنوز رياض الصالحين، لمجموعة من الباحثين (1/ 412).\nشرح رياض الصالحين، لابن عثيمين (1/ 210).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 62).","benefits":["إثبات كرامات الأولياء، ومن ذلك قتل الدابة العظيمة برمية الغلام، وإجابة دعاء الغلام مرتين، وكلام الطفل الرضيع.","نصر من توكل على الله سبحانه.","بيان شرف الصبر والثبات على الدين.","الحكمة في التعلّم في أول العُمر؛ لأنَّ الشاب في الغالب أسرع حفظًا من الكبير.","قُوَّة إيمان هذا الغلام، وأنه لم يتزحزح عن إيمانه ولم يتحول.","الله عز وجل يجيب دعوة المضطر إذا دعاه.","الإنسان يجوز أن يُغَرِّر بنفسه في مصلحة عامة للمسلمين، فإن هذا الغلام دل الملك على أمر يقتله به ويهلك به نفسه، وهو أن يأخذ سهمًا من كنانته ويضعه في كبد القوس ويقول: باسم الله رب الغلام.","جواز الكذب في الحرب ونحوها، وفي إنقاذ النفس من الهلاك.","المؤمن يُختَبر في صدق إيمانه والثبات على قول الحق، وإن وصل به الأمر إلى إزهاق نفسه.","التضحية في سبيل الدعوة إلى الله وإظهار الحق.","قلوب العباد بيد الله فيهدي من يشاء ويضل من يشاء، فقد اهتدى الغلام وهو في أحضان الساحر وعناية الملك العاثر.","جواز سؤال الله تعالى أن يري العبد علامة يعرف بها الصواب ويحصل له اليقين.","أهل الإيمان يسخرون كل ما أتاهم الله وتفضل به عليهم لخدمة دينه والدعوة إلى سبيله.","أسباب الهلاك بيد الله، فإن شاء أنفذها وإن شاء قطعها.","أهل الكفر لا تنقصهم الحجج والبراهين ليؤمنوا، وإنما سبب كفرهم هو العناد والكبر.","الطواغيت والظالمون عندهم الاستعداد لقتل الناس جميعًا ليبقوا على ما هم فيه من نعيم الدنيا.","الله يعاقب الذين ظلموا من حيث لم يحتسبوا، فقد آمن الناس برب الغلام عندما رأوا ثباته وصدق دعوته وعدم خشيته في الله لومة لائم.","هناك من تكلم في المهد غير المسيح عليه السلام، وهذا الحديث يشرح قول رسول الله صلى الله عليه وسلم: \"لم يتكلم في المهد إلا ثلاثة...\"، وذكرهم، وحصرهم في بني إسرائيل دون غيرهم."],"wordsMeanings":[],"category":"da3wah","bookId":"muslim","tags":["كان","ملك","فيمن","كان","قبلكم،","وكان"],"source":"hadeethenc"},{"id":"he_3311","text":"عن أبي ذر رضي الله عنه قال: قال لي رسول الله صلى الله عليه وسلم «يَا أَبَا ذَرٍّ، إِنِّي أَرَاكَ ضَعِيفًا، وَإِنِّي أُحِبُّ لَكَ مَا أُحِبُّ لِنَفْسِي، لاَ تَأَمَّرَنَّ عَلَى اثْنَينِ، وَلاَ تَوَلَّيَنَّ مَالَ يَتِيمٍ».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر أبو ذر رضي الله عنه أن النبي صلى الله عليه وسلم قال له: \"إني أراك ضعيفاً وإني أحب لك ما أحب لنفسي فلا تأمرن على اثنين ولا تولين على مال يتيم\" هذه أربع جمل بيَّنها الرسول -عليه الصلاة والسلام- لأبي ذر: \nالأولى: قال له: \"إني أراك ضعيفاً\"، وهذا الوصف المطابق للواقع يحمل عليه النصح، فلا حرج على الإنسان إذا قال لشخص مثلا: إن فيك كذا وكذا، من باب النصيحة لا من باب السب والتعيير. \nالثانية: قال: \"وإني أحب لك ما أحبه لنفسي\" وهذا من حسن خلق النبي -عليه الصلاة والسلام-، لما كانت الجملة الأولى فيها شيء من الجرح قال: \"وإني أحب لك ما أحب لنفسي\" يعني: لم أقل لك ذلك إلا أني أحب لك ما أحب لنفسي.\nالثالثة: \"فلا تأمرنَّ على اثنين\"، يعني: لا تكن أميرًا على اثنين، وما زاد فهو من باب أولى. \nوالمعنى أن النبي صلى الله عليه وسلم نهاه أن يكون أميرًا؛ لأنه ضعيف، والإمارة تحتاج إلى إنسان قوي أمين، قوي بحيث تكون له سلطة وكلمة حادة؛ وإذا قال فعل، لا يكون ضعيفا أمام الناس؛ لأن الناس إذا استضعفوا الشخص لم يبق له حرمة عندهم، وتجرأ عليه السفهاء، لكن إذا كان قويًّا لا يتجاوز حدود الله عز وجل، ولا يقصر عن السلطة التي جعلها الله له فهذا هو الأمير حقيقة. \nالرابعة: \"ولا تولين مال يتيم\" واليتيم هو الذي مات أبوه قبل أن يبلغ، فنهاه الرسول -عليه الصلاة والسلام- أن يتولى على مال اليتيم؛ لأنَّ مال اليتيم يحتاج إلى عناية ويحتاج إلى رعاية، وأبو ذر ضعيف لا يستطيع أن يرعى هذا المال حق رعايته فلهذا قال: \"ولا تولين مال يتيم\" يعني لا تكن وليا عليه دعه لغيرك.\nوليس في هذا انتقاصًا لأبي ذر فقد كان يأمر بالمعروف وينهى عن المنكر بالإضافة للزهد والتقشف، ولكنه ضعف في باب معين وهو باب الولاية والإمارة.","reference":"بهجة الناظرين شرح رياض الصالحين لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nرياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428هـ.\nرياض الصالحين، ط4، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بيروت، 1428هـ.\nكنوز رياض الصالحين، مجموعة من الباحثين برئاسة حمد بن ناصر العمار، ط1، كنوز إشبيليا، الرياض، 1430هـ.\nشرح رياض الصالحين  للشيخ ا","benefits":["تحريم الولاية لمن علم من نفسه الضعف عن القيام بأعبائها.","وجوب حفظ مال اليتيم وعدم الأكل منه بغير حق أو تضييعه.","حرص الإسلام على المصلحة العامة وأموال اليتامى."],"wordsMeanings":[{"word":"ضعيفاً","meaning":" لا قدرة لديك على القيام بأعباء الولاية، وذلك لما كان عليه من الزهد وعدم الاكتراث بأمور الدنيا."},{"word":"لا تَأَمَّرَنَّ","meaning":" لا تتأمرن أي تصير أميرا."},{"word":"لا تَوَلَّيَنَّ","meaning":" أي لا تتولين، وتولي الأمر تقلده والقيام به، ومنه ولي اليتيم: الذي يلي أمره ويقوم بكفايته."},{"word":"يتيم","meaning":" هو الذي مات أبوه قبل أن يبلغ."}],"category":"da3wah","bookId":"muslim","tags":["أبا","ذر،","إني","أراك","ضعيفًا،","وإني"],"source":"hadeethenc"},{"id":"he_3467","text":"عن أبي ذر رضي الله عنه قال: قُلتُ: يَا رسُولَ الله، أَلاَ تَسْتَعْمِلُنِي؟ فَضَرَبَ بِيَدِهِ عَلَى مَنْكِبِي، ثُمَّ قَالَ: «يَا أَبَا ذَرٍّ، إِنَّكَ ضَعِيفٌ، وَإِنَّهَا أَمَانَةٌ، وَإِنَّهَا يَوْمَ القِيَامَةِ خِزيٌ وَنَدَامَةٌ، إِلاَّ مَنْ أَخَذَهَا بِحَقِّهَا، وَأَدَّى الَّذِي عَلَيهِ فِيهَا».","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر أبو ذر أن النبي صلى الله عليه وسلم خصّه بنصيحة في شأن الإمارة وتوليها، وهذا لما سأل رضي الله عنه النبي صلى الله عليه وسلم أنْ يستعمله في الولاية، فقال له النبي صلى الله عليه وسلم : \"إنك ضعيفٌ\"، وهذا القول فيه نوع قوة لكن الأمانة تقتضي أن يُصرَّحَ للإنسان بوصفه الذي هو عليه، إن قويًّا فقوي، وإن ضعيفًا فضعيف.\nففي هذا دليل على أنه يشترط للإمارة أن يكون الإنسان قويًّا وأن يكون أمينًا؛ لأن الرسول -عليه الصلاة والسلام- قال: \"وإنها أمانة\"، فإذا كان قويًّا أمينًا فهذه هي الصفات التي يستحق بها أن يكون أميرًا واليًا، فإن كان قويًّا غيرَ أمينٍ، أو أمينًا غيرَ قوي، أو ضعيفًا غيرَ أمينٍ، فهذه الأقسام الثلاثة لا ينبغي أن يكون صاحبها أميرًا. \nوعليه فإنَّنَا نُؤَمِّر القوي؛ لأنَّ هذا أنفع للناس، فالناس يحتاجون إلى سلطة وإلى قوة، وإذا لم تكن قوة ولا سيما مع ضعف الدين ضاعت الأمور.\nفهذا الحديث أصل عظيم في اجتناب الولايات، لا سيما لمن كان فيه ضعف عن القيام بوظائف تلك الولاية. \nوأما الخزي والندامة الواردة في الحديث، في قوله: \"وإنها يوم القيامة خزي وندامة\" فهو في حق من لم يكن أهلًا لها، أو كان أهلًا ولم يعدل فيها، فيخزيه الله تعالى يوم القيامة، ويفضحه، ويندم على ما فرَّط. \nوأما من كان أهلًا للولاية وعدل فيها، فلا يشمله الوعيد؛ ولذلك النبي الكريم استثنى فقال صلى الله عليه وسلم : \"إلا من أخذها بحقها، وأدى الذي عليه فيها\"، ذلك أن من أخذها بحقها له فضل عظيم تظاهرت به الأحاديث الصحيحة؛ كحديث: \"سبعة يظلهم الله في ظله\"، ذكر منهم \"إمام عادل\"، وحديث: \"إنّ المقسطين على منابر من نور يوم القيامة\"، وغير ذلك.","reference":"بهجة الناظرين شرح رياض الصالحين، لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nرياض الصالحين، للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428 هـ.\nرياض الصالحين، ط4، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بيروت، 1428هـ.\nكنوز رياض الصالحين، مجموعة من الباحثين برئاسة حمد بن ناصر العمار، ط1، كنوز إشبيليا، الرياض، 1430هـ.\nشرح رياض الصالحين، للشي","benefits":["من طلب الولاية لا يُوَلَّى؛ فالإسلام لا يعطي الإمارة من سألها وحرص عليها وعمل على طلبها.","أحق الناس بالإمارة من امتنع عنها وكرهها، وكان أهلًا لها.","الولاية أمانة عظيمة ومسؤولية خطيرة، فعلى من وليها أن يرعاها حق رعايتها، وأن لا يخون عهد الله فيها.","فضل من تولى الولاية وكان أهلا لها، سواءً كان إمامًا عادلًا، أو خازنًا أمينًا، أو عاملًا متقنًا.","أن العاجز عن القيام بحقوق الإِمارة وتنفيذ أُمورها لا يجوز له أن يدخل فيها، وكذلك العاجز عن إصلاح مال اليتيم لا يتولاه."],"wordsMeanings":[{"word":"أَلاَ تَسْتَعْمِلُنِي","meaning":" تجعلني عاملًا، أي تجعلني موظفًا على شيء."},{"word":"مَنْكِبِي","meaning":" المنكب: مجتمع رأس العضُد والكتف."},{"word":"وَإِنَّهَا","meaning":" أي الإمارة."},{"word":"خِزيٌ وَنَدَامَةٌ","meaning":" فضيحة قبيحة لمن لم يقم بحقها فتجعله يندم على تقلدها."},{"word":"بِحَقِّهَا","meaning":" أي كان مستحقًّا لها قادرًا على القيام بأعمالها."}],"category":"da3wah","bookId":"muslim","tags":["أبا","ذر،","إنك","ضعيف،","وإنها","أمانة،"],"source":"hadeethenc"},{"id":"he_3483","text":"عن عقبة بن الحارث رضي الله عنه قال: صليت وراء النبي صلى الله عليه وسلم بالمدينة العصر، فسَلَّمَ ثم قام مُسرعًا، فتَخَطَّى رِقَابَ الناس إلى بعض حُجَرِ نِسائه، فَفَزِعَ الناسُ من سُرْعَتِهِ، فخرج عليهم، فرأى أنهم قد عجبوا من سُرْعَتِهِ، قال: «ذكرت شيئاً من تِبْرٍ عندنا فكرهت أن يَحْبِسَنِي، فأمرتُ بِقِسْمَتِهِ».\nوفي رواية: «كنت خَلَّفْتُ في البيت تِبْرًا من الصدقة، فكرهت أن أُبَيِّتَهُ».","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"قال عقبة بن الحارث رضي الله عنه أنه صلَّى مع النبي صلى الله عليه وسلم ذات يوم صلاة العصر، فقام النبي صلى الله عليه وسلم حين انصرف من صلاته مسرعاً، يَتخَطَّي رقاب الناس متوجهاً إلى بعض حجرات زوجاته؛ فخاف الناس من ذلك، ثم خرج فرأى الناس قد عجبوا من ذلك؛ فبين لهم النبي صلى الله عليه وسلم سبب هذا، وأخبر أنه تذكر شيئًا من ذهب غير مضروب مما تجب قسمته، فكره أن يمنعه ويشغله التفكير فيه عن التوجه والإقبال على الله تعالى .","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الدمام، الطبعة: الأولى 1415هـ.\nرياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق ماهر الفحل، دار ابن كثير، دمشق، بيروت، الطبعة: الأولى 1428هـ.\nكنوز رياض الصالحين، مجموعة من الباحثين برئاسة حمد بن ناصر العمار، كنوز إشبيليا، الرياض، الطبعة: الأولى1430هـ.\nشرح رياض الصالحين  للشيخ ابن عثيمين، دار الوطن للنشر، ال","benefits":["جواز قيام الإمام بعد الفراغ من الصلاة دون أن يقول أذكار دبر الصلاة إذا أتاه ما يشغله، ويؤخر الأذكار.","أن رسول الله -صلى الله عليه وسلم- أسرع الناس مبادرة إلى الخير.","جواز تخطي الرقاب بعد السلام من الصلاة، ولا سيما إذا كان لحاجة.","جواز التعجب ممن فعل فعلاً ليس من عادته.","أن رسول الله -صلى الله عليه وسلم- كغيره من البشر يلحقه النسيان، وأنه ينسى كما ينسى غيره.","انشغال الفكر في الصلاة لا يبطلها، ولكن يُخشى أن يذهب بالخشوع.","استحباب التخلص مما يشغل القلب عن الله -تعالى-، واستحباب المبادرة إلى عمل الخير.","شدة الأمانة وعظمها، وأن الإنسان إذا لم يبادر بأدائها فإنها قد تحبسه.","جواز الاستنابة والتوكيل في صرف الصدقات مع القدرة على المباشرة."],"wordsMeanings":[{"word":"فَتَخَطَّى","meaning":" قَطَع الصفوف حال جلوس الناس."},{"word":"حُجَر","meaning":" جمع حُجْرة، اسم للمنزل."},{"word":"فَفَزِعَ","meaning":" خاف الناس؛ لأنه خالف عادته؛ لأنَّ عادته أن يمشي بتأن."},{"word":"يَحْبِسَنِي","meaning":" يشغلني التفكير فيه عن التوجه والإقبال على الله -تعالى-."},{"word":"التِبر","meaning":" الذهب والفضة قبل أن يضربا دنانير ودراهم، ويطلق على الذهب تغليبًا، كما يطلق على غيره من المعادن."}],"category":"da3wah","bookId":"bukhari","tags":["ذكرتُ","شيئًا","تبر","عندنا","فكرهت","يحبسني،"],"source":"hadeethenc"},{"id":"he_3517","text":"عن أبي موسى الأشعري رضي الله عنه قال: دخلتُ عَلى النَبيِّ -صلَّى الله عليه وسلَّم- أنَا ورجلاَن مِنْ بَنِي عَمِّي، فَقَال أحدهما: يا رسول الله، أمرنا على بعض ما ولاك الله عز وجل وقال الآخر مثل ذلك، فقال: «إِنَّا وَالله لاَ نُوَلِّي هَذَا العَمَلَ أَحَدًا سَأَلَهُ، أَو أَحَدًا حَرِصَ عَلَيهِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"الحديث في النهي عن تولية من طلب الإمارة أو حرص عليها، فالنبيُّ -صلَّى الله عليه وسلَّم- لما سأله الرجلان أن يؤمرهما على بعض ما ولاه الله عليه، قال: \"إنا والله لا نولى هذا الأمر أحدًا سأله أو أحدًا حرص عليه\"، يعني لا نولي الإمارة أحدًا سأل أن يتأمَّر على شيء، أو أحدًا حرص عليه؛ وذلك لأنَّ الَّذِي يطلب أو يحرص على ذلك، ربما يكون غرضه بهذا أن يجعل لنفسه سلطة، لا أن يصلح الخلق، فلمَّا كان قد يُتهم بهذه التهمة مَنع النبي صلى الله عليه وسلم أن يُولَّى من طلب الإمارة، وقال: \"إنا والله لا نولي هذا الأمر أحدا سأله أو أحدا حرص عليه\". \nوقد أكَّد موضوع هذا الحديث حديث عبد الرحمن بن سمرة رضي الله عنه أنَّ النبيَّ -صلَّى الله عليه وسلَّم- قال: \"لا تسأل الإمارة؛ فإنك إن أعطيتها عن غير مسألة أعنت عليها، وإن أعطيتها عن مسألة وكلت إليها\". \nفلا ينبغي لولي الأمر إذا سأله أحد أن يؤمره على بلد أو على قطعة من الأرض فيها بادية أو ما أشبه ذلك، حتى وإن كان الطالب أهلًا لذلك؛ وكذلك أيضًا لو أن أحدًا سأل القضاء، فقال لولي الأمر في القضاء كوزير العدل مثلا: ولِّنِي القضاء في البلد الفلاني فإنه لا يولى، وأما من طلب النقل من بلد إلى بلد أو ما أشبه ذلك فلا يدخل في هذا الحديث؛ لأنَّه قد تولى من قبل، ولكنه طلب أن يكون في محل آخر، إلا إذا علمنا أن نيته وقصده هي السلطة على أهل هذه البلدة فإننا نمنعه؛ فالأعمال بالنيات. \nفإن قال قائل كيف تجيبون عن قول يوسف -عليه الصلاة والسلام- للعزيز: \"اجعلني على خزائن الأرض إني حفيظ عليم\". \nفإننا نجيب بأحد جوابين:\nالأول: أن يُقال إن شرع من قبلنا إذا خالفه شرعنا فالعمدة على شرعنا، بناءً على القاعدة المعروفة عند الأصوليين \"شرع من قبلنا شرعٌ لنا ما لم يرد شرعنا بخلافه\"، وقد ورد شرعنا بخلافه: أننا لا نولي الأمر أحدًا طلب الولاية عليه. \nالثاني: أن يقال: إن يوسف -عليه الصلاة والسلام- رأى أن المال ضائعٌ، وأنَّه يُفرِّط فيه ويُلعب فيه؛ فأراد أن ينقذ البلاد من هذا التلاعب، ومثل هذا يكون الغرض منه إزالة سوء التدبير وسوء العمل، ويكون هذا لا بأس به، فمثلا إذا رأينا أميرًا في ناحية لكنَّه قد أضاع الإمرة وأفسد الخلق، فللصالح لهذا الأمر، إذا لم يجد أحدا غيره، أن يطلب من ولي الأمر أن يوليه على هذه الناحية، فيقول له: ولني هذه البلدة؛ لأجل دفع الشر الذي فيها، ويكون هذا لا بأس به متفقا مع القواعد.\nوحديث عثمان بن أبي العاص أنه قال للنبي صلى الله عليه وسلم : اجعلني إمام قومي يعني في الصلاة، فقال: \"أنت إمامهم\"، قال بعض العلماء: الحديث يدل على جواز طلب الإمامة في الخير، وقد ورد في أدعية عباد الرحمن الذين وصفهم الله بتلك أنهم يقولون: {واجعلنا للمتقين إماماً} وليس من طلب الرياسة المكروهة؛ فإن ذلك فيما يتعلق برياسة الدنيا التي لا يعان من طلبها، ولا يستحق أن يعطاها.","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الدمام، الطبعة: الأولى 1415هـ.\nرياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق ماهر الفحل، دار ابن كثير، دمشق، بيروت، الطبعة: الأولى 1428هـ، 2007م.\nرياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بيروت، الطبعة: الرابعة ","benefits":["لا يجوز للخليفة أن يُولِّي أحدًا منصبًا طلبه أو حرص عليه؛ لأن ذلك مشعر بأنه يريده غالبا لنفع نفسه أو عشيرته، وليس لمصلحة الأمة.","ينبغي على الخليفة أن يختار الأكفاء الأتقياء لاستعمالهم على الولايات العامة؛ ليكونوا عونا له على إقامة العدل، وتطبيق شرع الله في الأمة، ونشر الأمن والأمان بين الناس."],"wordsMeanings":[{"word":"مِنْ بَنِي عَمِّي","meaning":" من الأشعريين."},{"word":"أَمِّرْنَا","meaning":" اجعلنا أمراء."},{"word":"هَذَا العَمَلَ","meaning":" إمارة المسلمين."},{"word":"حَرِصَ عَلَيهِ","meaning":" رغب به واهتم اهتمامًا شديدًا، وأظهر ذلك بطلبه."}],"category":"da3wah","tags":["إنا","والله","نولي","هذا","العمل","أحدا"],"source":"hadeethenc"},{"id":"he_3532","text":"أنَّ عَائِذَ بن عَمْرو رضي الله عنه دَخَل على عُبَيد الله بن زياد، فقال: أي بُنَيَّ، إِنِّي سَمِعت رَسُول الله صلى الله عليه وسلم يقول: «إِنَّ شَرَّ الرِّعَاءِ الحُطَمَةُ» فَإِيَّاك أَن تَكُون مِنهُم، فقال له: اجْلِس فَإِنَّما أَنْت مِن نُخَالَةِ أَصحَاب محمَّد صلى الله عليه وسلم فقال: وهل كَانَت لَهُم نُخَالَة؟! إِنَّمَا كَانَت النُخَالَة بَعدَهُم وَفِي غَيرِهِم.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"دخل عائذ بن عمرو رضي الله عنه على عبيد الله بن زياد وهو أمير العراقين بعد أبيه، فقال: \"إني سمعت رسول الله يقول: إن شرّ الرعاءالحطمة\"، والحُطَمَة: هو العنيف برعاية الإبل في السوق والإيراد والإصدار، ويلقي بعضها على بعض ويعسفها، ضَرَبَه مثلاً لوالي السوء، والمراد منه اللفظ القاسي الذي يظلمهم ولا يرق لهم ولا يرحمهم.\nوقوله: (فإياك أن تكون منهم) من كلام عائذ نصيحةً لابن زياد.\nفما كان من ابن زياد إلاَّ أن أجابه: (إنما أنت من نخالتهم)، يعني لست من فضلائهم وعلمائهم وأهل المراتب منهم بل من سَقَطِهم، والنخالة هنا استعارة من نخالة الدقيق، وهي قشوره، والنخالة والحقالة والحثالة بمعنى واحد، قوله.\nفردَّ عليه الصحابي الجليل رضي الله عنه : (وهل كانت لهم نخالة؟! إنما كانت النخالة بعدهم وفي غيرهم)، هذا من جزل الكلام وفصيحه وصدقه الذي ينقاد له كل مسلم؛ فإِنَّ الصحابة رضي الله عنهم كلهم هم صفوة الناس، وسادات الأمة، وأفضل ممن بعدهم، وكلهم عدول قدوة، لا نخالة فيهم، وإنما جاء التخليط ممن بعدهم وفيمن بعدهم.","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الدمام، الطبعة: الأولى 1415هـ.\nتطريز رياض الصالحين، فيصل بن عبد العزيز المبارك، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة للنشر والتوزيع، الرياض، الطبعة: الأولى 1423هـ، 2002م.\nدليل الفالحين لطرق رياض الصالحين، محمد علي بن البكري بن علان، اعتنى بها: خليل مأمون شيحا، دار المعرفة، بيروت، الطبعة: الرابعة 1425هـ.\nرياض الصالحي","benefits":["استحباب نصح الرجل لأبنائه.","أمر الأمراء بالمعروف، ونهيهم عن المنكر برفق.","مشروعية نصيحة الأمراء.","التزام الصحابة -رضي الله عنهم- بالأمر بالمعروف والنهي عن المنكر.","أنه لا يجوز للإنسان الذي ولاه الله -تعالى- على أمر من أمور المسلمين أن يكون عنيفًا عليهم؛ بل يكون رفيقًا بهم.","إصلاح الأمة وصلاحها يكون بِقَوْدِهَا إلى الطريق القويم باللين.","خير الناس للناس من كان هيِّناً ليِّناً.","وجوب الرفق بمن ولاه الله عليهم بحيث يرفق بهم في قضاء حوائجهم وغير ذلك، مع كونه يستعمل الحزم والقوة والنشاط، يعني لا يكون لينًا مع ضعف، ولكن لينًا بحزمٍ وقوةٍ ونشاطٍ.","جُرْأَة عائذ بن عمرو -رضي الله عنه- في الرد على عبيد الله بن زياد، وبيانه له أنَّ الصحابة كلهم سادة وأفاضل، ولم يعرف السقط والنخالة إلا بعد قرنهم.","فضل الصحابة -رضي الله عنهم-."],"wordsMeanings":[{"word":"الرِّعَاءِ","meaning":" جمع راع."},{"word":"الحُطَمَة","meaning":" أي: العنيف في رعيته، لا يرفِق بها في سوقها ومرعاها، بل يحطمها في ذلك وفي سقيها، ويزحم بعضها ببعض بحيث يؤذيها."},{"word":"النُخَالَة","meaning":" ما بقي في الغِربال بعد نَخْل الدقيق، والمراد: ليست من فضلائهم وعلمائهم وأهل المراتب منهم، بل من سَقَطهم."}],"category":"da3wah","bookId":"muslim","tags":["بني،","إني","سمعت","رسول","الله","صلى"],"source":"hadeethenc"},{"id":"he_6180","text":"عن أنس بن مالك رضي الله عنه قال: كَانَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَحْسَنَ النَّاسِ خُلُقًا.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبيُّ صلى الله عليه وسلم أكملَ الناس خُلُقًا، وله السَّبْقُ في جميع الأخلاق والمحاسن، من طِيْبِ الكلام، وبذلِ الخير، وطَلَاقة الوجه، وكَفِّ الأذى واحتمالِهِ من الآخرين.","reference":"صحيح البخاري (8/ 45) (6203).\nصحيح مسلم (4/ 1805) (2310).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 670).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخِن وغيره (1/ 524).\nكنوز رياض الصالحين، لمجموعة من الباحثين (9/ 57).\nشرح رياض الصالحين، لابن عثيمين (3/ 556).","benefits":["كمال خُلق النبي صلى الله عليه وسلم.","النبي صلى الله عليه وسلم هو القدوة الكاملة في حسن الخُلُق.","الحث على التأسي بالنبي صلى الله عليه وسلم في حسن خُلُقه."],"wordsMeanings":[],"category":"sirah","tags":["كان","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_8265","text":"قال سعد بن هشام بن عامر -عندما دخل على عائشة رضي الله عنها-: يَا أُمَّ الْمُؤْمِنِينَ، أَنْبِئِينِي عَنْ خُلُقِ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، قَالَتْ: أَلَسْتَ تَقْرَأُ الْقُرْآنَ؟ قُلْتُ: بَلَى، قَالَتْ: فَإِنَّ خُلُقَ نَبِيِّ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَانَ الْقُرْآنَ.","attribution":"رواه مسلم في جملة حديثٍ طويلٍ","grade":"صحيح","gradeKey":"sahih","explanation":"سُئِلتْ أمُّ المؤمنين عائشة رضي الله عنها عن خُلُقِ النبيِّ صلى الله عليه وسلم، فأجابتْ بكلمةٍ جامعةٍ، وأحالتْ السائلَ على القرآنِ الكريم الجامع لكلِّ صفات الكمال، فقالت كان صلى الله عليه وسلم يَتَخَلَّقُ بأخلاق القرآن، ما أَمَرَ به القرآنُ قام به، وما نهى عنه القرآن اجتَنَبَه، فكان خُلُقُه العملَ به، والوقوفَ عند حدودِه، والتأدُّب بآدابِه، والاعتبارَ بأمثاله وقصصه.","reference":"صحيح مسلم (1/ 512) (746).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (3/ 308).\nشرح رياض الصالحين، لابن عثيمين (6/ 660).\nنزهة المتقين شرح رياض الصالحين، لمصطفى الخن وغيره (2/ 1253).\nكنوز رياض الصالحين، لمجموعة من الباحثين (21/ 556).","benefits":["الحثُّ على التأسّي بالنبي صلى الله عليه وسلم في تَخَلُّقِهِ بأخلاق القرآن.","مدح أخلاق رسول الله صلى الله عليه وسلم، وأنها كانت من مِشْكَاة الوحي.","القرآن مَصدرٌ لكل الأخلاق الكريمة.","الأخلاق في الإسلام تشمل الدينَ كلَّه بفعل الأوامر واجتناب النواهي."],"wordsMeanings":[],"category":"sirah","bookId":"muslim","tags":["فإن","خلق","نبي","الله","صلى","الله"],"source":"hadeethenc"},{"id":"he_3018","text":"عَنْ عَائِشَةَ أُمِّ المُؤمنينَ رضي الله عنها قَالَتْ: كَانَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ التَّيَمُّنُ، فِي تَنَعُّلِهِ، وَتَرَجُّلِهِ، وَطُهُورِهِ، وَفِي شَأْنِهِ كُلِّهِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كانَ النبيُّ صلى الله عليه وسلم يحبُّ ويفضِّل أن يبدأ باليمين في أموره اللائقة بالتكريم، ومن ذلك:\nأن يبدأ بالرِّجْل اليمين في لبس نعله، ويبدأ باليمين في ترجيل شعر رأسه ولحيته وتسريحِهما ودَهنِهما، وفي وضوئه يقدِّم اليمين على اليسار من اليدين والرجلين.","reference":"صحيح البخاري (1/ 45) (168).\nصحيح مسلم (1/ 226) (268).","benefits":["قال النووي: هذه قاعدة مستمرة في الشرع، وهي أنَّ ما كان من باب التكريم والتشريف كلبس الثوب والسراويل والخُفِّ ودُخول المسجد والسواك والاكتحال، وتقليم الأظفار، وقص الشارب، وتَرْجِيْل الشَّعَرِ وهو مَشْطُه، ونتف الإبط، وحلق الرأس، والسلام من الصلاة، وغسل أعضاء الطهارة، والخروج من الخلاء، والأكل والشرب، والمصافحة، واستلام الحجر الأسود، وغير ذلك مما هو في معناه يستحب التيامن فيه، وأما ما كان بضده كدخول الخلاء والخروج من المسجد والامتخاط والاستنجاء وخلع الثوب والسراويل والخف وما أشبه ذلك، فيستحب التياسر فيه، وذلك كله بكرامة اليمين وشرفها.","\"يعجبه التيمن\"، يشمل: الابتداء في الأفعال باليد اليمنى، والرجل اليمنى، والجانب الأيمن،  وتعاطي الشيء باليمين.","قال النووي: اعلم أن من أعضاء الوضوء ما لا يستحب فيه التيامن؛ وهو الأذنان والكفان والخدان بل يُطَهَّران دفعة واحدة، فإن تعذَّر ذلك كما في حق الأقطع ونحوه؛ قَدَّمَ اليمين."],"wordsMeanings":[],"category":"sirah","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3060","text":"عَنْ عَائِشَةَ أُمِّ المُؤْمِنين رَضِيَ اللَّهُ عَنْهَا، قَالَتْ: مَا رَأَيْتُ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ مُسْتَجْمِعًا قَطُّ ضَاحِكًا، حَتَّى أَرَى مِنْهُ لَهَوَاتِهِ، إِنَّمَا كَانَ يَتَبَسَّمُ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَتْ عائشةُ رضي الله عنها أنَّ النبيَّ صلى الله عليه وسلم لم يكن مُبالِغًا في الضحك حتى تُرى لَهَاتُهُ، وهي اللَّحْمَة المُتعلِّقة في أعلى الحَلْق، إنما كان يَتَبَسّم.","reference":"صحيح البخاري (8/ 24) (6092).\nصحيح مسلم (2/ 616) (899).","benefits":["كان رسول الله صلى الله عليه وسلم ضَحِكُهُ التبسم إذا رضي أو أُعْجِب بشيء.","قال ابن حجر: ما رأيته مُستجْمِعًا من جهة الضحك بحيث يضحك ضَحِكًا تامًّا مُقبِلًا بِكُلّيته على الضحك.","كثرة الضحك وارتفاع الصوت بالقهقهة ليس من صفات الصالحين.","كثرة الضحك تُذهِب هيبةَ الرجل ووقارَه بين إخوانه."],"wordsMeanings":[],"category":"sirah","tags":["رأيت","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3062","text":"عَنِ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ: حَفِظْتُ مِنَ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ عَشْرَ رَكَعَاتٍ: رَكْعَتَيْنِ قَبْلَ الظُّهْرِ، وَرَكْعَتَيْنِ بَعْدَهَا، وَرَكْعَتَيْنِ بَعْدَ المَغْرِبِ فِي بَيْتِهِ، وَرَكْعَتَيْنِ بَعْدَ العِشَاءِ فِي بَيْتِهِ، وَرَكْعَتَيْنِ قَبْلَ صَلاَةِ الصُّبْحِ، وَكَانَتْ سَاعَةً لاَ يُدْخَلُ عَلَى النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فِيهَا، حَدَّثَتْنِي حَفْصَةُ أَنَّهُ كَانَ إِذَا أَذَّنَ المُؤَذِّنُ وَطَلَعَ الفَجْرُ صَلَّى رَكْعَتَيْنِ، وَفِي لَفْظٍ: أَنَّ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ.","attribution":"متفق عليه بجميع رواياته","grade":"صحيح","gradeKey":"sahih","explanation":"يُبَيِّنُ عبدُ الله بن عمر رضي الله عنهما: أنَّ مِن النوافل التي حفظها عن النبي صلى الله عليه وسلم عشر ركعات وتسمى السنن الرواتب، \nركعتين قبل الظهر، وركعتين بعدها، \nوركعتين بعد المغرب في بيتِه، \nوركعتين بعد العشاء في بيتِه، \nوقبل الفجر ركعتين، \nفتمَّتْ عشر ركعات. \nوأما صلاة الجمعة فيصلي بعدها ركعتين.","reference":"صحيح البخاري (2/ 58-59) (1180، 1181).\nصحيح مسلم (2/ 601) (882).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص112).","benefits":["استحباب هذه الرواتب، والمواظبة عليها.","مشروعية أداء السنة في البيت."],"wordsMeanings":[],"category":"sirah","tags":["حفظت","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3063","text":"عَنْ حُذَيْفَةَ رضي الله عنه قَالَ: كَانَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنَ اللَّيْلِ يَشُوصُ فَاهُ بِالسِّوَاكِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كانَ النبيُّ صلى الله عليه وسلم كثيرًا ما يَستاك ويأمر به، وهو يتأكد في بعض الأوقات، منها: الاستياكُ عند القيام من الليل، حيث كان صلى الله عليه وسلم يَدلُك وينقِّي فاه بالسواك.","reference":"صحيح البخاري (1/ 58) (245).\nصحيح مسلم (1/ 220) (255).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص47).\nخلاصة الكلام شرح عمدة الأحكام، لفيصل آل مبارك (ص24).","benefits":["تأكيد مشروعية السواك بعد نوم الليل، وذلك أنَّ النوم مُقتَضٍ لتَغَيُّر رائحة الفم، والسواك هو آلة تنظيفية.","تأكيد مشروعية السواك عند كل تَغَيُّرٍ كريهٍ للفم، أخذًا من المعنى السابق.","مشروعية النظافة على وجه العموم، وأنها من سنة النبي صلى الله عليه وسلم، ومن الآداب السامية.","التسوُّك في الفم كلِّه يشمل: الأسنان، واللثة، واللسان.","السواك هو عُودٌ يُقطَع من شجرة الأراك أو غيرها، ويُستخدم في تنظيف الفم والأسنان، ويطيِّب الفم، ويُزيل الروائح الكريهة."],"wordsMeanings":[],"category":"sirah","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3110","text":"عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ: قَالَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: «أَلاَ أُحَدِّثُكُمْ حَدِيثًا عَنِ الدَّجَّالِ، مَا حَدَّثَ بِهِ نَبِيٌّ قَوْمَهُ؟ إِنَّهُ أَعْوَرُ، وَإِنَّهُ يَجِيءُ مَعَهُ بِمِثَالِ الجَنَّةِ وَالنَّارِ، فَالَّتِي يَقُولُ إِنَّهَا الجَنَّةُ هِيَ النَّارُ، وَإِنِّي أُنْذِرُكُمْ كَمَا أَنْذَرَ بِهِ نُوحٌ قَوْمَهُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخبِرُ النبيُّ صلى الله عليه وسلم أصحابه عن الدجال وصفاته وعلاماته بما لم يحدِّث به نبي قبله، فمن ذلك:\n\n أنه أعور العين.\n\nوأن الله تعالى جعل معه مثل الجنة والنار، بحسب رؤيا العين.\n\n لكن جنته نار، وناره جنة، من أطاعه أدخله هذه الجنة فيما يرى الناس، ولكنها نار محرقة، ومن عصاه أدخله النار فيما يراه الناس، ولكنها جنة طيبة، \nثم حذرنا النبي صلى الله عليه وسلم من فتنته كما حذّر به نوح قومه.","reference":"صحيح البخاري (4/ 134) (3338).\nصحيح مسلم (4/ 2250) (2936).","benefits":["عظم فتنة الدجال.","النجاة من فتنة الدجال تكون بصدق الإيمان واللجوء إلى الله تعالى والاستعاذة بالله منه في التشهد الأخير، وحفظ عشر آيات من أول سورة الكهف.","شدة حرص النبي صلى الله عليه وسلم على أمته، حيث بين للمسلمين من صفات الدجال ما لم يبينه نبي قبله."],"wordsMeanings":[],"category":"sirah","tags":["ألا","أحدثكم","حديثا","الدجال،","حدث","نبي"],"source":"hadeethenc"},{"id":"he_3145","text":"عَنْ زَيْنَبَ بِنْتِ جَحْشٍ رَضِيَ اللَّهُ عَنْها أَنَّ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا فَزِعًا يَقُولُ: «لاَ إِلَهَ إِلَّا اللَّهُ، وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدِ اقْتَرَبَ، فُتِحَ اليَوْمَ مِنْ رَدْمِ يَأْجُوجَ وَمَأْجُوجَ مِثْلُ هَذِهِ» وَحَلَّقَ بِإِصْبَعِهِ الإِبْهَامِ وَالَّتِي تَلِيهَا، قَالَتْ زَيْنَبُ بِنْتُ جَحْشٍ فَقُلْتُ يَا رَسُولَ اللَّهِ: أَنَهْلِكُ وَفِينَا الصَّالِحُونَ؟ قَالَ: «نَعَمْ إِذَا كَثُرَ الخَبَثُ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"دَخَلَ النبيُّ صلى الله عليه وسلم على زينب بنت جَحْش رضي الله عنها فَزِعًا خائفًا، وهو يقول: لا إله إلا الله، إيذانًا بتوقُّع أمرٍ مكروهٍ يَحْدُث، ولا نجاة منه إلا بالالتجاء إلى الله سبحانه، ثم قال صلى الله عليه وسلم: \nويل للعرب من شر قد اقترب وقوعُه، فُتِح اليوم من رَدم يأجوج ومأجوج، وهو السَّدُّ الذي بناه ذو القرنين، مثل هذه، وحَلَّق بإصبعه الإبهام والتي تليها، \nفقالت زينب رضي الله عنها: كيف يُسلِّط الله علينا الهلاك وفينا المؤمنون الصالحون؟ \nفقال لها النبي صلى الله عليه وسلم: إذا كَثُرَ الخَبَث مِن الفسوق والفجور والمعاصي، والزنا، والخمور، وغيرها، عَمَّ الهلاكُ الجميع.","reference":"صحيح البخاري (4/ 138) (3346).\nصحيح مسلم (4/ 2208) (2880).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (1/ 280).\nكنوز رياض الصالحين، لمجموعة من الباحثين (4/ 54).\nشرح رياض الصالحين، لابن عثيمين (2/ 437).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 212).","benefits":["الفَزَع لا يشغل قلبَ المؤمن عن ذكر الله عند الخوف؛ لأنه بذكر الله تطمئن القلوب.","الحث على إنكار المعاصي ومنع وقوعها.","يحصل الهلاك العامُّ بسبب كثرة المعاصي وانتشارها وعدم إنكارها وإن كثر الصالحون.","المصائب تعمُّ الناس جميعًا صالحين وفاسدين، ولكنهم يُبعَثون على نيّاتهم.","خصَّ العربَ في قوله: \"وَيْلٌ لِلْعَرَبِ مِنْ شَرٍّ قَدِ اقْتَرَبَ\"؛ لأنهم مُعظم مَن أَسْلَم حين قال ذلك."],"wordsMeanings":[{"word":"يَأْجُوجَ ومَأجُوجَ","meaning":" اسم لقبيلتين من العجم، وهم من بني آدم، يظهرون آخر الزمان ويفسدون في الأرض، ويكون ظهورهم من علامات قُرب يوم القيامة."}],"category":"sirah","tags":["إله","إلا","الله،","ويل","للعرب","اقترب،"],"source":"hadeethenc"},{"id":"he_3153","text":"عَنْ أَبِي سَعِيدٍ الخُدْرِيِّ رضي الله عنه قَالَ: كَانَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ حَيَاءً مِنَ العَذْرَاءِ فِي خِدْرِهَا، فَإِذَا رَأَى شَيْئًا يَكْرَهُهُ عَرَفْنَاهُ فِي وَجْهِهِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يُخْبِرُ أبو سعيد الخدري رضي الله عنه أنَّ النبيَّ صلى الله عليه وسلم كان أشدَّ حياء من البنت البِكْر التي لم تتزوج وتعاشر الرجال المُستترة في بيتها، ومن شدة حيائه أنه إذا كَرِهَ شيئًا يتغير وجهه ولا يتكلم، بل يفهم أصحابه كراهيتَه لذلك في وجهه.","reference":"صحيح البخاري (8/ 26) (6102).\nصحيح مسلم (4/ 1809) (2320).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 11).\nشرح رياض الصالحين، لابن عثيمين (4/ 32).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 562).","benefits":["بيان ما اشتمل عليه النبي صلى الله عليه وسلم من الحياء، وهو الخُلُق العظيم.","حياء النبيِّ صلى الله عليه وسلم ما لم تُنتَهك حرمات الله، فإذا انتهكت؛ فإنه صلى الله عليه وسلم كان يغضب ويأمر أصحابَه وينهاهم.","الحث على التخلُّق بالحياء؛ لأنه يحمل النفس على فعل الجميل وترك القبيح."],"wordsMeanings":[{"word":"العَذْرَاء","meaning":" البكر، وهي الأنثى التي لم يمسها رجل، سميت به لبقاء عذرتها، وهي ما يكون من التحام في فم الرحم."},{"word":"الخِدْر","meaning":" ناحية في البيت يترك عليها ستر."}],"category":"sirah","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3177","text":"عن الْبَرَاء بْن عَازِبٍ رضي الله عنهما «أن النبي صلى الله عليه وسلم كان في سفر، فصلى العشاء الآخِرَةَ، فقرأ في إحدى الركعتين بِالتِّينِ وَالزَّيْتُون فما سمعت أحدًا أحسن صوتًا أو قراءة منه».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"قرأ النبي صلى الله عليه وسلم بسورة التين والزيتون في الركعة الأولى في صلاة العِشاء؛ لأنه كان في سفر، والسفر يراعى فيه التخفيف والتسهيل؛ لمشقته وعنائه، ومع كون النبي صلى الله عليه وسلم مسافرًا، فإنه لم يترك ما يبعث على الخشوع وإحضار القلب عند سماع القرآن، وهو تحسين الصوت في قراءة الصلاة.","reference":"تيسير العلام شرح عمدة الأحكام، عبد الله بن عبد الرحمن البسام، تحقيق: محمد صبحي حلاق، مكتبة الصحابة، الإمارات، مكتبة التابعين، القاهرة، الطبعة: العاشرة 1426هـ.\nتنبيه الأفهام شرح عمدة الأحكام، محمد بن صالح العثيمين، مكتبة الصحابة، الإمارات، الطبعة: الأولى، 1426هـ.\nالإلمام بشرح عمدة الأحكام، إسماعيل بن محمد الأنصاري، دار الفكر، دمشق، الطبعة: الأولى، 1381هـ.\nصحيح البخاري، محمد بن إسماعيل البخاري الجعف","benefits":["جواز قراءة قصار المُفَصَّل في صلاة العشاء.","أن الأحسن تخفيف الصلاة في السفر، ومراعاة حال المسافرين، ولو كان عند الإمام رغبة في التطويل.","استحباب تحسين الصوت في القراءة، ومن ذلك القراءة في الصلاة؛ لأنه يبعث على الخشوع والحضور.","الجهر في صلاة العشاء."],"wordsMeanings":[{"word":"إحدى الركعتين","meaning":" هي الأولى كما رواه النسائي."},{"word":"بالتين والزيتون","meaning":" سورة التين والزيتون."},{"word":"أحسن صوتًا أو قراءةً","meaning":" أو يحتمل أنها للشك من الراوي؛ فيكون الحسن إما في الصوت أو القراءة، ويحتمل أنها للتنويع، أي: أحسن صوتا وقراءة؛ فيكون الحسن في كليهما."}],"category":"sirah","tags":["النبي","صلى","الله","عليه","وسلم","كان"],"source":"hadeethenc"},{"id":"he_3220","text":"عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَ رضي الله عنه: أَنَّ النَّبِيَّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى فَرَّجَ بَيْنَ يَدَيْهِ حَتَّى يَبْدُوَ بَيَاضُ إِبْطَيْهِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كَانَ صلى الله عليه وسلم إذا سجد فرَّج بين يديه أثناء السجود؛ فنحَّى كلَّ يد عن الجنب الذي يليها، مثل الجناحين، حتى يبدو لون جلد إبطيه؛ \nوهذا من المبالغة في تجنيح الذراعين ومباعدتهما عن جانبيه.","reference":"صحيح البخاري (1/ 87) (390).\nصحيح مسلم (1/ 356) (495).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص162).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (2/ 207).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (1/ 134).","benefits":["استحباب هذه الهيئة في السجود، وهي مباعدة عَضُديه عن جنبيه.","المأموم الذي يتأذَّى جارُه بالمجافاة؛ فلا يُشرع له ذلك.","في المجافاة في السجود حِكم وفوائد كثيرة، منها: إظهار النشاط والرغبة في الصلاة، وأنه إذا اعتمد على كل أعضاء السجود أخذ كل عضو حقه من العبادة. وقيل: الحكمة في ذلك أنه أشبه بالتواضع، وأبلغ في تمكين الجبهة والأنف من الأرض، وأيضًا ليتميز كل عضو بنفسه."],"wordsMeanings":[],"category":"sirah","tags":["النبي","صلى","الله","عليه","وسلم","كان"],"source":"hadeethenc"},{"id":"he_3306","text":"عن أنس بن مالك رضي الله عنه قال: لمَّا ثَقُل النبي صلى الله عليه وسلم جَعَل يَتَغَشَّاه الكَرب، فقالت فاطمة رضي الله عنها : واكَربَ أَبَتَاه، فقال: «لَيسَ عَلَى أَبِيك كَرب بعد اليوم». فلما مات، قالت: يا أَبَتَاه، أجاب ربًّا دَعَاه! يا أبَتَاه، جَنَّة الفِردَوس مَأوَاه! يا أبتاه، إلى جبريل نَنعَاه! فلمَّا دُفِن قالت فاطمة رضي الله عنها : أَطَابَت أَنفُسُكُم أَن تَحثُوا عَلَى رسُولِ الله صلى الله عليه وسلم التُّراب؟!","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"يُصوِّر هذا الحديث صبر نبينا صلى الله عليه وسلم على سكرات الموت، فلمَّا ثقل في مرضه الذي مات فيه جعل يغشى عليه من الكرب من شدة ما يصيبه؛ لأنه -عليه الصلاة والسلام- يتشدد عليه الألم والمرض، وهذا لحكمة بالغة: حتى ينال ما عند الله من الدرجات العلى جزاء صبره، فإذا غشيه الكرب تقول فاطمة رضي الله عنها : \"وأكرب أبتاه\" تتوجع له من كربه، لأنها امرأة، والمرأة لا تطيق الصبر.\nفقال النبي -عليه الصلاة والسلام-: \"لا كرب على أبيك بعد اليوم\"؛ لأنه صلى الله عليه وسلم لما انتقل من الدنيا انتقل إلى الرفيق الأعلى، كما كان -صلى الله عليه وسلم -وهو يغشاه الموت- يقول \"اللهم في الرفيق الأعلى، اللهم في الرفيق الأعلى وينظر إلى سقف البيت صلى الله عليه وسلم \".\nتوفي الرسول -عليه الصلاة والسلام-، فجعلت رضي الله عنها تندبه، لكنه ندب خفيف، لا يدل على التسخط من قضاء الله وقدره.\nوقولها \"أجاب ربا دعاه\"؛ لأن الله تعالى هو الذي بيده ملكوت كل شيء، وآجال الخلق بيده.\nفأجاب داعي الله، وهو أنه صلى الله عليه وسلم إذا توفي صار كغيره من المؤمنين، يصعد بروحه حتى توقف بين يدي الله سبحانه فوق السماء السابعة. \nوقولها: \"وابتاه جنة الفردوس مأواه\" صلى الله عليه وسلم ؛ لأنه -عليه الصلاة والسلام- أعلى الخلق منزلة في الجنة، كما قال النبي صلى الله عليه وسلم : \"اسألوا الله لي الوسيلة؛ فإنها منزلة في الجنة لا تنبغي إلا لعبد من عباد الله، وأرجو أن أكون أنا هو\"، ولا شك أن النبي صلى الله عليه وسلم مأواه جنة الفردوس، وجنة الفردوس هي أعلي درجات الجنة، وسقفها الذي فوقها عرش الرب جل جلاله، والنبي -عليه الصلاة والسلام- في أعلى الدرجات منها.\nقولها: \"يا أبتاه إلى جبريل ننعاه\" وقالت: إننا نخبر بموته جبريل لأن جبريل هو الذي كان يأتيه ويدارسه بالوحي زمن حياته، والوحي مرتبط بحياة النبي -عليه الصلاة والسلام-.\nثمَّ لمَّا حُمِل ودفِن، قالت رضي الله عنها : \"أطابت أنفسكم أن تحثوا على رسول الله صلى الله عليه وسلم التراب؟\" يعني من شدة حزنها عليه، وحزنها وألمها على فِراق والدها، ومعرفتها بأن الصحابة رضي الله عنهم قد ملأ الله قلوبهم محبة الرسول -عليه الصلاة والسلام- سألتهم هذا السؤال، لكن الله سبحانه هو الذي له الحكم، وإليه المرجع، وكما قال الله تعالى في كتابة: (إِنَّكَ مَيِّتٌ وَإِنَّهُمْ مَيِّتُونَ).","reference":"بهجة الناظرين شرح رياض الصالحين، لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nرياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428 هـ.\nرياض الصالحين، ط4، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بيروت، 1428هـ.\nكنوز رياض الصالحين، مجموعة من الباحثين برئاسة حمد بن ناصر العمار، ط1، كنوز إشبيليا، الرياض، 1430هـ.\nشرح رياض الصالحين، للشيخ","benefits":["في هذا الحديث بيان أن رسول الله -صلى الله عليه وسلم- كغيره من البشر، يمرض ويجوع، ويعطش، ويموت.","في الحديث رد على الذين يشركون بالرسول -صلى الله عليه وسلم-؛ يدعون الرسول -عليه الصلاة والسلام-، ويستغيثون به وهو في قبره، فهو عليه السلام ميت ولا يملك لهم شيئاً.","في الحديث دليل على جواز الندب اليسير إذا لم يكن مؤذنا بالتسخُّط على الله -عز وجل-؛ لأن فاطمة ندَبَت النبي عليه -الصلاة والسلام-، لكنه نَدْب يسير، وليس فيه اعتراض على قدر الله -عز وجل-.","في الحديث دليل: على أن فاطمة بنت محمد -صلى الله عليه وسلم- و -رضي الله عنها- بقيت بعد حياته -صلى الله عليه وسلم-، ولكن ليس لها ميراث؛ لأن الأنبياء لا يورثون.","جواز التوجُّع للميت عند احتضاره.","يجوز ذكر الميت بصفاته بعد موته دون رفع صوت ولا تسخط.","صبر النبي -عليه الصلاة والسلام- على ما هو فيه من سكرات الموت وشدائده.","ما بعد الحياة الدنيا خير للأنبياء -صلوات الله عليهم وسلامه- وكذلك أتباعهم.","الدنيا دار تعب ونصب، والآخرة لا شيء فيها من هذا للمؤمن."],"wordsMeanings":[{"word":"ثَقُل","meaning":" من شدة المرض."},{"word":"يَتَغَشَّاه الكَرب","meaning":" تنزل به الشدة من سكرات الموت، لعلو درجته وشرف رتبته، فإن أشد الناس بلاء الأنبياء."},{"word":"واكَربَ أَبَتَاه","meaning":" أي ما أشد وجع أبي، لم ترفع صوتها -رضي الله عنها- بذلك، كما يفعله بعض النساء عند المصيبة."},{"word":"لَيسَ عَلَى أَبِيك كَرب","meaning":" لا يصيبه نصب ولا وصب يجد له ألما؛ لأنه ينتقل من دار البلاء إلى دار الخلود والصفاء."},{"word":"أجاب ربًّا دَعَاه","meaning":" لبى نداءه، وفيه إشارة إلى ما ثبت عنه -صلى الله عليه وسلم- أنه خُيِّر؛ فاختار جوار ربه ولِقَاه."},{"word":"الفِردَوس","meaning":" بستان يجمع كل ما في البساتين من شجر وزهر، وجنة الفردوس أعلى الجنان."},{"word":"مَأوَاه","meaning":" منزله."},{"word":"نَنعَاه","meaning":" نرفع خبر وفاته -صلى الله عليه وسلم- إلى جبريل."},{"word":"جبريل","meaning":" هو اسم خاص لملك كريم خصَّه الله -تعالى- بالوحي."},{"word":"تحثوا","meaning":" حثو التراب: دفعه باليد، والمراد دفنه عليه -صلى الله عليه وسلم- بالتراب."}],"category":"sirah","bookId":"bukhari","tags":["ليس","على","أبيك","كرب","بعد","اليوم"],"source":"hadeethenc"},{"id":"he_3317","text":"عن أبي هريرة رضي الله عنه قال: كان رسولُ الله صلى الله عليه وسلم إذا عَطَس وضَعَ يَدَه -أو ثوبَهُ- على فيهِ، وخَفَضَ -أو غضَّ- بها صوتَهُ.","attribution":"رواه أبو داود والترمذي وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"كان صلى الله عليه وسلم إذا عَطَس:\n\nأولًا: يضع يدَه، أو ثوبَه على فيه؛ لئلا يخرج من فيه أو أنفه شيء يؤذي جليسَه. \n\nثانيًا: يخفض صوته ولا يرفعه.","reference":"سنن أبي داود (7/ 375) (5029).\nسنن الترمذي (4/ 461) (2745).\nمسند أحمد (15/ 412) 9662).\nشرح رياض الصالحين، لابن عثيمين (4/ 440).\nتطريز رياض الصالحين، لفيصل آل مبارك (ص528).\nبهجة الناظرين، لسليم الهلالي (2/ 149).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (1/ 678).\nكنوز رياض الصالحين لمجموعة من الباحثين (11/ 432).","benefits":["بيان هديه صلى الله عليه وسلم في العطاس والاقتداء به في ذلك.","استحباب وضع الثوب أو منديل ونحوه على فمه وأنفه إذا عطس لئلا يخرج منه شيء يؤذي جليسه.","خفض الصوت بالعطاس مطلوب، وهو من كمال الأدب، ومن مكارم الأخلاق."],"wordsMeanings":[],"category":"sirah","bookId":"abudawud","tags":["كان","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_3321","text":"عن عائشة رضي الله عنها قالت: كَانَ كَلاَمُ رَسُولِ الله -صلَّى الله عليه وسلَّم- كَلاَمًا فَصلاً يَفْهَمُهُ كُلُّ مَنْ يَسْمَعُهُ.","attribution":"رواه أبو داود واللفظ له، والتُرمذي والنسائي وأحمد","grade":"حسن","gradeKey":"hasan","explanation":"حديث عائشة رضي الله عنها أنها قالت: إنَّ النبي صلى الله عليه وسلم كان كلامه فصلا، معناه أنه كان مفصلا لا يدخل الحروف بعضها على بعض، ولا الكلمات بعضها على بعض، بيِّن ظاهر لكل من سمعه ليس فيه تعقيد ولا تطويل، حتى لو شاء العاد أن يحصيه لأحصاه من شدة تأنيه صلى الله عليه وسلم في الكلام؛ وهذا لأنَّ النبيَّ -صلَّى الله عليه وسلَّم- أُعْطِيَ جوامع الكلم واختصر له الكلام اختصارا، وجوامع الكلم أن تجمع المعاني الكثيرة في اللفظ القليل.\nوهكذا ينبغي للإنسان أن لا يكون كلامه متداخلا بحيث يخفى على السامع؛ لأن المقصود من الكلام هو إفهام المخاطب، وكلما كان أقرب إلى الإفهام كان أولى وأحسن.\nثم إنه ينبغي للإنسان إذا استعمل هذه الطريقة، يعني إذا جعل كلامه فصلا بينا واضحا، وكرَّره ثلاث مرات لمن لم يفهم، ينبغي أن يستشعر في هذا أنه متبع لرسول الله صلى الله عليه وسلم حتى يحصل له بذلك الأجر وإفهام أخيه المسلم.\nوهكذا جميع السنن اجعل على بالك أنك متبع فيها لرسول صلى الله عليه وسلم حتى يتحقق لك الاتباع وثوابه.","reference":"بهجة الناظرين شرح رياض الصالحين، لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nجامع الترمذي، تحقيق وتعليق: أحمد محمد شاكر وآخرون، ط2، شركة مكتبة ومطبعة مصطفى البابي الحلبي، مصر، 1395هـ.\nتطريز رياض الصالحين، للشيخ فيصل المبارك، ط1، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة، الرياض، 1423هـ.\nدليل الفالحين لطرق رياض الصالحين، لمحمد علي بن محمد بن علان، ط4، اعتنى بها: خليل مأمون شيحا، دار ","benefits":["فصاحة النبي -صلى الله عليه وسلم- ومخاطبته للناس بما يفهمون.","ينبغي على الداعي إلى الله أن يبذل كل جهده ليصل كلامه إلى كل من أحب سماعه.","ينبغي على الداعي إلى الله أن يكون رحيما بالمدعوين في إيصال الحق لهم، وحريصا عليهم، ومهتما بأمرهم أكثر من أمره.","ينبغي على المتحدث أن يُفهِم السامعين حديثه حتى لا يخفى منه شيء على بعضهم، فيفهم ضده وعكسه."],"wordsMeanings":[{"word":"فَصلاً","meaning":" مفصولا بين أجزائه وواضحا، وفاصلا بين الحق والباطل."}],"category":"sirah","bookId":"abudawud","tags":["كان","كلام","رسول","الله","صلى","الله"],"source":"hadeethenc"},{"id":"he_3364","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ: «لَوْلَا أَنْ أَشُقَّ عَلَى الْمُؤْمِنِينَ -أَوْ: عَلَى أُمَّتِي- لَأَمَرْتُهُمْ بِالسِّوَاكِ عِنْدَ كُلِّ صَلَاةٍ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَ النبيُّ صلى الله عليه وسلم أنه لولا خوف المشقة على المؤمنين من أمته لأَوجب عليهم استعمال السواك مع كل صلاة.","reference":"صحيح مسلم (1/ 220) (252).\nصحيح البخاري (2/ 4) (887).\nتيسير العلام شرح عمدة الأحكام، لعبد الله البسام (ص46).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 50).","benefits":["رفق النبي صلى الله عليه وسلم بأمته، ومخافة المشقة عليهم.","الأصل في أَمْرِ النبيِّ صلى الله عليه وسلم الوجوب، إلا أنْ يقومَ الدليل على أنه تطوُّع.","استحباب السواك وفضله عند كل صلاة.","قال ابن دقيق العيد: الحكمة في استحباب السواك عند القيام إلى الصلاة كونها حالَ تقرُّبٍ إلى الله، فاقتضى أن تكون حالَ كمالٍ ونظافة إظهارًا لِشَرَف العبادة.","عموم الحديث يشمل السواك للصائم ولو بعد الزوال، كصلاتَي: الظهر والعصر."],"wordsMeanings":[],"category":"sirah","tags":["لولا","أشق","على","المؤمنين","أو:","على"],"source":"hadeethenc"},{"id":"he_3409","text":"عَنْ سَهْلُ بْنُ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمَ خَيْبَرَ: «لَأُعْطِيَنَّ هَذِهِ الرَّايَةَ غَدًا رَجُلًا يَفْتَحُ اللَّهُ عَلَى يَدَيْهِ، يُحِبُّ اللَّهَ وَرَسُولَهُ وَيُحِبُّهُ اللَّهُ وَرَسُولُهُ»، قَالَ: فَبَاتَ النَّاسُ يَدُوكُونَ لَيْلَتَهُمْ أَيُّهُمْ يُعْطَاهَا، فَلَمَّا أَصْبَحَ النَّاسُ غَدَوْا عَلَى رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ كُلُّهُمْ يَرْجُو أَنْ يُعْطَاهَا، فَقَالَ: «أَيْنَ عَلِيُّ بْنُ أَبِي طَالِبٍ؟» فَقِيلَ: هُوَ يَا رَسُولَ اللَّهِ يَشْتَكِي عَيْنَيْهِ، قَالَ: «فَأَرْسِلُوا إِلَيْهِ»، فَأُتِيَ بِهِ فَبَصَقَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فِي عَيْنَيْهِ وَدَعَا لَهُ، فَبَرَأَ حَتَّى كَأَنْ لَمْ يَكُنْ بِهِ وَجَعٌ، فَأَعْطَاهُ الرَّايَةَ، فَقَالَ عَلِيٌّ: يَا رَسُولَ اللَّهِ، أُقَاتِلُهُمْ حَتَّى يَكُونُوا مِثْلَنَا؟ فَقَالَ: «انْفُذْ عَلَى رِسْلِكَ حَتَّى تَنْزِلَ بِسَاحَتِهِمْ، ثُمَّ ادْعُهُمْ إِلَى الإِسْلاَمِ، وَأَخْبِرْهُمْ بِمَا يَجِبُ عَلَيْهِمْ مِنْ حَقِّ اللَّهِ فِيهِ، فَوَاللَّهِ لَأَنْ يَهْدِيَ اللَّهُ بِكَ رَجُلًا وَاحِدًا، خَيْرٌ لَكَ مِنْ أَنْ يَكُونَ لَكَ حُمْرُ النَّعَمِ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبرَ النبيُّ صلى الله عليه وسلم الصحابة بانتصار المسلمين على يهود خيبر من الغد، وذلك على يد رجل يعطيه الراية وهو العلم الذي يتخذه الجيش شعارًا له، \nوهذا الرجل من صفاته أنه يحب الله ورسوله، ويحبه الله ورسوله، \nفبات الصحابة ليلتهم يخوضون ويتحدثون عمن سيعطى الراية؟ رغبة في هذا الشرف العظيم، \nفلما كان الصبح ذهبوا إلى النبيِّ صلى الله عليه وسلم، كلهم يرجوا أن يفوز بهذا الشرف، \n\nفسأل صلى الله عليه وسلم عن علي بن أبي طالب رضي الله عنه؟ \n\nفقيل: إنه مريض يشتكي عينيه.\n\nفأرسل إليه صلى الله عليه وسلم، فجاؤوا به، فبصق في عيني علي من ريقه الشريف، ودعا له، فشفي من مرضه وكأنه لم يكن به وجع، فأعطاه الراية، وأمره بالمضي برفق حتى يقترب من حصن العدو فيعرض عليهم الدخول في الإسلام، فإن أجابوه؛ أخبرهم بما يجب عليهم من الفرائض.\n\nثم بيَّن صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لعلي فضل الدعوة إلى الله وأن الداعية إذا كان سببًا في هداية رجل واحد فذلك خير له من أن تكون له الإبل الحُمْر التي هي أنفس أموال العرب، فيمتلكها أو يتصدق بها.","reference":"صحيح البخاري (5/ 134) (4210).\nصحيح مسلم (4/ 1872) (2406).\nفتح المجيد شرح كتاب التوحيد، (ص88).\nالقول المفيد على كتاب التوحيد، (1/ 134).\nالملخص في شرح كتاب التوحيد، (ص57).\nالجديد في شرح كتاب التوحيد، (ص67).\nالتمهيد لشرح كتاب التوحيد، (ص59).","benefits":["فضيلة علي بن أبي طالب -رضي الله عنه-، وشهادة رسول -صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ- له، بمحبة الله ورسوله له، ومحبته لله ورسوله.","حرص الصحابة على الخير وتسابقهم إليه.","مشروعية الأدب عند القتال وترك الطيش والأصوات المزعجة التي لا حاجة إليها.","من دلائل نبوته صلى الله عليه وسلم إخباره بالنصر على اليهود، وشفاء عيني علي بن أبي طالب على يديه بإذن الله.","أن المقصود الأعظم من الجهاد هو دخول الناس في الإسلام.","أن الدعوة تكون بالتدريج فيطلب من الكافر أولًا الدخول في الإسلام بالنطق بالشهادتين، ثم يُؤمر بفرائض الإسلام بعد ذلك.","فضل الدعوة إلى الإسلام وما فيها من الخير للمدعو والداعي، فالمدعو قد يهتدي والداعي يُثاب ثوابًا عظيمًا."],"wordsMeanings":[],"category":"sirah","tags":["فوالله","لأن","يهدي","الله","رجلا","واحدا،"],"source":"hadeethenc"},{"id":"he_3443","text":"عن عبد الله بن عمر رضي الله عنهما قال: كان النبي صلى الله عليه وسلم يزورُ قُبَاءَ راكبًا وماشيًا، فيُصَلِّي فيه ركعتين. \nوفي رواية: كان النبي صلى الله عليه وسلم يأتي مسجد قُبَاءَ كل سَبْتٍ راكبًا وماشيًا، وكان ابن عُمر يفعله.","attribution":"الرواية الأولى: متفق عليها.\nالرواية الثانية: متفق عليها","grade":"صحيح","gradeKey":"sahih","explanation":"منطقة قباء التي بُنِيَ بها أول مسجد في الإسلام قرية قريبة من مركز المدينة من عواليها، فكان النبي صلى الله عليه وسلم يزوره راكبا وماشيا، وقوله كل سبت: حيث كان يخصص بعض الأيام بالزيارة \nوالحكمة في مجيئه صلى الله عليه وسلم إلى قباء يوم السبت من كل أسبوع، إنما كان لمواصلة الأنصار وتفقُّد حالهم وحال من تأخَّر منهم عن حضور الجمعة معه، وهذا هو السِر في تخصيص ذلك بالسبت.","reference":"رياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428هـ.\nرياض الصالحين، ط4، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بيروت، 1428هـ.\nشرح رياض الصالحين، للشيخ ابن عثيمين، دار الوطن للنشر، الرياض، 1426هـ.\nفتح الباري شرح صحيح البخاري، للحافظ ابن حجر العسقلاني، قام بإخراجه وصححه وأشرف على طبعه: محب الدين الخطيب، رقم كتبه وأبوابه وأحاديثه: محمد ","benefits":["استحباب زيارة مسجد قباء، وقد صح الخبر عن سيِّد البشر -صلى الله عليه وسلم- أن من خرج من بيته متطهرًا فصلى فيه ركعتين كان كعدل عمرة.","حرص عبد الله بن عمر -رضي الله عنهما- على التأسِّي برسول الله -صلى الله عليه وسلم-."],"wordsMeanings":[{"word":"قُبَاءَ","meaning":" منطقة قباء: قرية كانت على بُعد ميلين من المدينة، وهي الآن داخل المدينة."},{"word":"سبت","meaning":" السبت إما اليوم أي: كل يوم سبت، وهو الأقرب، أو الأسبوع، أي: أسبوعيًا."}],"category":"sirah","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_3446","text":"عن ابن شماسة المهري قال: حَضَرنَا عَمرو بن العاص رضي الله عنه وهُو فِي سِيَاقَةِ الْمَوتِ، فَبَكَى طَوِيلاً، وَحَوَّلَ وَجهَهُ إِلَى الجِدَارِ، فَجَعَلَ ابنَهُ، يقول: يَا أَبَتَاهُ، أَمَا بَشَّرَكَ رسُول الله -صلَّى الله عليه وسلَّم- بكَذَا؟ أمَا بشَّركَ رسول الله -صلَّى الله عليه وسلَّم- بِكَذَا؟ فَأَقبَلَ بِوَجهِهِ، فقَالَ: إِنَّ أَفضَلَ مَا نُعِدُّ شَهَادَةُ أَنْ لاَ إِلَهَ إِلاَّ الله، وَأَنَّ مُحَمَّدًا رسولُ الله، إِنِّي قَدْ كُنتُ عَلَى أَطْبَاقٍ ثَلاَثٍ: لَقَدْ رَأَيتُنِي وَمَا أَحَدٌ أَشَدَّ بُغْضًا لِرَسُولِ الله -صلَّى الله عليه وسلَّم- مِنِّي، وَلاَ أَحَبَّ إِلَيَّ مِنْ أَنْ أَكُونَ قَدْ اسْتَمْكَنْتُ مِنْهُ فَقَتَلْتُهُ، فَلَوْ مُتُّ عَلَى تِلْكَ الحَالِ لَكُنْتُ مِنْ أَهْلِ النَّارِ، فَلَمَّا جَعَلَ اللهُ الإِسْلاَمَ فِي قَلْبِي أَتَيتُ النَبيَّ -صلَّى الله عليه وسلَّم-، فَقُلتُ: ابْسُطْ يَمِينَكَ فَلِأُبَايِعُكَ، فَبَسَطَ يَمِينَهُ فَقَبَضْتُ يَدِي، فقال: «مَا لَكَ يَا عَمرُو؟» قُلتُ: أَرَدْتُ أَنْ أَشْتَرِطَ، قال: «تَشْتَرِطُ مَاذَا؟» قُلتُ: أَنْ يُغْفَرَ لِي، قال: «أَمَا عَلِمتَ أَنَّ الإِسْلاَمَ يَهْدِمُ مَا كَانَ قَبْلَهُ، وَأَنَّ الهِجْرَةَ تَهْدِمُ مَا كَانَ قَبْلَهَا، وَأَنَّ الحَجَّ يَهْدِمُ مَا كَانَ قَبْلَهُ؟» وَمَا كَان أَحَدٌ أَحبَّ إِلَيَّ مِنْ رسُول الله -صلَّى الله عليه وسلَّم- وَلاَ أَجَلَّ فِي عَينِي مِنْهُ، وَمَا كُنْتُ أُطِيقُ أَنْ أَمْلَأَ عَينِي مِنْهُ؛ إِجْلاَلاً لَهُ، وَلَوْ سُئِلْتُ أَنْ أَصِفَهُ مَا أَطَقْتُ؛ لِأَنِّي لَمْ أَكُنْ أَمْلَأُ عَينِي مِنْهُ، وَلَوْ مِتُّ عَلَى تِلْكَ الحَالِ لَرَجَوْتُ أَنْ أَكُونَ مِنْ أَهْلِ الجَنَّةِ، ثُمَّ وَلِينَا أَشْيَاءَ مَا أَدْرِي مَا حَالِي فِيهَا؟ فَإِذَا أَنَا مِتُّ فَلاَ تَصْحَبْنِي نَائِحَةٌ وَلاَ نَارٌ، فَإِذَا دَفَنْتُمُونِي، فَشُنُّوا عَلَيَّ التُرَابَ شَنًّا، ثُمَّ أَقِيمُوا حَولَ قَبرِي قَدْرَ مَا تُنْحَرُ جَزُور، وَيُقْسَمُ لَحْمُهَا، حتَّى أَسْتَأْنِسَ بِكُم، وَأَنْظُر مَا أُرَاجِعُ بِهِ رُسُلَ رَبِّي.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"تضمن حديث عمرو بن العاص رضي الله عنه المتضمن لموضوع التبشير والتهنئة بالخير قصة، وخُلاصة هذه القصة العظيمة: أنَّه حضَره بعض أصحابه وهو في سياق الموت، فبكى بكاء شديدا، وحوَّل وجهه نحو الجدار رضي الله عنه ، وهو في سياق الموت سيفارق الدنيا فقال له ابنه: علام تبكى وقد بشَّرك النبي صلى الله عليه وسلم بالجنة؟ فقال: يا بني إني كنت على أحوال ثلاثة، ثمَّ ذكر هذه الأحوال الثلاث: أنه كان يبغض النبي صلى الله عليه وسلم- بغضا شديدا، وأنه لم يكن على وجه الأرض أحد يبغضه كما كان يبغضه هو، وأنه يَوَدُّ أنَّه لو تمكَّن منه فقتَلَه، وهذا أشد ما يكون من الكفر، حتَّى ألقى الله الإسلام في قلبه فجاء إلى النبي صلى الله عليه وسلم ، فقال يا رسول الله: ابسط يدك فَلِأُبَايِعُكَ علَى الإسلام، وكان النبي صلى الله عليه وسلم أحسن الناس خُلُقًا فمدَّ يده، ولكن عمرو بن العاص كف يده؛ ليس استكبارًا، ولكن استثباتا لما سيذكره، فقال له: \"مالك؟\" قال: يا رسول الله، إني أشترط -يعني على الإسلام-، قال: \"ماذا تشترط؟\" قال: أشترط أن يغفر الله لي ما سبق من الكفر والذنوب. هذا أكبر همِّه رضي الله عنه ، يشترط أنَّ الله يغفر له، ظن أن الله لن يغفر له لما كان له من سابقة، فقال له النبي صلى الله عليه وسلم : \"أما علمت أن الإسلام يهدم ما كان قبله، وأن الهجرة تهدم ما كان قبلها، وأن الحج يهدم ما كان قبله\" ثلاثة أشياء.\n أما الإسلام: فإنه يهدم ما كان قبله بنص الكتاب العزيز، قال الله عز وجل : {قل للذين كفروا إن ينتهوا يغفر لهم ما قد سلف وإن يعودوا فقد مضت سنت الأولين}.\nوالهجرة: إذا هاجر الإنسان من بلده التي يعيش فيها، وهي بلد كفر هدمت ما قبلها.\nوالحج: يهدم ما قبله؛ لقول النبي صلى الله عليه وسلم : \"الحج المبرور ليس له جزاء إلا الجنة\". \nفبايع رضي الله عنه وأحب النبي صلى الله عليه وسلم حبًّا شديدًا حتى كان أحب الناس إليه، وحتى إنه لا يستطيع أن يحد النظر فيه؛ إجلالا له -عليه الصلاة والسلام-. سبحان مقلب القلوب! بالأمس كان يبغضه بغضا شديدا، حتى يتمنى أنه يقدر عليه فيقتله، والآن ما يستطيع أن يرفع طرفه إليه؛ إجلالا له، ولا يستطيع أن يصفه؛ لأنه لا يحيط به، حيث إنه لم يدركه إدراكا جيدا؛ مهابة له صلى الله عليه وسلم .\nيقول رضي الله عنه: إنَّه لو مات على الحال الأول؛ لكان من أهل النار، يقول: ولو مت على تلك الحال يعني الحال الثاني؛ لرجوت أن أكون من أهل الجنة. انظر الاحتياط فقد جزم أنه لو مات على الحال الأولى؛ لكان من أهل النار، أما الحال الثانية فإنه لشدة خوفه قال: لو مت على هذا الحال لرجوت أن أكون من أهل الجنة، ولم يقل: لكنت من أهل الجنة؛ لأن الشهادة بالجنة أمرها صعب.\nثم إنه بعد ذلك تولى أمورا رضي الله عنه ، تولى إمارات وقيادات، وحصل ما حصل في قصة حرب معاوية وغيره، وكان عمرو بن العاص معروفا أنه من أدهى العرب وأذكى العرب، فيقول: أخشى من هذا الذي حدث بي بعد الحال الأوسط أن يكون أحاط بعملي.\nثم أوصى رضي الله عنه أنه إذا مات لا تتبعه نائحة، والنائحة: هي المرأة التي تنوح على الميت، وتبكي عليه بكاء يشبه نوح الحمام، وأمر رضي الله عنه إذا دفنوه أن يبقوا عند قبره قدر ما ينحر واحد من الإبل، ويقسم لحمه، حتى يراجع رسل ربه وهم الملائكة الذين يأتون إلى الميت إذا دفن، فإن الميت إذا دفن يأتيه ملكان ويجلسانه في قبره، ويسألانه ثلاثة أسئلة: يقولان من ربك؟ وما دينك؟ ومن نبيك؟.\nفأمر عمرو بن العاص رضي الله عنه أهله أن يقيموا عليه قدر ما تنحر الجزور ويقسم لحمها؛ ليستأنس بهم، وهذا يدل على أن الميت يحس بأهله، وقد ثبت عن النبي -عليه الصلاة والسلام- أن الميت يسمع قرع نعالهم إذا انصرفوا من دفنه، قرع النعال الخفي يسمعه الميت إذا انصرفوا من دفنه.\nوقد ثبت عن النبي صلى الله عليه وسلم في حديث حسن أنه كان إذا دفن الميت وقف عليه، وقال: \"استغفروا لأخيكم، واسألوا له التثبيت؛ فإنه الآن يسأل\"، فيستحب إذا دفن الميت أن يقف الإنسان على قبره ويقول: اللهم ثبته، اللهم ثبته، اللهم ثبته، اللهم اغفر له، اللهم اغفر له، اللهم اغفر له؛ لأن النبي صلى الله عليه وسلم كان إذا سلم سلم ثلاثا، وإذا دعا دعا ثلاثًا. \nالحاصل أن ابن عمرو بن العاص قال له: بشرك النبي صلى الله عليه وسلم بالجنة، وهذا من باب البشارة بالخير والتهنئة به.","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الدمام، الطبعة: الأولى 1415هـ.\nتطريز رياض الصالحين، فيصل بن عبد العزيز المبارك، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة للنشر والتوزيع، الرياض، الطبعة: الأولى 1423هـ، 2002م.\nرياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق ماهر الفحل، دار ابن كثير، دمشق، بيروت، الطبعة: الأولى 1428هـ.\nشرح رياض الصا","benefits":["جواز البكاء عند الاحتضار، رجاء عفو الله، واتعاظ الأحياء الحاضرين.","في هذا الحديث: أن المؤمن لا تفارقه خشية الله ولو عمل من الصالحات ما عمل، كما قال -تعالى-: (والذين يؤتون ما آتوا وقلوبهم وجلة أنهم إلى ربهم راجعون).","استحباب ذكر أحسن أعمال المحتضر عنده؛ ليحسن ظنه بالله -تعالى- ويموت عليه.","تطييب نفس المحتضر وتبشيره برحمة الله وعفوه.","استحباب تنبيه المحتضر على إحسان ظنه بالله -سبحانه وتعالى-، وذكر آيات الرجاء، وأحاديث العفو عنده، وتبشيره بما أعده الله -تعالى- للمسلمين.","أن الكافر إذا أسلم لا يسأل عما مضى من الذنوب.","عِظَم موقع الإسلام والهجرة والحج، وأن كل واحد منها يهدم ما قبله من المعاصي.","أن الهجرة والحج والصلاة تكفر الصغائر من الذنوب، وأن الكبائر تكفرها التوبة بشروطها.","إجلال الصحابة -رضي الله عنهم- لرسول الله -صلى الله عليه وسلم- وحبهم له.","حرمة النياحة على الميت، واتباع جنازته بنار.","امتثال نهي رسول الله -صلى الله عليه وسلم- من عدم اتباعه بنائحة ولا نار.","استحباب الوصية قبل الموت.","استئناس الميت بدعاء إخوانه وأهله له عند قبره.","إثبات فتنة القبر، وسؤال الملكين.","استحباب المكث عند القبر مدة قصيرة؛ للدعاء والاستغفار للميت."],"wordsMeanings":[{"word":"سِيَاقَة الموت","meaning":" حال حضور الموت."},{"word":"أطْبَاق","meaning":" أحوال."},{"word":"اسْتَمْكَنت","meaning":" تمكَّنتُ وقَدِرت."},{"word":"أتيت النبي","meaning":" جئته وذلك سنة سبع من الهجرة، بعد عمرة القضاء."},{"word":"فَلِأُبَايِعُك","meaning":" أعاقدك وأعاهدك."},{"word":"أُطِيق","meaning":" أقدر."},{"word":"وَلِينا أشياء","meaning":" كُلِّفنا بأعمال."},{"word":"نائحة","meaning":" هي التي تعدد أوصاف الميت، وتبكي بصوت، وتنوح عليه."},{"word":"فشُـنُّوا","meaning":" صبُّوه قليلاً قليلاً."},{"word":"الجَزُور","meaning":" ما يصلح لأن يذبح من الإبل."},{"word":"أُرَاجِع","meaning":" أجاوب وأجادل."},{"word":"أَسْتَأْنِس","meaning":" أشعر بالأنس."}],"category":"sirah","bookId":"muslim","tags":["أما","علمت","الإسلام","يهدم","كان","قبله،"],"source":"hadeethenc"},{"id":"he_3476","text":"عَنْ عَائِشَةَ أُمِّ المُؤمنينَ رضي الله عنها قَالَتْ: كُنْتُ أَغْتَسِلُ أَنَا وَالنَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ مِنْ إِنَاءٍ وَاحِدٍ كِلاَنَا جُنُبٌ، وَكَانَ يَأْمُرُنِي، فَأَتَّزِرُ، فَيُبَاشِرُنِي وَأَنَا حَائِضٌ، وَكَانَ يُخْرِجُ رَأْسَهُ إِلَيَّ وَهُوَ مُعْتَكِفٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أَخْبَرَتْ عائشةُ أُمُّ المؤمنين رضي الله عنها عن بعض أحوالِها الخاصة معه صلى الله عليه وسلم، ومن ذلك: أنها كانت تغتسل من الجنابة معه صلى الله عليه وسلم مِن إناءٍ واحدٍ فيأخذان منه معًا. \nوأنه صلى الله عليه وسلم إذا أراد إتيانَها وهي حائض أَمَرَها أَنْ تُغطي بدنَها مِن السُّرَّةِ إلى الركبة، فيباشرها بما دون الجماع. \nوأنه صلى الله عليه وسلم كان يَعتكف في المسجد فيُخرِج رأسَه إلى عائشة فتغسله وهي في بيتها حائضٌ.","reference":"صحيح البخاري (1/ 67) (299 - 301).\nصحيح مسلم (1/ 244) (297)، (1/ 255) (319).\nالإلمام بشرح عمدة الأحكام، لإسماعيل الأنصاري (1/ 66).\nتيسير العلام شرح عمدة الأحكام، للبسام (ص79).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 76).","benefits":["جواز اغتسال الرجل وزوجتِه مِن إناءٍ واحد.","جواز مباشرة الحائض فيما دون الفرج، وأنَّ بدنَها طاهر.","استحباب لبسِها الإزارَ وقتَ المباشرة.","اتخاذ الأسباب المانعة من الوقوع في المحرم.","منع مُكْثِ الحائضِ في المسجد.","إباحة مباشرتِها الأشياءَ رطبة أو يابسة، ومن ذلك غسل الشعر وترجيله.","حسن عشرة النبي صلى الله عليه وسلم لأهله."],"wordsMeanings":[],"category":"sirah","tags":["كنت","أغتسل","أنا","والنبي","صلى","الله"],"source":"hadeethenc"},{"id":"he_3484","text":"عن عائشة رضي الله عنها قالت: ((دخل عبد الرحمن بن أبي بكر الصديق رضي الله عنهما على النبي صلى الله عليه وسلم وأنا مُسْنِدَتُه إلى صدري، ومع عبد الرحمن سِواك رَطْب يَسْتَنُّ به، فأَبَدَّه رسول الله صلى الله عليه وسلم بَصَره، فَأَخَذْتُ السِّوَاك فَقَضَمتُه، فَطَيَّبتُه، ثُمَّ دَفَعتُهُ إلى النبي صلى الله عليه وسلم فَاسْتَنَّ به فما رأيتُ رسول الله صلى الله عليه وسلم استَنَّ اسْتِنَانًا أَحسَنَ منه، فَما عَدَا أن فَرَغَ رسول الله صلى الله عليه وسلم : رَفَع يَدَه -أو إصبعه-، ثم قال: في الرفيق الأعلى -ثلاثا- ثمَّ قَضَى، وكَانت تقول: مَاتَ بَينَ حَاقِنَتِي وَذَاقِنَتِي)).","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"تذكر عائشة رضي الله عنها قصةً تبين لنا مدى محبة النبي صلى الله عليه وسلم للسواك وتعلقه به، وذلك أن عبد الرحمن بن أبى بكر رضي الله عنه -أخا عائشة- دخل على النبي صلى الله عليه وسلم في حال النزع ومعه سواك رطب، يدلك به أسنانه.\nفلما رأى النبي صلى الله عليه وسلم السواك مع عبد الرحمن، لم يشغله عنه ما هو فيه من المرض والنزع، من محبته له، فمدَّ إليه بصره، كالراغب فيه، ففطنت عائشة رضي الله عنها فأخذت السواك من أخيها، وقصت رأس السواك بأسنانها ونظفته وطيبته، ثم ناولته النبي صلى الله عليه وسلم ، فاستاك به.\nفما رأت عائشة تسوكًا أحسن من تسوكه.\nفلما طهر وفرغ من التسوك، رفع إصبعه، يوحد الله تعالى ، ويختار النقلة إلى ربه تعالى ، ثم توفي صلى الله عليه وسلم .\nفكانت عائشة رضي الله عنها مغتبطة، وحُق لها ذلك، بأنه صلى الله عليه وسلم توفي ورأسه على صدرها.","reference":"الإلمام بشرح عمدة الأحكام، إسماعيل بن محمد الأنصاري، دار الفكر، دمشق، الطبعة: الأولى 1381هـ.\nتأسيس الأحكام، أحمد بن يحيى النجمي، دار علماء السلف، الطبعة: الثانية 1414هـ.\nتيسير العلام شرح عمدة الأحكام، عبد الله بن عبد الرحمن البسام، تحقيق: محمد صبحي حلاق، مكتبة الصحابة، الأمارات، مكتبة التابعين، القاهرة، الطبعة: العاشرة 1426هـ.\nتنبيه الأفهام شرح عمدة الأحكام، محمد بن صالح العثيمين ، مكتبة الصحابة، ","benefits":["جواز الاستياك بالسواك الرطب.","محبة النبي -صلى الله عليه وسلم- للسواك.","قوة فطنة عائشة -رضي الله عنها-.","العمل بما يفهم من الإشارة والدلالة.","إصلاح السواك وتهيئته.","جواز الاستياك بسواك الغير بعد تطهيره وتنظيفه.","توكيد أمر السواك لكونه -صلى الله عليه وسلم- حرص عليه مع ما هو فيه من تعب المرض.","قوة قلب النبي -صلى الله عليه وسلم- ورباطة جأشه حيث لم يذهل عن التسوُّك والدعاء حال الموت.","استحباب الاستياك عند الاحتضار.","إثبات علو الله -عز وجل- في السماء.","فضيلة عائشة -رضي الله عنها- ووفاته -صلى الله عليه وسلم- في حِجرها، وبيتها، ويومها."],"wordsMeanings":[{"word":"مُسْنِدَتُه","meaning":" مميلته."},{"word":"الرطب","meaning":" ضد اليابس، ويصدق على الأخضر والمندى."},{"word":"يَستَنُّ به","meaning":" يُمِرُّ السواك على أسنانه، كأنه يحددها."},{"word":"فأَبَدَّه","meaning":" مدَّ إليه بصره وأطاله."},{"word":"بين حَاقِنَتِي وذَاقِنَتِي","meaning":" الحاقنة: هي المعدة أو أسفل البطن، والذاقنة: ما تحت الذقن ورأس الحلقوم."},{"word":"فقَضَمته","meaning":" مضغته بأطراف الأسنان؛ لِيَلِين."},{"word":"سواك","meaning":" مسواك من الجريد الأخضر."},{"word":"طيَّبتُه","meaning":" جعلته طيبا صالحا؛ للتسوك به."},{"word":"فما عَدَا أن فَرَغ رسول الله -صلى الله عليه وسلم- رَفَع","meaning":" ما جاوز، وفرغ: انتهى، والمعنى: ما جاوز فراغه من التسوك حتى رفع، أي: أنه بادر بذلك."},{"word":"الرفيق","meaning":" المرافق."},{"word":"والأعلى","meaning":" صفة للرفيق، وهو الأرجح؛ لأن الرسل أعلى الخلق فضلا ومنزلة."},{"word":"قضى","meaning":" مات."},{"word":"أشار برأسه","meaning":" أومأ به."}],"category":"sirah","bookId":"bukhari","tags":["دخل","عبد","الرحمن","أبي","بكر","الصديق"],"source":"hadeethenc"},{"id":"he_3537","text":"عن عَبْد اللَّهِ بْنِ عَبَّاسٍ رضي الله عنهما قال: «أّعْتَمَ النَبِيُّ -صلَّى الله عليه وسلَّم- بِالعِشَاء، فَخَرَج عُمَر فقال: الصَّلاةَ يا رسول الله، رَقَد النِسَاءُ والصِّبيَان. فَخَرَجَ ورَأسُهُ يَقطُر يقول: لَولاَ أن أَشُقَّ عَلَى أُمَّتِي -أو على النَّاس- لَأَمَرتُهُم بهذه الصَّلاة هذه السَّاعَة».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"تأخر النبي صلى الله عليه وسلم بصلاة العشاء، حتى ذهب كثير من الليل، ورقد النساء والصبيان، ممن ليس لهم طاقة ولا احتمال على طول الانتظار، فجاء إليه عمر بن الخطاب رضي الله عنه وقال: الصلاة، فقد رقد النساء والصبيان. فخرج صلى الله عليه وسلم من بيته إلى المسجد ورأسه يقطر ماء من الاغتسال وقال مبينًا أن الأفضل في العشاء التأخير، لولا المشقة التي تنال منتظري الصلاة: لولا أن أشق على أمتي لأمرتهم بهذه الصلاة في هذه الساعة المتأخرة.","reference":"الإلمام بشرح عمدة الأحكام لإسماعيل الأنصاري، ط1، دار الفكر، دمشق، 1381هـ\nتيسير العلام شرح عمدة الأحكام للبسام، حققه وعلق عليه وخرج أحاديثه وصنع فهارسه: محمد صبحي بن حسن حلاق، ط10، مكتبة الصحابة، الإمارات - مكتبة التابعين، القاهرة، 1426 هـ\nتنبيه الأفهام شرح عمدة لأحكام لابن عثيمين، ط1، مكتبة الصحابة، الإمارات، 1426هـ\nعمدة الأحكام من كلام خير الأنام صلى الله عليه وسلم لعبد الغني المقدسي، دراسة وتحقي","benefits":["الأمر للوجوب ومحل ذلك إذا لم يصرفه صارف؛ لإخباره -صلى الله عليه وسلم- أن في المر مشقة، والمستحب لا مشقة فيه لأنه بالخيار.","الأفضل في العشاء التأخير، ويمنع من ذلك المشقة.","المشقَّة تسبب اليسر والسهولة في هذه الشريعة السمحة.","أنَّه قد يكون ارتكاب العمل المفضول أولى من الفاضل، إذا اقترن به أحوال وملابسات.","جواز اسستدعاء الإمام إلى الصلاة، وإن كان كبيرًا إذا تأخر.","كمال شفقة النبي -صلى الله عليه وسلم- ورحمته بأمته.","صراحة عمر رضي الله عنه مع النبي -صلى الله عليه وسلم-، لمكانته عنده ولثقته بحسن خلق النبي -صلَّى الله عليه وسلم-.","دليل على تنبيه الأكابر لاحتمال غفلة أو تحصيل فائدة."],"wordsMeanings":[{"word":"أَعْتَمَ","meaning":" دخل في العتمة، وهى ظلمة الليل، المراد أنه أخر صلاة العشاء بعد ذهاب الشفق، فصلاها في ظلمة الليل."},{"word":"فَخَرَجَ عُمَر","meaning":" أي: من المسجد، أو من مكانه في الصف."},{"word":"رَقَد","meaning":" نام."},{"word":"الصلاةُّ","meaning":" بالرفع على تقدير: حضرت الصلاة.وبالنصب على تقدير: صل الصلاة."},{"word":"الصِّبْيَان","meaning":" صغار الأولاد حتى يبلغوا."},{"word":"ورأسه يقطر","meaning":" أي من الماء."},{"word":"لَوْلا أَنْ أشق عَلَى","meaning":" لولا: حرف امتناع لوجود، أي: أنها تدل على امتناع شيء لوجود شيء آخر، ففي هذه الحديث تدل على امتناع إلزام النبي -صلى الله عليه وسلم- أمته بتأخير صلاة العشاء إلى ثلث الليل الآخر لوجود المشقة عليهم بذلك."},{"word":"أُمَّتِي","meaning":" جماعتي، والمراد بهم: من آمن به واتبعه."},{"word":"أَشُقَّ","meaning":" أتعب وأثقل."},{"word":"لأَمَرْتُهُم","meaning":" لألزمتهم."},{"word":"هذه الساعة","meaning":" هذا الوقت، وهو ثلث الليل الآخر."}],"category":"sirah","tags":["أعتم","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_4239","text":"عن عائشة رضي الله عنها قالت: تُوُفِّيَ رسول الله صلى الله عليه وسلم وما في بيتي من شيء يَأكُلُهُ ذُو كَبدٍ إلا شَطْرُ شَعير في رَفٍّ لي، فأكَلتُ منه حتى طال عليَّ، فَكِلْتُهُ فَفَنِيَ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"تخبر عائشة رضي الله عنها أن النبي صلى الله عليه وسلم توفي وما في بيتها إلا شطر شعير، ومعناه: شيء من شعير، كما فسره الترمذي، فظلت تأكل من الشعير الذي تركه صلى الله عليه وسلم زمنًا، فلما وزنته نفد، وهذا دليل على استمرار بركته صلى الله عليه وسلم في ذلك الطعام القليل، مع عدم الكيل الدال على التوكل، فالكيل عند المبايعة مطلوب من أجل تعلق حق المتابعين، أما الكيل عند الإنفاق فغير مستحب.","reference":"كنوز رياض الصالحين، أ.د. حمد بن ناصر بن عبد الرحمن العمار، دار كنوز إشبيليا، الطبعة الأولى: 1430 هـ.\nبهجة الناظرين، الشيخ: سليم بن عيد الهلالي، دار ابن الجوزي.\nنزهة المتقين، د. مصطفى سعيد الخن، د. مصطفى البغا، محيي الدين مستو، علي الشرجبي، محمد أمين لطفي، مؤسسة الرسالة، بيروت، الطبعة الأولى: 1397 هـ 1977 م، الطبعة الرابعة عشرة 1407 هـ 1987م.\nشرح صحيح البخاري لابن بطال، المؤلف: ابن بطال أبو الحسن ع","benefits":["إعراض النبي -صلى الله عليه وسلم- عن الدنيا وقد دانت له الجزيرة العربية، ومع ذلك فلم يكن في بيت أحب الناس إليه إلا هذا الشيء اليسير من الشعير.","استحباب الاقتصاد في النفقة.","من رزقه الله شيئًا، أو أكرمه بكرامة، أو لطف به في أمر، فعليه أن يشكر الله -تعالى-.","الكيل عند المبايعة مطلوب من أجل تعلق حق المتابعين، أما الكيل عند الإنفاق فغير مستحب؛ لأن الباعث عليه الشح، وقد فني الشعير بعد كيله؛ لأن كيله مناف للتسليم."],"wordsMeanings":[{"word":"ذُو كَبدٍ","meaning":" شمل جميع الحيوان، وعبر بالكبد عن الحياة؛ لأنه من الأعضاء الرئيسية في الجسم."},{"word":"شَطْرُ شَعير","meaning":" شيء من شعير، والشطر يطلق على النصف وما قاربه وليس مرادًا هنا."},{"word":"الرَّفُّ","meaning":" خشبٌ يُرفع عن الأرض يوضع فيه ما يراد حفظه، أو شبه طاق في الحائط، والأخير أقرب إلى المراد."},{"word":"كِلْتُهُ","meaning":" أخذت منه بالكيل والمقدار."},{"word":"فَنِيَ","meaning":" فرَغَ ونَفَد."}],"category":"sirah","tags":["توفي","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_4247","text":"عن عائشة رضي الله عنها أن النبي صلى الله عليه وسلم كان يَنَام أول اللَّيل، ويقوم آخره فَيُصلِّي.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"تُخبر عائشة رضي الله عنها أن النبي صلى الله عليه وسلم كان ينام أول الليل، وذلك بعد صلاة العشاء، ويقوم آخره، وهو: الثلث الثاني من الليل، فإذا فَرَغ من صلاته، رجع إلى فراشه ليَنَام، وذلك في السُدس الأخير من الليل؛ ليستريح بَدَنه من عَنَاء قيام الليل، وفيه من المصلحة أيضاً استقبال صلاة الصبح، وأذكار النهار بنشاط وإقبال، ولأنه أقرب إلى عدم الرياء؛ لأن من نام السدس الأخير أصبح ظاهر اللون سليم القوى، فهو أقرب إلى أن يخفي عمله الماضي عمن يراه.\nولهذا جاء أن الأذان الأول؛ ليوقظ النائم ويرجع القائم، فالقائم يرجع إلى النوم؛ ليَكتَسِب بدنه قوة ونشاطاً، وأما النائم، فيستيقظ حتى يَستعد للصلاة، وحتى يصلي وتره إذا لم يوتر أول الليل.","reference":"1- بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الطبعة الأولى، 1418هـ - 1997م.\n2- نزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين، مؤسسة الرسالة، بيروت، الطبعة الرابعة عشر،  1407هـ - 1987م.\n3- صحيح البخاري، محمد بن إسماعيل البخاري الجعفي، تحقيق: محمد زهير الناصر، دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم: محمد فؤاد عبد الباقي)، الطبعة الأولى، 1422هـ.\n4- صحيح مسلم،","benefits":["كراهية قيام الليل كله، وأن الأفضل أن ينام جزءاً من الليل، ويقوم جزءا منه؛ دفعًا للملل والكسل.","الأفضل أن يكون القيام في الجزء الأخير من الليل؛ ليكون أنشط في العبادة.","آخر الليل أرْجَى في إجابة الدعاء.","بيان الوقت الذي كان يقوم فيه -صلى الله عليه وسلم- من الليل."],"wordsMeanings":[],"category":"sirah","tags":["النبي","صلى","الله","عليه","وسلم","كان"],"source":"hadeethenc"},{"id":"he_4829","text":"عن عائشة رضي الله عنها قالت: كان رسولُ اللهِ صلى الله عليه وسلم إذا فَاتَتْهُ الصَّلَاةُ مِنَ الليلِ مِن وَجَعٍ أَوْ غَيْرِهِ، صَلَّى من النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً.","attribution":"رواه مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبي صلى الله عليه وسلم إذا ترك قيام الليل من وجع أو غيره صلى من النهار ثنتي عشرة ركعة؛ لأنه صلى الله عليه وسلم كان يوتر بإحدى عشر ركعة، فإذا مضى الليل ولم يوتر لنوم أو شبهه؛ فإنه يقضي هذه الصلاة، لكن لما فات وقت الوتر صار المشروع أن يجعله شفعا.","reference":"دليل الفالحين لطرق رياض الصالحين، لابن علان، نشر دار الكتاب العربي.\nنزهة المتقين شرح رياض الصالحين، نشر: مؤسسة الرسالة، الطبعة: الرابعة عشر، 1407ه 1987م.\nشرح رياض الصالحين، لابن عثيمين، نشر: دار الوطن للنشر، الرياض، الطبعة: 1426ه.\nبهجة الناظرين شرح رياض الصالحين لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415ه.\nالمعجم الوسيط، نشر: دار إحياء التراث العربي، بيروت – لبنان، الطبعة: الثانية.\nصحيح مسلم،","benefits":["صلاة النهار هنا عِوض عن صلاة الليل لجَبْر فضيلتها.","الدليل على جواز قضاء النوافل.","الوتر يقضى في النهار بزيادة ركعة، فيصير شفعا."],"wordsMeanings":[{"word":"فاتته الصلاة","meaning":" مضى وقتها."},{"word":"وجع","meaning":" مرض أو ألم."},{"word":"أو غيره","meaning":" كغلبة نوم أو عذر أهم منه."}],"category":"sirah","bookId":"muslim","tags":["كان","رسولُ","اللهِ","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_4970","text":"عن جابر بن عبد الله وأبو هريرة رضي الله عنهم مرفوعاً: «مثلي ومثلُكم كمثل رجلٍ أَوْقَدَ نارًا فجعل الجنادِبُ والفَرَاشُ يَقَعْنَ فيها، وهو يَذُبُّهُنَّ عنها، وأنا آخذٌ بحُجَزِكُم عن النار، وأنتم تَفَلَّتُون من يَدَيَّ».","attribution":"حديث جابر رضي الله عنه: رواه مسلم.\nحديث أبي هريرة رضي الله عنه: متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يبين النبي صلى الله عليه وسلم أن حاله مع أمته كحال رجل في برية، أوقد نارًا فجعل الجنادب والفراش يقعن فيها؛ لأن هذه هي عادة الفراش والجنادب والحشرات الصغيرة، إذا أوقد إنسان نارًا في البر؛ فإنها تأوي إلى هذا الضوء. ويقول: لأمنعنكم من الوقوع فيها، ولكنكم تفلتون من يدي، وذلك بمخالفة النبي صلى الله عليه وسلم وترك سنته.","reference":"رياض الصالحين، للنووي، نشر: دار ابن كثير للطباعة والنشر والتوزيع، دمشق – بيروت، تحقيق: ماهر ياسين الفحل، الطبعة: الأولى، 1428هـ - 2007م.\nدليل الفالحين لطرق رياض الصالحين، لابن علان، نشر دار الكتاب العربي.\nنزهة المتقين شرح رياض الصالحين، نشر: مؤسسة الرسالة، الطبعة: الرابعة عشر، 1407ه 1987م.\nشرح رياض الصالحين، لابن عثيمين، نشر: دار الوطن للنشر، الرياض، الطبعة: 1426ه.\nكنوز رياض الصالحين، نشر: دار كنو","benefits":["حرص الرسول صلى الله عليه وسلم ورحمته بأمته.","دلَّ على جهل كثير من الناس حيث يأبون إلا مخالفة الدين، وفي هذه المخالفة شقاؤهم، وقد يصل بهم ذلك إلى العذاب في نار جهنم."],"wordsMeanings":[{"word":"مَثَلي","meaning":" المَثَل: النظير."},{"word":"الجنادب","meaning":" نحو الجراد والفراش، هذا هو المعروف الذي يقع في النار."},{"word":"الفراش","meaning":" جمع فراشة، وهي الطير الذي يلقي بنفسه في ضوء السراج."},{"word":"يذبهن","meaning":" يمنعهن ويدفعهن عنها."},{"word":"بحجزكم","meaning":" الحجز: جمع حجزة، وهي معقد الإزار والسراويل."},{"word":"تفلتون","meaning":" تغلبون وتهربون إليها."}],"category":"sirah","bookId":"muslim","tags":["مَثَلِي","وَمَثَلُكُم","كَمَثَلِ","رَجُلٍ","أَوْقَدَ","نَارًا"],"source":"hadeethenc"},{"id":"he_5210","text":"عن عبد الله بن عباس رضي الله عنهما : «أن النبي صلى الله عليه وسلم صلَّى على قبر بعدَ ما دُفِنَ، فَكَبَّرَ عليه أَرْبَعاً».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"قد جُبلَ النبي صلى الله عليه وسلم على محاسن الأخلاق، ومن ذلك ما اتصف به من الرحمة والرأفة، فما يَفْقِدُ أحداً من أصحابه حتى يسأل عنه، ويتفقد أحواله.\nفقد سأل عن صاحب هذا القبر، فأخبروه بوفاته، فأحب أنهم أخبروه ليصلي عليه، فإن صلاته سكنٌ للميت، ونور يزيل الظلمة التي هو فيها، فصلى على قبره كما يصلى على الميت الحاضر.\nصلاة النبي صلى الله عليه وسلم على القبر لا يفهم منها صعوده على القبر، وإنما المعنى الوقوف بجانبه واستقباله والصلاة عليه صلاة الجنازة.","reference":"- صحيح البخاري، أبو عبد الله محمد بن إسماعيل البخاري, تحقيق محمد زهير بن ناصر الناصر- الناشر: دار طوق النجاة، الطبعة الأولى، 1422هـ.\n- صحيح مسلم، المحقق: محمد فؤاد عبد الباقي، الناشر: دار إحياء التراث العربي – بيروت.\n- العمدة في الأحكام, لعبد الغني بن عبد الواحد بن علي الحنبلي, المحقق: سمير بن أمين الزهيري, الناشر: مكتبة المعارف للنشر والتوزيع، الرياض - المملكة العربية السعودية, الطبعة الأولى، 141","benefits":["مشروعية الصلاة على القبر، ولا يلتفت إلى من منعه، لرَدِّه النصوص بلا حجة.","أن صفة الصلاة على القبر، مثل صفة الصلاة على الميت الحاضر.","ما كان عليه -صلى الله عليه وسلم- من الرحمة والرأفة، وتفقد الواحد من أصحابه, مهما كانت منزلته.","صلاة الجنازة جائزة في المقبرة؛ لأنها ليس فيها ركوع ولا سجود، والنهي عن الصلاة في المقبرة مخصص بالصلاة ذات الركوع والسجود المعروفة."],"wordsMeanings":[{"word":"صلّى على قبر","meaning":" أي على صاحب قبر."},{"word":"بعد ما دفن","meaning":" أي بساعات لأن الصلاة كانت صبيحة دفنه."},{"word":"كَبَّرَ أربعا","meaning":" صلى عليه فقال: الله أكبر أربع مرات, كما يفعل في صلاة الجنازة على الميت الحاضر."}],"category":"sirah","tags":["النبي","صلى","الله","عليه","وسلم","صلَّى"],"source":"hadeethenc"},{"id":"he_5320","text":"عن أبي هُرَيْرة رضي الله عنه قال: «كان النبي صلى الله عليه وسلم يَقْرأ فِي صلاة الفجر يَومَ الجُمُعَةِ: الم تَنْزِيلُ السَّجْدَةَ وهَلْ أتى على الإنسَان».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كان من عادة النبي صلى الله عليه وسلم أن يقرأ في صلاة الفجر يوم الجمعة سورة السجدة كاملة، وذلك في الركعة الأولى بعد الفاتحة، ويقرأ في الركعة الثانية بعد الفاتحة سورة الإنسان كاملة؛ تذكيرا بما اشتملت عليه السورتان من أحداث عظيمة وقعت وستقع في هذا اليوم، كخلق آدم، وذكر المعاد وحشر العباد، وأحوال القيامة، وغيرها.","reference":"تيسير العلام، للبسام، الناشر: مكتبة الصحابة، الإمارات، مكتبة التابعين، القاهرة، الطبعة العاشرة، 1426هـ - 2006م.\nتنبيه الأفهام، للعثيمين، طبعة مكتبة الصحابة، الإمارات، مكتبة التابعين، القاهرة، الطبعة الأولى، 1426هـ.\nالإفهام في شرح عمدة الأحكام، لعبد العزيز بن باز، اعتناء سعيد بن علي بن وهف القحطاني، الرياض، الطبعة الأولى، 1435ه.\nخلاصة الكلام، لفيصل المبارك الحريملي، الطبعة الثانية، 1412هـ - 1992م.\n","benefits":["استحباب قراءة هاتين السورتين في صلاة فجر يوم الجمعة.","من السنة المواظبة على قراءة هاتين السورتين في صلاة الفجر يوم الجمعة.","فيه تذكير للناس بما كان وسيكون في هذا اليوم."],"wordsMeanings":[{"word":"كان","meaning":" هنا تدل على الاستمرار."},{"word":"\"الم تنزيل\" السجدة","meaning":" السورة التي اسمها السجدة."},{"word":"هل أتى على الإنسان","meaning":" السورة التي اسمها الإنسان."}],"category":"sirah","tags":["كان","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_5860","text":"عن عبدالله بن عباس رضي الله عنهما قال: كان رسول الله صلى الله عليه وسلم يبيت الليالي المتتابعة طَاوِياً، وأهلُهُ لا يجِدُون عَشَاءً، وكان أكثر خبزهم خبز الشعير.","attribution":"رواه الترمذي وابن ماجه وأحمد","grade":"صحيح","gradeKey":"sahih","explanation":"كان النبي صلى الله عليه وسلم ينام الليالي المتتابعة المتوالية من غير أكل، وكذلك زوجاته وعياله؛ لأنهم لا يجدون طعام العَشاء، وكان أكثر خبزهم من الشعير، وهو أقل كلفة من البر وغيره.","reference":"سنن الترمذي, تأليف: محمد بن عيسى الترمذي, تحقيق وتعليق: أحمد محمد شاكر ومحمد فؤاد عبد الباقي وإبراهيم عطوة عوض، شركة مكتبة ومطبعة مصطفى البابي الحلبي، مصر الطبعة: الثانية، 1395هـ - 1975م.\nسنن ابن ماجه: لابن ماجه أبو عبد الله محمد بن يزيد القزويني، تحقيق: محمد فؤاد عبد الباقي، دار إحياء الكتب العربية، فيصل عيسى البابي الحلبي.\nمسند الإمام أحمد بن حنبل المحقق: شعيب الأرنؤوط - عادل مرشد، وآخرون إشراف:","benefits":["بيان لزهده -صلى الله عليه وسلم- وتقلله من الدنيا وصبره على لأوائها.","فضيلة لأزواج النبي -صلى الله عليه وسلم- لتحملهم المشاق معه.","بيان لخشونة العيش التي كانوا عليها."],"wordsMeanings":[{"word":"طاوياً","meaning":" خالي البطن لم يأكل."}],"category":"sirah","bookId":"tirmidhi","tags":["كان","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_6010","text":"عن ابن مسعود رضي الله عنه قال: دخلتُ على النبيِّ صلى الله عليه وسلم وهو يُوعَكُ، فَمَسَسْتُهُ، فقلتُ: إنّكَ لَتُوعَكُ وَعَكًا شَدِيدًا، فقالَ: «أجَلْ، إنِّي أُوعَكُ كما يُوعَكُ رَجُلانِ منكُم».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يذكر ابن مسعود رضي الله عنه أنه دخل على النبي صلى الله عليه وسلم وهو يتألم من شدة المرض، فمد يده فقال له: إنك ليشدد عليك في المرض يا رسول الله، فأخبره أنه يشدد عليه صلى الله عليه وسلم في المرض، كما يشدد على الرجلين منا؛ وذلك من أجل أن ينال صلى الله عليه وسلم أعلى درجات الصبر.","reference":"بهجة الناظرين شرح رياض الصالحين، تأليف سليم الهلالي، دار ابن الجوزي.\nتطريز رياض الصالحين، تأليف فيصل آل مبارك، تحقيق د. عبدالعزيز آل حمد، دار العاصمة، الرياض، الطبعة الأولى، 1423هـ.\nرياض الصالحين من كلام سيد المرسلين، للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير، دمشق، الطبعة الأولى، 1428هـ.\nشرح رياض الصالحين، للشيخ محمد بن صالح العثيمين، مدار الوطن - الرياض، 1426هـ.\nصحيح البخاري، لل","benefits":["جواز إخبار المريض لمن سأله بما يجده من الألم.","الأنبياء ينالهم الوجع، والحكمة فيه زيادة في درجاتهم عند ربهم.","جواز مس المريض لمعرفة حاله.","المرض إذا اشتد عَظُم الأجر."],"wordsMeanings":[{"word":"يوعك","meaning":" يتألم من الحمى وغيرها."}],"category":"sirah","tags":["دخلت","على","النبي","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_6179","text":"عَنِ ابْنِ عَبَّاسٍ رضي الله عنهما قَالَ: كَانَ رَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَجْوَدَ النَّاسِ، وَكَانَ أَجْوَدُ مَا يَكُونُ فِي رَمَضَانَ حِينَ يَلْقَاهُ جِبْرِيلُ، وَكَانَ يَلْقَاهُ فِي كُلِّ لَيْلَةٍ مِنْ رَمَضَانَ فَيُدَارِسُهُ القُرْآنَ، فَلَرَسُولُ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَجْوَدُ بِالخَيْرِ مِنَ الرِّيحِ المُرْسَلَةِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"كَانَ النبيُّ صلى الله عليه وسلم أعظم الناس كَرمًا، وكان يَكثر كرمُه في شهر رمضان حيث كان يُعطي ما ينبغي لمَن ينبغي، والسبب في زيادة كرمه أمران: \n\nالأول: الْتِقاؤه بجبريل عليه السلام.\n\nوالأمر الآخر: مدارسة القرآن، وهو القراءة عن ظهر قلب.\n\nفيدارسه جبريل عليه السلام جميع ما نزل من القرآن، ولَرَسُول الله صلى الله عليه وسلم أكرم وأكثر عطاءً وفعلًا للخير، وأسرع نفعًا للخلق من الريح الطيبة التي يرسلها الله بالغيث والرحمة.","reference":"صحيح البخاري (1/ 8) (6).\nصحيح مسلم (4/ 1803) (2308).\nشرح رياض الصالحين، لابن عثيمين (5/ 275).\nنزهة المتقين شرح رياض الصالحين، مجموعة من الباحثين (2/ 870).\nبهجة الناظرين، لسليم الهلالي (2/ 364).\nكنوز رياض الصالحين، لمجموعة من الباحثين.","benefits":["بيان جُود النبي صلى الله عليه وسلم وسَعَة كرمه وخاصة في رمضان، فإنه شهر الطاعات ومواسم الخيرات.","الحث على الجود في كل وقت، وتستحب الزيادة في شهر رمضان.","الإكثار من البذل والعطاء والإحسان وقراءة القرآن في شهر رمضان.","من أسباب حفظ العلم مدارسته مع طلاب العلم والعلماء."],"wordsMeanings":[],"category":"sirah","tags":["كان","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_6219","text":"عن أبي هريرة رضي الله عنه عن النبيِّ صلى الله عليه وسلم قال: \"ما بَعَثَ اللهُ نبياً إلا رَعَى الغَنَمَ\"، فقالَ أصحابُهُ: وأنتَ؟، قال: \"نعم، كُنتُ أرعَاها على قَرَارِيطَ لأهلِ مكةَ\".","attribution":"رواه البخاري","grade":"صحيح","gradeKey":"sahih","explanation":"كل الأنبياء رعوا الغنم في حياتهم، وظاهر الحديث أن ذلك قبل النبوة، لذلك قال العلماء: الحكمة من ذلك أن يتمرن الإنسان على رعاية الخلق وتوجيههم إلى ما فيه الصلاح؛ لأن الراعي للغنم تارة يوجهها للمرعى وتارة يبقيها واقفة وتارة يردها إلى المراح، فالنبي -عليه الصلاة والسلام- سيرعى الأمة ويوجهها إلى الخير عن علم وهدى وبصيرة كالراعي الذي عنده علم بالمراعي الحسنة، وعنده نصح وتوجيه للغنم إلى ما فيه خيرها، وما فيه غذاؤها وسقاؤها.\nواختيرت الغنم لأن صاحب الغنم متصف بالسكينة والهدوء والاطمئنان بخلاف الإبل، فإن أصحابها في الغالب عندهم شدة وغلظة، لأن الإبل كذلك فيها الشدة والغلظة، فلهذا اختار الله سبحانه وتعالى لرسله أن يرعوا الغنم حتى يتعودوا ويتمرنوا على رعاية الخلق.","reference":"بهجة  الناظرين شرح رياض الصالحين، تأليف سليم الهلالي، دار ابن الجوزي.\nتطريز رياض الصالحين، تأليف فيصل آل مبارك، تحقيق د. عبدالعزيز آل حمد، دار العاصمة - الرياض، الطبعة الأولى، 1423هـ.\nرياض الصالحين من كلام سيد المرسلين، للإمام أبي زكريا النووي، تحقيق د. ماهر الفحل، دار ابن كثير - دمشق، الطبعة الأولى، 1428هـ.\nشرح رياض الصالحين، للشيخ محمد بن صالح العثيمين، مدار الوطن - الرياض، 1426هـ.\nصحيح البخاري،","benefits":["تواضع الأنبياء -عليهم الصلاة والسلام- باشتغالهم بأبسط الحِرَف.","يستحب للعبد أن يتكسب ويطلب الرزق وإن قل، ففيه البركة لمن قنع، ويجب أن يتحرى في ذلك أن يكون حلالًا.","الحكمة من رعي الأنبياء الغنم؛ ليتمرنوا بذلك على سياسة الأمم."],"wordsMeanings":[{"word":"قراريط","meaning":" جمع قيراط، وهو جزء من الدينار أو الدرهم."}],"category":"sirah","bookId":"bukhari","tags":["بعث","الله","نبيًّا","إلا","رعى","الغنم"],"source":"hadeethenc"},{"id":"he_6222","text":"عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ رَسُولَ اللهِ صلَّى الله عليه وسلم قال: «ما مِنْ أحَدٍ يُسلِّمُ علي إلا ردَّ اللهُ عليَّ رُوحي حتى أردَّ عليه السَّلامَ».","attribution":"رواه أبو داود وأحمد","grade":"إسناده حسن","gradeKey":"hasan","explanation":"يُخْبِرُ النبيُّ صلى الله عليه وسلم أنّه تُرَدُّ إليه رُوحُه ليَرُدَّ السلامَ على كل مَن سلَّم عليه سواء كان قريبًا أو بعيدًا؛ وحياة البَرْزَخ والقبور أمرٌ غيبي، لا يَعلم حقيقتَها إلا الله، وهو على كل شيء قدير.","reference":"سنن أبي داود (3/ 384) (2041).\nمسند أحمد (16/ 477) (10815).\nبهجة الناظرين شرح رياض الصالحين، لسليم الهلالي (2/ 486).\nشرح رياض الصالحين، لابن عثيمين (5/ 477).\nنزهة المتقين شرح رياض الصالحين، لمجموعة من الباحثين (2/ 964).","benefits":["الحث على الإكثار من الصلاة والسلام على النبي صلى الله عليه وسلم.","حياة النبي صلى الله عليه وسلم في قبره هي أكملُ حياة يحياها إنسان في بَرْزَخِه، فلا يَعلم حقيقتها إلا الله تعالى.","الحديث ليس فيه حُجّة لمن يقول بحياة رسول الله صلى الله عليه وسلم حياةً كما نعيشها نحن، حتى لا يَستدِلّ به أهل الشرك على الاستغاثة به عليه الصلاة والسلام، وإنما هي حياة برزخية."],"wordsMeanings":[],"category":"sirah","bookId":"abudawud","tags":["أحد","يسلم","علي","إلا","الله","علي"],"source":"hadeethenc"},{"id":"he_10603","text":"عَنْ أَبِي سَعِيدٍ الخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ -وَكَانَ غَزَا مَعَ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشْرَةَ غَزْوَةً- قَالَ: سَمِعْتُ أَرْبَعًا مِنَ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، فَأَعْجَبْنَنِي، قَالَ: «لاَ تُسَافِرِ المَرْأَةُ مَسِيرَةَ يَوْمَيْنِ إِلَّا وَمَعَهَا زَوْجُهَا أَوْ ذُو مَحْرَمٍ، وَلاَ صَوْمَ فِي يَوْمَيْنِ: الفِطْرِ وَالأَضْحَى، وَلاَ صَلاَةَ بَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ، وَلاَ بَعْدَ العَصْرِ حَتَّى تَغْرُبَ، وَلاَ تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلاَثَةِ مَسَاجِدَ: مَسْجِدِ الحَرَامِ، وَمَسْجِدِ الأَقْصَى، وَمَسْجِدِي هَذَا».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"نَهَى النبيُّ صلى الله عليه وسلم عَن أربعة أمور: \n\nأولها: منع المرأة من السفر مَسيرة يومين بدون زوجِها أو أحدٍ محارمِها وهو مَن حَرُمتْ عليه تحريمًا مؤبدًا مِن الأقارب، كالابن والأب، وابن الأخ وابن الأخت، والعم والخال، ونحو ذلك. \n\nثانيها: النهي عن صوم يوم عيد الفطر ويوم عيد الأضحى، وسواء صامهما المسلم عن نَذْر، أو تطوُّع، أو كفارة. \n\nثالثها: النهي عن صلاة التطوع بعد صلاة العصر حتى تغرب الشمس، وبعد طلوع الصبح حتى تطلع الشمس. \n\nرابعها: النهي عن السفر إلى بُقْعَة من البِقاع واعتقاد فضلها واعتقاد مضاعفة الحسنات فيها غير هذه المساجد الثلاثة فلا تُشد الرحال لغيرها لأجل الصلاة فيها، فإنَّ الأجر لا يُضاعف إلا في هذه المساجد الثلاثة، المسجد الحرام، والمسجد النبوي، والمسجد الأقصى.","reference":"صحيح البخاري (3/ 43) (1995).\nصحيح مسلم (2/ 975) (827).\nفتح الباري شرح صحيح البخاري، لابن حجر العسقلاني (4/ 75).\nتوضيح الأحكام مِن بلوغ المرام، للبسام (3/ 544).\nفتح ذي الجلال والإكرام شرح بلوغ المرام، لابن عثيمين (3/ 311).\nسبل السلام، لمحمد الصنعاني (1/ 598).\nمجموع فتاوى ومقالات، لابن باز(6/ 321).\nالشرح الممتع على زاد المستقنع، لابن عثيمين (6/ 516).\nشرح سنن أبي داود، عبد المحسن العباد (65/ 8 بترقيم","benefits":["عَدم جواز سَفر المرأة بلا مَحْرم.","المرأة ليست محرمًا للمرأة في السَّفر؛ لقوله: \"زوجُها أو ذو محرم\".","كلُّ ما يُسمى سفرًا فإن المرأة تُنهى عنه بغير زوج أو مَحرم، وهذا الحديث كان بحسب حال السائل وموطنه.","مَحْرَم المرأة هو زوجها أو من يحرم عليها الزواج منه بالتأبيد بسببِ قرابةٍ كالأب والابن والعم والخال، أو رضاع كالأب من الرضاع والعم من الرضاع، أو مصاهرة كأبي الزوج، ويكون مسلمًا بالغًا عاقلًا ثقة مأمونًا، فإنَّ المقصود من المحرم حمايةُ المرأة وصيانتُها والقيام بشأنها.","اعتناء الشريعة الإسلامية بالمرأة، وحمايتها وصَونها.","عدم صحة صلاة التطوع المُطْلق بعد صلاة الفجر والعصر، ويُستثنى مِن ذلك قضاء الفرائض الفوائت، وذوات الأسباب كتحيَّة المسجد ونحو ذلك.","تَحْرُم الصلاة بعد طلوع الشمس مباشرة، بل لابد من ارتفاعها قَدْرَ رمحٍ، بما يُقارب عشرَ دقائق إلى ربع ساعة تقريبًا.","وقت العصر يَمتدُّ إلى غروب الشمس.","فيه جواز شَد الرِّحال إلى المساجد الثلاثة.","فضل المساجد الثلاثة ومَزِيَّتُها على غيرها.","عدم جواز السفر لزيارة القبور ولو كان قَبر النبي صلى الله عليه وسلم، وتجوز زيارته لمن كان في المدينة، أو أتى إليها لغرضٍ مشروعٍ أو جائز."],"wordsMeanings":[],"category":"sirah","tags":["تسافر","المرأة","مسيرة","يومين","إلا","ومعها"],"source":"hadeethenc"},{"id":"he_10959","text":"عن عائشة رضي الله عنها ، قالت: «قُبِض رسولُ الله صلى الله عليه وسلم ورأسُه بين سَحْري ونَحْري»، قالت: «فلمَّا خَرَجَتْ نفْسُه، لم أَجِدْ ريحا قَطُّ أطْيَبَ منها».","attribution":"رواه أحمد","grade":"صحيح","gradeKey":"sahih","explanation":"تخبر عائشة زوج النبي صلى الله عليه وسلم أن النبي صلى الله عليه وسلم مات وهو مستند إلى صدرها، فلما خرجت روحه، شمت رائحة طيبة، لم تشم رائحة أطيب منها.","reference":"- مسند الإمام أحمد بن حنبل، تحقيق: شعيب الأرنؤوط - عادل مرشد، وآخرون، نشر: مؤسسة الرسالة، الطبعة: الأولى، 1421هـ - 2001م.\n- النهاية في غريب الحديث والأثر، لابن الأثير، نشر: المكتبة العلمية - بيروت، 1399هـ - 1979م، تحقيق: طاهر أحمد الزاوى - محمود محمد الطناحي.\n- تاج العروس من جواهر القاموس، للزبيدي، نشر: دار الهداية.\n- معجم اللغة العربية المعاصرة، للدكتور أحمد مختار عبد الحميد عمر بمساعدة فريق عمل،","benefits":["فيه معجزة واضحة للنبي -صلى الله عليه وسلم- عند موته، حيث شمت عائشة عند موته رائحة طيبة لم تشم رائحة أطيب منها.","مات النبي -صلى الله عليه وسلم- وهو مستند إلى صدر عائشة.","في الحديث فضيلة ظاهرة لعائشة، وأن الله اختارها ليموت النبي -صلى الله عليه وسلم- عندها وعلى صدرها."],"wordsMeanings":[{"word":"قُبِض","meaning":" مات."},{"word":"سَحْري","meaning":" السحر: الرئة."},{"word":"نَحْري","meaning":" النحر: أعلى الصدر, عند موضع القلادة."}],"category":"sirah","bookId":"ahmed","tags":["قبض","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_10970","text":"عن أنس رضي الله عنه ، قال: «لم يكن شخصٌ أَحَبَّ إليهم مِن رسول الله -صلى الله عليه وسلم، وكانوا إذا رَأَوْه لم يقوموا لِمَا يَعْلَمون مِن كَرَاهِيَته لذلك».","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر أنس رضي الله عنه أنه لم يكن أحد أشد حبًّ إلى الصحابة من رسول الله صلى الله عليه وسلم ، ومع حبهم الشديد له صلى الله عليه وسلم كانوا إذا رأوه مقبلًا عليهم لم يقوموا له؛ لأنهم يعلمون أنه صلى الله عليه وسلم يكره أن يقوم له أحد.","reference":"- سنن الترمذي، نشر: شركة مكتبة ومطبعة مصطفى البابي الحلبي – مصر، الطبعة: الثانية، 1395هـ - 1975م.\n- مسند الإمام أحمد بن حنبل، تحقيق: شعيب الأرنؤوط - عادل مرشد، وآخرون، نشر: مؤسسة الرسالة، الطبعة: الأولى، 1421هـ - 2001م.\n- مشكاة المصابيح، تحقيق الألباني، نشر: المكتب الإسلامي – بيروت، الطبعة: الثالثة، 1985م.\n- فتح الباري شرح صحيح البخاري, أحمد بن علي بن حجر العسقلاني الشافعي, دار المعرفة - بيروت، 13","benefits":["شدة تواضع النبي -صلى الله عليه وسلم- وكراهيته للقيام له.","كان الصحابة -رضي الله عنهم- يحبون النبي -صلى الله عليه وسلم- أكثر من حب أي أحد.","كراهية القيام للقادم, ما لم يكن هناك سبب للقيام كتلقي القادم من السفر أو التهنئة أو نحو ذلك من الأسباب."],"wordsMeanings":[],"category":"sirah","bookId":"tirmidhi","tags":["يكن","شخص","أحب","إليهم","رسول","الله"],"source":"hadeethenc"},{"id":"he_10973","text":"عن عائشة رضي الله عنها ، أنها سُئلتْ ما كان رسول الله صلى الله عليه وسلم يَعْمل في بيته؟ قالت: «كان بشرًا مِن البشر يَفْلي ثوبَه، ويَحْلِب شاتَه، ويَخْدِم نفْسَه».","attribution":"رواه أحمد","grade":"صحيح","gradeKey":"sahih","explanation":"سُئلت عائشة زوج النبي صلى الله عليه وسلم : ما الذي كان يعمله رسول الله صلى الله عليه وسلم في بيته؟ فقالت: كان بشرًا من البشر، يلتقط القمل والأذى من ثوبه، ويحلب شاتَه، ويخدم نفسَه، وذكرت هذه الأعمال من باب التمثيل.","reference":"- مسند الإمام أحمد بن حنبل، تحقيق: شعيب الأرنؤوط - عادل مرشد، وآخرون، نشر: مؤسسة الرسالة، الطبعة: الأولى، 1421هـ - 2001م.\n- مرقاة المفاتيح شرح مشكاة المصابيح، لعلي بن سلطان الملا الهروي القاري، الناشر: دار الفكر، بيروت – لبنان، الطبعة: الأولى، 1422هـ - 2002م.\n- سلسلة الأحاديث الصحيحة وشيء من فقهها وفوائدها، تأليف محمد ناصر الدين الألباني، الناشر: مكتبة المعارف للنشر والتوزيع، الرياض، الطبعة: الأول","benefits":["تواضع النبي -صلى الله عليه وسلم- فقد كان يباشر أعماله الخاصة في بيته بنفسه.","أن الأئمة والعلماء يتناولون خدمة أمورهم بأنفسهم، وأن ذلك من فعل الصالحين.","استحباب مساعدة الزوج لامرأته في عمل البيت.","النبي -صلى الله عليه وسلم- بشر كسائر البشر ولكن الله خصه بالرسالة."],"wordsMeanings":[{"word":"يَفْلي ثوبه","meaning":" يلتقط الشيء المؤذي من الثوب كالبرغوث والقمل ونحوه."}],"category":"sirah","bookId":"ahmed","tags":["سئلت","عائشة:","كان","رسول","الله","صلى"],"source":"hadeethenc"},{"id":"he_10975","text":"عن ابن عباس رضي الله عنهما قال: «بُعِث رسولُ الله صلى الله عليه وسلم لِأَربعين سَنَة، فَمَكَثَ بِمكة ثلاثَ عشرة سنة يوحَى إليه، ثم أُمِرَ بالهِجْرة فَهاجَر عشر سِنِين، ومات وهو ابنُ ثَلاثٍ وستِّين».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أفاد الحديث أن الوحي نزل على النبي صلى الله عليه وسلم وعمره أربعون سنة، فأقام بمكة ثلاث عشرة سنة يوحِي الله إليه، ثم أمره الله تعالى بالهجرة من مكة إلى المدينة، فأقام بها عشر سنين، ثم توفي بها، فيكون عمره ثلاثًا وستين سنة.","reference":"- صحيح البخاري، نشر: دار طوق النجاة (مصورة عن السلطانية بإضافة ترقيم محمد فؤاد عبد الباقي)، الطبعة: الأولى، 1422هـ.\n- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- معجم اللغة العربية المعاصرة، للدكتور أحمد مختار عبد الحميد عمر بمساعدة فريق عمل، الناشر: عالم الكتب، الطبعة: الأولى، 1429 هـ - 2008 م.\n- المفاتيح في شرح المصابيح, الحسين بن محمود بن الحسن المُظْهِري, تح","benefits":["ابتدأ نزول الوحي على النبي -صلى الله عليه وسلم- وعمره أربعون سنة.","أقام النبي -صلى الله عليه وسلم- بمكة ثلاث عشرة سنة يوحِي الله إليه.","أقام النبي -صلى الله عليه وسلم- بالمدينة عشر سنين بعد الهجرة.","توفي النبي -صلى الله عليه وسلم- وعمره ثلاث وستون سنة."],"wordsMeanings":[{"word":"مكث","meaning":" أقام."},{"word":"الوحي","meaning":" في اللغة الإشارة والرسالة والكتابة, وكل ما ألقي إلى الآخر ليعلمه وحي كيف كان, ثم غلب استعمال الوحي فيما يلقى إلى الأنبياء من عند الله -تعالى-."}],"category":"sirah","tags":["بُعِث","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_10976","text":"عن أنس رضي الله عنه قال: «آخِرُ نَظْرة نَظَرْتُها إلى رسول الله صلى الله عليه وسلم كَشَف السِّتارة والناسُ صُفوف خَلْف أبي بكر رضي الله عنه ، فأراد أبو بكر أنْ يَرْتَدَّ، فأشار إليهم أَنِ امكثُوا وأَلْقى السِّجْفَ، وتُوفِّي مِن آخِرِ ذلك اليوم، وذلك يومَ الإثنين».","attribution":"رواه النسائي, وأصله في مسلم","grade":"صحيح","gradeKey":"sahih","explanation":"آخر مرة نظر فيها أنس بن مالك إلى النبي صلى الله عليه وسلم أنه صلى الله عليه وسلم كشف الستارة التي بين حجرته وبين المسجد، فرأى الناس يصلون خلف أبي بكر في صفوف، فتنبه أبو بكر لذلك وظن أن النبي صلى الله عليه وسلم يريد أن يخرج للصلاة، فأراد أن يتأخر ويصلي في الصف؛ ليأتي النبي صلى الله عليه وسلم ويصلي بالناس، فأشار إليهم النبي صلى الله عليه وسلم آمرًا لهم بأن يظلوا في أماكنهم ويتموا صلاتهم، ثم أغلق الستارة مرة أخرى، وتوفي النبي صلى الله عليه وسلم من آخر ذلك اليوم، وهو يوم الإثنين.","reference":"- صحيح مسلم، تحقيق: محمد فؤاد عبد الباقي، نشر: دار إحياء التراث العربي – بيروت.\n- السنن الصغرى للنسائي \"المجتبى\"، تحقيق: عبد الفتاح أبو غدة، نشر: مكتب المطبوعات الإسلامية – حلب، الطبعة: الثانية، 1406ه – 1986م.\n- حاشية السندي على سنن ابن ماجه، لمحمد بن عبد الهادي التتوي نور الدين السندي، الناشر: دار الجيل – بيروت.\n- شرح سنن النسائي المسمى «ذخيرة العقبى في شرح المجتبى»، المؤلف: محمد بن علي بن آدم ال","benefits":["توفي النبي -صلى الله عليه وسلم- يوم الإثنين.","بيان فضل الموت يوم الاثنين، حيث اختاره اللَّه تعالى لنبيه -صلى اللَّه عليه وسلم-.","فضل أبي بكر -رضي اللَّه عنه-، حيث اختاره النبي -صلى اللَّه عليه وسلم- للإمامة في مرض موته، ولذا احتجّ الصحابة -رضي اللَّه عنهم- بذلك على استحقاقه الإمامةَ الكبرى، فبايعوه على الخلافة.","جواز استعمال الستارة على الأبواب، ونحوها للحاجة."],"wordsMeanings":[{"word":"يرتد","meaning":" أي يرجع عن مقامه إلى مقام المأمومين."},{"word":"امكثُوا","meaning":" ظلوا في أماكنكم."},{"word":"السِّجْف","meaning":" الستر."}],"category":"sirah","bookId":"muslim","tags":["آخر","نظرة","نظرتها","إلى","رسول","الله"],"source":"hadeethenc"},{"id":"he_11268","text":"عن أبي سَلمة بن عبد الرحمن، أنه أخْبَره: أنه سَأل عائشة رضي الله عنها ، كيف كانت صلاة رسول الله صلى الله عليه وسلم في رمضان؟ فقالت: «ما كان رسول الله صلى الله عليه وسلم يَزيد في رمضان ولا في غَيره على إحدى عَشرة ركعة يصلِّي أربعا، فلا تَسَل عن حُسْنِهِنَّ وَطُولِهِنَّ، ثم يصلِّي أربعا، فلا تَسَل عن حُسْنِهِنَّ وَطُولِهِنَّ، ثم يصلَّي ثلاثا». قالت عائشة: فقلت يا رسول الله: أتنام قبل أن توتر؟ فقال: «يا عائشة إن عَيْنَيَّ تَنَامَانِ ولا يَنام قَلْبِي»","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"معلوم أن النبي صلى الله عليه وسلم كان يقوم من الليل، سواء كان في رمضان أو في غيره؛ فلما كان كذلك سأل أبو سلمة عن قيام رمضان، هل صلاته صلى الله عليه وسلم في ليالي رمضان كصلاته في غير رمضان، من حيث عدد الركعات أو أن الأمر مختلف؟\nفأجابته رضي الله عنها بأنه لا فرق بين صلاته في رمضان ولا في غيره، فإنه كان يصلي على مدَار العام إحدى عَشرة ركعة لا يزيد عليها.\nثم بَيَّنت له كيفيتها بقولها : \"يصلِّي أربعا\" المراد أنه يصلِّي ركعتين، ثم يسلِّم، ثم يصلِّي ركعتين، ثم يسلِّم؛ لأن عائشة رضي الله عنها قد بَيَّنت وفصلت الإجمال في هذا الحديث في حديثها الآخر عند مسلم، حيث قالت: (كان رسول الله صلى الله عليه وسلم يصلِّي فيما بَيْن أن يَفرغ من صلاة العِشاء إلى الفجر، إحدى عَشَرة ركعة، يُسلِّم بَيْن كل ركعتين، ويوتر بواحدة). مع قوله صلى الله عليه وسلم : (صلاة الليل مَثْنَى مَثْنَى) متفق عليه. \n\"فلا تَسَل عن حُسْنِهِنَّ وَطُولِهِنّ\" أي: لا تسأل عن كيفيتهن، فإنهن في غاية الحُسن والكمال في جودة القراءة وطول القيام والرُّكوع والسُّجود. \nوكذلك الأربع الأخيرة ركعتين ركعتين، فلا تَسأل عن حُسنها وكمالها في جودة القراءة وطول القيام والرُّكوع والسُّجود. \n\"ثم يصلَّي ثلاثا\" ظاهر هذا: أنه يَسردهن سَرْدَا من غير فَصل، ثم يسلِّم في الرَّكعة الأخيرة، لكن رواية عائشة الأخرى بَيَّنت أنه يسلِّم من ركعتين، ثم يوتر بواحدة، ونصه :\" يُسلِّم بَيْن كل ركعتين، ويوتر بواحدة \"، فدل ذلك على أنه يَفْصِل بين الثلاث بالتَّسليم.\n \"قالت عائشة: فقلت يا رسول الله: أتَنَام قبل أن تُوتر؟\" أي: كيف تَنام قبل أن تصلِّي الوِتر.\n\"فقال: يا عائشة إن عَيْنَيَّ تَنَامَانِ ولا يَنام قلْبِي\" والمعنى: أن قَلبه صلى الله عليه وسلم لا يَغيب كما تَغيب عيناه، بل يُدرك ويَشعر بكل شَيء ومن ذلك: مُراعاة الوقت وضَبْطه، ولهذا كانت رؤية الأنبياء وحْي.","reference":"صحيح البخاري، تأليف: محمد بن إسماعيل البخاري، تحقيق: محمد زهير الناصر، الناشر: دار طوق النجاة الطبعة: الأولى، 1422هـ\nصحيح مسلم ، تأليف: مسلم بن الحجاج النيسابوري، تحقيق: محمد فؤاد عبد الباقي الناشر: دار إحياء التراث العربي – بيروت.\nسبل السلام شرح بلوغ المرام، تأليف : محمد بن إسماعيل بن صلاح الصنعاني، الناشر: دار الحديث الطبعة: بدون طبعة وبدون تاريخ\nتوضيح الأحكام مِن بلوغ المرام، تأليف: عبد الله بن","benefits":["أن قيام الليل إحدى عشرة ركعة يوتر منها بواحدة.","إجابة السَّائل بأكثر مما سأل؛ وجه ذلك: أنه سألها عن صلاته في رمضان، فأجابته عن صلاته في رمضان وفي غيره، وعن صفتها.","أن السُّنة في صلاة الليل إطالتها .","جواز الاستراحة بين ركعات صلاة القيام؛ لقولها: \"أربعا ثم أربعا \" وثم تفيد التَّرتيب مع التَّراخي.","أن وضوء النبي -صلى الله عليه وسلم- لا ينتقض بالنوم وهذا من خصائصه."],"wordsMeanings":[{"word":"لا توجد","meaning":""}],"category":"sirah","tags":["عائشة","عيني","تنامان","ولا","ينام","قلبي"],"source":"hadeethenc"},{"id":"he_65050","text":"عَنِ ‌ابْنِ عَبَّاسٍ رَضِيَ اللهُ عَنْهُمَا قَالَ: أُنْزِلَ عَلَى رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ وَهُوَ ابْنُ أَرْبَعِينَ، فَمَكَثَ بِمَكَّةَ ثَلَاثَ عَشْرَةَ سَنَةً، ثُمَّ أُمِرَ بِالْهِجْرَةِ، فَهَاجَرَ إِلَى الْمَدِينَةِ، فَمَكَثَ بِهَا عَشْرَ سِنِينَ، ثُمَّ تُوُفِّيَ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر ابن عباس رضي الله عنهما: أن الوحي أنزل على رسول الله صلى الله عليه وسلم وبُعث وعمره أربعون سنة، \nفأقام بمكة ثلاث عشرة سنة بعد الوحي، \nثم أُمِرَ بالهجرة إلى المدينة وأقام بها عشر سنين، \nثم توفي صلى الله عليه وسلم وعمره ثلاثٌ وستون سنة.","reference":"صحيح البخاري (5/ 45) (3851)، صحيح مسلم (4/ 1826) (2351)، عمدة القاري شرح صحيح البخاري (16/ 303).","benefits":["اهتمام الصحابة بسيرة النبي صلى الله عليه وسلم."],"wordsMeanings":[],"category":"sirah","tags":["أنزل","على","رسول","الله","صلى","الله"],"source":"hadeethenc"},{"id":"he_65485","text":"عن أنس قال: قدم رسول الله صلى الله عليه وسلم المدينة ولهم يومان يلعبون فيهما، فقال: \"ما هذان اليومان؟\" قالوا: كنا نلعب فيهما في الجاهلية، فقال رسول الله صلى الله عليه وسلم: \"إن الله قد أبدلكم بهما خيرا منهما: يوم الأضحى، ويوم الفطر\".","attribution":"رواه أبو داود والنسائي","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر أنس رضي الله عنه أنه عند قدوم رسول الله صلى الله عليه وسلم إلى المدينة، كان لهم يومان يلعبون فيهما، فلما سألهم عن هذين اليومين، قالوا: إنهم كانوا يلعبون فيهما في الجاهلية، فأخبر النبي صلى الله عليه وسلم أن الله تعالى أبدلنا في الإسلام ما هو خير منهما، وهما عيد الفطر وعيد الأضحى، وهما يوما فرح بالعبادة وبالقربى وإكمال العمل الصالح.\nوضابط العيد اليوم أو الأيام التي تعود وتتكرر ويكون فيها مظاهر احتفال وراحة ونحو ذلك، سواء كان عامًّا أم خاصًّا، وهذان العيدان هما المشروعان في الإسلام، والأعياد الأخرى محدثة، بدلالة هذا الحديث، وورد تسمية الجمعة عيدًا، ولكنها عيد أسبوعي؛ لأنها تتكرر كل أسبوع.","reference":"سنن أبي داود (2/ 345) (1134)، سنن النسائي (3/ 179) (1556)، شرح سنن أبي داود للعباد (141/ 22)، فتاوى اللجنة الدائمة - المجموعة الأولى (3/ 86) (11/ 436).","benefits":["الأعياد المشروعة في الإسلام هما الأضحى والفطر، والأعياد الأخرى محدثة.","الإسلام أبطل أعياد الجاهلية، ويلحق بها ما أُحدث بعد ذلك.","لا يدخل في العيد ما يسمى بأسبوع الشجرة أو أسبوع المرور ونحو ذلك؛ لأنها ليس فيها احتفال وإجازة.","يدخل في الأعياد المحدثة عيد الحب وعيد الأم وعيد الميلاد وعيد الزواج."],"wordsMeanings":[{"word":"يوم الأضحى","meaning":" العاشر من شهر ذي الحجة."},{"word":"يوم الفطر","meaning":" الأول من شهر شوال."}],"category":"sirah","bookId":"abudawud","tags":["قدم","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_65781","text":"عن ابن عمر قال: قال النبي صلى الله عليه وسلم لنا لما رجع من الأحزاب: «لا يُصليَنَّ أحدٌ العصر إلا في بني قريظة» فأدرك بعضهم العصر في الطريق، فقال بعضهم: لا نصلي حتى نأتيها، وقال بعضهم: بل نصلي، لم يُرِدْ منَّا ذلك، فذُكِرَ للنبي صلى الله عليه وسلم، فلم يعنف واحدًا منهم.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"لما رجع النبي صلى الله عليه وسلم من غزوة الأحزاب قال لأصحابه: لا يُصَلِّينَّ أحدٌ صلاةَ العصر إلا في بني قريظة، وهم من اليهود، وقد غدروا لما جاء المشركون للمدينة وتفاجؤوا بالخندق، فوقفوا مع المشركين ظنًّا منهم أنهم سينتصرون على المسلمين، وفي طريق الذهاب حضرت صلاة العصر، فقال فريق من الصحابة: لا نصلي العصر حتى نصل إلى بني قريظة؛ لأنه ظاهر النهي النبوي، وقال فريق: بل نصلي؛ لأن مفهوم قوله عليه الصلاة والسلام السرعة في الذهاب إلى بني قريظة، وعدم الانتظار، ولم يرد حقيقة عدم صلاتهم، فلما أخبروه لم يُعنِّفِ النبيُّ صلى الله عليه وسلم واحدةً من الطائفتين؛ لأن المسألة محتملة للقولين جميعًا.","reference":"صحيح البخاري (2/ 15) (946)، النهاية في غريب الحديث والأثر (645).","benefits":["أن المسائل العلمية على نوعين: نوع منها صريح الدلالة، ولا يحتمل إلا معنى واحد، فلا يجوز الخروج فيه عن النص، ونوع محتمل لمعان احتمالًا صحيحًا، فيسوغ فيها الخلاف، مع سلامة المقصد.","أن الصحابة كانوا يجتهدون في فهم النصوص الشرعية في عهد النبي صلى الله عليه وسلم؛ لأنهم أهلٌ لذلك."],"wordsMeanings":[{"word":"فأدرك بعضهم العصر في الطريق","meaning":" حضر وقت العصر وهم في الطريق."},{"word":"حتى نأتيها","meaning":" ديار بني قريظة."},{"word":"فلم يعنف","meaning":" لم يوبّخ ولم يقرّع."}],"category":"sirah","tags":["يُصليَنَّ","أحدٌ","العصر","إلا","بني","قريظة"],"source":"hadeethenc"},{"id":"he_65788","text":"عن طارق بن عبد الرحمن قال: انطلقت حاجًّا، فمررت بقوم يصلون، قلت: ما هذا المسجد؟ قالوا: هذه الشجرة، حيث بايع رسول الله صلى الله عليه وسلم بيعة الرضوان، فأتيت سعيد بن المسيب فأخبرته، فقال سعيد: حدثني أبي أنه كان فيمن بايع رسول الله صلى الله عليه وسلم تحت الشجرة، قال: فلما خرجنا من العام المقبل نسيناها، فلم نقدر عليها، فقال سعيد: إن أصحاب محمد صلى الله عليه وسلم لم يَعلموها، وعلمتموها أنتم، فأنتم أعلم؟!","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر طارق بن عبد الرحمن البجلي الكوفي رحمه الله أنه عندما ذهب إلى الحج، مرَّ بقومٍ يصلون، فسألهم عن المسجد الذي يصلون فيه، فقالوا: هذه الشجرة التي بايع النبي صلى الله عليه وسلم الصحابة تحتها بيعة الرضوان، عام الحديبية، وقد كانوا جعلوا تحتها مسجدًا يصلون فيه،  فجاء طارقٌ إلى سعيد بن المسيب، عالم المدينة، فأخبره بالقوم الذين يصلون وبما قالوه، فقال سعيد: إن أبي كان ممن بايع النبي صلى الله عليه وسلم تحت الشجرة، فقال المسيب والد سعيد: فلما رجع الصحابة في العام الذي يليه، وهي السنة السابعة؛ لأن البيعة كانت في السادسة، نسوا مكان الشجرة ولم يستطيعوا تذكُّر مكانها، قال سعيد: إن الصحابة لم يعلموا مكانها وأنتم علمتم مكانها، فهل أنتم أعلم من الصحابة، قالها تهكمًا وإنكارًا عليهم.","reference":"صحيح البخاري (5/ 124) (4163)، صحيح مسلم (3/ 1485) (1859)، شرح النووي على مسلم (13/ 5)، إرشاد الساري لشرح صحيح البخاري (6/ 349).","benefits":["الدلالة على كذب من يدعي بمعرفة مكان الشجرة، إذ إن الصحابة رضوان الله عليهم لم يعلموا مكانها.","الحكمة من نسيان الصحابة مكان الشجرة لئلا يتخذها من بعدهم معبدًا ولا يعظموها، فيقعوا في غلو الأمم السابقة."],"wordsMeanings":[{"word":"قلم نقدر عليها","meaning":" لم يعرفوا مكانها ولم يتذكروه."},{"word":"فأنتم أعلم","meaning":" قالها تهكمًا وتعجبًا."}],"category":"sirah","tags":["أصحاب","محمد","صلى","الله","عليه","وسلم"],"source":"hadeethenc"},{"id":"he_65811","text":"عن عبد الله بن الحارث بن جَزْءٍ قال: ما كان ضحك رسول الله صلى الله عليه وسلم إلا تبسُّمًا.","attribution":"رواه الترمذي","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر عبد الله بن الحارث رضي الله عنه أن النبي صلى الله عليه وسلم كان إذا ضحك لا يزيد على التبسم، وهو الضحك بدون إصدار صوت، فهذا من هديه عليه الصلاة والسلام، والمراد وجود السبب العارض الذي يحمل على الضحك، أما البشاشة في وجوه الآخرين وعدم العبوس فقد كان من خُلقه عليه الصلاة والسلام، كما في حديث جرير: ما حجبني رسول الله صلى الله عليه وسلم منذ أسلمت، ولا رآني إلا تبسم في وجهي. متفق عليه.\nوبناءً عليه فإما أن تُحمل أحاديث الضحك النبوي على مجرد التبسم، أو أن يكون المراد بهذا الحديث الأعم الأغلب من أحواله عليه الصلاة والسلام، وعلى كل حال دلت النصوص على أنه لم يكن يضحك بملء فمه ويقهقه ويبالغ في الضحك مطلقًا، عليه الصلاة والسلام.","reference":"سنن الترمذي (6/ 38) (3642)، صحيح البخاري (4/ 65) (3035)، صحيح مسلم (4/ 1925) (2475)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (9/ 336)، تحفة الأحوذي (10/ 87).","benefits":["جواز التبسم.","التبسم من صفات النبي صلى الله عليه وسلم وهديه.","الاقتصاد في الضحك من اعتدال الشخصية وكمال الخلق، وكثرةالضحك تميت القلب."],"wordsMeanings":[{"word":"تبسما","meaning":" ضحكًا خفيفًا بدون صوت."}],"category":"sirah","bookId":"tirmidhi","tags":["كان","ضحك","رسول","الله","صلى","الله"],"source":"hadeethenc"},{"id":"he_65825","text":"عن عائشة رضي الله عنها: أن أزواج النبي صلى الله عليه وسلم حين توفي رسول الله صلى الله عليه وسلم أَرَدْنَ أن يبعثْنَ عثمان إلى أبي بكر يسألنه ميراثهن، فقالت عائشة: أليس قد قال رسول الله صلى الله عليه وسلم: «لا نورث، ما تركنا صدقةٌ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"عندما توفى النبي صلى الله عليه وسلم أرادت زوجاته أمهات المؤمنين رضي الله عنهن أن يُرسلن عثمان بن عفان إلى أبي بكر رضي الله عنهما، يطلبن ميراثهن من رسول الله صلى الله عليه وسلم، من العقار والمتاع الذي خلَّفَه، فقالت عائشة: ألم يذكر النبي عليه الصلاة والسلام أن الأنبياء لا يُورثون، وما يتركونه من مال أو متاع فهو صدقة؟ وقيل: إن الحكمة في كونه لا يورث حسم المادة في تمني الوارث موت المورِّث من أجل المال، وقيل لكون النبي كالأب لأمته فيكون ميراثه للجميع، وهو معنى الصدقة العامة، ولغير ذلك من الحِكم.","reference":"صحيح البخاري (8/ 150) (6730)، صحيح مسلم (3/ 1379) (1758)، إرشاد الساري لشرح صحيح البخاري (9/ 426).","benefits":["الأنبياء لا يورثون كما يُورَث سائر الناس.","فقه وعلم عائشة رضي الله عنها."],"wordsMeanings":[],"category":"sirah","tags":["نورث،","تركنا","صدقةٌ"],"source":"hadeethenc"},{"id":"he_66227","text":"عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْ: سُئِلَ النَّبِيُّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ: أَيُّ الأَعْمَالِ أَحَبُّ إِلَى اللَّهِ؟ قَالَ: «أَدْوَمُهَا وَإِنْ قَلَّ» وَقَالَ: «اكْلَفُوا مِنَ الأَعْمَالِ مَا تُطِيقُونَ».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"سُئل النبي صلى الله عليه وسلم: ماهي أحب الأعمال إلى الله؟ قال: ما كان صاحبها أكثر دوامًا عليها وثباتًا، وإن كان العملُ قليلًا، فالمداومة على عمل من أعمال البر ولو كان مفضولًا أحبُّ إلى الله من عمل يكون أعظم أجرًا لكن ليس فيه مداومة، وقال عليه الصلاة والسلام: تحمَّلوا وعالجوا العمل المستحب الذي تطيقونه؛ ليحصل لكم الدوام عليه من غير توقف في المستقبل.","reference":"صحيح البخاري (8/ 98) (6465)، صحيح مسلم (1/ 541) (783)، إرشاد الساري لشرح صحيح البخاري (9/ 266)، ذخيرة العقبى في شرح المجتبى (9/ 487).","benefits":["الحث على المداومة على العمل، وأن قليله الدائم خير من كثير ينقطع، وإنما كان القليل الدائم خير من الكثير المنقطع؛ لأن بدوام القليل تدوم الطاعة والذكر والمراقبة.","النهي عن تكلف النفس مالا تطيقه من الأعمال.","المراد بالحديث عمل التطوع والنافلة."],"wordsMeanings":[{"word":"اكلفوا","meaning":" عالجوا وباشروا."}],"category":"sirah","tags":["اكْلَفُوا","الأعمال","تطيقون"],"source":"hadeethenc"},{"id":"he_66313","text":"عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ مَالِكِ بْنِ صَعْصَعَةَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ نَبِيَّ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُمْ عَنْ لَيْلَةِ أُسْرِيَ بِهِ: «بَيْنَمَا أَنَا فِي الحَطِيمِ -وَرُبَّمَا قَالَ: فِي الحِجْرِ- مُضْطَجِعًا إِذْ أَتَانِي آتٍ، فَقَدَّ -قَالَ: وَسَمِعْتُهُ يَقُولُ: فَشَقَّ- مَا بَيْنَ هَذِهِ إِلَى هَذِهِ -فَقُلْتُ لِلْجَارُودِ وَهُوَ إِلَى جَنْبِي: مَا يَعْنِي بِهِ؟ قَالَ: مِنْ ثُغْرَةِ نَحْرِهِ إِلَى شِعْرَتِهِ، وَسَمِعْتُهُ يَقُولُ: مِنْ قَصِّهِ إِلَى شِعْرَتِهِ- فَاسْتَخْرَجَ قَلْبِي، ثُمَّ أُتِيتُ بِطَسْتٍ مِنْ ذَهَبٍ مَمْلُوءَةٍ إِيمَانًا، فَغُسِلَ قَلْبِي، ثُمَّ حُشِيَ ثُمَّ أُعِيدَ، ثُمَّ أُتِيتُ بِدَابَّةٍ دُونَ البَغْلِ، وَفَوْقَ الحِمَارِ أَبْيَضَ، -فَقَالَ لَهُ الجَارُودُ: هُوَ البُرَاقُ يَا أَبَا حَمْزَةَ؟ قَالَ أَنَسٌ: نَعَمْ- يَضَعُ خَطْوَهُ عِنْدَ أَقْصَى طَرْفِهِ، فَحُمِلْتُ عَلَيْهِ، فَانْطَلَقَ بِي جِبْرِيلُ حَتَّى أَتَى السَّمَاءَ الدُّنْيَا فَاسْتَفْتَحَ، فَقِيلَ مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: وَمَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: وَقَدْ أُرْسِلَ إِلَيْهِ؟ قَالَ: نَعَمْ، قِيلَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَفَتَحَ، فَلَمَّا خَلَصْتُ فَإِذَا فِيهَا آدَمُ، فَقَالَ: هَذَا أَبُوكَ آدَمُ فَسَلِّمْ عَلَيْهِ، فَسَلَّمْتُ عَلَيْهِ، فَرَدَّ السَّلاَمَ، ثُمَّ قَالَ: مَرْحَبًا بِالِابْنِ الصَّالِحِ، وَالنَّبِيِّ الصَّالِحِ، ثُمَّ صَعِدَ بِي حَتَّى أَتَى السَّمَاءَ الثَّانِيَةَ، فَاسْتَفْتَحَ قِيلَ: مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: وَمَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: وَقَدْ أُرْسِلَ إِلَيْهِ؟ قَالَ: نَعَمْ، قِيلَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَفَتَحَ، فَلَمَّا خَلَصْتُ إِذَا يَحْيَى وَعِيسَى، وَهُمَا ابْنَا الخَالَةِ، قَالَ: هَذَا يَحْيَى وَعِيسَى فَسَلِّمْ عَلَيْهِمَا، فَسَلَّمْتُ فَرَدَّا، ثُمَّ قَالاَ: مَرْحَبًا بِالأَخِ الصَّالِحِ، وَالنَّبِيِّ الصَّالِحِ، ثُمَّ صَعِدَ بِي إِلَى السَّمَاءِ الثَّالِثَةِ، فَاسْتَفْتَحَ، قِيلَ: مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: وَمَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: وَقَدْ أُرْسِلَ إِلَيْهِ؟ قَالَ: نَعَمْ، قِيلَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَفُتِحَ، فَلَمَّا خَلَصْتُ إِذَا يُوسُفُ، قَالَ: هَذَا يُوسُفُ فَسَلِّمْ عَلَيْهِ، فَسَلَّمْتُ عَلَيْهِ، فَرَدَّ ثُمَّ قَالَ: مَرْحَبًا بِالأَخِ الصَّالِحِ وَالنَّبِيِّ الصَّالِحِ، ثُمَّ صَعِدَ بِي حَتَّى أَتَى السَّمَاءَ الرَّابِعَةَ فَاسْتَفْتَحَ، قِيلَ: مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: وَمَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: أَوَقَدْ أُرْسِلَ إِلَيْهِ؟ قَالَ: نَعَمْ، قِيلَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَفُتِحَ، فَلَمَّا خَلَصْتُ إِلَى إِدْرِيسَ قَالَ: هَذَا إِدْرِيسُ فَسَلِّمْ عَلَيْهِ فَسَلَّمْتُ عَلَيْهِ، فَرَدَّ ثُمَّ قَالَ: مَرْحَبًا بِالأَخِ الصَّالِحِ وَالنَّبِيِّ الصَّالِحِ، ثُمَّ صَعِدَ بِي، حَتَّى أَتَى السَّمَاءَ الخَامِسَةَ فَاسْتَفْتَحَ، قِيلَ: مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: وَمَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: وَقَدْ أُرْسِلَ إِلَيْهِ؟ قَالَ: نَعَمْ، قِيلَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَلَمَّا خَلَصْتُ فَإِذَا هَارُونُ، قَالَ: هَذَا هَارُونُ فَسَلِّمْ عَلَيْهِ، فَسَلَّمْتُ عَلَيْهِ، فَرَدَّ ثُمَّ قَالَ: مَرْحَبًا بِالأَخِ الصَّالِحِ، وَالنَّبِيِّ الصَّالِحِ، ثُمَّ صَعِدَ بِي حَتَّى أَتَى السَّمَاءَ السَّادِسَةَ، فَاسْتَفْتَحَ، قِيلَ: مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: مَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: وَقَدْ أُرْسِلَ إِلَيْهِ؟ قَالَ: نَعَمْ، قَالَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَلَمَّا خَلَصْتُ فَإِذَا مُوسَى، قَالَ: هَذَا مُوسَى فَسَلِّمْ عَلَيْهِ، فَسَلَّمْتُ عَلَيْهِ، فَرَدَّ ثُمَّ قَالَ: مَرْحَبًا بِالأَخِ الصَّالِحِ، وَالنَّبِيِّ الصَّالِحِ، فَلَمَّا تَجَاوَزْتُ بَكَى، قِيلَ لَهُ: مَا يُبْكِيكَ؟ قَالَ: أَبْكِي لِأَنَّ غُلاَمًا بُعِثَ بَعْدِي يَدْخُلُ الجَنَّةَ مِنْ أُمَّتِهِ أَكْثَرُ مِمَّنْ يَدْخُلُهَا مِنْ أُمَّتِي، ثُمَّ صَعِدَ بِي إِلَى السَّمَاءِ السَّابِعَةِ فَاسْتَفْتَحَ جِبْرِيلُ، قِيلَ: مَنْ هَذَا؟ قَالَ: جِبْرِيلُ، قِيلَ: وَمَنْ مَعَكَ؟ قَالَ: مُحَمَّدٌ، قِيلَ: وَقَدْ بُعِثَ إِلَيْهِ؟ قَالَ: نَعَمْ، قَالَ: مَرْحَبًا بِهِ، فَنِعْمَ المَجِيءُ جَاءَ، فَلَمَّا خَلَصْتُ فَإِذَا إِبْرَاهِيمُ قَالَ: هَذَا أَبُوكَ فَسَلِّمْ عَلَيْهِ، قَالَ: فَسَلَّمْتُ عَلَيْهِ فَرَدَّ السَّلاَمَ، قَالَ: مَرْحَبًا بِالِابْنِ الصَّالِحِ وَالنَّبِيِّ الصَّالِحِ، ثُمَّ رُفِعَتْ إِلَيَّ سِدْرَةُ المُنْتَهَى، فَإِذَا نَبْقُهَا مِثْلُ قِلاَلِ هَجَرَ، وَإِذَا وَرَقُهَا مِثْلُ آذَانِ الفِيَلَةِ، قَالَ: هَذِهِ سِدْرَةُ المُنْتَهَى، وَإِذَا أَرْبَعَةُ أَنْهَارٍ: نَهْرَانِ بَاطِنَانِ وَنَهْرَانِ ظَاهِرَانِ، فَقُلْتُ: مَا هَذَانِ يَا جِبْرِيلُ؟ قَالَ: أَمَّا البَاطِنَانِ فَنَهْرَانِ فِي الجَنَّةِ، وَأَمَّا الظَّاهِرَانِ فَالنِّيلُ وَالفُرَاتُ، ثُمَّ رُفِعَ لِي البَيْتُ المَعْمُورُ، ثُمَّ أُتِيتُ بِإِنَاءٍ مِنْ خَمْرٍ، وَإِنَاءٍ مِنْ لَبَنٍ، وَإِنَاءٍ مِنْ عَسَلٍ، فَأَخَذْتُ اللَّبَنَ فَقَالَ: هِيَ الفِطْرَةُ الَّتِي أَنْتَ عَلَيْهَا وَأُمَّتُكَ، ثُمَّ فُرِضَتْ عَلَيَّ الصَّلَوَاتُ خَمْسِينَ صَلاَةً كُلَّ يَوْمٍ، فَرَجَعْتُ فَمَرَرْتُ عَلَى مُوسَى، فَقَالَ: بِمَا أُمِرْتَ؟ قَالَ: أُمِرْتُ بِخَمْسِينَ صَلاَةً كُلَّ يَوْمٍ، قَالَ: إِنَّ أُمَّتَكَ لاَ تَسْتَطِيعُ خَمْسِينَ صَلاَةً كُلَّ يَوْمٍ، وَإِنِّي وَاللَّهِ قَدْ جَرَّبْتُ النَّاسَ قَبْلَكَ، وَعَالَجْتُ بَنِي إِسْرَائِيلَ أَشَدَّ المُعَالَجَةِ، فَارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ لِأُمَّتِكَ، فَرَجَعْتُ فَوَضَعَ عَنِّي عَشْرًا، فَرَجَعْتُ إِلَى مُوسَى فَقَالَ مِثْلَهُ، فَرَجَعْتُ فَوَضَعَ عَنِّي عَشْرًا، فَرَجَعْتُ إِلَى مُوسَى فَقَالَ مِثْلَهُ، فَرَجَعْتُ فَوَضَعَ عَنِّي عَشْرًا، فَرَجَعْتُ إِلَى مُوسَى فَقَالَ مِثْلَهُ، فَرَجَعْتُ فَأُمِرْتُ بِعَشْرِ صَلَوَاتٍ كُلَّ يَوْمٍ، فَرَجَعْتُ فَقَالَ مِثْلَهُ، فَرَجَعْتُ فَأُمِرْتُ بِخَمْسِ صَلَوَاتٍ كُلَّ يَوْمٍ، فَرَجَعْتُ إِلَى مُوسَى، فَقَالَ: بِمَ أُمِرْتَ؟ قُلْتُ: أُمِرْتُ بِخَمْسِ صَلَوَاتٍ كُلَّ يَوْمٍ، قَالَ: إِنَّ أُمَّتَكَ لاَ تَسْتَطِيعُ خَمْسَ صَلَوَاتٍ كُلَّ يَوْمٍ، وَإِنِّي قَدْ جَرَّبْتُ النَّاسَ قَبْلَكَ وَعَالَجْتُ بَنِي إِسْرَائِيلَ أَشَدَّ المُعَالَجَةِ، فَارْجِعْ إِلَى رَبِّكَ فَاسْأَلْهُ التَّخْفِيفَ لِأُمَّتِكَ، قَالَ: سَأَلْتُ رَبِّي حَتَّى اسْتَحْيَيْتُ، وَلَكِنِّي أَرْضَى وَأُسَلِّمُ، قَالَ: فَلَمَّا جَاوَزْتُ نَادَى مُنَادٍ: أَمْضَيْتُ فَرِيضَتِي، وَخَفَّفْتُ عَنْ عِبَادِي».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"أخبر أنس بن مالك عن مالك بن صعصعة رضي الله عنهما أن النبي صلى الله عليه وسلم أخبرهم عن الليلة التي أسري فيها فقال: بينما أنا في الحَطِيم، وربما قال: في الحِجْر بدل الحطيم، أي في البيت راقدًا، إذ جاءني جبريل عليه السلام، قال قتادة: وسمعت أنس يقول: فشقَّ ما بين هذه إلى هذه، فقلت للجارود بن سبرة البصري التابعي صاحب أنس رضي الله عنه وهو بجانبي: ماذا يعني أنس بقوله ما بين هذه إلى هذه؟ قال: يعني به من الموضع المنخفض بين الترقوتين إلى عانته أو منبت شعرها، قال قتادة: وسمعت أنسًا رضي الله عنه يقول أيضًا: شق من رأس صدره إلى عانته، فأخرج قلبي وجيء بقِدْرٍ من ذَهَبٍ، وكان القدر مملوءً بالإيمان ملأً حقيقيًّا، فغسل جبريل قلبي ثم ملأه إيمانًا وحكمةً، ثم أرجعه مكانه، ثم جيء لي بدابة أصغر من البغل وأكبر من الحمار، بيضاء اللون، فقال الجارود بن أبي سبرة لأنس: هذا هو البراق يا أبا حمزة؟ قال أنس: نعم هو، يضع رجله عند منتهى ما يرى بصره، فركبت عليه،  قال عليه الصلاة والسلام: فطلب جبريل فتح السماء الدنيا فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبا به، فنعم المجيء الذي جاء، ونعم كلمة ثناء ومدح، ففتح الباب، فلما وصلت السماء الأولى وجدت فيها آدم، فقال لي جبريل: هذا أبوك آدم فسلم عليه، فسلمت عليه فردَّ عليَّ السلام، ثم قال لي آدم: مرحبًا بالابن الصالح والنبي الصالح، ثم صعد جبريل حتى جاء إلى السماء الثانية فطلب جبريل فَتْحَ بابِها، فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبًا به، فنعم المجيء الذي جاء، ففتح الباب، فلما وصلت وجدت فيها يحيى بن زكريا وعيسى ابن مريم وهما ابنا الخالة، قال جبريل عليه السلام لي: هذا يحيى وعيسى فسلم عليهما، فسلمت عليهما فردا علي السلام، ثم قالا لي: مرحبا بالأخ الصالح والنبي الصالح، ثم صعد جبريل إلى السماء الثالثة، فطلب جبريل فتح بابها، فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبًا به فنعم المجيء الذي جاء، ففتح الباب، فلما وصلت وجدت فيها يوسف، قال لي جبريل: هذا يوسف فسلم عليه، فسلمت عليه فردَّ عليَّ السلام، ثم قال: مرحبًا بالأخ الصالح والنبي الصالح، ثم صعد بي جبريل حتى جاء إلى السماء الرابعة، فطلب جبريل فتح بابها، فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبًا به، فنعم المجيء الذي جاء، ففتح الباب، فلما وصلت وجدت فيها إدريس، قال لي جبريل: هذا إدريس فسلِّم عليه، فسلَّمتُ عليه، فردَّ عليَّ السلام ثم قال لي: مرحبًا بالأخ الصالح والنبي الصالح، ثم صعد جبريل بي حتى أتى السماء الخامسة، فطلب جبريل فتح بابها، فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبًا به، فنعم المجيء الذي جاء، ففتح الباب، فلما وصلت وجدت فيها هارون، قال لي جبريل: هذا هارون، فسلِّم عليه، فسلَّمتُ عليه، فردَّ السلام عليَّ، ثم قال: مرحبًا بالأخ الصالح والنبي الصالح، ثم صعد بي جبريل حتى أتى السماء السادسة، فطلب جبريل فتح بابها، فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبًا به فنعم المجيء الذي جاء، ففتح الباب، فلما وصلت وجدت فيها موسى، قال لي جبريل: هذا موسى فسلم عليه، فسلمت عليه فردَّ عليَّ السلام، ثم قال لي: مرحبًا بالأخ الصالح والنبي الصالح، فلما تركتُ موسى وصعدت بكى، قيل له: لماذا تبكي؟ قال: أبكي لأن غلامًا بعثه الله بعدي يدخل الجنة من أمته أكثر ممن يدخلها من أمتي بني إسرائيل، وليس بكاؤه حسدًا حاشاه الله، بل أسفًا وحزنًا على ما فاته من الأجر المترتب عليه رفع درجته، وقوله: غلام مراده به أنه صغير السن بالنسبة إليه، وقد أنعم الله عليه بما لم ينعم به عليه مع طول عمره، قال عليه الصلاة والسلام: ثم صعد بي جبريل إلى السماء السابعة، فطلب جبريل فتح بابها، فسأله خازنها: من هذا؟ قال: جبريل، قيل: ومن معك؟ قال: محمد، قيل: وهل أرسل إليه للعروج به؟ قال: نعم أرسل إليه، قيل: مرحبًا به، فنعم المجيء الذي جاء، ففتح الباب، فلما وصلت وجدت فيها إبراهيم، قال لي جبريل: هذا أبوك إبراهيم فسلم عليه، فسلمت عليه فرد السلام، ثم قال: مرحبًا بالابن الصالح والنبي الصالح، ثم كُشفت لي سِدْرة المُنْتهى، أي التي ينتهي إليها ما يَعرج من الأرض فيقبض منها، فإذا ثمرها في الكِبَر، كالجِرَار التي تصنع في بلدة هَجْر، وكانت معروفة عند المخاطبين، فلذا وقع التمثيل بها، وورق السدرة في كبرها مثل آذان الفيلة، قال لي جبريل: هذه سدرة المنتهى، ورأيت أربعة أنهار تخرج من أصلها، نهران باطنان ونهران ظاهران، فقلت: ما هذان يا جبريل؟ قال: أما الباطنان فنهران يجريان في الجنة، وأما الظاهران فهما النيل نهر مصر، والفرات نهر بغداد، ثم كُشف لي البيت المعمور فرأيته، ثم جيء لي  بإناء من خمر وإناء من لبن وإناء من عسل، فاخترت اللبن فشربت منه، فقال لي جبريل: هذه هي الفطرة التي أنت عليها وأمتك، ثم كُتبت علي الصلوات خمسون صلاة كل يوم، فرجعت فمررت على موسى، فقال: بماذا أُمرت؟ قلت له: أمرت بخمسين صلاة كل يوم وليلة، قال موسى عليه السلام: إن أمتك لن تستطيع أن تصلي خمسين صلاة كل يوم وليلة، وإني والله قد جربت الناس قبلك، وجادلت بني إسرائيل أشد المجادلة، ليمتثلوا الأوامر الشرعية، ولقيتُ منهم الشدة فيما أردت منهم من الطاعة، فارجع إلى ربك فاطلب منه التخفيف لأمتك، فقال عليه الصلاة والسلام: فرجعت إلى ربي فخفف عني عشرًا من الخمسين، فرجعت إلى موسى فأخبرته، فقال مثل ما قال، فرجعت فخفف عني عشرًا من الأربعين، فرجعت إلى موسى فأخبرته فقال مثل ما قال، فرجعت فخفف عني عشرًا من الثلاثين، فرجعت إلى موسى فأخبرته، فقال مثل قوله، فرجعت فأُمرت بعشر صلوات كل يوم وليلة، فرجعت إلى موسى فأخبرته، فقال مثل قوله، فرجعت فأُمرت بخمس صلوات كل يوم وليلة، فرجعت إلى موسى فقال: بماذا أُمرت؟ قلت: أمرت بخمس صلوات كل يوم، قال: إن أمتك لا تستطيع خمس صلوات كل يوم، وإني قد جربت الناس قبلك، وجادلت بني إسرائيل أشد المجادلة، فارجع إلى ربك فاطلب منه أن يخفف عن أمتك من هذه الخمس، قال عليه الصلاة والسلام: فقلت له: سألت ربي حتى استحييت منه، ولكني أرضى بما كتبه ربي وأسلم، فلما مررت جاء النداء من الله تعالى: أنفذت فريضتي بخمس صلوات وخففت عن عبادي من خمسين إلى خمس صلوات.","reference":"صحيح البخاري (5/ 52-53) (3887) صحيح مسلم (1/ 149) (164)، عمدة القاري شرح صحيح البخاري (15/ 129)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (4/ 543)، إرشاد الساري لشرح صحيح البخاري (6/ 203)، النهاية في غريب الحديث والأثر (123) (483) (423).","benefits":["الحكمة في شق قلب النبي صلى الله عليه وسلم مع القدرة على أن يمتلئ قلبه إيمانًا وحكمة بغير شق، الزيادة في قوة اليقين؛ لأنه أعطي برؤية شق بطنه، وعدم تأثره بذلك ما أمن معه من جميع المخاوف العادية.","أصل النيل والفرات من الجنة، ولا يلزم من ذلك أن ماءها الموجود الآن من الجنة.","الحكمة في تخصيص موسى عليه السلام بمراجعة النبي صلى الله عليه وسلم في أمر الصلاة، لعلها لكون أمة موسى كلفت من الصلوات بما لم يكلف به غيرها من الأمم، فثقلت عليهم، فأشفق موسى على أمة محمد صلى الله عليه وسلم من مثل ذلك.","اختصاص فرضية الصلاة بليلة الإسراء إشارة إلى عظيم شأنها، ولذلك اختص فرضها بكونه بغير واسطة.","أن الله سبحانه وتعالى كلم نبيه محمد صلى الله عليه وسلم ليلة الإسراء بغير واسطة.","التجربة أقوى في تحصيل المطلوب من المعرفة الكثيرة، يستفاد ذلك من قول موسى عليه السلام للنبي صلى الله عليه وسلم: إنه عالج الناس قبله وجربهم."],"wordsMeanings":[{"word":"ثغرة نحره","meaning":" النقرة التي بين الترقوتين."},{"word":"شعرته","meaning":" منبت شعر العانة."},{"word":"يضع خطوه عند أقصى طرفه","meaning":" ‌يضع ‌رجله عند منتهى ما يرى بصرُه."},{"word":"حُملت عليه","meaning":" ركبته."},{"word":"فاستفتح","meaning":" طلب فتح الباب من خازنها."},{"word":"سدرة المنتهى","meaning":" شجرة في أقصى الجنة إليها ينتهي علم الأولين والآخرين ولا يتعداها."},{"word":"قلال هجر","meaning":" الجرار التي كانت تصنع في بلدة هجر، في شرق جزيرة العرب."},{"word":"أمضيت","meaning":" أنفذت."}],"category":"sirah","tags":["حديث","الإسراء","والمعراج"],"source":"hadeethenc"},{"id":"he_66343","text":"عَنِ الزُّهْرِيِّ قَالَ: أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَ: حَدَّثَنِي ابْنُ عَبَّاسٍ، قَالَ: حَدَّثَنِي أَبُو سُفْيَانَ، مِنْ فِيهِ إِلَى فِيَّ، قَالَ: انْطَلَقْتُ فِي المُدَّةِ الَّتِي كَانَتْ بَيْنِي وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، قَالَ: فَبَيْنَا أَنَا بِالشَّأْمِ إِذْ جِيءَ بِكِتَابٍ مِنَ النَّبِيِّ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ إِلَى هِرَقْلَ، قَالَ: وَكَانَ دَحْيَةُ الكَلْبِيُّ جَاءَ بِهِ، فَدَفَعَهُ إِلَى عَظِيمِ بُصْرَى، فَدَفَعَهُ عَظِيمُ بُصْرَى إِلَى هِرَقْلَ، قَالَ: فَقَالَ هِرَقْلُ: هَلْ هَهُنَا أَحَدٌ مِنْ قَوْمِ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ؟ فَقَالُوا: نَعَمْ، قَالَ: فَدُعِيتُ فِي نَفَرٍ مِنْ قُرَيْشٍ، فَدَخَلْنَا عَلَى هِرَقْلَ فَأُجْلِسْنَا بَيْنَ يَدَيْهِ، فَقَالَ: أَيُّكُمْ أَقْرَبُ نَسَبًا مِنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ؟ فَقَالَ أَبُو سُفْيَانَ: فَقُلْتُ: أَنَا، فَأَجْلَسُونِي بَيْنَ يَدَيْهِ، وَأَجْلَسُوا أَصْحَابِي خَلْفِي، ثُمَّ دَعَا بِتَرْجُمَانِهِ، فَقَالَ: قُلْ لَهُمْ: إِنِّي سَائِلٌ هَذَا عَنْ هَذَا الرَّجُلِ الَّذِي يَزْعُمُ أَنَّهُ نَبِيٌّ، فَإِنْ كَذَبَنِي فَكَذِّبُوهُ، قَالَ أَبُو سُفْيَانَ: وَايْمُ اللَّهِ، لَوْلاَ أَنْ يُؤْثِرُوا عَلَيَّ الكَذِبَ لَكَذَبْتُ، ثُمَّ قَالَ: لِتَرْجُمَانِهِ، سَلْهُ كَيْفَ حَسَبُهُ فِيكُمْ؟ قَالَ: قُلْتُ: هُوَ فِينَا ذُو حَسَبٍ، قَالَ: فَهَلْ كَانَ مِنْ آبَائِهِ مَلِكٌ؟ قَالَ: قُلْتُ: لاَ، قَالَ: فَهَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ؟ قُلْتُ: لاَ، قَالَ: أَيَتَّبِعُهُ أَشْرَافُ النَّاسِ أَمْ ضُعَفَاؤُهُمْ؟ قَالَ: قُلْتُ: بَلْ ضُعَفَاؤُهُمْ، قَالَ: يَزِيدُونَ أَوْ يَنْقُصُونَ؟ قَالَ: قُلْتُ لاَ بَلْ يَزِيدُونَ، قَالَ: هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ؟ قَالَ: قُلْتُ: لاَ، قَالَ: فَهَلْ قَاتَلْتُمُوهُ؟ قَالَ: قُلْتُ: نَعَمْ، قَالَ: فَكَيْفَ كَانَ قِتَالُكُمْ إِيَّاهُ؟ قَالَ: قُلْتُ: تَكُونُ الحَرْبُ بَيْنَنَا وَبَيْنَهُ سِجَالًا يُصِيبُ مِنَّا وَنُصِيبُ مِنْهُ، قَالَ: فَهَلْ يَغْدِرُ؟ قَالَ: قُلْتُ: لاَ، وَنَحْنُ مِنْهُ فِي هَذِهِ المُدَّةِ لاَ نَدْرِي مَا هُوَ صَانِعٌ فِيهَا، قَالَ: وَاللَّهِ مَا أَمْكَنَنِي مِنْ كَلِمَةٍ أُدْخِلُ فِيهَا شَيْئًا غَيْرَ هَذِهِ، قَالَ: فَهَلْ قَالَ هَذَا القَوْلَ أَحَدٌ قَبْلَهُ؟ قُلْتُ: لاَ، ثُمَّ قَالَ لِتُرْجُمَانِهِ: قُلْ لَهُ: إِنِّي سَأَلْتُكَ عَنْ حَسَبِهِ فِيكُمْ، فَزَعَمْتَ أَنَّهُ فِيكُمْ ذُو حَسَبٍ، وَكَذَلِكَ الرُّسُلُ تُبْعَثُ فِي أَحْسَابِ قَوْمِهَا، وَسَأَلْتُكَ: هَلْ كَانَ فِي آبَائِهِ مَلِكٌ، فَزَعَمْتَ أَنْ لاَ، فَقُلْتُ: لَوْ كَانَ مِنْ آبَائِهِ مَلِكٌ قُلْتُ: رَجُلٌ يَطْلُبُ مُلْكَ آبَائِهِ، وَسَأَلْتُكَ عَنْ أَتْبَاعِهِ أَضُعَفَاؤُهُمْ أَمْ أَشْرَافُهُمْ، فَقُلْتَ: بَلْ ضُعَفَاؤُهُمْ، وَهُمْ أَتْبَاعُ الرُّسُلِ، وَسَأَلْتُكَ: هَلْ كُنْتُمْ تَتَّهِمُونَهُ بِالكَذِبِ قَبْلَ أَنْ يَقُولَ مَا قَالَ، فَزَعَمْتَ أَنْ لاَ، فَعَرَفْتُ أَنَّهُ لَمْ يَكُنْ لِيَدَعَ الكَذِبَ عَلَى النَّاسِ، ثُمَّ يَذْهَبَ فَيَكْذِبَ عَلَى اللَّهِ، وَسَأَلْتُكَ: هَلْ يَرْتَدُّ أَحَدٌ مِنْهُمْ عَنْ دِينِهِ بَعْدَ أَنْ يَدْخُلَ فِيهِ سَخْطَةً لَهُ، فَزَعَمْتَ أَنْ لاَ، وَكَذَلِكَ الإِيمَانُ إِذَا خَالَطَ بَشَاشَةَ القُلُوبِ، وَسَأَلْتُكَ هَلْ يَزِيدُونَ أَمْ يَنْقُصُونَ، فَزَعَمْتَ أَنَّهُمْ يُزِيدُونَ، وَكَذَلِكَ الإِيمَانُ حَتَّى يَتِمَّ، وَسَأَلْتُكَ: هَلْ قَاتَلْتُمُوهُ فَزَعَمْتَ أَنَّكُمْ قَاتَلْتُمُوهُ، فَتَكُونُ الحَرْبُ بَيْنَكُمْ وَبَيْنَهُ سِجَالًا يَنَالُ مِنْكُمْ وَتَنَالُونَ مِنْهُ، وَكَذَلِكَ الرُّسُلُ تُبْتَلَى ثُمَّ تَكُونُ لَهُمُ العَاقِبَةُ، وَسَأَلْتُكَ: هَلْ يَغْدِرُ فَزَعَمْتَ أَنَّهُ لاَ يَغْدِرُ، وَكَذَلِكَ الرُّسُلُ لاَ تَغْدِرُ، وَسَأَلْتُكَ: هَلْ قَالَ أَحَدٌ هَذَا القَوْلَ قَبْلَهُ، فَزَعَمْتَ أَنْ لاَ، فَقُلْتُ: لَوْ كَانَ قَالَ هَذَا القَوْلَ أَحَدٌ قَبْلَهُ قُلْتُ: رَجُلٌ ائْتَمَّ بِقَوْلٍ قِيلَ قَبْلَهُ، قَالَ: ثُمَّ قَالَ: بِمَ يَأْمُرُكُمْ؟ قَالَ: قُلْتُ: يَأْمُرُنَا بِالصَّلاَةِ وَالزَّكَاةِ وَالصِّلَةِ وَالعَفَافِ، قَالَ: إِنْ يَكُ مَا تَقُولُ فِيهِ حَقًّا فَإِنَّهُ نَبِيٌّ، وَقَدْ كُنْتُ أَعْلَمُ أَنَّهُ خَارِجٌ، وَلَمْ أَكُ أَظُنُّهُ مِنْكُمْ، وَلَوْ أَنِّي أَعْلَمُ أَنِّي أَخْلُصُ إِلَيْهِ لَأَحْبَبْتُ لِقَاءَهُ، وَلَوْ كُنْتُ عِنْدَهُ لَغَسَلْتُ عَنْ قَدَمَيْهِ، وَلَيَبْلُغَنَّ مُلْكُهُ مَا تَحْتَ قَدَمَيَّ، قَالَ: ثُمَّ دَعَا بِكِتَابِ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَهُ، فَإِذَا فِيهِ: بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ، مِنْ مُحَمَّدٍ رَسُولِ اللَّهِ إِلَى هِرَقْلَ عَظِيمِ الرُّومِ، سَلاَمٌ عَلَى مَنِ اتَّبَعَ الهُدَى، أَمَّا بَعْدُ: فَإِنِّي أَدْعُوكَ بِدِعَايَةِ الإِسْلاَمِ، أَسْلِمْ تَسْلَمْ، وَأَسْلِمْ يُؤْتِكَ اللَّهُ أَجْرَكَ مَرَّتَيْنِ، فَإِنْ تَوَلَّيْتَ فَإِنَّ عَلَيْكَ إِثْمَ الأَرِيسِيِّينَ، وَ:{يَا أَهْلَ الكِتَابِ تَعَالَوْا إِلَى كَلِمَةٍ سَوَاءٍ بَيْنَنَا وَبَيْنَكُمْ أَلَّاَ نَعْبُدَ إِلَّا اللَّهَ} إِلَى قَوْلِهِ: {اشْهَدُوا بِأَنَّا مُسْلِمُونَ} [آل عمران: 64]، فَلَمَّا فَرَغَ مِنْ قِرَاءَةِ الكِتَابِ، ارْتَفَعَتِ الأَصْوَاتُ عِنْدَهُ وَكَثُرَ اللَّغَطُ، وَأُمِرَ بِنَا فَأُخْرِجْنَا، قَالَ: فَقُلْتُ لِأَصْحَابِي حِينَ خَرَجْنَا: لَقَدْ أَمِرَ أَمْرُ ابْنِ أَبِي كَبْشَةَ، إِنَّهُ لَيَخَافُهُ مَلِكُ بَنِي الأَصْفَرِ، فَمَا زِلْتُ مُوقِنًا بِأَمْرِ رَسُولِ اللَّهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَيَظْهَرُ حَتَّى أَدْخَلَ اللَّهُ عَلَيَّ الإِسْلاَمَ، قَالَ الزُّهْرِيُّ: فَدَعَا هِرَقْلُ عُظَمَاءَ الرُّومِ فَجَمَعَهُمْ فِي دَارٍ لَهُ، فَقَالَ: يَا مَعْشَرَ الرُّومِ، هَلْ لَكُمْ فِي الفَلاَحِ وَالرَّشَدِ آخِرَ الأَبَدِ، وَأَنْ يَثْبُتَ لَكُمْ مُلْكُكُمْ؟ قَالَ: فَحَاصُوا حَيْصَةَ حُمُرِ الوَحْشِ إِلَى الأَبْوَابِ، فَوَجَدُوهَا قَدْ غُلِّقَتْ، فَقَالَ: عَلَيَّ بِهِمْ، فَدَعَا بِهِمْ فَقَالَ: إِنِّي إِنَّمَا اخْتَبَرْتُ شِدَّتَكُمْ عَلَى دِينِكُمْ فَقَدْ رَأَيْتُ مِنْكُمُ الَّذِي أَحْبَبْتُ فَسَجَدُوا لَهُ وَرَضُوا عَنْهُ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يروي ابن عباس رضي الله عنهما أن أبا سفيان رضي الله عنه أخبره عن ما دار بينه وبين هرقل الملقب بقيصر، عظيم الروم، وحصل ذلك قبل أن يسلم أبو سفيان، ثم حدث به ابنَ عباس بعد إسلامه، وأنه قد أخبره من فمه إلى فمه وعبر بفمه موضع أذنه؛ إشارة إلى تمكنه من الإصغاء إليه بحيث يجيبه إذا احتاج إلى الجواب، ذكر أبو سفيان أنه خرج من مكة في مدة صلح الحديبية التي كانت بين قريش والنبي صلى الله عليه وسلم على وضع الحرب عشر سنين، سنة ست من الهجرة، فبينما كان أبو سفيان بالشام وصل إلى هرقل كتابُ النبي صلى الله عليه وسلم، وكان دحية بن خليفة الكلبي رضي الله عنه هو من جاء به من عند النبي صلى الله عليه وسلم في آخر سنة ست، فأعطاه دحية إلى عظيم أهل بُصرى: الحارث بن أبي شَمِر الغَسَّاني، وعطاه عظيم بصرى إلى هرقل، فسأل هرقل: هل يوجد أحدٌ من قوم هذا الرجل الذي يدعي أنه نبي؟ فقيل: نعم، فجاء رسول هرقل إلى أبي سفيان ومعه أناس من قريش، فطلبهم فتوجهوا معه حتى وصلوا إليه، فاستأذن لهم فأذن لهم، فدخلوا عليه وجلسوا بين يديه، فسألهم هرقل: من منكم الأقرب نسبًا من هذا الرجل الذي يدعي أنه نبي؟ فقال أبو سفيان: أنا؛ لأنهما يلتقيان في عبد مناف، فالنبي صلى الله عليه وسلم هو محمد بن عبد الله بن عبد المطلب بن هاشم بن عبد مناف، وأبو سفيان هو صخر بن حرب بن أمية بن عبد شمس بن عبد مناف، واختار هرقل ذلك؛ لأن الأقرب أحرى بالاطلاع على قريبه من غيره، فأجلسوا أبا سفيان بين يدي هرقل، وأجلسوا أصحابه القرشيين خلفه، ثم أتى بمترجمه ليترجم لغته إلى العربية والعكس، وأمره أن يقول للقرشيين: إني سأسأل أبا سفيان عن هذا الرجل الذي يدعي النبوة، فإن كذب علي فأخبروني بكذبه، قال أبو سفيان: والله لولا أن يحكوا عني الكذب -وهو قبيح- لكذبت عليه، لعداوته يومئذ للنبي عليه الصلاة والسلام، فقال هرقل: كيف حسبه فيكم؟ قال أبو سفيان: هو ذو حسب، فسأله: هل كان من آبائه وأجداه مَلِكٌ من الملوك؟ فأجابه: لا، فسأله: هل كنتم تتهمونه بالكذب على الناس قبل أن يدعي النبوة؟ قال أبو سفيان: لا، فسأله: هل يتبعه شرفاء الناس أم ضعفاؤهم؟ قال: ضعفاؤهم، ثم سأله هرقل: هل يزيد أتباعه أم ينقصون؟ قال سفيان: لا ينقصون، بل يزيدون، ثم سأله: هل يرجع أحد منهم عن دينه كراهة لدينه وعدم رضا؟ فأجابه أن لا، فسأله: هل قاتلتموه؟ قال أبو سفيان: نعم قاتلناه، فسأله: كيف كان قتالكم له؟ فأجابه: أن الحرب تكون نوبة له مرةً ونوبة لنا مرةً أخرى، وقد كانت المقاتلة وقعت بينه عليه الصلاة والسلام وبينهم في بدر فأصاب المسلمون منهم وفي أحد فأصاب المشركون من المسلمين وفي الخندق فأصيب من الطائفتين ناس قليل، قال هرقل: هل ينقض العهد؟ قال أبو سفيان: لا ينقضه، ونحن الآن منه في مدة صلح الحديبية أو غيبته وانقطاع أخباره عنا، ولا ندري ماذا سيصنع فيها، فلم يجزم بغدره، وقال أبو سفيان: والله لم أستطع أن أُخل كلمة انتقصه بها غير هذه الكلمة، ثم سأله هرقل: هل ادعى أحد من قريش قبله مثل ادعاءه النبوة؟ فأجاب أبو سفيان أن لا،\nثم قال لمن يترجم له: قل له: قد سألتك عن رتبته وحسبه فيكم، فقلت: أنه ذو حسب رفيع، وكذلك الرسل تُرسل في أرفع حسب في قومها، وسألتك: هل له من آبائه ملك من الملوك، فأجبت أن لا، فقلت: لو كان في آبائه ملك لقلت إنه يطلب ملك أبيه، وسألتك عن الذين يتبعوه: هل هم الضعفاء أم الشرفاء؟ فقلت: أن ضعفاؤهم اتبعوه، وكذلك أتباع الرسل هم الضعفاء غالبًا بخلاف أهل الاستكبار المصرين على الشقاق بغضًا وحسدًا، وسألتك: هل كنتم تتهمونه بالكذب قبل أن يدعي النبوة؟ فذكرت أن لا، فعلمت أنه ما كان ليترك الكذب على الناس قبل أن يظهر رسالته، ثم يكذب على الله بعد إظهارها، ثم سألتك: هل يخرج أحد من اتباعه عن دينه الإسلام بعد أن يدخل فيه كراهةً له؟ فقلت: لا، وكذلك الإيمان إذا دخل القلوب وخالطها لم يخرج منها، وسألتك: هل يزيد أتباعه أم ينقصون؟ فذكرت أنهم يزيدون، وكذلك الإيمان لا يزال في زيادة حتى يتم بالفرائض والشرائع المعتبرة فيه من الصلاة وغيرها، وسألتك: هل قاتلتموه، فقلت: نعم، وتكون الحرب بينكم وبينه تنال منه وينال منكم، وكذلك يُبتلى الرسل ابتداءً، وتكون العاقبة والنصر لهم، وسألتك: هل يغدر وينقض العهد؟ فقلت: لا، وكذلك الرسل لا تغدر؛ لأنها لا تطلب حظ الدنيا الذي لا يبالي طالبه بالغدر، وسألتك: هل ادعى أحدٌ قبله النبوة؟ فأجبت أن لا،  فقلت: لو ادعى أحدٌ قبله لكان يقتدي به ويفعل مثله، قال هرقل: بماذا يأمركم؟ فأجاب أبو سفيان: يأمرنا بالصلاة والزكاة وصلة الأرحام والعفاف أي الكف عن المحارم وخوارم المروءة، فذكر هرقل الأجوبة على ترتيب الأسئلة، وأجاب عن كل بما دل على ثبوت النبوة، مما رآه في كتبهم أو استقرأه من العادة.\n ثم قال هرقل: إن يكن ما تقوله فيه حق وصدق فإنه نبي، وكنت أعلم أنه سيبعث في هذا الزمان، ولم أكن أعتقد أنه منكم معشر قريش، ولو كنت أعلم أني أستطيع أن أصل إليه لتكلفت الوصول إليه، ولو كنت عنده لغسلتُ قدميه، قاله مبالغة في خدمته، ولسوف يصل ملكه ما تحت قدمي، أي أرض ملكه، ثم دعا هرقل بكتاب النبي صلى الله عليه وسلم، فقرأه بنفسه أو قرأه المترجم بأمره، فإذا مكتوب فيه: بسم الله الرحمن الرحيم من محمد رسول الله صلى الله عليه وسلم إلى هرقل عظيم الروم، سلام على من اتبع الهدى، وهو كقول موسى وهارون لفرعون والسلام على من اتبع الهدى، أما بعد فإني أدعوك بالكلمة الداعية إلى الإسلام، وهي شهادة التوحيد، أسلم تسلم، أسلم يعطيك الله أجرك مرتين، لكونه مؤمنًا بنبيه ثم آمن بمحمد عليه الصلاة والسلام أو أن إسلامه سبب لإسلام أتباعه، فإن أعرضت ولم تسلم، فإن عليك مع إثمك إثم المزارعين، نبه بهم على جميع الرعايا، و: {يا أهل الكتاب تعالوا إلى كلمة سواء بيننا وبينكم، أن لا نعبد إلا الله} إلى قوله: {اشهدوا بأنا مسلمون} [آل عمران: 64]، والخطاب في اشهدوا للمسلمين، أي فإن تولوا عن هذه الدعوة فأشهدوهم أنتم على استمراركم على الإسلام الذي شرعه الله لكم، فلما انتهى هرقل من قراءة الكتاب ارتفعت الأصوات ممن كان عنده، ولعله بسبب ما فهموه من ميل هرقل إلى التصديق، وأمر أن يُخرج أبو سفيان ومن معه فخرجوا، قال أبو سفيان لأصحابه بعد خروجهم: لقد عظُم شأن ابن أبي كبشة، وهي كنية أبي النبي صلى الله عليه وسلم من الرضاع، وإنه ليخافه ملك الروم، فما زلت مؤمنًا وموقنًا أن أمر النبي صلى الله عليه وسلم سيظهر، حتى أدخل الله علي الإسلام، فأظهرت ذلك اليقين وأسلمتُ.\nثم دعا هرقل عظماء الروم وجمعهم في بيت له، ثم اطلع عليهم من مكان فيه عال خوفًا على نفسه أن ينكروا مقالته فيبادروا إلى قتله ثم خاطبهم فقال: يا معشر الروم هل لكم رغبة في الفلاح والرشد إلى آخر الزمان؟ وهل لكم رغبة في أن يثبت ملككم؟ لأنه علم من الكتب أن لا أمة بعد هذه الأمة، فنفروا نفرة حمر الوحش، وذهبوا إلى الأبواب ليخرجوا منها، فوجدوها مغلقة، فقال هرقل: أحضروهم لي، فردهم فقال لهم: إني كنت اختبر شدتكم وثباتكم على دينكم بمقالتي هذه، فقد رأيت منكم الذي أحببت من تمسكم بدينكم، فسجدوا له حقيقة إذ كانت عادتهم ذلك لملوكهم، ورجعوا عما كانوا هموا به عند نفرتهم من الخروج عليه.","reference":"صحيح البخاري (6/ 35) (4553)، صحيح مسلم (3/ 1393) (1773)، إرشاد الساري لشرح صحيح البخاري (7/ 55)، البحر المحيط الثجاج في شرح صحيح الإمام مسلم بن الحجاج (31/ 56).","benefits":["البداءة باسم الكاتب قبل المكتوب إليه.","ملاطفة المكتوب إليه، وتعظيمه بما ليس فيه كذب، فهو عظيم عند قومه.","مشروعية مكاتبة الكفار، وقد كاتب النبي صلى الله عليه وسلم سبعة من الملوك.","الدلالة لمن قال بجواز معاملة الكفار بالدراهم المنقوش فيها اسم الله تعالى للضرورة؛ لأن ما في هذا الكتاب أكثر مما في هذا المنقوش، من ذكر الله تعالى.","في هذا الخبر دليل على أن النهي عن المسافرة بالقرآن إلى أرض العدو، إنما هو في حمل المصحف، والسور الكثيرة، دون الآية والآيتين، ونحوهما.","وجوب العمل بخبر الواحد، وإلا لم يكن لبعثه مع دحية فائدة، مع غيره من الأحاديث الدالة عليه.","فيه حجة لمن منع أن يبتدأ الكافر بالسلام، وقد جاء عنه النهي في الأحاديث الصحيحة، وإنما يقول مثلما ورد في هذا الحديث.","استحباب بدء المكاتبة بالبسملة، وذكر أما بعد فيها، وأما الخطبة ونحوها فتبدأ بالحمد والثناء على الله، ويقال فيها أيضًا: أما بعد.","من أدرك من أهل الكتاب نبينا صلى الله عليه وسلم فآمن به فله أجران.","دعاء الكفار إلى الإسلام قبل قتالهم، وهو واجب، والقتال قبله حرام، إلم تكن بلغتهم الدعوة، وإن كانت بلغتهم فالدعاء مستحب.","أن ذا الحسب أولى بالتقديم في أمور المسلمين، ومهمات الدين والدنيا، ولذلك جعلت الخلفاء من قريش؛ لأن عادة الناس أن يطيعوا ويسمعوا لمن كان نسيبًا حسيبًا، ولا يأنفون عنه، فتجتمع به كلمة المسلمين، ولأنهم أحوط من أن يدنسوا أحسابهم.","بعضهم استدل به على جواز مس المحدث، والكافر كتابا فيه آية، أو آيات يسيرة من القرآن، مع غير القرآن.","استحباب البلاغة والإيجاز، وتحري الألفاظ الجزلة في المكاتبة، فإن قوله: \"أسلم تسلم\" في نهاية الاختصار، وغاية الإيجاز والبلاغة، وجمع المعاني، مع ما فيه من بديع التجنيس.","جواز المسافرة إلى أرض الكفار للحاجة.","جواز البعث إليهم بالآية من القرآن، ونحوها.","من كان سببًا لضلالة، أو منع هداية كان آثمًا متحملًا لأوزار من تبعوه في ذلك.","الكذب عيب في كل أمة.","وجوب الاحتراز من العدو؛ لأنه لا يؤمن أن يكذب على عدوه.","البيان الواضح أن صدق النبي صلى الله عليه وسلم وعلاماته كان معلوما لأهل الكتاب علمًا قطعيًا، ولم يروا معجزة، وإنما ترك الإيمان من تركه منهم عنادًا أو حسدًا، أو خوفًا على فوات مناصبهم في الدنيا.","من أخبر بحديث وهو معروف بالصدق قبل منه، بخلاف ضده."],"wordsMeanings":[{"word":"عظيم بُصرى","meaning":" رئيس مدينة من المُدن لبتي تتبع لهرقل."},{"word":"هرقل","meaning":" رئيس الروم كلهم."},{"word":"حسبه","meaning":" سيرته ومآثر آبائه وأفعالهم الجميلة."},{"word":"سخطةً له","meaning":" كرهًا لدينه."}],"category":"sirah","tags":["كتاب","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_2990","text":"عَنِ الْبَرَاءِ رَضيَ اللهُ عنه قَالَ: مَا رَأَيْتُ مِنْ ذِي لِمَّةٍ أَحْسَنَ فِي حُلَّةٍ حَمْرَاءَ مِنْ رَسُولِ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ، شَعْرُهُ يَضْرِبُ مَنْكِبَيْهِ، بَعِيدَ مَا بَيْنَ الْمَنْكِبَيْنِ، لَيْسَ بِالطَّوِيلِ وَلَا بِالْقَصِيرِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر البراء بن عازب رضي الله عنه أنه ما رأى أحدًا شَعَرُ رأسِه طويل قد وَصَل إلى منكبيه، ويلبس إزارًا ورداءً أسود وفيه خطوط حمراء أحسن من رسول الله صلى الله عليه وسلم، وأن من صفته الخَلْقية أنه كان بعيدَ ما بين المنكبين، واسع الصدر، وكان متوسط القَامَة بين الطويل والقصير.","reference":"صحيح البخاري (4/ 188) (3551).\nصحيح مسلم (4/ 1818) (2337).\nتيسير العلام شرح عمدة الأحكام، لعبد الله البسام (ص730).","benefits":["بيان بعض صفات النبي صلى الله عليه وسلم الجميلة في الظاهر من حسن الشعر ورَحَابة الصدر، وحسن القامة، وغير ذلك.","محبة الصحابة الكرام رضي الله عنهم للنبي صلى الله عليه وسلم، حتى أنهم يحكون وينقلون لمن بعدهم شمائله وأوصافه الجسدية والمعنوية."],"wordsMeanings":[],"category":"sirah","tags":["رأيت","لمة","أحسن","حلة","حمراء","رسول"],"source":"hadeethenc"},{"id":"he_3019","text":"عن عائشة رضي الله عنها قالت: \"كَانَت يَدُ رسُولِ الله -صلَّى الله عليه وسلَّم- اليُمنَى لِطُهُورِهِ وطَعَامِهِ، وكَانَت اليُسْرَى لِخَلاَئِهِ، ومَا كَانَ مِنْ أَذَى\". \nعن حفصة رضي الله عنها \"أَنَّ رَسُولَ الله -صلَّى الله عليه وسلَّم- كَانَ يَجْعَلُ يَمِينَهُ لِطَعَامِهِ وَشَرَابِهِ وَثِيَابِهِ، وَيَجْعَلُ يَسَارَهُ لِمَا سِوَى ذَلِك\".","attribution":"الحديث الأول: رواه أبو داود وأحمد.\nالحديث الثاني: رواه أبو داود وأحمد","grade":"الحديثان صحيحان","gradeKey":"sahih","explanation":"بيَّنت عائشة رضي الله عنها ، ما كان النبي صلى الله عليه وسلم يستعمل فيه اليمين، وما كان يستعمل فيه اليسار، فذكرت أن الذي يستعمل فيه اليسار ما كان فيه أذى؛ كالاستنجاء، والاستجمار، والاستنشاق، والاستنثار، وما أشبه ذلك، كل ما فيه أذى فإنه تقدم فيه اليسرى، وما سوى ذلك؛ فإنه تقدم فيه اليمنى؛ تكريمًا لها؛ لأن الأيمن أفضل من الأيسر.\n وهذ الحديث داخل في استحباب تقديم اليمنى فيما من شأنه التكريم فقولها -رضي الله عنها-. \nقولها: \"لطهوره\": يعني إذا تطهر يبدأ باليمين، فيبدأ بغسل اليد اليمنى قبل اليسرى، وبغسل الرجل اليمنى قبل اليسرى، وأما الأذنان فإنهما عضوٌ واحدٌ، وهما داخلان في الرأس، فيمسح بهما جميعًا إلا إذا كان لا يستطيع أن يمسح إلا بيد واحدة، فهنا يبدأ بالأذن اليمنى للضرورة.\nقولها: \"وطَعَامِهِ\": أي تناوله الطعام.\n\"وكانت يده اليسرى لخلائه\": أي لما فيه من استنجاء وتناول أحجار وإزالة أقذار.\n\"وما كان من أذى\" كتنحية بصاق ومخاط وقمل ونحوها.\nوحديث حفصة مؤكد لما سبق من حديث عائشة، الذي جاء في بيان استحباب البداءة باليمين فيما طريقه التكريم، وتقديم اليسار فيما طريقه الأذى والقذر؛ كالاستنجاء والاستجمار وما أشبه ذلك.","reference":"رياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق ماهر الفحل، دار ابن كثير، دمشق، بيروت، الطبعة: الأولى، 1428هـ، 2007م.\nسنن أبي داود، سليمان بن الأشعث أبوداود، المحقق: شعَيب الأرنؤوط، محَمَّد كامِل قره بلل، الناشر: دار الرسالة العالمية.\nصحيح أبي داود، محمد ناصر الدين الألباني، الناشر: مؤسسة غراس للنشر والتوزيع، الكويت، الطبعة: الأولى، 1423هـ، 2002م.\nدليل الفالحين لطرق رياض الص","benefits":["الحديث مؤكد لقاعدة الشريعة: في استحباب البداءة باليمين فيما فيه التكريم، وتقديم اليسار فيما فيه الأذى والقذر.","اليد اليسرى لا تستعمل إلا في إزالة الخبيث، وكل ما كان لا تكريم فيه."],"wordsMeanings":[{"word":"لِطُهُورِهِ","meaning":" وهو بضم الطاء المهملة: استعمال الماء للتطهر، وبفتحها الماء المتطهر به."},{"word":"لِخَلاَئِهِ","meaning":" أي: للاستنجاء وتناول الأحجار وإزالة الأقذار."},{"word":"مِنْ أَذَى","meaning":" كالبصاق والمخاط ونحو ذلك."}],"category":"sirah","bookId":"abudawud","tags":["كانت","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_3020","text":"عن عبد الله بن عباس رضي الله عنهما قال: «لَمَّا قَدِم رسُول الله -صلَّى الله عليه وسلَّم- وأصحابه مكة، فقَال المُشرِكُون: إِنَّه يَقدَمُ عَلَيكُم قَومٌ وَهَنَتهُم حُمَّى يَثرِب، فَأَمَرَهُم النَّبيُّ -صلَّى الله عليه وسلَّم- أن يَرمُلُوا الأَشوَاطَ الثلاَثَة، وأن يَمشُوا ما بَين الرُّكنَين، ولم يَمنَعهُم أَن يَرمُلُوا الأَشوَاطَ كُلَّها: إلاَّ الإِبقَاءُ عَليهِم».","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"جاء النبي صلى الله عليه وسلم سنة ست من الهجرة إلى مكة معتمرًا، ومعه كثير من أصحابه، فخرج لقتاله وصده عن البيت كفار قريش، فحصل بينهم صلح، من مواده أن النبي صلى الله عليه وسلم وأصحابه يرجعون في ذلك العام، ويأتون في العام القابل معتمرين، ويقيمون في مكة ثلاثة أيام، فجاءوا في السنة السابعة لعمرة القضاء. فقال المشركون، بعضهم لبعض -تشفيا وشماتة-: إنه سيقدم عليكم قوم قد وهنتهم وأضعفتهم حمى يثرب.\nفلما بلغ النبي صلى الله عليه وسلم قولهم، أراد أن يرد قولهم ويغيظهم، فأمر أصحابه أن يسرعوا إلا فيما بين الركن اليماني والركن الذي فيه الحجر الأسود فيمشوا، رفقًا بهم وشفقة عليهم، حين يكونوا بين الركنين لا يراهم المشركون، الذين تسلقوا جبل \"قعيقعان\" لينظروا إلى المسلمين وهم يطوفون فغاظهم ذلك حتى قالوا: إن هم إلا كالغزلان، فكان هذا الرمل سنة متبعة في طواف القادم إلى مكة، تذكرا لواقع سلفنا الماضين، وتأسيًا بهم في مواقفهم الحميدة، ومصابرتهم الشديدة، وما قاموا به من جليل الأعمال، لنصرة الدين، وإعلاء كلمة الله، رزقنا الله اتباعهم واقتفاء أثرهم. \n والمشي بين الركنين وترك الرمل منسوخ؛ لنه في حجة الوداع رمل من الحجر إلى الحجر، روى مسلم عن جابر وابن عمر رضي الله عنهم «أن رسول الله صلى الله عليه وسلم رمل من الحجر إلى الحجر ثلاثًا، ومشى أربعًا».","reference":"تيسير العلام شرح عمدة الأحكام للبسام، حققه وعلق عليه وخرج أحاديثه وصنع فهارسه: محمد صبحي بن حسن حلاق، ط10، مكتبة الصحابة، الإمارات - مكتبة التابعين، القاهرة، 1426هـ.\nتنبيه الأفهام شرح عمدة لأحكام لابن عثيمين، ط1، مكتبة الصحابة، الإمارات، 1426هـ.\nالإلمام بشرح عمدة الأحكام لإسماعيل الأنصاري، ط1، دار الفكر، دمشق، 1381هـ.\nصحيح البخاري، تحقيق: محمد زهير بن ناصر الناصر، ط1، دار طوق النجاة (مصورة عن السل","benefits":["أن النبي  -صلى الله عليه وسلم- وأصحابه، رملوا في الأشواط الثلاثة الأول ماعدا ما بين الركنين، فقد رخص لهم في تركه، إبقاء عليهم، وذلك في عمرة القضاء.","استحباب الرمل في كل طواف وقع بعد قدوم، سواء أكان لنسك أم لا ففي صحيح مسلم: \"كان ذلك إذا طاف الطواف الأول\".","إظهار القوة والجلد أمام أعداء الدين، إغاظة لهم، وتوهينا لعزمهم، وفتا في أعضادهم.","من الحكمة في الرمل الآن تذكر حال سلفنا الصالح، في كثير من مناسك الحج، كالسعي، ورمي الجمار والهدي وغيرها.","الرمل مختص بالرجال دون النساء، لأنه مطلوب منهن الستر.","لو فات الرمل في الثلاثة الأول، فإنه لا يقضيه، لأن المطلوب في الأربعة الباقية، المشي، فلا يخلف هيئتهن، فتكون سنة فات محلها.","جواز حِكاية قول الغير، وإن كان خلاف المشروع، في قوله: \"وهنتهم حمى يثرب\".","شدة عداوة المشركين للمسلمين، وإظهار الشماتة بهم.","شفقة النبي -صلى الله عليه وسلم- على أمته."],"wordsMeanings":[{"word":"وَهَنَتْهُم","meaning":" أضعفتهم."},{"word":"يَثْرِب","meaning":" من أسماء المدينة النبوية في الجاهلية."},{"word":"أَنْ يَرْمُلُوا","meaning":" الرمل: الإسراع في المشي مع تقارب الخطا."},{"word":"الأَشْوَاط","meaning":" جمع شوط: وهو الجرية الواحدة إلى الغاية. والمراد هنا: الطوفة حول الكعبة من الحجر إلى الحجر."},{"word":"الإِبْقَاءُ عَلَيْهِم","meaning":" الرفق بهم، والشفقة عليهم."},{"word":"الركنين","meaning":" المسافة بين الركنين: اليماني والحجر الأسود."}],"category":"sirah","tags":["لما","قدم","رسول","الله","صلى","الله"],"source":"hadeethenc"},{"id":"he_3030","text":"عَنْ أَنَسِ بْنِ مَالِكٍ رَضيَ اللهُ عنه قَالَ: كَانَ رَسُولُ اللهِ صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ يَدْخُلُ الْخَلَاءَ، فَأَحْمِلُ أَنَا وَغُلَامٌ نَحْوِي إِدَاوَةً مِنْ مَاءٍ وَعَنَزَةً فَيَسْتَنْجِي بِالْمَاءِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"يخبر أنس بن مالك رضي الله عنه أنه كان هو وخادم مقارب لسِنِّهِ يَتْبعان النبي صلى الله عليه وسلم إذا خرج لقضاء حاجته، يحملان معهما عصًا لها سنان مثل سنان الرمح ليجعلها سترة يعلق عليها شيء ساتر أو سترة لصلاته، ويحملان معهما أيضًا إناء صغير من جلد مملوءًا بالماء، فإذا فرغ النبي صلى الله عليه وسلم من قضاء حاجته ناوله أحدهما الإناء، فيستنجي بالماء.","reference":"صحيح البخاري (1/ 42) (152).\nصحيح مسلم (1/ 227) (271).\nتيسير العلام شرح عمدة الأحكام، لعبد الله البسام (ص40).\nتنبيه الأفهام شرح عمدة الأحكام، لابن عثيمين (1/ 43).\nالإفهام في شرح عمدة الأحكام، لابن باز (ص84).","benefits":["استعداد المسلم بطَهوره عند قضاء الحاجة؛ لئلا يُحْوِجَه إلى القيام فيتلوّث.","حفظ العورة عند قضاء الحاجة عن أن ينظر إليها أحد؛ لأن النظر إلى العورة محرم، فكان يركز العصا في الأرض وينصب عليها الثوب الساتر.","تعليم الأبناء الآداب الإسلامية وتربيتهم عليها؛ ليتوارثوها."],"wordsMeanings":[],"category":"sirah","tags":["كان","رسول","الله","صلى","الله","عليه"],"source":"hadeethenc"},{"id":"he_3058","text":"كَانَ ابنُ عمرَ -رضِيَ الله عنهما- يَقُول لِلرَّجُل إِذَا أَرَادَ سَفَرًا: ادْنُ مِنِّي حَتَّى أُوَّدِعَكَ كَمَا كَان رسولُ الله -صلَّى الله عليه وسلَّم- يُوَدِّعُنَا، فَيقُول: «أَسْتَوْدِعُ الله دِينَكَ، وَأَمَانَتَكَ، وَخَوَاتِيمَ عَمَلِكَ». \nوعن عبد الله بن يزيد الخطمي رضي الله عنه- قال: كَانَ رسُول الله -صلَّى الله عليه وسلَّم- إِذَا أَرَادَ أَنْ يُوَدِّعَ الجَيشَ، قال: «أَسْتَودِعُ الله دِينَكُم، وَأَمَانَتَكُم، وخَوَاتِيمَ أَعْمَالِكُم».","attribution":"الحديث الأول: رواه أبو داود، والتَرمذي واللفظ له، وابن ماجه والنسائي في الكبرى وأحمد.\n الحديث الثاني: رواه أبو داود والنسائي الكبرى","grade":"صحيحان","gradeKey":"sahih","explanation":"كَانَ ابنُ عمرَ -رضِيَ الله عنهما- يَقُول لِلرَّجُل إِذَا أَرَادَ سَفَرًا: ادْنُ مِنِّي حَتَّى أُوَّدِعَكَ كَمَا كَان رسولُ الله -صلَّى الله عليه وسلَّم- يُوَدِّعُنَا، وهذا من ابن عمر بيان لكمال حرص الصحابة رضي الله عنهم على التزام هدي رسول الله صلى الله عليه وسلم ، وقوله: (إذا ودع رجلا) أي مسافرا، (أخذ بيده فلا يدعها): وهذا ما جاء في بعض الروايات، أي: فلا يترك يد ذلك الرجل من غاية التواضع ونهاية إظهار المحبة والرحمة.\n ويقول صلى الله عليه وسلم : أي للمودع: \"أستودع الله دينك\" أي أستحفظ وأطلب منه حفظ دينك.\n و\"أمانتك\" أي حفظ أمانتك، وهي شاملة لكل ما استحفظ عليه الإنسان من حقوق الناس وحقوق الله من التكاليف، ولا يخلو الرجل في سفره ذلك من الاشتغال بما يحتاج فيه إلى الأخذ والإعطاء والمعاشرة مع الناس، فدعا له بحفظ الأمانة والاجتناب عن الخيانة، ثم إذا انقلب إلى أهله يكون مأمون العاقبة عما يسوءه في الدين والدنيا.\nوكان هذا من هديه أيضاً صلى الله عليه وسلم إذا أراد توديع الجماعة الخارجة للقتال في سبيل الله يودعهم بهذا الدعاء الجامع ليكون أدعى إلى إصابتهم التوفيق والسداد والتغلب على الأعداء والحفاظ على فرائض الله في الغزو.","reference":"بهجة الناظرين شرح رياض الصالحين، لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415هـ.\nتحفة الأحوذي بشرح جامع الترمذي، للمباركفوري، دار الكتب العلمية، بيروت.\nتطريز رياض الصالحين، للشيخ فيصل المبارك، ط1، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة، الرياض، 1423هـ.\nجامع الترمذي، تحقيق وتعليق: أحمد محمد شاكر وآخرون، ط2، شركة مكتبة ومطبعة مصطفى البابي الحلبي، مصر، 1395هـ.\nدليل الفالحين لطرق رياض ال","benefits":["استحباب توديع المسافر، كما صنع رسول الله -صلى الله عليه وسلم-.","حرص أصحاب رسول الله -صلى الله عليه وسلم- على هديه في أمورهم كلها.","استحباب دعاء المسلم لأخيه المسلم في كافة أحواله، سواء كان بظهر الغيب أو في وجهه.","أعظم ما يملك المرء في حياته ويخشى ضياعه هو الدين.","تمنِّي المسلم لأخيه خاتمة الخير كما يتمنى لنفسه أن يختم له بعمل صالح.","أن الخاتمة الحسنة منوطة بالتزام التقوى والمحافظة على الأمانات الشرعية.","التوفيق بيد الله -تعالى-، فعلى المسلم أن يطلب ذلك بتحري أسبابه وقرع بابه.","استحباب توديع ولي الأمر جيشه عند الذهاب للقتال وتوصيته بمثل هذه الكلمات السابقة."],"wordsMeanings":[{"word":"ادْنُ","meaning":" اقترب."},{"word":"أَسْتَوْدِعُ الله دِينَكَ","meaning":" أسْتَحفِظ وأطلب منه حفظ دينك."},{"word":"وَأَمَانَتَكَ","meaning":" أي حفظ أمانتك فيما تزاوله من الأخذ والإعطاء ومعاشرة الناس في السفر، وقيل المراد: الأهل والأولاد. وقيل: التكاليف كلها."},{"word":"وَخَوَاتِيمَ عَمَلِكَ","meaning":" حسن الخاتمة."},{"word":"إذا أراد سفراً","meaning":" أي همَّ به وأخذ في مقدماته."},{"word":"الجيش","meaning":" هم الجماعة الخارجون للقتال في سبيل الله -تعالى-."}],"category":"sirah","bookId":"abudawud","tags":["أستودع","الله","دينك،","وأمانتك،","وخواتيم","عملك"],"source":"hadeethenc"},{"id":"he_3131","text":"عن عبد الله بن عمر رضي الله عنهما أَنَّ النَّبِيَّ -صَلَّى اللهُ عَلَيْهِ وَسَلَّمَ- قَالَ: «أراني في المنام أَتَسَوَّكُ بِسِوَاكٍ، فجاءني رجلان، أحدهما أكبر من الآخر، فَنَاوَلْتُ السِّوَاكَ الأصغرَ، فقيل لي: كَبِّرْ، فَدَفَعْتُهُ إلى الأكبر منهما».","attribution":"رواه البخاري معلقًا ومسلم.\nللفائدة:\nالتعليق: أن يذكر المصنف الخبر بلا إسناد","grade":"صحيح","gradeKey":"sahih","explanation":"رأى النبي صلى الله عليه وسلم في النوم أنه كان يَتَسَوَّك بسواك، فجاءه رجلان أحدهما أكبر من الآخر، فأراد أن يعطيه إلى الأصغر منهما، فقيل له: قدم الأكبر في الإعطاء، فأعطاه إلى الكبير منهما.","reference":"بهجة الناظرين شرح رياض الصالحين، سليم بن عيد الهلالي، دار ابن الجوزي، الطبعة: الأولى 1418هـ.\nدليل الفالحين لطرق رياض الصالحين، محمد علي بن البكري بن علان، اعتنى بها: خليل مأمون شيحا، دار المعرفة، بيروت، الطبعة: الرابعة 1425هـ.\nرياض الصالحين من كلام سيد المرسلين، أبو زكريا محيي الدين النووي، تحقيق ماهر الفحل، دار ابن كثير، دمشق، بيروت، الطبعة: الأولى 1428هـ.\nشرح رياض الصالحين، محمد بن صالح العثيمين","benefits":["رؤيا الأنبياء حق؛ لأنها وحي معصوم؛ ولذلك ما يحدث فيها يدخل في التشريع.","استحباب استخدام السواك؛ لأنه سنة نبوية مؤكدة، وهو مطهرة للفم، مرضاة للرب، وبخاصة عند الوضوء والصلاة وقراءة القرآن.","أنَّ استعمال سواك الغير بإذنه غير مكروه، ويستحب غسله ثم استعماله.","فيه تقديم ذي السن في السواك، ويلتحق به الطعام والشراب والمشي والكلام.","يجوز اجتهاد رسول الله -صلى الله عليه وسلم- لكن لا يقر على خطأ بل يصوَّب مباشرة."],"wordsMeanings":[{"word":"أَرَانِي","meaning":" من الرؤيا، أي: أرى نفسي في النوم."},{"word":"المَنَامِ","meaning":" النوم."},{"word":"فَقِيل لِي","meaning":" كَبِّرْ : أي: قدِّم الكبير في السن."}],"category":"sirah","bookId":"bukhari","tags":["أراني","المنام","أتسوك","بسواك،","فجاءني","رجلان،"],"source":"hadeethenc"},{"id":"he_3139","text":"عن عائشة رضي الله عنها قالت: كُنَّ أزواجُ النبي صلى الله عليه وسلم عنده، فأقبلت فاطمة رضي الله عنها تمشي، ما تُخْطِئُ مِشْيَتُها من مِشْيَةِ رسول الله صلى الله عليه وسلم شيئًا، فلما رآها رَحَّبَ بها، وقال: «مَرْحَبًا بابنتي»، ثم أجلسها عن يمينه أو عن شماله، ثم سَارَّهَا فبكت بُكاءً شديدًا، فلما رأى جَزَعَهَا، سَارَّهَا الثانية فضحكت، فقلتُ لها: خَصَّكِ رسول الله صلى الله عليه وسلم من بين نسائه بالسِّرَارِ، ثم أنت تَبْكِينَ! فلما قام رسول الله صلى الله عليه وسلم سألتها: ما قال لك رسول الله صلى الله عليه وسلم ؟ قالت: ما كنت لأُفْشِيَ على رسول الله صلى الله عليه وسلم سِرَّهُ، فلما توفي رسول الله صلى الله عليه وسلم قلتُ: عَزَمْتُ عليك بما لي عليك من الحق، لما حَدَّثْتِنِي ما قال لك رسول الله صلى الله عليه وسلم ؟ فقالت: أما الآن فنعم، أما حين سَارَّنِي في المرة الأولى فأخبرني أن جبريل كان يُعارضه القرآن في كل سنة مرة أو مرتين، وأنه عارضه الآن مرتين، وإني لا أرى الأَجَلَ إلا قد اقترب، فاتقي الله واصبري، فإنه نِعْمَ السَّلَفُ أنا لك، فبكيت بكائي الذي رأيتِ، فلما رأى جَزَعِي سَارَّنِي الثانية، فقال: «يا فاطمة، أما تَرْضَينَ أن تكوني سيدة نساء المؤمنين، أو سيدة نساء هذه الأمة؟» فضحكتُ ضحكي الذي رأيتِ.","attribution":"متفق عليه","grade":"صحيح","gradeKey":"sahih","explanation":"ذكرت عائشة رضي الله عنها أن أزواج النبي صلى الله عليه وسلم كن عنده ثم جاءت فاطمة رضي الله عنها تعوده في مرضه وشكواه الذي قُبِض فيه، فذكرت أنَّ فاطمة رضي الله عنها أقبلت تمشي كأنَّ مشيتها مشية النبي صلى الله عليه وسلم ، وكانت عادته صلى الله عليه وسلم إذا دخلت عليه بنته فاطمة رضي الله عنها قام إليها وقبَّلها وأجلسها في مجلسه، فرحب بها وأجلسها بجانبه. \nثم أخبرت عائشة رضي الله عنها : أنه أسر إلى فاطمة رضي الله عنها بالقول فبكت بكاء شديدا، فلما رأى حزنها الشديد، أسر إليها بقول آخر فضحكت.\nفسألتها عائشة رضي الله عنها عن الذي خصها رسول الله صلى الله عليه وسلم به دون نسائه وبكت بسببه.\nفقالت: لم أكن لأنشر سر رسول الله صلى الله عليه وسلم .\nفلما توفي رسول الله صلى الله عليه وسلم أقسمت عائشة رضي الله عنها على فاطمة رضي الله عنها أن تحدثها بما قال لها الرسول صلى الله عليه وسلم .\nفقالت: أما إذا سألتني الآن فسأحدثك، أما بكائي حين أسر إلي بالقول في المرة الأولى، فإنه أخبرني أن جبريل -عليه السلام- كان يدارسه القرآن كل عام مرة أو مرتين، وأنه دارسه مرتين حينها، وظن رسول الله صلى الله عليه وسلم أن هذا نذير بانتهاء مدة حياته، وأمرني بالتقوى والصبر، وأن ما يترتب على ذلك من شرف السلف لي يعدل ما قد يبدو من جزع الفراق، فبكيت حين رأيتني بكيت، فلما رأى حزني الشديد، بشرني بأني سيدة نساء المؤمنين أو سيدة نساء هذه الأمة، فضحكت ضحكي الذي رأيتيه مني. \nوأما ضحكها فجاء هذا الحديث مبيِّنًا ذلك بكونها رضي الله عنها سيِّدة نساء أهل الجنة، ومع ذلك فقد اختلفت الروايات فيما سارها به ثانيا وضحكها لذلك على أقوال:\n1.\tأنه إخبار إيَّاها بأنها أول أهله لحوقا به.\n2.\t أنه إخباره إياها بأنها سيدة نساء أهل الجنة، وجعل كونها أول أهله لحوقا به مضموما إلى الأول وهو الراجح. \n3.\tأنه قال لفاطمة إنَّ جبريل أخبرني أنه ليس امرأة من نساء المسلمين أعظم ذرية منك فلا تكوني أدنى امرأة منهن صبرًا.\nولكن يبقى قبل ذلك أنَّ حرص عائشة رضي الله عنها على العلم سرَّع من سؤالها لفاطمة رضي الله عنها عمَّا حصل في السرار، فما كان من بنت رسول الله إلا أن قالت: \"مَا كُنتُ لِأُفشِيَ عَلَى رسول الله صلى الله عليه وسلم سِرَّه\"، وهو الشاهد من الحديث، فلما زال المحذور بموت النبي صلى الله عليه وسلم أخبرتها من أمر السرار.\nوفي الحديث إخباره صلى الله عليه وسلم بما سيقع فوقع كما قال، فإنهم اتفقوا على أن فاطمة -عليها السلام- كانت أول من مات من أهل بيت النبي صلى الله عليه وسلم بعده حتى قبل أزواجه -رضي الله عنهن-.","reference":"بهجة الناظرين شرح رياض الصالحين لسليم الهلالي، ط1، دار ابن الجوزي، الدمام، 1415ه.\nتطريز رياض الصالحين للشيخ فيصل المبارك، ط1، تحقيق: عبد العزيز بن عبد الله آل حمد، دار العاصمة، الرياض، 1423 هـ.\nرياض الصالحين للنووي، ط1، تحقيق: ماهر ياسين الفحل، دار ابن كثير، دمشق، بيروت، 1428 هـ.\nرياض الصالحين، ط4، تحقيق: عصام هادي، وزارة الأوقاف والشؤون الإسلامية القطرية، دار الريان، بيروت، 1428هـ.\nكنوز رياض الصا","benefits":["فضل فاطمة -رضي الله عنها-.","الحديث من دلائل النبوة؛ فقد أخبر الرسول -صلى الله عليه وسلم- ابنته بقرب أجله، وأعلمها بأنها أول أهله لحوقا به؛ فكان ما أخبر به رسول الله -صلى الله عليه وسلم-.","استحباب كتم السر وعدم إفشائه حتى يزول المانع من ذلك.","عرض القرآن على الحفاظ ومدارستهم له من طرق حفظه وتثبيته؛ فهي سنة متبعة بين أهل القرآن وحفاظه، ولذلك ينبغي على الحافظ أن يتعاهد حفظه.","جواز الاستدلال بالقرائن؛ فإن رسول الله -صلى الله عليه وسلم- استدل بمعارضة جبريل له القرآن مرتين- وقد كان يعارضه في كل سنة مرة- على قرب الأجل ودنو يوم الرحيل.","تقديم المؤانسة قبل الإخبار بالأمر.","جواز البكاء الخالي من الصراخ والعويل والنياحة ولطم الخدود وشق الجيوب؛ لأنه رحمة جعلها الله في قلب عبده المؤمن.","حال المؤمن الصبر عند المصيبة، والبعد عن الفخر والعجب بالنفس عند النعمة.","أن جزاء الصبر على قدر عظم المصيبة."],"wordsMeanings":[{"word":"مَرحَبا","meaning":" أي نزلت مكانًا رحبًا واسعًا."},{"word":"سارَّها","meaning":" ألقى إليها سرًّا."},{"word":"جَزَعَها","meaning":" خوفها وحزنها."},{"word":"السِّرار","meaning":" ما يُكتم من الأمور."},{"word":"أُفشِي","meaning":" أنشر."},{"word":"عَزَمت عليك","meaning":" أقسمت عليك."},{"word":"يُعَارضُه القرآن","meaning":" يدارسه القرآن، من المعارضة بمعنى المقابلة."},{"word":"السَّلَف","meaning":" سلف الإنسان: من تقدَّمه بالموت من آبائه وذوي قرابته."},{"word":"الأجَل","meaning":" آخر مدة الحياة."},{"word":"فاتَّقي","meaning":" المتقون هم:  الذين اتخذوا وقاية من عذاب الله بفعل أوامره واجتناب نواهيه."}],"category":"sirah","tags":["أزواج","النبي","صلى","الله","عليه","وسلم"],"source":"hadeethenc"}];
